/* AUTO-GENERATED by content-engine/import-dl.cjs — Texas DL (regular driver license) data.
   window.DL_DATA (EN) + window.DL_I18N (ru/tr/es/hi). 196 practice + 300 learn questions. */
window.DL_DATA = {"categories":[{"id":"road-signs","name":"Road Signs","blurb":"Texas DL Road Signs: practice tests plus a Learning Test that walks the whole handbook section.","accent":"#d7263d","kind":"core","classes":["DL"],"questions":[{"q":"Driving at dusk, you approach an intersection where the sign facing you is badly faded and you can no longer read any of its lettering. You can still clearly see that the sign has eight sides. What must you do at this intersection?","options":["Come to a complete stop, because an eight-sided (octagonal) sign always means STOP.","Slow down and yield the right of way, stopping only if other traffic is present.","Slow down and proceed with caution, since the shape only warns of a hazard ahead.","Treat it as a school crossing and be ready for children entering the roadway."],"answer":0,"explanation":"The octagon is the only eight-sided sign and always means STOP, so the shape alone tells you to come to a full stop even when the lettering is unreadable. Yielding is signaled by an inverted triangle, not an octagon, which makes that option the trap.","handbook":"An octagon (8-sided) sign means STOP, and it is the only sign that is octagonal; a driver must come to a full stop.","hbref":"Sign Shapes","qid":"DL-ROADSIGNS-TRAP-001"},{"q":"You are merging onto a highway from an on-ramp and see a red-and-white sign shaped like an upside-down (inverted) triangle facing you. What does this sign require you to do?","options":["Come to a complete stop and remain stopped until the highway is empty in both directions","Give the right of way to traffic on the highway, slowing or stopping only if necessary to do so safely","Proceed at the posted maximum speed because you have the right of way when merging","Treat it as a warning of a hazard ahead and continue with caution without yielding"],"answer":1,"explanation":"An inverted triangle is a YIELD sign: you must give the right of way to traffic already on the highway and slow or stop only if needed to merge safely. A full stop every time (A) describes an octagonal STOP sign, and a diamond-shaped warning sign (D) does not require yielding the right of way.","handbook":"An inverted (upside-down) triangle means YIELD; the driver must give the right of way and slow or stop if needed.","hbref":"Sign Shapes","qid":"DL-ROADSIGNS-TRAP-002"},{"q":"You're driving on a two-lane rural highway and want to pass a slow tractor ahead. Just before you pull out, you notice a sign shaped like a triangle lying on its side (a horizontal point) posted on the LEFT shoulder of the road. What is this sign telling you?","options":["Yield to oncoming traffic before merging back into your lane","A school zone or school crossing is ahead, so reduce speed","You are entering a No Passing Zone and must not pass the tractor here","A hazard or condition is ahead, so slow down and proceed with caution"],"answer":2,"explanation":"A pennant (a horizontal triangle) posted on the LEFT side of the road marks a No Passing Zone, so you must not pass the tractor. A yield is an inverted (upside-down) triangle, and a diamond is the warning shape, so those options confuse other sign shapes with the pennant.","handbook":"A pennant (horizontal triangle) located on the LEFT side of the road marks a No Passing Zone.","hbref":"Sign Shapes","qid":"DL-ROADSIGNS-TRAP-003"},{"q":"You're driving on an unfamiliar two-lane highway at dusk. Up ahead on the right shoulder you see a yellow, diamond-shaped sign, but you're still too far away to read the words or symbol printed on it. Based on its shape alone, what should you immediately understand?","options":["It is a regulatory sign telling you a law you must obey, such as a speed limit","It marks a school zone or school crossing ahead","It is a guide sign giving directions or distances to the next town","It is a warning sign alerting you to a hazard or change in road conditions ahead"],"answer":3,"explanation":"A diamond shape always means a warning sign, telling you a hazard or condition lies ahead. Regulatory laws use vertical rectangles (A) and guide/direction information uses horizontal rectangles (C), while school zones use a pentagon (B).","handbook":"A diamond-shaped sign is a Warning sign, indicating a hazard or condition ahead.","hbref":"Sign Shapes","qid":"DL-ROADSIGNS-TRAP-004"},{"q":"While driving through an unfamiliar residential area, you see a yellow-green, five-sided sign with the point facing up. Based on its shape alone, what is this sign warning you about?","options":["You are approaching a school zone or school crossing","There is a railroad crossing ahead","You are entering a no-passing zone","A general hazard or condition lies ahead"],"answer":0,"explanation":"A pentagon (5-sided, point up) shape always means a school zone or school crossing. A round sign warns of a railroad crossing ahead, so option B confuses two different sign shapes.","handbook":"A pentagon (5-sided, point up) sign indicates a school zone or school crossing.","hbref":"Sign Shapes","qid":"DL-ROADSIGNS-TRAP-005"},{"q":"You are driving on a rural two-lane highway and notice a round, yellow sign on the right shoulder with a black 'X' and the letters 'RR' on it, posted well before any tracks are visible. What is this sign telling you?","options":["You have reached the tracks themselves and must stop your vehicle on them","A railroad crossing is ahead, so be prepared to slow down and look for trains","You are entering a school zone and must reduce your speed for children","This is a no-passing zone and you may not pass other vehicles here"],"answer":1,"explanation":"A round (circular) sign is the advance warning that a railroad crossing lies ahead, so you should slow down and watch for trains. The crossing itself is marked by the X-shaped Crossbuck (not this round sign), and the pentagon shape, not the circle, signals a school zone.","handbook":"A round (circular) sign is an advance warning for a railroad crossing.","hbref":"Sign Shapes","qid":"DL-ROADSIGNS-TRAP-006"},{"q":"You are driving on a rural road and approach the railroad tracks themselves, where you see a white X-shaped sign with the words 'RAILROAD CROSSING.' There is no stop sign, no gate, and no flashing lights at this crossing. How should you treat this sign?","options":["Come to a full stop every time, because the X-shaped crossbuck legally functions as a stop sign","Ignore it unless a train is visible, because the crossbuck is only an advance warning posted ahead of the tracks","Treat it like a yield sign: slow down, look both ways, and stop only if a train is approaching","Proceed at your normal speed, because the round advance-warning sign earlier already told you everything you need"],"answer":2,"explanation":"A crossbuck (X-shaped) sign marks the railroad crossing itself and should be treated like a yield sign, meaning you slow down, check for trains, and stop only if one is approaching. It is not a stop sign (A), and unlike the round advance-warning sign (B, D), the crossbuck is located at the tracks themselves, not ahead of them.","handbook":"A crossbuck (X-shaped) sign is located at the railroad crossing itself and should be treated like a yield.","hbref":"Sign Shapes","qid":"DL-ROADSIGNS-TRAP-007"},{"q":"You are driving on an unfamiliar road and need to know how fast you are legally allowed to go. Up ahead you see a sign that is shaped as a vertical rectangle (taller than it is wide). Based on its shape alone, what kind of sign is this most likely to be?","options":["A guide or information sign giving directions and distances to the next town","A warning sign alerting you to a hazard or changing condition ahead","A construction or work zone sign warning of road crews ahead","A regulatory sign stating a law you must obey, such as a speed limit"],"answer":3,"explanation":"A vertical rectangle is a regulatory sign that tells you a law you must obey, such as the posted speed limit. A horizontal rectangle (option A) is the guide/information shape, and a diamond (option B) is the warning shape, so neither matches a vertical rectangle.","handbook":"A vertical rectangle is a regulatory sign, indicating a law you must obey (e.g., speed limit).","hbref":"Sign Shapes","qid":"DL-ROADSIGNS-TRAP-008"},{"q":"You're driving on a highway looking for the exit to your destination city. Up ahead you see a wide sign that is shaped like a horizontal rectangle (longer than it is tall). Based only on its shape, what kind of information should you expect this sign to give you?","options":["Directions and distances to places, such as which exit to take and how far away your city is","A traffic law you must obey, such as the posted speed limit","A warning about a hazard or condition ahead, such as a sharp curve","An order to come to a full stop before proceeding"],"answer":0,"explanation":"A horizontal rectangle is a guide/information sign, giving directions and distances. A vertical rectangle (not horizontal) is the regulatory shape for laws like speed limits, warnings use a diamond, and only an octagon means stop.","handbook":"A horizontal rectangle is a guide/information sign, giving directions and distances.","hbref":"Sign Shapes","qid":"DL-ROADSIGNS-TRAP-009"},{"q":"While driving at night, you turn onto a street and your headlights light up a red sign with white letters reading WRONG WAY directly ahead of you. What does this sign tell you to do?","options":["Slow down because there is a hazard or unusual condition ahead","Stop, you are facing oncoming traffic, and you must not continue in this direction","Continue, but yield to motorist services such as gas and food at the next exit","Proceed with caution because you are entering a construction or work zone"],"answer":1,"explanation":"WRONG WAY is a red sign, and red means stop, yield, or prohibited, so you must not continue in that direction because you are heading into oncoming traffic. Option A describes a yellow warning sign and option D describes an orange construction sign, neither of which is red.","handbook":"Red signs mean stop, yield, or prohibited (e.g., STOP, YIELD, DO NOT ENTER, WRONG WAY).","hbref":"Sign Colors","qid":"DL-ROADSIGNS-TRAP-010"},{"q":"You're driving on an unfamiliar two-lane highway at dusk when your headlights catch a yellow diamond-shaped sign showing a curved arrow bending to the right. Based on its color, what is this sign telling you?","options":["A law you must obey: a sharp right turn is required ahead","A construction crew is working around the bend to the right","A general warning: a curve in the road lies ahead, so slow down","A guide sign pointing you toward a destination to the right"],"answer":2,"explanation":"Yellow signs are general warning signs alerting you to a hazard or condition ahead, such as a curve, so you should reduce speed. The construction trap is wrong because work-zone warnings are orange, and the regulatory/guide traps are wrong because those use white/green, not yellow.","handbook":"Yellow signs are general warning signs (curve, hill, merge, signal ahead).","hbref":"Sign Colors","qid":"DL-ROADSIGNS-TRAP-011"},{"q":"You are driving on a highway when you see a diamond-shaped sign ahead with an orange background reading \"ROAD WORK AHEAD.\" What does the orange color of this sign tell you?","options":["It marks a recreation or scenic area you are approaching","It indicates motorist services such as gas, food, or lodging ahead","It is a general warning about a curve or hill in the road","You are entering a construction or work zone"],"answer":3,"explanation":"Orange signs always indicate a construction or work zone, so you should slow down and be alert for workers and equipment. Brown is used for recreation/scenic areas and yellow is used for general warnings like curves or hills, which is why those options are wrong.","handbook":"Orange signs indicate a construction or work zone.","hbref":"Sign Colors","qid":"DL-ROADSIGNS-TRAP-012"},{"q":"You're driving on a rural highway looking for the exit to your destination city. Up ahead you see a large green sign with white lettering reading \"Lubbock 45 / Amarillo 120\" and an arrow. What does this sign tell you?","options":["It is a guide sign giving you directions and the distances to those cities","It is a warning sign telling you the cities ahead have hazardous road conditions","It marks motorist services, such as gas and food, available in those cities","It is a regulatory sign requiring you to exit toward one of those cities"],"answer":0,"explanation":"Green signs are guide signs that indicate permitted movements, directions, and distances, so this sign is simply telling you the way and mileage to each city. Warning information would be on a yellow sign, and motorist-services signs are blue, so those choices place the wrong color and meaning together.","handbook":"Green signs are guide signs indicating permitted movements, directions, and distances.","hbref":"Sign Colors","qid":"DL-ROADSIGNS-TRAP-013"},{"q":"You're driving on an unfamiliar highway, low on fuel and hungry, when you notice a sign ahead with a blue background listing symbols for a gas pump and a fork and knife. What is this sign telling you?","options":["It is a guide sign showing the direction and distance to the next city","It is directing you to nearby motorist services such as gas and food","It is warning you of a hazard or condition ahead near the roadside","It marks a recreational or scenic area available at the next exit"],"answer":1,"explanation":"Blue signs indicate motorist services such as gas, food, lodging, and hospital, so the blue background with the fuel and dining symbols points you to those services. Green signs (not blue) handle directions and distances, and brown signs mark recreational or scenic areas.","handbook":"Blue signs indicate motorist services such as gas, food, lodging, and hospital.","hbref":"Sign Colors","qid":"DL-ROADSIGNS-TRAP-014"},{"q":"While driving on a rural highway, you see a square sign ahead with a brown background and white symbols pointing toward a state park and a historic battlefield. What is this sign telling you?","options":["You are approaching available motorist services such as gas, food, and lodging","There is a construction or work zone ahead, so you should slow down","You are nearing recreational, cultural, or scenic areas such as parks and historic sites","You must obey a regulatory law, such as a posted speed limit"],"answer":2,"explanation":"Brown signs indicate recreation, cultural, or scenic areas like parks and historic sites, so option C is correct. Blue signs (not brown) mark motorist services such as gas and food, which makes that the trap answer.","handbook":"Brown signs indicate recreation, cultural, or scenic areas.","hbref":"Sign Colors","qid":"DL-ROADSIGNS-TRAP-015"},{"q":"You are driving on an unfamiliar highway at night. A sign ahead is a vertical white rectangle with black lettering reading \"45.\" What does this sign tell you?","options":["It is a guide sign telling you the distance to the next exit.","It is a warning sign about a hazard 45 feet ahead.","It is a construction-zone sign setting a temporary work-zone limit.","It is a regulatory sign setting the maximum legal speed at 45 mph."],"answer":3,"explanation":"White signs with black lettering are regulatory signs, and a white rectangle with a number sets the maximum legal speed (45 mph). Guide/distance signs are green and warning signs are yellow, so those options place real facts on the wrong color of sign.","handbook":"White signs (with black lettering) are regulatory signs (speed limit, lane use).","hbref":"Sign Colors","qid":"DL-ROADSIGNS-TRAP-016"},{"q":"While driving through an unfamiliar neighborhood, you approach a diamond-shaped sign with a bright fluorescent yellow-green background showing two children walking. What is this sign warning you about?","options":["Pedestrians, bicyclists, or a school crossing ahead","A construction or work zone ahead","A recreation or scenic area ahead","A general curve or hill hazard ahead"],"answer":0,"explanation":"Fluorescent yellow-green is reserved for pedestrian, bicycle, and school warnings, so this sign means people may be crossing ahead. Orange signals construction zones and brown marks recreation/scenic areas, so those colors would not appear on this warning.","handbook":"Fluorescent yellow-green signs indicate pedestrian, bicycle, and school warnings.","hbref":"Sign Colors","qid":"DL-ROADSIGNS-TRAP-017"},{"q":"You are driving at dusk toward an unfamiliar intersection. The sign facing you has faded so much that you can no longer read the word on it, but you can still make out its outline and color. To know it is a STOP sign and that you must come to a full stop, which shape and color should you be looking for?","options":["A red, upside-down (inverted) triangle","A red, eight-sided octagon","A yellow diamond","A white vertical rectangle"],"answer":1,"explanation":"A STOP sign is the only red, eight-sided octagon, so its shape and color identify it even when the word is unreadable. A red inverted triangle is a YIELD sign (give the right of way, not necessarily a full stop), which is the trap.","handbook":"A STOP sign is a red octagon.","hbref":"Common Specific Signs","qid":"DL-ROADSIGNS-TRAP-018"},{"q":"You are merging onto a busy highway from an on-ramp. At the end of the ramp you see a sign shaped like a triangle pointing downward, colored red and white. What does this sign require you to do?","options":["Come to a complete stop, since this is the only sign shape that legally means stop","Treat the intersection as an all-way stop because the signal is dark","Slow down and give the right of way to highway traffic, stopping only if necessary","Do not enter, because a red-and-white sign always means the road is closed to you"],"answer":2,"explanation":"A red-and-white inverted (downward-pointing) triangle is a YIELD sign, which means give the right of way and slow or stop only if needed. The full-stop trap describes the red octagon STOP sign, and the 'do not enter' trap confuses YIELD with a prohibitory sign.","handbook":"A YIELD sign is a red-and-white inverted triangle.","hbref":"Common Specific Signs","qid":"DL-ROADSIGNS-TRAP-019"},{"q":"You're searching for a parking garage downtown and pull up to a ramp where you see a red sign reading 'DO NOT ENTER.' What does this red sign require you to do?","options":["Slow down and proceed with caution, since red signs only signal a hazard ahead","Yield to any traffic on the ramp, then enter if the way is clear","Come to a full stop, then continue once you've checked for oncoming cars","Do not proceed into the ramp; this entrance is closed to your direction of travel"],"answer":3,"explanation":"DO NOT ENTER is a red sign meaning do not proceed, because that entrance is closed to your direction of travel. Yielding (B) or stopping then continuing (C) are wrong because the sign prohibits entry entirely rather than allowing you to proceed after caution.","handbook":"DO NOT ENTER and WRONG WAY signs are red and mean do not proceed.","hbref":"Common Specific Signs","qid":"DL-ROADSIGNS-TRAP-020"},{"q":"You turn onto a street and see a rectangular sign with a horizontal arrow pointing right and the words ONE WAY. You wanted to go left down this street. What must you do?","options":["Do not turn left; travel only to the right, in the direction the arrow points","Turn left, but yield to any oncoming traffic first since it is a shared street","Turn left only if no DO NOT ENTER sign is also posted at the corner","Treat it as a warning and proceed left slowly with caution"],"answer":0,"explanation":"A ONE WAY sign means traffic may travel only in the direction the arrow points, so you must go right and cannot turn left onto that street. Turning left would send you against legal traffic flow, so the options allowing a left turn are wrong.","handbook":"A ONE WAY sign means travel only in the direction of the arrow.","hbref":"Common Specific Signs","qid":"DL-ROADSIGNS-TRAP-021"},{"q":"You are driving on a clear, dry day and pass a white rectangular sign with the black number 65 on it. Light rain begins to fall and the road becomes slick. What does that sign tell you about your speed in this changing weather?","options":["65 is the minimum speed you must maintain regardless of the rain","65 is the maximum legal speed for ideal conditions, so you should now slow below it for the wet road","The white rectangle is only a guide sign, so the 65 is just advisory and not enforceable","Because it is raining, the limit automatically increases to give you more room to stop"],"answer":1,"explanation":"A SPEED LIMIT sign is a white rectangle with black numbers showing the maximum legal speed in ideal conditions, so in rain you must drive slower than the posted number. It is not a minimum, it is a regulatory (not guide) sign, and the limit never rises in bad weather.","handbook":"A SPEED LIMIT sign is a white rectangle with black numbers and shows the maximum legal speed in ideal conditions.","hbref":"Common Specific Signs","qid":"DL-ROADSIGNS-TRAP-022"},{"q":"You're approaching an intersection and want to make a U-turn. Mounted above the signal is a white square sign showing a U-turn arrow inside a red circle with a red diagonal line crossing through it. What does this sign require you to do?","options":["It only warns that U-turns are tricky here, so you may make the U-turn if it is safe","It permits a U-turn but only on a protected green arrow","It prohibits U-turns at this intersection, so you must not make one","It means yield to oncoming traffic before completing the U-turn"],"answer":2,"explanation":"A red circle with a slash is a regulatory 'No' sign, and a U-turn arrow inside it means U-turns are prohibited here. The trap answers treat a mandatory prohibition as a mere warning or a conditional/yield situation, but the red circle and slash means the movement is flatly illegal.","handbook":"Regulatory 'No' signs (no U-turn, no left turn) use a red circle and slash.","hbref":"Common Specific Signs","qid":"DL-ROADSIGNS-TRAP-023"},{"q":"You are driving on an unfamiliar two-lane road at night. The line painted down the center of the road, between your lane and the lane to your left, is yellow. What does this color tell you about the traffic in the lane on the other side of that line?","options":["It is a one-way street, so no traffic comes from the opposite direction","The yellow line only marks the edge of the pavement, not a traffic lane","Traffic in that lane is moving in the same direction as you","Traffic in that lane is moving in the opposite direction, toward you"],"answer":3,"explanation":"Yellow lines separate traffic moving in opposite directions, so the lane across a yellow center line carries oncoming traffic. White lines (not yellow) separate same-direction traffic and mark the road edge, which makes the same-direction and edge-marking options wrong.","handbook":"Yellow lines separate traffic moving in OPPOSITE directions.","hbref":"Pavement Markings","qid":"DL-ROADSIGNS-TRAP-024"},{"q":"You are driving on a wide highway and approach a long line of solid white paint running parallel to your lane on your left, with more traffic flowing in the same direction on the other side of it. What does this white line tell you about the traffic next to you?","options":["The traffic beside you is moving in the same direction as you, and the line discourages changing lanes across it.","The traffic beside you is moving in the opposite direction, so crossing the line would put you into oncoming cars.","The line marks the edge of the road, so there is no traffic lane at all beyond it.","The line means passing is allowed only when the way ahead is clear, just like a broken yellow line."],"answer":0,"explanation":"White lines separate lanes of traffic moving in the SAME direction, and a solid white line discourages crossing or changing lanes. Yellow lines (B) separate opposite directions, white edge lines mark the pavement edge but here it sits between two same-direction lanes (C), and broken-line passing rules apply to yellow lines, not this solid white one (D).","handbook":"White lines separate traffic moving in the SAME direction (lanes) and mark the road edge.","hbref":"Pavement Markings","qid":"DL-ROADSIGNS-TRAP-025"},{"q":"You are driving on a two-lane highway and want to pass a slow tractor ahead. As you approach, you notice the lane line on your side of the center is a single solid yellow line, while the opposite side has a broken yellow line. What does this tell you about passing?","options":["You may pass because the broken yellow line on the other side applies to both directions of travel.","You may not pass, because the solid yellow line on your side prohibits passing.","You may pass only at speeds below the posted limit since the markings are advisory.","You must come to a complete stop before crossing any yellow line."],"answer":1,"explanation":"A solid yellow line on your side of the road means passing is prohibited for you, even if the opposite side has a broken (dashed) yellow line that permits passing for oncoming traffic. The broken line only allows passing for drivers on that side, and yellow markings are regulatory, not merely advisory.","handbook":"A solid yellow line on YOUR side of the road means no passing.","hbref":"Pavement Markings","qid":"DL-ROADSIGNS-TRAP-026"},{"q":"You are driving on a two-lane highway and want to pass a slow tractor ahead. On your side of the center, the pavement is marked with a broken (dashed) yellow line, the oncoming lane is empty, and you have a long clear view ahead. What does this marking tell you about passing?","options":["You may never cross a yellow line for any reason, so stay behind the tractor","The dashed line marks the edge of the roadway, so do not move left","Passing is permitted, and you may cross into the oncoming lane to pass when the way is clear","You may change lanes freely because dashed lines always separate same-direction traffic"],"answer":2,"explanation":"A broken (dashed) yellow line on your side means passing is allowed when the way ahead is clear, so you may cross to pass the tractor. Option D is the trap: dashed white lines separate same-direction traffic, but yellow lines always separate opposing traffic, so the rule it states is misapplied here.","handbook":"A broken (dashed) yellow line means passing is allowed when the way is clear.","hbref":"Pavement Markings","qid":"DL-ROADSIGNS-TRAP-027"},{"q":"You are driving on a two-lane road where a double solid yellow line runs down the center. A slow tractor is ahead of you, and the road is clear with good visibility. On your left, a driveway leads to the house you want to visit. What does the double solid yellow line allow you to do here?","options":["Pass the tractor, since the road is clear and visibility is good","Pass the tractor, because double yellow only restricts oncoming traffic","Nothing requires you to wait; you may change lanes freely as with a broken white line","Cross the line only to turn left into the driveway, but not to pass the tractor"],"answer":3,"explanation":"A double solid yellow line means no passing in either direction, so you cannot pass the tractor even with clear visibility; you may only cross it to turn (such as into the driveway). The clear-road and 'oncoming-only' options are traps because the prohibition applies to both directions regardless of visibility.","handbook":"A double solid yellow line means no passing in either direction; do not cross except to turn.","hbref":"Pavement Markings","qid":"DL-ROADSIGNS-TRAP-028"},{"q":"You are driving on a three-lane highway where all traffic moves in the same direction. As you approach an exit, you notice the lane line on your right has changed from a broken white line to a single solid white line. What does this solid white line tell you about changing lanes here?","options":["It discourages crossing the line to change lanes at this point","It allows you to freely change lanes whenever the way is clear","It separates traffic moving in opposite directions","It means passing is permitted only when no oncoming traffic is present"],"answer":0,"explanation":"A solid white line discourages lane changes, so you should stay in your lane rather than cross it near the exit, whereas a broken white line is what allows lane changes when clear (option B). White lines separate same-direction traffic, so the opposite-direction and oncoming-traffic options describe yellow-line rules, not this marking.","handbook":"A solid white line discourages lane changes, while a broken white line allows them.","hbref":"Pavement Markings","qid":"DL-ROADSIGNS-TRAP-029"},{"q":"You pull up to a red traffic light at an intersection and want to make a right turn. There is no sign posted that prohibits turning on red, and the crosswalk and cross traffic are clear. What is the correct action?","options":["Slow down but roll through the red light without stopping, since the way is clear","Come to a complete stop behind the line first, then turn right when it is safe","Wait for a green arrow before you are allowed to turn right","Treat the red light as a yield and merge into the turn without fully stopping"],"answer":1,"explanation":"A steady red light requires a complete stop behind the line, and a right turn on red is allowed only after that full stop when no sign prohibits it. Rolling through (A) or yielding without stopping (D) skips the mandatory full stop, and a green arrow (C) is not required for a permitted right on red.","handbook":"A steady RED light means stop completely behind the line and remain stopped; a right turn on red is allowed after a full stop unless a sign prohibits it.","hbref":"Traffic Signals","qid":"DL-ROADSIGNS-TRAP-030"},{"q":"You are approaching an intersection at the speed limit when the signal facing you changes from green to a steady YELLOW. You are still some distance back, with plenty of room to brake smoothly. What does this signal mean, and what should you do?","options":["The light is about to turn green again; speed up to clear the intersection before it changes","It is a warning of a hazard ahead, like a curve or merge; slow down but you may continue through","The light is about to turn red; stop before the line if you can do so safely","Treat the intersection as a four-way stop, come to a full stop, then proceed when it is your turn"],"answer":2,"explanation":"A steady yellow light warns that the signal is about to turn red, so you must stop before the line if you can do so safely, which you can from this distance. Option D describes a dark/non-working signal, and option B confuses the signal with a yellow warning sign, not a traffic light.","handbook":"A steady YELLOW light means the light is about to turn red; stop if you can do so safely.","hbref":"Traffic Signals","qid":"DL-ROADSIGNS-TRAP-031"},{"q":"You reach an intersection on a steady GREEN light and signal a left turn. Oncoming cars are approaching, and a pedestrian is stepping into the crosswalk you must cross. What should you do?","options":["Proceed immediately, since a green light gives you the protected right to turn.","Stop completely behind the line and wait for a green arrow before turning.","Turn quickly in front of the oncoming cars because they must yield to a turning vehicle.","Wait, yielding to the pedestrian and oncoming traffic, then complete the turn when the way is clear."],"answer":3,"explanation":"A steady green means go only if the way is clear; when turning you must yield to pedestrians and oncoming traffic, so you wait until both are clear before turning. A plain green is not a protected turn (only a green arrow is), and oncoming traffic does not yield to you, so the other answers are wrong.","handbook":"A steady GREEN light means go if the way is clear; when turning, yield to pedestrians and oncoming traffic.","hbref":"Traffic Signals","qid":"DL-ROADSIGNS-TRAP-032"},{"q":"You approach an intersection at night and the overhead traffic signal is flashing red in your direction. There is no other traffic visible. What must you do?","options":["Come to a complete stop, then proceed when the way is clear, treating it like a stop sign","Slow down and proceed with caution without stopping","Keep driving through, since a flashing light means the signal is not in effect","Stop and wait for the light to turn steady green before going"],"answer":0,"explanation":"A flashing red light must be treated exactly like a STOP sign: come to a full stop, then proceed when it is safe. Slowing without stopping (B) is the rule for a flashing yellow light, not a flashing red one.","handbook":"A flashing RED light should be treated as a STOP sign.","hbref":"Traffic Signals","qid":"DL-ROADSIGNS-TRAP-033"},{"q":"You are approaching an intersection at night and the traffic signal facing you is a flashing yellow light. What should you do?","options":["Come to a complete stop behind the line, then proceed when the way is clear, treating it like a stop sign","Slow down and proceed through the intersection with caution","Stop completely and remain stopped until the light turns green","Treat the intersection as an all-way stop and yield to the driver on your right"],"answer":1,"explanation":"A flashing yellow light means slow down and proceed with caution, so option B is correct. Option A describes a flashing RED light (treated as a stop sign), and option D describes a dark or non-working signal, which are the wrong responses for a flashing yellow.","handbook":"A flashing YELLOW light means slow down and proceed with caution.","hbref":"Traffic Signals","qid":"DL-ROADSIGNS-TRAP-034"},{"q":"You are stopped in the left-turn lane at an intersection. The main signal for your direction is steady red, but a separate left-turn signal next to it shows a steady GREEN ARROW pointing left. What does this mean for your left turn?","options":["You must wait, because the steady red light controls all movements at the intersection","You may turn left only after yielding to oncoming traffic, since green always means yield to oncoming vehicles","You have a protected turn and may turn left in the direction of the arrow","You should treat the intersection as an all-way stop and proceed in turn"],"answer":2,"explanation":"A green arrow signals a protected turn in the direction it points, so you may turn left with the right of way even though the main signal is red. Option B describes a steady green ball (yield to oncoming traffic), not a green arrow, and option A wrongly lets the red ball override the dedicated turn arrow.","handbook":"A green arrow signal means a protected turn in the direction of the arrow.","hbref":"Traffic Signals","qid":"DL-ROADSIGNS-TRAP-035"},{"q":"You are stopped in the left-turn lane at an intersection. The dedicated left-turn signal shows a steady red arrow pointing left, while the signal for traffic going straight ahead is green. What should you do?","options":["Make the left turn, because the green light for the through lanes gives you the right of way","Make the left turn after coming to a complete stop, the same as a right turn on red","Treat the red arrow like a flashing yellow and turn left with caution","Remain stopped and wait, because a red arrow means no left turn is allowed in that direction"],"answer":3,"explanation":"A red arrow means no turn is permitted in the direction the arrow points, so you must stay stopped until the arrow changes. The green light for the through lanes does not apply to your protected turn, and a red arrow does not allow a turn after stopping the way a steady red ball can.","handbook":"A red arrow signal means no turn is allowed in that direction.","hbref":"Traffic Signals","qid":"DL-ROADSIGNS-TRAP-036"},{"q":"You approach a busy four-way intersection during a power outage, and the traffic signal that normally controls it is completely dark and showing no lights at all. There are no police officers or temporary signs present. How should you proceed?","options":["Treat the intersection as an all-way STOP, stopping fully and yielding by the usual right-of-way rules.","Slow down and proceed with caution without stopping, since a dark signal works like a flashing yellow light.","Continue through at normal speed because a non-working signal means the intersection has no active control.","Stop only if cross traffic is present, then go before drivers who arrive after you."],"answer":0,"explanation":"A dark or non-working signal must be treated as an all-way STOP, so you stop fully and follow normal right-of-way rules. Option B is wrong because a dark signal is not the same as a flashing yellow (slow and proceed with caution); a dead signal requires a complete stop from every direction.","handbook":"A dark or non-working signal should be treated as an all-way STOP.","hbref":"Traffic Signals","qid":"DL-ROADSIGNS-TRAP-037"},{"q":"You're driving on a highway when you see two diamond-shaped warning signs ahead. The first is bright yellow showing a curving road, and the second is bright orange showing a worker with a shovel. What does the orange color of the second sign tell you specifically?","options":["A general curve or hill hazard is ahead, the same as the yellow sign","You are approaching a construction or work zone","There is a pedestrian or school crossing ahead","You must stop because the road is closed"],"answer":1,"explanation":"Orange signs indicate a construction or work zone, distinguishing them from standard yellow general-warning signs (curve, hill, merge). Option A confuses orange with the yellow general-warning color, and pedestrian/school warnings use fluorescent yellow-green, not orange.","handbook":"Among warning categories, standard general warnings are yellow while construction/work zone warnings are orange, distinguishing the two hazard types by color.","hbref":"Sign Colors","qid":"DL-ROADSIGNS-TRAP-038"},{"q":"You are driving on an unfamiliar two-lane road at dusk. The center line marking between your lane and the lane to your left is a solid YELLOW line. What does this color tell you about the traffic in the lane to your left?","options":["It is a turn lane that traffic may use from either direction","It is the paved shoulder, so no through traffic uses it","It carries traffic moving in the opposite direction to yours","It carries traffic moving in the same direction as yours"],"answer":2,"explanation":"Yellow lines separate traffic moving in opposite directions, so the yellow center line means the lane to your left carries oncoming traffic. White lines (option D) would indicate traffic moving in the same direction, which is the trap here.","handbook":"Line color indicates direction of traffic flow: yellow for opposing directions and white for same direction, which is the foundational rule for reading pavement markings.","hbref":"Pavement Markings","qid":"DL-ROADSIGNS-TRAP-039"},{"q":"Driving through an unfamiliar town at dusk, you approach a roadside sign you can see clearly but whose words are not yet readable. It is a tall vertical rectangle with a plain white background and black lettering. Before you can even read it, what does the sign's shape and color tell you about its purpose?","options":["It is a guide sign giving directions, distances, or services ahead","It is a warning sign alerting you to a hazard or changing condition ahead","It is a construction sign marking an active work zone","It is a regulatory sign stating a law you are required to obey"],"answer":3,"explanation":"A vertical rectangle that is white with black lettering is a regulatory sign, meaning it states a law (such as a speed limit) that you must obey. Guide signs are green or horizontal rectangles, warning signs are yellow diamonds, and construction signs are orange, so those choices misread the white-and-black vertical rectangle.","handbook":"Sign shape and color combine to identify a sign's purpose; for example a regulatory law sign is conveyed by white-with-black coloring and a vertical rectangle shape.","hbref":"Common Specific Signs","qid":"DL-ROADSIGNS-TRAP-040"}]},{"id":"learn-road-signs","name":"Road Signs — Learn","blurb":"Texas DL Road Signs: practice tests plus a Learning Test that walks the whole handbook section.","accent":"#0a7c43","kind":"learn","learnSubject":"road-signs","classes":["DL"],"questions":[{"q":"What shape is a STOP sign?","options":["Octagon (8 sides)","Diamond","Circle","Vertical rectangle"],"answer":0,"explanation":"A STOP sign is the only octagonal (8-sided) sign and requires a full stop.","handbook":"An octagon (8-sided) sign means STOP; it is the only octagonal sign and requires a full stop.","hbref":"Sign Shapes","qid":"DL-ROADSIGNS-LRN-001"},{"q":"What does an upside-down (inverted) triangle sign mean?","options":["Stop","Yield","No passing","School zone"],"answer":1,"explanation":"An inverted triangle means YIELD, so give the right of way and slow or stop if needed.","handbook":"An inverted (upside-down) triangle means YIELD; give the right of way and slow or stop if needed.","hbref":"Sign Shapes","qid":"DL-ROADSIGNS-LRN-002"},{"q":"What does a pennant sign (a horizontal triangle on the left side of the road) mean?","options":["School zone ahead","Stop completely","No Passing Zone","Railroad crossing"],"answer":2,"explanation":"A pennant, a horizontal triangle placed on the left side of the road, marks a No Passing Zone.","handbook":"A pennant (horizontal triangle on the LEFT side of the road) marks a No Passing Zone.","hbref":"Sign Shapes","qid":"DL-ROADSIGNS-LRN-003"},{"q":"What does a diamond-shaped sign tell you?","options":["You must come to a full stop","You are entering a one-way street","You have reached the speed limit","There is a hazard or condition ahead"],"answer":3,"explanation":"A diamond-shaped sign is a warning sign that indicates a hazard or condition ahead.","handbook":"A diamond-shaped sign is a Warning sign indicating a hazard or condition ahead.","hbref":"Sign Shapes","qid":"DL-ROADSIGNS-LRN-004"},{"q":"What does a pentagon-shaped sign (5 sides, point up) mark?","options":["A school zone or school crossing","A railroad crossing","A no passing zone","A stop intersection"],"answer":0,"explanation":"A pentagon (5 sides, point up) marks a school zone or school crossing.","handbook":"A pentagon (5 sides, point up) marks a school zone or school crossing.","hbref":"Sign Shapes","qid":"DL-ROADSIGNS-LRN-005"},{"q":"What does a round (circular) road sign warn you about?","options":["A school zone ahead","A railroad crossing ahead","A no-passing zone","A construction zone"],"answer":1,"explanation":"A round (circular) sign is an advance warning that a railroad crossing is ahead.","handbook":"A round (circular) sign is a railroad crossing advance warning.","hbref":"Sign Shapes","qid":"DL-ROADSIGNS-LRN-006"},{"q":"What does a crossbuck (X-shaped) sign mean?","options":["Stop completely","Construction ahead","Railroad crossing; treat like a yield","School zone ahead"],"answer":2,"explanation":"A crossbuck (X shape) marks the railroad crossing itself and should be treated like a yield.","handbook":"A crossbuck (X shape) is located at the railroad crossing itself and should be treated like a yield.","hbref":"Sign Shapes","qid":"DL-ROADSIGNS-LRN-007"},{"q":"What does a vertical rectangle sign mean?","options":["Warning of a hazard ahead","School zone crossing","Railroad crossing ahead","A regulatory law you must obey"],"answer":3,"explanation":"A vertical rectangle is a regulatory sign indicating a law you must obey, such as a speed limit.","handbook":"A vertical rectangle is a regulatory sign indicating a law you must obey, such as a speed limit.","hbref":"Sign Shapes","qid":"DL-ROADSIGNS-LRN-008"},{"q":"What type of sign is a horizontal rectangle?","options":["A guide or information sign with directions and distances","A stop sign","A warning sign for a hazard ahead","A school zone sign"],"answer":0,"explanation":"A horizontal rectangle is a guide or information sign that gives directions and distances.","handbook":"A horizontal rectangle is a guide or information sign giving directions and distances.","hbref":"Sign Shapes","qid":"DL-ROADSIGNS-LRN-009"},{"q":"Which sign shape is used only for STOP?","options":["Diamond","Octagon","Triangle","Rectangle"],"answer":1,"explanation":"The octagon (8 sides) is the only sign shape reserved exclusively for STOP.","handbook":"The octagon is the only sign shape reserved exclusively for STOP.","hbref":"Sign Shapes","qid":"DL-ROADSIGNS-LRN-010"},{"q":"What does the color red mean on a traffic sign?","options":["Construction zone","Motorist services","Stop, yield, or prohibited","General warning"],"answer":2,"explanation":"Red is used on STOP, YIELD, DO NOT ENTER, and WRONG WAY signs to mean stop, yield, or prohibited.","handbook":"Red signifies stop, yield, or prohibited (used on STOP, YIELD, DO NOT ENTER, and WRONG WAY signs).","hbref":"Sign Colors","qid":"DL-ROADSIGNS-LRN-011"},{"q":"What does a yellow road sign mean?","options":["Construction zone ahead","Stop or do not enter","Motorist services nearby","General warning ahead"],"answer":3,"explanation":"Yellow signals a general warning, such as a curve, hill, merge, or signal ahead.","handbook":"Yellow signifies a general warning, such as a curve, hill, merge, or signal ahead.","hbref":"Sign Colors","qid":"DL-ROADSIGNS-LRN-012"},{"q":"What does an orange road sign mean?","options":["Construction or work zone","Stop or yield","Motorist services","Recreation area"],"answer":0,"explanation":"Orange signs warn of construction or a work zone ahead.","handbook":"Orange signifies construction or a work zone.","hbref":"Sign Colors","qid":"DL-ROADSIGNS-LRN-013"},{"q":"What does a green road sign mean?","options":["Stop or yield","Guide and directions","Construction zone","General warning"],"answer":1,"explanation":"Green signs give guide information like directions and distances.","handbook":"Green signifies guide information: permitted movements, directions, and distances.","hbref":"Sign Colors","qid":"DL-ROADSIGNS-LRN-014"},{"q":"What does a blue road sign mean?","options":["Construction zone ahead","Stop or yield","Motorist services like gas and food","Recreation areas"],"answer":2,"explanation":"Blue signs show motorist services such as gas, food, lodging, and hospital.","handbook":"Blue signifies motorist services such as gas, food, lodging, and hospital.","hbref":"Sign Colors","qid":"DL-ROADSIGNS-LRN-015"},{"q":"What color road sign marks recreation, cultural, or scenic areas?","options":["Blue","Green","Yellow","Brown"],"answer":3,"explanation":"Brown signs mark recreation, cultural, or scenic areas.","handbook":"Brown signifies recreation, cultural, or scenic areas.","hbref":"Sign Colors","qid":"DL-ROADSIGNS-LRN-016"},{"q":"What does a white sign with black letters mean?","options":["Regulatory, such as a speed limit","Construction or work zone","Recreation or scenic area","General warning ahead"],"answer":0,"explanation":"A white sign with black letters is regulatory, such as a speed limit or lane use sign.","handbook":"White (with black) signifies a regulatory sign such as a speed limit or lane use sign.","hbref":"Sign Colors","qid":"DL-ROADSIGNS-LRN-017"},{"q":"What does a fluorescent yellow-green sign warn about?","options":["Construction work zones","Pedestrian, bicycle, and school areas","Motorist services like gas and food","Recreation and scenic areas"],"answer":1,"explanation":"Fluorescent yellow-green signs warn of pedestrian, bicycle, and school crossings.","handbook":"Fluorescent yellow-green signifies pedestrian, bicycle, and school warnings.","hbref":"Sign Colors","qid":"DL-ROADSIGNS-LRN-018"},{"q":"What color is a WRONG WAY sign?","options":["Yellow","Green","Red","Blue"],"answer":2,"explanation":"A WRONG WAY sign is red, signaling you must not proceed.","handbook":"A WRONG WAY sign is red, signaling you must not proceed.","hbref":"Sign Colors","qid":"DL-ROADSIGNS-LRN-019"},{"q":"What color is a merge warning sign?","options":["Orange","Blue","Green","Yellow"],"answer":3,"explanation":"Yellow is used for general warning signs, including merge signs.","handbook":"A merge warning sign uses yellow because it is a general warning.","hbref":"Sign Colors","qid":"DL-ROADSIGNS-LRN-020"},{"q":"What shape is a STOP sign?","options":["Octagon (8 sides)","Diamond","Circle","Square"],"answer":0,"explanation":"A STOP sign is a red octagon, the only sign with that shape.","handbook":"A STOP sign is a red octagon.","hbref":"Common Specific Signs","qid":"DL-ROADSIGNS-LRN-021"},{"q":"What color is a YIELD sign?","options":["Yellow and black","Red and white","Green and white","Blue and white"],"answer":1,"explanation":"A YIELD sign is a red-and-white inverted triangle.","handbook":"A YIELD sign is a red-and-white inverted triangle.","hbref":"Common Specific Signs","qid":"DL-ROADSIGNS-LRN-022"},{"q":"What color are DO NOT ENTER and WRONG WAY signs?","options":["Yellow","Green","Red","Blue"],"answer":2,"explanation":"DO NOT ENTER and WRONG WAY signs are red and mean do not proceed.","handbook":"DO NOT ENTER and WRONG WAY signs are red and mean do not proceed.","hbref":"Common Specific Signs","qid":"DL-ROADSIGNS-LRN-023"},{"q":"What does a ONE WAY sign tell you?","options":["Stop completely before turning","The road is closed ahead","Passing is allowed here","Travel only in the arrow's direction"],"answer":3,"explanation":"A ONE WAY sign means you may travel only in the direction the arrow points.","handbook":"A ONE WAY sign means you may travel only in the direction the arrow points.","hbref":"Common Specific Signs","qid":"DL-ROADSIGNS-LRN-024"},{"q":"What does a SPEED LIMIT sign show?","options":["The maximum legal speed in ideal conditions","The minimum speed you may never go below","A suggested speed for sharp curves","The speed only for nighttime driving"],"answer":0,"explanation":"A SPEED LIMIT sign is a white rectangle with black numbers showing the maximum legal speed in ideal conditions.","handbook":"A SPEED LIMIT sign is a white rectangle with black numbers showing the maximum legal speed in ideal conditions.","hbref":"Common Specific Signs","qid":"DL-ROADSIGNS-LRN-025"},{"q":"What design do regulatory \"No\" signs use?","options":["A yellow diamond","A red circle with a slash","A green rectangle","A blue square"],"answer":1,"explanation":"Regulatory \"No\" signs, such as no U-turn or no left turn, use a red circle with a slash.","handbook":"Regulatory 'No' signs (such as no U-turn or no left turn) use a red circle with a slash.","hbref":"Common Specific Signs","qid":"DL-ROADSIGNS-LRN-026"},{"q":"What does the number on a SPEED LIMIT sign mean?","options":["The minimum legal speed","The average traffic speed","The maximum legal speed","The recommended speed for trucks"],"answer":2,"explanation":"The number on a SPEED LIMIT sign is the maximum legal speed under ideal conditions.","handbook":"The number on a SPEED LIMIT sign indicates the maximum, not minimum, legal speed.","hbref":"Common Specific Signs","qid":"DL-ROADSIGNS-LRN-027"},{"q":"What does the posted speed limit show?","options":["The slowest you may ever drive","The speed for any weather","A speed only at night","The maximum for ideal conditions"],"answer":3,"explanation":"The posted speed limit is the maximum for ideal conditions, so drive slower in poor conditions.","handbook":"The posted speed limit applies to ideal conditions; you must drive slower in poor conditions.","hbref":"Common Specific Signs","qid":"DL-ROADSIGNS-LRN-028"},{"q":"What do yellow lines on the road separate?","options":["Traffic moving in opposite directions","Traffic moving in the same direction","Parking spaces","Bicycle lanes"],"answer":0,"explanation":"Yellow lines separate traffic moving in opposite directions.","handbook":"Yellow lines separate traffic moving in OPPOSITE directions.","hbref":"Pavement Markings","qid":"DL-ROADSIGNS-LRN-029"},{"q":"What do white lines on the road show?","options":["A school zone ahead","Traffic moving in the same direction","Traffic moving in opposite directions","A no passing zone"],"answer":1,"explanation":"White lines separate lanes of traffic moving in the same direction and mark the road edge.","handbook":"White lines separate traffic moving in the SAME direction and mark the road edge.","hbref":"Pavement Markings","qid":"DL-ROADSIGNS-LRN-030"},{"q":"What does a solid yellow line on your side of the road mean?","options":["Passing is allowed","Road ends ahead","No passing","One-way street"],"answer":2,"explanation":"A solid yellow line on your side means you may not pass.","handbook":"A solid yellow line on YOUR side of the road means no passing.","hbref":"Pavement Markings","qid":"DL-ROADSIGNS-LRN-031"},{"q":"What does a broken (dashed) yellow line mean?","options":["Never cross this line","No passing in either direction","This marks the road edge","Passing is allowed when the way is clear"],"answer":3,"explanation":"A broken (dashed) yellow line means passing is allowed when the way is clear.","handbook":"A broken (dashed) yellow line means passing is allowed when the way is clear.","hbref":"Pavement Markings","qid":"DL-ROADSIGNS-LRN-032"},{"q":"What does a double solid yellow line mean?","options":["No passing in either direction","Passing allowed both ways","Lanes go the same direction","Road edge ahead"],"answer":0,"explanation":"A double solid yellow line means no passing in either direction; do not cross except to turn.","handbook":"A double solid yellow line means no passing in either direction; do not cross except to turn.","hbref":"Pavement Markings","qid":"DL-ROADSIGNS-LRN-033"},{"q":"What does a solid white line on the road mean?","options":["Passing is allowed","Lane changes are discouraged","Traffic moves in opposite directions","You must stop"],"answer":1,"explanation":"A solid white line discourages lane changes.","handbook":"A solid white line discourages lane changes.","hbref":"Pavement Markings","qid":"DL-ROADSIGNS-LRN-034"},{"q":"What does a broken white line allow you to do?","options":["Stop completely","Pass oncoming traffic","Change lanes","Never cross it"],"answer":2,"explanation":"A broken white line separates lanes going the same way and allows lane changes.","handbook":"A broken white line allows lane changes.","hbref":"Pavement Markings","qid":"DL-ROADSIGNS-LRN-035"},{"q":"What do white lines on the pavement mark?","options":["A railroad crossing","A school zone ahead","Traffic moving in opposite directions","The edge of the road"],"answer":3,"explanation":"White lines mark the edge of the road and separate traffic moving in the same direction.","handbook":"White lines mark the edge of the road.","hbref":"Pavement Markings","qid":"DL-ROADSIGNS-LRN-036"},{"q":"What color are the lines that separate lanes of traffic going the same direction?","options":["White","Yellow","Red","Blue"],"answer":0,"explanation":"White lines separate traffic moving in the same direction, while yellow lines separate opposite directions.","handbook":"Lane lines separating traffic going the same direction are white, not yellow.","hbref":"Pavement Markings","qid":"DL-ROADSIGNS-LRN-037"},{"q":"What must you do at a steady red traffic light?","options":["Slow down and keep going","Stop completely behind the line","Speed up to clear the intersection","Honk and proceed"],"answer":1,"explanation":"A steady red light means you must stop completely behind the line and remain stopped.","handbook":"A steady RED light means stop completely behind the line and remain stopped.","hbref":"Traffic Signals","qid":"DL-ROADSIGNS-LRN-038"},{"q":"When may you turn right at a steady red light?","options":["Never, at any time","Without stopping first","After a full stop, unless a sign prohibits it","Only when an arrow is showing"],"answer":2,"explanation":"At a steady red light you may turn right after coming to a full stop, unless a sign prohibits it.","handbook":"A right turn on a steady red light is allowed after a full stop unless a sign prohibits it.","hbref":"Traffic Signals","qid":"DL-ROADSIGNS-LRN-039"},{"q":"What does a steady yellow traffic light mean?","options":["Speed up to beat the red light","The light is broken; go anytime","Stop only if a car is behind you","The light is about to turn red; stop if safe"],"answer":3,"explanation":"A steady yellow light warns that the signal is about to turn red, so stop if you can do so safely.","handbook":"A steady YELLOW light means the light is about to turn red; stop if you can do so safely.","hbref":"Traffic Signals","qid":"DL-ROADSIGNS-LRN-040"},{"q":"What does a steady GREEN traffic light mean?","options":["Go if the way is clear","Stop completely","Slow down and prepare to stop","Make a protected turn only"],"answer":0,"explanation":"A steady green light means you may go if the way is clear.","handbook":"A steady GREEN light means go if the way is clear.","hbref":"Traffic Signals","qid":"DL-ROADSIGNS-LRN-041"},{"q":"At a steady green light, who must you yield to when turning?","options":["No one","Pedestrians and oncoming traffic","Only parked cars","Traffic behind you"],"answer":1,"explanation":"At a steady green light, you must yield to pedestrians and oncoming traffic when turning.","handbook":"When turning at a steady green light, you must yield to pedestrians and oncoming traffic.","hbref":"Traffic Signals","qid":"DL-ROADSIGNS-LRN-042"},{"q":"How should you treat a flashing red traffic light?","options":["Like a green light","Like a yield sign","Like a stop sign","Like a yellow light"],"answer":2,"explanation":"A flashing red light means you must stop completely, just like at a stop sign.","handbook":"A flashing RED light should be treated as a STOP sign.","hbref":"Traffic Signals","qid":"DL-ROADSIGNS-LRN-043"},{"q":"What does a flashing yellow traffic light mean?","options":["Come to a full stop","Speed up to clear the intersection","The light is broken, do not move","Slow down and proceed with caution"],"answer":3,"explanation":"A flashing yellow light means slow down and proceed with caution.","handbook":"A flashing YELLOW light means slow down and proceed with caution.","hbref":"Traffic Signals","qid":"DL-ROADSIGNS-LRN-044"},{"q":"What does a green arrow traffic signal mean?","options":["A protected turn in the arrow's direction","No turn in that direction","Stop before turning","Slow down and use caution"],"answer":0,"explanation":"A green arrow means a protected turn in the direction the arrow points.","handbook":"A green arrow means a protected turn in the direction the arrow points.","hbref":"Traffic Signals","qid":"DL-ROADSIGNS-LRN-045"},{"q":"What does a red arrow signal mean?","options":["Turn quickly in that direction","No turn is permitted in that direction","Yield before turning","Turn only after stopping"],"answer":1,"explanation":"A red arrow means you may not turn in that direction.","handbook":"A red arrow means no turn is permitted in that direction.","hbref":"Traffic Signals","qid":"DL-ROADSIGNS-LRN-046"},{"q":"How should you treat a dark or non-working traffic signal?","options":["Drive through without stopping","Treat it as a yield sign","Treat it as an all-way stop","Speed up to clear the intersection"],"answer":2,"explanation":"A dark or non-working signal should be treated as an all-way stop.","handbook":"A dark or non-working signal should be treated as an all-way STOP.","hbref":"Traffic Signals","qid":"DL-ROADSIGNS-LRN-047"},{"q":"What shape is a STOP sign?","options":["Diamond","Round","Triangle","Octagon"],"answer":3,"explanation":"A STOP sign is the only octagonal (8-sided) sign, so its shape alone tells you to stop.","handbook":"Shape alone tells you the sign type, even before reading any text.","hbref":"Sign Shapes","qid":"DL-ROADSIGNS-LRN-048"},{"q":"What color is a speed limit sign?","options":["White with black lettering","Yellow with black lettering","Red with white lettering","Green with white lettering"],"answer":0,"explanation":"A speed limit sign is white with black lettering because it is regulatory, not a warning.","handbook":"A speed limit sign is white with black lettering because it is regulatory, not a warning.","hbref":"Sign Colors","qid":"DL-ROADSIGNS-LRN-049"},{"q":"What color is a scenic area sign?","options":["Blue","Brown","Green","Yellow"],"answer":1,"explanation":"Brown signs mark recreation, cultural, and scenic areas.","handbook":"A scenic area sign is brown because brown denotes recreation, cultural, and scenic areas.","hbref":"Sign Colors","qid":"DL-ROADSIGNS-LRN-050"},{"q":"What color are signs for motorist services like hospitals and food?","options":["Red","Green","Blue","Brown"],"answer":2,"explanation":"Blue signs show motorist services such as gas, food, lodging, and hospitals.","handbook":"A hospital or food services sign is blue because blue denotes motorist services.","hbref":"Sign Colors","qid":"DL-ROADSIGNS-LRN-051"},{"q":"What color is a work zone or construction sign?","options":["Yellow","Green","Blue","Orange"],"answer":3,"explanation":"Work zone and construction signs are orange, which sets them apart from yellow general-warning signs.","handbook":"A work zone or construction sign is orange, distinguishing it from yellow general-warning signs.","hbref":"Sign Colors","qid":"DL-ROADSIGNS-LRN-052"},{"q":"What color is a school crossing warning sign?","options":["Fluorescent yellow-green","Blue","Brown","Orange"],"answer":0,"explanation":"Fluorescent yellow-green is the color for pedestrian, bicycle, and school warnings.","handbook":"A school crossing warning may use fluorescent yellow-green, the color for pedestrian, bicycle, and school warnings.","hbref":"Sign Colors","qid":"DL-ROADSIGNS-LRN-053"},{"q":"What color do STOP, YIELD, DO NOT ENTER, and WRONG WAY signs share?","options":["Yellow","Red","Green","Blue"],"answer":1,"explanation":"Red is the color shared by STOP, YIELD, DO NOT ENTER, and WRONG WAY signs.","handbook":"Red is the color shared by STOP, YIELD, DO NOT ENTER, and WRONG WAY signs.","hbref":"Common Specific Signs","qid":"DL-ROADSIGNS-LRN-054"},{"q":"When may you cross a double solid yellow line?","options":["To pass another car","Anytime it is clear","Only to turn","Never for any reason"],"answer":2,"explanation":"A double solid yellow line may be crossed only to turn, not to pass.","handbook":"A double solid yellow line may be crossed only to turn, not to pass.","hbref":"Pavement Markings","qid":"DL-ROADSIGNS-LRN-055"},{"q":"What does a green arrow traffic signal mean?","options":["Stop and wait for traffic","Slow down and yield","No turn allowed","A protected turn with oncoming traffic stopped"],"answer":3,"explanation":"A green arrow gives a protected turn because oncoming traffic is stopped during that movement.","handbook":"A green arrow provides a protected turn, meaning oncoming traffic is stopped during that movement.","hbref":"Traffic Signals","qid":"DL-ROADSIGNS-LRN-056"},{"q":"What does a broken yellow line on your side of the road mean?","options":["Passing is allowed when the road ahead is clear","Passing is never allowed","You must stop","The road is one way"],"answer":0,"explanation":"A broken yellow line on your side means you may pass when the road ahead is clear.","handbook":"When there is a broken yellow line on your side, passing is permitted only when the road ahead is clear.","hbref":"Pavement Markings","qid":"DL-ROADSIGNS-LRN-057"},{"q":"What shape is the railroad crossing advance-warning sign?","options":["Diamond","Round","Octagon","Crossbuck (X shape)"],"answer":1,"explanation":"The railroad advance-warning sign is round, while the sign at the crossing itself is a crossbuck.","handbook":"The railroad advance-warning sign is round, while the sign at the crossing itself is a crossbuck.","hbref":"Sign Shapes","qid":"DL-ROADSIGNS-LRN-058"},{"q":"What must you do at a flashing red traffic light?","options":["Slow down and keep going","Speed up to clear it","Come to a complete stop","Ignore it if clear"],"answer":2,"explanation":"A flashing red light means come to a complete stop, just like at a STOP sign.","handbook":"At a flashing red light you must come to a complete stop before proceeding, just as at a STOP sign.","hbref":"Traffic Signals","qid":"DL-ROADSIGNS-LRN-059"},{"q":"What does a red circle and slash over a left-turn arrow mean?","options":["Left turn only","Left lane ends","Left turn ahead","No left turn"],"answer":3,"explanation":"A red circle and slash over a left-turn arrow means no left turn is allowed.","handbook":"A no left turn sign uses a red circle and slash over a left-turn arrow symbol.","hbref":"Common Specific Signs","qid":"DL-ROADSIGNS-LRN-060"}]},{"id":"rules-of-the-road","name":"Rules of the Road","blurb":"Texas DL Rules of the Road: practice tests plus a Learning Test that walks the whole handbook section.","accent":"#2563eb","kind":"core","classes":["DL"],"questions":[{"q":"You are driving on a rural Texas highway posted at 70 mph. A sudden, heavy fog rolls in and you can barely see two car lengths ahead. Under Texas law, what speed are you permitted to drive?","options":["Slower than 70 mph — a speed that is reasonable and safe for the fog, because the posted limit is the maximum for ideal conditions only","Up to 70 mph, because that is the legally posted limit and you may always drive the posted speed","Exactly 50 mph, because Texas law requires reducing speed by 20 mph whenever visibility is poor","Up to 75 mph, since rural Texas interstates allow 75 mph regardless of conditions"],"answer":0,"explanation":"Under Texas's prima facie (basic speed law), you must never drive faster than is reasonable and safe for existing conditions, so in heavy fog you must slow well below the posted 70 mph. Driving the full posted limit (B) is the trap: the posted number is a maximum for good conditions, not a guarantee, and the 20-mph and 75-mph figures (C, D) are real rules pulled into the wrong context.","handbook":"Texas uses the prima facie (basic speed law): you must never drive faster than is reasonable and safe for existing conditions.","hbref":"Speed limits","qid":"DL-RULESOFTHEROAD-TRAP-001"},{"q":"You turn off a posted highway onto a residential street inside a city's urban district. You see no speed limit sign anywhere along the block. What speed should you assume is the legal maximum here?","options":["20 mph, because that is the default in any area where homes are present","30 mph, the common default limit for an urban district when no sign is posted","70 mph, since that is the default for highways and no other sign overrides it","There is no limit as long as you drive safely, because the sign is missing"],"answer":1,"explanation":"Where no sign is posted, the common default speed limit in an urban district is 30 mph, so you should treat 30 mph as the legal maximum. The 20 mph figure is the typical reduced limit for active school zones, not residential streets generally, and 70 mph is the daytime default for numbered highways, not a city street.","handbook":"Where unposted, the common default speed limit in an urban district is 30 mph.","hbref":"Speed limits","qid":"DL-RULESOFTHEROAD-TRAP-002"},{"q":"You are driving on a numbered Texas highway in the middle of the afternoon. Conditions are clear and dry, but you have not seen a single posted speed limit sign for several miles. What is the maximum speed you may legally drive under the basic speed law?","options":["75 mph, because that is the limit on all rural Texas highways","30 mph, because that is the default limit where signs are absent","70 mph, the default daytime limit on numbered highways","85 mph, the highest speed allowed anywhere in Texas"],"answer":2,"explanation":"Where no sign is posted, the default daytime limit on numbered highways in Texas is 70 mph. The 30 mph trap is the default for urban districts, not numbered highways, and 75 and 85 mph apply only to specific posted Interstates and tollways, not as a general default.","handbook":"Where unposted, the common default speed limit on numbered highways in daytime is 70 mph.","hbref":"Speed limits","qid":"DL-RULESOFTHEROAD-TRAP-003"},{"q":"You are driving on a rural Texas Interstate posted at 75 mph. After a few miles you transition onto a specific Texas tollway, and the posted signs now read 85 mph. Traffic is light, the pavement is dry, and visibility is clear. What is the maximum speed you may legally drive on this tollway stretch?","options":["70 mph, because that is the statewide daytime maximum for numbered highways","75 mph, because that was the limit on the Interstate you just left","80 mph, because Texas law caps all roadways at 80 mph","85 mph, because that is the speed posted on this specific tollway"],"answer":3,"explanation":"On Texas roads you may legally drive up to the posted speed limit when conditions are safe, and some specific Texas tollways are posted as high as 80 to 85 mph. The 70 and 75 mph options are real limits for other roads but do not override the higher posted sign on this tollway.","handbook":"Many rural Texas Interstates are posted at 75 mph, and some specific tollways are posted as high as 80 to 85 mph.","hbref":"Speed limits","qid":"DL-RULESOFTHEROAD-TRAP-004"},{"q":"You're driving past an elementary school at 7:45 a.m. The posted school-zone sign reads '20 MPH WHEN FLASHING,' and the yellow beacons on it are blinking. What is the correct speed to drive here?","options":["20 mph, because you must obey the posted reduced school-zone limit while the lights are flashing","30 mph, the default urban speed limit, since the school zone speed only applies to the curb lane","Any safe speed under the regular limit, because flashing beacons are only a warning, not a law","70 mph, the daytime highway limit, since the reduced limit applies only after children exit the building"],"answer":0,"explanation":"When school-zone lights are flashing (or children are present), you must obey the posted reduced limit, typically 20 mph. The 30 mph default applies only on ordinary urban streets without a posted school-zone sign, so it is the wrong limit here.","handbook":"In a school zone, obey the posted reduced limit (often 20 mph) when the lights flash or children are present.","hbref":"Speed limits","qid":"DL-RULESOFTHEROAD-TRAP-005"},{"q":"You are driving past an elementary school in the morning. The school-zone lights are flashing and children are on the sidewalk. Your phone rings with a call from work. What does Texas law require you to do?","options":["Answer the call, since the school-zone speed limit only restricts how fast you may drive","Leave the handheld phone alone, because using a handheld phone is illegal in an active school zone","Answer the call but slow to 20 mph below the posted limit while talking","Pull over within 15 feet of the school crosswalk to take the call safely"],"answer":1,"explanation":"In an active school zone (lights flashing or children present), Texas law prohibits using a handheld phone, so you must not answer the call. Option A is wrong because the rule covers phone use, not just speed; the 20-mph-below figure in C is the Move Over/Slow Down rule for stopped emergency vehicles, not school zones.","handbook":"Using a handheld phone is illegal in an active school zone.","hbref":"Speed limits","qid":"DL-RULESOFTHEROAD-TRAP-006"},{"q":"You are driving on a two-lane road at the posted 55 mph limit when a thick fog rolls in and visibility drops sharply. What should you do?","options":["Maintain 55 mph since that is the legal posted limit and you have the right to drive it","Turn on your high-beam headlights and keep your current speed to see farther ahead","Reduce your speed below the posted limit to match the reduced visibility and road conditions","Pull onto the right shoulder and park there until the fog completely clears"],"answer":2,"explanation":"Texas's basic speed law requires you to never drive faster than is safe for conditions, so you must slow below the posted limit in fog. Keeping 55 mph (A) ignores that the posted number is only a maximum for ideal conditions, and high beams (B) actually reflect off fog and worsen visibility.","handbook":"You should always reduce speed in rain, fog, heavy traffic, curves, and near pedestrians.","hbref":"Speed limits","qid":"DL-RULESOFTHEROAD-TRAP-007"},{"q":"You roll up to a quiet residential intersection with no stop signs, yield signs, or traffic lights in any direction. A pickup truck on the cross street clearly reached the intersection a couple of seconds before you did and is waiting to proceed straight through. What should you do?","options":["Proceed first, because the truck must yield to the vehicle on its right","Proceed first, because traffic on the through road has the right of way","Both of you should treat it as an all-way stop and you go if you are on the right","Yield to the pickup truck and let it go through first, because it arrived at the intersection before you"],"answer":3,"explanation":"At an uncontrolled intersection, you must yield to the vehicle that arrived first, so the pickup truck goes through before you. The 'yield to the driver on your right' rule only applies when two vehicles reach the intersection at the same time, which is not the case here.","handbook":"At an uncontrolled intersection, yield to the vehicle that arrived first.","hbref":"Right-of-way","qid":"DL-RULESOFTHEROAD-TRAP-008"},{"q":"You roll up to a neighborhood intersection that has no stop signs, yield signs, or traffic lights in any direction. Another car reaches the intersection from your right at exactly the same moment you do, and both of you intend to go straight through. What should you do?","options":["Let the car on your right go first, then proceed once it has cleared the intersection.","Go first, because the vehicle on the right is required to yield to the vehicle on the left.","Proceed immediately, since the driver who is going straight always has the right of way over one turning.","Both of you should stop fully and wait, because an uncontrolled intersection is treated the same as an all-way stop."],"answer":0,"explanation":"At an uncontrolled intersection where two vehicles arrive at the same time, you must yield to the driver on your right. The car is on your right, so it goes first; the idea that the left vehicle has priority or that you must treat it as an all-way stop is incorrect.","handbook":"At an uncontrolled intersection, if two vehicles arrive at the same time, yield to the driver on your right.","hbref":"Right-of-way","qid":"DL-RULESOFTHEROAD-TRAP-009"},{"q":"You are stopped at a green light waiting to turn left at an intersection. A car is approaching from the opposite direction going straight, and a pedestrian is starting to cross the street you want to turn onto. What must you do before completing your left turn?","options":["Turn quickly before the oncoming car arrives, since the green light gives you the right of way","Yield to both the oncoming car and the pedestrian, then complete your turn when it is safe","Yield only to the oncoming car, because pedestrians must wait for vehicles to clear the intersection","Proceed first because the driver on your right must yield to you"],"answer":1,"explanation":"When making a left turn you must yield to oncoming traffic and to pedestrians, so you wait for both the approaching car and the crossing pedestrian before turning. A green light does not give a left-turning driver priority over oncoming traffic, and pedestrians in a crosswalk always have the right of way.","handbook":"When making a left turn, you must yield to oncoming traffic and to pedestrians.","hbref":"Right-of-way","qid":"DL-RULESOFTHEROAD-TRAP-010"},{"q":"You are driving on a residential street that dead-ends into a busy through street, forming a T-intersection. There are no stop signs, traffic signals, or other controls at the junction. As you reach the top of your street, a car is approaching from your left on the through street. What should you do?","options":["Proceed first, because at an uncontrolled intersection the vehicle on the right always has the right of way","Proceed first, because the car on the through street must yield to traffic entering from a side road","Yield to the car on the through street, because traffic on the through road (the top of the T) has the right of way","Yield only if the other car signals a turn, otherwise you may enter the intersection first"],"answer":2,"explanation":"At a T-intersection, the road that ends (the stem of the T) must yield to traffic on the through road that forms the top of the T, so you wait for the approaching car. The right-on-arrival rule applies only to vehicles arriving together at an equal, uncontrolled crossing, not to a side road meeting a through road.","handbook":"At a T-intersection, traffic on the through road (the top of the T) has the right of way.","hbref":"Right-of-way","qid":"DL-RULESOFTHEROAD-TRAP-011"},{"q":"You approach a single-lane roundabout in Texas with two cars already traveling around the circle to your left. What should you do to enter correctly and safely?","options":["Enter immediately and turn left (clockwise), since traffic in the circle must yield to vehicles entering","Come to a complete stop and wait for all traffic in the circle to exit before entering","Yield to the cars in the circle, then enter to the left (clockwise) when there is a gap","Yield to the cars already in the circle, then enter to the right (counter-clockwise) when there is a gap"],"answer":3,"explanation":"At a roundabout you must yield to traffic already in the circle and enter to the right, traveling counter-clockwise. Option C uses the correct yield rule but the wrong direction, and you do not need a full stop or to wait for the circle to empty if a safe gap is available.","handbook":"At a roundabout, yield to traffic already in the circle and enter to the right (counter-clockwise).","hbref":"Right-of-way","qid":"DL-RULESOFTHEROAD-TRAP-012"},{"q":"You are driving in the right lane of a two-lane, one-way city street when you hear a siren and see an ambulance approaching from behind with its emergency lights flashing. There is open curb space to your right. What should you do?","options":["Pull over to the right and come to a stop until the ambulance has passed.","Maintain your speed and stay in your lane so the ambulance can pass you on the left.","Move over one lane or slow to 20 mph below the speed limit, then keep driving.","Speed up to clear the intersection ahead before the ambulance reaches you."],"answer":0,"explanation":"When an emergency vehicle approaches with lights and siren, you must pull over to the right and stop until it passes. Option C describes the separate Move Over/Slow Down law for stopped emergency vehicles on the roadside, not for an emergency vehicle responding behind you, and the other choices fail to yield.","handbook":"For an emergency vehicle with lights/siren, pull over to the right and stop until it passes.","hbref":"Right-of-way","qid":"DL-RULESOFTHEROAD-TRAP-013"},{"q":"You are stopped at a green light, waiting to make a right turn at a busy intersection in Houston. A pedestrian has just stepped off the curb and is walking across the crosswalk into the lane you want to turn onto. What must you do?","options":["Make your turn quickly before the pedestrian reaches your path, since you have a green light","Yield to the pedestrian in the crosswalk and wait until they have safely cleared your path","Proceed if you sound your horn first to warn the pedestrian to hurry","Edge forward into the crosswalk so the pedestrian knows to walk behind your vehicle"],"answer":1,"explanation":"Pedestrians in a crosswalk always have the right of way, so you must yield and wait until they have safely cleared your path before turning, even on a green light. Having a green signal does not allow you to turn through a pedestrian who is already lawfully crossing, and honking or edging forward does not transfer that right of way to you.","handbook":"Pedestrians in a crosswalk always have the right of way.","hbref":"Right-of-way","qid":"DL-RULESOFTHEROAD-TRAP-014"},{"q":"You are stopped at a green light, waiting to make a right turn. A pedestrian wearing dark glasses steps off the curb into the crosswalk, sweeping a white cane in front of them and clearly heading across your path. What must you do?","options":["Proceed slowly through the turn, since a green light gives your vehicle the right of way over crossing pedestrians","Tap your horn to warn the pedestrian, then complete your right turn before they reach your lane","Come to a full stop and yield, allowing the pedestrian with the white cane to cross safely before you turn","Wait only if the pedestrian is already in your lane, otherwise turn around the front of them"],"answer":2,"explanation":"Texas law requires drivers to yield to a blind pedestrian using a white cane or guide dog, and pedestrians in a crosswalk always have the right of way. A green light does not override your duty to yield to a pedestrian lawfully in the crosswalk, so you must stop and let them cross.","handbook":"You must yield to a blind pedestrian using a white cane or guide dog.","hbref":"Right-of-way","qid":"DL-RULESOFTHEROAD-TRAP-015"},{"q":"You approach a green light at an intersection and are about to drive straight through. From the cross street, a line of cars with their headlights on and small flags follows a hearse, slowly entering the intersection against their red light as part of a funeral procession. What should you do?","options":["Proceed through on your green light, since the procession faces a red signal and must stop for you","Honk and edge forward to claim your turn, then merge into a gap between the procession vehicles","Pull over to the right and stop completely until the entire procession has passed, as you would for an emergency vehicle","Yield and wait for the entire funeral procession to pass through the intersection before you proceed"],"answer":3,"explanation":"A funeral procession has the right of way at intersections, so you must yield and let the whole procession pass even though you have a green light. Proceeding on green ignores the procession's right of way, and pulling fully to the right is the rule for emergency vehicles with lights and siren, not a funeral procession.","handbook":"A funeral procession has the right of way at intersections.","hbref":"Right-of-way","qid":"DL-RULESOFTHEROAD-TRAP-016"},{"q":"You are driving on a city street and plan to turn right at the next intersection. You want to signal correctly so other drivers know your intentions in time. At what point should you begin signaling before the turn?","options":["At least 100 feet before the intersection where you will turn","At least 20 feet before the intersection where you will turn","Only after you have moved into the right lane near the curb","At least 30 feet before the intersection where you will turn"],"answer":0,"explanation":"Texas law requires you to signal at least 100 feet before making a turn or changing lanes so other drivers have enough warning. The 20-foot and 30-foot distances are real Texas rules (no parking within 20 feet of a crosswalk, 30 feet of a stop sign), but they do not apply to signaling for a turn.","handbook":"You must signal at least 100 feet before a turn or lane change.","hbref":"Turns & turning","qid":"DL-RULESOFTHEROAD-TRAP-017"},{"q":"You are driving on a two-lane, one-way street and need to turn right at the upcoming intersection. There is no sign restricting lane use for turns. Which lane should you be in, and where should your vehicle be positioned to make the turn correctly?","options":["In the left lane, staying close to the center line as you turn","In the right lane, close to the curb as you turn","In either lane, as long as you signal at least 100 feet before turning","In the right lane, but staying well away from the curb to allow room for cyclists"],"answer":1,"explanation":"A right turn must be made from the right lane, keeping close to the curb. Option A describes the correct setup for a left turn, and signaling distance (Option C) does not change the lane and curb requirement for a right turn.","handbook":"Make a right turn from the right lane, close to the curb.","hbref":"Turns & turning","qid":"DL-RULESOFTHEROAD-TRAP-018"},{"q":"You are approaching an intersection on a two-way street and plan to turn left onto the cross street. There are two lanes going in your direction. To position your vehicle correctly for the turn, which lane should you move into before the intersection?","options":["The right lane, staying close to the curb","Either lane, as long as you signal at least 100 feet ahead","The left lane, nearest the center line","The center two-way left-turn lane, used for traveling up to the intersection"],"answer":2,"explanation":"A left turn must be made from the left lane, the one nearest the center line, so you cross the least amount of opposing traffic. The right lane is for right turns, and a two-way left-turn lane is only for turning, not for traveling up to an intersection on a two-way street with regular through lanes.","handbook":"Make a left turn from the left lane.","hbref":"Turns & turning","qid":"DL-RULESOFTHEROAD-TRAP-019"},{"q":"You stop completely at a red light in the right lane, intending to turn right. There is no sign at the intersection prohibiting a turn on red, and cross traffic is clear. What should you do?","options":["Wait for the light to turn green before turning, because right turns are never permitted on a red light.","Turn only after yielding to oncoming traffic in the opposite direction, the same as a left turn.","Turn without stopping, since the lane is already clear of cross traffic.","Proceed with the right turn after your full stop, since no sign prohibits it and traffic is clear."],"answer":3,"explanation":"In Texas, a right turn on red is allowed after coming to a full stop, unless a sign prohibits it; with no such sign and clear traffic, you may turn. Option C is wrong because a complete stop is always required first, and the oncoming-traffic yield in B applies to left turns, not a right turn on red.","handbook":"A right turn on red is allowed after a full stop, unless a sign prohibits it.","hbref":"Turns & turning","qid":"DL-RULESOFTHEROAD-TRAP-020"},{"q":"You are stopped at a red light on a one-way street, intending to turn left onto another one-way street whose traffic flows to the left. No sign at the intersection prohibits the turn. What may you legally do?","options":["Turn left after coming to a complete stop, once the way is clear","Turn left without stopping, since both streets are one-way","Wait for a green light, because left turns on red are never permitted in Texas","Turn left on red only if you are also coming from a two-way street"],"answer":0,"explanation":"A left turn on red is allowed only from a one-way street onto a one-way street, and only after a full stop when no sign prohibits it. You may not roll through without stopping (B), and the turn is permitted in Texas in this exact situation, so waiting for green is not required (C).","handbook":"A left turn on red is allowed only from a one-way street onto a one-way street, after a full stop.","hbref":"Turns & turning","qid":"DL-RULESOFTHEROAD-TRAP-021"},{"q":"You are driving in the middle lane of a three-lane one-way street and need to make a right turn at the upcoming intersection. From which lane should you complete the turn?","options":["From the middle lane, since you are already positioned in the center of the road","From the rightmost lane, the lane nearest the direction you are turning","From the leftmost lane, because all turns must begin from the left on a one-way street","From any lane, since lane position does not matter on a one-way street"],"answer":1,"explanation":"On a one-way street you turn from the lane nearest the direction you are turning, so a right turn must be made from the rightmost lane. Option C confuses this with the left-turn rule, and the left lane is correct only when turning left.","handbook":"On a one-way street, turn from the lane nearest the direction you are turning.","hbref":"Turns & turning","qid":"DL-RULESOFTHEROAD-TRAP-022"},{"q":"On a two-lane highway, you pull into the left lane to pass a slow truck. After accelerating past it, you want to merge back into the right lane. When is it safe to return to your lane?","options":["As soon as your front bumper clears the front of the truck","Only after the truck flashes its headlights to signal you back","Once you can see the passed truck in your rearview mirror","After you have traveled at least 100 feet beyond the truck"],"answer":2,"explanation":"You may return to your lane only when you can see the passed vehicle in your rearview mirror, which confirms you have enough space ahead of it to merge safely. Clearing only your front bumper (A) leaves too little room and could cut the truck off, and there is no rule about a 100-foot distance for merging back.","handbook":"Pass on the left, and return to your lane only when you can see the passed vehicle in your mirror.","hbref":"Passing & lane use","qid":"DL-RULESOFTHEROAD-TRAP-023"},{"q":"You are driving on a two-lane country road behind a slow tractor. As you approach the crest of a hill, the road ahead is hidden from view and you cannot see whether any vehicle is coming toward you. What should you do about passing the tractor?","options":["Pass quickly while on the hill, since the tractor is moving well below the speed limit","Pass on the right shoulder to avoid crossing into the oncoming lane","Pass now, but only after sounding your horn to warn any oncoming traffic","Do not pass; wait until you are past the hill and can clearly see the road ahead"],"answer":3,"explanation":"You must not pass on a hill where your view of oncoming traffic is blocked, so you should wait until you can see the road ahead clearly. Passing on the hill (A), sounding the horn (C), or using the right shoulder (B) are all unsafe and illegal because you still cannot verify the lane is clear and passing must be done on the left.","handbook":"Do not pass on a hill or curve, at an intersection or railroad crossing, where a solid yellow line is on your side, or in a No Passing Zone.","hbref":"Passing & lane use","qid":"DL-RULESOFTHEROAD-TRAP-024"},{"q":"You are driving on a two-lane rural highway behind a slow truck and want to pass. Up ahead on the right shoulder you notice a yellow, pennant-shaped (pointed triangle) sign. What does this sign tell you about passing?","options":["You are entering a No Passing Zone, so you must not pass the truck here","This is a Yield sign, so you may pass once oncoming traffic clears","It marks a two-way left-turn lane ahead that you may use to pass","It is a warning for a railroad crossing only, and passing is still allowed"],"answer":0,"explanation":"A pennant-shaped sign on the right side of the road marks the start of a No Passing Zone, so you must not pass here. A Yield sign is a downward-pointing triangle facing oncoming drivers, not a side-mounted pennant, which makes option B the trap.","handbook":"A No Passing Zone is marked with a pennant-shaped sign.","hbref":"Passing & lane use","qid":"DL-RULESOFTHEROAD-TRAP-025"},{"q":"You are driving in the left lane of a three-lane Texas freeway at the posted speed limit. A faster vehicle comes up behind you and wants to pass. What should you do?","options":["Maintain your speed and stay in the left lane, since you are already at the legal limit","Move into a lane to your right to let the faster vehicle pass, then keep right","Speed up above the limit so the vehicle behind no longer needs to pass","Stop in the left lane and wave the faster vehicle around you"],"answer":1,"explanation":"In Texas you must keep right except to pass, and slower traffic keeps right, so you should move into a lane to your right and let the faster vehicle pass. Staying in the left lane just because you are at the limit is wrong, and speeding up or stopping would create a hazard.","handbook":"Keep right except to pass; slower traffic keeps right.","hbref":"Passing & lane use","qid":"DL-RULESOFTHEROAD-TRAP-026"},{"q":"You are driving on an unfamiliar two-lane road at night. To your left, a solid yellow line runs alongside the lane carrying traffic, and you notice headlights of cars coming toward you on the other side of that line. What does this yellow center line tell you about the road?","options":["The lane on the other side is going in the same direction as you, so you may merge across whenever it is clear","The road is one-way, and the yellow line simply marks the far edge of the roadway","Traffic on the other side of the line is moving in the opposite direction toward you","The yellow line is only a shoulder marking, and there is no traffic lane beyond it"],"answer":2,"explanation":"Yellow center lines divide traffic moving in opposite directions, which is why you see oncoming headlights across that line. White lines (not yellow) separate lanes traveling the same direction, so options suggesting same-direction or one-way travel are wrong.","handbook":"Yellow center lines divide traffic moving in opposite directions.","hbref":"Passing & lane use","qid":"DL-RULESOFTHEROAD-TRAP-027"},{"q":"You are driving on a four-lane road and notice that the line separating your lane from the lane immediately to your left is solid white, while the line down the far center of the road is yellow. What does the white line between you and the lane on your left tell you about that adjacent lane?","options":["Traffic in that lane is moving in the opposite direction, so you must never cross into it","The lane to your left is a center two-way left-turn lane meant only for turning","You may freely change into that lane at any time because white lines are always advisory","Traffic in that lane is moving in the same direction as you"],"answer":3,"explanation":"White lines separate lanes of traffic traveling in the same direction, so the lane to your left carries traffic going your way. Yellow lines (option A) divide opposite-direction traffic and mark the center of the road, which is the trap here.","handbook":"White lines separate lanes of traffic going the same direction.","hbref":"Passing & lane use","qid":"DL-RULESOFTHEROAD-TRAP-028"},{"q":"Heavy traffic is backing up in your lane, so you steer into the center lane marked with left-turn arrows on both ends and drive forward in it for half a block to get past the slow cars. Why is this illegal?","options":["A two-way left-turn lane is reserved only for making left turns and cannot be used to travel through, even briefly.","You may travel in a center left-turn lane only if you stay in it for less than 200 feet.","The center lane is a passing lane, but you may only use it to pass on the right.","Driving in the center lane is allowed as long as you signal at least 100 feet beforehand."],"answer":0,"explanation":"A two-way left-turn lane (the center lane marked with arrows) is only for preparing to turn left, never for driving through traffic. Option B invents a distance allowance, and the 100-foot signal rule in D applies to turns and lane changes, not to using this lane for travel.","handbook":"A two-way left-turn lane (center lane marked with arrows) is only for turning left, not for travel.","hbref":"Passing & lane use","qid":"DL-RULESOFTHEROAD-TRAP-029"},{"q":"You approach a stop sign at an intersection. There is a clearly painted white stop line on the pavement a few feet before the crosswalk, but from there your view of cross traffic is partly blocked by a parked truck. What is the correct procedure?","options":["Roll slowly through the stop line and stop only once you can see cross traffic at the crosswalk","Come to a complete stop behind the stop line first, then edge forward and stop again if needed to see","Slow to about 5 mph at the line; a full stop is required only if another vehicle is present","Stop on the crosswalk itself so you have the best possible view of cross traffic"],"answer":1,"explanation":"Texas law requires a full stop at a stop sign behind the stop line or crosswalk, so you must stop there first even if your view is blocked, then creep forward and stop again to see. Rolling through the line, stopping on the crosswalk, or only slowing down all violate the stop-line requirement.","handbook":"Come to a full stop at a stop sign, behind the stop line or crosswalk.","hbref":"Stopping & parking","qid":"DL-RULESOFTHEROAD-TRAP-030"},{"q":"You are driving on a two-lane road with one lane in each direction and no median. Ahead of you, in your same direction, a school bus stops, turns on its flashing red lights, and extends its stop arm. What must you do?","options":["Slow to 20 mph below the speed limit and pass the bus carefully on the left","Continue at a reduced speed only if no children are visible near the bus","Come to a full stop and remain stopped until the red lights stop flashing and the stop arm is withdrawn","Stop only if you are behind the bus; oncoming traffic on this road may proceed"],"answer":2,"explanation":"On a road with no physical median or barrier, all traffic from both directions must stop for a school bus showing flashing red lights and an extended stop arm, and stay stopped until the lights stop and the arm folds in. Option D states the median exception, but here there is no median, so traffic from both directions must stop; the 20-mph-below rule in A applies to stopped emergency/utility vehicles, not school buses.","handbook":"You must stop for a stopped school bus with red lights flashing and stop arm out from both directions, unless separated by a physical median or barrier.","hbref":"Stopping & parking","qid":"DL-RULESOFTHEROAD-TRAP-031"},{"q":"You're running late and spot an open curb space on a busy downtown street. Just ahead of the space is a fire hydrant. To park legally, how far from the hydrant must you keep your vehicle?","options":["At least 30 feet, the same distance required from a stop sign or signal","At least 20 feet, the same distance required from a crosswalk at an intersection","It's fine to park right up to the hydrant as long as you don't block the sidewalk","At least 15 feet"],"answer":3,"explanation":"Texas law prohibits parking within 15 feet of a fire hydrant so firefighters can access it in an emergency. The 30-foot and 20-foot figures are real Texas distances, but they apply to stop signs/signals and crosswalks respectively, not hydrants.","handbook":"No parking within 15 feet of a fire hydrant.","hbref":"Stopping & parking","qid":"DL-RULESOFTHEROAD-TRAP-032"},{"q":"You are looking for a place to park along a busy downtown street near an intersection. There is a marked crosswalk where the side street meets the main road. To park legally, how far from that crosswalk must your vehicle stay?","options":["At least 20 feet from the crosswalk","At least 15 feet from the crosswalk","At least 30 feet from the crosswalk","At least 10 feet from the crosswalk"],"answer":0,"explanation":"Texas law prohibits parking within 20 feet of a crosswalk at an intersection so drivers turning into the street can see crossing pedestrians. The 15-foot figure is the no-parking distance for a fire hydrant, and 30 feet applies to a stop sign or signal, so both are real rules placed in the wrong situation.","handbook":"No parking within 20 feet of a crosswalk at an intersection.","hbref":"Stopping & parking","qid":"DL-RULESOFTHEROAD-TRAP-033"},{"q":"You are looking for a place to park on a busy downtown street. You spot an open stretch of curb right next to the corner where there is a stop sign. To park legally, how far back from that stop sign must your vehicle be?","options":["At least 15 feet","At least 30 feet","At least 20 feet","At least 50 feet"],"answer":1,"explanation":"In Texas you may not park within 30 feet of a stop sign or traffic signal so your vehicle does not block other drivers' view of it. The 15-foot rule applies to fire hydrants and the 20-foot rule to crosswalks at an intersection, so those distances are traps from other parking rules.","handbook":"No parking within 30 feet of a stop sign or signal.","hbref":"Stopping & parking","qid":"DL-RULESOFTHEROAD-TRAP-034"},{"q":"You're running late and want to leave your car for just a minute while you grab coffee. Looking around, you spot several open spots along the block. Which of these is a LEGAL place to park?","options":["Halfway across a marked crosswalk, since only part of your car sticks out","Directly in front of a residential driveway, because you'll only be gone a minute","Along the right-hand curb on your side of a two-way street, clear of any driveway, crosswalk, or hydrant","Facing oncoming traffic against the left curb, where the only open space is"],"answer":2,"explanation":"Parking is legal only when you are on the correct (right) side of the street and not blocking a driveway, crosswalk, sidewalk, hydrant, or traffic. Options A and B are prohibited because you may never park on a crosswalk or in front of a driveway, and D is illegal because parking against the left curb means facing the wrong way on a two-way street.","handbook":"No parking on a crosswalk or sidewalk, in front of a driveway, on the wrong side of the street, or blocking traffic.","hbref":"Stopping & parking","qid":"DL-RULESOFTHEROAD-TRAP-035"},{"q":"You park on a steep street that climbs uphill, and there is a curb on the right edge of the road. Before you leave the car, which way should you turn your front wheels?","options":["Toward the curb, so the tires wedge against it if the car rolls","Straight ahead, since the curb alone will hold the car in place","Sharply left toward the center of the road to keep tires off the curb","Away from the curb, so a rolling car drifts back into the curb"],"answer":3,"explanation":"When parking uphill with a curb, turn the wheels away from the curb so that if the car rolls back, the front tire catches against the curb and stops it. Turning toward the curb is correct only when parking downhill, and the curb by itself is never a substitute for properly aimed wheels and a set parking brake.","handbook":"When parking uphill with a curb, turn the wheels away from the curb.","hbref":"Stopping & parking","qid":"DL-RULESOFTHEROAD-TRAP-036"},{"q":"You park your car facing downhill on a street with a curb. Before you leave the vehicle, which way should you turn your front wheels?","options":["Toward the curb, so the car would roll into the curb if it moves","Away from the curb, so the car would roll toward the curb if it moves","Straight ahead, since the parking brake will hold the car","Toward the curb only if you are also on the wrong side of the street"],"answer":0,"explanation":"When parking downhill next to a curb, turn the front wheels toward the curb so that if the car rolls, the curb blocks it. Turning the wheels away from the curb is the correct method for parking uphill, not downhill, which makes that option a common reversal trap.","handbook":"When parking downhill with a curb, turn the wheels toward the curb.","hbref":"Stopping & parking","qid":"DL-RULESOFTHEROAD-TRAP-037"},{"q":"You pull onto the gravel shoulder of a flat country road to take a phone call. There is no curb here, just a sloped dirt shoulder dropping off to your right. Before you step away from your vehicle, which way should you turn your front wheels?","options":["Straight ahead, since the road is flat and there is no curb to push against","Toward the shoulder (to the right), so the vehicle would roll off the road if it moves","Toward the center of the road (to the left), so traffic can see your front wheels","It does not matter on a flat road; just set the parking brake and leave them as they are"],"answer":1,"explanation":"When parking where there is no curb, you should always turn the front wheels toward the shoulder (to the right) so the vehicle would roll away from traffic and off the road if it starts to move. Turning them straight or toward the road is wrong because, even on ground that looks flat, a rolling vehicle could drift into the travel lane and into oncoming traffic.","handbook":"When parking without a curb, always turn the wheels toward the shoulder/right.","hbref":"Stopping & parking","qid":"DL-RULESOFTHEROAD-TRAP-038"},{"q":"You are driving 65 mph on a two-lane Texas highway when you see a TxDOT maintenance truck stopped on the right shoulder ahead with its amber lights flashing. There is steady traffic in the left lane, so you cannot safely change lanes. What does the Move Over/Slow Down law require you to do?","options":["Maintain your speed but sound your horn to warn the workers as you pass","Stop completely behind the truck and wait for a worker to wave you through","Slow down to 45 mph (20 mph below the speed limit) until you have passed the stopped truck","Slow to 20 mph and proceed only when the shoulder is clear"],"answer":2,"explanation":"When you cannot safely move over a lane, Texas's Move Over/Slow Down law requires you to slow to 20 mph below the posted speed limit, which is 45 mph in a 65 mph zone. Option D wrongly uses 20 mph itself (a school-zone figure) instead of 20 mph below the limit, and stopping or just honking is not required.","handbook":"Under Texas Move Over/Slow Down law, you must move over a lane or slow to 20 mph below the speed limit for stopped emergency, tow, TxDOT, and utility vehicles with flashing lights.","hbref":"Move Over / Slow Down","qid":"DL-RULESOFTHEROAD-TRAP-039"}]},{"id":"learn-rules-of-the-road","name":"Rules of the Road — Learn","blurb":"Texas DL Rules of the Road: practice tests plus a Learning Test that walks the whole handbook section.","accent":"#0a7c43","kind":"learn","learnSubject":"rules-of-the-road","classes":["DL"],"questions":[{"q":"Under Texas's basic speed law, how fast may you drive?","options":["Never faster than is safe for current conditions","Always exactly the posted speed limit","As fast as your vehicle allows","10 mph over the limit if traffic is light"],"answer":0,"explanation":"Texas's basic speed law means you must never drive faster than is safe for the current conditions.","handbook":"Texas uses the 'prima facie' / basic speed law: you must never drive faster than is safe for the current conditions.","hbref":"Speed limits","qid":"DL-RULESOFTHEROAD-LRN-001"},{"q":"In Texas, what is the default speed limit in an urban district where no sign is posted?","options":["20 mph","30 mph","45 mph","55 mph"],"answer":1,"explanation":"Where unposted, the default speed limit in a Texas urban district is 30 mph.","handbook":"The default speed limit in an urban district, where unposted, is 30 mph.","hbref":"Speed limits","qid":"DL-RULESOFTHEROAD-LRN-002"},{"q":"On a numbered highway in the daytime with no posted sign, what is the default speed limit?","options":["30 mph","55 mph","70 mph","85 mph"],"answer":2,"explanation":"Where unposted, the default daytime speed limit on numbered highways is 70 mph.","handbook":"The default daytime speed limit on numbered highways, where unposted, is 70 mph.","hbref":"Speed limits","qid":"DL-RULESOFTHEROAD-LRN-003"},{"q":"What is the highest speed limit allowed on some Texas tollways?","options":["65 mph","70 mph","75 mph","85 mph"],"answer":3,"explanation":"Some specific Texas tollways are posted with speed limits as high as 85 mph.","handbook":"Many rural Texas Interstates are posted at 75 mph, and some specific tollways are posted as high as 80-85 mph.","hbref":"Speed limits","qid":"DL-RULESOFTHEROAD-LRN-004"},{"q":"What must you do in a school zone when the lights flash or children are present?","options":["Obey the posted reduced speed limit","Drive at the normal speed limit","Speed up to clear the area","Stop completely and wait"],"answer":0,"explanation":"In a school zone you must obey the posted reduced limit (often 20 mph) when lights flash or children are present.","handbook":"In a school zone you must obey the posted reduced limit (often 20 mph) when the lights flash or children are present.","hbref":"Speed limits","qid":"DL-RULESOFTHEROAD-LRN-005"},{"q":"In an active school zone in Texas, is it legal to use a handheld phone?","options":["Yes, always","No, it is illegal","Only after 9 p.m.","Only while parked nearby"],"answer":1,"explanation":"Using a handheld phone in an active school zone is illegal in Texas.","handbook":"Using a handheld phone is illegal in an active school zone.","hbref":"Speed limits","qid":"DL-RULESOFTHEROAD-LRN-006"},{"q":"When should you reduce your driving speed?","options":["Only on dry, empty highways","Only when there are no pedestrians","In rain, fog, heavy traffic, on curves, and near pedestrians","Only at night on straight roads"],"answer":2,"explanation":"You should always reduce speed in rain, fog, heavy traffic, on curves, and near pedestrians.","handbook":"You should always reduce speed in rain, fog, heavy traffic, on curves, and near pedestrians.","hbref":"Speed limits","qid":"DL-RULESOFTHEROAD-LRN-007"},{"q":"At an uncontrolled intersection, which vehicle has the right-of-way?","options":["The faster vehicle","The larger vehicle","The vehicle on the left","The vehicle that arrived first"],"answer":3,"explanation":"At an uncontrolled intersection, you yield to the vehicle that arrived first.","handbook":"At an uncontrolled intersection, yield to the vehicle that arrived first.","hbref":"Right-of-way","qid":"DL-RULESOFTHEROAD-LRN-008"},{"q":"At an uncontrolled intersection, if two vehicles arrive at the same time, who has the right-of-way?","options":["The driver on the right","The driver on the left","The faster vehicle","The larger vehicle"],"answer":0,"explanation":"When two vehicles arrive at the same time, yield to the driver on your right.","handbook":"At an uncontrolled intersection, if two vehicles arrive at the same time, yield to the driver on your right.","hbref":"Right-of-way","qid":"DL-RULESOFTHEROAD-LRN-009"},{"q":"When turning left, who must you yield to?","options":["Only pedestrians","Oncoming traffic and pedestrians","Only traffic behind you","No one, you have the right of way"],"answer":1,"explanation":"When turning left, you must yield to oncoming traffic and to pedestrians.","handbook":"When turning left, you must yield to oncoming traffic and to pedestrians.","hbref":"Right-of-way","qid":"DL-RULESOFTHEROAD-LRN-010"},{"q":"At a T-intersection, which traffic has the right of way?","options":["Traffic turning left","The vehicle on the left","Traffic on the through road","The newest arrival"],"answer":2,"explanation":"Traffic on the through road (the top of the T) has the right of way.","handbook":"At a T-intersection, traffic on the through road (the top of the T) has the right of way.","hbref":"Right-of-way","qid":"DL-RULESOFTHEROAD-LRN-011"},{"q":"At a roundabout, who has the right of way?","options":["Drivers waiting to enter","The faster vehicle","Whoever honks first","Traffic already in the circle"],"answer":3,"explanation":"At a roundabout, you must yield to traffic already in the circle before entering.","handbook":"At a roundabout, yield to traffic already in the circle and enter to the right (counter-clockwise).","hbref":"Right-of-way","qid":"DL-RULESOFTHEROAD-LRN-012"},{"q":"What should you do when an emergency vehicle approaches with lights and siren?","options":["Pull over to the right and stop until it passes","Speed up to get out of the way","Stop in the middle of your lane","Turn left in front of it"],"answer":0,"explanation":"Pull over to the right and stop until the emergency vehicle has passed.","handbook":"When an emergency vehicle approaches with lights and siren, pull over to the right and stop until it passes.","hbref":"Right-of-way","qid":"DL-RULESOFTHEROAD-LRN-013"},{"q":"Who has the right of way in a crosswalk?","options":["The nearest vehicle","Pedestrians","The faster vehicle","Turning vehicles"],"answer":1,"explanation":"Pedestrians in a crosswalk always have the right of way.","handbook":"Pedestrians in a crosswalk always have the right of way.","hbref":"Right-of-way","qid":"DL-RULESOFTHEROAD-LRN-014"},{"q":"Who must you yield to when they carry a white cane or use a guide dog?","options":["A parked car","A road worker","A blind pedestrian","A bicycle rider"],"answer":2,"explanation":"You must yield to a blind pedestrian carrying a white cane or using a guide dog.","handbook":"You must yield to a blind pedestrian carrying a white cane or using a guide dog.","hbref":"Right-of-way","qid":"DL-RULESOFTHEROAD-LRN-015"},{"q":"Who has the right of way at intersections during a funeral procession?","options":["Cross traffic","Whoever arrives first","The driver on the right","The funeral procession"],"answer":3,"explanation":"A funeral procession has the right of way at intersections.","handbook":"A funeral procession has the right of way at intersections.","hbref":"Right-of-way","qid":"DL-RULESOFTHEROAD-LRN-016"},{"q":"How far before a turn or lane change must you signal?","options":["At least 100 feet","At least 25 feet","At least 250 feet","At least 500 feet"],"answer":0,"explanation":"In Texas, you must signal at least 100 feet before a turn or lane change.","handbook":"You must signal at least 100 feet before a turn or lane change.","hbref":"Turns & turning","qid":"DL-RULESOFTHEROAD-LRN-017"},{"q":"Which lane should you use to make a right turn?","options":["The left lane","The right lane, close to the curb","The center lane","Any open lane"],"answer":1,"explanation":"A right turn should be made from the right lane, close to the curb.","handbook":"A right turn should be made from the right lane, close to the curb.","hbref":"Turns & turning","qid":"DL-RULESOFTHEROAD-LRN-018"},{"q":"From which lane should you make a left turn?","options":["The right lane","The center lane","The left lane","Any open lane"],"answer":2,"explanation":"A left turn should be made from the left lane.","handbook":"A left turn should be made from the left lane.","hbref":"Turns & turning","qid":"DL-RULESOFTHEROAD-LRN-019"},{"q":"When is a right turn on red allowed in Texas?","options":["Never, under any condition","Only at night","Without stopping first","After a full stop, unless a sign prohibits it"],"answer":3,"explanation":"A right turn on red is allowed after coming to a full stop, unless a sign prohibits it.","handbook":"A right turn on red is allowed after a full stop, unless a sign prohibits it.","hbref":"Turns & turning","qid":"DL-RULESOFTHEROAD-LRN-020"},{"q":"When is a left turn on a red light allowed in Texas?","options":["From a one-way street onto a one-way street, after a full stop","From any street, after a full stop","Onto a two-way street, after a full stop","Never, under any condition"],"answer":0,"explanation":"In Texas, a left turn on red is only allowed from a one-way street onto a one-way street after stopping fully.","handbook":"A left turn on red is allowed only when turning from a one-way street onto a one-way street, after a full stop.","hbref":"Turns & turning","qid":"DL-RULESOFTHEROAD-LRN-021"},{"q":"On a one-way street, which lane should you turn from?","options":["The center lane","The lane nearest the direction you are turning","Any open lane","The lane farthest from your turn"],"answer":1,"explanation":"On a one-way street, turn from the lane nearest the direction you are turning.","handbook":"On a one-way street, turn from the lane nearest the direction you are turning.","hbref":"Turns & turning","qid":"DL-RULESOFTHEROAD-LRN-022"},{"q":"On which side should you pass another vehicle?","options":["On the right","On either side","On the left","On the shoulder"],"answer":2,"explanation":"You should pass on the left and return to your lane only when you can see the passed vehicle in your mirror.","handbook":"You should pass on the left, and return to your lane only when you can see the passed vehicle in your mirror.","hbref":"Passing & lane use","qid":"DL-RULESOFTHEROAD-LRN-023"},{"q":"Where should you NOT pass another vehicle?","options":["On a straight, flat road","When the lane is clear","On a wide street","On a hill or curve"],"answer":3,"explanation":"You must not pass on a hill or curve because you cannot see oncoming traffic.","handbook":"Do not pass on a hill or curve.","hbref":"Passing & lane use","qid":"DL-RULESOFTHEROAD-LRN-024"},{"q":"Where should you NOT pass another vehicle?","options":["At an intersection or railroad crossing","On a long, straight, flat road","On a clearly marked passing lane","Where a broken yellow line is on your side"],"answer":0,"explanation":"It is unsafe and illegal to pass at an intersection or railroad crossing.","handbook":"Do not pass at an intersection or railroad crossing.","hbref":"Passing & lane use","qid":"DL-RULESOFTHEROAD-LRN-025"},{"q":"When may you pass another vehicle?","options":["When a solid yellow line is on your side","When the line on your side is broken","On a hill or curve","At a railroad crossing"],"answer":1,"explanation":"You may pass when the yellow line on your side is broken, but not where a solid yellow line is on your side.","handbook":"Do not pass where a solid yellow line is on your side of the road.","hbref":"Passing & lane use","qid":"DL-RULESOFTHEROAD-LRN-026"},{"q":"What shape is the sign that marks a No Passing Zone?","options":["Round","Square","Pennant (triangle)","Diamond"],"answer":2,"explanation":"A No Passing Zone is marked by a pennant-shaped (triangular) sign, where passing is not allowed.","handbook":"Do not pass in a No Passing Zone, which is marked by a pennant-shaped sign.","hbref":"Passing & lane use","qid":"DL-RULESOFTHEROAD-LRN-027"},{"q":"On a multi-lane road, which lane should slower traffic use?","options":["The left lane","The center lane","Any lane they choose","The right lane"],"answer":3,"explanation":"Keep right except to pass; slower traffic stays in the right lane.","handbook":"Keep right except to pass; slower traffic keeps right.","hbref":"Passing & lane use","qid":"DL-RULESOFTHEROAD-LRN-028"},{"q":"What do yellow center lines on a road separate?","options":["Traffic moving in opposite directions","Traffic moving in the same direction","Parking spaces from travel lanes","Bike lanes from sidewalks"],"answer":0,"explanation":"Yellow center lines divide traffic moving in opposite directions.","handbook":"Yellow center lines divide traffic moving in opposite directions.","hbref":"Passing & lane use","qid":"DL-RULESOFTHEROAD-LRN-029"},{"q":"What do white lines on a road separate?","options":["Traffic going in opposite directions","Lanes of traffic going the same direction","Parking spaces from the road","The road from the sidewalk"],"answer":1,"explanation":"White lines separate lanes of traffic moving in the same direction.","handbook":"White lines separate lanes of traffic going the same direction.","hbref":"Passing & lane use","qid":"DL-RULESOFTHEROAD-LRN-030"},{"q":"What is the center lane marked with left-turn arrows used for?","options":["Passing other cars","Driving through traffic","Turning left only","Parking your vehicle"],"answer":2,"explanation":"A two-way left-turn lane is only for turning left, not for travel.","handbook":"A two-way left-turn lane (the center lane marked with arrows) is only for turning left, not for travel.","hbref":"Passing & lane use","qid":"DL-RULESOFTHEROAD-LRN-031"},{"q":"At a stop sign, where must you come to a full stop?","options":["In the middle of the intersection","Anywhere you feel safe","After you cross the crosswalk","Behind the stop line or crosswalk"],"answer":3,"explanation":"At a stop sign you must come to a full stop behind the stop line or crosswalk.","handbook":"At a stop sign you must come to a full stop behind the stop line or crosswalk.","hbref":"Stopping & parking","qid":"DL-RULESOFTHEROAD-LRN-032"},{"q":"When must you stop for a stopped school bus?","options":["When its red lights flash and stop arm is out","Only when children are crossing the road","Only if you are directly behind it","Never, you may pass slowly"],"answer":0,"explanation":"You must stop for a stopped school bus when its red lights are flashing and its stop arm is out.","handbook":"You must stop for a stopped school bus with its red lights flashing and its stop arm out.","hbref":"Stopping & parking","qid":"DL-RULESOFTHEROAD-LRN-033"},{"q":"When must you stop for a stopped school bus with its red lights flashing?","options":["Only if you are behind the bus","From both directions, unless a median separates the roads","Never, just slow down","Only if children are crossing"],"answer":1,"explanation":"You must stop from both directions unless a physical median or barrier separates the roadways.","handbook":"You must stop for a stopped school bus from both directions, unless the roadways are separated by a physical median or barrier.","hbref":"Stopping & parking","qid":"DL-RULESOFTHEROAD-LRN-034"},{"q":"How close to a fire hydrant may you park?","options":["Within 5 feet","Within 10 feet","No closer than 15 feet","Right next to it"],"answer":2,"explanation":"You may not park within 15 feet of a fire hydrant.","handbook":"You may not park within 15 feet of a fire hydrant.","hbref":"Stopping & parking","qid":"DL-RULESOFTHEROAD-LRN-035"},{"q":"How far from a crosswalk at an intersection must you not park?","options":["5 feet","10 feet","15 feet","20 feet"],"answer":3,"explanation":"You may not park within 20 feet of a crosswalk at an intersection.","handbook":"You may not park within 20 feet of a crosswalk at an intersection.","hbref":"Stopping & parking","qid":"DL-RULESOFTHEROAD-LRN-036"},{"q":"How close to a stop sign may you park?","options":["No closer than 30 feet","No closer than 5 feet","No closer than 10 feet","No closer than 15 feet"],"answer":0,"explanation":"In Texas, you may not park within 30 feet of a stop sign or signal.","handbook":"You may not park within 30 feet of a stop sign or signal.","hbref":"Stopping & parking","qid":"DL-RULESOFTHEROAD-LRN-037"},{"q":"Where are you not allowed to park your vehicle?","options":["In a marked parking space","On a crosswalk or sidewalk","Along the right curb","In a parking garage"],"answer":1,"explanation":"It is illegal to park on a crosswalk or sidewalk.","handbook":"You may not park on a crosswalk or sidewalk.","hbref":"Stopping & parking","qid":"DL-RULESOFTHEROAD-LRN-038"},{"q":"Where is parking NOT allowed?","options":["On a quiet side street","In a marked parking lot","In front of a driveway","Next to a parking meter"],"answer":2,"explanation":"You may not park in front of a driveway.","handbook":"You may not park in front of a driveway.","hbref":"Stopping & parking","qid":"DL-RULESOFTHEROAD-LRN-039"},{"q":"Where is parking not allowed?","options":["On the right side of the street","In a marked parking space","Next to a parking meter","On the wrong side of the street"],"answer":3,"explanation":"You may not park on the wrong side of the street.","handbook":"You may not park on the wrong side of the street.","hbref":"Stopping & parking","qid":"DL-RULESOFTHEROAD-LRN-040"},{"q":"Where are you not allowed to park?","options":["Where you would block traffic","In a marked parking space","In a parking garage","In your own driveway"],"answer":0,"explanation":"You may not park where you would be blocking traffic.","handbook":"You may not park where you would be blocking traffic.","hbref":"Stopping & parking","qid":"DL-RULESOFTHEROAD-LRN-041"},{"q":"When parking uphill next to a curb, which way should you turn your wheels?","options":["Straight ahead","Away from the curb","Toward the curb","It does not matter"],"answer":1,"explanation":"When parking uphill with a curb, turn your wheels away from the curb so the car rolls into the curb if it moves.","handbook":"When parking uphill with a curb, turn your wheels away from the curb.","hbref":"Stopping & parking","qid":"DL-RULESOFTHEROAD-LRN-042"},{"q":"When parking downhill next to a curb, which way should you turn your front wheels?","options":["Straight ahead","Away from the curb","Toward the curb","It does not matter"],"answer":2,"explanation":"When parking downhill with a curb, turn your wheels toward the curb so the car rolls into it if it moves.","handbook":"When parking downhill with a curb, turn your wheels toward the curb.","hbref":"Stopping & parking","qid":"DL-RULESOFTHEROAD-LRN-043"},{"q":"When parking on a hill with no curb, which way do you turn your wheels?","options":["Straight ahead","Toward the center of the road","It does not matter","Toward the shoulder (to the right)"],"answer":3,"explanation":"Without a curb, always turn your wheels toward the shoulder/right so the car rolls off the road if it moves.","handbook":"When parking on a hill without a curb, always turn your wheels toward the shoulder/right.","hbref":"Stopping & parking","qid":"DL-RULESOFTHEROAD-LRN-044"},{"q":"Under the Move Over law, how much must you slow down for a stopped emergency vehicle with flashing lights?","options":["20 mph below the speed limit","5 mph below the speed limit","10 mph below the speed limit","To a complete stop"],"answer":0,"explanation":"You must move over a lane or slow to 20 mph below the speed limit for stopped emergency vehicles.","handbook":"Under the Texas Move Over / Slow Down law, you must move over a lane or slow to 20 mph below the speed limit for stopped emergency, tow, TxDOT, and utility vehicles with flashing lights.","hbref":"Move Over / Slow Down","qid":"DL-RULESOFTHEROAD-LRN-045"},{"q":"At an uncontrolled intersection, who has the right-of-way?","options":["The faster vehicle","The vehicle that arrived first","The larger vehicle","The vehicle on the left"],"answer":1,"explanation":"At an uncontrolled intersection, yield to the vehicle that arrived first.","handbook":"At an uncontrolled intersection the basic principle is to yield based on arrival order, with the right-hand driver favored only when arrivals are simultaneous.","hbref":"Right-of-way","qid":"DL-RULESOFTHEROAD-LRN-046"},{"q":"How far before a turn or lane change must you signal?","options":["At least 25 feet","At least 50 feet","At least 100 feet","At least 200 feet"],"answer":2,"explanation":"In Texas, you must signal at least 100 feet before turning or changing lanes.","handbook":"The 100-foot signal requirement applies to both turns and lane changes.","hbref":"Turns & turning","qid":"DL-RULESOFTHEROAD-LRN-047"},{"q":"What is the speed limit commonly posted in a school zone?","options":["40 mph","55 mph","70 mph","20 mph"],"answer":3,"explanation":"The reduced school zone speed limit is commonly posted at 20 mph.","handbook":"The posted reduced school zone limit is commonly 20 mph.","hbref":"Speed limits","qid":"DL-RULESOFTHEROAD-LRN-048"},{"q":"After passing, when can you safely return to your lane?","options":["When you can see the passed vehicle in your rearview mirror","As soon as you finish passing","When the passed vehicle honks","After waiting 30 seconds"],"answer":0,"explanation":"You may return to your lane once you can see the passed vehicle in your rearview mirror.","handbook":"After passing, the cue to return safely to your lane is being able to see the passed vehicle in your rearview mirror.","hbref":"Passing & lane use","qid":"DL-RULESOFTHEROAD-LRN-049"},{"q":"In a roundabout, which direction do you drive around the circle?","options":["Clockwise","Counter-clockwise","Either direction","Straight across"],"answer":1,"explanation":"In a roundabout, traffic moves around the circle counter-clockwise.","handbook":"When entering a roundabout the direction of travel within the circle is counter-clockwise.","hbref":"Right-of-way","qid":"DL-RULESOFTHEROAD-LRN-050"},{"q":"How close to a fire hydrant may you park?","options":["No limit","5 feet","15 feet","50 feet"],"answer":2,"explanation":"You may not park within 15 feet of a fire hydrant.","handbook":"The no-parking distance from a fire hydrant (15 ft) is shorter than that from a crosswalk at an intersection (20 ft), which is shorter than that from a stop sign or signal (30 ft).","hbref":"Stopping & parking","qid":"DL-RULESOFTHEROAD-LRN-051"},{"q":"The Move Over / Slow Down law also protects which type of vehicle with flashing lights?","options":["Delivery vans","School buses","City buses","Utility vehicles"],"answer":3,"explanation":"The Move Over / Slow Down law also covers utility vehicles, along with emergency, tow, and TxDOT vehicles.","handbook":"The Move Over / Slow Down law covers utility vehicles in addition to emergency, tow, and TxDOT vehicles when they display flashing lights.","hbref":"Move Over / Slow Down","qid":"DL-RULESOFTHEROAD-LRN-052"},{"q":"What is the highest posted speed limit in Texas?","options":["80 to 85 mph","55 mph","65 mph","70 mph"],"answer":0,"explanation":"Some specific Texas tollways are posted at 80 to 85 mph, the highest posted limits in the state.","handbook":"Some specific Texas tollways are posted at 80 to 85 mph, the highest posted limits in the state.","hbref":"Speed limits","qid":"DL-RULESOFTHEROAD-LRN-053"},{"q":"What must you do before turning right on a red light?","options":["Speed up to merge quickly","Come to a full stop first","Honk to warn other drivers","Turn off your headlights"],"answer":1,"explanation":"A right turn on red is allowed only after coming to a full stop, unless a sign prohibits it.","handbook":"A right turn on red requires first coming to a full stop and is permitted only if no sign prohibits the turn.","hbref":"Turns & turning","qid":"DL-RULESOFTHEROAD-LRN-054"},{"q":"What shape is a No Passing Zone sign?","options":["Round","Square","Pennant (triangular)","Diamond"],"answer":2,"explanation":"A No Passing Zone is marked by a pennant-shaped (triangular) sign.","handbook":"A No Passing Zone is identified by a pennant-shaped (triangular) sign.","hbref":"Passing & lane use","qid":"DL-RULESOFTHEROAD-LRN-055"},{"q":"At a T-intersection, who has the right of way?","options":["Traffic on the stem of the T","The faster vehicle","The vehicle on the left","Traffic on the through road"],"answer":3,"explanation":"Traffic on the through road (top of the T) has the right of way.","handbook":"On the through road of a T-intersection, the through traffic does not have to yield to traffic entering from the stem of the T.","hbref":"Right-of-way","qid":"DL-RULESOFTHEROAD-LRN-056"},{"q":"When parking downhill, which way should you turn your front wheels?","options":["Toward the curb","Away from the curb","Straight ahead","It does not matter"],"answer":0,"explanation":"Turning the wheels toward the curb lets the curb block the vehicle if it rolls.","handbook":"When parking downhill, turning the wheels toward the curb lets the curb block the vehicle if it rolls.","hbref":"Stopping & parking","qid":"DL-RULESOFTHEROAD-LRN-057"},{"q":"Under the basic speed law, can the legal maximum speed be lower than the posted number?","options":["No, the posted number is always the legal maximum","Yes, when conditions make the posted speed unsafe","No, only police can lower it","Yes, but only at night"],"answer":1,"explanation":"The basic speed law requires a speed safe for conditions, so the legal limit can fall below the posted number when conditions make it unsafe.","handbook":"The basic speed law means the legal maximum can be lower than a posted number whenever conditions make the posted speed unsafe.","hbref":"Speed limits","qid":"DL-RULESOFTHEROAD-LRN-058"},{"q":"When making a left turn, who must you yield to?","options":["Only oncoming vehicles","Only pedestrians","Oncoming vehicles and pedestrians","No one"],"answer":2,"explanation":"A driver turning left must yield to both oncoming vehicles and pedestrians before completing the turn.","handbook":"A driver making a left turn must yield to both oncoming vehicles and pedestrians before completing the turn.","hbref":"Right-of-way","qid":"DL-RULESOFTHEROAD-LRN-059"},{"q":"Under the Move Over / Slow Down law, what are a driver's two options when passing a stopped emergency vehicle with flashing lights?","options":["Stop fully or honk twice","Turn on hazards or flash high beams","Speed up or change lanes","Move over one lane or slow to 20 mph below the limit"],"answer":3,"explanation":"The Move Over / Slow Down law lets you move over one lane away or slow to 20 mph below the speed limit.","handbook":"Drivers have two options under the Move Over / Slow Down law: move over one lane away from the stopped vehicle, or slow to 20 mph below the speed limit.","hbref":"Move Over / Slow Down","qid":"DL-RULESOFTHEROAD-LRN-060"}]},{"id":"signals-and-markings","name":"Traffic Signals & Markings","blurb":"Texas DL Traffic Signals & Markings: practice tests plus a Learning Test that walks the whole handbook section.","accent":"#0f9d8c","kind":"core","classes":["DL"],"questions":[{"q":"You arrive at an intersection and the traffic signal facing you is a steady green light. You want to turn left across oncoming traffic, but several cars are coming toward you through the intersection. What are you legally allowed to do?","options":["Proceed straight through or make your turn, but first yield to the oncoming cars and any traffic already in the intersection.","Turn left immediately, because a steady green light gives you a protected turn and oncoming traffic must stop for you.","Stop completely behind the line and wait, treating the green like a flashing red until the oncoming cars clear.","Slow down and proceed with caution without yielding, since a steady green works the same as a flashing yellow."],"answer":0,"explanation":"A steady green means go only when the intersection is clear; you may proceed straight or turn, but you must yield to oncoming traffic and vehicles already in the intersection. Option B is the trap: only a green arrow gives a protected turn where oncoming traffic is stopped, not a steady green light.","handbook":"A steady GREEN light means go if the intersection is clear; you may proceed straight or turn after yielding.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-TRAP-001"},{"q":"You are driving toward an intersection at the speed limit when the green light turns to a steady yellow. You are still about half a block away and the road behind you is clear. What should you do?","options":["Speed up to get through the intersection before the light turns red","Stop before the intersection if you can do so safely, because the light is about to turn red","Treat it like a flashing yellow and continue through carefully without stopping","Come to a full stop and then proceed when the way is clear, as you would for a flashing red"],"answer":1,"explanation":"A steady yellow light warns that the signal is about to turn red, so you should stop if you can do so safely and never speed up to beat the light. Option C describes a flashing yellow (caution) and Option D describes a flashing red (stop sign), which are different signals.","handbook":"A steady YELLOW light means the light is about to turn red; stop if you can do so safely and do not speed up.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-TRAP-002"},{"q":"You are approaching an intersection and the traffic light facing you turns to a steady red while you are still a short distance from the marked stop line. There is no sign prohibiting a turn, and you intend to go straight ahead. What must you do?","options":["Slow down and proceed carefully through the intersection without stopping, since the light may change soon","Stop only if cross traffic is present, then continue straight through the red light","Come to a complete stop behind the stop line and remain stopped until the light turns green","Treat the signal as a stop sign, stop fully, then proceed straight when the way is clear"],"answer":2,"explanation":"A steady red light requires you to stop completely behind the stop line and remain stopped until the light turns green. Option D describes a flashing red light (treated like a stop sign), not a steady red, so proceeding straight on a steady red is wrong.","handbook":"A steady RED light means stop completely behind the line and remain stopped until the light turns green.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-TRAP-003"},{"q":"You are in the right lane approaching an intersection with a steady red light. You want to turn right. There is no sign prohibiting the turn, and cross traffic has a gap. What should you do?","options":["Slow down and turn right without stopping, since the cross traffic has a gap","Treat it as a stop sign, then turn right only when a green arrow appears","Wait for the light to turn green before turning right, because you may never turn on red","Come to a full stop behind the line, then turn right since it is clear and no sign prohibits it"],"answer":3,"explanation":"At a steady red light you must stop completely behind the line, and a right turn is permitted only after that full stop when the way is clear and no sign prohibits it. Option A skips the required full stop, and option C wrongly claims right-on-red is never allowed.","handbook":"At a steady red light where a right turn is permitted, you must stop fully, then turn right only if it is clear and not prohibited by a sign.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-TRAP-004"},{"q":"You approach an intersection late at night and the overhead traffic signal is flashing red in every direction. There is no other traffic in sight. What must you do?","options":["Come to a complete stop, then proceed through the intersection when it is safe.","Slow down, look both ways, and roll through without stopping since the way is clear.","Stop and remain stopped until the flashing red changes to a steady green light.","Treat it as a yield sign and merge through only if another vehicle is approaching."],"answer":0,"explanation":"A flashing red light means the same thing as a stop sign: you must come to a full stop and then proceed when it is safe. Option B is wrong because a flashing red always requires a complete stop (rolling through is the rule for a flashing yellow), and option C is wrong because a flashing red signal will not turn green.","handbook":"A flashing RED light is treated as a STOP sign: come to a full stop, then proceed when it is safe.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-TRAP-005"},{"q":"Late at night, you approach an intersection where the traffic signal is no longer running its normal cycle and is instead showing a steadily flashing YELLOW light over your lane. What should you do?","options":["Come to a complete stop behind the line, then proceed when the way is clear, as you would at a stop sign.","Slow down and proceed carefully through the intersection without stopping, watching for cross traffic.","Treat the intersection as an all-way stop because the signal is not cycling normally.","Stop and remain stopped until the signal returns to a steady green light."],"answer":1,"explanation":"A flashing YELLOW light means caution, so you slow down and proceed carefully through the intersection without coming to a stop. A flashing RED light is the one that means a full stop like a stop sign, and a completely dark or non-working signal is the one treated as an all-way stop, so those are the wrong responses here.","handbook":"A flashing YELLOW light means caution: slow down and proceed carefully without stopping.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-TRAP-006"},{"q":"You're stopped at an intersection waiting to turn left. Your signal had been a steady red light, but it just changed to a green left-turn ARROW pointing in the direction you want to go. What does this tell you about how to proceed?","options":["You may turn left, but you must first yield to oncoming traffic that has the right-of-way","You must come to a full stop and wait, because an arrow signal means no turn is allowed in that direction","You may turn left now and oncoming traffic is stopped, giving you a protected turn","You may turn left only after slowing to check, since the arrow works like a flashing yellow caution signal"],"answer":2,"explanation":"A green ARROW means a protected turn in the arrow's direction, so oncoming traffic is being held by a red light and you may turn without yielding. Option A describes a steady green light (a permitted turn requiring you to yield), and option B incorrectly describes a red arrow, so both are wrong.","handbook":"A green ARROW means a protected turn in the arrow's direction, with oncoming traffic stopped.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-TRAP-007"},{"q":"You are in the left-turn lane at a busy intersection, waiting to turn left. The signal for your lane shows a steady red ARROW pointing left, while the regular round signal for traffic going straight is green. What should you do?","options":["Turn left carefully, since the green light for the straight lanes means oncoming traffic has a protected stop","Treat the red arrow like a flashing red and make the left turn after coming to a full stop","Make the left turn after yielding to oncoming traffic, since left turns are always permitted on a red arrow when clear","Remain stopped and wait, because a red arrow means no turn is allowed in that direction until it changes"],"answer":3,"explanation":"A red arrow means no turn is allowed in the direction it points, so you must wait until the signal changes, regardless of what the round signal for other lanes shows. A red arrow is not the same as a flashing red, and there is no 'turn after yielding' permitted on a steady red arrow.","handbook":"A red ARROW means no turn is allowed in that direction; you must wait.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-TRAP-008"},{"q":"You approach a busy four-way intersection during a power outage. The traffic signals are completely dark and not working at all. What should you do?","options":["Treat the intersection as an all-way STOP, stopping and yielding in turn before proceeding","Slow down and proceed carefully through the intersection without stopping","Treat your direction as having the right of way and continue at normal speed","Stop only if a vehicle is already in the intersection, otherwise keep moving"],"answer":0,"explanation":"A dark or non-working signal must be treated as an all-way STOP, so every driver stops and yields in turn. Slowing without stopping (B) is the rule for a flashing yellow light, not a dead signal, and the other options wrongly assume right of way.","handbook":"A dark or non-working signal should be treated as an all-way STOP.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-TRAP-009"},{"q":"You are stopped at a green light and want to turn right onto a side street. On the pedestrian signal facing the crosswalk you intend to cross, a steady white walking-person symbol is showing. What does this symbol tell you about the people on the corner?","options":["Pedestrians must wait, so you may turn without checking the crosswalk","Pedestrians may legally begin crossing, so you must yield to them before turning","Pedestrians may only finish crossing but cannot start, so few will be in the crosswalk","The crosswalk is closed to pedestrians and reserved for turning vehicles"],"answer":1,"explanation":"A WALK signal or walking-person symbol means pedestrians may cross, so they have the right of way and you must yield before turning. Option C describes a flashing DON'T WALK/raised hand (finish but don't start), not the steady walking-person symbol.","handbook":"A WALK signal or walking-person symbol means pedestrians may cross.","hbref":"Pedestrian & lane signals","qid":"DL-SIGNALSANDMARKINGS-TRAP-010"},{"q":"You pull up to a downtown intersection and stop at a red light. As you wait, you watch the pedestrian signal across the street switch from a flashing raised-hand symbol to a steady raised-hand symbol while a person is still standing on your corner. What does that steady raised hand tell that pedestrian to do?","options":["It means they should hurry to finish crossing before the light changes","It means the crosswalk is closed and they must use a different intersection","It means they must not start to cross the street","It means they may begin crossing because the WALK phase is starting"],"answer":2,"explanation":"A steady DON'T WALK signal or steady raised-hand symbol means do not start to cross. The flashing raised hand (option A) is what tells someone already in the crosswalk to finish crossing, but a steady hand means do not begin.","handbook":"A steady DON'T WALK signal or steady raised-hand symbol means do not start to cross.","hbref":"Pedestrian & lane signals","qid":"DL-SIGNALSANDMARKINGS-TRAP-011"},{"q":"You are stopped at a green light waiting to turn right on a city street. A pedestrian steps off the curb into the crosswalk you must cross just as the pedestrian signal facing them begins to show a flashing raised-hand (DON'T WALK) symbol. What does that flashing signal tell you about the pedestrian's legal right to be in the crosswalk?","options":["The pedestrian must immediately stop and return to the curb, so you may turn as soon as they step back","The flashing hand means the same as a steady hand, so the pedestrian had no right to enter and you may proceed","The flashing hand is only a caution like a flashing yellow light, so the pedestrian and you may both proceed together","A pedestrian already in the crosswalk may finish crossing; the flashing hand only means no one new should start to cross"],"answer":3,"explanation":"A flashing DON'T WALK or flashing raised-hand symbol means anyone already in the crosswalk should finish crossing, while no new pedestrian should start; you must yield until they finish. The steady-hand meaning (B) and the flashing-yellow caution rule (C) are real facts placed in the wrong context.","handbook":"A flashing DON'T WALK or flashing raised-hand symbol means finish crossing if already in the crosswalk but do not start to cross.","hbref":"Pedestrian & lane signals","qid":"DL-SIGNALSANDMARKINGS-TRAP-012"},{"q":"You are driving on a multi-lane highway where overhead lane-use signals hang above each lane. Above the lane you want to enter, you see a steady green down-arrow. What does this tell you about that lane?","options":["The lane is open and you may drive in it","The lane is closed and you must move out of it","The lane is changing use, so move out of it before it closes","The lane is reserved for HOV or carpool vehicles only"],"answer":0,"explanation":"A lane-use green down-arrow means the lane is open for travel, so you may drive in it. A red X means the lane is closed and a yellow X means the lane is changing use and you should move out of it, but neither of those signals is shown here.","handbook":"A lane-use green down-arrow means the lane is open for travel.","hbref":"Pedestrian & lane signals","qid":"DL-SIGNALSANDMARKINGS-TRAP-013"},{"q":"You are driving on a multi-lane highway when you look up at the overhead lane-control signals. Above your lane, a steady red X is illuminated, while the lane to your right shows a steady green down-arrow. What should you do?","options":["Stay in your lane and proceed with caution, since the red X simply warns of an upcoming hazard","Merge into the lane on your right, because the red X means your lane is closed and the green down-arrow means that lane is open","Come to a full stop in your lane and wait, treating the red X like a flashing red signal","Stay in your lane but immediately move out of it, because the red X means the lane is changing use"],"answer":1,"explanation":"A lane-use red X means the lane is closed, so you must leave it, and a green down-arrow means the lane beneath it is open for travel. The trap options confuse the red X with a flashing red (stop) signal or with a yellow X, which is the signal that means the lane is changing use and you should move out of it.","handbook":"A lane-use red X means the lane is closed.","hbref":"Pedestrian & lane signals","qid":"DL-SIGNALSANDMARKINGS-TRAP-014"},{"q":"You are driving in a center lane on a multi-lane road when the overhead lane-use signal above your lane changes to a steady yellow X. What does this signal mean you should do?","options":["Stop immediately within the lane, because a yellow X works like a steady red light overhead","Stay in the lane but slow to a crawl, since a yellow X only warns that the lane is congested ahead","Prepare to move out of the lane safely, because the lane is changing use and is about to close to your direction","Continue normally, because a yellow X simply confirms the lane is open for through traffic"],"answer":2,"explanation":"An overhead lane-use yellow X means the lane is changing use, so you should prepare to safely move out of it before it closes. Stopping in the lane (A) is wrong because a yellow X is not a red light, and continuing as if the lane is open (D) confuses it with a green down-arrow, which is the signal for an open lane.","handbook":"A lane-use yellow X means the lane is changing use and you should move out of it.","hbref":"Pedestrian & lane signals","qid":"DL-SIGNALSANDMARKINGS-TRAP-015"},{"q":"You are driving on a two-lane rural highway behind a slow tractor. You want to pass it, but you notice a solid yellow line painted along the center on your side of the road. What does this marking tell you about passing here?","options":["You may pass because yellow lines always allow passing when the road is clear","You may pass only if a broken white line is also present alongside it","Passing is allowed in both directions since the line is yellow","You must not pass; the solid yellow line on your side means passing is prohibited"],"answer":3,"explanation":"A solid yellow line on your side of the centerline means no passing, so you must stay behind the tractor until the marking changes. Option A confuses this with a broken yellow line (passing allowed when safe), and the white-line and both-directions ideas do not apply to a solid yellow line on your side.","handbook":"A solid YELLOW line on your side of the road means no passing.","hbref":"Pavement line markings","qid":"DL-SIGNALSANDMARKINGS-TRAP-016"},{"q":"You're driving on a two-lane rural highway behind a slow tractor. The center of the road has a broken (dashed) yellow line on your side, the road ahead is straight with clear visibility, and no oncoming traffic is in sight. What does this pavement marking tell you about passing the tractor?","options":["Passing is permitted when it is safe, so you may cross to overtake the tractor","Passing is prohibited on your side because any yellow line means no passing","You may only cross the line to make a left turn, not to pass","Passing is allowed only on the right shoulder, never across the center line"],"answer":0,"explanation":"A broken (dashed) yellow line on your side of the center means passing is permitted when it is safe to do so, which it is here with clear visibility and no oncoming traffic. The trap in B confuses this with a solid yellow line (no passing), and the turn-only restriction in C applies to a double solid yellow line.","handbook":"A broken (dashed) yellow line means passing is allowed when safe.","hbref":"Pavement line markings","qid":"DL-SIGNALSANDMARKINGS-TRAP-017"},{"q":"You are driving on a two-lane road and reach a stretch marked down the center with two side-by-side solid yellow lines. A slow tractor is ahead of you and the road is clear in both directions. On your left, there is a driveway you could turn into. What does this marking permit you to do?","options":["Pass the tractor, because the road is clear in both directions and you can see far ahead","Stay in your lane and not pass, though you may cross the lines to turn left into the driveway","Pass the tractor, since a double solid yellow line restricts passing only for the oncoming direction","Cross the lines freely to pass, because solid yellow only discourages crossing but does not forbid it"],"answer":1,"explanation":"A double solid yellow line means no passing in either direction, so you must stay in your lane, but you may still cross it to turn (such as into a driveway). Passing is never allowed here regardless of visibility, and the rule applies to both directions, not just oncoming traffic.","handbook":"A double solid yellow line means no passing in either direction; do not cross it except to turn.","hbref":"Pavement line markings","qid":"DL-SIGNALSANDMARKINGS-TRAP-018"},{"q":"You are driving on a multi-lane highway where all traffic is moving in the same direction. You notice a line painted between your lane and the lane immediately to your right. What color is that line most likely to be?","options":["Yellow, because yellow lines always mark the edges of every lane","Yellow, because the line warns that passing is not allowed there","White, because white lines separate lanes of traffic traveling in the same direction","Double solid yellow, because it prevents crossing into the next lane"],"answer":2,"explanation":"White lines separate lanes of traffic that travel in the same direction, so the line between two same-direction lanes is white. Yellow lines are used to separate traffic moving in opposite directions or to mark no-passing zones, which does not apply here.","handbook":"White lines separate lanes of traffic traveling in the same direction.","hbref":"Pavement line markings","qid":"DL-SIGNALSANDMARKINGS-TRAP-019"},{"q":"You are driving on a multi-lane road where all traffic moves in the same direction. The lane to your left is separated from yours by a broken (dashed) white line. Traffic ahead in your lane is slowing, and the left lane is clear. What does that marking tell you about moving into the left lane?","options":["You may not cross it; a white line always means you must stay in your lane","Crossing is only allowed to make a turn, the way you would treat a double solid yellow line","Passing is allowed here only because the line separates opposing traffic","You may change lanes across it when the way is clear and it is safe to do so"],"answer":3,"explanation":"A broken white line separates lanes going the same direction and permits a lane change when it is safe, so moving into the clear left lane is allowed. Option A describes a solid white line, and option B describes a double solid yellow line, so both apply the wrong marking's rule here.","handbook":"A broken white line means a lane change is allowed.","hbref":"Pavement line markings","qid":"DL-SIGNALSANDMARKINGS-TRAP-020"},{"q":"You're driving on a four-lane highway where all lanes move in the same direction. As you approach a freeway entrance ramp, a single solid white line separates your lane from the lane to your right. You'd like to slide over to that lane to get a better position. What does this marking tell you?","options":["Stay in your lane; crossing the solid white line is discouraged","You may freely change into the right lane whenever it's clear","Passing is prohibited in both directions, like a double solid line","This marks the right edge of the roadway, so don't drive past it"],"answer":0,"explanation":"A solid white line separates lanes going the same direction and means stay in your lane, as crossing it is discouraged. A broken white line is what allows a free lane change (option B), and a solid white edge line marks the road's right edge (option D), so those facts are placed here in the wrong context.","handbook":"A solid white line means stay in your lane; crossing it is discouraged.","hbref":"Pavement line markings","qid":"DL-SIGNALSANDMARKINGS-TRAP-021"},{"q":"You are driving at night on an unfamiliar rural highway with poor visibility. To your right you notice a solid white line running along the pavement, parallel to your direction of travel. What does this line tell you?","options":["It marks the center of the road and you must not cross it to pass","It marks the right edge of the road, helping you stay on the pavement","It marks the left edge of the road on a one-way street","It indicates a bike lane that you must not drive in"],"answer":1,"explanation":"A solid white edge line marks the right edge of the road, which is especially useful for staying on the pavement at night or in poor visibility. The trap in C confuses edge colors: a yellow line marks the left edge, while white marks the right edge.","handbook":"A solid white edge line marks the right edge of the road.","hbref":"Pavement line markings","qid":"DL-SIGNALSANDMARKINGS-TRAP-022"},{"q":"You're driving at night on an unfamiliar two-way road. Your headlights catch a solid yellow line running along the far-left side of your lane, right at the boundary of the pavement. What is this line telling you?","options":["It marks the right edge of the road, so the pavement ends just to your left","It's a no-passing line, so you must not cross the center of the road to pass","It marks the left edge of the road, so it shows where the pavement ends on your left","It separates lanes of traffic moving in the same direction as you"],"answer":2,"explanation":"A yellow edge line marks the left edge of the roadway, showing the driver where the pavement ends on the left side. The line being yellow does not make it a center no-passing line, and the right edge of the road is marked with a solid white line, not yellow.","handbook":"A yellow edge line marks the left edge of the road.","hbref":"Pavement line markings","qid":"DL-SIGNALSANDMARKINGS-TRAP-023"},{"q":"You approach an intersection with a red light. Before the crosswalk, you notice a wide white line painted across your lane. Where should you bring your vehicle to a complete stop?","options":["On top of the wide white line, so your bumper lines up evenly with it","Just past the wide white line but before entering the crosswalk","Anywhere in the intersection, as long as you are fully stopped before the green","Behind the wide white line, which is the stop line marking where to stop"],"answer":3,"explanation":"The wide white line is a stop line, and you must stop behind it, not on or beyond it. Stopping on the line or past it into the crosswalk blocks pedestrians and is incorrect even though you are technically stopped.","handbook":"A stop line is a wide white line showing where to stop; you must stop behind it.","hbref":"Other markings","qid":"DL-SIGNALSANDMARKINGS-TRAP-024"},{"q":"As you approach a green light at an intersection, you see a set of white markings painted across the road and a pedestrian stepping onto them. Where must you stop?","options":["Before the white crosswalk markings, to let the pedestrian cross","On top of the crosswalk markings, as long as you leave room for the pedestrian","Wherever you like, since a green light means you always have the right of way","Behind the diamond symbol painted in the lane"],"answer":0,"explanation":"A crosswalk is marked by white lines for pedestrians, and you must stop before it to let them cross safely. Stopping on top of it blocks the pedestrian, and a green light still requires yielding to people already in the crosswalk; the diamond symbol marks an HOV/carpool lane, not a stopping point.","handbook":"A crosswalk consists of white markings for pedestrians, and you must stop before it.","hbref":"Other markings","qid":"DL-SIGNALSANDMARKINGS-TRAP-025"},{"q":"You're driving alone on a Texas freeway during rush hour. The lane farthest to the left has large diamond symbols painted on the pavement at regular intervals. What does this marking tell you about that lane?","options":["It is a bike lane, so you must not drive or park in it","It is a reserved HOV/carpool or special-use lane that you may not be allowed to use alone","It is closed to all traffic, the same as a red X overhead signal","It is an edge lane and the diamonds mark where the road surface ends"],"answer":1,"explanation":"A diamond symbol painted in a lane marks a reserved HOV/carpool or special-use lane, which often requires a minimum number of occupants, so driving alone may not be permitted. A bike lane is marked differently, and a closed lane is shown by an overhead red X, not pavement diamonds.","handbook":"A diamond symbol in a lane indicates a reserved HOV/carpool or special-use lane.","hbref":"Other markings","qid":"DL-SIGNALSANDMARKINGS-TRAP-026"},{"q":"You're running late and spot an open stretch of pavement to the right of the regular traffic lane. It's marked off with a solid white line and has a painted bicycle symbol, but no cyclists are currently in it. What should you do?","options":["Drive in it to pass the slow traffic, since it's empty right now","Pull into it and park while you wait for traffic to clear","Stay out of it entirely; it is a bike lane reserved for bicycles, not for driving or parking","Use it as a carpool lane since you have passengers in the vehicle"],"answer":2,"explanation":"A lane marked with a bicycle symbol is a bike lane reserved for bicycles, and you must not drive or park in it even when no cyclists are present. Options A and B are the trap (driving and parking are both prohibited), and D confuses the bike lane with an HOV/carpool lane, which is marked with a diamond symbol instead.","handbook":"A bike lane is a lane marked for bicycles; you must not drive or park in it.","hbref":"Other markings","qid":"DL-SIGNALSANDMARKINGS-TRAP-027"},{"q":"You're running late and need to leave your car for a few minutes. The only open space is along a curb painted solid yellow, with no signs posted nearby. What does that yellow curb tell you about parking there?","options":["Parking is fine because there is no posted sign restricting it","It marks the left edge of the roadway, so parking is allowed to the right of it","It is reserved for HOV or carpool vehicles only","It indicates a no-parking or loading restriction, so you should not park there"],"answer":3,"explanation":"A yellow curb signals a no-parking or loading restriction even when no sign is present, though exact meanings can vary by city, so you should not leave your car there. The left-edge yellow line refers to roadway center markings, not curbs, and HOV reservations are shown by a diamond symbol in a lane, not by a painted curb.","handbook":"A yellow curb indicates a no-parking or loading restriction, though curb colors vary by city.","hbref":"Other markings","qid":"DL-SIGNALSANDMARKINGS-TRAP-028"},{"q":"You are driving down an unfamiliar road and the pavement ahead shows a large painted \"RXR\" symbol followed by a wide white line across your lane. The crossing gates are still up, but you can hear a train horn and see one approaching. What should you do?","options":["Stop behind the white line and wait, because the RXR marks a railroad crossing and you must stop when a train is approaching","Treat the white line as optional and roll across slowly, since the gates are still up and a train can be beaten","Stop only if the line were yellow, since a yellow line on your side means no passing","Proceed without stopping because the diamond symbol means it is a special-use lane for crossing traffic"],"answer":0,"explanation":"The large RXR painted on the pavement marks a railroad crossing, and the wide white line is a stop line; you must stop behind it when a train is approaching. The traps misuse other real facts: a solid yellow line means no passing, and a diamond marks an HOV/special-use lane, neither of which applies at a railroad crossing.","handbook":"Railroad crossing pavement is marked with a large RXR and a stop line; stop if a train approaches.","hbref":"Other markings","qid":"DL-SIGNALSANDMARKINGS-TRAP-029"},{"q":"You are stopped at an intersection waiting to turn left when your light turns a steady green. An oncoming car is approaching from the opposite direction and is close to the intersection. What should you do?","options":["Turn left immediately, since a steady green light gives you the right to proceed ahead of oncoming traffic.","Yield to the oncoming car, then complete your left turn when it is safe to do so.","Wait for a green arrow, because a steady green light does not permit a left turn.","Come to a full stop behind the line and proceed only after the oncoming car has passed, as a steady green requires a stop first."],"answer":1,"explanation":"At a steady green light you may proceed or turn, but you must first yield to oncoming traffic and pedestrians rather than turn without regard to other vehicles. A green arrow gives a protected turn and a stop is required only at red or yellow, so options C and D misapply other signal rules.","handbook":"At a steady green light you must yield before turning rather than turn without regard to other traffic.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-TRAP-030"},{"q":"You are approaching an intersection at the posted speed limit when the light turns from green to steady yellow. There is enough distance ahead of you to stop safely before the line. What should you do?","options":["Accelerate through the intersection to clear it before the light turns red","Stop only if a sign tells you to, otherwise maintain your speed through the yellow","Slow down and stop safely behind the line, because yellow warns that red is coming","Treat the yellow like a flashing yellow and proceed through with caution without stopping"],"answer":2,"explanation":"A steady yellow means the light is about to turn red, so you should stop if you can do so safely rather than speed up to beat the light. Accelerating through (A) is the exact mistake the yellow warns against, and a flashing yellow (D) is a different signal that means caution and does not require stopping.","handbook":"On yellow you should not speed up to beat the light, since yellow warns that red is coming.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-TRAP-031"},{"q":"You are approaching an intersection late at night when the traffic signal switches to a flashing yellow light in your direction. There is no cross traffic visible. What should you do?","options":["Come to a complete stop behind the stop line, then proceed when the intersection is clear","Stop completely, treat it as an all-way stop, and yield to any vehicle on your right","Speed up to clear the intersection before the light changes to red","Slow down and proceed through the intersection carefully without stopping"],"answer":3,"explanation":"A flashing yellow light means caution: you slow down and proceed carefully without needing to stop. A full stop is required at a flashing red (which is treated like a stop sign), so options requiring a complete stop confuse the flashing red rule with the flashing yellow.","handbook":"At a flashing yellow signal you do not need to come to a complete stop, unlike at a flashing red.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-TRAP-032"},{"q":"You are driving on an unfamiliar two-lane road at dusk. The line down the center of the road, separating your lane from the lane next to you, is yellow. What does this color tell you about the traffic in the lane on the other side of that line?","options":["It is moving in the opposite direction, toward you","It is moving in the same direction as you","It is a lane reserved for HOV or carpool use","It is the right edge of the roadway"],"answer":0,"explanation":"Yellow center lines separate traffic moving in opposite directions, so the lane across a yellow line carries oncoming traffic. White lines, not yellow, separate traffic moving in the same direction, which makes B the trap.","handbook":"Yellow center lines separate traffic moving in opposite directions, while white lines separate same-direction traffic.","hbref":"Pavement line markings","qid":"DL-SIGNALSANDMARKINGS-TRAP-033"},{"q":"You arrive at a crosswalk on foot and want to cross the street. As you reach the curb, the pedestrian signal switches to a flashing DON'T WALK / raised hand. What does this mean for you?","options":["Do not start crossing now, but if you are already in the crosswalk you must turn back to the curb you came from","Do not begin crossing now; only those already in the crosswalk should continue and finish","You may begin crossing because flashing means caution, similar to a flashing yellow signal","You may begin crossing carefully, but only after stopping at the edge of the crosswalk first"],"answer":1,"explanation":"A flashing DON'T WALK warns pedestrians not to begin crossing; those already in the crosswalk should finish crossing. Option C wrongly borrows the flashing-yellow 'caution, proceed' meaning, and A invents a rule about turning back that the handbook does not state.","handbook":"A flashing DON'T WALK is a warning to pedestrians not to begin crossing, distinct from the steady DON'T WALK that means do not start at all.","hbref":"Pedestrian & lane signals","qid":"DL-SIGNALSANDMARKINGS-TRAP-034"},{"q":"You are stopped at a red light, intending to turn right. You see a sign at the intersection that reads 'NO TURN ON RED.' After coming to a complete stop and seeing that the cross traffic is clear, what should you do?","options":["Turn right, because a full stop satisfies the legal requirement for a right on red","Turn right slowly, since the lane is clear and you yielded properly","Remain stopped and wait for the green light before turning right","Treat the red light as a flashing red and proceed once traffic is clear"],"answer":2,"explanation":"When a posted sign prohibits turning right on red, you may not turn regardless of stopping or a clear path, so you must wait for the green light. Stopping fully only permits a right on red when no sign forbids it, and a steady red is never treated like a flashing red.","handbook":"When a permitted right turn on red is prohibited by a posted sign, you may not turn right on red even after stopping.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-TRAP-035"},{"q":"You are studying for the Texas driver-license knowledge test and want to be certain that a specific pavement-marking rule you read online is actually correct and currently enforced in Texas. To confirm what the official rules really are, which source should you rely on?","options":["Whatever the majority of online driving-quiz websites agree on, since they summarize many states' rules","Only the federal MUTCD, because national standards completely replace any state-specific Texas guidance","A neighboring state's driver handbook, since pavement markings are identical across all U.S. states","The Texas Driver Handbook (DPS, DL-7) together with the MUTCD national standards that apply in Texas"],"answer":3,"explanation":"The authoritative source of truth is the Texas Driver Handbook (DPS, DL-7) combined with the MUTCD national standards that apply in Texas. The MUTCD alone is not enough because it works together with the state handbook, and quiz sites or another state's handbook are not official Texas sources.","handbook":"The source of truth for these rules is the Texas Driver Handbook (DPS, DL-7) together with the MUTCD national standards that apply in Texas.","hbref":"Other markings","qid":"DL-SIGNALSANDMARKINGS-TRAP-036"},{"q":"You are driving on a two-lane road and there is a double solid yellow line down the center. A slow tractor is ahead of you, and just past it you see the driveway where you need to turn left into a parking lot. What are you legally allowed to do with that double solid yellow line?","options":["Cross it to make your left turn into the parking lot, but not to pass the tractor","Cross it to pass the tractor, since the lane ahead is clear","Cross it freely because double yellow lines only apply to oncoming traffic","Treat it like a broken yellow line and pass when it is safe to do so"],"answer":0,"explanation":"A double solid yellow line means no passing in either direction; you may cross it only to make a turn, such as turning left into a driveway or parking lot. Passing the tractor (B and D) is prohibited, and the line applies to drivers on both sides, not just oncoming traffic (C).","handbook":"A double solid yellow line may be crossed only to make a turn, not to pass.","hbref":"Pavement line markings","qid":"DL-SIGNALSANDMARKINGS-TRAP-037"},{"q":"You drive up to a railroad crossing marked with a large RXR symbol and a wide white stop line painted on the pavement. There are no flashing lights or gates, no train is in sight, and you can clearly hear and see that none is approaching. What should you do?","options":["Come to a full stop at the stop line and wait, since every railroad crossing requires a complete stop","Proceed across the tracks without stopping, but be ready to stop at the marked stop line if a train approaches","Slow down and treat the crossing as an all-way stop, yielding to traffic on your right first","Stop on the tracks momentarily to check both directions before continuing across"],"answer":1,"explanation":"At this type of railroad crossing you stop only if a train is approaching, and the stop must be made at the marked stop line; with no train coming you may proceed across without stopping. Option A is wrong because a stop is not required at every crossing when no train is near, and stopping on the tracks (D) is always dangerous.","handbook":"At a railroad crossing you stop only if a train approaches, with the stop made at the marked stop line.","hbref":"Other markings","qid":"DL-SIGNALSANDMARKINGS-TRAP-038"},{"q":"You are driving on a multi-lane freeway when you notice the overhead signal directly above your lane changes from a green down-arrow to a steady yellow X. What does this mean, and what should you do?","options":["Your lane is now closed for stopped traffic only; come to a complete stop within the lane and wait.","It is a caution signal like a flashing yellow light; slow down but stay in your current lane.","Your lane is changing use; safely move out of this lane into an open lane marked with a green down-arrow.","Pedestrians are crossing ahead; remain in your lane and yield until the signal clears."],"answer":2,"explanation":"A yellow X overhead lane-control signal means the lane is changing use and you should move out of it safely, while a green down-arrow marks a lane that is open. The caution answer confuses this with a flashing yellow traffic light, which applies to intersections, not overhead lane control.","handbook":"The lane-use green down-arrow, red X, and yellow X are overhead lane-control signals indicating whether a specific lane is open, closed, or changing use.","hbref":"Pedestrian & lane signals","qid":"DL-SIGNALSANDMARKINGS-TRAP-039"},{"q":"You are waiting at an intersection in the left-turn lane. The signal facing you displays a steady green LEFT arrow alongside a steady red light for the through lanes. Why can you begin your left turn without yielding to oncoming traffic?","options":["Because a green arrow means you must come to a full stop first and then turn only if the way is clear","Because the green arrow only gives caution, so you should slow down and yield to any oncoming cars before turning","Because oncoming traffic has a flashing yellow light telling them to proceed carefully through the intersection","Because the green arrow gives a protected turn, oncoming traffic is facing a red signal and is stopped during the arrow"],"answer":3,"explanation":"A green arrow grants a protected turn in the arrow's direction because oncoming traffic faces a red signal and is stopped, so you may turn without yielding. A green arrow is not a stop-and-go or caution signal, and oncoming drivers are stopped by red, not waved through by a flashing yellow.","handbook":"A green arrow provides a protected turn because oncoming traffic faces a red signal and is stopped during the arrow.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-TRAP-040"}]},{"id":"learn-signals-and-markings","name":"Traffic Signals & Markings — Learn","blurb":"Texas DL Traffic Signals & Markings: practice tests plus a Learning Test that walks the whole handbook section.","accent":"#0a7c43","kind":"learn","learnSubject":"signals-and-markings","classes":["DL"],"questions":[{"q":"What does a steady green traffic light mean?","options":["Go if the intersection is clear","Stop completely behind the line","Slow down and stop if safe","Treat it as a stop sign"],"answer":0,"explanation":"A steady green light means you may go if the intersection is clear, proceeding straight or turning after yielding.","handbook":"A steady green light means go if the intersection is clear; you may proceed straight or turn after yielding.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-LRN-001"},{"q":"What must you do before turning at a steady green light?","options":["Speed up to clear the turn","Yield to other traffic and pedestrians","Always come to a full stop first","Wait for a green arrow to appear"],"answer":1,"explanation":"At a steady green light you may turn only after yielding to other traffic and pedestrians.","handbook":"At a steady green light you may turn only after yielding to other traffic and pedestrians.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-LRN-002"},{"q":"What does a steady yellow traffic light mean?","options":["Speed up to clear the intersection","The light just turned green","The light is about to turn red","You have the right of way"],"answer":2,"explanation":"A steady yellow light warns that the signal is about to turn red, so stop if you can do so safely.","handbook":"A steady yellow light means the light is about to turn red.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-LRN-003"},{"q":"What should you do at a steady yellow traffic light?","options":["Speed up to beat the red","Always come to a full stop","Ignore it and keep driving","Stop if you can do so safely"],"answer":3,"explanation":"A steady yellow light means the light is about to turn red, so stop if you can do so safely and do not speed up.","handbook":"At a steady yellow light you should stop if you can do so safely, and you should not speed up.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-LRN-004"},{"q":"What does a steady red light mean?","options":["Stop completely until it turns green","Slow down and proceed with caution","Speed up to clear the intersection","Go if the intersection is clear"],"answer":0,"explanation":"A steady red light means stop completely behind the line and stay stopped until the light turns green.","handbook":"A steady red light means stop completely behind the line and remain stopped until the light turns green.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-LRN-005"},{"q":"At a red light where a right turn is allowed, what must you do first?","options":["Speed up and turn right","Stop fully, then turn if clear","Turn without stopping","Wait for a green arrow"],"answer":1,"explanation":"At a red light where right turns are permitted, you must stop completely, then turn right if it is clear and not prohibited by a sign.","handbook":"At a red light where a right turn is permitted, you must stop fully, then turn right if it is clear and not prohibited by a sign.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-LRN-006"},{"q":"What must you do at a flashing red light?","options":["Speed up to clear it","Slow down but keep going","Make a full stop, then go when safe","Ignore it if no cars are near"],"answer":2,"explanation":"A flashing red light means the same as a stop sign: stop fully, then go when it is safe.","handbook":"A flashing red light is treated as a STOP sign: you must come to a full stop, then proceed when it is safe.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-LRN-007"},{"q":"What does a flashing yellow traffic light mean?","options":["Stop completely, then go","The light is about to turn red","Lane is closed ahead","Caution: slow down and proceed carefully"],"answer":3,"explanation":"A flashing yellow light means caution, so slow down and proceed carefully without stopping.","handbook":"A flashing yellow light means caution: slow down and proceed carefully without stopping.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-LRN-008"},{"q":"What does a green arrow signal mean?","options":["A protected turn in the arrow's direction","Stop and wait for the next light","Slow down and yield to oncoming traffic","No turn is allowed in that direction"],"answer":0,"explanation":"A green arrow means a protected turn in the arrow's direction, and oncoming traffic is stopped.","handbook":"A green arrow means a protected turn in the arrow's direction, and oncoming traffic is stopped.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-LRN-009"},{"q":"What does a red arrow signal mean?","options":["Turn now if the way is clear","No turn that way; wait","Speed up to turn quickly","Turn only for trucks"],"answer":1,"explanation":"A red arrow means no turn is allowed in that direction, so you must wait.","handbook":"A red arrow means no turn is allowed in that direction; you must wait.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-LRN-010"},{"q":"How should you treat a dark or non-working traffic signal?","options":["Speed through it","Treat it as a green light","Treat it as an all-way stop","Ignore the intersection"],"answer":2,"explanation":"A dark or non-working signal should be treated as an all-way stop.","handbook":"A dark or non-working signal should be treated as an all-way STOP.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-LRN-011"},{"q":"What does a WALK signal mean?","options":["Cars must speed up","Bikes must stop","Drivers may turn left","Pedestrians may cross"],"answer":3,"explanation":"A WALK signal or walking-person symbol means pedestrians may cross.","handbook":"A WALK signal or walking-person symbol means pedestrians may cross.","hbref":"Pedestrian & lane signals","qid":"DL-SIGNALSANDMARKINGS-LRN-012"},{"q":"What does a steady DON'T WALK signal or steady raised-hand symbol mean?","options":["Do not start to cross","Begin crossing now","Cross only if running","Stop driving your car"],"answer":0,"explanation":"A steady DON'T WALK signal or steady raised-hand symbol means pedestrians should not start to cross.","handbook":"A steady DON'T WALK signal or steady raised-hand symbol means do not start to cross.","hbref":"Pedestrian & lane signals","qid":"DL-SIGNALSANDMARKINGS-LRN-013"},{"q":"What does a flashing DON'T WALK or raised-hand signal mean?","options":["Start crossing the street right away","Finish crossing if already started, but do not start","Run across the street quickly","Cross only if a car waves you on"],"answer":1,"explanation":"A flashing DON'T WALK means finish crossing if you have already started, but do not begin to cross.","handbook":"A flashing DON'T WALK or flashing raised-hand signal means finish crossing if already in the crosswalk, but do not start to cross.","hbref":"Pedestrian & lane signals","qid":"DL-SIGNALSANDMARKINGS-LRN-014"},{"q":"On a lane-use signal, what does a green down-arrow mean?","options":["The lane is closed","Move out of the lane","The lane is open","Slow down and stop"],"answer":2,"explanation":"A green down-arrow on a lane-use signal means the lane is open.","handbook":"On a lane-use signal, a green down-arrow means the lane is open.","hbref":"Pedestrian & lane signals","qid":"DL-SIGNALSANDMARKINGS-LRN-015"},{"q":"On a lane-use signal, what does a red X mean?","options":["The lane is open","Slow down in the lane","Move out of the lane soon","The lane is closed"],"answer":3,"explanation":"A red X on a lane-use signal means the lane is closed.","handbook":"On a lane-use signal, a red X means the lane is closed.","hbref":"Pedestrian & lane signals","qid":"DL-SIGNALSANDMARKINGS-LRN-016"},{"q":"On a lane-use signal, what does a yellow X over your lane mean?","options":["The lane is changing use, move out of it","The lane is open, you may use it","The lane is closed, never use it","Stop and wait in the lane"],"answer":0,"explanation":"A yellow X means the lane is changing use, so you should move out of it.","handbook":"On a lane-use signal, a yellow X means the lane is changing use and you should move out of it.","hbref":"Pedestrian & lane signals","qid":"DL-SIGNALSANDMARKINGS-LRN-017"},{"q":"What does a solid yellow line on your side of the road mean?","options":["Passing is allowed","No passing","Lane is closed","Stop ahead"],"answer":1,"explanation":"A solid yellow line on your side of the road means you may not pass.","handbook":"A solid yellow line on your side of the road means no passing.","hbref":"Pavement line markings","qid":"DL-SIGNALSANDMARKINGS-LRN-018"},{"q":"What does a broken (dashed) yellow line mean?","options":["No passing allowed","Stop and wait","Passing is allowed when safe","Lane is closed"],"answer":2,"explanation":"A broken (dashed) yellow line means passing is allowed when it is safe to do so.","handbook":"A broken (dashed) yellow line means passing is allowed when it is safe.","hbref":"Pavement line markings","qid":"DL-SIGNALSANDMARKINGS-LRN-019"},{"q":"What does a double solid yellow line mean?","options":["Passing is allowed both ways","Lanes go the same direction","You may pass when clear","No passing in either direction"],"answer":3,"explanation":"A double solid yellow line means no passing in either direction; do not cross it except to turn.","handbook":"A double solid yellow line means no passing in either direction; do not cross it except to turn.","hbref":"Pavement line markings","qid":"DL-SIGNALSANDMARKINGS-LRN-020"},{"q":"What do white lines on the road separate?","options":["Lanes going the same direction","Lanes going opposite directions","Parking spaces","Bike lanes only"],"answer":0,"explanation":"White lines separate lanes of traffic traveling in the same direction.","handbook":"White lines separate lanes of traffic traveling in the same direction.","hbref":"Pavement line markings","qid":"DL-SIGNALSANDMARKINGS-LRN-021"},{"q":"What does a broken white line mean?","options":["No passing allowed","Lane changes are allowed","Road edge ahead","Stop and wait here"],"answer":1,"explanation":"A broken white line means you may change lanes when it is safe.","handbook":"A broken white line means lane changes are allowed.","hbref":"Pavement line markings","qid":"DL-SIGNALSANDMARKINGS-LRN-022"},{"q":"What does a solid white line mean?","options":["You may pass other cars","Lane changes are allowed","Stay in your lane","Traffic moves the opposite way"],"answer":2,"explanation":"A solid white line means stay in your lane; crossing it is discouraged.","handbook":"A solid white line means stay in your lane; crossing it is discouraged.","hbref":"Pavement line markings","qid":"DL-SIGNALSANDMARKINGS-LRN-023"},{"q":"What do yellow lines on the road separate?","options":["Traffic moving in the same direction","Bike lanes from car lanes","Parking spaces","Traffic moving in opposite directions"],"answer":3,"explanation":"Yellow lines separate traffic moving in opposite directions, while white lines separate traffic moving in the same direction.","handbook":"Yellow lines separate traffic moving in opposite directions, while white lines separate traffic moving in the same direction.","hbref":"Pavement line markings","qid":"DL-SIGNALSANDMARKINGS-LRN-024"},{"q":"What does a solid white edge line mark?","options":["The right edge of the road","The left edge of the road","The center of the road","A passing zone"],"answer":0,"explanation":"A solid white edge line marks the right edge of the road.","handbook":"A solid white edge line marks the right edge of the road.","hbref":"Pavement line markings","qid":"DL-SIGNALSANDMARKINGS-LRN-025"},{"q":"What does a yellow edge line mark on a road?","options":["The right edge of the road","The left edge of the road","The center of a bike lane","A pedestrian crosswalk"],"answer":1,"explanation":"A yellow edge line marks the left edge of the road.","handbook":"A yellow edge line marks the left edge of the road.","hbref":"Pavement line markings","qid":"DL-SIGNALSANDMARKINGS-LRN-026"},{"q":"What is a stop line?","options":["A line for pedestrians to walk","A line that marks a bike lane","A wide white line showing where to stop","A line separating two-way traffic"],"answer":2,"explanation":"A stop line is a wide white line that shows where to stop, and you must stop behind it.","handbook":"A stop line is a wide white line that shows where to stop; you must stop behind it.","hbref":"Other markings","qid":"DL-SIGNALSANDMARKINGS-LRN-027"},{"q":"What does a crosswalk marked with white lines mean?","options":["It marks the road's edge","It is a carpool lane","It is closed to traffic","It is for pedestrians; stop before it"],"answer":3,"explanation":"A crosswalk has white markings for pedestrians, and you must stop before it.","handbook":"A crosswalk is marked with white markings for pedestrians, and you must stop before it.","hbref":"Other markings","qid":"DL-SIGNALSANDMARKINGS-LRN-028"},{"q":"What does a diamond symbol painted in a lane mean?","options":["Reserved HOV or carpool lane","Lane for trucks only","Bicycle lane ahead","Lane is closed"],"answer":0,"explanation":"A diamond symbol marks a reserved HOV, carpool, or special-use lane.","handbook":"A diamond symbol painted in a lane indicates a reserved HOV/carpool or special-use lane.","hbref":"Other markings","qid":"DL-SIGNALSANDMARKINGS-LRN-029"},{"q":"What is a bike lane marked for?","options":["Parking cars","Bicycles","Turning left","Emergency vehicles"],"answer":1,"explanation":"A bike lane is marked for bicycles, and you should not drive or park in it.","handbook":"A bike lane is a lane marked for bicycles, and you should not drive or park in it.","hbref":"Other markings","qid":"DL-SIGNALSANDMARKINGS-LRN-030"},{"q":"What does a yellow curb usually mean?","options":["Free parking anytime","Reserved disabled parking","No parking or loading restriction","Bus stop only"],"answer":2,"explanation":"A yellow curb indicates a no-parking or loading restriction, though curb colors vary by city.","handbook":"A yellow curb indicates a no-parking or loading restriction, though curb colors vary by city.","hbref":"Other markings","qid":"DL-SIGNALSANDMARKINGS-LRN-031"},{"q":"What pavement marking warns of a railroad crossing?","options":["A diamond symbol","A double yellow line","A white crosswalk","A large RXR"],"answer":3,"explanation":"A railroad crossing is marked on the pavement with a large RXR and a stop line.","handbook":"A railroad crossing is marked on the pavement with a large RXR and a stop line; stop if a train approaches.","hbref":"Other markings","qid":"DL-SIGNALSANDMARKINGS-LRN-032"},{"q":"What should you do at a steady yellow traffic light?","options":["Stop if you can do so safely","Speed up to beat the light","Always stop completely","Make a full stop, then go"],"answer":0,"explanation":"A steady yellow light means the light is about to turn red, so stop if you can do so safely and do not speed up.","handbook":"You should not speed up to beat a steady yellow light.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-LRN-033"},{"q":"At a steady red light, where must you stop?","options":["On top of the line","Behind the line","Past the line","In the crosswalk"],"answer":1,"explanation":"At a steady red light you must stop behind the line, not on or beyond it.","handbook":"At a steady red light you must stop behind the line, not on or beyond it.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-LRN-034"},{"q":"What does a green arrow signal mean?","options":["Slow down and yield to all traffic","Stop and wait before turning","Protected turn in the arrow's direction","No turn is allowed"],"answer":2,"explanation":"A green arrow means a protected turn in the arrow's direction because oncoming traffic is stopped.","handbook":"During a green arrow turn, oncoming traffic is stopped, making the turn protected.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-LRN-035"},{"q":"What must you do at a flashing red light?","options":["Speed up to clear it","Slow down and proceed with caution","Ignore it and keep going","Make a full stop, like a stop sign"],"answer":3,"explanation":"A flashing red light means make a full stop and go when safe, just like a stop sign.","handbook":"The difference between a flashing red and a flashing yellow is that flashing red requires a full stop (like a stop sign) while flashing yellow requires only slowing down with caution.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-LRN-036"},{"q":"At a red light, when is a permitted right turn allowed?","options":["When the way is clear and no sign prohibits it","At any time without stopping","Only when another car turns first","Never at a red light"],"answer":0,"explanation":"At a red light you may turn right only when the way is clear and no sign prohibits it.","handbook":"At a red light, a permitted right turn is only allowed when the way is clear and no sign prohibits it.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-LRN-037"},{"q":"What should you do if DON'T WALK starts flashing while you are crossing?","options":["Stop where you are","Finish crossing the street","Turn back to the curb","Run across quickly"],"answer":1,"explanation":"If the signal flashes while you are crossing, finish crossing rather than turn back.","handbook":"If the DON'T WALK or raised hand begins flashing while you are crossing, you should finish crossing rather than turn back.","hbref":"Pedestrian & lane signals","qid":"DL-SIGNALSANDMARKINGS-LRN-038"},{"q":"What does a red X over a lane mean?","options":["The lane is open","You must move out of the lane","The lane is closed","Pedestrians may cross"],"answer":2,"explanation":"A red X means the lane is closed, while a yellow X means the lane is changing use and you must move out of it.","handbook":"A red X over a lane and a yellow X over a lane differ in that red X means the lane is closed while yellow X means the lane is changing use and you must move out of it.","hbref":"Pedestrian & lane signals","qid":"DL-SIGNALSANDMARKINGS-LRN-039"},{"q":"What does a broken (dashed) yellow centerline mean?","options":["No passing on your side","No passing in either direction","Lanes go the same direction","Passing is allowed when safe"],"answer":3,"explanation":"A broken (dashed) yellow centerline means passing is allowed when it is safe.","handbook":"When passing is allowed when safe, the centerline is a broken (dashed) yellow line.","hbref":"Pavement line markings","qid":"DL-SIGNALSANDMARKINGS-LRN-040"},{"q":"When may you cross a double solid yellow line?","options":["Only to make a turn","Only to pass slow cars","Anytime it is clear","Only at night"],"answer":0,"explanation":"A double solid yellow line may be crossed only to make a turn.","handbook":"A double solid yellow line may be crossed only to make a turn.","hbref":"Pavement line markings","qid":"DL-SIGNALSANDMARKINGS-LRN-041"},{"q":"What should you do at a solid white line?","options":["Pass other cars","Stay in your lane","Make a U-turn","Park your car"],"answer":1,"explanation":"A solid white line means you should stay in your lane, as crossing it is discouraged.","handbook":"Crossing a solid white line is discouraged, so you should stay in your lane.","hbref":"Pavement line markings","qid":"DL-SIGNALSANDMARKINGS-LRN-042"},{"q":"Where should you stop at a stop line?","options":["On top of the line","Past the line","Behind the line","In the crosswalk"],"answer":2,"explanation":"A stop line shows where to stop, and you must stop behind it.","handbook":"The correct stopping position relative to a stop line is behind the line.","hbref":"Other markings","qid":"DL-SIGNALSANDMARKINGS-LRN-043"},{"q":"What color are crosswalk markings?","options":["Red","Blue","Green","White"],"answer":3,"explanation":"Crosswalk markings are white and are for pedestrians.","handbook":"Crosswalk markings are white and are for pedestrians.","hbref":"Other markings","qid":"DL-SIGNALSANDMARKINGS-LRN-044"},{"q":"What does a diamond symbol painted in a lane mean?","options":["The lane is reserved for carpools and high-occupancy vehicles","The lane is a bike lane","The lane is closed to all traffic","The lane is for turning only"],"answer":0,"explanation":"A diamond symbol marks a lane reserved for carpools and high-occupancy (HOV) vehicles.","handbook":"A lane reserved for carpools and high-occupancy vehicles is identified by a diamond symbol painted in the lane.","hbref":"Other markings","qid":"DL-SIGNALSANDMARKINGS-LRN-045"},{"q":"What may you do in a bike lane?","options":["Drive in it","Neither drive nor park in it","Park in it","Stop and wait in it"],"answer":1,"explanation":"You may not drive in a bike lane, and you may not park in a bike lane.","handbook":"You may not drive in a bike lane, and you may not park in a bike lane.","hbref":"Other markings","qid":"DL-SIGNALSANDMARKINGS-LRN-046"},{"q":"What does a solid yellow line on your side of the road mean?","options":["Passing is allowed","Lane is closed","No passing","Stop and wait"],"answer":2,"explanation":"A solid yellow line on your side means no passing.","handbook":"The source of truth for these traffic-signal and pavement-marking rules is the Texas Driver Handbook (DPS, DL-7) combined with the MUTCD.","hbref":"Source","qid":"DL-SIGNALSANDMARKINGS-LRN-047"},{"q":"Which traffic sign and signal standards apply in Texas?","options":["Only city rules","Only county rules","No set standards","Shared national standards"],"answer":3,"explanation":"Texas follows the shared national MUTCD standards for signs and signals.","handbook":"Shared national MUTCD standards apply in Texas.","hbref":"Source","qid":"DL-SIGNALSANDMARKINGS-LRN-048"},{"q":"What does a steady green traffic light mean?","options":["Proceed only if the intersection is clear","Stop completely behind the line","Slow down and prepare to stop","No turn is allowed in that direction"],"answer":0,"explanation":"A steady green light means go, but only proceed if the intersection is clear.","handbook":"Green means proceed only if the intersection is clear.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-LRN-049"},{"q":"What does a red X lane-use signal above a lane mean?","options":["The lane is open","The lane is closed","The lane is for turning","The lane is for parking"],"answer":1,"explanation":"A red X means the lane is closed, while a green down-arrow means the lane is open.","handbook":"A green down-arrow lane-use signal and a red X lane-use signal differ in that the green down-arrow means the lane is open while the red X means the lane is closed.","hbref":"Pedestrian & lane signals","qid":"DL-SIGNALSANDMARKINGS-LRN-050"},{"q":"What does a solid yellow line on your side of the road mean?","options":["Passing is allowed","Lane is closed","No passing","Stop and wait"],"answer":2,"explanation":"A solid yellow line on your side means no passing, while a broken yellow line allows passing when safe.","handbook":"A solid yellow line on your side prohibits passing, whereas a broken yellow line permits it.","hbref":"Pavement line markings","qid":"DL-SIGNALSANDMARKINGS-LRN-051"},{"q":"What color are the lines that separate traffic moving in opposite directions?","options":["Blue","Green","White","Yellow"],"answer":3,"explanation":"Yellow lines separate traffic moving in opposite directions and show passing rules.","handbook":"The color of lines that separate opposing directions of travel and indicate passing rules is yellow.","hbref":"Pavement line markings","qid":"DL-SIGNALSANDMARKINGS-LRN-052"},{"q":"What color are lines that separate lanes going the same direction?","options":["White","Yellow","Red","Blue"],"answer":0,"explanation":"White lines separate lanes of traffic traveling in the same direction.","handbook":"The color of lines used to separate lanes going the same direction is white.","hbref":"Pavement line markings","qid":"DL-SIGNALSANDMARKINGS-LRN-053"},{"q":"What must you do at a railroad crossing (RXR) marking if a train approaches?","options":["Speed up to cross first","Stop at the stop line","Honk and keep going","Change lanes"],"answer":1,"explanation":"At a railroad crossing marked RXR with a stop line, you must stop if a train approaches.","handbook":"At a railroad crossing pavement marking (RXR with a stop line), you must stop if a train approaches.","hbref":"Other markings","qid":"DL-SIGNALSANDMARKINGS-LRN-054"},{"q":"What should you do at an intersection when the traffic signal is completely dark or not working?","options":["Speed up to clear it quickly","Proceed without slowing down","Treat it as an all-way stop","Wait until the light turns on"],"answer":2,"explanation":"A dark or non-working signal should be treated as an all-way stop.","handbook":"When a traffic signal is completely dark or not working, drivers should treat the intersection as an all-way stop rather than proceeding without stopping.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-LRN-055"},{"q":"What does a steady raised-hand (DON'T WALK) signal mean for pedestrians?","options":["Cross faster","Run across now","Begin crossing","Do not start to cross"],"answer":3,"explanation":"A steady raised-hand (DON'T WALK) signal means pedestrians should not start to cross.","handbook":"A steady raised-hand (DON'T WALK) signal means pedestrians should not start to cross.","hbref":"Pedestrian & lane signals","qid":"DL-SIGNALSANDMARKINGS-LRN-056"},{"q":"What does a yellow curb generally mean?","options":["No parking or loading restriction","Free parking anytime","Reserved for buses only","Safe place to wait"],"answer":0,"explanation":"A yellow curb generally indicates a no-parking or loading restriction, though curb colors can vary by city.","handbook":"Curb colors and their parking meanings can vary by city, so a yellow curb generally indicates a no-parking or loading restriction.","hbref":"Other markings","qid":"DL-SIGNALSANDMARKINGS-LRN-057"},{"q":"What must you do at a steady red arrow?","options":["Turn in the arrow's direction","Wait; do not turn that way","Speed up through the turn","Yield, then turn freely"],"answer":1,"explanation":"A red arrow means you cannot turn in that direction and must wait until the signal changes.","handbook":"A red arrow prohibits turning in the arrow's direction until the signal changes; you must wait.","hbref":"Traffic signal lights","qid":"DL-SIGNALSANDMARKINGS-LRN-058"},{"q":"What does a broken white line on the road allow you to do?","options":["Pass a vehicle going the other way","Stop in the middle of the road","Change lanes when it is safe","Park along the road edge"],"answer":2,"explanation":"A broken white line allows you to change lanes when it is safe, while a solid white line means stay in your lane.","handbook":"A broken white line permits lane changes while a solid white line discourages crossing and signals you to stay in your lane.","hbref":"Pavement line markings","qid":"DL-SIGNALSANDMARKINGS-LRN-059"},{"q":"What does a stop line look like?","options":["A green dashed line","A row of small dots","A double yellow line","A wide white line across the lane"],"answer":3,"explanation":"A stop line is a wide white line painted across the lane to show where to stop.","handbook":"A stop line appears as a wide white line painted across the lane.","hbref":"Other markings","qid":"DL-SIGNALSANDMARKINGS-LRN-060"}]},{"id":"safe-driving","name":"Safe Driving","blurb":"Texas DL Safe Driving: practice tests plus a Learning Test that walks the whole handbook section.","accent":"#7c3aed","kind":"core","classes":["DL"],"questions":[{"q":"You're following a sedan on a dry highway. As its rear bumper passes a roadside sign, you start counting; you reach the same sign just under 2 seconds later. What does this tell you, and what should you do?","options":["You are following too closely; ease off the gas to open the gap to at least 3 seconds.","Your distance is safe because 2 seconds is the recommended minimum on dry roads.","Your distance is fine; the 3-second rule only applies in rain, fog, or ice.","You should brake hard immediately to drop back, since you are within the truck's No-Zone."],"answer":0,"explanation":"The three-second rule says that if you reach the fixed point in less than 3 seconds after the car ahead, you are too close, so easing off the gas to restore a 3-second gap is correct. Two seconds is not the safe minimum, the 3-second rule applies in all conditions (you add more seconds for bad weather), and braking hard or worrying about a truck's No-Zone does not fit this car-following scenario.","handbook":"Use the three-second rule: pick a fixed point; if you reach it less than 3 seconds after the car ahead, you are too close.","hbref":"Following distance & space","qid":"DL-SAFEDRIVING-TRAP-001"},{"q":"You normally leave a 3-second gap behind the car ahead. Tonight it starts raining hard on the freeway and a thick fog rolls in. What should you do about your following distance?","options":["Keep the same 3-second gap, since the three-second rule already covers all driving conditions","Increase the gap to more than 3 seconds, because rain and fog reduce traction and visibility","Reduce the gap so you can keep the car ahead's taillights in clear view through the fog","Switch on your high beams and hold a 2-second gap to react faster to its brake lights"],"answer":1,"explanation":"The three-second rule is a minimum for good conditions; in rain, fog, ice, or at high speed you must add more seconds because traction and visibility are reduced. Shortening the gap or relying on high beams (which reflect back off fog) only increases your danger.","handbook":"Add more seconds to your following distance in rain, fog, ice, or at high speed.","hbref":"Following distance & space","qid":"DL-SAFEDRIVING-TRAP-002"},{"q":"You are driving on a Texas highway when a pickup truck moves in close behind you and stays just a few feet off your bumper, clearly tailgating. What is the safest way to handle the space around your vehicle?","options":["Tap your brakes a few times to warn the tailgater to back off","Speed up so the tailgater falls farther behind you","Increase the following distance between you and the vehicle ahead so you have more room to brake gradually","Stay exactly three seconds behind the car ahead, since that rule already covers every situation"],"answer":2,"explanation":"When you are being tailgated, you should increase your following distance to the vehicle ahead so you can slow down or stop gradually instead of braking hard, giving the tailgater more time to react. Three seconds is only a minimum baseline and should be increased behind motorcycles, large trucks, and when tailgated, so option D is wrong, and brake-tapping or speeding up only raises the risk of a crash.","handbook":"Increase your following distance behind motorcycles, large trucks, and when you are being tailgated.","hbref":"Following distance & space","qid":"DL-SAFEDRIVING-TRAP-003"},{"q":"You are driving on a multi-lane highway alongside an 18-wheeler, staying just behind its cab where you cannot see the truck driver's side mirrors. What does this position tell you, and what should you do?","options":["The truck driver can see you fine, so you may stay there as long as you keep a steady speed","You should move closer to the trailer, since the safest spot is directly beside the rear wheels","You should flash your high beams so the truck driver knows you are there before passing","You are in the truck's blind spot (a No-Zone) because you can't see the driver's mirrors, so speed up or drop back to get out of it"],"answer":3,"explanation":"If you can't see a large truck's side mirrors, the driver can't see you, meaning you are sitting in a No-Zone blind spot; the safe response is to clear it quickly by speeding up to pass or easing back. Staying put, moving beside the rear wheels, or relying on high-beam flashes all leave you in the blind spot where the driver cannot see you.","handbook":"Large trucks and buses have big blind spots called No-Zones; if you can't see the driver's mirrors, the driver can't see you.","hbref":"Following distance & space","qid":"DL-SAFEDRIVING-TRAP-004"},{"q":"Driving on a Texas highway, you spot a stalled car ahead and bring your vehicle to a complete stop. Thinking back, you realize the whole stop took longer than you expected. Which three distances added together make up the total distance your car traveled from the moment the hazard appeared until you were fully stopped?","options":["Perception distance + reaction distance + braking distance","Perception distance + reaction distance + following distance","Reaction distance + braking distance + hydroplaning distance","Following distance + braking distance + headlight sight distance"],"answer":0,"explanation":"Total stopping distance is the sum of perception distance (seeing the hazard), reaction distance (moving your foot to the brake), and braking distance (the car slowing to a stop). Following distance, hydroplaning, and headlight sight distance are real safe-driving concepts but are not components of the stopping-distance formula.","handbook":"Total stopping distance = perception distance + reaction distance + braking distance.","hbref":"Stopping distance & speed","qid":"DL-SAFEDRIVING-TRAP-005"},{"q":"A deer suddenly steps into the road ahead of you on a dry highway. From the moment your eyes register the deer to the instant your foot actually starts pressing the brake, your car keeps rolling forward. About how long does that reaction time typically take for the average driver?","options":["About 1.5 seconds","About three-quarters (¾) of a second","About 3 seconds","About 35 seconds"],"answer":1,"explanation":"The average driver's reaction time is about ¾ of a second, so the car keeps moving during that interval before braking begins. Option A (about 1.5 s) is the combined perception-plus-reaction time, and 3 seconds is the safe-following-distance rule, not reaction time.","handbook":"The average driver's reaction time is about three-quarters (¾) of a second.","hbref":"Stopping distance & speed","qid":"DL-SAFEDRIVING-TRAP-006"},{"q":"You're driving on a Texas highway when a deer suddenly steps into the road far ahead. Before your car even begins to slow, two things must happen: your eyes and brain must perceive the deer, and then you must move your foot to the brake. Together, about how long does this perception-plus-reaction process take before the brakes actually start working?","options":["About 1,000 feet, the same distance at which you should be able to see ahead at night","About 3 seconds, because that's the safe following distance you should always keep","Roughly 1.5 seconds combined, before any braking distance is added","About 35 mph, the speed at which hydroplaning can begin on wet roads"],"answer":2,"explanation":"The combined perception-plus-reaction time is roughly 1.5 seconds, and this happens before braking distance is even added to the total stopping distance. The 3-second answer confuses the separate three-second following-distance rule with reaction time, and the other options misplace unrelated facts (night visibility distance and hydroplaning speed).","handbook":"The combined perception-plus-reaction time is roughly 1.5 seconds.","hbref":"Stopping distance & speed","qid":"DL-SAFEDRIVING-TRAP-007"},{"q":"On a dry Texas highway you normally need about 45 feet of braking distance to stop from 30 mph once your brakes are applied. Traffic opens up and you increase your speed from 30 mph to 60 mph. Roughly how much braking distance should you now expect to need to stop?","options":["About the same 45 feet, because braking distance does not change much with speed","About 90 feet, because doubling your speed doubles the braking distance","About 68 feet, because braking distance increases by only about half","About 180 feet, because doubling your speed roughly quadruples the braking distance"],"answer":3,"explanation":"Braking distance increases with the square of speed, so doubling speed from 30 to 60 mph roughly quadruples it (45 feet x 4 = about 180 feet). Option B is the common trap of assuming the relationship is simply linear (double speed = double distance).","handbook":"Braking distance increases with the square of speed: doubling your speed roughly quadruples the braking distance.","hbref":"Stopping distance & speed","qid":"DL-SAFEDRIVING-TRAP-008"},{"q":"You are leaving a 30 mph residential street and merging onto a highway where you double your speed to 60 mph. A child's ball suddenly rolls into the road ahead. Compared with stopping at 30 mph, how does your higher speed change your ability to stop?","options":["Your braking distance roughly quadruples, so it takes much farther to stop and any crash would hit harder","Your braking distance roughly doubles, matching the increase in your speed","Your stopping distance stays about the same because your reaction time is still about three-quarters of a second","Your stopping distance shortens because higher speed gives the brakes more energy to work with"],"answer":0,"explanation":"Braking distance increases with the square of speed, so doubling your speed from 30 to 60 mph roughly quadruples the braking distance and a crash carries far more energy. Doubling speed does not merely double braking distance, and a faster speed never shortens stopping distance even though reaction time stays about three-quarters of a second.","handbook":"The faster you go, the longer it takes to stop and the harder a crash will be (speed-energy).","hbref":"Stopping distance & speed","qid":"DL-SAFEDRIVING-TRAP-009"},{"q":"It has been raining steadily on the highway and there is standing water in the lane. You are driving about 40 mph when you feel the steering go light and the front tires seem to skim across the water. What is the safest way to regain traction?","options":["Brake firmly to slow the tires and let them grip the road again","Ease off the gas, keep the steering wheel straight, and do not brake hard","Steer in the direction you want the front of the car to go and pump the brakes","Turn on your high beams and add one second to your following distance"],"answer":1,"explanation":"You are hydroplaning, which can begin near 35 mph as water builds under the tires; easing off the gas, steering straight, and avoiding hard braking lets the tires settle back onto the road. Braking firmly (A) can lock the tires and worsen the slide, and steering/pumping advice (C) is the procedure for a skid, not hydroplaning.","handbook":"On wet roads slow down; hydroplaning can start near 35 mph as water builds under the tires.","hbref":"Weather & reduced traction","qid":"DL-SAFEDRIVING-TRAP-010"},{"q":"You're driving 45 mph on a Texas highway during a steady downpour when you suddenly feel the steering go light and the car begins to glide as if floating on the water. What should you do?","options":["Pump the brake pedal firmly to dig the tires back into the pavement","Steer in the direction you want the front of the car to go and brake gently","Ease off the gas, keep the wheel steady and pointed straight, and avoid braking hard","Brake hard immediately and downshift to a lower gear to slow the car"],"answer":2,"explanation":"When hydroplaning, the tires lose contact with the road, so you should ease off the gas, hold the wheel straight, and avoid braking hard until traction returns. Braking hard (A, D) can cause a skid, and the steer-where-you-want technique (B) applies to correcting a skid, not recovering from hydroplaning.","handbook":"If you begin to hydroplane, ease off the gas, don't brake hard, and steer straight.","hbref":"Weather & reduced traction","qid":"DL-SAFEDRIVING-TRAP-011"},{"q":"After three weeks without rain, a light drizzle begins to fall as you drive through town. The road surface looks barely wet, and traffic around you keeps moving at the normal speed limit. Why should you be especially cautious about traction right now?","options":["Light rain cannot reduce traction, so the only real danger is heavy downpours that pool water on the road","Bridges and overpasses are the only surfaces that get slippery this early in a rainstorm","The road is most slippery once enough water has built up to start hydroplaning near 35 mph","Oil and grease built up during the dry spell mix with the first light rain, making the road most slippery now"],"answer":3,"explanation":"The first rain after a dry spell is the most slippery because accumulated oil and grease mix with the water before being washed away, so a light early drizzle is more dangerous than it looks. Option C is a real fact about hydroplaning but describes a different hazard that needs water to build up, not the slick oily film of the first rain.","handbook":"The first rain after a dry spell is the most slippery because oil mixes with water.","hbref":"Weather & reduced traction","qid":"DL-SAFEDRIVING-TRAP-012"},{"q":"It is just below freezing on a clear morning and you are driving on a rural highway. The road surface ahead looks dry and you feel good traction. As you approach a bridge spanning a creek, what should you do?","options":["Ease off the gas and slow down before the bridge, because bridges and overpasses freeze before the rest of the road","Maintain your speed, since the dry road behind you proves the bridge surface is also safe","Brake hard right as you reach the bridge to test whether the surface is slippery","Switch to high beams so you can spot ice on the bridge sooner"],"answer":0,"explanation":"Bridges and overpasses are exposed to cold air on all sides, so they freeze before regular pavement; easing off the gas and slowing down before the bridge is the safe response. Maintaining speed because the road behind feels dry ignores that the bridge can be icy even when the surrounding road is not, and braking hard on a possibly icy surface can cause a skid.","handbook":"Bridges and overpasses freeze first in icy conditions.","hbref":"Weather & reduced traction","qid":"DL-SAFEDRIVING-TRAP-013"},{"q":"It's a clear, very cold winter morning around 30°F. You're driving on a highway and approach an overpass. The pavement ahead looks slightly darker and wet but you don't see any obvious ice. What is the safest way to handle this situation?","options":["The road only looks wet, so maintain your speed and brake firmly if you start to slip","Treat the dark, wet-looking patch as possible black ice; slow down gradually before the overpass and avoid sudden braking or steering","Switch to your high beams so the wet pavement reflects more light and you can see the surface better","Speed up to cross the overpass quickly so you spend less time on the slippery surface"],"answer":1,"explanation":"Bridges and overpasses freeze first, and black ice is hard to see, so a dark, wet-looking patch in freezing temperatures should be treated as ice by slowing gradually and avoiding sudden braking or steering. Maintaining speed (A) assumes the surface is only wet, and speeding up (D) increases the risk of a skid you cannot control.","handbook":"Black ice is hard to see.","hbref":"Weather & reduced traction","qid":"DL-SAFEDRIVING-TRAP-014"},{"q":"You're driving on a damp Texas highway when your car's rear end suddenly slides to the right and the back begins to swing out. What should you do to regain control?","options":["Press firmly on the brakes to slow the car immediately, then straighten the wheel","Keep steady pressure on the gas to pull the car forward and out of the slide","Take your foot off the gas and steer in the direction you want the front of the car to go, without slamming the brakes","Shift into a lower gear and pump the brake pedal repeatedly until traction returns"],"answer":2,"explanation":"In a skid you should ease off the gas and steer in the direction you want the front of the car to go, never slamming the brakes, which would only worsen the loss of traction. Hard braking (A) and pumping the brake while downshifting (D) are recovery steps for other emergencies, not skids, and holding the gas (B) keeps the wheels spinning.","handbook":"In a skid, take your foot off the gas and steer in the direction you want the front of the car to go; don't slam the brakes.","hbref":"Weather & reduced traction","qid":"DL-SAFEDRIVING-TRAP-015"},{"q":"You are driving on a rural highway at night when you suddenly enter a thick patch of fog and can barely see the road ahead. What should you do?","options":["Switch on your high beams so the brighter light cuts farther through the fog","Keep your current speed but turn on your hazard flashers to stay visible","Steer toward the right edge of the road and look away from the glare","Switch to low beams, slow down, and pull off safely if visibility gets too poor"],"answer":3,"explanation":"In fog or smoke you should use low beams because high beams reflect off the moisture and glare back at you, and you should slow down or pull off safely. High beams (A) make visibility worse, and looking to the right edge (C) is the response for oncoming headlight glare, not fog.","handbook":"In fog or smoke use low beams because high beams reflect back; slow down or pull off safely.","hbref":"Weather & reduced traction","qid":"DL-SAFEDRIVING-TRAP-016"},{"q":"You're driving home on a clear afternoon when a heavy storm rolls in. Visibility drops so much that you can barely make out a road sign about 800 feet ahead, even though it's well before sunset. What should you do about your lights?","options":["Turn on your headlights, because you must use them any time you can't see about 1,000 feet ahead, regardless of the time of day.","Leave your headlights off, since the rule to use them only applies between sunset and sunrise.","Switch on your high beams to cut through the rain and improve how far you can see.","Keep your lights off but slow down, because headlights are only required when you can't see about 500 feet ahead."],"answer":0,"explanation":"Texas requires headlights from sunset to sunrise AND any time you cannot see about 1,000 feet ahead, so the reduced visibility means you must turn them on even in daylight. High beams reflect off rain and fog and make it harder to see, and 500 feet is the dimming distance for oncoming traffic, not the visibility threshold for using lights.","handbook":"Use headlights from sunset to sunrise and any time you can't see about 1,000 feet ahead.","hbref":"Night & visibility","qid":"DL-SAFEDRIVING-TRAP-017"},{"q":"You are driving on a dark two-lane country road at night with your high beams on. You spot a vehicle approaching you in the opposite lane, and you estimate it is now a bit less than 500 feet away. What should you do?","options":["Keep your high beams on until the other vehicle dims its lights first","Dim your high beams to low beams now","Switch to low beams only if you are also within 300 feet behind another vehicle","Flash your high beams to warn the oncoming driver, then continue on high"],"answer":1,"explanation":"Texas requires you to dim high beams to low when within 500 feet of an oncoming vehicle, so you must switch now. Waiting for the other driver (A) or flashing (D) keeps blinding glare on the road, and the 300-foot rule (C) applies to following behind a vehicle, not to oncoming traffic.","handbook":"Dim high beams to low when within 500 feet of an oncoming vehicle.","hbref":"Night & visibility","qid":"DL-SAFEDRIVING-TRAP-018"},{"q":"You are driving on a dark rural highway at night with your high beams on. You catch up to a slower car ahead and gradually close the gap until you are roughly 250 feet behind it, with no oncoming traffic visible. What should you do with your high beams?","options":["Keep the high beams on, since the rule to dim only applies to oncoming vehicles you meet head-on","Leave the high beams on until you are within 100 feet of the car ahead, then switch to low","Switch to low beams now, because you must dim within 300 feet when following another vehicle","Keep the high beams on but look toward the right edge of the road to avoid glare"],"answer":2,"explanation":"Texas law requires you to dim your high beams to low when within 300 feet behind another vehicle, so at 250 feet you must already be on low beams. The high beams glare in the lead driver's mirrors; the 500-foot rule (A) applies to oncoming traffic, and looking to the right edge (D) is the technique for when you are blinded, not for following.","handbook":"Dim high beams to low when within 300 feet behind another vehicle.","hbref":"Night & visibility","qid":"DL-SAFEDRIVING-TRAP-019"},{"q":"You're driving on a dark two-lane highway at night when an oncoming car fails to dim its high beams, and the glare makes it hard for you to see the road ahead. What should you do to keep control until the vehicle passes?","options":["Switch on your own high beams so the other driver sees how bright it is and dims them","Brake hard immediately and come to a stop in your lane until your eyes recover","Stare directly at the oncoming headlights so you can track exactly where the other car is","Slow down and look toward the right edge of your lane until the vehicle has passed"],"answer":3,"explanation":"When blinded by oncoming high beams, you should look toward the right edge of the road to avoid the glare while still guiding your car. Flashing your own high beams or staring into the lights only worsens the blindness, and stopping hard in a travel lane risks a rear-end collision.","handbook":"If blinded by oncoming high beams, look toward the right edge of the road.","hbref":"Night & visibility","qid":"DL-SAFEDRIVING-TRAP-020"},{"q":"You're driving on a dark rural highway at night with your low beams on. The road ahead is lit only as far as your headlights reach, and you're traveling fast enough that a deer suddenly stepping into that lit area would be inside your stopping distance before you could react and brake. What mistake are you making?","options":["You're overdriving your headlights—going so fast you can't stop within the lighted distance ahead","You're following the three-second rule incorrectly for the conditions","You failed to dim your high beams within 500 feet of an oncoming vehicle","You're hydroplaning because your speed exceeded the safe limit for the surface"],"answer":0,"explanation":"Overdriving your headlights means traveling so fast that you cannot stop within the distance your headlights illuminate ahead, which is exactly the scenario described. The three-second rule applies to spacing behind another vehicle, dimming high beams concerns glare to others, and hydroplaning involves water on the road—none fit a dry night road with a fixed lighted distance.","handbook":"Overdriving your headlights means going so fast you can't stop within the lighted distance ahead.","hbref":"Night & visibility","qid":"DL-SAFEDRIVING-TRAP-021"},{"q":"You are driving down a long hill when you press the brake pedal and it sinks to the floor with almost no resistance. The car keeps gaining speed. What is the best way to slow down and stop?","options":["Hold the wheel firmly, ease off the gas, and do not brake hard, then pull off slowly","Pump the brake pedal, shift to a lower gear, and apply the parking brake gradually","Take your foot off the gas and steer in the direction you want the front of the car to go","Yank the parking brake all the way up at once and turn off the engine to kill the speed"],"answer":1,"explanation":"When the brakes fail, pumping the pedal may restore some pressure, shifting to a lower gear uses engine braking to slow you, and applying the parking brake gradually brings you to a stop. Option A is the correct response to a tire blowout, and pulling the parking brake all the way up at once (D) can cause a skid.","handbook":"For brake failure: pump the pedal, shift to a lower gear, and use the parking brake gradually.","hbref":"Emergencies & breakdowns","qid":"DL-SAFEDRIVING-TRAP-022"},{"q":"You're driving 60 mph on a Texas highway when you hear a loud bang and your steering suddenly pulls hard to one side. You realize a front tire has blown out. What is the safest way to regain control?","options":["Slam on the brakes immediately to stop as fast as possible before the car swerves further","Jerk the wheel toward the opposite side to counter the pull, then brake hard onto the shoulder","Grip the wheel firmly, ease your foot off the gas, and let the car slow gradually before pulling off the road","Pump the brake pedal and shift into a lower gear to slow the vehicle down"],"answer":2,"explanation":"In a blowout you hold the wheel firmly, ease off the gas, and avoid braking hard, then pull off slowly once the car has slowed. Braking hard (A) or jerking the wheel (B) can cause a complete loss of control, and pumping the pedal with a lower gear (D) is the technique for brake failure, not a tire blowout.","handbook":"For a tire blowout: hold the wheel firmly, ease off the gas, do NOT brake hard, then pull off slowly.","hbref":"Emergencies & breakdowns","qid":"DL-SAFEDRIVING-TRAP-023"},{"q":"Your car's engine dies while you are crossing a railroad track at a rural crossing. The car won't restart, and you can see a train approaching in the distance. What should you do?","options":["Stay buckled in the car and quickly pump the brake pedal to roll the car off the tracks","Turn on your hazard flashers and wait in the vehicle for the train to pass","Shift to a lower gear and try to drive across before the train reaches the crossing","Get everyone out of the car and move far away from the tracks, then call for help"],"answer":3,"explanation":"If your vehicle stalls on railroad tracks, the only priority is getting everyone out and well away from the tracks before calling for help, because you can never safely beat an approaching train. Pumping the brake, waiting in the car, or trying to drive across all keep people in the path of the train.","handbook":"If your vehicle stalls on railroad tracks: get everyone out and away, then call for help; never try to beat a train.","hbref":"Emergencies & breakdowns","qid":"DL-SAFEDRIVING-TRAP-024"},{"q":"Your engine suddenly loses power on a rural two-lane highway and you manage to coast to the edge of the road. There is a wide paved shoulder available. What is the correct way to stop and protect yourself while you wait for help?","options":["Pull completely onto the shoulder, turn on your hazard flashers, and set out warning devices behind your vehicle.","Stop in your lane with the parking brake on so other drivers see you clearly, and turn on your headlights.","Leave the rear of the car in the lane, pump the brake pedal, and shift to a lower gear to stay visible.","Park halfway on the shoulder, get out, and stand in the lane to wave traffic around you."],"answer":0,"explanation":"If you must stop on the road, pull fully onto the shoulder, turn on your hazard flashers, and use warning devices so approaching traffic is alerted. Stopping in the lane or leaving part of the car in traffic exposes you to a rear-end crash, and pumping the brake/shifting down is the procedure for brake failure, not a stopped breakdown.","handbook":"If you must stop on the road, pull fully onto the shoulder, turn on hazard flashers, and use warning devices.","hbref":"Emergencies & breakdowns","qid":"DL-SAFEDRIVING-TRAP-025"},{"q":"You've been driving for six hours on a long road trip and notice you're yawning constantly, drifting toward the lane line, and struggling to remember the last few miles. Your destination is still two hours away. What should you do?","options":["Roll down the window and turn up the radio to stay alert, then keep driving to your destination","Pull off at a safe rest stop and take a nap or stop for the night, because drowsiness slows your reaction time and judgment just like alcohol","Increase your following distance to the three-second rule and continue driving the remaining two hours","Switch on your high beams to see farther ahead and push through the last two hours"],"answer":1,"explanation":"Fatigue slows reaction time and impairs judgment much like drugs or alcohol, so the only safe choice is to stop and rest rather than drive drowsy. Tricks like fresh air, loud music, or a longer following distance do not cure drowsiness, and high beams have nothing to do with the danger of falling asleep at the wheel.","handbook":"Fatigue, drugs, and alcohol all slow reaction time and judgment; never drive impaired or drowsy.","hbref":"Impairment & distraction (safety)","qid":"DL-SAFEDRIVING-TRAP-026"},{"q":"You're stopped at a red light in Texas when a text message arrives on your phone. The light is still red and traffic is heavy. What should you do?","options":["Quickly reply now while stopped, since handling it before the light turns green is the safest moment","Glance at the screen only to read it, because reading a text is permitted as long as you don't type","Leave the phone alone and wait until you are safely parked, because texting while driving is illegal in Texas and a major distraction","Reply, but first turn on your hazard flashers to warn drivers that you are temporarily occupied"],"answer":2,"explanation":"Texting while driving is illegal in Texas and is a major distraction, so you should not text from behind the wheel even when stopped at a light; wait until you are safely parked. Reading or replying at a red light is still using the phone to text, and hazard flashers are for a disabled or stopped-on-the-road vehicle, not for excusing phone use.","handbook":"Texting and handheld phone use are major distractions; texting while driving is illegal in Texas.","hbref":"Impairment & distraction (safety)","qid":"DL-SAFEDRIVING-TRAP-027"},{"q":"You're driving two friends to a game in Texas. One sits up front, the other climbs into the back seat and says, \"I'll skip the belt, I'm only riding back here for ten minutes.\" What should you do before pulling out?","options":["Let the back-seat passenger ride unbelted, since seat belt rules only apply to the driver and front-seat passengers","Allow it because the trip is short and you'll be staying on slow neighborhood streets","Hand him your phone to text someone for a ride instead, so he doesn't have to ride unbelted","Insist he buckle up before you drive, because Texas law requires the driver and all passengers to wear a seat belt"],"answer":3,"explanation":"Texas law requires a seat belt for the driver and every passenger, including those in the back seat, regardless of how short the trip is. Options A and B rely on common myths (rear seats are exempt, or short/slow trips don't count), and texting while driving is itself illegal and unsafe.","handbook":"Always wear your seat belt; Texas law requires it for the driver and all passengers.","hbref":"Impairment & distraction (safety)","qid":"DL-SAFEDRIVING-TRAP-028"},{"q":"You're driving on a dry highway behind a pickup truck. To check your following distance, you watch the truck pass an overpass shadow on the road, then count until the front of your car reaches that same spot. How long should that count be for your following distance to be considered adequate?","options":["Three seconds or more after the truck passes the point","Less than three seconds after the truck passes the point","About three-quarters of a second, matching average reaction time","Exactly 500 feet of space behind the truck"],"answer":0,"explanation":"With the three-second rule, you pick a fixed point and count; reaching it in three seconds or more after the vehicle ahead means your following distance is adequate. Reaching it in less than three seconds means you are too close, while three-quarters of a second describes average reaction time and 500 feet is the high-beam dimming distance, not a following gap.","handbook":"With the three-second rule, reaching the fixed point in 3 seconds or more after the car ahead means your following distance is adequate.","hbref":"Following distance & space","qid":"DL-SAFEDRIVING-TRAP-029"},{"q":"You're following a pickup truck on a dry highway and want to check whether you're keeping a safe following distance using the three-second rule. The truck's rear bumper just passes a road sign up ahead. What should you do to apply the rule correctly?","options":["Start counting when the truck passes the sign and stop counting after three seconds, then make sure the truck is still within that distance.","Start counting when the truck's rear passes the sign and stop when your front bumper reaches the same sign; if it's less than three seconds, you're too close.","Measure three car lengths of space between your front bumper and the truck's rear bumper.","Count the seconds it takes the truck to come to a complete stop from the moment it passes the sign."],"answer":1,"explanation":"The three-second rule works by picking a fixed point and counting the seconds between when the vehicle ahead passes it and when you pass the same point; under three seconds means you're following too closely. Fixed car-length spacing (C) and timing the lead vehicle's stop (D) are not how the rule works.","handbook":"The three-second rule works by counting the seconds between when the vehicle ahead passes a fixed point and when you pass the same point.","hbref":"Following distance & space","qid":"DL-SAFEDRIVING-TRAP-030"},{"q":"You are driving on a clear highway and a deer suddenly jumps onto the road ahead. You see it, decide to stop, and press the brake. Once your foot is pressing the brake pedal, the distance your car keeps traveling before it finally comes to a complete stop is known as what?","options":["Total stopping distance, which is the full distance from seeing the deer until the car stops","Reaction distance, the distance traveled while you decide to press the brake","Braking distance, one of the three components of total stopping distance","Perception distance, the distance traveled before your eyes notice the deer"],"answer":2,"explanation":"Braking distance is the distance the vehicle travels from the moment the brakes are applied until it stops, and it is one of the three components of total stopping distance (perception + reaction + braking). Total stopping distance is the sum of all three, not just the part after braking begins, so that option is the trap.","handbook":"Braking distance is the distance a vehicle travels from the moment the brakes are applied until it stops, and it is one of the three components of total stopping distance.","hbref":"Stopping distance & speed","qid":"DL-SAFEDRIVING-TRAP-031"},{"q":"You are driving at highway speed when a deer suddenly steps into your lane far ahead. Before your foot ever touches the brake pedal, your vehicle has already traveled some distance. Which components of total stopping distance account for that travel that happens BEFORE the brakes are actually applied?","options":["Braking distance and reaction distance","Perception distance and braking distance","Braking distance only, since the car keeps moving until the wheels lock","Perception distance and reaction distance"],"answer":3,"explanation":"Total stopping distance is perception distance plus reaction distance plus braking distance, and only perception and reaction distance occur before the brakes are applied; braking distance is the travel after the brakes engage, so any option containing braking distance is wrong.","handbook":"Perception distance and reaction distance are the components of stopping distance covered before the brakes are actually applied.","hbref":"Stopping distance & speed","qid":"DL-SAFEDRIVING-TRAP-032"},{"q":"You're driving about 40 mph on a Texas highway during a heavy rainstorm when you suddenly feel the steering go light and the car begins to slide on top of the water without responding to the wheel. What is the safest way to react?","options":["Ease your foot off the gas, keep the steering wheel straight, and let the car slow until the tires grip again","Press firmly and steadily on the brakes to scrub off speed and regain traction quickly","Turn the wheel sharply toward the shoulder to steer out of the water film","Pump the brake pedal rapidly and shift into a lower gear to control the slide"],"answer":0,"explanation":"During hydroplaning the tires ride on a layer of water and lose contact with the road, so you should ease off the gas, steer straight, and avoid braking hard until traction returns. Braking firmly (B) or pumping the brakes (D) is a real technique for other emergencies like brake failure, but hard braking during hydroplaning can cause you to skid out of control.","handbook":"During hydroplaning the tires ride on a layer of water and lose contact with the road, so hard braking should be avoided.","hbref":"Weather & reduced traction","qid":"DL-SAFEDRIVING-TRAP-033"},{"q":"It is just below freezing on a clear winter morning. The asphalt highway looks dry, but you are approaching a long overpass. To drive safely, what should you expect and do?","options":["The overpass is the warmest part of the road, so you can keep your current speed across it","The overpass may be icy even though the road looks dry, so slow down before reaching it","Hydroplaning is the main danger on the overpass, so ease off the gas and steer straight","Use your high beams across the overpass to spot any ice ahead of you"],"answer":1,"explanation":"Bridges and overpasses freeze before the rest of the roadway because cold air reaches them from all sides, so they can be icy even when the surrounding pavement looks dry; slowing before the overpass is the safe move. Hydroplaning involves water on the road near 35 mph, not freezing, and high beams do not help here, so those are the traps.","handbook":"Bridges and overpasses freeze before the rest of the roadway because they are exposed to cold air on all sides.","hbref":"Weather & reduced traction","qid":"DL-SAFEDRIVING-TRAP-034"},{"q":"It is 2:00 in the afternoon on a Texas highway when a sudden, heavy downpour sets in. The rain is so dense that you can barely make out the taillights of the vehicle a couple hundred feet ahead, and you estimate you can no longer see clearly even 1,000 feet down the road. What should you do about your lights?","options":["Leave your headlights off because it is daytime, and only switch on your hazard flashers while you keep moving","Switch on your high beams so the heavy rain ahead is lit up as far as possible","Turn on your headlights, since you must use them any time you cannot see about 1,000 feet ahead, even in daylight","Keep your headlights off but turn on your interior dome light to stay visible to other drivers"],"answer":2,"explanation":"In Texas you must use headlights any time you cannot see roughly 1,000 feet ahead, which includes daytime conditions like heavy rain, so turning them on is correct. High beams are wrong because in rain or fog they reflect back and reduce visibility, and hazard flashers or a dome light are no substitute for headlights while you are driving.","handbook":"Headlights must be turned on whenever visibility ahead is less than about 1,000 feet, even during daylight conditions like heavy rain.","hbref":"Night & visibility","qid":"DL-SAFEDRIVING-TRAP-035"},{"q":"You are driving at night on a dark two-lane highway with your high beams on. Ahead, a car is coming toward you in the opposite lane, and at the same time you are gradually catching up to a slower truck in your own lane just ahead. What does Texas law require you to do with your high beams?","options":["Keep high beams on for the oncoming car but dim them for the truck ahead, since following traffic matters more","Dim them only for the oncoming car within 500 feet; high beams behind another vehicle are allowed at any distance","Dim them only for the truck ahead within 300 feet; high beams toward oncoming traffic are allowed at any distance","Dim them to low beams for the oncoming car when within 500 feet and for the truck ahead when within 300 feet"],"answer":3,"explanation":"Texas law requires dimming high beams to low within 500 feet of an oncoming vehicle and within 300 feet when approaching another vehicle from behind, so in this scenario both situations require low beams. Options that excuse you from dimming for one of the two vehicles ignore half the rule and would blind another driver.","handbook":"High beams must be dimmed both for oncoming traffic (within 500 feet) and when approaching a vehicle from behind (within 300 feet).","hbref":"Night & visibility","qid":"DL-SAFEDRIVING-TRAP-036"},{"q":"You're driving 65 mph on a Texas interstate when you hear a loud bang and the steering suddenly pulls hard to one side—a front tire has blown out. What should you do?","options":["Grip the wheel firmly to keep the car straight, gradually ease off the gas, and pull off the road slowly once you've slowed down","Brake firmly and immediately to bring the vehicle to a stop as quickly as possible","Take your foot off the gas and steer in the direction you want the front of the car to go","Pump the brake pedal and shift into a lower gear to slow the vehicle"],"answer":0,"explanation":"During a blowout you must hold the wheel firmly and gradually ease off the gas before pulling off slowly—braking hard (B) can cause you to lose control. Steering toward where you want the front to go (C) is the fix for a skid, and pumping the brakes with a lower gear (D) is the procedure for brake failure, not a blowout.","handbook":"During a tire blowout you should not brake hard; instead hold the wheel firmly and gradually ease off the gas before pulling off slowly.","hbref":"Emergencies & breakdowns","qid":"DL-SAFEDRIVING-TRAP-037"}]},{"id":"learn-safe-driving","name":"Safe Driving — Learn","blurb":"Texas DL Safe Driving: practice tests plus a Learning Test that walks the whole handbook section.","accent":"#0a7c43","kind":"learn","learnSubject":"safe-driving","classes":["DL"],"questions":[{"q":"What is the three-second rule used for?","options":["Keeping a safe following distance","Knowing when to change your oil","Setting your parking brake","Timing how long to signal"],"answer":0,"explanation":"The three-second rule helps you keep a safe following distance behind the car ahead.","handbook":"Use the three-second rule: pick a fixed point and if you reach it less than 3 seconds after the car ahead, you are following too closely.","hbref":"Following distance & space","qid":"DL-SAFEDRIVING-LRN-001"},{"q":"How do you use the three-second rule?","options":["Count three car lengths ahead","Count the seconds to reach a fixed point","Drive three miles per hour slower","Wait three seconds at every stop"],"answer":1,"explanation":"Pick a fixed point ahead and count the seconds it takes to reach it after the car ahead passes it.","handbook":"To use the three-second rule, pick a fixed point ahead and count the seconds it takes you to reach it after the vehicle ahead passes it.","hbref":"Following distance & space","qid":"DL-SAFEDRIVING-LRN-002"},{"q":"When should you add more seconds to your following distance?","options":["On dry, clear roads","When traffic is light","In rain, fog, ice, or at high speed","When driving slowly"],"answer":2,"explanation":"Add more seconds to your following distance in rain, fog, ice, or at high speed.","handbook":"Add more seconds to your following distance in rain, fog, ice, or at high speed.","hbref":"Following distance & space","qid":"DL-SAFEDRIVING-LRN-003"},{"q":"When should you add extra seconds to the three-second following distance?","options":["Only on sunny days","When the road is dry and empty","When traffic is light","In rain, fog, ice, or at high speed"],"answer":3,"explanation":"Rain, fog, ice, and high speed all require adding extra seconds to your following distance.","handbook":"Rain, fog, ice, and high speed are conditions that require adding extra seconds to the three-second following distance.","hbref":"Following distance & space","qid":"DL-SAFEDRIVING-LRN-004"},{"q":"When should you increase your following distance?","options":["When driving behind a motorcycle or large truck","When the road is dry and clear","When traffic is light","When you are in a hurry"],"answer":0,"explanation":"Increase your following distance behind motorcycles, large trucks, or when being tailgated.","handbook":"Increase your following distance when driving behind motorcycles, large trucks, or when being tailgated.","hbref":"Following distance & space","qid":"DL-SAFEDRIVING-LRN-005"},{"q":"When another driver is tailgating you, what should you do?","options":["Brake suddenly to warn them","Increase your following distance ahead","Speed up to escape them","Stop in the middle of the road"],"answer":1,"explanation":"Increasing your following distance gives you more room to stop safely when being tailgated.","handbook":"When another driver is tailgating you, you should increase your following distance from the vehicle ahead.","hbref":"Following distance & space","qid":"DL-SAFEDRIVING-LRN-006"},{"q":"What are the big blind spots around large trucks and buses called?","options":["Slow zones","Safe zones","No-Zones","Crash zones"],"answer":2,"explanation":"Large trucks and buses have big blind spots called No-Zones, and if you can't see the driver's mirrors, they can't see you.","handbook":"Large trucks and buses have big blind spots called No-Zones.","hbref":"Following distance & space","qid":"DL-SAFEDRIVING-LRN-007"},{"q":"If you cannot see a truck or bus driver's mirrors, what does it mean?","options":["You may pass on the right","The driver can see you clearly","Your own mirrors are broken","The driver cannot see you"],"answer":3,"explanation":"Large trucks and buses have big blind spots, so if you can't see the driver's mirrors, the driver can't see you.","handbook":"If you cannot see a truck or bus driver's mirrors, the driver cannot see you.","hbref":"Following distance & space","qid":"DL-SAFEDRIVING-LRN-008"},{"q":"What three distances make up total stopping distance?","options":["Perception distance, reaction distance, and braking distance","Speed distance, weather distance, and braking distance","Following distance, blind-spot distance, and reaction distance","Daytime distance, night distance, and perception distance"],"answer":0,"explanation":"Total stopping distance equals perception distance plus reaction distance plus braking distance.","handbook":"Total stopping distance equals perception distance plus reaction distance plus braking distance.","hbref":"Stopping distance & speed","qid":"DL-SAFEDRIVING-LRN-009"},{"q":"What are the three parts of total stopping distance?","options":["Speed, weight, and tire distance","Perception, reaction, and braking distance","Steering, signal, and braking distance","Vision, weather, and reaction distance"],"answer":1,"explanation":"Total stopping distance is made up of perception distance, reaction distance, and braking distance.","handbook":"The three components that make up total stopping distance are perception distance, reaction distance, and braking distance.","hbref":"Stopping distance & speed","qid":"DL-SAFEDRIVING-LRN-010"},{"q":"About how long is the average driver's reaction time?","options":["About 3 seconds","About 2 seconds","About three-fourths of a second","About 5 seconds"],"answer":2,"explanation":"The average driver's reaction time is about three-fourths (3/4) of a second.","handbook":"The average driver's reaction time is about three-fourths (¾) of a second.","hbref":"Stopping distance & speed","qid":"DL-SAFEDRIVING-LRN-011"},{"q":"About how long is the combined perception-plus-reaction time?","options":["About 0.5 seconds","About 3 seconds","About 5 seconds","About 1.5 seconds"],"answer":3,"explanation":"The combined perception-plus-reaction time is roughly 1.5 seconds.","handbook":"The combined perception-plus-reaction time is roughly 1.5 seconds.","hbref":"Stopping distance & speed","qid":"DL-SAFEDRIVING-LRN-012"},{"q":"If you double your speed, the braking distance roughly:","options":["Quadruples (becomes about 4 times)","Doubles (becomes about 2 times)","Stays the same","Is cut in half"],"answer":0,"explanation":"Braking distance increases with the square of speed, so doubling speed roughly quadruples it.","handbook":"Braking distance increases with the square of speed, so doubling your speed roughly quadruples the braking distance.","hbref":"Stopping distance & speed","qid":"DL-SAFEDRIVING-LRN-013"},{"q":"If you double your speed, your braking distance roughly increases by how much?","options":["Stays the same","About four times","About two times","About three times"],"answer":1,"explanation":"Doubling your speed roughly quadruples your braking distance.","handbook":"Doubling your speed roughly quadruples (multiplies by four) your braking distance.","hbref":"Stopping distance & speed","qid":"DL-SAFEDRIVING-LRN-014"},{"q":"How does driving faster affect stopping?","options":["It makes stopping easier","It has no effect on stopping","It takes longer to stop","It shortens the crash impact"],"answer":2,"explanation":"The faster you go, the longer it takes to stop and the harder a crash, because of the speed-energy relationship.","handbook":"The faster you go, the longer it takes to stop and the harder the crash, because of the speed-energy relationship.","hbref":"Stopping distance & speed","qid":"DL-SAFEDRIVING-LRN-015"},{"q":"Why should you slow down on wet roads?","options":["To save fuel","To follow more closely","To brighten your headlights","Because traction is reduced"],"answer":3,"explanation":"Wet roads reduce traction, so slowing down helps you stay in control.","handbook":"On wet roads you should slow down because traction is reduced.","hbref":"Weather & reduced traction","qid":"DL-SAFEDRIVING-LRN-016"},{"q":"At about what speed can hydroplaning begin on a wet road?","options":["Near 35 mph","Near 5 mph","Near 15 mph","Near 70 mph"],"answer":0,"explanation":"Hydroplaning can begin near 35 mph as water builds up under the tires.","handbook":"Hydroplaning can begin near 35 mph as water builds up under the tires.","hbref":"Weather & reduced traction","qid":"DL-SAFEDRIVING-LRN-017"},{"q":"What is hydroplaning?","options":["When tires grip the road better in rain","When tires lose contact with the road on water","When brakes overheat on a long downhill","When headlights reflect off wet pavement"],"answer":1,"explanation":"Hydroplaning happens when water builds up under the tires and they lose contact with the road surface.","handbook":"Hydroplaning occurs when water builds up under the tires and the tires lose contact with the road surface.","hbref":"Weather & reduced traction","qid":"DL-SAFEDRIVING-LRN-018"},{"q":"What should you do if your car starts to hydroplane?","options":["Brake hard right away","Speed up to regain grip","Ease off the gas and steer straight","Turn the wheel sharply"],"answer":2,"explanation":"If you hydroplane, ease off the gas, do not brake hard, and steer straight.","handbook":"If you start to hydroplane, ease off the gas, do not brake hard, and steer straight.","hbref":"Weather & reduced traction","qid":"DL-SAFEDRIVING-LRN-019"},{"q":"Why is the first rain after a dry spell the most slippery?","options":["The road is colder than usual","Rain washes away all the dirt","Tires lose air in wet weather","Oil mixes with the water on the road"],"answer":3,"explanation":"The first rain mixes with built-up oil on the road, making it the most slippery.","handbook":"The first rain after a dry spell is the most slippery because oil mixes with the water on the road.","hbref":"Weather & reduced traction","qid":"DL-SAFEDRIVING-LRN-020"},{"q":"In icy weather, which part of the road freezes first?","options":["Bridges and overpasses","Hilltops","Tunnels","Parking lots"],"answer":0,"explanation":"Bridges and overpasses freeze before the rest of the road in icy conditions.","handbook":"Bridges and overpasses freeze before the rest of the road in icy conditions.","hbref":"Weather & reduced traction","qid":"DL-SAFEDRIVING-LRN-021"},{"q":"Why is black ice dangerous?","options":["It melts quickly","It is hard to see on the road","It smells strong","It makes loud noise"],"answer":1,"explanation":"Black ice is dangerous because it is hard to see on the road.","handbook":"Black ice is dangerous because it is hard to see on the road.","hbref":"Weather & reduced traction","qid":"DL-SAFEDRIVING-LRN-022"},{"q":"If your car starts to skid, what should you do?","options":["Slam on the brakes hard","Press harder on the gas","Ease off the gas and steer where you want to go","Close your eyes and hold on"],"answer":2,"explanation":"In a skid, take your foot off the gas, don't slam the brakes, and steer in the direction you want the front of the car to go.","handbook":"If your vehicle goes into a skid, take your foot off the gas, do not slam the brakes, and steer in the direction you want the front of the car to go.","hbref":"Weather & reduced traction","qid":"DL-SAFEDRIVING-LRN-023"},{"q":"How should you steer to recover from a skid?","options":["Toward the side of the road","In the opposite direction of the skid","Away from where you want to go","In the direction you want the front to go"],"answer":3,"explanation":"To recover from a skid, steer in the direction you want the front of the car to go.","handbook":"To recover from a skid, steer in the direction you want the front of the car to go.","hbref":"Weather & reduced traction","qid":"DL-SAFEDRIVING-LRN-024"},{"q":"During a skid, what should you do with your foot?","options":["Take your foot off the gas pedal","Press the gas pedal harder","Slam on the brake pedal","Keep steady pressure on the gas"],"answer":0,"explanation":"Easing off the gas helps you regain traction during a skid.","handbook":"During a skid you should take your foot off the gas pedal rather than press it.","hbref":"Weather & reduced traction","qid":"DL-SAFEDRIVING-LRN-025"},{"q":"In fog or smoke, which headlights should you use?","options":["High beams","Low beams","No headlights","Hazard flashers only"],"answer":1,"explanation":"Use low beams in fog or smoke because high beams reflect back and reduce your visibility.","handbook":"In fog or smoke, use low beams because high beams reflect back and reduce visibility.","hbref":"Weather & reduced traction","qid":"DL-SAFEDRIVING-LRN-026"},{"q":"In fog or smoke, what should you do?","options":["Speed up to pass through it","Turn on your high beams","Slow down or pull off the road safely","Turn off your headlights"],"answer":2,"explanation":"In fog or smoke you should slow down or pull off the road safely.","handbook":"In fog or smoke you should slow down or pull off the road safely.","hbref":"Weather & reduced traction","qid":"DL-SAFEDRIVING-LRN-027"},{"q":"In fog, which headlights should you use?","options":["Hazard flashers only","No headlights at all","High beams","Low beams"],"answer":3,"explanation":"In fog you should use low beams because high beams reflect off the fog and reduce your visibility.","handbook":"High beams should not be used in fog because they reflect back off the fog and reduce your visibility.","hbref":"Weather & reduced traction","qid":"DL-SAFEDRIVING-LRN-028"},{"q":"When should you use your headlights?","options":["From sunset to sunrise","Only during heavy rain","Only on the highway","Only when parking"],"answer":0,"explanation":"Texas law requires headlights from sunset to sunrise.","handbook":"Use your headlights from sunset to sunrise.","hbref":"Night & visibility","qid":"DL-SAFEDRIVING-LRN-029"},{"q":"When must you turn on your headlights based on visibility?","options":["When you cannot see at least 100 feet ahead","When you cannot see at least 1,000 feet ahead","When you cannot see at least 50 feet ahead","When you cannot see at least 5,000 feet ahead"],"answer":1,"explanation":"Use your headlights any time you cannot see at least about 1,000 feet ahead.","handbook":"Use your headlights any time you cannot see at least about 1,000 feet ahead.","hbref":"Night & visibility","qid":"DL-SAFEDRIVING-LRN-030"},{"q":"When must you dim your high beams to low beams for an oncoming vehicle?","options":["Within 100 feet","Within 250 feet","Within 500 feet","Within 1,000 feet"],"answer":2,"explanation":"You must dim your high beams to low beams when within 500 feet of an oncoming vehicle.","handbook":"Dim your high beams to low beams when you are within 500 feet of an oncoming vehicle.","hbref":"Night & visibility","qid":"DL-SAFEDRIVING-LRN-031"},{"q":"When following another vehicle, within what distance must you dim your high beams to low beams?","options":["Within 100 feet behind","Within 150 feet behind","Within 200 feet behind","Within 300 feet behind"],"answer":3,"explanation":"You must dim your high beams to low beams when within 300 feet behind another vehicle.","handbook":"Dim your high beams to low beams when you are within 300 feet behind another vehicle.","hbref":"Night & visibility","qid":"DL-SAFEDRIVING-LRN-032"},{"q":"Within how many feet of an oncoming vehicle must you dim your high beams?","options":["500 feet","100 feet","250 feet","1,000 feet"],"answer":0,"explanation":"You must dim your high beams to low within 500 feet of an oncoming vehicle.","handbook":"The distance at which you must dim high beams for an oncoming vehicle is 500 feet.","hbref":"Night & visibility","qid":"DL-SAFEDRIVING-LRN-033"},{"q":"Within how many feet of a vehicle you are following must you dim your high beams?","options":["100 feet","300 feet","500 feet","1,000 feet"],"answer":1,"explanation":"You must dim your high beams to low when within 300 feet behind another vehicle.","handbook":"The distance at which you must dim high beams when following another vehicle is 300 feet.","hbref":"Night & visibility","qid":"DL-SAFEDRIVING-LRN-034"},{"q":"If an oncoming vehicle's high beams blind you, where should you look?","options":["Straight at the headlights","Up at the sky","Toward the right edge of the road","Down at your dashboard"],"answer":2,"explanation":"Looking toward the right edge of the road helps you avoid the glare and stay in your lane.","handbook":"If you are blinded by an oncoming vehicle's high beams, look toward the right edge of the road.","hbref":"Night & visibility","qid":"DL-SAFEDRIVING-LRN-035"},{"q":"What does \"overdriving your headlights\" mean?","options":["Using high beams too often","Forgetting to turn on your lights","Driving with one headlight out","Going too fast to stop within the lighted area"],"answer":3,"explanation":"Overdriving your headlights means going so fast you cannot stop within the distance lighted by your headlights.","handbook":"Overdriving your headlights means going so fast that you cannot stop within the distance lighted by your headlights.","hbref":"Night & visibility","qid":"DL-SAFEDRIVING-LRN-036"},{"q":"What should you do if your brakes fail?","options":["Pump the pedal, shift to a lower gear, use the parking brake gradually","Turn off the engine and steer hard","Speed up to reach the next exit","Close your eyes and honk"],"answer":0,"explanation":"If your brakes fail, pump the brake pedal, shift to a lower gear, and use the parking brake gradually.","handbook":"If your brakes fail, pump the brake pedal, shift to a lower gear, and use the parking brake gradually.","hbref":"Emergencies & breakdowns","qid":"DL-SAFEDRIVING-LRN-037"},{"q":"How should you apply the parking brake during brake failure?","options":["All at once","Gradually","Never use it","Only after stopping"],"answer":1,"explanation":"During brake failure, apply the parking brake gradually rather than all at once.","handbook":"During brake failure you should apply the parking brake gradually rather than all at once.","hbref":"Emergencies & breakdowns","qid":"DL-SAFEDRIVING-LRN-038"},{"q":"If your brakes fail, what is a recommended response?","options":["Speed up to keep moving","Turn off your headlights","Shift to a lower gear","Honk your horn loudly"],"answer":2,"explanation":"Shifting to a lower gear helps slow the vehicle when your brakes fail.","handbook":"Shifting to a lower gear is a recommended response to brake failure.","hbref":"Emergencies & breakdowns","qid":"DL-SAFEDRIVING-LRN-039"},{"q":"What should you do if you have a tire blowout?","options":["Brake hard immediately","Speed up to keep control","Let go of the wheel","Hold the wheel firmly and ease off the gas"],"answer":3,"explanation":"In a blowout, hold the wheel firmly, ease off the gas, and do not brake hard.","handbook":"If you have a tire blowout, hold the wheel firmly, ease off the gas, and do not brake hard.","hbref":"Emergencies & breakdowns","qid":"DL-SAFEDRIVING-LRN-040"},{"q":"After a tire blowout, once you have control, how should you leave the road?","options":["Pull off the road slowly","Brake hard and stop fast","Speed up to merge","Stay in your lane"],"answer":0,"explanation":"After a tire blowout, once you have control you should pull off the road slowly.","handbook":"After a tire blowout, once you have control you should pull off the road slowly.","hbref":"Emergencies & breakdowns","qid":"DL-SAFEDRIVING-LRN-041"},{"q":"What should you do during a tire blowout?","options":["Brake hard immediately","Do not brake hard","Speed up quickly","Let go of the wheel"],"answer":1,"explanation":"During a tire blowout, do not brake hard; ease off the gas and pull off slowly.","handbook":"You should not brake hard during a tire blowout.","hbref":"Emergencies & breakdowns","qid":"DL-SAFEDRIVING-LRN-042"},{"q":"If your vehicle stalls on railroad tracks, what should you do?","options":["Stay in the vehicle and wait","Try to restart and beat the train","Get everyone out and away, then call for help","Push the vehicle along the tracks"],"answer":2,"explanation":"Get everyone out and away from the tracks, then call for help; never try to beat a train.","handbook":"If your vehicle stalls on railroad tracks, get everyone out of the vehicle and away from the tracks, then call for help.","hbref":"Emergencies & breakdowns","qid":"DL-SAFEDRIVING-LRN-043"},{"q":"What should you never try to do at railroad tracks?","options":["Stop before the tracks","Look both ways","Slow down near tracks","Beat a train across"],"answer":3,"explanation":"You should never try to beat a train across railroad tracks.","handbook":"You should never try to beat a train across railroad tracks.","hbref":"Emergencies & breakdowns","qid":"DL-SAFEDRIVING-LRN-044"},{"q":"If you must stop on the road, what should you do?","options":["Pull onto the shoulder and turn on hazard flashers","Stop in your lane and wait","Park halfway in the traffic lane","Leave your headlights off"],"answer":0,"explanation":"Pull fully onto the shoulder, turn on hazard flashers, and use warning devices.","handbook":"If you must stop on the road, pull fully onto the shoulder, turn on your hazard flashers, and use warning devices.","hbref":"Emergencies & breakdowns","qid":"DL-SAFEDRIVING-LRN-045"},{"q":"What should you turn on when stopped on the roadside in an emergency?","options":["Your high beams","Your hazard (emergency) flashers","Your interior dome light","Nothing at all"],"answer":1,"explanation":"When stopped on the roadside in an emergency, turn on your hazard (emergency) flashers.","handbook":"When stopped on the roadside in an emergency, turn on your hazard (emergency) flashers.","hbref":"Emergencies & breakdowns","qid":"DL-SAFEDRIVING-LRN-046"},{"q":"When stopping on the road in an emergency, how far should you move your vehicle?","options":["Stay in your driving lane","Halfway onto the shoulder","Fully onto the shoulder","Onto the center line"],"answer":2,"explanation":"Pull fully onto the shoulder so your vehicle is clear of traffic.","handbook":"When stopping on the road in an emergency, you should pull fully onto the shoulder.","hbref":"Emergencies & breakdowns","qid":"DL-SAFEDRIVING-LRN-047"},{"q":"What do fatigue, drugs, and alcohol do to a driver?","options":["Improve reaction time","Sharpen judgment","Have no effect","Slow reaction time and impair judgment"],"answer":3,"explanation":"Fatigue, drugs, and alcohol all slow reaction time and impair judgment.","handbook":"Fatigue, drugs, and alcohol all slow reaction time and impair judgment.","hbref":"Impairment & distraction (safety)","qid":"DL-SAFEDRIVING-LRN-048"},{"q":"When should you avoid driving?","options":["When you are impaired or drowsy","When you are well-rested","When the road is clear","When traffic is light"],"answer":0,"explanation":"You should never drive while impaired or drowsy because it slows your reaction time and judgment.","handbook":"You should never drive while impaired or drowsy.","hbref":"Impairment & distraction (safety)","qid":"DL-SAFEDRIVING-LRN-049"},{"q":"How does fatigue (drowsiness) affect your driving?","options":["It improves your focus","It slows reaction time and judgment, like drugs and alcohol","It has no effect on driving","It makes you brake faster"],"answer":1,"explanation":"Fatigue slows your reaction time and judgment just like drugs and alcohol.","handbook":"Fatigue (drowsiness) slows your reaction time and judgment just like drugs and alcohol.","hbref":"Impairment & distraction (safety)","qid":"DL-SAFEDRIVING-LRN-050"},{"q":"Which activity is a major driving distraction?","options":["Wearing your seat belt","Checking your mirrors","Texting or using a handheld phone","Slowing down in rain"],"answer":2,"explanation":"Texting and handheld phone use is a major distraction and texting while driving is illegal in Texas.","handbook":"Texting and handheld phone use is a major driving distraction.","hbref":"Impairment & distraction (safety)","qid":"DL-SAFEDRIVING-LRN-051"},{"q":"In Texas, is texting while driving legal?","options":["Yes, it is always legal","Yes, on highways only","Yes, if traffic is slow","No, it is illegal"],"answer":3,"explanation":"Texting while driving is illegal in Texas.","handbook":"Texting while driving is illegal in Texas.","hbref":"Impairment & distraction (safety)","qid":"DL-SAFEDRIVING-LRN-052"},{"q":"When must you wear your seat belt while driving?","options":["Always","Only on highways","Only at night","Only in the rain"],"answer":0,"explanation":"Texas law requires you to always wear your seat belt while driving.","handbook":"You must always wear your seat belt while driving.","hbref":"Impairment & distraction (safety)","qid":"DL-SAFEDRIVING-LRN-053"},{"q":"Who must wear a seat belt in Texas?","options":["Only the driver","The driver and all passengers","Only front-seat riders","Only children under 12"],"answer":1,"explanation":"Texas law requires the driver and all passengers to wear seat belts.","handbook":"Texas law requires seat belts for the driver and all passengers.","hbref":"Impairment & distraction (safety)","qid":"DL-SAFEDRIVING-LRN-054"},{"q":"What is reaction distance?","options":["The distance your tires leave skid marks","The distance you keep behind other cars","The distance your vehicle travels while you react after seeing a hazard","The distance your brakes stop the vehicle"],"answer":2,"explanation":"Reaction distance is how far your vehicle travels while you react after perceiving a hazard.","handbook":"Reaction distance is the distance your vehicle travels while you react after perceiving a hazard.","hbref":"Stopping distance & speed","qid":"DL-SAFEDRIVING-LRN-055"},{"q":"What is braking distance?","options":["The time you spend looking at the road","The distance you drive before a turn","The space between two parked cars","The distance your vehicle travels from braking until it stops"],"answer":3,"explanation":"Braking distance is how far your vehicle travels from when you apply the brakes until it fully stops.","handbook":"Braking distance is the distance your vehicle travels from when you apply the brakes until it stops.","hbref":"Stopping distance & speed","qid":"DL-SAFEDRIVING-LRN-056"},{"q":"If your car starts to hydroplane, what should you do?","options":["Ease off the gas and steer straight","Brake hard right away","Speed up quickly","Turn the wheel sharply"],"answer":0,"explanation":"During hydroplaning, ease off the gas and steer straight instead of braking hard.","handbook":"During hydroplaning you should not brake hard.","hbref":"Weather & reduced traction","qid":"DL-SAFEDRIVING-LRN-057"},{"q":"What does the three-second rule help you keep?","options":["A clean windshield","A safe following distance","A full fuel tank","A correct tire pressure"],"answer":1,"explanation":"The three-second rule helps you keep a safe following distance behind the vehicle ahead.","handbook":"If you reach a fixed point in fewer than three seconds after the vehicle ahead, you are too close and should drop back.","hbref":"Following distance & space","qid":"DL-SAFEDRIVING-LRN-058"},{"q":"When should you turn on your headlights during the day?","options":["Only on the highway","Only when it is dark outside","When you cannot see about 1,000 feet ahead","Never during the day"],"answer":2,"explanation":"Turn on headlights whenever visibility drops and you cannot see about 1,000 feet ahead, even in daytime rain or fog.","handbook":"Headlights should be on whenever visibility is reduced and you cannot see about 1,000 feet ahead, even during daytime conditions like rain or fog.","hbref":"Night & visibility","qid":"DL-SAFEDRIVING-LRN-059"},{"q":"If you stop on the roadside in an emergency, what should you do?","options":["Stay in your lane and wait","Turn off all your lights","Speed away quickly","Set out warning devices for other drivers"],"answer":3,"explanation":"Warning devices alert other drivers that your vehicle is stopped on the roadside.","handbook":"When stopped on the roadside in an emergency, set out warning devices to alert other drivers.","hbref":"Emergencies & breakdowns","qid":"DL-SAFEDRIVING-LRN-060"}]},{"id":"alcohol-and-penalties","name":"Alcohol, Drugs & Penalties","blurb":"Texas DL Alcohol, Drugs & Penalties: practice tests plus a Learning Test that walks the whole handbook section.","accent":"#ea580c","kind":"core","classes":["DL"],"questions":[{"q":"Marcus, age 34, is pulled over leaving a friend's barbecue in Houston. The officer suspects he has been drinking and asks for a breath test. At what BAC level is Marcus, as an adult driver, legally considered to be Driving While Intoxicated (DWI) in Texas?","options":["0.08% BAC or higher","0.04% BAC or higher","0.15% BAC or higher","Any detectable amount above 0.00% BAC"],"answer":0,"explanation":"For an adult driver age 21 or older, the Texas DWI limit is 0.08% BAC. 0.04% is the limit for commercial drivers, and any detectable amount (above 0.00%) applies only to drivers under 21 under Zero Tolerance.","handbook":"The adult (21+) DWI limit in Texas is 0.08% BAC.","hbref":"Blood-alcohol limits (Texas)","qid":"DL-ALCOHOLANDPENALTIES-TRAP-001"},{"q":"Marcus, age 26, is pulled over in Austin after weaving between lanes. He passes a breath test reading 0.08% BAC and tells the officer he feels completely fine and was driving carefully. Under Texas law, what offense has Marcus committed based on that reading?","options":["Nothing, because 0.08% is the legal limit and he is only over it once the reading exceeds 0.08%","Driving While Intoxicated (DWI), because driving at or above 0.08% BAC is DWI for an adult","Driving Under the Influence (DUI), because any detectable alcohol makes an adult guilty of DUI","Nothing, because he told the officer he felt fine and showed no real impairment"],"answer":1,"explanation":"For an adult 21 or older, driving at or above 0.08% BAC is the offense of Driving While Intoxicated (DWI), so reaching exactly 0.08% counts. The Zero Tolerance DUI for any detectable alcohol applies only to drivers under 21, and feeling 'fine' does not change the legal BAC limit.","handbook":"Driving at or above 0.08% BAC is the offense of Driving While Intoxicated (DWI).","hbref":"Blood-alcohol limits (Texas)","qid":"DL-ALCOHOLANDPENALTIES-TRAP-002"},{"q":"A 30-year-old driver is pulled over after weaving across lanes. A breath test reads 0.06% BAC, but the officer observes slurred speech and poor coordination consistent with alcohol impairment. Under Texas law, what can happen?","options":["Nothing, because 0.06% is below the 0.08% adult limit, so DWI cannot apply","The driver is automatically cleared once the breath test reads under 0.08%","The driver can still be charged with DWI because they are impaired by alcohol, even though BAC is below 0.08%","The driver can only be cited for an open-container violation, not DWI"],"answer":2,"explanation":"In Texas, a driver can be charged with DWI below 0.08% BAC if alcohol or drugs impair them, so the observed impairment supports a DWI charge. The 0.08% figure is a per se limit, not a safe harbor, so being under it does not automatically clear the driver.","handbook":"A driver can still be charged with DWI below 0.08% BAC if impaired by alcohol or drugs.","hbref":"Blood-alcohol limits (Texas)","qid":"DL-ALCOHOLANDPENALTIES-TRAP-003"},{"q":"Marcus drives a commercial tractor-trailer for a freight company. After a long shift, he has two beers with dinner and a breath test later reads 0.05% BAC. He argues he is well under the legal limit and is fine to keep driving his rig. Is he correct, and what is the relevant limit?","options":["He is correct; the limit for all drivers in Texas is 0.08% BAC, so 0.05% is legal.","He is correct because any BAC under 0.08% can never result in a charge.","He is over the limit because Texas has zero tolerance and any detectable alcohol is illegal for him.","He is over the limit; commercial drivers have a lower limit of 0.04% BAC, and 0.05% exceeds it."],"answer":3,"explanation":"Commercial drivers in Texas are held to a lower limit of 0.04% BAC, so Marcus's 0.05% reading puts him over the limit. The 0.08% figure (A) is the standard adult limit, not the commercial one, and zero tolerance (C) applies only to drivers under 21, not commercial drivers.","handbook":"The BAC limit for a commercial driver is 0.04% BAC (lower than the 0.08% adult limit).","hbref":"Blood-alcohol limits (Texas)","qid":"DL-ALCOHOLANDPENALTIES-TRAP-004"},{"q":"Marcus is 19 and drives home from a friend's party where he had one beer. A police officer lawfully stops him and a breath test shows a BAC of 0.03%. Under Texas law, what is his legal status?","options":["He is illegal to drive — under Texas Zero Tolerance, any detectable alcohol (a BAC above 0.00) for a driver under 21 is a DUI by a minor.","He is legal to drive because his 0.03% BAC is below the 0.08% DWI limit.","He is legal to drive because his 0.03% BAC is below the 0.04% commercial-driver limit.","He is legal to drive because he had only one drink and the liver processes one standard drink per hour."],"answer":0,"explanation":"For drivers under 21, Texas has Zero Tolerance, so ANY detectable alcohol (a BAC above 0.00) is illegal and is a DUI by a minor. The 0.08% adult DWI limit and the 0.04% commercial limit do not apply to a 19-year-old minor, making those traps wrong.","handbook":"For drivers under 21, Texas has Zero Tolerance: ANY detectable alcohol (a BAC above 0.00) is illegal.","hbref":"Blood-alcohol limits (Texas)","qid":"DL-ALCOHOLANDPENALTIES-TRAP-005"},{"q":"A 19-year-old leaves a party and is pulled over in Texas. A breath test shows a BAC of 0.03%, well below the adult limit of 0.08%. What offense, if any, has the driver committed?","options":["Nothing, because the BAC is under the 0.08% adult limit","DUI (Driving Under the Influence) of alcohol by a minor, because any detectable alcohol is illegal under 21","DWI, because the driver is automatically intoxicated at any BAC","Nothing, but the driver's license is suspended 180 days for implied consent"],"answer":1,"explanation":"Texas has a Zero Tolerance law for drivers under 21: any detectable alcohol (a BAC above 0.00) is a DUI of alcohol by a minor, regardless of the 0.08% adult DWI limit. Option A wrongly applies the adult threshold to a minor, and the 180-day suspension in D is the penalty for refusing a test, not for a 0.03% reading.","handbook":"A minor driving with any detectable alcohol commits a DUI (Driving Under the Influence) of alcohol by a minor.","hbref":"Blood-alcohol limits (Texas)","qid":"DL-ALCOHOLANDPENALTIES-TRAP-006"},{"q":"At a party, Marcus has had a couple of beers and feels calm and relaxed, so he tells a friend he's actually a safer, more careful driver after drinking. His friend warns him this is dangerous. Why does alcohol make Marcus a more dangerous driver, even though he feels relaxed?","options":["Alcohol is a stimulant that speeds up his heart and makes him overly aggressive behind the wheel","Alcohol only affects drivers once their BAC reaches the 0.08% legal limit, so two beers cannot impair him","Alcohol is a depressant that slows his reaction time and impairs his judgment, even though he feels relaxed","Alcohol sharpens his vision and coordination but dulls his ability to obey traffic signals"],"answer":2,"explanation":"Alcohol is a depressant, so it slows reaction time and impairs judgment even when the drinker feels calm and relaxed. It is not a stimulant (A is the wrong category), and a driver can be impaired well below 0.08% (B is false), making C correct.","handbook":"Alcohol is a depressant.","hbref":"How alcohol affects driving","qid":"DL-ALCOHOLANDPENALTIES-TRAP-007"},{"q":"Driving home from a party where he had several drinks, Marcus notices he keeps drifting in his lane, fumbles when reaching for the turn signal, and reacts a beat too late when the car ahead brakes. Which combination of effects from the alcohol best explains what he is experiencing?","options":["His blood-alcohol level is rising because the fresh night air is speeding the alcohol back into his bloodstream.","Alcohol acts as a stimulant, so it sharpens his focus but makes his muscle movements jittery and quick.","The effects come only from being tired; alcohol itself has worn off since more than an hour has passed since his last drink.","Alcohol has slowed his reaction time, impaired his judgment, and reduced his coordination and vision."],"answer":3,"explanation":"Alcohol is a depressant that slows reaction time, impairs judgment, and reduces coordination and vision, which matches Marcus's lane drifting, fumbling, and delayed braking. Alcohol is not a stimulant and does not sharpen focus, and only time lowers BAC, so fresh air and the passage of one hour do not undo the impairment.","handbook":"Alcohol slows reaction time, impairs judgment, and reduces coordination and vision.","hbref":"How alcohol affects driving","qid":"DL-ALCOHOLANDPENALTIES-TRAP-008"},{"q":"After two beers at a friend's house, Marcus feels physically fine, his hands are steady, and his speech is normal, so he decides it's safe to drive home and even speeds up to make a yellow light he normally would have stopped for. Which of his abilities did the alcohol most likely impair FIRST, leading to this risky choice?","options":["His judgment, which is the first driving ability affected by alcohol","His vision, which is always the first ability alcohol affects","His coordination, since steady hands prove judgment is still intact","His reaction time, which alcohol affects before anything else"],"answer":0,"explanation":"Judgment is the first driving ability affected by alcohol, which is why Marcus made the risky decision to speed through the light even though he felt physically fine. Vision, coordination, and reaction time are all impaired by alcohol too, but they are affected after judgment, not before it.","handbook":"The first driving ability affected by alcohol is judgment.","hbref":"How alcohol affects driving","qid":"DL-ALCOHOLANDPENALTIES-TRAP-009"},{"q":"At a party, a friend has had several drinks over the past two hours and now wants to drive home. He insists he is fine because he just drank two large cups of black coffee, ate a full meal, and stepped outside into the cold air to 'clear his head.' What should you tell him about his ability to drive safely?","options":["The coffee and cold air have sped up his body's processing of the alcohol, so he is now safe to drive.","None of those things lower his BAC; only the passage of time can sober him up, so he should not drive.","Eating a full meal absorbs the alcohol already in his bloodstream, so his BAC is now back to a legal level.","Since he feels alert, his judgment and reaction time have fully returned and he can legally drive."],"answer":1,"explanation":"Only the passage of time lowers BAC, because the liver processes alcohol at a fixed rate of about one drink per hour. Coffee, food, cold air, and feeling alert do not speed up sobering or reduce impairment, so he should not drive.","handbook":"Only time lowers BAC.","hbref":"How alcohol affects driving","qid":"DL-ALCOHOLANDPENALTIES-TRAP-010"},{"q":"At a party, your friend has had several beers over the last two hours and now wants to drive home. He says he'll be fine to drive if he drinks a strong cup of coffee, eats a big meal, and takes a cold shower first. From what you know about how alcohol leaves the body, what is the most accurate response?","options":["Coffee and a cold shower will sober him up quickly, so he can drive once he feels alert again.","A big meal will absorb the alcohol already in his blood and lower his BAC enough to drive safely.","None of those will speed up sobering up; only time lowers his BAC, so he should not drive.","Fresh air on the drive home will clear the alcohol from his system, so a short trip is fine."],"answer":2,"explanation":"Only the passage of time lowers BAC because the liver processes about one standard drink per hour, and nothing makes it faster. Coffee, food, a cold shower, and fresh air may make a person feel more alert but do not reduce intoxication, so they are dangerous myths.","handbook":"Coffee, food, a cold shower, or fresh air do NOT speed up sobering.","hbref":"How alcohol affects driving","qid":"DL-ALCOHOLANDPENALTIES-TRAP-011"},{"q":"Marcus had four standard drinks at a party that ended at midnight. He drinks two large coffees, eats a full meal, and takes a cold shower before driving home at 1:30 a.m. He feels alert. What is true about his ability to drive safely?","options":["The coffee and food have lowered his BAC enough that he is now safe to drive","The cold shower sped up his liver, so most of the alcohol is already gone","Because he feels alert and his judgment is clear, he is fine to drive","Only time can lower his BAC; his liver clears about one drink per hour, so he is likely still impaired"],"answer":3,"explanation":"The liver processes only about one standard drink per hour and nothing speeds it up, so after roughly 90 minutes Marcus has cleared at most one or two of his four drinks. Coffee, food, and a cold shower do not lower BAC, and feeling alert is misleading because judgment is the first ability alcohol impairs.","handbook":"The liver processes about one standard drink per hour, and nothing makes it faster.","hbref":"How alcohol affects driving","qid":"DL-ALCOHOLANDPENALTIES-TRAP-012"},{"q":"Marcus has had one beer at dinner and feels barely buzzed. Earlier that day he took an over-the-counter allergy pill that warns it may cause drowsiness. He figures one beer is well under the legal limit, so he's fine to drive home. What is the real danger in his situation?","options":["The over-the-counter medicine combined with the alcohol can multiply his impairment, making him far less safe to drive than the single beer alone would suggest","Nothing is wrong, because over-the-counter medicines are legal and cannot affect his ability to drive","He is safe as long as he eats more food and drinks coffee to counteract the combined effects before leaving","He is only at risk if his BAC reaches the 0.04% commercial-driver limit, which one beer cannot do"],"answer":0,"explanation":"Drugs of any kind—including legal over-the-counter medicines—combined with alcohol multiply impairment, so Marcus can be far more impaired than one beer alone would suggest. Coffee and food do not speed sobering, and the 0.04% limit applies only to commercial drivers, not Marcus.","handbook":"Drugs (illegal, prescription, or over-the-counter) combined with alcohol multiply impairment.","hbref":"How alcohol affects driving","qid":"DL-ALCOHOLANDPENALTIES-TRAP-013"},{"q":"Marcus is pulled over late at night and lawfully arrested for DWI in Austin. At the station, the officer asks him to provide a breath sample. Marcus says he never agreed to any test and refuses. Under Texas law, what is the basis on which he was already considered to have agreed?","options":["He agreed when he signed the arrest paperwork at the station, so the test is now mandatory.","By driving in Texas, he gave implied consent to a breath or blood test when lawfully arrested for DWI.","He agreed only because his BAC was already measured at 0.08% or higher during the stop.","He gave consent when he applied for his Texas driver license, which permanently waives all refusals."],"answer":1,"explanation":"Texas law states that by driving in the state you give implied consent to a breath or blood test if lawfully arrested for DWI, so consent already exists at the time of arrest. Option A is wrong because consent comes from the act of driving, not signing paperwork, and a 0.08% reading or the license application does not establish it.","handbook":"By driving in Texas you give implied consent to a breath or blood test if lawfully arrested for DWI.","hbref":"Implied consent","qid":"DL-ALCOHOLANDPENALTIES-TRAP-014"},{"q":"Marcus is lawfully arrested for DWI after being pulled over late at night. At the station, the officer asks him to provide a breath sample, but Marcus refuses, believing that without a test there is no evidence against him. Putting aside any DWI charge itself, what happens to his driver license solely because he refused the test?","options":["Nothing happens to his license, because under implied consent a driver always has the right to refuse a breath or blood test with no consequences","His license is suspended for up to 1 year for this first refusal","His license is automatically suspended for 180 days for this first refusal","He faces a $2,000 fine and up to 180 days in jail for refusing the test"],"answer":2,"explanation":"Under Texas implied consent, refusing a lawful breath or blood test triggers an automatic 180-day license suspension for a first refusal under Administrative License Revocation, separate from any DWI charge. The 'up to 1 year' suspension and the $2,000 fine/jail time are penalties for a DWI conviction, not for refusing the test, and refusal does carry consequences.","handbook":"Refusing the breath or blood test results in an automatic license suspension of 180 days for a first refusal.","hbref":"Implied consent","qid":"DL-ALCOHOLANDPENALTIES-TRAP-015"},{"q":"Marcus is lawfully arrested for DWI in Texas after failing a roadside sobriety check. At the station, he refuses to give a breath or blood sample, believing that without a test result the State has no case and his license is safe. Several months later his DWI charge is dismissed in court. What is the status of his driving privileges?","options":["Because the DWI charge was dismissed, no suspension applies and his license remains fully valid.","His license is suspended for up to 1 year, the standard penalty tied to a first DWI conviction.","He faces only a $2,000 fine for the refusal, but his license is not suspended.","His license is automatically suspended for 180 days under Administrative License Revocation (ALR) for the refusal, separate from the dismissed DWI charge."],"answer":3,"explanation":"Refusing a breath or blood test triggers an automatic 180-day ALR suspension that is entirely separate from the DWI case, so it stands even though the DWI charge was dismissed. Option B wrongly applies the up-to-1-year suspension tied to a DWI conviction, which never occurred here, and the dismissal does not erase the refusal-based ALR suspension.","handbook":"The automatic suspension for refusing a test is under Administrative License Revocation (ALR) and is separate from any DWI conviction.","hbref":"Implied consent","qid":"DL-ALCOHOLANDPENALTIES-TRAP-016"},{"q":"At a Houston bar, 24-year-old Marcus has several drinks, then drives home and is pulled over with a BAC of 0.11%. He is arrested and convicted of his first DWI, with no prior offenses and no passengers in the car. What is the maximum fine a court can impose for this first DWI conviction?","options":["Up to $2,000","Up to $500","Up to $4,000","Up to $10,000"],"answer":0,"explanation":"A first DWI in Texas carries a fine of up to $2,000, along with possible jail time and license suspension. The $500 figure is the maximum fine for a minor's first DUI, and the higher amounts apply to repeat or aggravated offenses, not a standard first DWI.","handbook":"A first DWI carries a fine of up to $2,000.","hbref":"DWI penalties (Texas, first offense)","qid":"DL-ALCOHOLANDPENALTIES-TRAP-017"},{"q":"Marcus is convicted of his first DWI in Texas after being pulled over leaving a friend's party with a BAC of 0.10%. The judge is now deciding his jail sentence within the range set by Texas law for a first DWI. What is the possible jail term the judge may impose?","options":["Up to 1 year in jail","3 days to 180 days in jail","A flat 180-day suspension instead of jail","No jail, only a $500 fine"],"answer":1,"explanation":"Under Texas law, a first DWI carries 3 days to 180 days in jail, so the judge's range is set by that statute. The 1-year figure is the license suspension (not jail), the 180-day suspension applies to refusing a chemical test under ALR, and the $500 fine is a minor's first DUI penalty.","handbook":"A first DWI carries 3 days to 180 days in jail.","hbref":"DWI penalties (Texas, first offense)","qid":"DL-ALCOHOLANDPENALTIES-TRAP-018"},{"q":"Marcus, age 28, is pulled over leaving a Friday-night party. He takes the breath test, blows 0.10% BAC, and is convicted of his first DWI in Texas. He has no child passenger and no prior offenses. At sentencing, what is the maximum period his driver license can be suspended for this first DWI conviction?","options":["180 days, the same period imposed for refusing a breath test","No suspension, since his BAC was below 0.15%","Up to 1 year","Up to 2 years, the standard term for any DWI"],"answer":2,"explanation":"A first DWI conviction in Texas carries a license suspension of up to 1 year. The 180-day figure is the separate automatic suspension for refusing a chemical test under implied consent, not the penalty for a DWI conviction, so option A is a trap.","handbook":"A first DWI carries a license suspension of up to 1 year.","hbref":"DWI penalties (Texas, first offense)","qid":"DL-ALCOHOLANDPENALTIES-TRAP-019"},{"q":"Marcus was convicted of DWI in Texas last year and paid his fine and served his time. Tonight he is pulled over and arrested for DWI a second time. Compared to his first conviction, what should he expect for this repeat offense?","options":["The penalties are exactly the same as a first DWI: a maximum $2,000 fine and up to 1 year of license suspension.","There are no additional penalties because Texas only counts the most recent DWI conviction.","His license is automatically suspended for 180 days, and that replaces any other DWI penalty.","The penalties increase for a repeat offense, so he faces tougher fines, longer jail time, and a longer suspension than the first DWI."],"answer":3,"explanation":"Texas law increases DWI penalties for repeat offenses, so a second conviction brings tougher consequences than the first. Option A wrongly states the first-offense maximums ($2,000 / 1 year) apply unchanged, and option C confuses the 180-day ALR suspension for refusing a test with the criminal DWI penalty.","handbook":"Penalties increase for repeat offenses.","hbref":"DWI penalties (Texas, first offense)","qid":"DL-ALCOHOLANDPENALTIES-TRAP-020"},{"q":"Marcus is pulled over on his way home from a party. He is 27, this is his first-ever DWI arrest, and the breath test shows a BAC of 0.16%. His friend says the penalties will be exactly the same as any other first-offense DWI. Why is the friend wrong?","options":["Because a BAC of 0.15% or more triggers increased penalties, even on a first offense.","Because refusing the breath test always doubles the standard first-offense fine.","Because any first-offense DWI is automatically charged as a felony.","Because the penalties only increase if a child under 15 is in the vehicle."],"answer":0,"explanation":"In Texas, penalties for a first DWI increase when the driver's BAC is 0.15% or higher, so Marcus's 0.16% reading means enhanced penalties. A child passenger under 15 (D) is a separate felony enhancement, but it does not apply here since Marcus was alone.","handbook":"Penalties increase for a high BAC of 0.15% or more.","hbref":"DWI penalties (Texas, first offense)","qid":"DL-ALCOHOLANDPENALTIES-TRAP-021"},{"q":"On the way home from a party, Marcus is pulled over and his BAC tests at 0.10%. It is his first DWI offense, but his 8-year-old niece is buckled in the back seat. How does having the child passenger change how this offense is classified?","options":["It has no effect on the charge because it is still his first offense","Driving while intoxicated with a child passenger under 15 makes the offense a felony","It adds an automatic 180-day license suspension under the open container rule","It raises the maximum fine to $500 because a minor is involved"],"answer":1,"explanation":"In Texas, DWI with a child passenger under age 15 is a felony, regardless of whether it is a first offense. The 180-day suspension belongs to refusing a chemical test, and the $500 figure is the fine for a minor's own first DUI, not a penalty tied to carrying a child passenger.","handbook":"DWI with a child passenger under 15 is a felony.","hbref":"DWI penalties (Texas, first offense)","qid":"DL-ALCOHOLANDPENALTIES-TRAP-022"},{"q":"A driver in Texas is pulled over and passes the field sobriety test, registering a BAC of 0.05%, so the officer does not charge him with DWI. However, the officer notices a half-empty beer bottle in the cup holder next to the driver. How does Texas law treat this open container of alcohol in the passenger area?","options":["It is ignored because his BAC was under the 0.08% legal limit.","It automatically suspends his license for 180 days under implied consent.","It is a separate offense from any DWI charge.","It is only an offense if a child under 15 is in the vehicle."],"answer":2,"explanation":"Having an open container of alcohol in the passenger area is a separate offense in Texas, independent of whether a DWI charge applies or what the driver's BAC was. The 180-day suspension relates to refusing a chemical test under implied consent, and the child-passenger rule concerns the felony DWI enhancement, not open containers.","handbook":"Having an open container of alcohol in the passenger area is a separate offense.","hbref":"DWI penalties (Texas, first offense)","qid":"DL-ALCOHOLANDPENALTIES-TRAP-023"},{"q":"Marcus is 18 and gets pulled over driving home from a party. A breath test shows a BAC of 0.02%, and he is convicted of his first DUI (alcohol) as a minor. Aside from a license suspension, community service, and an alcohol-awareness course, what is the maximum fine he can face for this first offense?","options":["Up to $2,000, the same fine used for an adult first DWI","No fine at all, since the BAC was below the 0.08% adult limit","Up to $1,000, doubled because alcohol was detected","Up to $500"],"answer":3,"explanation":"Under Texas zero-tolerance law, a minor's first DUI (alcohol) carries a fine of up to $500, along with license suspension, community service, and an alcohol-awareness course. The $2,000 figure is the maximum for an adult first DWI, and no fine being charged is wrong because any detectable alcohol is illegal for a driver under 21.","handbook":"A minor's first DUI (alcohol) carries a fine of up to $500.","hbref":"Minors & zero tolerance penalties","qid":"DL-ALCOHOLANDPENALTIES-TRAP-024"},{"q":"Marcus is 19 and gets pulled over on his way home from a party. The officer smells alcohol, and a breath test shows a BAC of 0.03%. This is Marcus's first alcohol-related offense. Under Texas law, what happens to his driving privileges?","options":["His license is suspended, because any detectable alcohol for a driver under 21 is a DUI carrying a suspension.","Nothing happens to his license, because his BAC is below the 0.08% legal limit.","His license is suspended for 180 days specifically for refusing the breath test.","He faces a felony charge and a one-year suspension because his BAC was measured."],"answer":0,"explanation":"Texas has zero tolerance for drivers under 21, so any detectable alcohol (above 0.00%) is a DUI for a minor and carries a license suspension. The 0.08% limit (B) applies only to adults 21+, the 180-day suspension (C) is for refusing a test, and a felony (D) does not result from a minor's first DUI.","handbook":"A minor's first DUI (alcohol) carries a license suspension.","hbref":"Minors & zero tolerance penalties","qid":"DL-ALCOHOLANDPENALTIES-TRAP-025"},{"q":"Marcus, age 19, is pulled over in Austin late one night. The officer detects a small amount of alcohol on his breath, and a test confirms a BAC of 0.03%. This is his first offense. Under Texas zero-tolerance law, which of the following will his sentence include?","options":["Only a written warning, since his BAC is well under the adult 0.08% limit","A fine up to $500, license suspension, community service, and an alcohol-awareness course","Up to 180 days in jail and a $2,000 fine, the same as an adult DWI","An automatic 180-day suspension for refusing the breath test"],"answer":1,"explanation":"Because Marcus is under 21, any detectable alcohol is a DUI by a minor under zero-tolerance, and a first offense carries a fine up to $500, license suspension, community service, and an alcohol-awareness course. The 0.08% adult limit and adult DWI jail/fine penalties do not apply to a minor's first DUI, and the 180-day suspension is for refusing the test, which he did not refuse.","handbook":"A minor's first DUI (alcohol) requires community service.","hbref":"Minors & zero tolerance penalties","qid":"DL-ALCOHOLANDPENALTIES-TRAP-026"},{"q":"Marcus, age 19, is pulled over leaving a party in Austin. A breath test shows a BAC of 0.03%, and he is convicted of his first DUI by a minor. As part of resolving the case, which of the following is a required component of his penalty under Texas zero-tolerance law?","options":["Nothing further, because his BAC was below the adult 0.08% limit","An automatic 180-day suspension solely for taking the breath test","Completion of an alcohol-awareness course","A mandatory minimum of 3 days in jail"],"answer":2,"explanation":"A minor's first DUI for alcohol requires completion of an alcohol-awareness course (plus a fine up to $500, license suspension, and community service). Option A is wrong because under-21 zero tolerance makes ANY detectable alcohol illegal, and the 3-day jail minimum (D) and the 180-day suspension for refusing a test (B) belong to adult DWI and refusal rules, not a minor's first DUI.","handbook":"A minor's first DUI (alcohol) requires completion of an alcohol-awareness course.","hbref":"Minors & zero tolerance penalties","qid":"DL-ALCOHOLANDPENALTIES-TRAP-027"},{"q":"Marcus has picked up three speeding tickets and a running-a-red-light conviction over the past two years. He's worried about what these moving violations mean for his Texas driving record beyond just the fines he already paid. What is the most accurate consequence of accumulating these traffic convictions?","options":["Nothing further happens once the fines are paid; the convictions have no effect on his record.","Each conviction automatically requires him to carry SR-22 financial responsibility insurance.","The convictions trigger an automatic 180-day license suspension after the second ticket.","The convictions add points to his record, and too many can lead to surcharges and license suspension."],"answer":3,"explanation":"Traffic convictions add points to your Texas driving record, and accumulating too many can result in surcharges and license suspension. SR-22 is tied to serious offenses like a DWI rather than ordinary tickets, and the automatic 180-day suspension applies to refusing a breath/blood test under implied consent, not to routine moving violations.","handbook":"Traffic convictions add points to your driving record.","hbref":"The Texas point / surcharge & insurance context","qid":"DL-ALCOHOLANDPENALTIES-TRAP-028"},{"q":"Marcus has racked up several traffic convictions over the past two years on his Texas driver license. At his latest court appearance, the judge warns him that continuing to accumulate convictions will trigger additional consequences beyond the individual fines. Based on the Texas point/surcharge system, what can too many convictions ultimately lead to?","options":["Surcharges and license suspension","An automatic 180-day suspension for refusing a breath test","A mandatory SR-22 only if one conviction is for an open container","Felony charges because repeated convictions are treated as DWI with a child"],"answer":0,"explanation":"Under the Texas point/surcharge system, traffic convictions add points to your record, and too many convictions can lead to surcharges and license suspension. The 180-day suspension applies specifically to refusing a breath or blood test (implied consent), not to accumulating ordinary convictions, so that option is a misplaced fact.","handbook":"Too many convictions can lead to surcharges and license suspension.","hbref":"The Texas point / surcharge & insurance context","qid":"DL-ALCOHOLANDPENALTIES-TRAP-029"},{"q":"Marcus was convicted of his first DWI in Texas a year ago. He has now completed his suspension and paid his fine, but his auto insurance company has dropped him, and the only policies he can find quote rates nearly triple what he paid before. He calls the DPS to ask why his driving situation is still being affected so long after the case ended. What is the most accurate explanation he will receive?","options":["Once his fine is paid and suspension served, the DWI is automatically cleared from his record, so any high rates are an unrelated billing error.","A DWI conviction stays on his record and sharply raises insurance costs, and he may be required to carry SR-22 financial responsibility insurance to reinstate driving privileges.","The high cost is only a temporary 180-day surcharge tied to his refusal of the breath test, and it will disappear after that period ends.","His record now shows the DWI, but insurers in Texas are legally barred from raising rates based on a single first offense."],"answer":1,"explanation":"A DWI conviction stays on the driver's record and sharply raises insurance costs, and an SR-22 financial responsibility filing may be required to reinstate driving privileges. Option A is wrong because completing penalties does not erase the conviction, and option C confuses this with the separate 180-day ALR suspension for refusing a test.","handbook":"A DWI conviction stays on your record and sharply raises insurance costs.","hbref":"The Texas point / surcharge & insurance context","qid":"DL-ALCOHOLANDPENALTIES-TRAP-030"},{"q":"Marcus completed his court sentence for a first DWI conviction, and his one-year license suspension period has now ended. When he visits the DPS office to get his driving privileges reinstated, the clerk tells him he must first file a specific form proving he carries adequate liability coverage going forward. What is this requirement called?","options":["An open container declaration showing he keeps no alcohol in the passenger area","An implied consent waiver acknowledging future breath or blood tests","SR-22 financial responsibility insurance","An alcohol-awareness course completion certificate"],"answer":2,"explanation":"After a DWI, Texas may require SR-22 financial responsibility insurance to prove coverage before driving privileges are reinstated. The alcohol-awareness course is tied to a minor's DUI penalty, not the insurance reinstatement requirement, and implied consent and open container are unrelated to proving financial responsibility.","handbook":"SR-22 financial responsibility insurance may be required to reinstate driving privileges.","hbref":"The Texas point / surcharge & insurance context","qid":"DL-ALCOHOLANDPENALTIES-TRAP-031"},{"q":"You are 28 years old and have had two beers over dinner at a friend's house. You feel completely fine, and you have a 25-minute drive home on quiet roads. What is the safest choice?","options":["Drive home, since two drinks always keep an adult under the 0.08% legal limit","Wait about 20 minutes, drink some coffee, and then drive once you feel alert","Drive now because you are not legally intoxicated unless your judgment is visibly affected","Do not drive at all; arrange a ride service, a sober driver, or stay put"],"answer":3,"explanation":"The safest choice is always zero alcohol before driving, so arranging a sober ride or staying put is correct. Two beers will not reliably keep you under 0.08%, and only time (not coffee) lowers BAC, so the other options are dangerous mistakes.","handbook":"The safest choice is zero alcohol before driving.","hbref":"Always-true safety rules","qid":"DL-ALCOHOLANDPENALTIES-TRAP-032"},{"q":"You meet friends at a bar after work and have several drinks over two hours. You feel the effects of the alcohol and know you are in no condition to drive home safely. What is the safest way to handle getting home?","options":["Call a ride service, hand your keys to a friend who has not been drinking, or simply stay where you are until you are sober","Drink a few cups of strong coffee and wait about 30 minutes before driving home","Eat a large meal and take a cold shower to speed up sobering before you drive","Wait one hour per drink while sitting in your car, then drive yourself home"],"answer":0,"explanation":"The safe, always-true choices are to use a ride service, designate a sober driver, or stay put until sober. Coffee, food, and a cold shower do NOT speed up sobering; only time lowers BAC, and the answer to alcohol is not to drive at all rather than wait it out in your car and then drive.","handbook":"Safe alternatives to driving after drinking include designating a sober driver, using a ride service, or staying put.","hbref":"Always-true safety rules","qid":"DL-ALCOHOLANDPENALTIES-TRAP-033"},{"q":"Marcus is 24 and drives his own car home after a dinner party. A police officer stops him, and a breath test shows his BAC is exactly 0.08%. At this reading, what is Marcus legally considered under Texas law?","options":["He is under the legal limit because the 0.08% threshold only applies to commercial drivers","He is Driving While Intoxicated (DWI), because for adults 21 and older a BAC at or above 0.08% is the legal threshold","He is only guilty if he also shows visible signs of impairment, since 0.08% alone is not enough","He has committed a DUI under Zero Tolerance, since any detectable alcohol is illegal"],"answer":1,"explanation":"For adults 21 and older, driving at or above 0.08% BAC is Driving While Intoxicated (DWI), so Marcus's exact 0.08% reading meets the threshold. The 0.04% commercial limit and the Zero Tolerance rule for drivers under 21 do not apply to a 24-year-old in his personal vehicle, and no additional visible impairment is required at or above 0.08%.","handbook":"The 0.08% BAC threshold applies specifically to adults aged 21 and older.","hbref":"Blood-alcohol limits (Texas)","qid":"DL-ALCOHOLANDPENALTIES-TRAP-034"},{"q":"Marcus is 19 years old. After a graduation party he is pulled over, and a breath test shows a BAC of 0.03%. He argues he cannot be charged because his reading is well below the adult 0.08% limit. Under Texas law, what is true about his situation?","options":["He is correct; no charge applies because 0.03% is under the 0.08% DWI limit.","He can only be charged if his BAC reaches 0.04%, the commercial-driver limit.","Because he is under 21, Zero Tolerance applies, so any detectable alcohol makes it a DUI by a minor.","He faces a felony DWI charge because 0.03% counts as a high BAC for a minor."],"answer":2,"explanation":"Texas Zero Tolerance makes any detectable alcohol (BAC above 0.00) illegal for drivers under 21, so Marcus is charged with DUI by a minor regardless of being under 0.08%. The 0.08% adult and 0.04% commercial limits do not apply to minors, and 0.03% is not a high-BAC felony situation.","handbook":"Zero Tolerance applies to drivers under the age of 21.","hbref":"Blood-alcohol limits (Texas)","qid":"DL-ALCOHOLANDPENALTIES-TRAP-035"},{"q":"Maria is stopped in Austin for weaving across lanes. It is her first-ever DWI arrest, her BAC tests at 0.10%, and her 9-year-old nephew is buckled in the back seat. How does the presence of the child change the legal seriousness of her DWI?","options":["Nothing changes; the child passenger only affects the fine amount, which rises to a maximum of $2,000","Her license is automatically suspended for 180 days because a child was present in the vehicle","It remains a standard first-offense misdemeanor, but she must also complete an alcohol-awareness course","Because a child passenger under 15 was present, the offense is elevated from a misdemeanor to a felony"],"answer":3,"explanation":"Under Texas law, a DWI committed with a child passenger younger than 15 in the vehicle is elevated to a felony, regardless of it being a first offense. Option B confuses this with the 180-day ALR suspension for refusing a chemical test, and the $2,000 fine in A is the standard first-offense misdemeanor penalty, not the felony enhancement triggered by the child.","handbook":"DWI penalties are increased when a child passenger under 15 is present, elevating the offense to a felony.","hbref":"DWI penalties (Texas, first offense)","qid":"DL-ALCOHOLANDPENALTIES-TRAP-036"},{"q":"You're lawfully arrested for DWI in Austin. The officer asks you to take a breath test, but you refuse, saying you'll only agree to give a blood sample instead. Under Texas implied consent law, what is true about your situation?","options":["By driving in Texas you've given implied consent to a breath OR blood test, so the test type isn't limited to one; refusing the requested test can trigger an automatic license suspension.","Implied consent only covers a breath test, so you have the right to demand a blood test instead with no penalty.","Implied consent only applies to a blood test, so refusing the breath test carries no consequences at all.","Because you offered an alternative, the liver will process the alcohol within one hour and no test is needed."],"answer":0,"explanation":"Texas implied consent covers a breath OR blood test, not just one type, so you can't limit it to your preferred test; refusing the lawfully requested test triggers an automatic 180-day suspension under ALR. Options B and C wrongly restrict implied consent to a single test type, and D confuses the unrelated fact that the liver processes about one drink per hour.","handbook":"Implied consent applies to a breath OR blood test, not just one type of test.","hbref":"Implied consent","qid":"DL-ALCOHOLANDPENALTIES-TRAP-037"},{"q":"After a couple of beers at dinner, a driver notices that oncoming headlights now look blurry and he has trouble seeing the edges of his lane and a pedestrian stepping off the curb. Which effect of alcohol best explains what he is experiencing behind the wheel?","options":["Alcohol acts as a stimulant that sharpens focus, so the blurriness must be caused by his headlights, not the alcohol","Alcohol is a depressant that reduces vision, making objects harder to see clearly and narrowing what he can detect","Alcohol only affects vision once a driver is above the 0.08% legal limit, so below that his eyesight is unaffected","Alcohol speeds up reaction time, which only makes nearby objects appear blurry at high speeds"],"answer":1,"explanation":"Alcohol is a depressant that reduces vision among the abilities it impairs, so blurry headlights and trouble seeing the lane and pedestrian are direct effects of the alcohol. Option C is wrong because alcohol can impair vision and driving even below 0.08%, and A and D misstate alcohol as a stimulant or claim it speeds reaction time, when it actually slows reactions.","handbook":"Alcohol reduces vision (one of the abilities it impairs).","hbref":"How alcohol affects driving","qid":"DL-ALCOHOLANDPENALTIES-TRAP-038"},{"q":"After three beers at a friend's house, Marcus gets behind the wheel. On the drive home he notices he keeps drifting in his lane and his hands feel clumsy and slow when he tries to make small steering corrections. Which effect of alcohol on his body best explains why his steering has become sloppy and imprecise?","options":["Alcohol speeds up his reaction time, so he is over-correcting the wheel","Alcohol acts as a stimulant that makes his muscles tense and jerky","Alcohol reduces his coordination, making smooth, precise steering harder","Alcohol has worn off because three beers are below the legal limit"],"answer":2,"explanation":"Alcohol is a depressant that reduces coordination, which is exactly why smooth, precise steering becomes difficult. Option A is wrong because alcohol slows reaction time rather than speeding it up, and option B is wrong because alcohol is a depressant, not a stimulant.","handbook":"Alcohol reduces coordination (one of the abilities it impairs).","hbref":"How alcohol affects driving","qid":"DL-ALCOHOLANDPENALTIES-TRAP-039"},{"q":"An officer pulls Marcus over for weaving across lanes late at night. After field sobriety tests, the officer lawfully arrests Marcus for DWI and then asks him to provide a breath sample. Under Texas implied consent law, what made it lawful for the officer to require this breath test?","options":["Marcus's BAC had already been measured at or above 0.08% before any arrest","Marcus signed an implied consent waiver when he renewed his driver license","The officer observed Marcus weaving across lanes, which is enough on its own to compel a test","Marcus was lawfully arrested for DWI, which triggers implied consent to a breath or blood test"],"answer":3,"explanation":"In Texas, the lawful trigger for implied consent testing is being lawfully arrested for DWI, so option D is correct. Observing bad driving (C) may justify the stop or arrest but does not by itself compel a test, and there is no separately signed waiver at license renewal (B).","handbook":"The lawful trigger for implied consent testing is being lawfully arrested for DWI.","hbref":"Implied consent","qid":"DL-ALCOHOLANDPENALTIES-TRAP-040"}]},{"id":"learn-alcohol-and-penalties","name":"Alcohol, Drugs & Penalties — Learn","blurb":"Texas DL Alcohol, Drugs & Penalties: practice tests plus a Learning Test that walks the whole handbook section.","accent":"#0a7c43","kind":"learn","learnSubject":"alcohol-and-penalties","classes":["DL"],"questions":[{"q":"In Texas, what is the BAC limit for DWI for an adult driver age 21 or older?","options":["0.08%","0.04%","0.10%","0.05%"],"answer":0,"explanation":"In Texas, an adult age 21 or older is legally intoxicated (DWI) at a BAC of 0.08% or higher.","handbook":"The adult (21+) BAC limit for DWI in Texas is 0.08%.","hbref":"Blood-alcohol limits (Texas)","qid":"DL-ALCOHOLANDPENALTIES-LRN-001"},{"q":"In Texas, what offense is driving at or above 0.08% BAC?","options":["Speeding","Driving While Intoxicated (DWI)","Reckless driving","Open container violation"],"answer":1,"explanation":"Driving at or above 0.08% BAC is the offense called Driving While Intoxicated (DWI).","handbook":"Driving at or above 0.08% BAC is the offense called Driving While Intoxicated (DWI).","hbref":"Blood-alcohol limits (Texas)","qid":"DL-ALCOHOLANDPENALTIES-LRN-002"},{"q":"Can a driver be charged with DWI if their BAC is below 0.08%?","options":["No, never below 0.08%","Only commercial drivers","Yes, if impaired by alcohol or drugs","Only if they refuse a test"],"answer":2,"explanation":"A driver can still be charged with DWI below 0.08% BAC if impaired by alcohol or drugs.","handbook":"A driver can still be charged with DWI below 0.08% BAC if they are impaired by alcohol or drugs.","hbref":"Blood-alcohol limits (Texas)","qid":"DL-ALCOHOLANDPENALTIES-LRN-003"},{"q":"What is the BAC limit for a commercial driver in Texas?","options":["0.08%","0.10%","0.02%","0.04%"],"answer":3,"explanation":"A commercial driver's BAC limit is 0.04%, lower than the standard adult limit of 0.08%.","handbook":"The BAC limit for a commercial driver in Texas is 0.04%, lower than the standard adult limit.","hbref":"Blood-alcohol limits (Texas)","qid":"DL-ALCOHOLANDPENALTIES-LRN-004"},{"q":"In Texas, what is the legal blood alcohol limit for a driver under 21?","options":["Any amount above 0.00 is illegal","0.08 BAC","0.04 BAC","0.05 BAC"],"answer":0,"explanation":"Texas uses Zero Tolerance, so any detectable alcohol (a BAC above 0.00) is illegal for a driver under 21.","handbook":"Under 21, Texas uses Zero Tolerance: ANY detectable alcohol (a BAC above 0.00) is illegal for a minor.","hbref":"Blood-alcohol limits (Texas)","qid":"DL-ALCOHOLANDPENALTIES-LRN-005"},{"q":"What does a minor commit by driving with any detectable alcohol?","options":["Nothing illegal","DUI of alcohol by a minor","A parking violation","A commercial DWI"],"answer":1,"explanation":"Under Texas Zero Tolerance, any detectable alcohol means a minor commits DUI of alcohol by a minor.","handbook":"A minor driving with any detectable alcohol commits DUI (Driving Under the Influence) of alcohol by a minor.","hbref":"Blood-alcohol limits (Texas)","qid":"DL-ALCOHOLANDPENALTIES-LRN-006"},{"q":"In Texas, what does DUI by a minor mean?","options":["Driving Unsafely Indoors","Driving Under Insurance","Driving Under the Influence","Driving With Intent"],"answer":2,"explanation":"DUI stands for Driving Under the Influence, the offense used for minors, distinct from the adult DWI.","handbook":"DUI by a minor refers to Driving Under the Influence, which is distinct from the adult DWI offense.","hbref":"Blood-alcohol limits (Texas)","qid":"DL-ALCOHOLANDPENALTIES-LRN-007"},{"q":"In Texas, the Zero Tolerance law applies to drivers who are under what age?","options":["16 years of age","18 years of age","25 years of age","21 years of age"],"answer":3,"explanation":"Texas's Zero Tolerance law makes any detectable alcohol illegal for drivers under 21 years of age.","handbook":"The Zero Tolerance law applies to drivers who are under 21 years of age.","hbref":"Blood-alcohol limits (Texas)","qid":"DL-ALCOHOLANDPENALTIES-LRN-008"},{"q":"What type of drug is alcohol?","options":["A depressant","A stimulant","A painkiller","A vitamin"],"answer":0,"explanation":"Alcohol is a depressant that slows your reaction time and impairs your judgment.","handbook":"Alcohol is a depressant.","hbref":"How alcohol affects driving","qid":"DL-ALCOHOLANDPENALTIES-LRN-009"},{"q":"How does alcohol affect a driver's reaction time?","options":["It speeds it up","It slows it down","It has no effect","It improves it"],"answer":1,"explanation":"Alcohol is a depressant that slows your reaction time.","handbook":"Alcohol slows reaction time.","hbref":"How alcohol affects driving","qid":"DL-ALCOHOLANDPENALTIES-LRN-010"},{"q":"What does alcohol impair when you drive?","options":["Your fuel level","Your tire pressure","Your judgment","Your headlights"],"answer":2,"explanation":"Alcohol impairs judgment, which is the first driving ability affected.","handbook":"Alcohol impairs judgment.","hbref":"How alcohol affects driving","qid":"DL-ALCOHOLANDPENALTIES-LRN-011"},{"q":"What does alcohol do to a driver's coordination?","options":["It sharpens coordination","It has no effect on coordination","It only affects coordination at night","It reduces coordination"],"answer":3,"explanation":"Alcohol is a depressant that reduces a driver's coordination.","handbook":"Alcohol reduces coordination.","hbref":"How alcohol affects driving","qid":"DL-ALCOHOLANDPENALTIES-LRN-012"},{"q":"How does alcohol affect a driver's vision?","options":["It reduces vision","It improves vision","It has no effect on vision","It sharpens night vision"],"answer":0,"explanation":"Alcohol reduces vision, making it harder to see clearly while driving.","handbook":"Alcohol reduces vision.","hbref":"How alcohol affects driving","qid":"DL-ALCOHOLANDPENALTIES-LRN-013"},{"q":"Which driving ability does alcohol affect first?","options":["Vision","Judgment","Hearing","Steering grip"],"answer":1,"explanation":"Alcohol affects judgment before other driving abilities.","handbook":"The first driving ability affected by alcohol is judgment.","hbref":"How alcohol affects driving","qid":"DL-ALCOHOLANDPENALTIES-LRN-014"},{"q":"What is the only thing that lowers your blood alcohol concentration (BAC)?","options":["Drinking coffee","Taking a cold shower","The passage of time","Eating a big meal"],"answer":2,"explanation":"Only the passage of time lowers BAC; coffee, food, and showers do not speed it up.","handbook":"Only the passage of time lowers BAC.","hbref":"How alcohol affects driving","qid":"DL-ALCOHOLANDPENALTIES-LRN-015"},{"q":"What is the only thing that lowers your blood alcohol level?","options":["Drinking coffee","Eating a big meal","Taking a cold shower","Waiting and letting time pass"],"answer":3,"explanation":"Only time lowers your BAC; coffee, food, and showers do not speed up sobering.","handbook":"Coffee does NOT speed up sobering up or lower BAC.","hbref":"How alcohol affects driving","qid":"DL-ALCOHOLANDPENALTIES-LRN-016"},{"q":"What is the only thing that lowers your blood alcohol content (BAC)?","options":["Time","Eating food","Drinking coffee","Taking a cold shower"],"answer":0,"explanation":"Only time lowers BAC; food, coffee, and showers do not speed up sobering.","handbook":"Food does NOT speed up sobering up or lower BAC.","hbref":"How alcohol affects driving","qid":"DL-ALCOHOLANDPENALTIES-LRN-017"},{"q":"What is the only thing that lowers a person's blood alcohol concentration (BAC)?","options":["Drinking coffee","Time","A cold shower","Fresh air"],"answer":1,"explanation":"Only time lowers BAC; coffee, a cold shower, and fresh air do not speed up sobering.","handbook":"A cold shower does NOT speed up sobering up or lower BAC.","hbref":"How alcohol affects driving","qid":"DL-ALCOHOLANDPENALTIES-LRN-018"},{"q":"What is the only thing that lowers your blood alcohol level?","options":["Fresh air","Drinking coffee","Time","A cold shower"],"answer":2,"explanation":"Only time lowers BAC; fresh air, coffee, and a cold shower do not speed up sobering.","handbook":"Fresh air does NOT speed up sobering up or lower BAC.","hbref":"How alcohol affects driving","qid":"DL-ALCOHOLANDPENALTIES-LRN-019"},{"q":"About how much alcohol can your liver process in one hour?","options":["About four drinks","About three drinks","About two drinks","About one drink"],"answer":3,"explanation":"The liver processes about one standard drink per hour, and nothing can speed it up.","handbook":"The liver processes about one standard drink per hour.","hbref":"How alcohol affects driving","qid":"DL-ALCOHOLANDPENALTIES-LRN-020"},{"q":"Can anything make the liver process alcohol faster than its normal rate?","options":["No, nothing speeds it up","Yes, drinking coffee","Yes, a cold shower","Yes, eating food"],"answer":0,"explanation":"Nothing can make the liver process alcohol faster than its normal rate.","handbook":"Nothing can make the liver process alcohol faster than its normal rate.","hbref":"How alcohol affects driving","qid":"DL-ALCOHOLANDPENALTIES-LRN-021"},{"q":"What happens when you combine drugs with alcohol?","options":["It cancels out the alcohol","It multiplies impairment","It speeds up sobering","It has no effect"],"answer":1,"explanation":"Mixing drugs (illegal, prescription, or over-the-counter) with alcohol multiplies impairment.","handbook":"Combining drugs (illegal, prescription, or over-the-counter) with alcohol multiplies impairment.","hbref":"How alcohol affects driving","qid":"DL-ALCOHOLANDPENALTIES-LRN-022"},{"q":"Can prescription or over-the-counter drugs increase impairment when taken with alcohol?","options":["No, only illegal drugs do","No, they cancel alcohol out","Yes, they can multiply impairment","No, they have no effect"],"answer":2,"explanation":"Even prescription and over-the-counter drugs can multiply impairment when combined with alcohol.","handbook":"Even prescription and over-the-counter drugs can multiply impairment when combined with alcohol.","hbref":"How alcohol affects driving","qid":"DL-ALCOHOLANDPENALTIES-LRN-023"},{"q":"In Texas, what do you agree to by driving if you are lawfully arrested for DWI?","options":["A vision test","A driving test","A hearing test","A breath or blood test"],"answer":3,"explanation":"By driving in Texas you give implied consent to a breath or blood test if lawfully arrested for DWI.","handbook":"By driving in Texas you give implied consent to a breath or blood test if lawfully arrested for DWI.","hbref":"Implied consent","qid":"DL-ALCOHOLANDPENALTIES-LRN-024"},{"q":"In Texas, implied consent applies to which test?","options":["A breath or blood test","A vision test","A hearing test","A written test"],"answer":0,"explanation":"By driving in Texas, you give implied consent to a breath or blood test if lawfully arrested for DWI.","handbook":"Implied consent applies to a breath or blood test.","hbref":"Implied consent","qid":"DL-ALCOHOLANDPENALTIES-LRN-025"},{"q":"When does Texas implied consent to testing apply?","options":["When a driver is stopped for speeding","When a driver is lawfully arrested for DWI","When a driver parks illegally","When a driver renews a license"],"answer":1,"explanation":"By driving in Texas you give implied consent to a breath or blood test if you are lawfully arrested for DWI.","handbook":"Implied consent to testing applies when a driver is lawfully arrested for DWI.","hbref":"Implied consent","qid":"DL-ALCOHOLANDPENALTIES-LRN-026"},{"q":"Refusing a breath or blood test causes an automatic license suspension of how many days for a first refusal?","options":["30 days","90 days","180 days","365 days"],"answer":2,"explanation":"A first refusal of the breath or blood test results in an automatic 180-day license suspension.","handbook":"Refusing the breath or blood test results in an automatic license suspension of 180 days for a first refusal.","hbref":"Implied consent","qid":"DL-ALCOHOLANDPENALTIES-LRN-027"},{"q":"Under which law is the automatic license suspension for refusing a test imposed?","options":["Implied Consent Repeal Act","Open Container Law","Zero Tolerance Law","Administrative License Revocation (ALR)"],"answer":3,"explanation":"Refusing a breath or blood test triggers an automatic license suspension under Administrative License Revocation (ALR).","handbook":"The automatic suspension for refusing a test is imposed under Administrative License Revocation (ALR).","hbref":"Implied consent","qid":"DL-ALCOHOLANDPENALTIES-LRN-028"},{"q":"Is the ALR license suspension for refusing a test separate from DWI conviction penalties?","options":["Yes, it is separate","No, it replaces them","No, only if convicted","Yes, but only for minors"],"answer":0,"explanation":"The ALR suspension for refusing a test is separate from any DWI conviction penalties.","handbook":"The ALR suspension for refusing a test is separate from any DWI conviction penalties.","hbref":"Implied consent","qid":"DL-ALCOHOLANDPENALTIES-LRN-029"},{"q":"What is the maximum fine for a first DWI in Texas?","options":["Up to $500","Up to $2,000","Up to $5,000","Up to $10,000"],"answer":1,"explanation":"A first DWI in Texas carries a fine of up to $2,000.","handbook":"A first DWI carries a fine of up to $2,000.","hbref":"DWI penalties (Texas, first offense)","qid":"DL-ALCOHOLANDPENALTIES-LRN-030"},{"q":"How much jail time can a first DWI carry in Texas?","options":["1 to 30 days","2 to 90 days","3 days to 180 days","5 days to 365 days"],"answer":2,"explanation":"A first DWI in Texas carries jail time of 3 days to 180 days.","handbook":"A first DWI carries jail time of 3 days to 180 days.","hbref":"DWI penalties (Texas, first offense)","qid":"DL-ALCOHOLANDPENALTIES-LRN-031"},{"q":"What is the minimum jail time for a first DWI in Texas?","options":["30 days","10 days","1 day","3 days"],"answer":3,"explanation":"A first DWI in Texas carries a minimum jail time of 3 days.","handbook":"The minimum jail time for a first DWI is 3 days.","hbref":"DWI penalties (Texas, first offense)","qid":"DL-ALCOHOLANDPENALTIES-LRN-032"},{"q":"What is the maximum jail time for a first DWI in Texas?","options":["180 days","30 days","1 year","10 days"],"answer":0,"explanation":"A first DWI in Texas carries a maximum jail term of 180 days.","handbook":"The maximum jail time for a first DWI is 180 days.","hbref":"DWI penalties (Texas, first offense)","qid":"DL-ALCOHOLANDPENALTIES-LRN-033"},{"q":"In Texas, how long can your license be suspended for a first DWI?","options":["Up to 30 days","Up to 1 year","Up to 5 years","Never suspended"],"answer":1,"explanation":"A first DWI in Texas carries a license suspension of up to 1 year.","handbook":"A first DWI carries a license suspension of up to 1 year.","hbref":"DWI penalties (Texas, first offense)","qid":"DL-ALCOHOLANDPENALTIES-LRN-034"},{"q":"In Texas, what happens to DWI penalties for repeat offenses?","options":["They are removed","They stay the same","They increase","They become optional"],"answer":2,"explanation":"In Texas, penalties increase for repeat DWI offenses.","handbook":"Penalties increase for repeat DWI offenses.","hbref":"DWI penalties (Texas, first offense)","qid":"DL-ALCOHOLANDPENALTIES-LRN-035"},{"q":"In Texas, what BAC level is high enough to increase DWI penalties?","options":["0.04% or above","0.06% or above","0.08% or above","0.15% or above"],"answer":3,"explanation":"A high BAC of 0.15% or above increases the penalties for DWI.","handbook":"Penalties increase for a high BAC of 0.15% or above.","hbref":"DWI penalties (Texas, first offense)","qid":"DL-ALCOHOLANDPENALTIES-LRN-036"},{"q":"In Texas, what high BAC level increases DWI penalties?","options":["0.15%","0.08%","0.04%","0.02%"],"answer":0,"explanation":"A BAC of 0.15% or higher increases the penalties for a Texas DWI.","handbook":"The high-BAC threshold that increases penalties is 0.15%.","hbref":"DWI penalties (Texas, first offense)","qid":"DL-ALCOHOLANDPENALTIES-LRN-037"},{"q":"In Texas, what makes DWI penalties increase on a first offense?","options":["Driving slowly","Having a child passenger","Wearing a seatbelt","Driving at night"],"answer":1,"explanation":"Penalties increase when there is a child passenger in the vehicle.","handbook":"Penalties increase when there is a child passenger.","hbref":"DWI penalties (Texas, first offense)","qid":"DL-ALCOHOLANDPENALTIES-LRN-038"},{"q":"In Texas, what is DWI with a child under 15 in the vehicle?","options":["A warning only","A parking ticket","A felony","Not an offense"],"answer":2,"explanation":"In Texas, driving while intoxicated with a child under 15 in the vehicle is a felony.","handbook":"DWI with a child under 15 is a felony.","hbref":"DWI penalties (Texas, first offense)","qid":"DL-ALCOHOLANDPENALTIES-LRN-039"},{"q":"In Texas, DWI becomes a felony if there is a child passenger under what age?","options":["Under 8 years old","Under 10 years old","Under 12 years old","Under 15 years old"],"answer":3,"explanation":"In Texas, DWI with a child passenger under 15 years old is a felony.","handbook":"The child-passenger age threshold making DWI a felony is under 15 years old.","hbref":"DWI penalties (Texas, first offense)","qid":"DL-ALCOHOLANDPENALTIES-LRN-040"},{"q":"In Texas, is having an open container of alcohol in the passenger area a separate offense?","options":["Yes, it is a separate offense","No, it is always allowed","Only for passengers, never the driver","Only on highways"],"answer":0,"explanation":"In Texas, having an open container of alcohol in the passenger area is a separate offense.","handbook":"Having an open container of alcohol in the passenger area is a separate offense.","hbref":"DWI penalties (Texas, first offense)","qid":"DL-ALCOHOLANDPENALTIES-LRN-041"},{"q":"Where does the open container alcohol offense apply in a vehicle?","options":["Only in the trunk","In the passenger area","On the roof","Under the hood"],"answer":1,"explanation":"The open container offense applies to alcohol in the passenger area of the vehicle.","handbook":"The open container offense applies to alcohol in the passenger area of the vehicle.","hbref":"DWI penalties (Texas, first offense)","qid":"DL-ALCOHOLANDPENALTIES-LRN-042"},{"q":"What is the maximum fine for a minor's first DUI (alcohol) in Texas?","options":["Up to $100","Up to $250","Up to $500","Up to $2,000"],"answer":2,"explanation":"A minor's first DUI for alcohol carries a fine of up to $500.","handbook":"A minor's first DUI (alcohol) carries a fine of up to $500.","hbref":"Minors & zero tolerance penalties","qid":"DL-ALCOHOLANDPENALTIES-LRN-043"},{"q":"What does a minor's first DUI for alcohol include?","options":["No penalty at all","Only a warning letter","A free driving lesson","A license suspension"],"answer":3,"explanation":"A minor's first DUI for alcohol includes a license suspension.","handbook":"A minor's first DUI (alcohol) includes a license suspension.","hbref":"Minors & zero tolerance penalties","qid":"DL-ALCOHOLANDPENALTIES-LRN-044"},{"q":"What is one penalty for a minor's first DUI (alcohol) in Texas?","options":["Community service","A free driving course","A new license discount","Extra license points removed"],"answer":0,"explanation":"A minor's first alcohol DUI in Texas includes community service.","handbook":"A minor's first DUI (alcohol) includes community service.","hbref":"Minors & zero tolerance penalties","qid":"DL-ALCOHOLANDPENALTIES-LRN-045"},{"q":"In Texas, what is a minor required to complete after a first DUI for alcohol?","options":["A defensive driving course","An alcohol-awareness course","A vision exam","A first-aid course"],"answer":1,"explanation":"A minor's first alcohol DUI requires completing an alcohol-awareness course.","handbook":"A minor's first DUI (alcohol) requires an alcohol-awareness course.","hbref":"Minors & zero tolerance penalties","qid":"DL-ALCOHOLANDPENALTIES-LRN-046"},{"q":"What do traffic convictions add to your driving record?","options":["Free driving lessons","Extra license years","Points","Cash rewards"],"answer":2,"explanation":"Traffic convictions add points to your driving record.","handbook":"Traffic convictions add points to your driving record.","hbref":"The Texas point / surcharge & insurance context","qid":"DL-ALCOHOLANDPENALTIES-LRN-047"},{"q":"What can too many traffic convictions lead to?","options":["Lower insurance rates","A free driving course","Extra license points removed","Surcharges"],"answer":3,"explanation":"Too many convictions can lead to surcharges and even license suspension.","handbook":"Too many convictions can lead to surcharges.","hbref":"The Texas point / surcharge & insurance context","qid":"DL-ALCOHOLANDPENALTIES-LRN-048"},{"q":"What can too many traffic convictions lead to?","options":["License suspension","A free license renewal","More driving privileges","Lower insurance costs"],"answer":0,"explanation":"Too many convictions can add surcharges and lead to license suspension.","handbook":"Too many convictions can lead to license suspension.","hbref":"The Texas point / surcharge & insurance context","qid":"DL-ALCOHOLANDPENALTIES-LRN-049"},{"q":"In Texas, what happens to a DWI conviction over time?","options":["It is erased after one month","It stays on your record","It disappears when you pay the fine","It is removed after one safe trip"],"answer":1,"explanation":"A DWI conviction stays on your record and raises your insurance costs.","handbook":"A DWI conviction stays on your record.","hbref":"The Texas point / surcharge & insurance context","qid":"DL-ALCOHOLANDPENALTIES-LRN-050"},{"q":"How does a DWI conviction affect your car insurance costs?","options":["It lowers them","It has no effect","It sharply raises them","It cancels all fees"],"answer":2,"explanation":"A DWI conviction stays on your record and sharply raises insurance costs.","handbook":"A DWI conviction sharply raises insurance costs.","hbref":"The Texas point / surcharge & insurance context","qid":"DL-ALCOHOLANDPENALTIES-LRN-051"},{"q":"What insurance may be required to reinstate your driving privileges in Texas?","options":["Travel insurance","Pet insurance","Health insurance","SR-22 financial responsibility insurance"],"answer":3,"explanation":"SR-22 financial responsibility insurance may be required to reinstate your driving privileges.","handbook":"SR-22 financial responsibility insurance may be required to reinstate driving privileges.","hbref":"The Texas point / surcharge & insurance context","qid":"DL-ALCOHOLANDPENALTIES-LRN-052"},{"q":"What is SR-22?","options":["A form of financial responsibility insurance","A type of driver license","A traffic ticket","A blood alcohol test"],"answer":0,"explanation":"SR-22 is a form of financial responsibility insurance that may be required to reinstate driving privileges.","handbook":"SR-22 is a form of financial responsibility insurance.","hbref":"The Texas point / surcharge & insurance context","qid":"DL-ALCOHOLANDPENALTIES-LRN-053"},{"q":"What is the safest amount of alcohol to drink before driving?","options":["One drink","Zero alcohol","Two drinks","One beer"],"answer":1,"explanation":"The safest choice is zero alcohol before driving.","handbook":"The safest choice is zero alcohol before driving.","hbref":"Always-true safety rules","qid":"DL-ALCOHOLANDPENALTIES-LRN-054"},{"q":"How can you avoid drinking and driving?","options":["Drink coffee first","Drive slowly","Designate a sober driver","Open the windows"],"answer":2,"explanation":"Choosing a sober driver lets you avoid driving after drinking.","handbook":"To avoid drinking and driving you can designate a sober driver.","hbref":"Always-true safety rules","qid":"DL-ALCOHOLANDPENALTIES-LRN-055"},{"q":"What can you use to avoid drinking and driving?","options":["A cup of coffee","A cold shower","Fresh air","A ride service"],"answer":3,"explanation":"Using a ride service lets you avoid drinking and driving.","handbook":"To avoid drinking and driving you can use a ride service.","hbref":"Always-true safety rules","qid":"DL-ALCOHOLANDPENALTIES-LRN-056"},{"q":"What is one way to avoid drinking and driving?","options":["Stay put instead of driving","Drive very slowly","Drink some water first","Open the car windows"],"answer":0,"explanation":"Staying put instead of driving keeps you from drinking and driving.","handbook":"To avoid drinking and driving you can stay put rather than drive.","hbref":"Always-true safety rules","qid":"DL-ALCOHOLANDPENALTIES-LRN-057"},{"q":"What blood-alcohol level is illegal for a driver under 21 in Texas?","options":["0.08% or higher","Any amount above 0.00","0.04% or higher","0.15% or higher"],"answer":1,"explanation":"Texas has zero tolerance, so any detectable alcohol above 0.00 is illegal for a minor.","handbook":"A minor's illegal alcohol level is any BAC above 0.00, not the adult 0.08% threshold.","hbref":"Blood-alcohol limits (Texas)","qid":"DL-ALCOHOLANDPENALTIES-LRN-058"},{"q":"Alcohol is a depressant, so what does it do to the body?","options":["Speeds up reaction time","Improves coordination","Slows down body functions","Sharpens vision"],"answer":2,"explanation":"As a depressant, alcohol slows down the body's functions instead of stimulating them.","handbook":"Because alcohol is a depressant, it slows down the body's functions rather than stimulating them.","hbref":"How alcohol affects driving","qid":"DL-ALCOHOLANDPENALTIES-LRN-059"},{"q":"In Texas, what is the maximum fine for a first DWI conviction?","options":["$200","$500","$1,000","$2,000"],"answer":3,"explanation":"A first DWI conviction in Texas carries a fine of up to $2,000.","handbook":"DWI penalties (fine, jail, suspension) and the high-BAC/child-passenger enhancements are distinct from the open container offense.","hbref":"DWI penalties (Texas, first offense)","qid":"DL-ALCOHOLANDPENALTIES-LRN-060"}]}]};
window.DL_I18N = {"cat":{"en":{"road-signs":{"name":"Road Signs","blurb":"Texas DL Road Signs: practice tests plus a Learning Test that walks the whole handbook section."},"learn-road-signs":{"name":"Road Signs — Learn","blurb":"Texas DL Road Signs: practice tests plus a Learning Test that walks the whole handbook section."},"rules-of-the-road":{"name":"Rules of the Road","blurb":"Texas DL Rules of the Road: practice tests plus a Learning Test that walks the whole handbook section."},"learn-rules-of-the-road":{"name":"Rules of the Road — Learn","blurb":"Texas DL Rules of the Road: practice tests plus a Learning Test that walks the whole handbook section."},"signals-and-markings":{"name":"Traffic Signals & Markings","blurb":"Texas DL Traffic Signals & Markings: practice tests plus a Learning Test that walks the whole handbook section."},"learn-signals-and-markings":{"name":"Traffic Signals & Markings — Learn","blurb":"Texas DL Traffic Signals & Markings: practice tests plus a Learning Test that walks the whole handbook section."},"safe-driving":{"name":"Safe Driving","blurb":"Texas DL Safe Driving: practice tests plus a Learning Test that walks the whole handbook section."},"learn-safe-driving":{"name":"Safe Driving — Learn","blurb":"Texas DL Safe Driving: practice tests plus a Learning Test that walks the whole handbook section."},"alcohol-and-penalties":{"name":"Alcohol, Drugs & Penalties","blurb":"Texas DL Alcohol, Drugs & Penalties: practice tests plus a Learning Test that walks the whole handbook section."},"learn-alcohol-and-penalties":{"name":"Alcohol, Drugs & Penalties — Learn","blurb":"Texas DL Alcohol, Drugs & Penalties: practice tests plus a Learning Test that walks the whole handbook section."}},"ru":{"road-signs":{"name":"Дорожные знаки","blurb":"Texas DL «Дорожные знаки»: пробные тесты и обучающий тест по всему разделу руководства."},"learn-road-signs":{"name":"Дорожные знаки — Learn","blurb":"Texas DL «Дорожные знаки»: пробные тесты и обучающий тест по всему разделу руководства."},"rules-of-the-road":{"name":"Правила дорожного движения","blurb":"Texas DL «Правила дорожного движения»: пробные тесты и обучающий тест по всему разделу руководства."},"learn-rules-of-the-road":{"name":"Правила дорожного движения — Learn","blurb":"Texas DL «Правила дорожного движения»: пробные тесты и обучающий тест по всему разделу руководства."},"signals-and-markings":{"name":"Сигналы и разметка","blurb":"Texas DL «Сигналы и разметка»: пробные тесты и обучающий тест по всему разделу руководства."},"learn-signals-and-markings":{"name":"Сигналы и разметка — Learn","blurb":"Texas DL «Сигналы и разметка»: пробные тесты и обучающий тест по всему разделу руководства."},"safe-driving":{"name":"Безопасное вождение","blurb":"Texas DL «Безопасное вождение»: пробные тесты и обучающий тест по всему разделу руководства."},"learn-safe-driving":{"name":"Безопасное вождение — Learn","blurb":"Texas DL «Безопасное вождение»: пробные тесты и обучающий тест по всему разделу руководства."},"alcohol-and-penalties":{"name":"Алкоголь, наркотики и штрафы","blurb":"Texas DL «Алкоголь, наркотики и штрафы»: пробные тесты и обучающий тест по всему разделу руководства."},"learn-alcohol-and-penalties":{"name":"Алкоголь, наркотики и штрафы — Learn","blurb":"Texas DL «Алкоголь, наркотики и штрафы»: пробные тесты и обучающий тест по всему разделу руководства."}},"tr":{"road-signs":{"name":"Trafik İşaretleri","blurb":"Texas DL Trafik İşaretleri: deneme testleri ve el kitabının tüm bölümünü gezen bir Öğrenme Testi."},"learn-road-signs":{"name":"Trafik İşaretleri — Learn","blurb":"Texas DL Trafik İşaretleri: deneme testleri ve el kitabının tüm bölümünü gezen bir Öğrenme Testi."},"rules-of-the-road":{"name":"Trafik Kuralları","blurb":"Texas DL Trafik Kuralları: deneme testleri ve el kitabının tüm bölümünü gezen bir Öğrenme Testi."},"learn-rules-of-the-road":{"name":"Trafik Kuralları — Learn","blurb":"Texas DL Trafik Kuralları: deneme testleri ve el kitabının tüm bölümünü gezen bir Öğrenme Testi."},"signals-and-markings":{"name":"Trafik Işıkları ve İşaretlemeler","blurb":"Texas DL Trafik Işıkları ve İşaretlemeler: deneme testleri ve el kitabının tüm bölümünü gezen bir Öğrenme Testi."},"learn-signals-and-markings":{"name":"Trafik Işıkları ve İşaretlemeler — Learn","blurb":"Texas DL Trafik Işıkları ve İşaretlemeler: deneme testleri ve el kitabının tüm bölümünü gezen bir Öğrenme Testi."},"safe-driving":{"name":"Güvenli Sürüş","blurb":"Texas DL Güvenli Sürüş: deneme testleri ve el kitabının tüm bölümünü gezen bir Öğrenme Testi."},"learn-safe-driving":{"name":"Güvenli Sürüş — Learn","blurb":"Texas DL Güvenli Sürüş: deneme testleri ve el kitabının tüm bölümünü gezen bir Öğrenme Testi."},"alcohol-and-penalties":{"name":"Alkol, Uyuşturucu ve Cezalar","blurb":"Texas DL Alkol, Uyuşturucu ve Cezalar: deneme testleri ve el kitabının tüm bölümünü gezen bir Öğrenme Testi."},"learn-alcohol-and-penalties":{"name":"Alkol, Uyuşturucu ve Cezalar — Learn","blurb":"Texas DL Alkol, Uyuşturucu ve Cezalar: deneme testleri ve el kitabının tüm bölümünü gezen bir Öğrenme Testi."}},"es":{"road-signs":{"name":"Señales de Tránsito","blurb":"Texas DL Señales de Tránsito: exámenes de práctica y un examen de aprendizaje que recorre toda la sección."},"learn-road-signs":{"name":"Señales de Tránsito — Learn","blurb":"Texas DL Señales de Tránsito: exámenes de práctica y un examen de aprendizaje que recorre toda la sección."},"rules-of-the-road":{"name":"Reglas de la Vía","blurb":"Texas DL Reglas de la Vía: exámenes de práctica y un examen de aprendizaje que recorre toda la sección."},"learn-rules-of-the-road":{"name":"Reglas de la Vía — Learn","blurb":"Texas DL Reglas de la Vía: exámenes de práctica y un examen de aprendizaje que recorre toda la sección."},"signals-and-markings":{"name":"Señales y Marcas Viales","blurb":"Texas DL Señales y Marcas Viales: exámenes de práctica y un examen de aprendizaje que recorre toda la sección."},"learn-signals-and-markings":{"name":"Señales y Marcas Viales — Learn","blurb":"Texas DL Señales y Marcas Viales: exámenes de práctica y un examen de aprendizaje que recorre toda la sección."},"safe-driving":{"name":"Conducción Segura","blurb":"Texas DL Conducción Segura: exámenes de práctica y un examen de aprendizaje que recorre toda la sección."},"learn-safe-driving":{"name":"Conducción Segura — Learn","blurb":"Texas DL Conducción Segura: exámenes de práctica y un examen de aprendizaje que recorre toda la sección."},"alcohol-and-penalties":{"name":"Alcohol, Drogas y Sanciones","blurb":"Texas DL Alcohol, Drogas y Sanciones: exámenes de práctica y un examen de aprendizaje que recorre toda la sección."},"learn-alcohol-and-penalties":{"name":"Alcohol, Drogas y Sanciones — Learn","blurb":"Texas DL Alcohol, Drogas y Sanciones: exámenes de práctica y un examen de aprendizaje que recorre toda la sección."}},"hi":{"road-signs":{"name":"सड़क संकेत","blurb":"Texas DL सड़क संकेत: अभ्यास परीक्षाएँ और पूरे हैंडबुक खंड को कवर करने वाला एक लर्निंग टेस्ट।"},"learn-road-signs":{"name":"सड़क संकेत — Learn","blurb":"Texas DL सड़क संकेत: अभ्यास परीक्षाएँ और पूरे हैंडबुक खंड को कवर करने वाला एक लर्निंग टेस्ट।"},"rules-of-the-road":{"name":"यातायात के नियम","blurb":"Texas DL यातायात के नियम: अभ्यास परीक्षाएँ और पूरे हैंडबुक खंड को कवर करने वाला एक लर्निंग टेस्ट।"},"learn-rules-of-the-road":{"name":"यातायात के नियम — Learn","blurb":"Texas DL यातायात के नियम: अभ्यास परीक्षाएँ और पूरे हैंडबुक खंड को कवर करने वाला एक लर्निंग टेस्ट।"},"signals-and-markings":{"name":"ट्रैफ़िक सिग्नल और चिह्न","blurb":"Texas DL ट्रैफ़िक सिग्नल और चिह्न: अभ्यास परीक्षाएँ और पूरे हैंडबुक खंड को कवर करने वाला एक लर्निंग टेस्ट।"},"learn-signals-and-markings":{"name":"ट्रैफ़िक सिग्नल और चिह्न — Learn","blurb":"Texas DL ट्रैफ़िक सिग्नल और चिह्न: अभ्यास परीक्षाएँ और पूरे हैंडबुक खंड को कवर करने वाला एक लर्निंग टेस्ट।"},"safe-driving":{"name":"सुरक्षित ड्राइविंग","blurb":"Texas DL सुरक्षित ड्राइविंग: अभ्यास परीक्षाएँ और पूरे हैंडबुक खंड को कवर करने वाला एक लर्निंग टेस्ट।"},"learn-safe-driving":{"name":"सुरक्षित ड्राइविंग — Learn","blurb":"Texas DL सुरक्षित ड्राइविंग: अभ्यास परीक्षाएँ और पूरे हैंडबुक खंड को कवर करने वाला एक लर्निंग टेस्ट।"},"alcohol-and-penalties":{"name":"शराब, नशीले पदार्थ और दंड","blurb":"Texas DL शराब, नशीले पदार्थ और दंड: अभ्यास परीक्षाएँ और पूरे हैंडबुक खंड को कवर करने वाला एक लर्निंग टेस्ट।"},"learn-alcohol-and-penalties":{"name":"शराब, नशीले पदार्थ और दंड — Learn","blurb":"Texas DL शराब, नशीले पदार्थ और दंड: अभ्यास परीक्षाएँ और पूरे हैंडबुक खंड को कवर करने वाला एक लर्निंग टेस्ट।"}}},"q":{"ru":{"road-signs":{"0":{"q":"В сумерках вы приближаетесь к перекрёстку, где обращённый к вам знак сильно выцвел, и вы больше не можете прочитать на нём ни одной буквы. При этом вы по-прежнему отчётливо видите, что у знака восемь сторон. Что вы должны сделать на этом перекрёстке?","options":["Полностью остановиться, потому что восьмиугольный знак всегда означает СТОП.","Снизить скорость и уступить дорогу, останавливаясь только при наличии другого транспорта.","Снизить скорость и проехать с осторожностью, так как форма лишь предупреждает об опасности впереди.","Расценить его как знак школьного перехода и быть готовым к выходу детей на проезжую часть."],"explanation":"The octagon is the only eight-sided sign and always means STOP, so the shape alone tells you to come to a full stop even when the lettering is unreadable. Yielding is signaled by an inverted triangle, not an octagon, which makes that option the trap."},"1":{"q":"Вы выезжаете на шоссе с разгонной полосы и видите перед собой красно-белый знак в форме перевёрнутого (вершиной вниз) треугольника. Что требует от вас этот знак?","options":["Полностью остановиться и стоять, пока шоссе не освободится в обоих направлениях","Уступить дорогу транспорту на шоссе, снижая скорость или останавливаясь только при необходимости для безопасного манёвра","Двигаться с указанной максимальной скоростью, поскольку при перестроении приоритет у вас","Воспринимать его как предупреждение об опасности впереди и продолжать движение осторожно, не уступая дорогу"],"explanation":"An inverted triangle is a YIELD sign: you must give the right of way to traffic already on the highway and slow or stop only if needed to merge safely. A full stop every time (A) describes an octagonal STOP sign, and a diamond-shaped warning sign (D) does not require yielding the right of way."},"2":{"q":"Вы едете по двухполосному сельскому шоссе и хотите обогнать медленный трактор впереди. Прямо перед выездом на встречную полосу вы замечаете знак в форме треугольника, лежащего на боку (горизонтальный угол), установленный на ЛЕВОЙ обочине дороги. О чём говорит вам этот знак?","options":["Уступите дорогу встречному транспорту, прежде чем вернуться на свою полосу","Впереди школьная зона или школьный переход, снизьте скорость","Вы въезжаете в зону запрета обгона и не должны обгонять трактор здесь","Впереди опасность или особое условие, снизьте скорость и двигайтесь осторожно"],"explanation":"A pennant (a horizontal triangle) posted on the LEFT side of the road marks a No Passing Zone, so you must not pass the tractor. A yield is an inverted (upside-down) triangle, and a diamond is the warning shape, so those options confuse other sign shapes with the pennant."},"3":{"q":"Вы едете по незнакомому двухполосному шоссе в сумерках. Впереди справа на обочине вы видите жёлтый знак в форме ромба, но вы ещё слишком далеко, чтобы прочитать слова или символ на нём. Что вы должны сразу понять, исходя только из его формы?","options":["Это предписывающий знак, сообщающий о законе, который вы обязаны соблюдать, например об ограничении скорости","Он обозначает школьную зону или школьный переход впереди","Это указательный знак, дающий направления или расстояния до ближайшего города","Это предупреждающий знак, сообщающий об опасности или изменении дорожных условий впереди"],"explanation":"A diamond shape always means a warning sign, telling you a hazard or condition lies ahead. Regulatory laws use vertical rectangles (A) and guide/direction information uses horizontal rectangles (C), while school zones use a pentagon (B)."},"4":{"q":"Проезжая по незнакомому жилому району, вы видите жёлто-зелёный пятиугольный знак с вершиной, направленной вверх. Только по его форме — о чём этот знак вас предупреждает?","options":["Вы приближаетесь к школьной зоне или школьному переходу","Впереди железнодорожный переезд","Вы въезжаете в зону, где обгон запрещён","Впереди опасность или особое дорожное условие"],"explanation":"A pentagon (5-sided, point up) shape always means a school zone or school crossing. A round sign warns of a railroad crossing ahead, so option B confuses two different sign shapes."},"5":{"q":"Вы едете по сельскому двухполосному шоссе и замечаете на правой обочине круглый жёлтый знак с чёрным крестом 'X' и буквами 'RR', установленный задолго до того, как становятся видны какие-либо рельсы. О чём вас предупреждает этот знак?","options":["Вы достигли самих путей и должны остановить машину прямо на них","Впереди железнодорожный переезд, поэтому будьте готовы снизить скорость и следить за поездами","Вы въезжаете в школьную зону и должны снизить скорость из-за детей","Это зона запрета обгона, и вам нельзя обгонять другие машины здесь"],"explanation":"A round (circular) sign is the advance warning that a railroad crossing lies ahead, so you should slow down and watch for trains. The crossing itself is marked by the X-shaped Crossbuck (not this round sign), and the pentagon shape, not the circle, signals a school zone."},"6":{"q":"Вы едете по сельской дороге и приближаетесь к самим железнодорожным путям, где видите белый знак в форме буквы X со словами 'ЖЕЛЕЗНОДОРОЖНЫЙ ПЕРЕЕЗД'. На этом переезде нет знака 'стоп', нет шлагбаума и нет мигающих огней. Как следует поступить при виде этого знака?","options":["Каждый раз полностью останавливаться, потому что крестообразный знак юридически выполняет функцию знака 'стоп'","Игнорировать его, пока не виден поезд, потому что этот знак является лишь предупреждением, установленным заранее перед путями","Относиться к нему как к знаку 'уступи дорогу': снизить скорость, посмотреть в обе стороны и остановиться только если приближается поезд","Продолжать движение с обычной скоростью, потому что круглый предупреждающий знак ранее уже сообщил всё необходимое"],"explanation":"Крестообразный знак (в форме X) обозначает сам железнодорожный переезд и его следует воспринимать как знак 'уступи дорогу': снизить скорость, проверить наличие поездов и остановиться только если поезд приближается. Это не знак 'стоп' (A), и в отличие от круглого предупреждающего знака (B, D), крестообразный знак расположен у самих путей, а не перед ними."},"7":{"q":"Вы едете по незнакомой дороге и хотите узнать, с какой скоростью вам разрешено ехать по закону. Впереди вы видите знак в форме вертикального прямоугольника (он выше, чем шире). Судя только по его форме, к какому типу знаков он скорее всего относится?","options":["Указательный или информационный знак с направлениями и расстояниями до следующего города","Предупреждающий знак, сообщающий об опасности или изменении условий впереди","Знак строительной зоны или зоны дорожных работ, предупреждающий о дорожных бригадах впереди","Регулирующий знак, устанавливающий закон, который вы обязаны соблюдать, например ограничение скорости"],"explanation":"A vertical rectangle is a regulatory sign that tells you a law you must obey, such as the posted speed limit. A horizontal rectangle (option A) is the guide/information shape, and a diamond (option B) is the warning shape, so neither matches a vertical rectangle."},"8":{"q":"Вы едете по шоссе и ищете съезд к нужному вам городу. Впереди вы видите широкий знак в форме горизонтального прямоугольника (шире, чем выше). Основываясь только на его форме, какую информацию следует ожидать от этого знака?","options":["Направления и расстояния до мест, например, какой съезд выбрать и как далеко находится ваш город","Правило дорожного движения, которое вы обязаны соблюдать, например, установленное ограничение скорости","Предупреждение об опасности или условии впереди, например, о крутом повороте","Требование полностью остановиться перед продолжением движения"],"explanation":"A horizontal rectangle is a guide/information sign, giving directions and distances. A vertical rectangle (not horizontal) is the regulatory shape for laws like speed limits, warnings use a diamond, and only an octagon means stop."},"9":{"q":"Двигаясь ночью, вы поворачиваете на улицу, и фары освещают прямо перед вами красный знак с белыми буквами WRONG WAY (ДВИЖЕНИЕ ПО ВСТРЕЧНОЙ ПОЛОСЕ). Что этот знак предписывает вам сделать?","options":["Снизить скорость, потому что впереди опасность или необычное условие","Остановиться: вы движетесь навстречу встречному потоку и не должны продолжать движение в этом направлении","Продолжать движение, но уступать дорогу услугам для водителей, таким как заправка и еда, на следующем съезде","Двигаться с осторожностью, потому что вы въезжаете в зону строительства или дорожных работ"],"explanation":"WRONG WAY is a red sign, and red means stop, yield, or prohibited, so you must not continue in that direction because you are heading into oncoming traffic. Option A describes a yellow warning sign and option D describes an orange construction sign, neither of which is red."},"10":{"q":"Вы едете по незнакомому двухполосному шоссе в сумерках, когда фары выхватывают жёлтый знак в форме ромба с изогнутой стрелкой, поворачивающей вправо. Исходя из его цвета, о чём вам сообщает этот знак?","options":["Закон, который вы обязаны соблюдать: впереди требуется крутой поворот направо","За поворотом направо работает строительная бригада","Общее предупреждение: впереди поворот дороги, поэтому снизьте скорость","Указательный знак, направляющий вас к пункту назначения справа"],"explanation":"Yellow signs are general warning signs alerting you to a hazard or condition ahead, such as a curve, so you should reduce speed. The construction trap is wrong because work-zone warnings are orange, and the regulatory/guide traps are wrong because those use white/green, not yellow."},"11":{"q":"Вы едете по шоссе и видите впереди знак ромбовидной формы с оранжевым фоном и надписью \"ДОРОЖНЫЕ РАБОТЫ ВПЕРЕДИ\". О чём говорит вам оранжевый цвет этого знака?","options":["Он обозначает зону отдыха или живописную местность, к которой вы приближаетесь","Он указывает на услуги для водителей, такие как заправка, еда или ночлег впереди","Это общее предупреждение о повороте или подъёме на дороге","Вы въезжаете в зону строительства или дорожных работ"],"explanation":"Orange signs always indicate a construction or work zone, so you should slow down and be alert for workers and equipment. Brown is used for recreation/scenic areas and yellow is used for general warnings like curves or hills, which is why those options are wrong."},"12":{"q":"Вы едете по сельской автомагистрали в поисках съезда к городу назначения. Впереди вы видите большой зеленый знак с белыми буквами «Лаббок 45 / Амарилло 120» и стрелкой. О чем сообщает этот знак?","options":["Это указательный знак, который дает направления и расстояния до этих городов","Это предупреждающий знак, сообщающий, что впереди в этих городах опасные дорожные условия","Он обозначает услуги для водителей, такие как заправка и еда, доступные в этих городах","Это предписывающий знак, обязывающий вас съехать в сторону одного из этих городов"],"explanation":"Green signs are guide signs that indicate permitted movements, directions, and distances, so this sign is simply telling you the way and mileage to each city. Warning information would be on a yellow sign, and motorist-services signs are blue, so those choices place the wrong color and meaning together."},"13":{"q":"Вы едете по незнакомому шоссе, топлива мало и вы голодны, когда впереди замечаете знак на синем фоне с символами топливной колонки и вилки с ножом. О чём вам сообщает этот знак?","options":["Это указательный знак, показывающий направление и расстояние до следующего города","Он указывает на расположенные поблизости услуги для водителей, такие как заправка и питание","Он предупреждает об опасности или условии впереди у обочины","Он обозначает зону отдыха или живописное место у следующего съезда"],"explanation":"Blue signs indicate motorist services such as gas, food, lodging, and hospital, so the blue background with the fuel and dining symbols points you to those services. Green signs (not blue) handle directions and distances, and brown signs mark recreational or scenic areas."},"14":{"q":"Двигаясь по сельскому шоссе, вы видите впереди квадратный знак с коричневым фоном и белыми символами, указывающими на государственный парк и историческое поле битвы. О чём говорит вам этот знак?","options":["Вы приближаетесь к услугам для водителей, таким как заправка, еда и ночлег","Впереди строительная или рабочая зона, поэтому следует снизить скорость","Вы приближаетесь к зонам отдыха, культурным или живописным местам, таким как парки и исторические объекты","Вы обязаны соблюдать предписывающий закон, например указанное ограничение скорости"],"explanation":"Brown signs indicate recreation, cultural, or scenic areas like parks and historic sites, so option C is correct. Blue signs (not brown) mark motorist services such as gas and food, which makes that the trap answer."},"15":{"q":"Вы едете по незнакомому шоссе ночью. Впереди знак — вертикальный белый прямоугольник с чёрной надписью \"45\". О чём говорит этот знак?","options":["Это указательный знак, сообщающий расстояние до следующего съезда.","Это предупреждающий знак об опасности в 45 футах впереди.","Это знак строительной зоны, устанавливающий временный лимит в зоне работ.","Это регулирующий знак, устанавливающий максимально разрешённую скорость 45 миль/ч."],"explanation":"White signs with black lettering are regulatory signs, and a white rectangle with a number sets the maximum legal speed (45 mph). Guide/distance signs are green and warning signs are yellow, so those options place real facts on the wrong color of sign."},"16":{"q":"Проезжая через незнакомый район, вы приближаетесь к знаку в форме ромба с ярким флуоресцентным желто-зеленым фоном, на котором изображены двое идущих детей. О чем предупреждает этот знак?","options":["Впереди пешеходы, велосипедисты или школьный переход","Впереди строительная или рабочая зона","Впереди зона отдыха или живописная местность","Впереди обычный поворот или подъем"],"explanation":"Fluorescent yellow-green is reserved for pedestrian, bicycle, and school warnings, so this sign means people may be crossing ahead. Orange signals construction zones and brown marks recreation/scenic areas, so those colors would not appear on this warning."},"17":{"q":"Вы едете в сумерках к незнакомому перекрёстку. Знак перед вами настолько выцвел, что вы уже не можете прочитать на нём слово, но по-прежнему различаете его контур и цвет. Чтобы понять, что это знак STOP и что вы должны полностью остановиться, какую форму и цвет вам следует искать?","options":["Красный перевёрнутый (вершиной вниз) треугольник","Красный восьмиугольник (октагон)","Жёлтый ромб","Белый вертикальный прямоугольник"],"explanation":"A STOP sign is the only red, eight-sided octagon, so its shape and color identify it even when the word is unreadable. A red inverted triangle is a YIELD sign (give the right of way, not necessarily a full stop), which is the trap."},"18":{"q":"Вы выезжаете на оживлённое шоссе с разгонной полосы. В конце полосы вы видите знак в форме треугольника, направленного вершиной вниз, красно-белого цвета. Что этот знак требует от вас сделать?","options":["Полностью остановиться, так как это единственная форма знака, которая по закону означает «стоп»","Считать перекрёсток нерегулируемым со всех сторон, потому что светофор не работает","Снизить скорость и уступить дорогу транспорту на шоссе, останавливаясь только при необходимости","Не въезжать, потому что красно-белый знак всегда означает, что дорога для вас закрыта"],"explanation":"A red-and-white inverted (downward-pointing) triangle is a YIELD sign, which means give the right of way and slow or stop only if needed. The full-stop trap describes the red octagon STOP sign, and the 'do not enter' trap confuses YIELD with a prohibitory sign."},"19":{"q":"Вы ищете парковочный гараж в центре города и подъезжаете к пандусу, где видите красный знак с надписью 'ВЪЕЗД ЗАПРЕЩЁН' (DO NOT ENTER). Что требует от вас этот красный знак?","options":["Снизить скорость и проехать с осторожностью, так как красные знаки лишь предупреждают об опасности впереди","Уступить любому транспорту на пандусе, а затем въехать, если путь свободен","Полностью остановиться, а затем продолжить движение, проверив, нет ли встречных машин","Не въезжать на пандус; этот въезд закрыт для вашего направления движения"],"explanation":"DO NOT ENTER is a red sign meaning do not proceed, because that entrance is closed to your direction of travel. Yielding (B) or stopping then continuing (C) are wrong because the sign prohibits entry entirely rather than allowing you to proceed after caution."},"20":{"q":"Вы поворачиваете на улицу и видите прямоугольный знак с горизонтальной стрелкой, указывающей вправо, и надписью ONE WAY (одностороннее движение). Вы хотели поехать налево по этой улице. Что вы должны сделать?","options":["Не поворачивайте налево; двигайтесь только направо, в направлении, куда указывает стрелка","Поверните налево, но сначала уступите встречному транспорту, так как это улица общего пользования","Поворачивайте налево только если на углу нет также знака DO NOT ENTER (въезд запрещён)","Считайте это предупреждением и медленно поезжайте налево с осторожностью"],"explanation":"A ONE WAY sign means traffic may travel only in the direction the arrow points, so you must go right and cannot turn left onto that street. Turning left would send you against legal traffic flow, so the options allowing a left turn are wrong."},"21":{"q":"Вы едете ясным сухим днём и проезжаете белый прямоугольный знак с чёрным числом 65. Начинается лёгкий дождь, и дорога становится скользкой. Что этот знак говорит вам о вашей скорости в меняющуюся погоду?","options":["65 — это минимальная скорость, которую вы обязаны поддерживать независимо от дождя","65 — это максимальная разрешённая скорость для идеальных условий, поэтому теперь на мокрой дороге следует ехать медленнее","Белый прямоугольник — это только указательный знак, поэтому 65 лишь рекомендация и не обязателен к исполнению","Поскольку идёт дождь, ограничение автоматически повышается, чтобы дать вам больше места для остановки"],"explanation":"A SPEED LIMIT sign is a white rectangle with black numbers showing the maximum legal speed in ideal conditions, so in rain you must drive slower than the posted number. It is not a minimum, it is a regulatory (not guide) sign, and the limit never rises in bad weather."},"22":{"q":"Вы подъезжаете к перекрёстку и хотите выполнить разворот. Над светофором установлен белый квадратный знак, на котором изображена стрелка разворота внутри красного круга с красной диагональной чертой, перечёркивающей её. Что требует от вас этот знак?","options":["Он лишь предупреждает, что разворот здесь затруднён, поэтому вы можете развернуться, если это безопасно","Он разрешает разворот, но только при защищённой зелёной стрелке","Он запрещает разворот на этом перекрёстке, поэтому вы не должны разворачиваться","Он означает, что нужно уступить встречному транспорту перед завершением разворота"],"explanation":"A red circle with a slash is a regulatory 'No' sign, and a U-turn arrow inside it means U-turns are prohibited here. The trap answers treat a mandatory prohibition as a mere warning or a conditional/yield situation, but the red circle and slash means the movement is flatly illegal."},"23":{"q":"Вы едете ночью по незнакомой двухполосной дороге. Линия, нанесённая по центру дороги между вашей полосой и полосой слева от вас, жёлтая. Что этот цвет говорит вам о движении на полосе по другую сторону этой линии?","options":["Это улица с односторонним движением, поэтому встречного транспорта нет","Жёлтая линия лишь обозначает край проезжей части, а не полосу движения","Транспорт на той полосе движется в том же направлении, что и вы","Транспорт на той полосе движется в противоположном направлении, навстречу вам"],"explanation":"Жёлтые линии разделяют потоки, движущиеся в противоположных направлениях, поэтому полоса за жёлтой осевой линией предназначена для встречного движения. Белые линии (а не жёлтые) разделяют потоки одного направления и обозначают край дороги, поэтому варианты про то же направление и край дороги неверны."},"24":{"q":"Вы едете по широкой автомагистрали и приближаетесь к длинной сплошной белой линии, идущей параллельно вашей полосе слева, при этом за ней движется ещё поток транспорта в том же направлении. Что эта белая линия говорит вам о транспорте рядом с вами?","options":["Транспорт рядом с вами движется в том же направлении, что и вы, и эта линия не рекомендует перестраиваться через неё.","Транспорт рядом с вами движется в противоположном направлении, поэтому пересечение линии выведет вас на встречные машины.","Линия обозначает край дороги, поэтому за ней вообще нет полосы движения.","Линия означает, что обгон разрешён только тогда, когда путь впереди свободен, как и прерывистая жёлтая линия."],"explanation":"White lines separate lanes of traffic moving in the SAME direction, and a solid white line discourages crossing or changing lanes. Yellow lines (B) separate opposite directions, white edge lines mark the pavement edge but here it sits between two same-direction lanes (C), and broken-line passing rules apply to yellow lines, not this solid white one (D)."},"25":{"q":"Вы едете по двухполосному шоссе и хотите обогнать медленный трактор впереди. Приближаясь, вы замечаете, что разметка с вашей стороны от центра — это сплошная жёлтая линия, а с противоположной стороны — прерывистая жёлтая линия. Что это говорит вам об обгоне?","options":["Вы можете обгонять, потому что прерывистая жёлтая линия с другой стороны действует для обоих направлений движения.","Вы не можете обгонять, потому что сплошная жёлтая линия с вашей стороны запрещает обгон.","Вы можете обгонять только на скорости ниже установленного ограничения, так как разметка носит рекомендательный характер.","Вы должны полностью остановиться, прежде чем пересекать любую жёлтую линию."],"explanation":"A solid yellow line on your side of the road means passing is prohibited for you, even if the opposite side has a broken (dashed) yellow line that permits passing for oncoming traffic. The broken line only allows passing for drivers on that side, and yellow markings are regulatory, not merely advisory."},"26":{"q":"Вы едете по двухполосному шоссе и хотите обогнать медленный трактор впереди. С вашей стороны от центра дорога размечена прерывистой (пунктирной) жёлтой линией, встречная полоса пуста, и впереди хорошо просматривается дальний участок дороги. Что эта разметка говорит вам об обгоне?","options":["Жёлтую линию нельзя пересекать ни при каких обстоятельствах, поэтому оставайтесь позади трактора","Пунктирная линия обозначает край проезжей части, поэтому не смещайтесь влево","Обгон разрешён, и вы можете выехать на встречную полосу для обгона, когда путь свободен","Вы можете свободно перестраиваться, потому что пунктирные линии всегда разделяют попутные потоки"],"explanation":"Прерывистая (пунктирная) жёлтая линия с вашей стороны означает, что обгон разрешён, когда впереди свободно, поэтому вы можете пересечь её, чтобы обогнать трактор. Вариант D — ловушка: пунктирные белые линии разделяют попутный транспорт, но жёлтые линии всегда разделяют встречные потоки, поэтому здесь это правило применено неверно."},"27":{"q":"Вы едете по двухполосной дороге, по центру которой проходит двойная сплошная жёлтая линия. Перед вами медленный трактор, дорога свободна и видимость хорошая. Слева от вас подъездная дорожка ведёт к дому, который вы хотите посетить. Что двойная сплошная жёлтая линия позволяет вам сделать здесь?","options":["Обогнать трактор, так как дорога свободна и видимость хорошая","Обогнать трактор, потому что двойная жёлтая линия ограничивает только встречное движение","Ничто не требует ждать; вы можете свободно менять полосу, как при прерывистой белой линии","Пересечь линию только для поворота налево на подъездную дорожку, но не для обгона трактора"],"explanation":"Двойная сплошная жёлтая линия означает запрет обгона в обоих направлениях, поэтому вы не можете обогнать трактор даже при хорошей видимости; пересекать её можно только для поворота (например, на подъездную дорожку). Варианты про свободную дорогу и 'только встречное движение' — ловушки, потому что запрет действует в обоих направлениях независимо от видимости."},"28":{"q":"Вы едете по трёхполосному шоссе, где весь поток движется в одном направлении. Приближаясь к съезду, вы замечаете, что линия разметки справа от вас изменилась с прерывистой белой на одну сплошную белую линию. Что эта сплошная белая линия говорит вам о смене полосы здесь?","options":["Она не рекомендует пересекать линию для смены полосы в этом месте","Она позволяет вам свободно менять полосу всякий раз, когда путь свободен","Она разделяет потоки, движущиеся в противоположных направлениях","Она означает, что обгон разрешён только при отсутствии встречного транспорта"],"explanation":"A solid white line discourages lane changes, so you should stay in your lane rather than cross it near the exit, whereas a broken white line is what allows lane changes when clear (option B). White lines separate same-direction traffic, so the opposite-direction and oncoming-traffic options describe yellow-line rules, not this marking."},"29":{"q":"Вы подъезжаете к красному сигналу светофора на перекрёстке и хотите повернуть направо. Нет знака, запрещающего поворот на красный, а пешеходный переход и поперечное движение свободны. Каким будет правильное действие?","options":["Снизить скорость, но проехать на красный, не останавливаясь, раз путь свободен","Сначала полностью остановиться за стоп-линией, затем повернуть направо, когда это безопасно","Дождаться зелёной стрелки, прежде чем вам разрешат повернуть направо","Рассматривать красный сигнал как «уступи дорогу» и выполнить поворот без полной остановки"],"explanation":"Постоянный красный сигнал требует полной остановки за стоп-линией, а поворот направо на красный разрешён только после такой полной остановки, если нет запрещающего знака. Проезд без остановки (A) или поворот без остановки (D) пропускают обязательную полную остановку, а зелёная стрелка (C) для разрешённого поворота направо на красный не требуется."},"30":{"q":"Вы приближаетесь к перекрестку на разрешенной скорости, когда сигнал светофора перед вами меняется с зеленого на постоянный ЖЕЛТЫЙ. Вы все еще находитесь на некотором расстоянии, и у вас достаточно места, чтобы плавно затормозить. Что означает этот сигнал и что вам следует делать?","options":["Свет вот-вот снова станет зеленым; ускорьтесь, чтобы проехать перекресток до его смены","Это предупреждение об опасности впереди, например о повороте или слиянии полос; снизьте скорость, но вы можете продолжать движение","Свет вот-вот станет красным; остановитесь перед линией, если можете сделать это безопасно","Считайте перекресток четырехсторонним стопом, полностью остановитесь, затем продолжайте движение, когда наступит ваша очередь"],"explanation":"A steady yellow light warns that the signal is about to turn red, so you must stop before the line if you can do so safely, which you can from this distance. Option D describes a dark/non-working signal, and option B confuses the signal with a yellow warning sign, not a traffic light."},"31":{"q":"Вы подъезжаете к перекрестку на постоянный ЗЕЛЕНЫЙ сигнал и включаете указатель левого поворота. Встречные машины приближаются, а пешеход выходит на пешеходный переход, который вам нужно пересечь. Что вы должны сделать?","options":["Сразу начать движение, так как зеленый сигнал дает вам защищенное право на поворот.","Полностью остановиться за линией и ждать зеленой стрелки перед поворотом.","Быстро повернуть перед встречными машинами, потому что они обязаны уступить поворачивающему автомобилю.","Подождать, уступив пешеходу и встречному транспорту, а затем завершить поворот, когда путь будет свободен."],"explanation":"A steady green means go only if the way is clear; when turning you must yield to pedestrians and oncoming traffic, so you wait until both are clear before turning. A plain green is not a protected turn (only a green arrow is), and oncoming traffic does not yield to you, so the other answers are wrong."},"32":{"q":"Ночью вы подъезжаете к перекрёстку, и подвесной светофор в вашем направлении мигает красным. Другого транспорта не видно. Что вы должны сделать?","options":["Полностью остановиться, затем продолжить движение, когда путь свободен, действуя как у знака «СТОП»","Снизить скорость и проехать с осторожностью, не останавливаясь","Продолжить движение, поскольку мигающий сигнал означает, что светофор не действует","Остановиться и ждать, пока загорится постоянный зелёный, прежде чем ехать"],"explanation":"A flashing red light must be treated exactly like a STOP sign: come to a full stop, then proceed when it is safe. Slowing without stopping (B) is the rule for a flashing yellow light, not a flashing red one."},"33":{"q":"Вы приближаетесь к перекрестку ночью, и обращенный к вам светофор показывает мигающий желтый свет. Что вам следует сделать?","options":["Полностью остановиться за линией, затем продолжить движение, когда путь свободен, считая это знаком «стоп»","Снизить скорость и проехать перекресток с осторожностью","Полностью остановиться и оставаться на месте, пока не загорится зеленый свет","Считать перекресток четырехсторонней остановкой и уступить водителю справа"],"explanation":"A flashing yellow light means slow down and proceed with caution, so option B is correct. Option A describes a flashing RED light (treated as a stop sign), and option D describes a dark or non-working signal, which are the wrong responses for a flashing yellow."},"34":{"q":"Вы остановились в полосе для левого поворота на перекрёстке. Основной сигнал для вашего направления горит постоянным красным, но отдельный сигнал поворота рядом с ним показывает постоянную ЗЕЛЁНУЮ СТРЕЛКУ, направленную влево. Что это означает для вашего левого поворота?","options":["Вы должны ждать, потому что постоянный красный сигнал управляет всеми движениями на перекрёстке","Вы можете повернуть налево только уступив встречному транспорту, так как зелёный всегда означает уступить встречным машинам","У вас защищённый поворот, и вы можете повернуть налево в направлении стрелки","Вы должны считать перекрёсток нерегулируемым с остановкой всех направлений и проезжать в порядке очереди"],"explanation":"A green arrow signals a protected turn in the direction it points, so you may turn left with the right of way even though the main signal is red. Option B describes a steady green ball (yield to oncoming traffic), not a green arrow, and option A wrongly lets the red ball override the dedicated turn arrow."},"35":{"q":"Вы остановились в полосе для поворота налево на перекрёстке. Отдельный сигнал для поворота налево показывает постоянную красную стрелку, направленную влево, а сигнал для движущихся прямо транспортных средств зелёный. Что вам следует сделать?","options":["Повернуть налево, потому что зелёный свет для полос прямого движения даёт вам преимущество","Повернуть налево после полной остановки, как при повороте направо на красный","Считать красную стрелку мигающей жёлтой и повернуть налево с осторожностью","Оставаться на месте и ждать, потому что красная стрелка означает, что поворот налево в этом направлении запрещён"],"explanation":"A red arrow means no turn is permitted in the direction the arrow points, so you must stay stopped until the arrow changes. The green light for the through lanes does not apply to your protected turn, and a red arrow does not allow a turn after stopping the way a steady red ball can."},"36":{"q":"Вы подъезжаете к оживлённому перекрёстку с четырьмя направлениями во время отключения электричества, и светофор, который обычно им управляет, полностью погас и не показывает никаких сигналов. Поблизости нет ни полицейских, ни временных знаков. Как вам следует действовать?","options":["Рассматривать перекрёсток как обязательную остановку со всех сторон: полностью остановиться и уступать дорогу по обычным правилам приоритета.","Снизить скорость и проехать с осторожностью без остановки, поскольку погасший светофор работает как мигающий жёлтый сигнал.","Проехать на обычной скорости, потому что неработающий светофор означает, что перекрёсток не имеет активного регулирования.","Останавливаться, только если есть поперечное движение, а затем ехать раньше водителей, прибывших после вас."],"explanation":"A dark or non-working signal must be treated as an all-way STOP, so you stop fully and follow normal right-of-way rules. Option B is wrong because a dark signal is not the same as a flashing yellow (slow and proceed with caution); a dead signal requires a complete stop from every direction."},"37":{"q":"Вы едете по шоссе и видите впереди два предупреждающих знака в форме ромба. Первый ярко-жёлтый с изображением изгибающейся дороги, а второй ярко-оранжевый с изображением рабочего с лопатой. Что именно сообщает вам оранжевый цвет второго знака?","options":["Впереди обычная опасность — поворот или подъём, то же самое, что и жёлтый знак","Вы приближаетесь к зоне строительства или дорожных работ","Впереди пешеходный или школьный переход","Вы должны остановиться, потому что дорога закрыта"],"explanation":"Orange signs indicate a construction or work zone, distinguishing them from standard yellow general-warning signs (curve, hill, merge). Option A confuses orange with the yellow general-warning color, and pedestrian/school warnings use fluorescent yellow-green, not orange."},"38":{"q":"Вы едете по незнакомой двухполосной дороге в сумерках. Центральная разметка между вашей полосой и полосой слева от вас представляет собой сплошную ЖЕЛТУЮ линию. Что этот цвет говорит вам о движении на полосе слева?","options":["Это полоса для поворота, которой может пользоваться транспорт с обоих направлений","Это мощёная обочина, поэтому по ней не движется сквозной транспорт","По ней движется транспорт в направлении, противоположном вашему","По ней движется транспорт в том же направлении, что и вы"],"explanation":"Yellow lines separate traffic moving in opposite directions, so the yellow center line means the lane to your left carries oncoming traffic. White lines (option D) would indicate traffic moving in the same direction, which is the trap here."},"39":{"q":"Проезжая в сумерках через незнакомый город, вы приближаетесь к придорожному знаку, который хорошо видно, но слова на нём пока невозможно прочитать. Это высокий вертикальный прямоугольник с простым белым фоном и чёрными буквами. Ещё до того, как вы сможете прочитать его, что форма и цвет знака говорят о его назначении?","options":["Это указательный знак, дающий направления, расстояния или информацию об услугах впереди","Это предупреждающий знак, сообщающий об опасности или изменении условий впереди","Это знак дорожных работ, обозначающий активную рабочую зону","Это регулирующий знак, устанавливающий закон, который вы обязаны соблюдать"],"explanation":"A vertical rectangle that is white with black lettering is a regulatory sign, meaning it states a law (such as a speed limit) that you must obey. Guide signs are green or horizontal rectangles, warning signs are yellow diamonds, and construction signs are orange, so those choices misread the white-and-black vertical rectangle."}},"learn-road-signs":{"0":{"q":"Какую форму имеет знак СТОП?","options":["Восьмиугольник (8 сторон)","Ромб","Круг","Вертикальный прямоугольник"],"explanation":"A STOP sign is the only octagonal (8-sided) sign and requires a full stop."},"1":{"q":"Что означает знак в форме перевёрнутого треугольника?","options":["Стоп","Уступи дорогу","Обгон запрещён","Школьная зона"],"explanation":"An inverted triangle means YIELD, so give the right of way and slow or stop if needed."},"2":{"q":"Что означает вымпельный знак (горизонтальный треугольник с левой стороны дороги)?","options":["Впереди школьная зона","Полная остановка","Зона запрета обгона","Железнодорожный переезд"],"explanation":"A pennant, a horizontal triangle placed on the left side of the road, marks a No Passing Zone."},"3":{"q":"Что означает знак в форме ромба?","options":["Вы должны полностью остановиться","Вы выезжаете на улицу с односторонним движением","Вы достигли ограничения скорости","Впереди опасность или особое условие"],"explanation":"A diamond-shaped sign is a warning sign that indicates a hazard or condition ahead."},"4":{"q":"Что обозначает знак в форме пятиугольника (5 сторон, вершина вверх)?","options":["Школьную зону или школьный переход","Железнодорожный переезд","Зону запрета обгона","Перекресток со знаком стоп"],"explanation":"A pentagon (5 sides, point up) marks a school zone or school crossing."},"5":{"q":"О чём предупреждает круглый дорожный знак?","options":["О школьной зоне впереди","О железнодорожном переезде впереди","О зоне запрета обгона","О зоне дорожных работ"],"explanation":"A round (circular) sign is an advance warning that a railroad crossing is ahead."},"6":{"q":"Что означает знак-крестовина (в форме X)?","options":["Полная остановка","Впереди дорожные работы","Железнодорожный переезд; уступите дорогу","Впереди школьная зона"],"explanation":"A crossbuck (X shape) marks the railroad crossing itself and should be treated like a yield."},"7":{"q":"Что означает знак в форме вертикального прямоугольника?","options":["Предупреждение об опасности впереди","Пешеходный переход у школы","Железнодорожный переезд впереди","Закон, который вы обязаны соблюдать"],"explanation":"A vertical rectangle is a regulatory sign indicating a law you must obey, such as a speed limit."},"8":{"q":"Какой тип знака представляет собой горизонтальный прямоугольник?","options":["Указательный или информационный знак с направлениями и расстояниями","Знак \"стоп\"","Предупреждающий знак об опасности впереди","Знак школьной зоны"],"explanation":"A horizontal rectangle is a guide or information sign that gives directions and distances."},"9":{"q":"Какая форма знака используется только для STOP?","options":["Ромб","Восьмиугольник","Треугольник","Прямоугольник"],"explanation":"The octagon (8 sides) is the only sign shape reserved exclusively for STOP."},"10":{"q":"Что означает красный цвет на дорожном знаке?","options":["Зона строительства","Услуги для водителей","Стоп, уступи или запрещено","Общее предупреждение"],"explanation":"Red is used on STOP, YIELD, DO NOT ENTER, and WRONG WAY signs to mean stop, yield, or prohibited."},"11":{"q":"Что означает желтый дорожный знак?","options":["Впереди зона строительства","Стоп или въезд запрещен","Услуги для водителей рядом","Общее предупреждение впереди"],"explanation":"Yellow signals a general warning, such as a curve, hill, merge, or signal ahead."},"12":{"q":"Что означает оранжевый дорожный знак?","options":["Зона строительства или дорожных работ","Стоп или уступи дорогу","Услуги для водителей","Зона отдыха"],"explanation":"Orange signs warn of construction or a work zone ahead."},"13":{"q":"Что означает зелёный дорожный знак?","options":["Стоп или уступи дорогу","Указатель и направления","Зона дорожных работ","Общее предупреждение"],"explanation":"Green signs give guide information like directions and distances."},"14":{"q":"Что означает синий дорожный знак?","options":["Впереди зона строительства","Стоп или уступите дорогу","Услуги для водителей: заправка и еда","Зоны отдыха"],"explanation":"Blue signs show motorist services such as gas, food, lodging, and hospital."},"15":{"q":"Какой цвет дорожного знака обозначает зоны отдыха, культурные или живописные места?","options":["Синий","Зелёный","Жёлтый","Коричневый"],"explanation":"Brown signs mark recreation, cultural, or scenic areas."},"16":{"q":"Что означает белый знак с чёрными буквами?","options":["Предписывающий, например ограничение скорости","Строительство или зона работ","Зона отдыха или живописное место","Общее предупреждение впереди"],"explanation":"A white sign with black letters is regulatory, such as a speed limit or lane use sign."},"17":{"q":"О чем предупреждает флуоресцентный желто-зеленый знак?","options":["О зонах дорожных работ","О пешеходах, велосипедистах и школьных зонах","Об услугах для водителей, таких как заправка и еда","О зонах отдыха и живописных местах"],"explanation":"Fluorescent yellow-green signs warn of pedestrian, bicycle, and school crossings."},"18":{"q":"Какого цвета знак \"WRONG WAY\" (Неверное направление)?","options":["Жёлтый","Зелёный","Красный","Синий"],"explanation":"A WRONG WAY sign is red, signaling you must not proceed."},"19":{"q":"Какого цвета знак, предупреждающий о слиянии полос?","options":["Оранжевый","Синий","Зеленый","Желтый"],"explanation":"Yellow is used for general warning signs, including merge signs."},"20":{"q":"Какую форму имеет знак STOP?","options":["Восьмиугольник (8 сторон)","Ромб","Круг","Квадрат"],"explanation":"A STOP sign is a red octagon, the only sign with that shape."},"21":{"q":"Какого цвета знак «УСТУПИТЕ ДОРОГУ»?","options":["Жёлтый и чёрный","Красный и белый","Зелёный и белый","Синий и белый"],"explanation":"A YIELD sign is a red-and-white inverted triangle."},"22":{"q":"Какого цвета знаки ВЪЕЗД ЗАПРЕЩЕН и ДВИЖЕНИЕ В НЕПРАВИЛЬНОМ НАПРАВЛЕНИИ?","options":["Желтого","Зеленого","Красного","Синего"],"explanation":"DO NOT ENTER and WRONG WAY signs are red and mean do not proceed."},"23":{"q":"Что означает знак ОДНОСТОРОННЕЕ ДВИЖЕНИЕ (ONE WAY)?","options":["Полностью остановиться перед поворотом","Дорога впереди закрыта","Здесь разрешён обгон","Двигаться только в направлении стрелки"],"explanation":"A ONE WAY sign means you may travel only in the direction the arrow points."},"24":{"q":"Что показывает знак ОГРАНИЧЕНИЕ СКОРОСТИ?","options":["Максимальную разрешённую скорость в идеальных условиях","Минимальную скорость, ниже которой нельзя ехать","Рекомендуемую скорость для крутых поворотов","Скорость только для ночной езды"],"explanation":"A SPEED LIMIT sign is a white rectangle with black numbers showing the maximum legal speed in ideal conditions."},"25":{"q":"Какой дизайн используют запрещающие знаки «Нельзя»?","options":["Жёлтый ромб","Красный круг с косой чертой","Зелёный прямоугольник","Синий квадрат"],"explanation":"Regulatory \"No\" signs, such as no U-turn or no left turn, use a red circle with a slash."},"26":{"q":"Что означает число на знаке ОГРАНИЧЕНИЕ СКОРОСТИ?","options":["Минимальную разрешённую скорость","Среднюю скорость потока","Максимальную разрешённую скорость","Рекомендуемую скорость для грузовиков"],"explanation":"The number on a SPEED LIMIT sign is the maximum legal speed under ideal conditions."},"27":{"q":"Что показывает указанное ограничение скорости?","options":["Самую низкую скорость, с которой можно ехать","Скорость при любой погоде","Скорость только ночью","Максимум для идеальных условий"],"explanation":"The posted speed limit is the maximum for ideal conditions, so drive slower in poor conditions."},"28":{"q":"Что разделяют жёлтые линии на дороге?","options":["Транспорт, движущийся в противоположных направлениях","Транспорт, движущийся в одном направлении","Парковочные места","Велосипедные дорожки"],"explanation":"Yellow lines separate traffic moving in opposite directions."},"29":{"q":"Что показывают белые линии на дороге?","options":["Впереди школьная зона","Движение транспорта в одном направлении","Движение транспорта в противоположных направлениях","Зону запрета обгона"],"explanation":"White lines separate lanes of traffic moving in the same direction and mark the road edge."},"30":{"q":"Что означает сплошная жёлтая линия с вашей стороны дороги?","options":["Обгон разрешён","Дорога заканчивается впереди","Обгон запрещён","Улица с односторонним движением"],"explanation":"A solid yellow line on your side means you may not pass."},"31":{"q":"Что означает прерывистая (пунктирная) жёлтая линия?","options":["Эту линию никогда нельзя пересекать","Обгон запрещён в обоих направлениях","Она обозначает край дороги","Обгон разрешён, когда путь свободен"],"explanation":"A broken (dashed) yellow line means passing is allowed when the way is clear."},"32":{"q":"Что означает двойная сплошная жёлтая линия?","options":["Обгон запрещён в обоих направлениях","Обгон разрешён в обе стороны","Полосы идут в одном направлении","Впереди край дороги"],"explanation":"A double solid yellow line means no passing in either direction; do not cross except to turn."},"33":{"q":"Что означает сплошная белая линия на дороге?","options":["Обгон разрешён","Смена полосы не рекомендуется","Движение в противоположных направлениях","Вы должны остановиться"],"explanation":"A solid white line discourages lane changes."},"34":{"q":"Что разрешает прерывистая белая линия?","options":["Полностью остановиться","Обгонять встречный транспорт","Менять полосу движения","Никогда её не пересекать"],"explanation":"A broken white line separates lanes going the same way and allows lane changes."},"35":{"q":"Что обозначают белые линии на дорожном покрытии?","options":["Железнодорожный переезд","Школьную зону впереди","Движение в противоположных направлениях","Край дороги"],"explanation":"White lines mark the edge of the road and separate traffic moving in the same direction."},"36":{"q":"Какого цвета линии, разделяющие полосы движения в одном направлении?","options":["Белые","Жёлтые","Красные","Синие"],"explanation":"White lines separate traffic moving in the same direction, while yellow lines separate opposite directions."},"37":{"q":"Что нужно делать на постоянном красном сигнале светофора?","options":["Снизить скорость и продолжить движение","Полностью остановиться за линией","Ускориться, чтобы проехать перекресток","Посигналить и проехать"],"explanation":"A steady red light means you must stop completely behind the line and remain stopped."},"38":{"q":"Когда можно повернуть направо на постоянный красный свет?","options":["Никогда, ни при каких условиях","Без предварительной остановки","После полной остановки, если знак этого не запрещает","Только при наличии стрелки"],"explanation":"At a steady red light you may turn right after coming to a full stop, unless a sign prohibits it."},"39":{"q":"Что означает постоянный желтый сигнал светофора?","options":["Ускориться, чтобы успеть до красного","Светофор сломан; можно ехать в любое время","Остановиться, только если сзади есть машина","Сигнал скоро станет красным; остановитесь, если это безопасно"],"explanation":"A steady yellow light warns that the signal is about to turn red, so stop if you can do so safely."},"40":{"q":"Что означает постоянный ЗЕЛЕНЫЙ сигнал светофора?","options":["Двигайтесь, если путь свободен","Полностью остановитесь","Сбавьте скорость и приготовьтесь остановиться","Только защищенный поворот"],"explanation":"A steady green light means you may go if the way is clear."},"41":{"q":"На горящем зеленом светофоре кому вы должны уступить при повороте?","options":["Никому","Пешеходам и встречному транспорту","Только припаркованным машинам","Транспорту позади вас"],"explanation":"At a steady green light, you must yield to pedestrians and oncoming traffic when turning."},"42":{"q":"Как следует воспринимать мигающий красный сигнал светофора?","options":["Как зелёный сигнал","Как знак уступи дорогу","Как знак стоп","Как жёлтый сигнал"],"explanation":"A flashing red light means you must stop completely, just like at a stop sign."},"43":{"q":"Что означает мигающий желтый сигнал светофора?","options":["Полностью остановиться","Ускориться, чтобы проехать перекресток","Светофор сломан, не двигаться","Снизить скорость и проехать с осторожностью"],"explanation":"A flashing yellow light means slow down and proceed with caution."},"44":{"q":"Что означает зелёная стрелка светофора?","options":["Защищённый поворот в направлении стрелки","Поворот в этом направлении запрещён","Остановиться перед поворотом","Снизить скорость и проявить осторожность"],"explanation":"A green arrow means a protected turn in the direction the arrow points."},"45":{"q":"Что означает красная стрелка светофора?","options":["Быстро поверните в этом направлении","Поворот в этом направлении запрещён","Уступите дорогу перед поворотом","Поворачивайте только после остановки"],"explanation":"A red arrow means you may not turn in that direction."},"46":{"q":"Как следует относиться к погасшему или неработающему светофору?","options":["Проехать без остановки","Считать его знаком \"уступи дорогу\"","Считать его перекрёстком со знаком \"стоп\" во всех направлениях","Ускориться, чтобы быстрее проехать перекрёсток"],"explanation":"A dark or non-working signal should be treated as an all-way stop."},"47":{"q":"Какую форму имеет знак STOP («СТОП»)?","options":["Ромб","Круг","Треугольник","Восьмиугольник"],"explanation":"A STOP sign is the only octagonal (8-sided) sign, so its shape alone tells you to stop."},"48":{"q":"Какого цвета знак ограничения скорости?","options":["Белый с черными буквами","Желтый с черными буквами","Красный с белыми буквами","Зеленый с белыми буквами"],"explanation":"A speed limit sign is white with black lettering because it is regulatory, not a warning."},"49":{"q":"Какого цвета знак живописной зоны?","options":["Синий","Коричневый","Зелёный","Жёлтый"],"explanation":"Brown signs mark recreation, cultural, and scenic areas."},"50":{"q":"Какого цвета знаки услуг для водителей, например больницы и питание?","options":["Красный","Зелёный","Синий","Коричневый"],"explanation":"Blue signs show motorist services such as gas, food, lodging, and hospitals."},"51":{"q":"Какого цвета знак зоны дорожных работ или строительства?","options":["Жёлтый","Зелёный","Синий","Оранжевый"],"explanation":"Work zone and construction signs are orange, which sets them apart from yellow general-warning signs."},"52":{"q":"Какого цвета предупреждающий знак о школьном переходе?","options":["Флуоресцентный жёлто-зелёный","Синий","Коричневый","Оранжевый"],"explanation":"Fluorescent yellow-green is the color for pedestrian, bicycle, and school warnings."},"53":{"q":"Какой цвет общий для знаков STOP (СТОП), YIELD (УСТУПИ ДОРОГУ), DO NOT ENTER (ВЪЕЗД ЗАПРЕЩЕН) и WRONG WAY (ДВИЖЕНИЕ ЗАПРЕЩЕНО)?","options":["Желтый","Красный","Зеленый","Синий"],"explanation":"Red is the color shared by STOP, YIELD, DO NOT ENTER, and WRONG WAY signs."},"54":{"q":"Когда можно пересекать двойную сплошную желтую линию?","options":["Чтобы обогнать другую машину","В любое время, когда свободно","Только для поворота","Никогда ни по какой причине"],"explanation":"A double solid yellow line may be crossed only to turn, not to pass."},"55":{"q":"Что означает зеленая стрелка светофора?","options":["Остановитесь и ждите транспорт","Снизьте скорость и уступите дорогу","Поворот запрещен","Защищенный поворот, встречный транспорт остановлен"],"explanation":"A green arrow gives a protected turn because oncoming traffic is stopped during that movement."},"56":{"q":"Что означает прерывистая желтая линия на вашей стороне дороги?","options":["Обгон разрешен, когда дорога впереди свободна","Обгон никогда не разрешен","Вы должны остановиться","Дорога с односторонним движением"],"explanation":"A broken yellow line on your side means you may pass when the road ahead is clear."},"57":{"q":"Какую форму имеет предупреждающий знак о приближении к железнодорожному переезду?","options":["Ромб","Круг","Восьмиугольник","Крестовина (форма X)"],"explanation":"The railroad advance-warning sign is round, while the sign at the crossing itself is a crossbuck."},"58":{"q":"Что вы должны сделать на мигающем красном светофоре?","options":["Снизить скорость и продолжить движение","Ускориться, чтобы проехать","Полностью остановиться","Проигнорировать, если путь свободен"],"explanation":"A flashing red light means come to a complete stop, just like at a STOP sign."},"59":{"q":"Что означает красный круг с косой чертой поверх стрелки поворота налево?","options":["Только поворот налево","Левая полоса заканчивается","Поворот налево впереди","Поворот налево запрещён"],"explanation":"A red circle and slash over a left-turn arrow means no left turn is allowed."}},"rules-of-the-road":{"0":{"q":"Вы едете по сельскому шоссе в Техасе с установленным ограничением 70 миль/ч. Внезапно накрывает густой туман, и вы едва видите на две длины машины впереди. Согласно закону Техаса, с какой скоростью вам разрешено ехать?","options":["Медленнее 70 миль/ч — со скоростью, разумной и безопасной для тумана, потому что установленное ограничение является максимумом только для идеальных условий","До 70 миль/ч, потому что это официально установленный лимит, и вы всегда можете ехать с установленной скоростью","Ровно 50 миль/ч, потому что закон Техаса требует снижать скорость на 20 миль/ч при плохой видимости","До 75 миль/ч, поскольку на сельских автострадах Техаса разрешено 75 миль/ч независимо от условий"],"explanation":"Согласно базовому закону о скорости (prima facie) в Техасе вы никогда не должны ехать быстрее, чем это разумно и безопасно для имеющихся условий, поэтому в густом тумане нужно заметно снизить скорость ниже 70 миль/ч. Езда на полной установленной скорости (B) — это ловушка: обозначенный лимит — это максимум для хороших условий, а не гарантия, а цифры 20 миль/ч и 75 миль/ч (C, D) — это реальные правила, применённые в неподходящем контексте."},"1":{"q":"Вы сворачиваете с обозначенного шоссе на жилую улицу внутри городского района. На всём протяжении квартала вы не видите ни одного знака ограничения скорости. Какую скорость следует считать законным максимумом здесь?","options":["20 миль/ч, потому что это значение по умолчанию в любой зоне, где есть жилые дома","30 миль/ч — обычное ограничение по умолчанию для городского района, когда знак не установлен","70 миль/ч, поскольку это значение по умолчанию для шоссе, и никакой другой знак его не отменяет","Ограничения нет, пока вы едете безопасно, потому что знак отсутствует"],"explanation":"Where no sign is posted, the common default speed limit in an urban district is 30 mph, so you should treat 30 mph as the legal maximum. The 20 mph figure is the typical reduced limit for active school zones, not residential streets generally, and 70 mph is the daytime default for numbered highways, not a city street."},"2":{"q":"Вы едете по нумерованной автомагистрали в Техасе среди дня. Условия ясные и сухие, но вы уже несколько миль не видели ни одного знака ограничения скорости. Какова максимальная скорость, с которой вы можете законно ехать согласно основному закону о скорости?","options":["75 миль/ч, потому что это ограничение на всех сельских автомагистралях Техаса","30 миль/ч, потому что это ограничение по умолчанию там, где нет знаков","70 миль/ч — ограничение по умолчанию в дневное время на нумерованных автомагистралях","85 миль/ч — самая высокая разрешённая скорость где-либо в Техасе"],"explanation":"Where no sign is posted, the default daytime limit on numbered highways in Texas is 70 mph. The 30 mph trap is the default for urban districts, not numbered highways, and 75 and 85 mph apply only to specific posted Interstates and tollways, not as a general default."},"3":{"q":"Вы едете по сельской автомагистрали (Interstate) в Техасе, где установлено ограничение 75 миль/ч. Через несколько миль вы переезжаете на отдельную платную дорогу (tollway) Техаса, и теперь на знаках указано 85 миль/ч. Движение слабое, покрытие сухое, видимость хорошая. Какова максимальная скорость, с которой вы можете законно ехать на этом участке платной дороги?","options":["70 миль/ч, потому что это общештатный дневной максимум для пронумерованных шоссе","75 миль/ч, потому что это было ограничение на автомагистрали, которую вы только что покинули","80 миль/ч, потому что закон Техаса ограничивает все дороги до 80 миль/ч","85 миль/ч, потому что именно эта скорость указана на знаках этой конкретной платной дороги"],"explanation":"На дорогах Техаса вы можете законно ехать вплоть до установленного на знаке ограничения скорости, когда условия безопасны, а на некоторых отдельных платных дорогах Техаса установлено ограничение до 80–85 миль/ч. Варианты 70 и 75 миль/ч являются реальными ограничениями для других дорог, но не отменяют более высокий показатель на знаке этой платной дороги."},"4":{"q":"Вы проезжаете мимо начальной школы в 7:45 утра. Установленный знак школьной зоны гласит «20 миль/ч, КОГДА МИГАЕТ», и жёлтые маячки на нём мигают. С какой скоростью здесь правильно ехать?","options":["20 миль/ч, потому что вы обязаны соблюдать установленное сниженное ограничение школьной зоны, пока мигают огни","30 миль/ч, стандартное городское ограничение, поскольку ограничение школьной зоны действует только в крайней полосе у обочины","Любую безопасную скорость ниже обычного ограничения, потому что мигающие маячки — это лишь предупреждение, а не закон","70 миль/ч, дневное ограничение на шоссе, поскольку сниженное ограничение действует только после того, как дети выйдут из здания"],"explanation":"When school-zone lights are flashing (or children are present), you must obey the posted reduced limit, typically 20 mph. The 30 mph default applies only on ordinary urban streets without a posted school-zone sign, so it is the wrong limit here."},"5":{"q":"Вы едете утром мимо начальной школы. Мигают огни школьной зоны, и на тротуаре находятся дети. На вашем телефоне раздается звонок с работы. Что требует от вас закон Техаса?","options":["Ответить на звонок, поскольку ограничение скорости в школьной зоне регулирует только то, как быстро можно ехать","Не трогать телефон, который держат в руке, потому что использование ручного телефона в активной школьной зоне запрещено","Ответить на звонок, но снизить скорость до 20 миль/ч ниже установленного предела во время разговора","Остановиться в пределах 15 футов от школьного пешеходного перехода, чтобы безопасно ответить на звонок"],"explanation":"In an active school zone (lights flashing or children present), Texas law prohibits using a handheld phone, so you must not answer the call. Option A is wrong because the rule covers phone use, not just speed; the 20-mph-below figure in C is the Move Over/Slow Down rule for stopped emergency vehicles, not school zones."},"6":{"q":"Вы едете по двухполосной дороге с разрешённой скоростью 55 миль/ч, когда наползает густой туман и видимость резко падает. Что вам следует сделать?","options":["Сохранять скорость 55 миль/ч, поскольку это законный установленный лимит и вы имеете право так ехать","Включить дальний свет фар и сохранять текущую скорость, чтобы видеть дальше вперёд","Снизить скорость ниже установленного лимита, чтобы она соответствовала ухудшившейся видимости и дорожным условиям","Съехать на правую обочину и припарковаться там, пока туман полностью не рассеется"],"explanation":"Texas's basic speed law requires you to never drive faster than is safe for conditions, so you must slow below the posted limit in fog. Keeping 55 mph (A) ignores that the posted number is only a maximum for ideal conditions, and high beams (B) actually reflect off fog and worsen visibility."},"7":{"q":"Вы подъезжаете к тихому жилому перекрёстку, где ни в одном направлении нет знаков «стоп», знаков «уступи дорогу» или светофоров. Пикап на пересекающей улице явно достиг перекрёстка на пару секунд раньше вас и ждёт, чтобы проехать прямо. Что вам следует сделать?","options":["Проехать первым, потому что пикап должен уступить дорогу транспортному средству справа от него","Проехать первым, потому что у транспорта на главной дороге есть преимущество","Вам обоим следует считать это перекрёстком с обязательной остановкой, и вы едете, если находитесь справа","Уступить дорогу пикапу и дать ему проехать первым, потому что он прибыл на перекрёсток раньше вас"],"explanation":"At an uncontrolled intersection, you must yield to the vehicle that arrived first, so the pickup truck goes through before you. The 'yield to the driver on your right' rule only applies when two vehicles reach the intersection at the same time, which is not the case here."},"8":{"q":"Вы подъезжаете к перекрестку в жилом районе, где нет ни знаков \"стоп\", ни знаков \"уступи дорогу\", ни светофоров ни в одном направлении. Другая машина подъезжает к перекрестку справа от вас точно в тот же момент, что и вы, и вы оба собираетесь ехать прямо. Что вам следует сделать?","options":["Пропустить машину справа, а затем ехать после того, как она освободит перекресток.","Ехать первым, потому что машина справа обязана уступить дорогу машине слева.","Ехать немедленно, поскольку водитель, едущий прямо, всегда имеет преимущество перед тем, кто поворачивает.","Вам обоим следует полностью остановиться и ждать, потому что нерегулируемый перекресток приравнивается к перекрестку со знаками \"стоп\" во всех направлениях."],"explanation":"At an uncontrolled intersection where two vehicles arrive at the same time, you must yield to the driver on your right. The car is on your right, so it goes first; the idea that the left vehicle has priority or that you must treat it as an all-way stop is incorrect."},"9":{"q":"Вы остановились на зелёный сигнал светофора, ожидая поворота налево на перекрёстке. Со встречного направления приближается автомобиль, едущий прямо, а пешеход начинает переходить улицу, на которую вы хотите повернуть. Что вы должны сделать, прежде чем завершить поворот налево?","options":["Быстро повернуть до приближения встречного автомобиля, так как зелёный сигнал даёт вам преимущество","Уступить дорогу и встречному автомобилю, и пешеходу, а затем завершить поворот, когда это будет безопасно","Уступить только встречному автомобилю, потому что пешеходы должны ждать, пока транспорт освободит перекрёсток","Проехать первым, потому что водитель справа от вас обязан уступить вам дорогу"],"explanation":"When making a left turn you must yield to oncoming traffic and to pedestrians, so you wait for both the approaching car and the crossing pedestrian before turning. A green light does not give a left-turning driver priority over oncoming traffic, and pedestrians in a crosswalk always have the right of way."},"10":{"q":"Вы едете по жилой улице, которая упирается в оживленную сквозную улицу, образуя Т-образный перекресток. На этом перекрестке нет знаков «стоп», светофоров или других средств регулирования. Когда вы подъезжаете к концу своей улицы, слева по сквозной улице приближается автомобиль. Что вам следует сделать?","options":["Проехать первым, потому что на нерегулируемом перекрестке преимущество всегда у автомобиля справа","Проехать первым, потому что автомобиль на сквозной улице должен уступить дорогу транспорту, выезжающему с боковой дороги","Уступить дорогу автомобилю на сквозной улице, потому что у транспорта на сквозной дороге (верхняя часть буквы Т) есть преимущество","Уступать только если другой автомобиль сигнализирует о повороте, иначе вы можете въехать на перекресток первым"],"explanation":"At a T-intersection, the road that ends (the stem of the T) must yield to traffic on the through road that forms the top of the T, so you wait for the approaching car. The right-on-arrival rule applies only to vehicles arriving together at an equal, uncontrolled crossing, not to a side road meeting a through road."},"11":{"q":"Вы подъезжаете к однополосному круговому перекрёстку в Техасе, и слева по кругу уже движутся две машины. Что нужно сделать, чтобы въехать правильно и безопасно?","options":["Сразу въехать и повернуть налево (по часовой стрелке), так как транспорт в круге обязан уступить въезжающим","Полностью остановиться и подождать, пока весь транспорт в круге выедет, прежде чем въезжать","Уступить машинам в круге, затем при появлении промежутка въехать налево (по часовой стрелке)","Уступить машинам, уже находящимся в круге, затем при появлении промежутка въехать направо (против часовой стрелки)"],"explanation":"At a roundabout you must yield to traffic already in the circle and enter to the right, traveling counter-clockwise. Option C uses the correct yield rule but the wrong direction, and you do not need a full stop or to wait for the circle to empty if a safe gap is available."},"12":{"q":"Вы едете по правой полосе двухполосной городской улицы с односторонним движением, когда слышите сирену и видите позади приближающуюся машину скорой помощи с включёнными проблесковыми маячками. Справа от вас свободное место у обочины. Что вы должны сделать?","options":["Прижаться вправо и остановиться, пока машина скорой помощи не проедет.","Сохранять скорость и оставаться в своей полосе, чтобы скорая помощь могла объехать вас слева.","Перестроиться на одну полосу или снизить скорость до 20 миль/ч ниже разрешённой и продолжить движение.","Ускориться, чтобы проехать перекрёсток впереди до того, как скорая помощь вас догонит."],"explanation":"When an emergency vehicle approaches with lights and siren, you must pull over to the right and stop until it passes. Option C describes the separate Move Over/Slow Down law for stopped emergency vehicles on the roadside, not for an emergency vehicle responding behind you, and the other choices fail to yield."},"13":{"q":"Вы стоите на зелёный свет, ожидая поворота направо на оживлённом перекрёстке в Хьюстоне. Пешеход только что сошёл с тротуара и идёт по пешеходному переходу на ту полосу, на которую вы хотите повернуть. Что вы должны сделать?","options":["Быстро повернуть, прежде чем пешеход окажется на вашем пути, так как у вас зелёный свет","Уступить дорогу пешеходу на переходе и подождать, пока он безопасно не освободит ваш путь","Поехать, если сначала посигналить, чтобы предупредить пешехода поторопиться","Подъехать вперёд на переход, чтобы пешеход понял, что нужно пройти позади вашего автомобиля"],"explanation":"Pedestrians in a crosswalk always have the right of way, so you must yield and wait until they have safely cleared your path before turning, even on a green light. Having a green signal does not allow you to turn through a pedestrian who is already lawfully crossing, and honking or edging forward does not transfer that right of way to you."},"14":{"q":"Вы остановились на зелёный сигнал светофора, ожидая возможности повернуть направо. Пешеход в тёмных очках сходит с тротуара на пешеходный переход, водя перед собой белой тростью, и явно направляется через ваш путь. Что вы обязаны сделать?","options":["Медленно проехать поворот, поскольку зелёный сигнал даёт вашему автомобилю преимущество перед переходящими дорогу пешеходами","Подать звуковой сигнал, чтобы предупредить пешехода, а затем завершить поворот направо, прежде чем он дойдёт до вашей полосы","Полностью остановиться и уступить дорогу, позволив пешеходу с белой тростью безопасно перейти, прежде чем вы повернёте","Ждать только если пешеход уже на вашей полосе, иначе объехать его спереди"],"explanation":"Texas law requires drivers to yield to a blind pedestrian using a white cane or guide dog, and pedestrians in a crosswalk always have the right of way. A green light does not override your duty to yield to a pedestrian lawfully in the crosswalk, so you must stop and let them cross."},"15":{"q":"Вы подъезжаете к перекрёстку на зелёный сигнал и собираетесь проехать прямо. С пересекающей улицы вереница машин с включёнными фарами и маленькими флажками следует за катафалком, медленно въезжая на перекрёсток на свой красный сигнал в составе похоронной процессии. Что вам следует сделать?","options":["Проехать на свой зелёный, поскольку у процессии красный сигнал и она должна вас пропустить","Посигналить и продвинуться вперёд, чтобы занять свою очередь, затем вклиниться в промежуток между машинами процессии","Прижаться вправо и полностью остановиться, пока вся процессия не проедет, как при появлении автомобиля экстренных служб","Уступить дорогу и дождаться, пока вся похоронная процессия проедет перекрёсток, прежде чем двигаться дальше"],"explanation":"A funeral procession has the right of way at intersections, so you must yield and let the whole procession pass even though you have a green light. Proceeding on green ignores the procession's right of way, and pulling fully to the right is the rule for emergency vehicles with lights and siren, not a funeral procession."},"16":{"q":"Вы едете по городской улице и планируете повернуть направо на следующем перекрёстке. Вы хотите подать сигнал правильно, чтобы другие водители вовремя поняли ваши намерения. В какой момент следует начать подавать сигнал перед поворотом?","options":["Не менее чем за 100 футов до перекрёстка, где вы будете поворачивать","Не менее чем за 20 футов до перекрёстка, где вы будете поворачивать","Только после того, как вы перестроились в правый ряд возле бордюра","Не менее чем за 30 футов до перекрёстка, где вы будете поворачивать"],"explanation":"Texas law requires you to signal at least 100 feet before making a turn or changing lanes so other drivers have enough warning. The 20-foot and 30-foot distances are real Texas rules (no parking within 20 feet of a crosswalk, 30 feet of a stop sign), but they do not apply to signaling for a turn."},"17":{"q":"Вы едете по двухполосной улице с односторонним движением и должны повернуть направо на ближайшем перекрёстке. Знаков, ограничивающих использование полос для поворотов, нет. В какой полосе вы должны находиться и где должен располагаться ваш автомобиль, чтобы правильно совершить поворот?","options":["В левой полосе, держась ближе к центральной линии при повороте","В правой полосе, близко к бордюру при повороте","В любой полосе, при условии что вы подадите сигнал не менее чем за 100 футов до поворота","В правой полосе, но держась подальше от бордюра, чтобы оставить место для велосипедистов"],"explanation":"A right turn must be made from the right lane, keeping close to the curb. Option A describes the correct setup for a left turn, and signaling distance (Option C) does not change the lane and curb requirement for a right turn."},"18":{"q":"Вы приближаетесь к перекрёстку на дороге с двусторонним движением и планируете повернуть налево на пересекающую улицу. В вашем направлении движения есть две полосы. Чтобы правильно расположить автомобиль для поворота, в какую полосу следует перестроиться перед перекрёстком?","options":["В правую полосу, держась ближе к бордюру","В любую полосу, если вы подаёте сигнал не менее чем за 100 футов","В левую полосу, ближайшую к осевой линии","В центральную полосу для поворота налево в обоих направлениях, используя её для движения до перекрёстка"],"explanation":"A left turn must be made from the left lane, the one nearest the center line, so you cross the least amount of opposing traffic. The right lane is for right turns, and a two-way left-turn lane is only for turning, not for traveling up to an intersection on a two-way street with regular through lanes."},"19":{"q":"Вы полностью остановились на красный свет в правой полосе, намереваясь повернуть направо. На перекрёстке нет знака, запрещающего поворот на красный, и поперечное движение свободно. Что вам следует сделать?","options":["Дождаться зелёного света перед поворотом, потому что поворот направо на красный свет никогда не разрешён.","Поворачивать только после того, как уступите встречному транспорту, как при повороте налево.","Повернуть без остановки, поскольку полоса уже свободна от поперечного движения.","Выполнить поворот направо после полной остановки, поскольку нет запрещающего знака и движение свободно."],"explanation":"In Texas, a right turn on red is allowed after coming to a full stop, unless a sign prohibits it; with no such sign and clear traffic, you may turn. Option C is wrong because a complete stop is always required first, and the oncoming-traffic yield in B applies to left turns, not a right turn on red."},"20":{"q":"Вы остановились на красный свет на улице с односторонним движением и собираетесь повернуть налево на другую улицу с односторонним движением, по которой поток движется налево. Никакой знак на перекрёстке не запрещает поворот. Что вам разрешено сделать по закону?","options":["Повернуть налево после полной остановки, когда путь свободен","Повернуть налево без остановки, поскольку обе улицы с односторонним движением","Дождаться зелёного света, потому что поворот налево на красный в Техасе никогда не разрешён","Повернуть налево на красный только если вы также выезжаете с улицы с двусторонним движением"],"explanation":"A left turn on red is allowed only from a one-way street onto a one-way street, and only after a full stop when no sign prohibits it. You may not roll through without stopping (B), and the turn is permitted in Texas in this exact situation, so waiting for green is not required (C)."},"21":{"q":"Вы едете по средней полосе трехполосной улицы с односторонним движением и вам нужно повернуть направо на ближайшем перекрестке. С какой полосы следует завершить поворот?","options":["Со средней полосы, поскольку вы уже находитесь в центре дороги","С крайней правой полосы — полосы, ближайшей к направлению вашего поворота","С крайней левой полосы, потому что на улице с односторонним движением все повороты должны начинаться слева","С любой полосы, поскольку на улице с односторонним движением положение полосы не имеет значения"],"explanation":"On a one-way street you turn from the lane nearest the direction you are turning, so a right turn must be made from the rightmost lane. Option C confuses this with the left-turn rule, and the left lane is correct only when turning left."},"22":{"q":"На двухполосном шоссе вы выезжаете на левую полосу, чтобы обогнать медленный грузовик. Разогнавшись и проехав мимо него, вы хотите вернуться на правую полосу. Когда безопасно возвращаться на свою полосу?","options":["Как только ваш передний бампер поравняется с передней частью грузовика","Только после того, как грузовик мигнёт фарами, подавая вам сигнал вернуться","Как только вы увидите обгоняемый грузовик в зеркале заднего вида","После того, как вы проедете не менее 100 футов за грузовик"],"explanation":"You may return to your lane only when you can see the passed vehicle in your rearview mirror, which confirms you have enough space ahead of it to merge safely. Clearing only your front bumper (A) leaves too little room and could cut the truck off, and there is no rule about a 100-foot distance for merging back."},"23":{"q":"Вы едете по двухполосной загородной дороге за медленным трактором. Приближаясь к вершине холма, вы не видите дорогу впереди и не можете определить, не едет ли навстречу какой-либо автомобиль. Что вам следует сделать относительно обгона трактора?","options":["Быстро обогнать на холме, поскольку трактор едет значительно ниже разрешённой скорости","Обогнать по правой обочине, чтобы не выезжать на встречную полосу","Обогнать сейчас, но только после звукового сигнала, чтобы предупредить встречный транспорт","Не обгонять; подождать, пока вы не проедете холм и не будете чётко видеть дорогу впереди"],"explanation":"You must not pass on a hill where your view of oncoming traffic is blocked, so you should wait until you can see the road ahead clearly. Passing on the hill (A), sounding the horn (C), or using the right shoulder (B) are all unsafe and illegal because you still cannot verify the lane is clear and passing must be done on the left."},"24":{"q":"Вы едете по двухполосному сельскому шоссе позади медленного грузовика и хотите его обогнать. Впереди справа на обочине вы замечаете жёлтый знак в форме вымпела (вытянутого треугольника). Что этот знак говорит вам об обгоне?","options":["Вы въезжаете в зону, где обгон запрещён, поэтому здесь обгонять грузовик нельзя","Это знак «Уступи дорогу», поэтому вы можете обгонять, как только освободится встречная полоса","Он обозначает впереди центральную полосу для левых поворотов, которую можно использовать для обгона","Это лишь предупреждение о железнодорожном переезде, и обгон по-прежнему разрешён"],"explanation":"A pennant-shaped sign on the right side of the road marks the start of a No Passing Zone, so you must not pass here. A Yield sign is a downward-pointing triangle facing oncoming drivers, not a side-mounted pennant, which makes option B the trap."},"25":{"q":"Вы едете по левой полосе трёхполосного техасского шоссе с установленной максимальной скоростью. Сзади приближается более быстрый автомобиль, который хочет вас обогнать. Что вы должны сделать?","options":["Сохранять скорость и оставаться в левой полосе, поскольку вы уже едете на максимальной разрешённой скорости","Перестроиться в полосу справа, чтобы пропустить более быстрый автомобиль, а затем держаться правее","Ускориться выше разрешённого предела, чтобы автомобилю сзади больше не нужно было вас обгонять","Остановиться в левой полосе и жестом показать более быстрому автомобилю объехать вас"],"explanation":"In Texas you must keep right except to pass, and slower traffic keeps right, so you should move into a lane to your right and let the faster vehicle pass. Staying in the left lane just because you are at the limit is wrong, and speeding up or stopping would create a hazard."},"26":{"q":"Вы едете ночью по незнакомой двухполосной дороге. Слева от вас сплошная жёлтая линия проходит вдоль полосы с движением, и вы замечаете фары машин, едущих вам навстречу по другую сторону этой линии. О чём говорит вам эта жёлтая осевая линия?","options":["Полоса по другую сторону идёт в том же направлении, что и вы, поэтому вы можете перестроиться через неё, когда будет свободно","Дорога с односторонним движением, и жёлтая линия просто отмечает дальний край проезжей части","Движение по другую сторону линии идёт в противоположном направлении, вам навстречу","Жёлтая линия — это только разметка обочины, и за ней нет полосы движения"],"explanation":"Yellow center lines divide traffic moving in opposite directions, which is why you see oncoming headlights across that line. White lines (not yellow) separate lanes traveling the same direction, so options suggesting same-direction or one-way travel are wrong."},"27":{"q":"Вы едете по четырёхполосной дороге и замечаете, что линия, отделяющая вашу полосу от полосы непосредственно слева от вас, сплошная белая, а линия по центру дороги жёлтая. Что белая линия между вами и полосой слева говорит вам об этой соседней полосе?","options":["Движение по этой полосе идёт в противоположном направлении, поэтому вы никогда не должны на неё выезжать","Полоса слева от вас — это центральная полоса для поворота налево в обоих направлениях, предназначенная только для поворотов","Вы можете свободно перестраиваться на эту полосу в любой момент, потому что белые линии всегда лишь рекомендательные","Движение по этой полосе идёт в том же направлении, что и у вас"],"explanation":"White lines separate lanes of traffic traveling in the same direction, so the lane to your left carries traffic going your way. Yellow lines (option A) divide opposite-direction traffic and mark the center of the road, which is the trap here."},"28":{"q":"В вашей полосе образуется пробка, поэтому вы выезжаете в центральную полосу, размеченную стрелками левого поворота с обоих концов, и проезжаете по ней вперёд полквартала, чтобы обогнать медленные машины. Почему это незаконно?","options":["Двусторонняя полоса для левого поворота предназначена только для выполнения левых поворотов и не может использоваться для сквозного движения, даже кратковременно.","Вы можете двигаться по центральной полосе для левого поворота, только если остаётесь в ней менее 200 футов.","Центральная полоса — это полоса для обгона, но использовать её можно только для обгона справа.","Движение по центральной полосе разрешено, если вы подаёте сигнал не менее чем за 100 футов."],"explanation":"A two-way left-turn lane (the center lane marked with arrows) is only for preparing to turn left, never for driving through traffic. Option B invents a distance allowance, and the 100-foot signal rule in D applies to turns and lane changes, not to using this lane for travel."},"29":{"q":"Вы подъезжаете к знаку «стоп» на перекрёстке. На асфальте в нескольких футах перед пешеходным переходом чётко нанесена белая стоп-линия, но отсюда обзор поперечного движения частично закрыт припаркованным грузовиком. Каков правильный порядок действий?","options":["Медленно проехать стоп-линию и остановиться только тогда, когда у пешеходного перехода станет видно поперечное движение","Сначала полностью остановиться за стоп-линией, затем продвинуться вперёд и при необходимости остановиться снова, чтобы видеть дорогу","Снизить скорость примерно до 5 миль/ч у линии; полная остановка нужна только при наличии другого транспортного средства","Остановиться прямо на пешеходном переходе, чтобы обеспечить наилучший обзор поперечного движения"],"explanation":"Texas law requires a full stop at a stop sign behind the stop line or crosswalk, so you must stop there first even if your view is blocked, then creep forward and stop again to see. Rolling through the line, stopping on the crosswalk, or only slowing down all violate the stop-line requirement."},"30":{"q":"Вы едете по двухполосной дороге с одной полосой в каждом направлении и без разделительной полосы. Впереди вас, в том же направлении, школьный автобус останавливается, включает мигающие красные огни и выдвигает знак \"Стоп\". Что вы должны сделать?","options":["Снизить скорость до 20 миль/ч ниже ограничения и осторожно объехать автобус слева","Продолжать движение со сниженной скоростью, только если рядом с автобусом не видно детей","Полностью остановиться и оставаться на месте, пока красные огни не перестанут мигать, а знак \"Стоп\" не будет убран","Останавливаться только если вы позади автобуса; встречный транспорт на этой дороге может продолжать движение"],"explanation":"On a road with no physical median or barrier, all traffic from both directions must stop for a school bus showing flashing red lights and an extended stop arm, and stay stopped until the lights stop and the arm folds in. Option D states the median exception, but here there is no median, so traffic from both directions must stop; the 20-mph-below rule in A applies to stopped emergency/utility vehicles, not school buses."},"31":{"q":"Вы опаздываете и замечаете свободное место у бордюра на оживлённой улице в центре города. Прямо перед этим местом находится пожарный гидрант. Чтобы припарковаться по закону, на каком расстоянии от гидранта вы должны оставить свой автомобиль?","options":["Не менее 30 футов — на том же расстоянии, что требуется от знака или сигнала «стоп»","Не менее 20 футов — на том же расстоянии, что требуется от пешеходного перехода на перекрёстке","Можно парковаться вплотную к гидранту, если вы не перекрываете тротуар","Не менее 15 футов"],"explanation":"Закон Техаса запрещает парковку в пределах 15 футов от пожарного гидранта, чтобы пожарные могли получить к нему доступ в экстренной ситуации. Расстояния 30 футов и 20 футов реальны для Техаса, но они относятся соответственно к знакам/сигналам «стоп» и к пешеходным переходам, а не к гидрантам."},"32":{"q":"Вы ищете место для парковки на оживленной улице в центре города возле перекрестка. Там, где боковая улица выходит на главную дорогу, есть размеченный пешеходный переход. Чтобы припарковаться по закону, на каком расстоянии от этого пешеходного перехода должен оставаться ваш автомобиль?","options":["Не менее 20 футов от пешеходного перехода","Не менее 15 футов от пешеходного перехода","Не менее 30 футов от пешеходного перехода","Не менее 10 футов от пешеходного перехода"],"explanation":"Texas law prohibits parking within 20 feet of a crosswalk at an intersection so drivers turning into the street can see crossing pedestrians. The 15-foot figure is the no-parking distance for a fire hydrant, and 30 feet applies to a stop sign or signal, so both are real rules placed in the wrong situation."},"33":{"q":"Вы ищете место для парковки на оживлённой улице в центре города. Вы замечаете свободный участок у бордюра прямо рядом с углом, где установлен знак \"Стоп\". Чтобы припарковаться по закону, на каком расстоянии от этого знака \"Стоп\" должна находиться ваша машина?","options":["Не менее 15 футов","Не менее 30 футов","Не менее 20 футов","Не менее 50 футов"],"explanation":"In Texas you may not park within 30 feet of a stop sign or traffic signal so your vehicle does not block other drivers' view of it. The 15-foot rule applies to fire hydrants and the 20-foot rule to crosswalks at an intersection, so those distances are traps from other parking rules."},"34":{"q":"Вы опаздываете и хотите оставить машину буквально на минуту, чтобы взять кофе. Оглядевшись, вы замечаете несколько свободных мест вдоль квартала. Какое из них является ЗАКОННЫМ местом для парковки?","options":["На середине размеченного пешеходного перехода, ведь машина торчит лишь частично","Прямо перед въездом во двор жилого дома, ведь вы отлучитесь лишь на минуту","Вдоль правого бордюра на вашей стороне двусторонней улицы, в стороне от любого въезда, перехода или гидранта","Лицом к встречному потоку у левого бордюра, где есть единственное свободное место"],"explanation":"Parking is legal only when you are on the correct (right) side of the street and not blocking a driveway, crosswalk, sidewalk, hydrant, or traffic. Options A and B are prohibited because you may never park on a crosswalk or in front of a driveway, and D is illegal because parking against the left curb means facing the wrong way on a two-way street."},"35":{"q":"Вы паркуетесь на крутой улице, идущей в гору, и у правого края дороги есть бордюр. Прежде чем выйти из машины, в какую сторону нужно повернуть передние колёса?","options":["К бордюру, чтобы шины упёрлись в него, если машина покатится","Прямо, так как бордюр сам удержит машину на месте","Резко влево, к центру дороги, чтобы шины не касались бордюра","От бордюра, чтобы катящаяся машина откатилась обратно к бордюру"],"explanation":"When parking uphill with a curb, turn the wheels away from the curb so that if the car rolls back, the front tire catches against the curb and stops it. Turning toward the curb is correct only when parking downhill, and the curb by itself is never a substitute for properly aimed wheels and a set parking brake."},"36":{"q":"Вы паркуете машину носом под уклон на улице с бордюром. Прежде чем выйти из машины, в какую сторону следует повернуть передние колёса?","options":["К бордюру, чтобы машина упёрлась в бордюр, если начнёт катиться","От бордюра, чтобы машина покатилась в сторону бордюра, если начнёт двигаться","Прямо, так как стояночный тормоз удержит машину","К бордюру только если вы стоите ещё и не на той стороне улицы"],"explanation":"When parking downhill next to a curb, turn the front wheels toward the curb so that if the car rolls, the curb blocks it. Turning the wheels away from the curb is the correct method for parking uphill, not downhill, which makes that option a common reversal trap."},"37":{"q":"Вы съезжаете на гравийную обочину ровной загородной дороги, чтобы ответить на телефонный звонок. Здесь нет бордюра, только наклонная грунтовая обочина, уходящая вниз справа от вас. Прежде чем выйти из автомобиля, в какую сторону следует повернуть передние колёса?","options":["Прямо, ведь дорога ровная и нет бордюра, в который можно упереться","В сторону обочины (вправо), чтобы автомобиль скатился с дороги, если сдвинется","В сторону центра дороги (влево), чтобы водители видели ваши передние колёса","На ровной дороге это неважно; просто поставьте на стояночный тормоз и оставьте колёса как есть"],"explanation":"When parking where there is no curb, you should always turn the front wheels toward the shoulder (to the right) so the vehicle would roll away from traffic and off the road if it starts to move. Turning them straight or toward the road is wrong because, even on ground that looks flat, a rolling vehicle could drift into the travel lane and into oncoming traffic."},"38":{"q":"Вы едете со скоростью 65 миль/ч по двухполосному шоссе в Техасе и видите впереди ремонтный грузовик TxDOT, остановившийся на правой обочине с мигающими жёлтыми огнями. В левой полосе плотный поток машин, поэтому вы не можете безопасно перестроиться. Что требует от вас закон «Перестройся/Сбавь скорость» (Move Over/Slow Down)?","options":["Сохранять скорость, но подать звуковой сигнал, чтобы предупредить рабочих при проезде","Полностью остановиться позади грузовика и ждать, пока рабочий не пропустит вас взмахом руки","Снизить скорость до 45 миль/ч (на 20 миль/ч ниже разрешённой скорости), пока не проедете остановившийся грузовик","Снизить скорость до 20 миль/ч и продолжать движение только когда обочина свободна"],"explanation":"When you cannot safely move over a lane, Texas's Move Over/Slow Down law requires you to slow to 20 mph below the posted speed limit, which is 45 mph in a 65 mph zone. Option D wrongly uses 20 mph itself (a school-zone figure) instead of 20 mph below the limit, and stopping or just honking is not required."}},"learn-rules-of-the-road":{"0":{"q":"Согласно основному закону о скорости штата Техас, с какой скоростью вам разрешено ехать?","options":["Никогда не быстрее, чем безопасно для текущих условий","Всегда точно по установленному ограничению скорости","Так быстро, как позволяет ваш автомобиль","На 10 миль/ч выше лимита, если движение слабое"],"explanation":"Texas's basic speed law means you must never drive faster than is safe for the current conditions."},"1":{"q":"В Техасе, какое ограничение скорости по умолчанию действует в городском районе, где нет дорожного знака?","options":["20 миль/ч","30 миль/ч","45 миль/ч","55 миль/ч"],"explanation":"Where unposted, the default speed limit in a Texas urban district is 30 mph."},"2":{"q":"Какое ограничение скорости по умолчанию на нумерованном шоссе днём, если знак не установлен?","options":["30 миль/ч","55 миль/ч","70 миль/ч","85 миль/ч"],"explanation":"Where unposted, the default daytime speed limit on numbered highways is 70 mph."},"3":{"q":"Какое максимальное ограничение скорости разрешено на некоторых платных дорогах Техаса?","options":["65 миль/ч","70 миль/ч","75 миль/ч","85 миль/ч"],"explanation":"Some specific Texas tollways are posted with speed limits as high as 85 mph."},"4":{"q":"Что нужно делать в школьной зоне, когда мигают огни или присутствуют дети?","options":["Соблюдать установленный сниженный лимит скорости","Ехать с обычной разрешённой скоростью","Ускориться, чтобы покинуть зону","Полностью остановиться и ждать"],"explanation":"In a school zone you must obey the posted reduced limit (often 20 mph) when lights flash or children are present."},"5":{"q":"В активной школьной зоне в Техасе законно ли пользоваться ручным телефоном?","options":["Да, всегда","Нет, это незаконно","Только после 21:00","Только во время стоянки рядом"],"explanation":"Using a handheld phone in an active school zone is illegal in Texas."},"6":{"q":"Когда следует снижать скорость движения?","options":["Только на сухих, пустых шоссе","Только когда нет пешеходов","В дождь, туман, плотный поток, на поворотах и рядом с пешеходами","Только ночью на прямых дорогах"],"explanation":"You should always reduce speed in rain, fog, heavy traffic, on curves, and near pedestrians."},"7":{"q":"На нерегулируемом перекрёстке какое транспортное средство имеет преимущество проезда?","options":["Более быстрое транспортное средство","Более крупное транспортное средство","Транспортное средство слева","Транспортное средство, прибывшее первым"],"explanation":"At an uncontrolled intersection, you yield to the vehicle that arrived first."},"8":{"q":"На нерегулируемом перекрёстке, если два автомобиля прибывают одновременно, кто имеет преимущество в движении?","options":["Водитель справа","Водитель слева","Более быстрый автомобиль","Более крупный автомобиль"],"explanation":"When two vehicles arrive at the same time, yield to the driver on your right."},"9":{"q":"При повороте налево кому вы должны уступить дорогу?","options":["Только пешеходам","Встречному транспорту и пешеходам","Только транспорту позади вас","Никому, у вас преимущество"],"explanation":"When turning left, you must yield to oncoming traffic and to pedestrians."},"10":{"q":"На T-образном перекрёстке у какого транспорта есть преимущество проезда?","options":["У транспорта, поворачивающего налево","У транспортного средства слева","У транспорта на сквозной дороге","У того, кто приехал последним"],"explanation":"Traffic on the through road (the top of the T) has the right of way."},"11":{"q":"Кто имеет преимущество на круговом перекрёстке?","options":["Водители, ожидающие въезда","Более быстрый автомобиль","Тот, кто первым посигналит","Транспорт, уже находящийся в круге"],"explanation":"At a roundabout, you must yield to traffic already in the circle before entering."},"12":{"q":"Что нужно делать, когда приближается машина экстренной службы с включёнными мигалками и сиреной?","options":["Прижаться вправо и остановиться, пока она не проедет","Ускориться, чтобы уехать с дороги","Остановиться посреди своей полосы","Повернуть налево перед ней"],"explanation":"Pull over to the right and stop until the emergency vehicle has passed."},"13":{"q":"У кого есть преимущество проезда на пешеходном переходе?","options":["У ближайшего автомобиля","У пешеходов","У более быстрого автомобиля","У поворачивающих автомобилей"],"explanation":"Pedestrians in a crosswalk always have the right of way."},"14":{"q":"Кому вы должны уступить дорогу, если у него белая трость или собака-поводырь?","options":["Припаркованной машине","Дорожному рабочему","Слепому пешеходу","Велосипедисту"],"explanation":"You must yield to a blind pedestrian carrying a white cane or using a guide dog."},"15":{"q":"Кто имеет преимущество на перекрёстках во время похоронной процессии?","options":["Поперечный поток транспорта","Тот, кто прибыл первым","Водитель справа","Похоронная процессия"],"explanation":"A funeral procession has the right of way at intersections."},"16":{"q":"За какое расстояние до поворота или смены полосы нужно подавать сигнал?","options":["Не менее 100 футов","Не менее 25 футов","Не менее 250 футов","Не менее 500 футов"],"explanation":"In Texas, you must signal at least 100 feet before a turn or lane change."},"17":{"q":"Какую полосу следует использовать для поворота направо?","options":["Левую полосу","Правую полосу, ближе к бордюру","Центральную полосу","Любую свободную полосу"],"explanation":"A right turn should be made from the right lane, close to the curb."},"18":{"q":"Из какой полосы следует выполнять левый поворот?","options":["Из правой полосы","Из центральной полосы","Из левой полосы","Из любой свободной полосы"],"explanation":"A left turn should be made from the left lane."},"19":{"q":"Когда в Техасе разрешён поворот направо на красный свет?","options":["Никогда, ни при каких условиях","Только ночью","Без предварительной остановки","После полной остановки, если знак этого не запрещает"],"explanation":"A right turn on red is allowed after coming to a full stop, unless a sign prohibits it."},"20":{"q":"Когда в Техасе разрешен левый поворот на красный свет?","options":["С улицы с односторонним движением на улицу с односторонним движением, после полной остановки","С любой улицы, после полной остановки","На улицу с двусторонним движением, после полной остановки","Никогда, ни при каких условиях"],"explanation":"In Texas, a left turn on red is only allowed from a one-way street onto a one-way street after stopping fully."},"21":{"q":"На улице с односторонним движением из какой полосы нужно поворачивать?","options":["Из центральной полосы","Из полосы, ближайшей к направлению поворота","Из любой свободной полосы","Из полосы, наиболее удалённой от поворота"],"explanation":"On a one-way street, turn from the lane nearest the direction you are turning."},"22":{"q":"С какой стороны следует обгонять другое транспортное средство?","options":["Справа","С любой стороны","Слева","По обочине"],"explanation":"You should pass on the left and return to your lane only when you can see the passed vehicle in your mirror."},"23":{"q":"Где НЕЛЬЗЯ обгонять другой автомобиль?","options":["На прямой, ровной дороге","Когда полоса свободна","На широкой улице","На подъёме или повороте"],"explanation":"You must not pass on a hill or curve because you cannot see oncoming traffic."},"24":{"q":"Где НЕЛЬЗЯ обгонять другое транспортное средство?","options":["На перекрёстке или железнодорожном переезде","На длинной, прямой и ровной дороге","На чётко обозначенной полосе для обгона","Там, где прерывистая жёлтая линия с вашей стороны"],"explanation":"It is unsafe and illegal to pass at an intersection or railroad crossing."},"25":{"q":"Когда вы можете обгонять другой автомобиль?","options":["Когда сплошная жёлтая линия на вашей стороне","Когда линия на вашей стороне прерывистая","На холме или повороте","На железнодорожном переезде"],"explanation":"You may pass when the yellow line on your side is broken, but not where a solid yellow line is on your side."},"26":{"q":"Какую форму имеет знак, обозначающий зону запрета обгона?","options":["Круглую","Квадратную","Вымпел (треугольник)","Ромб"],"explanation":"A No Passing Zone is marked by a pennant-shaped (triangular) sign, where passing is not allowed."},"27":{"q":"На многополосной дороге какую полосу должен использовать медленный транспорт?","options":["Левую полосу","Центральную полосу","Любую полосу на выбор","Правую полосу"],"explanation":"Keep right except to pass; slower traffic stays in the right lane."},"28":{"q":"Что разделяют желтые осевые линии на дороге?","options":["Транспорт, движущийся в противоположных направлениях","Транспорт, движущийся в одном направлении","Парковочные места от полос движения","Велосипедные дорожки от тротуаров"],"explanation":"Yellow center lines divide traffic moving in opposite directions."},"29":{"q":"Что разделяют белые линии на дороге?","options":["Транспорт, движущийся в противоположных направлениях","Полосы движения, идущие в одном направлении","Парковочные места от дороги","Дорогу от тротуара"],"explanation":"White lines separate lanes of traffic moving in the same direction."},"30":{"q":"Для чего используется центральная полоса со стрелками левого поворота?","options":["Для обгона других машин","Для сквозного движения","Только для поворота налево","Для парковки автомобиля"],"explanation":"A two-way left-turn lane is only for turning left, not for travel."},"31":{"q":"У знака \"стоп\" где вы должны полностью остановиться?","options":["Посередине перекрёстка","Везде, где вам кажется безопасным","После того как пересечёте пешеходный переход","Перед стоп-линией или пешеходным переходом"],"explanation":"At a stop sign you must come to a full stop behind the stop line or crosswalk."},"32":{"q":"Когда вы должны остановиться перед остановившимся школьным автобусом?","options":["Когда мигают красные огни и выдвинут знак \"стоп\"","Только когда дети переходят дорогу","Только если вы находитесь прямо за ним","Никогда, можно медленно проехать"],"explanation":"You must stop for a stopped school bus when its red lights are flashing and its stop arm is out."},"33":{"q":"Когда вы должны остановиться перед остановившимся школьным автобусом с мигающими красными огнями?","options":["Только если вы едете позади автобуса","С обоих направлений, если дороги не разделены разделительной полосой","Никогда, просто снизьте скорость","Только если дети переходят дорогу"],"explanation":"You must stop from both directions unless a physical median or barrier separates the roadways."},"34":{"q":"Как близко к пожарному гидранту можно парковаться?","options":["В пределах 5 футов","В пределах 10 футов","Не ближе 15 футов","Прямо рядом с ним"],"explanation":"You may not park within 15 feet of a fire hydrant."},"35":{"q":"На каком расстоянии от пешеходного перехода на перекрёстке нельзя парковаться?","options":["5 футов","10 футов","15 футов","20 футов"],"explanation":"You may not park within 20 feet of a crosswalk at an intersection."},"36":{"q":"Насколько близко к знаку \"Стоп\" можно парковаться?","options":["Не ближе 30 футов","Не ближе 5 футов","Не ближе 10 футов","Не ближе 15 футов"],"explanation":"In Texas, you may not park within 30 feet of a stop sign or signal."},"37":{"q":"Где запрещено парковать автомобиль?","options":["На размеченном парковочном месте","На пешеходном переходе или тротуаре","Вдоль правого бордюра","В парковочном гараже"],"explanation":"It is illegal to park on a crosswalk or sidewalk."},"38":{"q":"Где парковка ЗАПРЕЩЕНА?","options":["На тихой боковой улице","На размеченной парковке","Перед въездом во двор","Рядом с парковочным счётчиком"],"explanation":"You may not park in front of a driveway."},"39":{"q":"Где парковка запрещена?","options":["На правой стороне улицы","На размеченном парковочном месте","Рядом с парковочным счётчиком","На неправильной стороне улицы"],"explanation":"You may not park on the wrong side of the street."},"40":{"q":"Где запрещено парковаться?","options":["Там, где вы будете мешать движению","На размеченном парковочном месте","В парковочном гараже","На своей собственной подъездной дорожке"],"explanation":"You may not park where you would be blocking traffic."},"41":{"q":"При парковке в гору рядом с бордюром, в какую сторону нужно повернуть колёса?","options":["Прямо","В сторону от бордюра","В сторону бордюра","Это не имеет значения"],"explanation":"When parking uphill with a curb, turn your wheels away from the curb so the car rolls into the curb if it moves."},"42":{"q":"Когда вы паркуетесь под уклон рядом с бордюром, в какую сторону нужно повернуть передние колёса?","options":["Прямо вперёд","От бордюра","К бордюру","Это не имеет значения"],"explanation":"When parking downhill with a curb, turn your wheels toward the curb so the car rolls into it if it moves."},"43":{"q":"При парковке на склоне без бордюра в какую сторону повернуть колёса?","options":["Прямо","В сторону центра дороги","Это не имеет значения","В сторону обочины (вправо)"],"explanation":"Without a curb, always turn your wheels toward the shoulder/right so the car rolls off the road if it moves."},"44":{"q":"По закону \"Уступи дорогу\", насколько нужно сбросить скорость перед остановившейся машиной экстренной службы с мигающими огнями?","options":["На 20 миль/ч ниже ограничения скорости","На 5 миль/ч ниже ограничения скорости","На 10 миль/ч ниже ограничения скорости","До полной остановки"],"explanation":"You must move over a lane or slow to 20 mph below the speed limit for stopped emergency vehicles."},"45":{"q":"Кто имеет преимущество проезда на нерегулируемом перекрёстке?","options":["Более быстрый автомобиль","Автомобиль, который подъехал первым","Более крупный автомобиль","Автомобиль слева"],"explanation":"At an uncontrolled intersection, yield to the vehicle that arrived first."},"46":{"q":"За какое расстояние до поворота или смены полосы нужно подавать сигнал?","options":["Не менее 25 футов","Не менее 50 футов","Не менее 100 футов","Не менее 200 футов"],"explanation":"In Texas, you must signal at least 100 feet before turning or changing lanes."},"47":{"q":"Какое ограничение скорости обычно установлено в школьной зоне?","options":["40 миль/ч","55 миль/ч","70 миль/ч","20 миль/ч"],"explanation":"The reduced school zone speed limit is commonly posted at 20 mph."},"48":{"q":"После обгона, когда можно безопасно вернуться на свою полосу?","options":["Когда вы видите обгоняемый автомобиль в зеркале заднего вида","Сразу после завершения обгона","Когда обгоняемый автомобиль сигналит","После ожидания 30 секунд"],"explanation":"You may return to your lane once you can see the passed vehicle in your rearview mirror."},"49":{"q":"В каком направлении нужно двигаться по кругу на кольцевой развязке?","options":["По часовой стрелке","Против часовой стрелки","В любом направлении","Прямо через центр"],"explanation":"In a roundabout, traffic moves around the circle counter-clockwise."},"50":{"q":"Насколько близко к пожарному гидранту можно парковаться?","options":["Без ограничений","5 футов","15 футов","50 футов"],"explanation":"You may not park within 15 feet of a fire hydrant."},"51":{"q":"Закон «Перестройся / Сбавь скорость» также защищает какой тип транспорта с мигающими огнями?","options":["Грузовики доставки","Школьные автобусы","Городские автобусы","Коммунальные машины"],"explanation":"The Move Over / Slow Down law also covers utility vehicles, along with emergency, tow, and TxDOT vehicles."},"52":{"q":"Какое самое высокое установленное ограничение скорости в Техасе?","options":["80–85 миль/ч","55 миль/ч","65 миль/ч","70 миль/ч"],"explanation":"Some specific Texas tollways are posted at 80 to 85 mph, the highest posted limits in the state."},"53":{"q":"Что нужно сделать перед поворотом направо на красный свет?","options":["Ускориться, чтобы быстро встроиться","Сначала полностью остановиться","Посигналить, чтобы предупредить других водителей","Выключить фары"],"explanation":"A right turn on red is allowed only after coming to a full stop, unless a sign prohibits it."},"54":{"q":"Какой формы знак зоны запрета обгона?","options":["Круглый","Квадратный","Вымпел (треугольный)","Ромбовидный"],"explanation":"A No Passing Zone is marked by a pennant-shaped (triangular) sign."},"55":{"q":"На Т-образном перекрёстке кто имеет преимущество проезда?","options":["Транспорт со стороны ножки буквы Т","Более быстрый автомобиль","Автомобиль слева","Транспорт на сквозной дороге"],"explanation":"Traffic on the through road (top of the T) has the right of way."},"56":{"q":"При парковке под уклон в какую сторону нужно повернуть передние колёса?","options":["К бордюру","От бордюра","Прямо","Это не имеет значения"],"explanation":"Turning the wheels toward the curb lets the curb block the vehicle if it rolls."},"57":{"q":"Согласно основному закону о скорости, может ли законный максимум быть ниже указанного на знаке числа?","options":["Нет, число на знаке всегда является законным максимумом","Да, когда условия делают указанную скорость небезопасной","Нет, только полиция может его снизить","Да, но только ночью"],"explanation":"The basic speed law requires a speed safe for conditions, so the legal limit can fall below the posted number when conditions make it unsafe."},"58":{"q":"При повороте налево кому вы должны уступить дорогу?","options":["Только встречным автомобилям","Только пешеходам","Встречным автомобилям и пешеходам","Никому"],"explanation":"A driver turning left must yield to both oncoming vehicles and pedestrians before completing the turn."},"59":{"q":"Согласно закону \"Уступи полосу / Снизь скорость\", какие два варианта есть у водителя при проезде мимо остановившегося аварийного автомобиля с мигающими огнями?","options":["Полностью остановиться или дважды посигналить","Включить аварийку или мигнуть дальним светом","Ускориться или сменить полосу","Перестроиться на одну полосу или снизить скорость до 20 миль/ч ниже лимита"],"explanation":"The Move Over / Slow Down law lets you move over one lane away or slow to 20 mph below the speed limit."}},"signals-and-markings":{"0":{"q":"Вы подъезжаете к перекрестку, и обращенный к вам сигнал светофора горит постоянным зеленым светом. Вы хотите повернуть налево через встречный поток, но несколько машин едут вам навстречу через перекресток. Что вам разрешено делать по закону?","options":["Проехать прямо или совершить поворот, но сначала уступить дорогу встречным машинам и любому транспорту, уже находящемуся на перекрестке.","Немедленно повернуть налево, потому что постоянный зеленый свет дает вам защищенный поворот, и встречный транспорт обязан вам уступить.","Полностью остановиться за линией и ждать, рассматривая зеленый как мигающий красный, пока встречные машины не проедут.","Сбросить скорость и проехать с осторожностью, не уступая дорогу, так как постоянный зеленый действует так же, как мигающий желтый."],"explanation":"A steady green means go only when the intersection is clear; you may proceed straight or turn, but you must yield to oncoming traffic and vehicles already in the intersection. Option B is the trap: only a green arrow gives a protected turn where oncoming traffic is stopped, not a steady green light."},"1":{"q":"Вы едете к перекрёстку с разрешённой скоростью, когда зелёный свет сменяется постоянным жёлтым. Вы всё ещё примерно в полуквартале от перекрёстка, и дорога позади вас свободна. Что вам следует сделать?","options":["Ускориться, чтобы проехать перекрёсток до того, как загорится красный","Остановиться перед перекрёстком, если это можно сделать безопасно, потому что свет вот-вот станет красным","Воспринять это как мигающий жёлтый и осторожно проехать, не останавливаясь","Полностью остановиться, а затем продолжить движение, когда путь свободен, как при мигающем красном"],"explanation":"A steady yellow light warns that the signal is about to turn red, so you should stop if you can do so safely and never speed up to beat the light. Option C describes a flashing yellow (caution) and Option D describes a flashing red (stop sign), which are different signals."},"2":{"q":"Вы приближаетесь к перекрёстку, и обращённый к вам светофор загорается постоянным красным, когда вы ещё находитесь на небольшом расстоянии от размеченной стоп-линии. Знака, запрещающего поворот, нет, и вы намереваетесь ехать прямо. Что вы обязаны сделать?","options":["Снизить скорость и осторожно проехать перекрёсток без остановки, поскольку сигнал скоро может смениться","Остановиться только при наличии поперечного движения, затем продолжить движение прямо на красный свет","Полностью остановиться за стоп-линией и оставаться на месте, пока сигнал не сменится на зелёный","Считать сигнал знаком «Стоп», полностью остановиться, затем ехать прямо, когда путь свободен"],"explanation":"Постоянный красный сигнал требует полностью остановиться за стоп-линией и оставаться на месте, пока сигнал не сменится на зелёный. Вариант D описывает мигающий красный сигнал (приравниваемый к знаку «Стоп»), а не постоянный красный, поэтому проезд прямо на постоянный красный неверен."},"3":{"q":"Вы находитесь в правой полосе и приближаетесь к перекрёстку с горящим красным сигналом светофора. Вы хотите повернуть направо. Знака, запрещающего поворот, нет, а в поперечном потоке есть просвет. Что вам следует сделать?","options":["Снизить скорость и повернуть направо без остановки, раз в поперечном потоке есть просвет","Рассматривать его как знак «Стоп», а затем поворачивать направо только когда загорится зелёная стрелка","Дождаться зелёного сигнала перед поворотом направо, потому что на красный поворачивать нельзя никогда","Полностью остановиться за линией, а затем повернуть направо, поскольку путь свободен и нет запрещающего знака"],"explanation":"At a steady red light you must stop completely behind the line, and a right turn is permitted only after that full stop when the way is clear and no sign prohibits it. Option A skips the required full stop, and option C wrongly claims right-on-red is never allowed."},"4":{"q":"Поздно ночью вы подъезжаете к перекрёстку, и расположенный над ним светофор мигает красным во всех направлениях. Другого транспорта поблизости нет. Что вы должны сделать?","options":["Полностью остановиться, а затем проехать перекрёсток, когда это будет безопасно.","Снизить скорость, посмотреть в обе стороны и проехать без остановки, раз путь свободен.","Остановиться и стоять, пока мигающий красный не сменится постоянным зелёным сигналом.","Считать это знаком «уступи дорогу» и проезжать только если приближается другой автомобиль."],"explanation":"A flashing red light means the same thing as a stop sign: you must come to a full stop and then proceed when it is safe. Option B is wrong because a flashing red always requires a complete stop (rolling through is the rule for a flashing yellow), and option C is wrong because a flashing red signal will not turn green."},"5":{"q":"Поздно ночью вы подъезжаете к перекрёстку, где светофор больше не работает в обычном режиме, а вместо этого показывает над вашей полосой постоянно мигающий ЖЁЛТЫЙ свет. Что вам следует сделать?","options":["Полностью остановиться за линией, а затем продолжить движение, когда путь свободен, как на знаке «Стоп».","Снизить скорость и осторожно проехать перекрёсток без остановки, следя за поперечным движением.","Считать перекрёсток равнозначным со всесторонней остановкой, потому что светофор работает не в обычном режиме.","Остановиться и оставаться на месте, пока светофор не вернётся к постоянному зелёному свету."],"explanation":"A flashing YELLOW light means caution, so you slow down and proceed carefully through the intersection without coming to a stop. A flashing RED light is the one that means a full stop like a stop sign, and a completely dark or non-working signal is the one treated as an all-way stop, so those are the wrong responses here."},"6":{"q":"Вы остановились на перекрёстке, ожидая поворота налево. Ваш сигнал был постоянным красным, но он только что сменился на зелёную СТРЕЛКУ поворота налево, указывающую в нужном вам направлении. О чём это говорит вам в плане того, как продолжать движение?","options":["Вы можете повернуть налево, но сначала должны уступить дорогу встречному транспорту, имеющему преимущество","Вы должны полностью остановиться и ждать, потому что сигнал в виде стрелки означает запрет поворота в этом направлении","Вы можете повернуть налево сейчас, и встречный транспорт остановлен, что даёт вам защищённый поворот","Вы можете повернуть налево только после снижения скорости для проверки, так как стрелка действует как мигающий жёлтый предупреждающий сигнал"],"explanation":"A green ARROW means a protected turn in the arrow's direction, so oncoming traffic is being held by a red light and you may turn without yielding. Option A describes a steady green light (a permitted turn requiring you to yield), and option B incorrectly describes a red arrow, so both are wrong."},"7":{"q":"Вы находитесь в полосе для левого поворота на оживлённом перекрёстке и ждёте, чтобы повернуть налево. Сигнал для вашей полосы показывает горящую красную СТРЕЛКУ, направленную влево, в то время как обычный круглый сигнал для движения прямо горит зелёным. Что вам следует сделать?","options":["Осторожно повернуть налево, поскольку зелёный свет для полос движения прямо означает, что встречный транспорт имеет защищённую остановку","Рассматривать красную стрелку как мигающий красный и совершить левый поворот после полной остановки","Совершить левый поворот, уступив встречному транспорту, поскольку левые повороты на красной стрелке всегда разрешены при отсутствии помех","Оставаться на месте и ждать, потому что красная стрелка означает, что поворот в этом направлении запрещён, пока сигнал не сменится"],"explanation":"A red arrow means no turn is allowed in the direction it points, so you must wait until the signal changes, regardless of what the round signal for other lanes shows. A red arrow is not the same as a flashing red, and there is no 'turn after yielding' permitted on a steady red arrow."},"8":{"q":"Вы подъезжаете к оживлённому перекрёстку с четырьмя направлениями во время отключения электричества. Светофоры полностью погасли и совсем не работают. Что вам следует сделать?","options":["Считать перекрёсток равнозначным со знаком STOP во всех направлениях: остановиться и уступить дорогу по очереди, прежде чем продолжить движение","Снизить скорость и осторожно проехать перекрёсток, не останавливаясь","Считать, что у вашего направления есть преимущество, и продолжать движение с обычной скоростью","Останавливаться только если на перекрёстке уже есть автомобиль, иначе продолжать движение"],"explanation":"A dark or non-working signal must be treated as an all-way STOP, so every driver stops and yields in turn. Slowing without stopping (B) is the rule for a flashing yellow light, not a dead signal, and the other options wrongly assume right of way."},"9":{"q":"Вы остановились на зелёный свет и хотите повернуть направо на боковую улицу. На пешеходном светофоре, обращённом к пешеходному переходу, который вы собираетесь пересечь, горит постоянный белый символ идущего человека. Что этот символ говорит вам о людях на углу?","options":["Пешеходы должны ждать, поэтому вы можете повернуть, не проверяя пешеходный переход","Пешеходы могут законно начать переход, поэтому вы должны уступить им дорогу перед поворотом","Пешеходы могут только закончить переход, но не могут начинать, поэтому их на переходе будет немного","Пешеходный переход закрыт для пешеходов и предназначен для поворачивающих автомобилей"],"explanation":"A WALK signal or walking-person symbol means pedestrians may cross, so they have the right of way and you must yield before turning. Option C describes a flashing DON'T WALK/raised hand (finish but don't start), not the steady walking-person symbol."},"10":{"q":"Вы подъезжаете к перекрёстку в центре города и останавливаетесь на красный свет. Ожидая, вы видите, как пешеходный сигнал через дорогу переключается с мигающего символа поднятой руки на постоянный символ поднятой руки, в то время как человек всё ещё стоит на вашем углу. Что эта постоянная поднятая рука говорит этому пешеходу делать?","options":["Это значит, что ему следует поспешить и закончить переход до смены сигнала","Это значит, что переход закрыт и нужно использовать другой перекрёсток","Это значит, что он не должен начинать переходить улицу","Это значит, что можно начинать переход, потому что начинается фаза ИДИТЕ"],"explanation":"A steady DON'T WALK signal or steady raised-hand symbol means do not start to cross. The flashing raised hand (option A) is what tells someone already in the crosswalk to finish crossing, but a steady hand means do not begin."},"11":{"q":"Вы остановились на зелёный свет, ожидая поворота направо на городской улице. Пешеход сходит с тротуара на пешеходный переход, который вам нужно пересечь, как раз в тот момент, когда обращённый к нему светофор начинает показывать мигающий символ поднятой руки (НЕ ИДИТЕ). Что этот мигающий сигнал говорит вам о законном праве пешехода находиться на переходе?","options":["Пешеход должен немедленно остановиться и вернуться на тротуар, поэтому вы можете поворачивать, как только он отступит назад","Мигающая рука означает то же, что и постоянная рука, поэтому пешеход не имел права входить, и вы можете продолжать движение","Мигающая рука — это только предупреждение, как мигающий жёлтый свет, поэтому и пешеход, и вы можете двигаться одновременно","Пешеход, уже находящийся на переходе, может закончить переход; мигающая рука означает лишь то, что никто новый не должен начинать переходить"],"explanation":"A flashing DON'T WALK or flashing raised-hand symbol means anyone already in the crosswalk should finish crossing, while no new pedestrian should start; you must yield until they finish. The steady-hand meaning (B) and the flashing-yellow caution rule (C) are real facts placed in the wrong context."},"12":{"q":"Вы едете по многополосному шоссе, где над каждой полосой висят сигналы использования полос. Над полосой, на которую вы хотите перестроиться, вы видите постоянную зелёную стрелку вниз. О чём это говорит вам относительно этой полосы?","options":["Полоса открыта, и вы можете по ней ехать","Полоса закрыта, и вы должны её покинуть","Полоса меняет назначение, поэтому покиньте её, прежде чем она закроется","Полоса предназначена только для автомобилей HOV или с пассажирами"],"explanation":"A lane-use green down-arrow means the lane is open for travel, so you may drive in it. A red X means the lane is closed and a yellow X means the lane is changing use and you should move out of it, but neither of those signals is shown here."},"13":{"q":"Вы едете по многополосному шоссе и смотрите на расположенные над дорогой сигналы управления полосами. Над вашей полосой горит постоянный красный крест (X), а на полосе справа от вас горит постоянная зелёная стрелка вниз. Что вам следует сделать?","options":["Оставаться на своей полосе и ехать осторожно, так как красный крест просто предупреждает о приближающейся опасности","Перестроиться на полосу справа, потому что красный крест означает, что ваша полоса закрыта, а зелёная стрелка вниз означает, что та полоса открыта","Полностью остановиться на своей полосе и ждать, расценивая красный крест как мигающий красный сигнал","Оставаться на своей полосе, но немедленно покинуть её, потому что красный крест означает, что полоса меняет назначение"],"explanation":"A lane-use red X means the lane is closed, so you must leave it, and a green down-arrow means the lane beneath it is open for travel. The trap options confuse the red X with a flashing red (stop) signal or with a yellow X, which is the signal that means the lane is changing use and you should move out of it."},"14":{"q":"Вы едете по средней полосе на многополосной дороге, когда сигнал использования полосы над вашей полосой меняется на постоянный жёлтый X. Что означает этот сигнал — что вы должны сделать?","options":["Немедленно остановиться в полосе, потому что жёлтый X работает как постоянный красный сигнал сверху","Остаться в полосе, но замедлиться почти до остановки, так как жёлтый X лишь предупреждает о заторе впереди","Приготовиться безопасно покинуть полосу, потому что полоса меняет назначение и вот-вот закроется для вашего направления","Продолжать движение как обычно, потому что жёлтый X просто подтверждает, что полоса открыта для сквозного движения"],"explanation":"An overhead lane-use yellow X means the lane is changing use, so you should prepare to safely move out of it before it closes. Stopping in the lane (A) is wrong because a yellow X is not a red light, and continuing as if the lane is open (D) confuses it with a green down-arrow, which is the signal for an open lane."},"15":{"q":"Вы едете по двухполосному загородному шоссе позади медленного трактора. Вы хотите его обогнать, но замечаете сплошную жёлтую линию, нанесённую по центру с вашей стороны дороги. Что эта разметка говорит вам об обгоне в этом месте?","options":["Вы можете обгонять, потому что жёлтые линии всегда разрешают обгон, когда дорога свободна","Вы можете обгонять только при наличии рядом прерывистой белой линии","Обгон разрешён в обоих направлениях, поскольку линия жёлтая","Вы не должны обгонять; сплошная жёлтая линия с вашей стороны означает, что обгон запрещён"],"explanation":"A solid yellow line on your side of the centerline means no passing, so you must stay behind the tractor until the marking changes. Option A confuses this with a broken yellow line (passing allowed when safe), and the white-line and both-directions ideas do not apply to a solid yellow line on your side."},"16":{"q":"Вы едете по двухполосному сельскому шоссе за медленным трактором. По центру дороги с вашей стороны нанесена прерывистая (пунктирная) жёлтая линия, дорога впереди прямая с хорошей видимостью, встречного транспорта не видно. Что эта дорожная разметка говорит вам об обгоне трактора?","options":["Обгон разрешён, когда это безопасно, поэтому вы можете пересечь линию, чтобы обогнать трактор","Обгон запрещён с вашей стороны, потому что любая жёлтая линия означает запрет обгона","Вы можете пересекать линию только для поворота налево, но не для обгона","Обгон разрешён только по правой обочине, никогда через центральную линию"],"explanation":"A broken (dashed) yellow line on your side of the center means passing is permitted when it is safe to do so, which it is here with clear visibility and no oncoming traffic. The trap in B confuses this with a solid yellow line (no passing), and the turn-only restriction in C applies to a double solid yellow line."},"17":{"q":"Вы едете по двухполосной дороге и попадаете на участок, где по центру нанесены две сплошные жёлтые линии рядом друг с другом. Впереди вас медленно едет трактор, и дорога свободна в обоих направлениях. Слева от вас есть выезд, куда вы могли бы повернуть. Что разрешает вам эта разметка?","options":["Обогнать трактор, потому что дорога свободна в обоих направлениях и вам далеко видно впереди","Оставаться на своей полосе и не обгонять, но вы можете пересечь линии, чтобы повернуть налево к выезду","Обогнать трактор, поскольку двойная сплошная жёлтая линия ограничивает обгон только для встречного направления","Свободно пересекать линии для обгона, потому что сплошная жёлтая лишь не рекомендует пересечение, но не запрещает его"],"explanation":"A double solid yellow line means no passing in either direction, so you must stay in your lane, but you may still cross it to turn (such as into a driveway). Passing is never allowed here regardless of visibility, and the rule applies to both directions, not just oncoming traffic."},"18":{"q":"Вы едете по многополосному шоссе, где весь поток движется в одном направлении. Вы замечаете линию, нанесённую между вашей полосой и полосой непосредственно справа от вас. Какого цвета, скорее всего, эта линия?","options":["Жёлтого, потому что жёлтые линии всегда обозначают края каждой полосы","Жёлтого, потому что линия предупреждает, что обгон здесь запрещён","Белого, потому что белые линии разделяют полосы движения транспорта, движущегося в одном направлении","Двойного сплошного жёлтого, потому что она не даёт перестроиться в соседнюю полосу"],"explanation":"White lines separate lanes of traffic that travel in the same direction, so the line between two same-direction lanes is white. Yellow lines are used to separate traffic moving in opposite directions or to mark no-passing zones, which does not apply here."},"19":{"q":"Вы едете по многополосной дороге, где весь транспорт движется в одном направлении. Полоса слева отделена от вашей прерывистой (пунктирной) белой линией. Транспорт впереди на вашей полосе замедляется, а левая полоса свободна. Что эта разметка говорит вам о перестроении на левую полосу?","options":["Вам нельзя её пересекать; белая линия всегда означает, что вы должны оставаться на своей полосе","Пересечение разрешено только для поворота, как если бы это была двойная сплошная жёлтая линия","Обгон здесь разрешён только потому, что линия разделяет встречные потоки","Вы можете перестроиться через неё, когда путь свободен и это безопасно"],"explanation":"A broken white line separates lanes going the same direction and permits a lane change when it is safe, so moving into the clear left lane is allowed. Option A describes a solid white line, and option B describes a double solid yellow line, so both apply the wrong marking's rule here."},"20":{"q":"Вы едете по четырёхполосному шоссе, где все полосы движутся в одном направлении. Приближаясь к въездной рампе на автомагистраль, вы видите, что одна сплошная белая линия отделяет вашу полосу от полосы справа. Вы хотели бы перестроиться на ту полосу, чтобы занять более удобное положение. О чём говорит вам эта разметка?","options":["Оставайтесь на своей полосе; пересекать сплошную белую линию не рекомендуется","Вы можете свободно перестраиваться в правую полосу, когда она свободна","Обгон запрещён в обоих направлениях, как при двойной сплошной линии","Это обозначает правый край проезжей части, поэтому не выезжайте за него"],"explanation":"A solid white line separates lanes going the same direction and means stay in your lane, as crossing it is discouraged. A broken white line is what allows a free lane change (option B), and a solid white edge line marks the road's right edge (option D), so those facts are placed here in the wrong context."},"21":{"q":"Вы едете ночью по незнакомому сельскому шоссе с плохой видимостью. Справа от себя вы замечаете сплошную белую линию вдоль покрытия, параллельную направлению вашего движения. О чём говорит вам эта линия?","options":["Она обозначает центр дороги, и её нельзя пересекать для обгона","Она обозначает правый край дороги, помогая вам держаться на покрытии","Она обозначает левый край дороги на улице с односторонним движением","Она указывает на велосипедную полосу, по которой нельзя ездить"],"explanation":"A solid white edge line marks the right edge of the road, which is especially useful for staying on the pavement at night or in poor visibility. The trap in C confuses edge colors: a yellow line marks the left edge, while white marks the right edge."},"22":{"q":"Вы едете ночью по незнакомой двусторонней дороге. Фары освещают сплошную желтую линию вдоль крайней левой стороны вашей полосы, прямо на границе покрытия. О чем говорит вам эта линия?","options":["Она обозначает правый край дороги, поэтому покрытие заканчивается слева от вас","Это линия запрета обгона, поэтому вы не должны пересекать центр дороги для обгона","Она обозначает левый край дороги, поэтому показывает, где заканчивается покрытие слева от вас","Она разделяет полосы движения, идущие в том же направлении, что и вы"],"explanation":"A yellow edge line marks the left edge of the roadway, showing the driver where the pavement ends on the left side. The line being yellow does not make it a center no-passing line, and the right edge of the road is marked with a solid white line, not yellow."},"23":{"q":"Вы подъезжаете к перекрёстку на красный сигнал светофора. Перед пешеходным переходом вы замечаете широкую белую линию, нанесённую поперёк вашей полосы. Где вы должны полностью остановить автомобиль?","options":["На самой широкой белой линии, чтобы бампер был вровень с ней","Сразу за широкой белой линией, но перед въездом на пешеходный переход","В любом месте перекрёстка, лишь бы полностью остановиться до зелёного сигнала","Перед широкой белой линией, которая является стоп-линией, обозначающей место остановки"],"explanation":"The wide white line is a stop line, and you must stop behind it, not on or beyond it. Stopping on the line or past it into the crosswalk blocks pedestrians and is incorrect even though you are technically stopped."},"24":{"q":"Подъезжая к перекрёстку на зелёный сигнал, вы видите белую разметку поперёк дороги и пешехода, ступающего на неё. Где вы должны остановиться?","options":["Перед белой разметкой пешеходного перехода, чтобы пропустить пешехода","Поверх разметки пешеходного перехода, пока вы оставляете место для пешехода","Где угодно, ведь зелёный сигнал означает, что у вас всегда преимущество","За символом ромба, нарисованным на полосе"],"explanation":"A crosswalk is marked by white lines for pedestrians, and you must stop before it to let them cross safely. Stopping on top of it blocks the pedestrian, and a green light still requires yielding to people already in the crosswalk; the diamond symbol marks an HOV/carpool lane, not a stopping point."},"25":{"q":"Вы едете в одиночку по техасской автомагистрали в час пик. На крайней левой полосе через равные промежутки нанесены большие символы-ромбы. Что эта разметка говорит вам об этой полосе?","options":["Это велосипедная полоса, поэтому по ней нельзя ездить или парковаться","Это зарезервированная полоса HOV/для совместных поездок или специального назначения, по которой вам в одиночку может быть запрещено ехать","Она закрыта для всего движения, так же как при сигнале красного X над полосой","Это краевая полоса, и ромбы обозначают, где заканчивается дорожное покрытие"],"explanation":"A diamond symbol painted in a lane marks a reserved HOV/carpool or special-use lane, which often requires a minimum number of occupants, so driving alone may not be permitted. A bike lane is marked differently, and a closed lane is shown by an overhead red X, not pavement diamonds."},"26":{"q":"Вы опаздываете и замечаете свободный участок дорожного покрытия справа от обычной полосы движения. Он отделён сплошной белой линией и имеет нарисованный символ велосипеда, но в данный момент в нём нет велосипедистов. Что вам следует сделать?","options":["Ехать по нему, чтобы обогнать медленный поток, ведь сейчас он пуст","Заехать в него и припарковаться, пока ждёте, когда рассосётся движение","Полностью держаться от него подальше; это велосипедная полоса, предназначенная для велосипедов, а не для движения или парковки","Использовать его как полосу для автомобилей с пассажирами, раз у вас в машине есть пассажиры"],"explanation":"A lane marked with a bicycle symbol is a bike lane reserved for bicycles, and you must not drive or park in it even when no cyclists are present. Options A and B are the trap (driving and parking are both prohibited), and D confuses the bike lane with an HOV/carpool lane, which is marked with a diamond symbol instead."},"27":{"q":"Вы опаздываете, и вам нужно оставить машину на несколько минут. Единственное свободное место — вдоль бордюра, окрашенного в сплошной жёлтый цвет, при этом рядом нет никаких знаков. Что этот жёлтый бордюр говорит вам о парковке в этом месте?","options":["Парковка разрешена, потому что нет установленного знака, запрещающего её","Он обозначает левый край проезжей части, поэтому парковка разрешена справа от него","Он зарезервирован только для машин с пассажирами (HOV) или для совместных поездок","Он указывает на запрет парковки или ограничение для погрузки, поэтому здесь парковаться нельзя"],"explanation":"A yellow curb signals a no-parking or loading restriction even when no sign is present, though exact meanings can vary by city, so you should not leave your car there. The left-edge yellow line refers to roadway center markings, not curbs, and HOV reservations are shown by a diamond symbol in a lane, not by a painted curb."},"28":{"q":"Вы едете по незнакомой дороге, и на покрытии впереди виден большой нарисованный символ «RXR», за которым следует широкая белая линия поперёк вашей полосы. Шлагбаум ещё поднят, но вы слышите гудок поезда и видите приближающийся состав. Что вам следует сделать?","options":["Остановиться за белой линией и ждать, потому что RXR обозначает железнодорожный переезд, и вы обязаны остановиться при приближении поезда","Считать белую линию необязательной и медленно проехать через переезд, ведь шлагбаум ещё поднят, а поезд можно опередить","Останавливаться только если бы линия была жёлтой, ведь жёлтая линия с вашей стороны означает запрет обгона","Проехать без остановки, потому что символ ромба означает специальную полосу для пересекающего движения"],"explanation":"The large RXR painted on the pavement marks a railroad crossing, and the wide white line is a stop line; you must stop behind it when a train is approaching. The traps misuse other real facts: a solid yellow line means no passing, and a diamond marks an HOV/special-use lane, neither of which applies at a railroad crossing."},"29":{"q":"Вы остановились на перекрестке в ожидании поворота налево, когда ваш сигнал светофора загорается постоянным зеленым. Встречный автомобиль приближается с противоположной стороны и находится близко к перекрестку. Что вам следует сделать?","options":["Немедленно повернуть налево, поскольку постоянный зеленый сигнал дает вам право проехать раньше встречного транспорта.","Уступить дорогу встречному автомобилю, а затем завершить поворот налево, когда это будет безопасно.","Дождаться зеленой стрелки, поскольку постоянный зеленый сигнал не разрешает поворот налево.","Полностью остановиться за линией и продолжить движение только после того, как встречный автомобиль проедет, так как постоянный зеленый требует сначала остановиться."],"explanation":"At a steady green light you may proceed or turn, but you must first yield to oncoming traffic and pedestrians rather than turn without regard to other vehicles. A green arrow gives a protected turn and a stop is required only at red or yellow, so options C and D misapply other signal rules."},"30":{"q":"Вы приближаетесь к перекрестку с разрешенной скоростью, когда сигнал меняется с зеленого на постоянный желтый. Впереди достаточно расстояния, чтобы безопасно остановиться перед линией. Что вам следует сделать?","options":["Ускориться и проехать перекресток, чтобы успеть до того, как загорится красный","Останавливаться только если об этом говорит знак, иначе сохранять скорость и проезжать на желтый","Снизить скорость и безопасно остановиться за линией, потому что желтый предупреждает, что скоро будет красный","Считать желтый как мигающий желтый и проехать с осторожностью без остановки"],"explanation":"A steady yellow means the light is about to turn red, so you should stop if you can do so safely rather than speed up to beat the light. Accelerating through (A) is the exact mistake the yellow warns against, and a flashing yellow (D) is a different signal that means caution and does not require stopping."},"31":{"q":"Поздно ночью вы приближаетесь к перекрёстку, когда светофор в вашем направлении переключается на мигающий жёлтый сигнал. Поперечного движения не видно. Что вам следует сделать?","options":["Полностью остановиться за стоп-линией, затем продолжить движение, когда перекрёсток свободен","Полностью остановиться, считать это перекрёстком со всесторонней остановкой и уступить дорогу любому транспортному средству справа","Ускориться, чтобы проехать перекрёсток до того, как загорится красный","Снизить скорость и осторожно проехать перекрёсток без остановки"],"explanation":"A flashing yellow light means caution: you slow down and proceed carefully without needing to stop. A full stop is required at a flashing red (which is treated like a stop sign), so options requiring a complete stop confuse the flashing red rule with the flashing yellow."},"32":{"q":"Вы едете по незнакомой двухполосной дороге в сумерках. Линия посередине дороги, отделяющая вашу полосу от соседней, жёлтая. О чём этот цвет говорит вам относительно движения на полосе по другую сторону этой линии?","options":["Движение идёт в противоположном направлении, навстречу вам","Движение идёт в том же направлении, что и у вас","Это полоса, зарезервированная для HOV или совместных поездок (carpool)","Это правый край проезжей части"],"explanation":"Yellow center lines separate traffic moving in opposite directions, so the lane across a yellow line carries oncoming traffic. White lines, not yellow, separate traffic moving in the same direction, which makes B the trap."},"33":{"q":"Вы подходите к пешеходному переходу и хотите перейти улицу. Когда вы доходите до бордюра, пешеходный сигнал переключается на мигающий DON'T WALK / поднятую ладонь. Что это означает для вас?","options":["Не начинайте переход сейчас, но если вы уже на переходе, вы должны вернуться к бордюру, от которого пошли","Не начинайте переход сейчас; продолжать и закончить переход должны только те, кто уже находится на переходе","Вы можете начать переход, потому что мигание означает осторожность, как мигающий жёлтый сигнал","Вы можете осторожно начать переход, но только после того, как сначала остановитесь у края перехода"],"explanation":"A flashing DON'T WALK warns pedestrians not to begin crossing; those already in the crosswalk should finish crossing. Option C wrongly borrows the flashing-yellow 'caution, proceed' meaning, and A invents a rule about turning back that the handbook does not state."},"34":{"q":"Вы остановились на красный свет, намереваясь повернуть направо. На перекрёстке вы видите знак с надписью 'ПОВОРОТ НА КРАСНЫЙ ЗАПРЕЩЁН' (NO TURN ON RED). После полной остановки и убедившись, что встречного и поперечного движения нет, что вам следует сделать?","options":["Повернуть направо, потому что полная остановка выполняет требование закона для поворота направо на красный","Медленно повернуть направо, так как полоса свободна и вы правильно уступили дорогу","Оставаться на месте и дождаться зелёного света, прежде чем поворачивать направо","Воспринять красный свет как мигающий красный и проехать, как только движение освободится"],"explanation":"When a posted sign prohibits turning right on red, you may not turn regardless of stopping or a clear path, so you must wait for the green light. Stopping fully only permits a right on red when no sign forbids it, and a steady red is never treated like a flashing red."},"35":{"q":"Вы готовитесь к экзамену на водительские права в Техасе и хотите убедиться, что конкретное правило дорожной разметки, которое вы прочитали в интернете, действительно верно и применяется в Техасе сейчас. Чтобы подтвердить, каковы официальные правила на самом деле, на какой источник вам следует опираться?","options":["На то, с чем согласно большинство онлайн-сайтов с тестами по вождению, поскольку они обобщают правила многих штатов","Только на федеральный MUTCD, поскольку национальные стандарты полностью заменяют любые правила, специфичные для Техаса","На справочник водителя соседнего штата, поскольку дорожная разметка одинакова во всех штатах США","На Руководство водителя Техаса (DPS, DL-7) вместе с национальными стандартами MUTCD, действующими в Техасе"],"explanation":"The authoritative source of truth is the Texas Driver Handbook (DPS, DL-7) combined with the MUTCD national standards that apply in Texas. The MUTCD alone is not enough because it works together with the state handbook, and quiz sites or another state's handbook are not official Texas sources."},"36":{"q":"Вы едете по двухполосной дороге, по центру которой проходит двойная сплошная жёлтая линия. Впереди вас медленный трактор, а сразу за ним вы видите въезд, где вам нужно повернуть налево на парковку. Что вам по закону разрешено делать с этой двойной сплошной жёлтой линией?","options":["Пересечь её, чтобы повернуть налево на парковку, но не для обгона трактора","Пересечь её, чтобы обогнать трактор, так как полоса впереди свободна","Свободно пересекать её, потому что двойная жёлтая линия касается только встречного движения","Считать её прерывистой жёлтой линией и обгонять, когда это безопасно"],"explanation":"A double solid yellow line means no passing in either direction; you may cross it only to make a turn, such as turning left into a driveway or parking lot. Passing the tractor (B and D) is prohibited, and the line applies to drivers on both sides, not just oncoming traffic (C)."},"37":{"q":"Вы подъезжаете к железнодорожному переезду, обозначенному большим символом RXR и широкой белой стоп-линией, нанесённой на дорожное покрытие. Мигающих огней и шлагбаумов нет, поезда не видно, и вы ясно видите и слышите, что ни один не приближается. Что вам следует сделать?","options":["Полностью остановиться у стоп-линии и ждать, поскольку каждый железнодорожный переезд требует полной остановки","Проехать через пути без остановки, но быть готовым остановиться у обозначенной стоп-линии, если приближается поезд","Снизить скорость и воспринимать переезд как перекрёсток со знаком «стоп» для всех направлений, сначала уступив дорогу транспорту справа","Ненадолго остановиться на путях, чтобы посмотреть в обе стороны, прежде чем продолжить движение"],"explanation":"At this type of railroad crossing you stop only if a train is approaching, and the stop must be made at the marked stop line; with no train coming you may proceed across without stopping. Option A is wrong because a stop is not required at every crossing when no train is near, and stopping on the tracks (D) is always dangerous."},"38":{"q":"Вы едете по многополосной автомагистрали и замечаете, что сигнал над вашей полосой меняется с зелёной стрелки вниз на постоянный жёлтый крест (X). Что это означает и что вам следует сделать?","options":["Ваша полоса теперь закрыта только для остановившегося транспорта; полностью остановитесь в пределах полосы и ждите.","Это предупреждающий сигнал, как мигающий жёлтый свет; сбавьте скорость, но оставайтесь на своей полосе.","Назначение вашей полосы меняется; безопасно перестройтесь из этой полосы в открытую полосу, обозначенную зелёной стрелкой вниз.","Впереди переходят пешеходы; оставайтесь на своей полосе и уступайте дорогу, пока сигнал не изменится."],"explanation":"A yellow X overhead lane-control signal means the lane is changing use and you should move out of it safely, while a green down-arrow marks a lane that is open. The caution answer confuses this with a flashing yellow traffic light, which applies to intersections, not overhead lane control."},"39":{"q":"Вы ждёте на перекрёстке в полосе для поворота налево. Сигнал перед вами показывает постоянную зелёную СТРЕЛКУ влево вместе с постоянным красным светом для полос прямого движения. Почему вы можете начать поворот налево, не уступая встречному транспорту?","options":["Потому что зелёная стрелка означает, что сначала нужно полностью остановиться, а затем поворачивать только если путь свободен","Потому что зелёная стрелка лишь предупреждает, поэтому следует снизить скорость и уступить встречным машинам перед поворотом","Потому что у встречного транспорта мигающий жёлтый сигнал, говорящий им осторожно проезжать перекрёсток","Потому что зелёная стрелка даёт защищённый поворот: встречный транспорт стоит на красный сигнал и остановлен во время действия стрелки"],"explanation":"A green arrow grants a protected turn in the arrow's direction because oncoming traffic faces a red signal and is stopped, so you may turn without yielding. A green arrow is not a stop-and-go or caution signal, and oncoming drivers are stopped by red, not waved through by a flashing yellow."}},"learn-signals-and-markings":{"0":{"q":"Что означает постоянный зелёный сигнал светофора?","options":["Двигайтесь, если перекрёсток свободен","Полностью остановитесь за линией","Снизьте скорость и остановитесь, если безопасно","Считайте это знаком \"Стоп\""],"explanation":"A steady green light means you may go if the intersection is clear, proceeding straight or turning after yielding."},"1":{"q":"Что нужно сделать перед поворотом на постоянный зелёный свет?","options":["Ускориться, чтобы быстрее завершить поворот","Уступить дорогу другим машинам и пешеходам","Всегда сначала полностью остановиться","Дождаться появления зелёной стрелки"],"explanation":"At a steady green light you may turn only after yielding to other traffic and pedestrians."},"2":{"q":"Что означает постоянный желтый сигнал светофора?","options":["Ускориться, чтобы проехать перекресток","Светофор только что загорелся зеленым","Сигнал скоро сменится на красный","У вас преимущественное право проезда"],"explanation":"A steady yellow light warns that the signal is about to turn red, so stop if you can do so safely."},"3":{"q":"Что нужно делать при постоянном желтом сигнале светофора?","options":["Ускориться, чтобы успеть до красного","Всегда полностью останавливаться","Игнорировать его и продолжать движение","Остановиться, если это можно сделать безопасно"],"explanation":"A steady yellow light means the light is about to turn red, so stop if you can do so safely and do not speed up."},"4":{"q":"Что означает постоянный красный свет?","options":["Полностью остановиться, пока не загорится зелёный","Снизить скорость и проехать осторожно","Ускориться, чтобы освободить перекрёсток","Ехать, если перекрёсток свободен"],"explanation":"A steady red light means stop completely behind the line and stay stopped until the light turns green."},"5":{"q":"На красный свет, где разрешён поворот направо, что нужно сделать в первую очередь?","options":["Ускориться и повернуть направо","Полностью остановиться, затем повернуть, если путь свободен","Повернуть, не останавливаясь","Ждать зелёную стрелку"],"explanation":"At a red light where right turns are permitted, you must stop completely, then turn right if it is clear and not prohibited by a sign."},"6":{"q":"Что нужно делать на мигающий красный сигнал?","options":["Ускориться, чтобы проехать","Снизить скорость, но не останавливаться","Полностью остановиться, затем ехать, когда безопасно","Игнорировать, если рядом нет машин"],"explanation":"A flashing red light means the same as a stop sign: stop fully, then go when it is safe."},"7":{"q":"Что означает мигающий жёлтый сигнал светофора?","options":["Полностью остановиться, затем ехать","Сигнал скоро сменится на красный","Полоса впереди закрыта","Осторожно: снизьте скорость и проезжайте внимательно"],"explanation":"A flashing yellow light means caution, so slow down and proceed carefully without stopping."},"8":{"q":"Что означает сигнал в виде зелёной стрелки?","options":["Защищённый поворот в направлении стрелки","Остановиться и ждать следующего сигнала","Снизить скорость и уступить встречному транспорту","Поворот в этом направлении запрещён"],"explanation":"A green arrow means a protected turn in the arrow's direction, and oncoming traffic is stopped."},"9":{"q":"Что означает сигнал красной стрелки?","options":["Поверните сейчас, если путь свободен","Поворот в эту сторону запрещён; ждите","Ускорьтесь, чтобы быстро повернуть","Поворот только для грузовиков"],"explanation":"A red arrow means no turn is allowed in that direction, so you must wait."},"10":{"q":"Как следует относиться к погасшему или неработающему светофору?","options":["Проехать на скорости","Считать его зелёным светом","Считать его перекрёстком со знаком «стоп» для всех направлений","Игнорировать перекрёсток"],"explanation":"A dark or non-working signal should be treated as an all-way stop."},"11":{"q":"Что означает сигнал WALK («Идите»)?","options":["Машины должны ускориться","Велосипеды должны остановиться","Водители могут повернуть налево","Пешеходы могут переходить"],"explanation":"A WALK signal or walking-person symbol means pedestrians may cross."},"12":{"q":"Что означает постоянный сигнал DON'T WALK (\"Не идти\") или постоянный символ поднятой руки?","options":["Не начинать переход","Начать переход сейчас","Переходить только бегом","Прекратить движение автомобиля"],"explanation":"A steady DON'T WALK signal or steady raised-hand symbol means pedestrians should not start to cross."},"13":{"q":"Что означает мигающий сигнал \"НЕ ИДИТЕ\" или поднятая ладонь?","options":["Сразу начинайте переходить улицу","Закончите переход, если уже начали, но не начинайте","Быстро перебегите улицу","Переходите, только если машина пропускает вас"],"explanation":"A flashing DON'T WALK means finish crossing if you have already started, but do not begin to cross."},"14":{"q":"Что означает зеленая стрелка вниз на сигнале использования полосы?","options":["Полоса закрыта","Уйдите с этой полосы","Полоса открыта","Снизьте скорость и остановитесь"],"explanation":"A green down-arrow on a lane-use signal means the lane is open."},"15":{"q":"Что означает красный знак X на сигнале использования полосы?","options":["Полоса открыта","Снизьте скорость на полосе","Скоро покиньте полосу","Полоса закрыта"],"explanation":"A red X on a lane-use signal means the lane is closed."},"16":{"q":"На сигнале использования полосы, что означает желтый знак X над вашей полосой?","options":["Полоса меняет назначение, покиньте ее","Полоса открыта, вы можете ее использовать","Полоса закрыта, никогда не используйте ее","Остановитесь и ждите на полосе"],"explanation":"A yellow X means the lane is changing use, so you should move out of it."},"17":{"q":"Что означает сплошная жёлтая линия на вашей стороне дороги?","options":["Обгон разрешён","Обгон запрещён","Полоса закрыта","Впереди остановка"],"explanation":"A solid yellow line on your side of the road means you may not pass."},"18":{"q":"Что означает прерывистая (пунктирная) жёлтая линия?","options":["Обгон запрещён","Остановитесь и ждите","Обгон разрешён, когда это безопасно","Полоса закрыта"],"explanation":"A broken (dashed) yellow line means passing is allowed when it is safe to do so."},"19":{"q":"Что означает двойная сплошная жёлтая линия?","options":["Обгон разрешён в обе стороны","Полосы идут в одном направлении","Можно обгонять, когда свободно","Обгон запрещён в обе стороны"],"explanation":"A double solid yellow line means no passing in either direction; do not cross it except to turn."},"20":{"q":"Что разделяют белые линии на дороге?","options":["Полосы движения в одном направлении","Полосы движения в противоположных направлениях","Парковочные места","Только велосипедные дорожки"],"explanation":"White lines separate lanes of traffic traveling in the same direction."},"21":{"q":"Что означает прерывистая белая линия?","options":["Обгон запрещён","Смена полосы разрешена","Впереди край дороги","Остановитесь и ждите здесь"],"explanation":"A broken white line means you may change lanes when it is safe."},"22":{"q":"Что означает сплошная белая линия?","options":["Вы можете обгонять другие машины","Перестроение разрешено","Оставайтесь на своей полосе","Движение идёт в обратном направлении"],"explanation":"A solid white line means stay in your lane; crossing it is discouraged."},"23":{"q":"Что разделяют жёлтые линии на дороге?","options":["Транспорт, движущийся в одном направлении","Велодорожки от автомобильных полос","Парковочные места","Транспорт, движущийся в противоположных направлениях"],"explanation":"Yellow lines separate traffic moving in opposite directions, while white lines separate traffic moving in the same direction."},"24":{"q":"Что обозначает сплошная белая краевая линия?","options":["Правый край дороги","Левый край дороги","Центр дороги","Зону обгона"],"explanation":"A solid white edge line marks the right edge of the road."},"25":{"q":"Что обозначает желтая краевая линия на дороге?","options":["Правый край дороги","Левый край дороги","Центр велосипедной полосы","Пешеходный переход"],"explanation":"A yellow edge line marks the left edge of the road."},"26":{"q":"Что такое стоп-линия?","options":["Линия для перехода пешеходов","Линия, обозначающая велосипедную полосу","Широкая белая линия, показывающая, где остановиться","Линия, разделяющая встречное движение"],"explanation":"A stop line is a wide white line that shows where to stop, and you must stop behind it."},"27":{"q":"Что означает пешеходный переход, обозначенный белыми линиями?","options":["Он обозначает край дороги","Это полоса для совместных поездок","Он закрыт для движения","Он для пешеходов; остановитесь перед ним"],"explanation":"A crosswalk has white markings for pedestrians, and you must stop before it."},"28":{"q":"Что означает символ ромба, нарисованный на полосе движения?","options":["Зарезервированная полоса для HOV или совместных поездок","Полоса только для грузовиков","Впереди велосипедная полоса","Полоса закрыта"],"explanation":"A diamond symbol marks a reserved HOV, carpool, or special-use lane."},"29":{"q":"Для чего предназначена велосипедная полоса?","options":["Для парковки машин","Для велосипедов","Для поворота налево","Для машин экстренных служб"],"explanation":"A bike lane is marked for bicycles, and you should not drive or park in it."},"30":{"q":"Что обычно означает жёлтый бордюр?","options":["Бесплатная парковка в любое время","Парковка для инвалидов","Запрет парковки или ограничение для погрузки","Только остановка автобуса"],"explanation":"A yellow curb indicates a no-parking or loading restriction, though curb colors vary by city."},"31":{"q":"Какая дорожная разметка предупреждает о железнодорожном переезде?","options":["Символ ромба","Двойная жёлтая линия","Белый пешеходный переход","Большие буквы RXR"],"explanation":"A railroad crossing is marked on the pavement with a large RXR and a stop line."},"32":{"q":"Что нужно делать на постоянном жёлтом сигнале светофора?","options":["Остановиться, если это можно сделать безопасно","Ускориться, чтобы успеть проехать","Всегда полностью останавливаться","Полностью остановиться, затем ехать"],"explanation":"A steady yellow light means the light is about to turn red, so stop if you can do so safely and do not speed up."},"33":{"q":"На сплошной красный свет, где вы должны остановиться?","options":["На линии","Перед линией","За линией","На пешеходном переходе"],"explanation":"At a steady red light you must stop behind the line, not on or beyond it."},"34":{"q":"Что означает сигнал в виде зелёной стрелки?","options":["Снизьте скорость и уступите всему транспорту","Остановитесь и подождите перед поворотом","Защищённый поворот в направлении стрелки","Поворот запрещён"],"explanation":"A green arrow means a protected turn in the arrow's direction because oncoming traffic is stopped."},"35":{"q":"Что нужно делать на мигающий красный сигнал?","options":["Ускориться, чтобы проехать","Снизить скорость и проехать с осторожностью","Игнорировать его и ехать дальше","Полностью остановиться, как у знака «Стоп»"],"explanation":"A flashing red light means make a full stop and go when safe, just like a stop sign."},"36":{"q":"На красный свет, когда разрешён правый поворот?","options":["Когда путь свободен и нет знака, запрещающего его","В любое время без остановки","Только когда сначала повернёт другая машина","Никогда на красный свет"],"explanation":"At a red light you may turn right only when the way is clear and no sign prohibits it."},"37":{"q":"Что делать, если знак НЕ ИДИТЕ начинает мигать, пока вы переходите дорогу?","options":["Остановиться на месте","Закончить переход улицы","Вернуться на тротуар","Быстро перебежать"],"explanation":"If the signal flashes while you are crossing, finish crossing rather than turn back."},"38":{"q":"Что означает красный знак X над полосой движения?","options":["Полоса открыта","Вы должны покинуть полосу","Полоса закрыта","Пешеходы могут переходить"],"explanation":"A red X means the lane is closed, while a yellow X means the lane is changing use and you must move out of it."},"39":{"q":"Что означает прерывистая (пунктирная) жёлтая осевая линия?","options":["Обгон запрещён на вашей стороне","Обгон запрещён в обоих направлениях","Полосы идут в одном направлении","Обгон разрешён, когда это безопасно"],"explanation":"A broken (dashed) yellow centerline means passing is allowed when it is safe."},"40":{"q":"Когда можно пересекать двойную сплошную желтую линию?","options":["Только чтобы совершить поворот","Только чтобы обогнать медленные машины","В любое время, когда путь свободен","Только ночью"],"explanation":"A double solid yellow line may be crossed only to make a turn."},"41":{"q":"Что нужно делать у сплошной белой линии?","options":["Обгонять другие машины","Оставаться в своей полосе","Развернуться","Припарковать машину"],"explanation":"A solid white line means you should stay in your lane, as crossing it is discouraged."},"42":{"q":"Где нужно остановиться у стоп-линии?","options":["На линии","За линией (проехав её)","Не доезжая до линии","На пешеходном переходе"],"explanation":"A stop line shows where to stop, and you must stop behind it."},"43":{"q":"Какого цвета разметка пешеходного перехода?","options":["Красного","Синего","Зелёного","Белого"],"explanation":"Crosswalk markings are white and are for pedestrians."},"44":{"q":"Что означает символ ромба, нарисованный на полосе?","options":["Полоса предназначена для автомобилей с пассажирами и высокой загрузкой (HOV)","Полоса является велосипедной","Полоса закрыта для всего транспорта","Полоса предназначена только для поворота"],"explanation":"A diamond symbol marks a lane reserved for carpools and high-occupancy (HOV) vehicles."},"45":{"q":"Что вам разрешено делать на велосипедной полосе?","options":["Ездить по ней","Ни ездить, ни парковаться на ней","Парковаться на ней","Останавливаться и ждать на ней"],"explanation":"You may not drive in a bike lane, and you may not park in a bike lane."},"46":{"q":"Что означает сплошная жёлтая линия с вашей стороны дороги?","options":["Обгон разрешён","Полоса закрыта","Обгон запрещён","Остановиться и ждать"],"explanation":"A solid yellow line on your side means no passing."},"47":{"q":"Какие стандарты дорожных знаков и сигналов действуют в Техасе?","options":["Только городские правила","Только окружные правила","Нет установленных стандартов","Общие национальные стандарты"],"explanation":"Texas follows the shared national MUTCD standards for signs and signals."},"48":{"q":"Что означает постоянный зелёный сигнал светофора?","options":["Продолжайте движение только если перекрёсток свободен","Полностью остановитесь за линией","Снизьте скорость и приготовьтесь остановиться","Поворот в этом направлении запрещён"],"explanation":"A steady green light means go, but only proceed if the intersection is clear."},"49":{"q":"Что означает сигнал управления полосой в виде красного крестика (X) над полосой?","options":["Полоса открыта","Полоса закрыта","Полоса для поворота","Полоса для парковки"],"explanation":"A red X means the lane is closed, while a green down-arrow means the lane is open."},"50":{"q":"Что означает сплошная жёлтая линия на вашей стороне дороги?","options":["Обгон разрешён","Полоса закрыта","Обгон запрещён","Остановитесь и ждите"],"explanation":"A solid yellow line on your side means no passing, while a broken yellow line allows passing when safe."},"51":{"q":"Какого цвета линии, разделяющие транспорт, движущийся в противоположных направлениях?","options":["Синего","Зеленого","Белого","Желтого"],"explanation":"Yellow lines separate traffic moving in opposite directions and show passing rules."},"52":{"q":"Какого цвета линии, разделяющие полосы движения в одном направлении?","options":["Белого","Жёлтого","Красного","Синего"],"explanation":"White lines separate lanes of traffic traveling in the same direction."},"53":{"q":"Что нужно сделать у разметки железнодорожного переезда (RXR), если приближается поезд?","options":["Ускориться, чтобы проехать первым","Остановиться у стоп-линии","Сигналить и продолжать движение","Сменить полосу"],"explanation":"At a railroad crossing marked RXR with a stop line, you must stop if a train approaches."},"54":{"q":"Что нужно делать на перекрёстке, когда светофор полностью погас или не работает?","options":["Ускориться, чтобы быстро его проехать","Проехать не снижая скорости","Считать его перекрёстком со знаком «стоп» во всех направлениях","Ждать, пока загорится светофор"],"explanation":"A dark or non-working signal should be treated as an all-way stop."},"55":{"q":"Что означает для пешеходов постоянный сигнал с поднятой ладонью (НЕ ИДИТЕ)?","options":["Перейти быстрее","Бежать через дорогу сейчас","Начать переход","Не начинать переход"],"explanation":"A steady raised-hand (DON'T WALK) signal means pedestrians should not start to cross."},"56":{"q":"Что обычно означает жёлтый бордюр?","options":["Запрет парковки или ограничение для погрузки","Бесплатная парковка в любое время","Только для автобусов","Безопасное место для ожидания"],"explanation":"A yellow curb generally indicates a no-parking or loading restriction, though curb colors can vary by city."},"57":{"q":"Что нужно делать при горящей красной стрелке?","options":["Поворачивать в направлении стрелки","Ждать; не поворачивать туда","Ускориться при повороте","Уступить, затем свободно повернуть"],"explanation":"A red arrow means you cannot turn in that direction and must wait until the signal changes."},"58":{"q":"Что разрешает прерывистая белая линия на дороге?","options":["Обгонять встречный автомобиль","Останавливаться посреди дороги","Менять полосу, когда это безопасно","Парковаться у края дороги"],"explanation":"A broken white line allows you to change lanes when it is safe, while a solid white line means stay in your lane."},"59":{"q":"Как выглядит стоп-линия?","options":["Зелёная пунктирная линия","Ряд маленьких точек","Двойная жёлтая линия","Широкая белая линия поперёк полосы"],"explanation":"A stop line is a wide white line painted across the lane to show where to stop."}},"safe-driving":{"0":{"q":"Вы едете за седаном по сухому шоссе. Когда его задний бампер проезжает придорожный знак, вы начинаете считать; до того же знака вы доезжаете чуть менее чем через 2 секунды. О чём это говорит и что следует сделать?","options":["Вы едете слишком близко; отпустите газ, чтобы увеличить дистанцию минимум до 3 секунд.","Дистанция безопасна, потому что 2 секунды — это рекомендуемый минимум на сухой дороге.","Дистанция нормальная; правило трёх секунд действует только в дождь, туман или гололёд.","Нужно немедленно резко затормозить, чтобы отстать, так как вы находитесь в «слепой зоне» грузовика."],"explanation":"The three-second rule says that if you reach the fixed point in less than 3 seconds after the car ahead, you are too close, so easing off the gas to restore a 3-second gap is correct. Two seconds is not the safe minimum, the 3-second rule applies in all conditions (you add more seconds for bad weather), and braking hard or worrying about a truck's No-Zone does not fit this car-following scenario."},"1":{"q":"Обычно вы держите интервал в 3 секунды до машины впереди. Сегодня ночью на автостраде начинается сильный дождь и наплывает густой туман. Что вам следует сделать с дистанцией следования?","options":["Сохранить тот же интервал в 3 секунды, поскольку правило трёх секунд уже учитывает все условия движения","Увеличить интервал до более чем 3 секунд, потому что дождь и туман снижают сцепление с дорогой и видимость","Сократить интервал, чтобы хорошо видеть задние габаритные огни машины впереди сквозь туман","Включить дальний свет и держать интервал в 2 секунды, чтобы быстрее реагировать на её стоп-сигналы"],"explanation":"The three-second rule is a minimum for good conditions; in rain, fog, ice, or at high speed you must add more seconds because traction and visibility are reduced. Shortening the gap or relying on high beams (which reflect back off fog) only increases your danger."},"2":{"q":"Вы едете по техасскому шоссе, когда пикап подъезжает вплотную сзади и держится всего в нескольких футах от вашего бампера, явно «висит на хвосте». Как безопаснее всего управлять пространством вокруг вашего автомобиля?","options":["Несколько раз нажать на тормоз, чтобы предупредить водителя сзади, чтобы он отстал","Ускориться, чтобы преследующий автомобиль отстал дальше","Увеличить дистанцию до автомобиля впереди, чтобы иметь больше места для плавного торможения","Держать ровно три секунды до машины впереди, ведь это правило уже охватывает любую ситуацию"],"explanation":"When you are being tailgated, you should increase your following distance to the vehicle ahead so you can slow down or stop gradually instead of braking hard, giving the tailgater more time to react. Three seconds is only a minimum baseline and should be increased behind motorcycles, large trucks, and when tailgated, so option D is wrong, and brake-tapping or speeding up only raises the risk of a crash."},"3":{"q":"Вы едете по многополосному шоссе рядом с большим грузовиком-фурой, держась чуть позади его кабины, где вы не видите боковые зеркала водителя грузовика. О чём говорит эта позиция и что вам следует сделать?","options":["Водитель грузовика прекрасно вас видит, поэтому вы можете оставаться там, пока держите постоянную скорость","Вам следует приблизиться к прицепу, так как самое безопасное место — прямо рядом с задними колёсами","Вам следует моргнуть дальним светом, чтобы водитель грузовика знал, что вы здесь, прежде чем обгонять","Вы находитесь в слепой зоне грузовика (No-Zone), потому что не видите зеркала водителя, поэтому ускорьтесь или отстаньте, чтобы выйти из неё"],"explanation":"If you can't see a large truck's side mirrors, the driver can't see you, meaning you are sitting in a No-Zone blind spot; the safe response is to clear it quickly by speeding up to pass or easing back. Staying put, moving beside the rear wheels, or relying on high-beam flashes all leave you in the blind spot where the driver cannot see you."},"4":{"q":"Двигаясь по шоссе в Техасе, вы замечаете впереди заглохший автомобиль и полностью останавливаете свою машину. Вспоминая произошедшее, вы понимаете, что остановка заняла больше времени, чем вы ожидали. Какие три расстояния в сумме составляют общее расстояние, которое проехал ваш автомобиль с момента появления опасности до полной остановки?","options":["Расстояние восприятия + расстояние реакции + тормозной путь","Расстояние восприятия + расстояние реакции + дистанция следования","Расстояние реакции + тормозной путь + расстояние аквапланирования","Дистанция следования + тормозной путь + дальность видимости фар"],"explanation":"Total stopping distance is the sum of perception distance (seeing the hazard), reaction distance (moving your foot to the brake), and braking distance (the car slowing to a stop). Following distance, hydroplaning, and headlight sight distance are real safe-driving concepts but are not components of the stopping-distance formula."},"5":{"q":"Олень внезапно выходит на дорогу перед вами на сухом шоссе. С момента, когда ваши глаза замечают оленя, до момента, когда ваша нога действительно начинает нажимать на тормоз, ваш автомобиль продолжает катиться вперёд. Сколько примерно времени обычно занимает это время реакции у среднего водителя?","options":["Около 1,5 секунды","Около трёх четвертей (¾) секунды","Около 3 секунд","Около 35 секунд"],"explanation":"The average driver's reaction time is about ¾ of a second, so the car keeps moving during that interval before braking begins. Option A (about 1.5 s) is the combined perception-plus-reaction time, and 3 seconds is the safe-following-distance rule, not reaction time."},"6":{"q":"Вы едете по техасскому шоссе, когда олень внезапно выходит на дорогу далеко впереди. Прежде чем ваша машина начнёт замедляться, должны произойти две вещи: ваши глаза и мозг должны заметить оленя, а затем вы должны переместить ногу на тормоз. Сколько примерно времени в сумме занимает этот процесс восприятия и реакции, прежде чем тормоза действительно начнут работать?","options":["Около 1000 футов — то же расстояние, на которое вы должны видеть впереди ночью","Около 3 секунд, потому что это безопасная дистанция следования, которую нужно всегда соблюдать","Примерно 1,5 секунды в сумме, ещё до того, как добавляется тормозной путь","Около 35 миль/ч — скорость, при которой на мокрой дороге может начаться аквапланирование"],"explanation":"The combined perception-plus-reaction time is roughly 1.5 seconds, and this happens before braking distance is even added to the total stopping distance. The 3-second answer confuses the separate three-second following-distance rule with reaction time, and the other options misplace unrelated facts (night visibility distance and hydroplaning speed)."},"7":{"q":"На сухом шоссе в Техасе вам обычно требуется около 45 футов тормозного пути, чтобы остановиться со скорости 30 миль/ч после нажатия на тормоз. Движение освобождается, и вы увеличиваете скорость с 30 до 60 миль/ч. Какой тормозной путь вам теперь примерно понадобится для остановки?","options":["Примерно те же 45 футов, потому что тормозной путь мало зависит от скорости","Около 90 футов, потому что удвоение скорости удваивает тормозной путь","Около 68 футов, потому что тормозной путь увеличивается лишь примерно наполовину","Около 180 футов, потому что удвоение скорости примерно учетверяет тормозной путь"],"explanation":"Braking distance increases with the square of speed, so doubling speed from 30 to 60 mph roughly quadruples it (45 feet x 4 = about 180 feet). Option B is the common trap of assuming the relationship is simply linear (double speed = double distance)."},"8":{"q":"Вы выезжаете с жилой улицы с ограничением 30 миль/ч и въезжаете на шоссе, где удваиваете скорость до 60 миль/ч. Внезапно на дорогу впереди выкатывается детский мяч. По сравнению с торможением на скорости 30 миль/ч, как более высокая скорость влияет на вашу способность остановиться?","options":["Ваш тормозной путь увеличивается примерно в четыре раза, поэтому остановка займёт гораздо больше расстояния, а любое столкновение будет сильнее","Ваш тормозной путь увеличивается примерно вдвое, соответствуя росту вашей скорости","Ваш тормозной путь остаётся примерно тем же, потому что время реакции всё ещё составляет около трёх четвертей секунды","Ваш тормозной путь сокращается, потому что более высокая скорость даёт тормозам больше энергии для работы"],"explanation":"Braking distance increases with the square of speed, so doubling your speed from 30 to 60 mph roughly quadruples the braking distance and a crash carries far more energy. Doubling speed does not merely double braking distance, and a faster speed never shortens stopping distance even though reaction time stays about three-quarters of a second."},"9":{"q":"На шоссе идёт сильный дождь, и в полосе стоит вода. Вы едете со скоростью около 40 миль/ч и чувствуете, что руль стал лёгким, а передние шины будто скользят по поверхности воды. Как безопаснее всего восстановить сцепление с дорогой?","options":["Резко затормозить, чтобы замедлить колёса и снова дать им зацепиться за дорогу","Отпустить педаль газа, держать руль прямо и не тормозить резко","Поворачивать руль туда, куда должна ехать передняя часть машины, и прерывисто нажимать на тормоз","Включить дальний свет и добавить одну секунду к дистанции следования"],"explanation":"You are hydroplaning, which can begin near 35 mph as water builds under the tires; easing off the gas, steering straight, and avoiding hard braking lets the tires settle back onto the road. Braking firmly (A) can lock the tires and worsen the slide, and steering/pumping advice (C) is the procedure for a skid, not hydroplaning."},"10":{"q":"Вы едете со скоростью 45 миль/ч по техасскому шоссе во время сильного ливня, и вдруг чувствуете, что руль стал лёгким, а машина начинает скользить, словно плывёт по воде. Что вам следует сделать?","options":["Сильно нажимать на педаль тормоза, чтобы шины снова сцепились с покрытием","Поворачивать руль в ту сторону, куда должна двигаться передняя часть машины, и плавно тормозить","Отпустить педаль газа, держать руль ровно и направленным прямо, и избегать резкого торможения","Немедленно резко затормозить и перейти на пониженную передачу, чтобы сбросить скорость"],"explanation":"When hydroplaning, the tires lose contact with the road, so you should ease off the gas, hold the wheel straight, and avoid braking hard until traction returns. Braking hard (A, D) can cause a skid, and the steer-where-you-want technique (B) applies to correcting a skid, not recovering from hydroplaning."},"11":{"q":"После трёх недель без дождя начинается лёгкая морось, пока вы едете по городу. Поверхность дороги выглядит едва влажной, и транспорт вокруг вас продолжает двигаться с обычной разрешённой скоростью. Почему вам следует быть особенно осторожным со сцеплением прямо сейчас?","options":["Лёгкий дождь не может снизить сцепление, поэтому единственная реальная опасность — это сильные ливни, образующие лужи на дороге","Мосты и эстакады — единственные поверхности, которые становятся скользкими в самом начале дождя","Дорога становится наиболее скользкой, когда накапливается достаточно воды, чтобы началось аквапланирование около 35 миль/ч","Масло и смазка, накопившиеся за сухой период, смешиваются с первым лёгким дождём, делая дорогу наиболее скользкой именно сейчас"],"explanation":"The first rain after a dry spell is the most slippery because accumulated oil and grease mix with the water before being washed away, so a light early drizzle is more dangerous than it looks. Option C is a real fact about hydroplaning but describes a different hazard that needs water to build up, not the slick oily film of the first rain."},"12":{"q":"Ясным утром температура чуть ниже нуля, и вы едете по сельскому шоссе. Дорожное покрытие впереди выглядит сухим, и вы чувствуете хорошее сцепление. Приближаясь к мосту через ручей, что вам следует сделать?","options":["Отпустить педаль газа и снизить скорость перед мостом, потому что мосты и эстакады замерзают раньше остальной дороги","Сохранять скорость, ведь сухая дорога позади доказывает, что покрытие моста тоже безопасно","Резко затормозить прямо при въезде на мост, чтобы проверить, скользкое ли покрытие","Переключиться на дальний свет, чтобы быстрее заметить лёд на мосту"],"explanation":"Bridges and overpasses are exposed to cold air on all sides, so they freeze before regular pavement; easing off the gas and slowing down before the bridge is the safe response. Maintaining speed because the road behind feels dry ignores that the bridge can be icy even when the surrounding road is not, and braking hard on a possibly icy surface can cause a skid."},"13":{"q":"Ясное, очень холодное зимнее утро, около -1°C. Вы едете по шоссе и приближаетесь к эстакаде. Дорога впереди выглядит немного темнее и мокрой, но явного льда вы не видите. Как безопаснее всего поступить в этой ситуации?","options":["Дорога выглядит просто мокрой, поэтому сохраняйте скорость и резко тормозите, если начнёте скользить","Считайте тёмный, мокрый на вид участок возможным чёрным льдом; плавно снизьте скорость перед эстакадой и избегайте резкого торможения или поворотов руля","Включите дальний свет, чтобы мокрое покрытие отражало больше света и вы лучше видели поверхность","Ускорьтесь, чтобы быстрее проехать эстакаду и провести меньше времени на скользкой поверхности"],"explanation":"Bridges and overpasses freeze first, and black ice is hard to see, so a dark, wet-looking patch in freezing temperatures should be treated as ice by slowing gradually and avoiding sudden braking or steering. Maintaining speed (A) assumes the surface is only wet, and speeding up (D) increases the risk of a skid you cannot control."},"14":{"q":"Вы едете по влажному шоссе в Техасе, когда задняя часть машины внезапно соскальзывает вправо и начинает заносить. Что нужно сделать, чтобы восстановить управление?","options":["Сильно нажать на тормоз, чтобы немедленно замедлить машину, затем выровнять руль","Сохранять равномерное давление на газ, чтобы вытянуть машину вперёд из заноса","Убрать ногу с педали газа и поворачивать руль в ту сторону, куда вы хотите направить переднюю часть машины, не нажимая резко на тормоз","Переключиться на пониженную передачу и многократно прокачивать педаль тормоза, пока не вернётся сцепление"],"explanation":"In a skid you should ease off the gas and steer in the direction you want the front of the car to go, never slamming the brakes, which would only worsen the loss of traction. Hard braking (A) and pumping the brake while downshifting (D) are recovery steps for other emergencies, not skids, and holding the gas (B) keeps the wheels spinning."},"15":{"q":"Вы едете ночью по сельскому шоссе и внезапно въезжаете в густой туман, в котором почти не видно дороги впереди. Что вам следует сделать?","options":["Включить дальний свет, чтобы более яркий свет лучше пробивал туман","Сохранить текущую скорость, но включить аварийную сигнализацию, чтобы оставаться заметным","Сместиться к правому краю дороги и отвести взгляд от слепящего света","Переключиться на ближний свет, снизить скорость и безопасно съехать с дороги, если видимость станет слишком плохой"],"explanation":"In fog or smoke you should use low beams because high beams reflect off the moisture and glare back at you, and you should slow down or pull off safely. High beams (A) make visibility worse, and looking to the right edge (C) is the response for oncoming headlight glare, not fog."},"16":{"q":"Вы едете домой ясным днём, когда налетает сильная гроза. Видимость падает настолько, что вы едва различаете дорожный знак примерно в 800 футах впереди, хотя до заката ещё далеко. Что вам следует сделать с фарами?","options":["Включить фары, потому что вы обязаны использовать их в любое время, когда не видите примерно на 1000 футов вперёд, независимо от времени суток.","Оставить фары выключенными, так как правило их использования действует только в период от заката до восхода.","Включить дальний свет, чтобы пробиться сквозь дождь и улучшить дальность видимости.","Оставить фары выключенными, но снизить скорость, потому что фары требуются только тогда, когда вы не видите примерно на 500 футов вперёд."],"explanation":"Texas requires headlights from sunset to sunrise AND any time you cannot see about 1,000 feet ahead, so the reduced visibility means you must turn them on even in daylight. High beams reflect off rain and fog and make it harder to see, and 500 feet is the dimming distance for oncoming traffic, not the visibility threshold for using lights."},"17":{"q":"Вы едете ночью по тёмной просёлочной дороге с двумя полосами движения с включённым дальним светом. Вы замечаете автомобиль, приближающийся к вам по встречной полосе, и оцениваете, что сейчас он находится чуть менее чем в 500 футах. Что вам следует сделать?","options":["Не выключать дальний свет, пока встречный автомобиль первым не приглушит свои фары","Сейчас же переключить дальний свет на ближний","Переключиться на ближний свет только если вы также находитесь в пределах 300 футов позади другого автомобиля","Мигнуть дальним светом, чтобы предупредить встречного водителя, и продолжать ехать на дальнем свете"],"explanation":"В Техасе требуется переключать дальний свет на ближний, находясь в пределах 500 футов от встречного автомобиля, поэтому переключиться нужно сейчас. Ожидание действий другого водителя (A) или мигание (D) оставляют ослепляющий блеск на дороге, а правило 300 футов (C) относится к движению позади автомобиля, а не к встречному транспорту."},"18":{"q":"Вы едете ночью по тёмному сельскому шоссе с включённым дальним светом. Вы догоняете более медленный автомобиль впереди и постепенно сокращаете расстояние, пока не оказываетесь примерно в 250 футах позади него, при этом встречного транспорта не видно. Что нужно сделать с дальним светом?","options":["Оставить дальний свет включённым, так как правило о переключении касается только встречных автомобилей, с которыми вы разъезжаетесь","Оставить дальний свет включённым, пока вы не приблизитесь к автомобилю впереди на 100 футов, затем переключиться на ближний","Переключиться на ближний свет сейчас, потому что нужно приглушать дальний свет в пределах 300 футов при движении за другим автомобилем","Оставить дальний свет включённым, но смотреть на правый край дороги, чтобы избежать ослепления"],"explanation":"Texas law requires you to dim your high beams to low when within 300 feet behind another vehicle, so at 250 feet you must already be on low beams. The high beams glare in the lead driver's mirrors; the 500-foot rule (A) applies to oncoming traffic, and looking to the right edge (D) is the technique for when you are blinded, not for following."},"19":{"q":"Вы едете ночью по тёмному двухполосному шоссе, и встречный автомобиль не переключает дальний свет на ближний, а яркий свет мешает вам видеть дорогу впереди. Что нужно сделать, чтобы сохранить контроль, пока машина не проедет мимо?","options":["Включить свой дальний свет, чтобы другой водитель увидел, насколько это ярко, и переключился на ближний","Немедленно резко затормозить и остановиться на своей полосе, пока глаза не восстановятся","Смотреть прямо на встречные фары, чтобы точно отслеживать, где находится другая машина","Снизить скорость и смотреть на правый край своей полосы, пока автомобиль не проедет"],"explanation":"When blinded by oncoming high beams, you should look toward the right edge of the road to avoid the glare while still guiding your car. Flashing your own high beams or staring into the lights only worsens the blindness, and stopping hard in a travel lane risks a rear-end collision."},"20":{"q":"Вы едете ночью по тёмной сельской трассе с включённым ближним светом. Дорога впереди освещена только настолько, насколько достаёт свет фар, и вы едете настолько быстро, что олень, внезапно вышедший в эту освещённую зону, окажется внутри вашего тормозного пути раньше, чем вы успеете отреагировать и затормозить. Какую ошибку вы допускаете?","options":["Вы «переезжаете» свои фары — едете настолько быстро, что не можете остановиться в пределах освещённого участка впереди","Вы неправильно применяете правило трёх секунд для данных условий","Вы не переключились с дальнего света на ближний в пределах 500 футов от встречного автомобиля","Вы аквапланируете, потому что ваша скорость превысила безопасный предел для этого покрытия"],"explanation":"Overdriving your headlights means traveling so fast that you cannot stop within the distance your headlights illuminate ahead, which is exactly the scenario described. The three-second rule applies to spacing behind another vehicle, dimming high beams concerns glare to others, and hydroplaning involves water on the road—none fit a dry night road with a fixed lighted distance."},"21":{"q":"Вы спускаетесь с длинного склона, нажимаете на педаль тормоза, а она проваливается в пол почти без сопротивления. Машина продолжает разгоняться. Как лучше всего замедлиться и остановиться?","options":["Крепко держать руль, отпустить газ и не тормозить резко, затем медленно съехать на обочину","Прокачать педаль тормоза, переключиться на низшую передачу и постепенно задействовать стояночный тормоз","Убрать ногу с газа и поворачивать руль в ту сторону, куда вы хотите направить переднюю часть машины","Резко поднять стояночный тормоз до упора и заглушить двигатель, чтобы погасить скорость"],"explanation":"When the brakes fail, pumping the pedal may restore some pressure, shifting to a lower gear uses engine braking to slow you, and applying the parking brake gradually brings you to a stop. Option A is the correct response to a tire blowout, and pulling the parking brake all the way up at once (D) can cause a skid."},"22":{"q":"Вы едете со скоростью 60 миль/ч по техасскому шоссе, когда слышите громкий хлопок, и руль внезапно резко тянет в одну сторону. Вы понимаете, что лопнула переднее колесо. Как безопаснее всего восстановить контроль?","options":["Немедленно резко затормозить, чтобы остановиться как можно быстрее, пока машину не занесло сильнее","Резко повернуть руль в противоположную сторону, чтобы компенсировать увод, затем резко затормозить на обочине","Крепко держать руль, плавно отпустить педаль газа и дать машине постепенно замедлиться, прежде чем съехать с дороги","Прокачать педаль тормоза и переключиться на пониженную передачу, чтобы замедлить машину"],"explanation":"In a blowout you hold the wheel firmly, ease off the gas, and avoid braking hard, then pull off slowly once the car has slowed. Braking hard (A) or jerking the wheel (B) can cause a complete loss of control, and pumping the pedal with a lower gear (D) is the technique for brake failure, not a tire blowout."},"23":{"q":"Двигатель вашей машины глохнет, когда вы пересекаете железнодорожный переезд в сельской местности. Машина не заводится, и вдали вы видите приближающийся поезд. Что вам следует сделать?","options":["Оставаться пристёгнутым в машине и быстро нажимать на педаль тормоза, чтобы откатить машину с путей","Включить аварийную сигнализацию и ждать в автомобиле, пока поезд проедет","Переключиться на пониженную передачу и попытаться проехать переезд до того, как подойдёт поезд","Вывести всех из машины и отойти далеко от путей, затем вызвать помощь"],"explanation":"If your vehicle stalls on railroad tracks, the only priority is getting everyone out and well away from the tracks before calling for help, because you can never safely beat an approaching train. Pumping the brake, waiting in the car, or trying to drive across all keep people in the path of the train."},"24":{"q":"На сельском двухполосном шоссе ваш двигатель внезапно теряет мощность, и вам удаётся накатом съехать к краю дороги. Рядом есть широкая асфальтированная обочина. Как правильно остановиться и обеспечить свою безопасность, пока вы ждёте помощи?","options":["Полностью съехать на обочину, включить аварийную сигнализацию и выставить знаки аварийной остановки позади автомобиля.","Остановиться в своей полосе с включённым стояночным тормозом, чтобы вас хорошо видели другие водители, и включить фары.","Оставить заднюю часть машины в полосе, нажимать на педаль тормоза и переключиться на пониженную передачу, чтобы оставаться заметным.","Припарковаться наполовину на обочине, выйти и стоять в полосе, показывая транспорту объезжать вас."],"explanation":"If you must stop on the road, pull fully onto the shoulder, turn on your hazard flashers, and use warning devices so approaching traffic is alerted. Stopping in the lane or leaving part of the car in traffic exposes you to a rear-end crash, and pumping the brake/shifting down is the procedure for brake failure, not a stopped breakdown."},"25":{"q":"Вы за рулём уже шесть часов в дальней поездке и замечаете, что постоянно зеваете, машину уводит к разметке полосы, и вы с трудом вспоминаете последние несколько миль. До пункта назначения ещё два часа пути. Что вам следует сделать?","options":["Опустить стекло и сделать радио погромче, чтобы взбодриться, и продолжить ехать до пункта назначения","Свернуть на безопасную зону отдыха и вздремнуть или остаться на ночь, потому что сонливость замедляет реакцию и ухудшает суждение так же, как алкоголь","Увеличить дистанцию до правила трёх секунд и продолжить ехать оставшиеся два часа","Включить дальний свет, чтобы видеть дальше, и продержаться последние два часа"],"explanation":"Fatigue slows reaction time and impairs judgment much like drugs or alcohol, so the only safe choice is to stop and rest rather than drive drowsy. Tricks like fresh air, loud music, or a longer following distance do not cure drowsiness, and high beams have nothing to do with the danger of falling asleep at the wheel."},"26":{"q":"Вы остановились на красный сигнал светофора в Техасе, и в этот момент на телефон приходит текстовое сообщение. Светофор всё ещё красный, движение плотное. Что вам следует сделать?","options":["Быстро ответить прямо сейчас, пока вы стоите, ведь сделать это до того, как загорится зелёный, — самый безопасный момент","Только взглянуть на экран, чтобы прочитать, ведь читать сообщение разрешено, пока вы не печатаете","Не трогать телефон и подождать, пока вы безопасно не припаркуетесь, потому что переписка за рулём в Техасе запрещена законом и является серьёзным отвлечением","Ответить, но сначала включить аварийную сигнализацию, чтобы предупредить водителей, что вы временно заняты"],"explanation":"Texting while driving is illegal in Texas and is a major distraction, so you should not text from behind the wheel even when stopped at a light; wait until you are safely parked. Reading or replying at a red light is still using the phone to text, and hazard flashers are for a disabled or stopped-on-the-road vehicle, not for excusing phone use."},"27":{"q":"Вы везёте двух друзей на матч в Техасе. Один садится впереди, второй забирается на заднее сиденье и говорит: \"Я не буду пристёгиваться, мне ехать всего десять минут\". Что вам следует сделать перед началом движения?","options":["Разрешить пассажиру на заднем сиденье ехать непристёгнутым, так как правила ремней безопасности касаются только водителя и пассажиров на передних сиденьях","Разрешить это, потому что поездка короткая и вы будете ехать по медленным улицам района","Дать ему свой телефон, чтобы он написал кому-нибудь и вызвал другую машину, чтобы не ехать непристёгнутым","Настоять, чтобы он пристегнулся перед поездкой, потому что закон Техаса требует, чтобы водитель и все пассажиры были пристёгнуты ремнями безопасности"],"explanation":"Texas law requires a seat belt for the driver and every passenger, including those in the back seat, regardless of how short the trip is. Options A and B rely on common myths (rear seats are exempt, or short/slow trips don't count), and texting while driving is itself illegal and unsafe."},"28":{"q":"Вы едете по сухому шоссе за пикапом. Чтобы проверить дистанцию следования, вы смотрите, как грузовик проезжает тень от путепровода на дороге, а затем считаете, пока передняя часть вашего автомобиля не достигнет той же точки. Каким должен быть этот счёт, чтобы дистанция следования считалась достаточной?","options":["Три секунды или более после того, как грузовик проедет точку","Менее трёх секунд после того, как грузовик проедет точку","Около трёх четвертей секунды, что соответствует среднему времени реакции","Ровно 500 футов пространства за грузовиком"],"explanation":"With the three-second rule, you pick a fixed point and count; reaching it in three seconds or more after the vehicle ahead means your following distance is adequate. Reaching it in less than three seconds means you are too close, while three-quarters of a second describes average reaction time and 500 feet is the high-beam dimming distance, not a following gap."},"29":{"q":"Вы едете за пикапом по сухому шоссе и хотите проверить, соблюдаете ли вы безопасную дистанцию, используя правило трёх секунд. Задний бампер пикапа только что миновал дорожный знак впереди. Что нужно сделать, чтобы правильно применить это правило?","options":["Начать отсчёт, когда пикап проезжает знак, и остановиться через три секунды, затем убедиться, что пикап всё ещё находится в пределах этого расстояния.","Начать отсчёт, когда задняя часть пикапа проезжает знак, и остановиться, когда ваш передний бампер достигнет того же знака; если прошло меньше трёх секунд, вы едете слишком близко.","Отмерить расстояние в три длины автомобиля между вашим передним бампером и задним бампером пикапа.","Отсчитать секунды, которые требуются пикапу, чтобы полностью остановиться с момента, когда он проезжает знак."],"explanation":"The three-second rule works by picking a fixed point and counting the seconds between when the vehicle ahead passes it and when you pass the same point; under three seconds means you're following too closely. Fixed car-length spacing (C) and timing the lead vehicle's stop (D) are not how the rule works."},"30":{"q":"Вы едете по чистому шоссе, и впереди на дорогу внезапно выскакивает олень. Вы видите его, решаете остановиться и нажимаете на тормоз. После того как ваша нога уже нажимает на педаль тормоза, расстояние, которое машина продолжает проезжать до полной остановки, называется как?","options":["Общий тормозной путь — полное расстояние с момента, когда вы увидели оленя, до остановки машины","Расстояние реакции — расстояние, пройденное, пока вы решаете нажать на тормоз","Расстояние торможения — один из трёх компонентов общего пути остановки","Расстояние восприятия — расстояние, пройденное до того, как ваши глаза заметят оленя"],"explanation":"Braking distance is the distance the vehicle travels from the moment the brakes are applied until it stops, and it is one of the three components of total stopping distance (perception + reaction + braking). Total stopping distance is the sum of all three, not just the part after braking begins, so that option is the trap."},"31":{"q":"Вы едете со скоростью трассы, когда впереди на вашу полосу внезапно выходит олень. Прежде чем ваша нога вообще коснётся педали тормоза, автомобиль уже проедет некоторое расстояние. Какие составляющие полного тормозного пути отвечают за это перемещение, происходящее ДО того, как тормоза действительно сработают?","options":["Путь торможения и путь реакции","Путь восприятия и путь торможения","Только путь торможения, так как машина продолжает двигаться, пока колёса не заблокируются","Путь восприятия и путь реакции"],"explanation":"Total stopping distance is perception distance plus reaction distance plus braking distance, and only perception and reaction distance occur before the brakes are applied; braking distance is the travel after the brakes engage, so any option containing braking distance is wrong."},"32":{"q":"Вы едете со скоростью около 40 миль/ч по техасскому шоссе во время сильного ливня, как вдруг чувствуете, что руль стал лёгким, и машина начинает скользить по слою воды, не реагируя на повороты руля. Как безопаснее всего отреагировать?","options":["Плавно отпустите педаль газа, держите руль прямо и дайте машине замедлиться, пока шины снова не сцепятся с дорогой","Сильно и равномерно нажмите на тормоз, чтобы сбросить скорость и быстро восстановить сцепление","Резко поверните руль в сторону обочины, чтобы выехать из водяной плёнки","Быстро прокачивайте педаль тормоза и переключитесь на пониженную передачу, чтобы контролировать скольжение"],"explanation":"During hydroplaning the tires ride on a layer of water and lose contact with the road, so you should ease off the gas, steer straight, and avoid braking hard until traction returns. Braking firmly (B) or pumping the brakes (D) is a real technique for other emergencies like brake failure, but hard braking during hydroplaning can cause you to skid out of control."},"33":{"q":"Ясное зимнее утро, температура чуть ниже нуля. Асфальтовое шоссе выглядит сухим, но вы приближаетесь к длинной эстакаде. Что следует ожидать и сделать, чтобы ехать безопасно?","options":["Эстакада — самая теплая часть дороги, поэтому можно сохранять текущую скорость на ней","Эстакада может быть обледенелой, даже если дорога выглядит сухой, поэтому снизьте скорость перед въездом на нее","Главная опасность на эстакаде — аквапланирование, поэтому отпустите газ и держите руль прямо","Включите дальний свет на эстакаде, чтобы заметить лед впереди"],"explanation":"Bridges and overpasses freeze before the rest of the roadway because cold air reaches them from all sides, so they can be icy even when the surrounding pavement looks dry; slowing before the overpass is the safe move. Hydroplaning involves water on the road near 35 mph, not freezing, and high beams do not help here, so those are the traps."},"34":{"q":"Два часа дня на шоссе в Техасе, когда внезапно начинается сильный ливень. Дождь настолько густой, что вы едва различаете задние фонари автомобиля в паре сотен футов впереди, и вы оцениваете, что больше не видите четко даже на 1000 футов вперед по дороге. Что вам следует сделать с фарами?","options":["Не включать фары, потому что сейчас день, и включить только аварийную сигнализацию, продолжая движение","Включить дальний свет, чтобы сильный дождь впереди был освещен как можно дальше","Включить фары, поскольку вы обязаны их использовать всякий раз, когда не видите примерно на 1000 футов вперед, даже днем","Оставить фары выключенными, но включить внутренний плафон, чтобы оставаться заметным для других водителей"],"explanation":"В Техасе вы обязаны использовать фары всякий раз, когда не видите примерно на 1000 футов вперед, что включает дневные условия, такие как сильный дождь, поэтому их включение является правильным. Дальний свет неверен, потому что в дождь или туман он отражается обратно и снижает видимость, а аварийная сигнализация или плафон салона не заменяют фары во время движения."},"35":{"q":"Вы едете ночью по тёмному двухполосному шоссе с включённым дальним светом. Впереди по встречной полосе движется автомобиль, и в то же время вы постепенно нагоняете более медленный грузовик в своей полосе прямо перед вами. Что требует закон Техаса делать с дальним светом?","options":["Оставить дальний свет для встречного автомобиля, но переключить на ближний для грузовика впереди, так как попутный транспорт важнее","Переключить на ближний только перед встречным автомобилем в пределах 500 футов; за другим транспортом дальний свет разрешён на любом расстоянии","Переключить на ближний только перед грузовиком в пределах 300 футов; в сторону встречного транспорта дальний свет разрешён на любом расстоянии","Переключить на ближний свет перед встречным автомобилем в пределах 500 футов и перед грузовиком в пределах 300 футов"],"explanation":"Texas law requires dimming high beams to low within 500 feet of an oncoming vehicle and within 300 feet when approaching another vehicle from behind, so in this scenario both situations require low beams. Options that excuse you from dimming for one of the two vehicles ignore half the rule and would blind another driver."},"36":{"q":"Вы едете со скоростью 65 миль/ч по автомагистрали в Техасе, когда слышите громкий хлопок и руль внезапно резко тянет в сторону — лопнула передняя шина. Что вам следует сделать?","options":["Крепко держать руль, чтобы машина шла прямо, постепенно отпустить педаль газа и медленно съехать с дороги после того, как сбавите скорость","Сильно и немедленно нажать на тормоз, чтобы остановить машину как можно быстрее","Убрать ногу с педали газа и поворачивать руль в ту сторону, куда вы хотите направить перёд машины","Прокачивать педаль тормоза и переключиться на пониженную передачу, чтобы замедлить машину"],"explanation":"During a blowout you must hold the wheel firmly and gradually ease off the gas before pulling off slowly—braking hard (B) can cause you to lose control. Steering toward where you want the front to go (C) is the fix for a skid, and pumping the brakes with a lower gear (D) is the procedure for brake failure, not a blowout."}},"learn-safe-driving":{"0":{"q":"Для чего используется правило трёх секунд?","options":["Для соблюдения безопасной дистанции до впереди идущей машины","Чтобы знать, когда менять масло","Для включения стояночного тормоза","Для отсчёта времени подачи сигнала поворота"],"explanation":"The three-second rule helps you keep a safe following distance behind the car ahead."},"1":{"q":"Как использовать правило трёх секунд?","options":["Отсчитать три длины машины впереди","Сосчитать секунды до неподвижной точки","Ехать на три мили в час медленнее","Ждать три секунды на каждой остановке"],"explanation":"Pick a fixed point ahead and count the seconds it takes to reach it after the car ahead passes it."},"2":{"q":"Когда следует добавить больше секунд к дистанции до впереди идущего автомобиля?","options":["На сухих, чистых дорогах","Когда движение слабое","В дождь, туман, гололёд или на высокой скорости","Когда едете медленно"],"explanation":"Add more seconds to your following distance in rain, fog, ice, or at high speed."},"3":{"q":"Когда следует добавить дополнительные секунды к трёхсекундной дистанции следования?","options":["Только в солнечные дни","Когда дорога сухая и пустая","Когда движение слабое","В дождь, туман, гололёд или на высокой скорости"],"explanation":"Rain, fog, ice, and high speed all require adding extra seconds to your following distance."},"4":{"q":"Когда следует увеличить дистанцию до впереди идущего транспорта?","options":["Когда едете за мотоциклом или крупным грузовиком","Когда дорога сухая и чистая","Когда движение слабое","Когда вы спешите"],"explanation":"Increase your following distance behind motorcycles, large trucks, or when being tailgated."},"5":{"q":"Когда другой водитель едет слишком близко за вами, что вам следует сделать?","options":["Резко затормозить, чтобы предупредить его","Увеличить дистанцию до машины впереди","Ускориться, чтобы оторваться от него","Остановиться посреди дороги"],"explanation":"Increasing your following distance gives you more room to stop safely when being tailgated."},"6":{"q":"Как называются большие слепые зоны вокруг крупных грузовиков и автобусов?","options":["Зоны замедления","Безопасные зоны","No-Zones (слепые зоны)","Зоны аварий"],"explanation":"Large trucks and buses have big blind spots called No-Zones, and if you can't see the driver's mirrors, they can't see you."},"7":{"q":"Если вы не видите зеркала водителя грузовика или автобуса, что это значит?","options":["Вы можете обгонять справа","Водитель хорошо вас видит","Ваши зеркала сломаны","Водитель вас не видит"],"explanation":"Large trucks and buses have big blind spots, so if you can't see the driver's mirrors, the driver can't see you."},"8":{"q":"Из каких трёх дистанций складывается общая тормозная дистанция?","options":["Дистанция восприятия, дистанция реакции и дистанция торможения","Дистанция скорости, дистанция погоды и дистанция торможения","Дистанция следования, дистанция слепой зоны и дистанция реакции","Дневная дистанция, ночная дистанция и дистанция восприятия"],"explanation":"Total stopping distance equals perception distance plus reaction distance plus braking distance."},"9":{"q":"Какие три части составляют общий тормозной путь?","options":["Скорость, вес и расстояние шин","Расстояние восприятия, реакции и торможения","Расстояние рулевого управления, сигнала и торможения","Расстояние видимости, погоды и реакции"],"explanation":"Total stopping distance is made up of perception distance, reaction distance, and braking distance."},"10":{"q":"Примерно сколько составляет среднее время реакции водителя?","options":["Около 3 секунд","Около 2 секунд","Около трёх четвертей секунды","Около 5 секунд"],"explanation":"The average driver's reaction time is about three-fourths (3/4) of a second."},"11":{"q":"Примерно сколько составляет суммарное время восприятия и реакции?","options":["Около 0,5 секунды","Около 3 секунд","Около 5 секунд","Около 1,5 секунды"],"explanation":"The combined perception-plus-reaction time is roughly 1.5 seconds."},"12":{"q":"Если вы удвоите скорость, тормозной путь примерно:","options":["Увеличивается в четыре раза (примерно в 4 раза)","Удваивается (примерно в 2 раза)","Остаётся прежним","Уменьшается вдвое"],"explanation":"Braking distance increases with the square of speed, so doubling speed roughly quadruples it."},"13":{"q":"Если вы удвоите скорость, тормозной путь увеличится примерно во сколько раз?","options":["Останется прежним","Примерно в четыре раза","Примерно в два раза","Примерно в три раза"],"explanation":"Doubling your speed roughly quadruples your braking distance."},"14":{"q":"Как более быстрая езда влияет на остановку?","options":["Останавливаться становится легче","Это не влияет на остановку","Останавливаться приходится дольше","Это смягчает удар при аварии"],"explanation":"The faster you go, the longer it takes to stop and the harder a crash, because of the speed-energy relationship."},"15":{"q":"Почему на мокрой дороге нужно снижать скорость?","options":["Чтобы экономить топливо","Чтобы ехать ближе к машине впереди","Чтобы фары светили ярче","Потому что сцепление с дорогой снижается"],"explanation":"Wet roads reduce traction, so slowing down helps you stay in control."},"16":{"q":"Примерно на какой скорости может начаться аквапланирование на мокрой дороге?","options":["Около 35 миль/ч","Около 5 миль/ч","Около 15 миль/ч","Около 70 миль/ч"],"explanation":"Hydroplaning can begin near 35 mph as water builds up under the tires."},"17":{"q":"Что такое аквапланирование?","options":["Когда шины лучше держат дорогу под дождём","Когда шины теряют контакт с дорогой на воде","Когда тормоза перегреваются на длинном спуске","Когда фары отражаются от мокрого асфальта"],"explanation":"Hydroplaning happens when water builds up under the tires and they lose contact with the road surface."},"18":{"q":"Что делать, если ваш автомобиль начинает аквапланировать?","options":["Сразу резко затормозить","Ускориться, чтобы вернуть сцепление","Отпустить газ и держать руль прямо","Резко повернуть руль"],"explanation":"If you hydroplane, ease off the gas, do not brake hard, and steer straight."},"19":{"q":"Почему первый дождь после засушливого периода самый скользкий?","options":["Дорога холоднее обычного","Дождь смывает всю грязь","Шины теряют воздух в сырую погоду","Масло смешивается с водой на дороге"],"explanation":"The first rain mixes with built-up oil on the road, making it the most slippery."},"20":{"q":"В гололёд какая часть дороги замерзает первой?","options":["Мосты и эстакады","Вершины холмов","Туннели","Парковки"],"explanation":"Bridges and overpasses freeze before the rest of the road in icy conditions."},"21":{"q":"Почему черный лед опасен?","options":["Он быстро тает","Его трудно увидеть на дороге","Он сильно пахнет","Он издает громкий звук"],"explanation":"Black ice is dangerous because it is hard to see on the road."},"22":{"q":"Если вашу машину начинает заносить, что нужно сделать?","options":["Резко нажать на тормоз","Сильнее нажать на газ","Отпустить газ и рулить туда, куда хотите ехать","Закрыть глаза и держаться"],"explanation":"In a skid, take your foot off the gas, don't slam the brakes, and steer in the direction you want the front of the car to go."},"23":{"q":"Как нужно рулить, чтобы выйти из заноса?","options":["В сторону обочины","В противоположную сторону от заноса","В сторону от того, куда вы хотите ехать","В ту сторону, куда должен ехать перёд машины"],"explanation":"To recover from a skid, steer in the direction you want the front of the car to go."},"24":{"q":"Во время заноса что нужно сделать с ногой?","options":["Убрать ногу с педали газа","Сильнее нажать на педаль газа","Резко нажать на педаль тормоза","Удерживать ровное давление на газ"],"explanation":"Easing off the gas helps you regain traction during a skid."},"25":{"q":"В тумане или дыму какие фары следует использовать?","options":["Дальний свет","Ближний свет","Без фар","Только аварийная сигнализация"],"explanation":"Use low beams in fog or smoke because high beams reflect back and reduce your visibility."},"26":{"q":"Что нужно делать в тумане или дыму?","options":["Ускориться, чтобы проехать сквозь них","Включить дальний свет","Снизить скорость или безопасно съехать с дороги","Выключить фары"],"explanation":"In fog or smoke you should slow down or pull off the road safely."},"27":{"q":"В тумане какие фары следует использовать?","options":["Только аварийную сигнализацию","Вообще не включать фары","Дальний свет","Ближний свет"],"explanation":"In fog you should use low beams because high beams reflect off the fog and reduce your visibility."},"28":{"q":"Когда нужно включать фары?","options":["С заката до рассвета","Только во время сильного дождя","Только на шоссе","Только при парковке"],"explanation":"Texas law requires headlights from sunset to sunrise."},"29":{"q":"Когда нужно включать фары исходя из видимости?","options":["Когда вы не видите хотя бы на 100 футов вперёд","Когда вы не видите хотя бы на 1000 футов вперёд","Когда вы не видите хотя бы на 50 футов вперёд","Когда вы не видите хотя бы на 5000 футов вперёд"],"explanation":"Use your headlights any time you cannot see at least about 1,000 feet ahead."},"30":{"q":"Когда нужно переключить дальний свет на ближний при встречном автомобиле?","options":["В пределах 100 футов","В пределах 250 футов","В пределах 500 футов","В пределах 1000 футов"],"explanation":"You must dim your high beams to low beams when within 500 feet of an oncoming vehicle."},"31":{"q":"Двигаясь за другим транспортным средством, на каком расстоянии вы должны переключить дальний свет на ближний?","options":["В пределах 100 футов сзади","В пределах 150 футов сзади","В пределах 200 футов сзади","В пределах 300 футов сзади"],"explanation":"You must dim your high beams to low beams when within 300 feet behind another vehicle."},"32":{"q":"На каком расстоянии (в футах) от встречного автомобиля нужно переключить дальний свет на ближний?","options":["500 футов","100 футов","250 футов","1000 футов"],"explanation":"You must dim your high beams to low within 500 feet of an oncoming vehicle."},"33":{"q":"На каком расстоянии в футах от автомобиля, за которым вы следуете, нужно переключить дальний свет на ближний?","options":["100 футов","300 футов","500 футов","1000 футов"],"explanation":"You must dim your high beams to low when within 300 feet behind another vehicle."},"34":{"q":"Если дальний свет встречного автомобиля ослепляет вас, куда следует смотреть?","options":["Прямо на фары","Вверх на небо","На правый край дороги","Вниз на приборную панель"],"explanation":"Looking toward the right edge of the road helps you avoid the glare and stay in your lane."},"35":{"q":"Что означает \"опережение света фар\"?","options":["Слишком частое использование дальнего света","Забывание включить фары","Езда с одной неработающей фарой","Слишком быстрая езда, чтобы остановиться в освещённой зоне"],"explanation":"Overdriving your headlights means going so fast you cannot stop within the distance lighted by your headlights."},"36":{"q":"Что делать, если откажут тормоза?","options":["Качайте педаль, переключитесь на низшую передачу, плавно используйте стояночный тормоз","Заглушите двигатель и резко выверните руль","Ускорьтесь, чтобы доехать до следующего съезда","Закройте глаза и сигнальте"],"explanation":"If your brakes fail, pump the brake pedal, shift to a lower gear, and use the parking brake gradually."},"37":{"q":"Как следует использовать стояночный тормоз при отказе тормозов?","options":["Сразу полностью","Постепенно","Никогда не использовать","Только после остановки"],"explanation":"During brake failure, apply the parking brake gradually rather than all at once."},"38":{"q":"Если ваши тормоза отказали, какой ответ рекомендуется?","options":["Ускориться, чтобы продолжать движение","Выключить фары","Переключиться на пониженную передачу","Громко сигналить"],"explanation":"Shifting to a lower gear helps slow the vehicle when your brakes fail."},"39":{"q":"Что делать, если у вас лопнула шина?","options":["Резко затормозить немедленно","Ускориться, чтобы сохранить контроль","Отпустить руль","Крепко держать руль и отпустить педаль газа"],"explanation":"In a blowout, hold the wheel firmly, ease off the gas, and do not brake hard."},"40":{"q":"После разрыва шины, когда вы восстановили контроль, как следует съехать с дороги?","options":["Медленно съехать с дороги","Резко затормозить и быстро остановиться","Ускориться, чтобы перестроиться","Оставаться в своей полосе"],"explanation":"After a tire blowout, once you have control you should pull off the road slowly."},"41":{"q":"Что нужно делать при разрыве шины?","options":["Сразу резко тормозить","Не тормозить резко","Быстро ускоряться","Отпустить руль"],"explanation":"During a tire blowout, do not brake hard; ease off the gas and pull off slowly."},"42":{"q":"Если ваш автомобиль заглох на железнодорожных путях, что нужно сделать?","options":["Остаться в машине и ждать","Попытаться завести и проскочить перед поездом","Вывести всех и отойти, затем позвать на помощь","Толкать машину вдоль путей"],"explanation":"Get everyone out and away from the tracks, then call for help; never try to beat a train."},"43":{"q":"Что никогда нельзя пытаться сделать на железнодорожных путях?","options":["Остановиться перед путями","Посмотреть в обе стороны","Снизить скорость у путей","Проскочить перед поездом"],"explanation":"You should never try to beat a train across railroad tracks."},"44":{"q":"Если вам необходимо остановиться на дороге, что нужно сделать?","options":["Съехать на обочину и включить аварийную сигнализацию","Остановиться в своей полосе и ждать","Припарковаться наполовину в полосе движения","Не включать фары"],"explanation":"Pull fully onto the shoulder, turn on hazard flashers, and use warning devices."},"45":{"q":"Что нужно включить, остановившись на обочине в аварийной ситуации?","options":["Дальний свет фар","Аварийную сигнализацию (аварийные мигалки)","Лампу освещения салона","Ничего"],"explanation":"When stopped on the roadside in an emergency, turn on your hazard (emergency) flashers."},"46":{"q":"При остановке на дороге в экстренной ситуации, насколько далеко нужно отвести машину?","options":["Остаться в своей полосе движения","Наполовину на обочину","Полностью на обочину","На центральную линию"],"explanation":"Pull fully onto the shoulder so your vehicle is clear of traffic."},"47":{"q":"Что усталость, наркотики и алкоголь делают с водителем?","options":["Улучшают время реакции","Обостряют рассудительность","Не оказывают влияния","Замедляют реакцию и ухудшают суждение"],"explanation":"Fatigue, drugs, and alcohol all slow reaction time and impair judgment."},"48":{"q":"Когда следует воздержаться от вождения?","options":["Когда вы в состоянии опьянения или сонливы","Когда вы хорошо отдохнули","Когда дорога свободна","Когда движение слабое"],"explanation":"You should never drive while impaired or drowsy because it slows your reaction time and judgment."},"49":{"q":"Как усталость (сонливость) влияет на ваше вождение?","options":["Она улучшает вашу концентрацию","Она замедляет реакцию и ухудшает суждение, как наркотики и алкоголь","Она никак не влияет на вождение","Она помогает быстрее тормозить"],"explanation":"Fatigue slows your reaction time and judgment just like drugs and alcohol."},"50":{"q":"Какое действие является серьёзным отвлечением при вождении?","options":["Пристёгивание ремня безопасности","Проверка зеркал","Отправка сообщений или использование телефона в руке","Снижение скорости под дождём"],"explanation":"Texting and handheld phone use is a major distraction and texting while driving is illegal in Texas."},"51":{"q":"В Техасе разрешено отправлять текстовые сообщения за рулём?","options":["Да, это всегда разрешено","Да, только на автомагистралях","Да, если движение медленное","Нет, это запрещено"],"explanation":"Texting while driving is illegal in Texas."},"52":{"q":"Когда вы должны пристёгивать ремень безопасности во время вождения?","options":["Всегда","Только на автомагистралях","Только ночью","Только в дождь"],"explanation":"Texas law requires you to always wear your seat belt while driving."},"53":{"q":"Кто должен пристёгиваться ремнём безопасности в Техасе?","options":["Только водитель","Водитель и все пассажиры","Только сидящие спереди","Только дети младше 12 лет"],"explanation":"Texas law requires the driver and all passengers to wear seat belts."},"54":{"q":"Что такое дистанция реакции?","options":["Расстояние, на котором шины оставляют следы заноса","Расстояние, которое вы держите за другими машинами","Расстояние, которое проезжает ваш автомобиль, пока вы реагируете после того, как заметили опасность","Расстояние, на котором тормоза останавливают автомобиль"],"explanation":"Reaction distance is how far your vehicle travels while you react after perceiving a hazard."},"55":{"q":"Что такое тормозной путь?","options":["Время, которое вы смотрите на дорогу","Расстояние, которое вы проезжаете перед поворотом","Пространство между двумя припаркованными машинами","Расстояние, которое проезжает машина от нажатия на тормоз до остановки"],"explanation":"Braking distance is how far your vehicle travels from when you apply the brakes until it fully stops."},"56":{"q":"Если ваша машина начинает аквапланировать, что вы должны сделать?","options":["Отпустить газ и держать руль прямо","Сразу резко затормозить","Быстро ускориться","Резко повернуть руль"],"explanation":"During hydroplaning, ease off the gas and steer straight instead of braking hard."},"57":{"q":"Что помогает соблюдать правило трёх секунд?","options":["Чистое лобовое стекло","Безопасную дистанцию до впереди идущего","Полный бак топлива","Правильное давление в шинах"],"explanation":"The three-second rule helps you keep a safe following distance behind the vehicle ahead."},"58":{"q":"Когда нужно включать фары днём?","options":["Только на автомагистрали","Только когда на улице темно","Когда вы не видите примерно на 1000 футов вперёд","Никогда днём"],"explanation":"Turn on headlights whenever visibility drops and you cannot see about 1,000 feet ahead, even in daytime rain or fog."},"59":{"q":"Если вы остановились на обочине из-за аварийной ситуации, что нужно сделать?","options":["Оставаться на полосе и ждать","Выключить все огни","Быстро уехать","Выставить аварийные знаки для других водителей"],"explanation":"Warning devices alert other drivers that your vehicle is stopped on the roadside."}},"alcohol-and-penalties":{"0":{"q":"Маркусу 34 года, его останавливают, когда он уезжает с барбекю у друга в Хьюстоне. Офицер подозревает, что он выпивал, и просит пройти тест на алкоголь в выдыхаемом воздухе. При каком уровне содержания алкоголя в крови (BAC) Маркус как взрослый водитель в Техасе по закону считается управляющим автомобилем в состоянии опьянения (DWI)?","options":["0,08% BAC или выше","0,04% BAC или выше","0,15% BAC или выше","Любое обнаруживаемое количество выше 0,00% BAC"],"explanation":"For an adult driver age 21 or older, the Texas DWI limit is 0.08% BAC. 0.04% is the limit for commercial drivers, and any detectable amount (above 0.00%) applies only to drivers under 21 under Zero Tolerance."},"1":{"q":"Маркусу 26 лет, его остановили в Остине после того, как он вилял между полосами. Он проходит тест дыхания, который показывает 0,08% содержания алкоголя в крови (BAC), и говорит офицеру, что чувствует себя совершенно нормально и вёл машину осторожно. Какое правонарушение совершил Маркус согласно законам Техаса на основании этого показателя?","options":["Ничего, потому что 0,08% — это допустимый предел, и он превышает его только тогда, когда показатель выше 0,08%","Вождение в состоянии опьянения (DWI), потому что вождение при содержании алкоголя в крови 0,08% или выше является DWI для взрослого","Вождение под воздействием (DUI), потому что любое обнаруживаемое количество алкоголя делает взрослого виновным в DUI","Ничего, потому что он сказал офицеру, что чувствует себя нормально, и не проявлял реального опьянения"],"explanation":"For an adult 21 or older, driving at or above 0.08% BAC is the offense of Driving While Intoxicated (DWI), so reaching exactly 0.08% counts. The Zero Tolerance DUI for any detectable alcohol applies only to drivers under 21, and feeling 'fine' does not change the legal BAC limit."},"2":{"q":"30-летнего водителя останавливают после того, как он петлял по полосам движения. Тест дыхания показывает 0,06% BAC, но офицер замечает невнятную речь и плохую координацию, характерные для алкогольного опьянения. Что может произойти согласно законам Техаса?","options":["Ничего, потому что 0,06% ниже взрослого предела 0,08%, поэтому DWI не может применяться","Водитель автоматически оправдан, как только тест дыхания показывает менее 0,08%","Водителя все равно могут обвинить в DWI, потому что он находится под воздействием алкоголя, даже несмотря на то, что BAC ниже 0,08%","Водителю могут предъявить только нарушение за открытую тару, но не DWI"],"explanation":"In Texas, a driver can be charged with DWI below 0.08% BAC if alcohol or drugs impair them, so the observed impairment supports a DWI charge. The 0.08% figure is a per se limit, not a safe harbor, so being under it does not automatically clear the driver."},"3":{"q":"Маркус водит коммерческий тягач с прицепом для грузовой компании. После долгой смены он выпивает два пива за ужином, и более поздний тест на алкоголь показывает 0,05% BAC. Он утверждает, что значительно ниже допустимого предела и может продолжать управлять своим грузовиком. Прав ли он и какой предел применяется?","options":["Он прав; предел для всех водителей в Техасе составляет 0,08% BAC, поэтому 0,05% законно.","Он прав, потому что любой BAC ниже 0,08% никогда не может привести к обвинению.","Он превысил предел, потому что в Техасе действует нулевая терпимость, и любой обнаруживаемый алкоголь для него незаконен.","Он превысил предел; для коммерческих водителей действует более низкий предел 0,04% BAC, а 0,05% его превышает."],"explanation":"Commercial drivers in Texas are held to a lower limit of 0.04% BAC, so Marcus's 0.05% reading puts him over the limit. The 0.08% figure (A) is the standard adult limit, not the commercial one, and zero tolerance (C) applies only to drivers under 21, not commercial drivers."},"4":{"q":"Маркусу 19 лет, и он едет домой с вечеринки у друга, где выпил одну бутылку пива. Полицейский законно останавливает его, и тест дыхания показывает уровень алкоголя в крови (BAC) 0,03%. Каков его правовой статус по законам Техаса?","options":["Ему запрещено водить — по закону Техаса о нулевой терпимости любое обнаруживаемое количество алкоголя (BAC выше 0,00) для водителя младше 21 года является DUI несовершеннолетнего.","Ему разрешено водить, потому что его BAC 0,03% ниже предела DWI в 0,08%.","Ему разрешено водить, потому что его BAC 0,03% ниже предела 0,04% для водителей коммерческого транспорта.","Ему разрешено водить, потому что он выпил только один напиток, а печень перерабатывает один стандартный напиток в час."],"explanation":"For drivers under 21, Texas has Zero Tolerance, so ANY detectable alcohol (a BAC above 0.00) is illegal and is a DUI by a minor. The 0.08% adult DWI limit and the 0.04% commercial limit do not apply to a 19-year-old minor, making those traps wrong."},"5":{"q":"19-летний водитель уезжает с вечеринки, и его останавливают в Техасе. Тест дыхания показывает концентрацию алкоголя в крови (BAC) 0,03%, что намного ниже взрослого предела в 0,08%. Какое правонарушение, если таковое имеется, совершил водитель?","options":["Ничего, потому что BAC ниже взрослого предела в 0,08%","DUI (вождение под воздействием) алкоголя несовершеннолетним, потому что любое обнаружимое количество алкоголя незаконно для лиц до 21 года","DWI, потому что водитель автоматически считается в состоянии опьянения при любом BAC","Ничего, но водительские права приостановлены на 180 дней из-за подразумеваемого согласия"],"explanation":"Texas has a Zero Tolerance law for drivers under 21: any detectable alcohol (a BAC above 0.00) is a DUI of alcohol by a minor, regardless of the 0.08% adult DWI limit. Option A wrongly applies the adult threshold to a minor, and the 180-day suspension in D is the penalty for refusing a test, not for a 0.03% reading."},"6":{"q":"На вечеринке Маркус выпил пару кружек пива и чувствует себя спокойным и расслабленным, поэтому говорит другу, что после выпивки он на самом деле более безопасный и осторожный водитель. Друг предупреждает, что это опасно. Почему алкоголь делает Маркуса более опасным водителем, даже если он чувствует себя расслабленным?","options":["Алкоголь — это стимулятор, который ускоряет сердцебиение и делает его чрезмерно агрессивным за рулём","Алкоголь влияет на водителей только тогда, когда их концентрация алкоголя в крови достигает законного предела 0,08%, поэтому две кружки пива не могут его ослабить","Алкоголь — это депрессант, который замедляет реакцию и ухудшает рассудительность, даже если он чувствует себя расслабленным","Алкоголь обостряет его зрение и координацию, но притупляет способность соблюдать дорожные сигналы"],"explanation":"Alcohol is a depressant, so it slows reaction time and impairs judgment even when the drinker feels calm and relaxed. It is not a stimulant (A is the wrong category), and a driver can be impaired well below 0.08% (B is false), making C correct."},"7":{"q":"Возвращаясь домой с вечеринки, где он выпил несколько напитков, Маркус замечает, что постоянно смещается в своей полосе, путается, когда тянется к указателю поворота, и реагирует с опозданием, когда машина впереди тормозит. Какое сочетание эффектов алкоголя лучше всего объясняет то, что он испытывает?","options":["Уровень алкоголя в его крови повышается, потому что свежий ночной воздух ускоряет возвращение алкоголя в кровоток.","Алкоголь действует как стимулятор, поэтому он обостряет его внимание, но делает движения мышц нервными и резкими.","Эффекты вызваны только усталостью; сам алкоголь уже выветрился, так как с момента последнего напитка прошло более часа.","Алкоголь замедлил его время реакции, ухудшил рассудительность и снизил координацию и зрение."],"explanation":"Alcohol is a depressant that slows reaction time, impairs judgment, and reduces coordination and vision, which matches Marcus's lane drifting, fumbling, and delayed braking. Alcohol is not a stimulant and does not sharpen focus, and only time lowers BAC, so fresh air and the passage of one hour do not undo the impairment."},"8":{"q":"После двух кружек пива в гостях у друга Маркус чувствует себя физически нормально, руки не дрожат, речь не нарушена, поэтому он решает, что может безопасно ехать домой, и даже ускоряется, чтобы успеть на жёлтый сигнал, перед которым обычно остановился бы. Какую из его способностей алкоголь, скорее всего, нарушил ПЕРВОЙ, что привело к этому рискованному решению?","options":["Его рассудительность (способность здраво оценивать ситуацию) — первая способность вождения, на которую влияет алкоголь","Его зрение, которое всегда является первой способностью, на которую влияет алкоголь","Его координацию, ведь не дрожащие руки доказывают, что рассудительность сохранена","Его время реакции, на которое алкоголь влияет раньше всего остального"],"explanation":"Рассудительность — первая способность вождения, на которую влияет алкоголь, поэтому Маркус принял рискованное решение проскочить на жёлтый, хотя физически чувствовал себя нормально. Зрение, координация и время реакции тоже нарушаются алкоголем, но это происходит после рассудительности, а не до неё."},"9":{"q":"На вечеринке ваш друг выпил несколько порций алкоголя за последние два часа и теперь хочет ехать домой за рулём. Он уверяет, что с ним всё в порядке, потому что только что выпил две большие чашки чёрного кофе, плотно поел и вышел на холодный воздух, чтобы 'прояснить голову'. Что вы должны сказать ему о его способности безопасно вести машину?","options":["Кофе и холодный воздух ускорили переработку алкоголя организмом, поэтому теперь он может безопасно вести машину.","Ничто из этого не снижает уровень алкоголя в крови; протрезветь помогает только время, поэтому ему не следует садиться за руль.","Плотная еда впитывает алкоголь, уже находящийся в крови, поэтому уровень алкоголя теперь снова в допустимых пределах.","Раз он чувствует себя бодрым, его рассудительность и скорость реакции полностью восстановились, и он может законно вести машину."],"explanation":"Only the passage of time lowers BAC, because the liver processes alcohol at a fixed rate of about one drink per hour. Coffee, food, cold air, and feeling alert do not speed up sobering or reduce impairment, so he should not drive."},"10":{"q":"На вечеринке ваш друг за последние два часа выпил несколько кружек пива и теперь хочет ехать домой. Он говорит, что будет в порядке за рулём, если сначала выпьет крепкого кофе, плотно поест и примет холодный душ. Исходя из того, что вы знаете о том, как алкоголь выводится из организма, какой ответ наиболее точен?","options":["Кофе и холодный душ быстро его протрезвят, поэтому он сможет ехать, как только снова почувствует бодрость.","Плотная еда впитает уже находящийся в крови алкоголь и снизит уровень BAC достаточно, чтобы безопасно вести машину.","Ничто из этого не ускорит протрезвление; только время снижает уровень BAC, поэтому ему не следует садиться за руль.","Свежий воздух по дороге домой очистит его организм от алкоголя, поэтому короткая поездка допустима."],"explanation":"Only the passage of time lowers BAC because the liver processes about one standard drink per hour, and nothing makes it faster. Coffee, food, a cold shower, and fresh air may make a person feel more alert but do not reduce intoxication, so they are dangerous myths."},"11":{"q":"Маркус выпил четыре стандартные порции спиртного на вечеринке, которая закончилась в полночь. Он выпивает две большие чашки кофе, плотно ест и принимает холодный душ, прежде чем поехать домой в 1:30 ночи. Он чувствует себя бодрым. Что верно в отношении его способности безопасно управлять автомобилем?","options":["Кофе и еда достаточно снизили его уровень алкоголя в крови, и теперь он может безопасно вести машину","Холодный душ ускорил работу его печени, поэтому большая часть алкоголя уже выведена","Поскольку он чувствует себя бодрым и мыслит ясно, он может вести машину","Только время может снизить уровень алкоголя в крови; его печень выводит около одной порции в час, поэтому он, скорее всего, всё ещё в состоянии опьянения"],"explanation":"The liver processes only about one standard drink per hour and nothing speeds it up, so after roughly 90 minutes Marcus has cleared at most one or two of his four drinks. Coffee, food, and a cold shower do not lower BAC, and feeling alert is misleading because judgment is the first ability alcohol impairs."},"12":{"q":"Маркус выпил одно пиво за ужином и чувствует лишь лёгкое опьянение. Ранее в тот же день он принял безрецептурную таблетку от аллергии, на которой есть предупреждение о возможной сонливости. Он решает, что одно пиво намного ниже законного предела, поэтому можно ехать домой. В чём реальная опасность в его ситуации?","options":["Безрецептурное лекарство в сочетании с алкоголем может многократно усилить его состояние опьянения, сделав вождение гораздо опаснее, чем предполагало бы одно пиво","Ничего страшного, потому что безрецептурные лекарства разрешены и не могут влиять на способность вести машину","Он в безопасности, если поест побольше и выпьет кофе, чтобы нейтрализовать совместное действие перед отъездом","Он в опасности, только если его BAC достигнет предела 0,04% для коммерческих водителей, чего одно пиво дать не может"],"explanation":"Drugs of any kind—including legal over-the-counter medicines—combined with alcohol multiply impairment, so Marcus can be far more impaired than one beer alone would suggest. Coffee and food do not speed sobering, and the 0.04% limit applies only to commercial drivers, not Marcus."},"13":{"q":"Маркуса останавливают поздно ночью в Остине и законно арестовывают за вождение в нетрезвом виде (DWI). В участке офицер просит его сдать пробу дыхания. Маркус говорит, что никогда не соглашался на какой-либо тест, и отказывается. Согласно законам Техаса, на каком основании он уже считался давшим согласие?","options":["Он согласился, когда подписал документы об аресте в участке, поэтому тест теперь обязателен.","Управляя автомобилем в Техасе, он дал подразумеваемое согласие на тест дыхания или крови при законном аресте за DWI.","Он согласился только потому, что его уровень алкоголя в крови уже был измерен на уровне 0,08% или выше во время остановки.","Он дал согласие, когда подавал заявление на получение водительского удостоверения Техаса, что навсегда отменяет любые отказы."],"explanation":"Texas law states that by driving in the state you give implied consent to a breath or blood test if lawfully arrested for DWI, so consent already exists at the time of arrest. Option A is wrong because consent comes from the act of driving, not signing paperwork, and a 0.08% reading or the license application does not establish it."},"14":{"q":"Маркуса законно арестовали за вождение в нетрезвом виде (DWI) после остановки поздно ночью. В участке офицер просит его предоставить образец выдыхаемого воздуха, но Маркус отказывается, полагая, что без теста против него не будет доказательств. Если отложить в сторону само обвинение в DWI, что произойдёт с его водительскими правами исключительно из-за того, что он отказался от теста?","options":["С его правами ничего не случится, потому что по принципу подразумеваемого согласия водитель всегда имеет право отказаться от теста дыхания или крови без последствий","Его права будут приостановлены на срок до 1 года за этот первый отказ","Его права автоматически приостанавливаются на 180 дней за этот первый отказ","Ему грозит штраф в размере 2 000 долларов и до 180 дней тюрьмы за отказ от теста"],"explanation":"Under Texas implied consent, refusing a lawful breath or blood test triggers an automatic 180-day license suspension for a first refusal under Administrative License Revocation, separate from any DWI charge. The 'up to 1 year' suspension and the $2,000 fine/jail time are penalties for a DWI conviction, not for refusing the test, and refusal does carry consequences."},"15":{"q":"Маркуса законно арестовывают за вождение в нетрезвом виде (DWI) в Техасе после того, как он не прошёл придорожную проверку на трезвость. В участке он отказывается сдать пробу дыхания или крови, полагая, что без результата теста у штата нет дела, а его права в безопасности. Несколько месяцев спустя обвинение в DWI прекращают в суде. Каков статус его водительских прав?","options":["Поскольку обвинение в DWI было прекращено, никакое лишение не применяется, и его права остаются полностью действительными.","Его права приостановлены на срок до 1 года — стандартное наказание, связанное с первым осуждением за DWI.","Ему грозит только штраф в размере 2000 долларов за отказ, но его права не приостанавливаются.","Его права автоматически приостанавливаются на 180 дней в рамках административного отзыва лицензии (ALR) за отказ, отдельно от прекращённого обвинения в DWI."],"explanation":"Refusing a breath or blood test triggers an automatic 180-day ALR suspension that is entirely separate from the DWI case, so it stands even though the DWI charge was dismissed. Option B wrongly applies the up-to-1-year suspension tied to a DWI conviction, which never occurred here, and the dismissal does not erase the refusal-based ALR suspension."},"16":{"q":"В баре в Хьюстоне 24-летний Маркус выпивает несколько порций алкоголя, затем едет домой и его останавливают с уровнем алкоголя в крови (BAC) 0,11%. Его арестовывают и признают виновным в первом вождении в состоянии опьянения (DWI), без предыдущих нарушений и без пассажиров в машине. Какой максимальный штраф суд может назначить за это первое осуждение за DWI?","options":["До 2 000 долларов","До 500 долларов","До 4 000 долларов","До 10 000 долларов"],"explanation":"A first DWI in Texas carries a fine of up to $2,000, along with possible jail time and license suspension. The $500 figure is the maximum fine for a minor's first DUI, and the higher amounts apply to repeat or aggravated offenses, not a standard first DWI."},"17":{"q":"Маркуса осудили за первое в Техасе вождение в нетрезвом виде (DWI) после того, как его остановили при выезде с вечеринки друга с уровнем алкоголя в крови 0,10%. Судья теперь определяет срок заключения в пределах, установленных законом Техаса для первого DWI. Какой возможный срок тюремного заключения может назначить судья?","options":["До 1 года тюремного заключения","От 3 до 180 дней тюремного заключения","Фиксированное лишение прав на 180 дней вместо тюрьмы","Без тюрьмы, только штраф 500 долларов"],"explanation":"Under Texas law, a first DWI carries 3 days to 180 days in jail, so the judge's range is set by that statute. The 1-year figure is the license suspension (not jail), the 180-day suspension applies to refusing a chemical test under ALR, and the $500 fine is a minor's first DUI penalty."},"18":{"q":"Маркус, 28 лет, остановлен полицией, когда уезжал с вечеринки в пятницу вечером. Он проходит тест на алкоголь, показывает 0,10% BAC и осужден за первое вождение в нетрезвом виде (DWI) в Техасе. У него нет пассажира-ребенка и нет прежних правонарушений. При вынесении приговора, на какой максимальный срок может быть приостановлено его водительское удостоверение за это первое осуждение за DWI?","options":["180 дней — тот же срок, что назначается за отказ от теста на алкоголь","Без приостановления, поскольку его BAC был ниже 0,15%","До 1 года","До 2 лет — стандартный срок за любое DWI"],"explanation":"A first DWI conviction in Texas carries a license suspension of up to 1 year. The 180-day figure is the separate automatic suspension for refusing a chemical test under implied consent, not the penalty for a DWI conviction, so option A is a trap."},"19":{"q":"Маркуса в прошлом году в Техасе осудили за вождение в нетрезвом виде (DWI); он заплатил штраф и отбыл наказание. Сегодня вечером его остановили и арестовали за DWI во второй раз. По сравнению с первым осуждением, чего ему следует ожидать за это повторное нарушение?","options":["Наказание точно такое же, как за первое DWI: максимальный штраф 2000 долларов и приостановка действия прав на срок до 1 года.","Дополнительных наказаний нет, потому что в Техасе учитывается только последнее осуждение за DWI.","Его права автоматически приостанавливаются на 180 дней, и это заменяет любое другое наказание за DWI.","Наказание за повторное нарушение усиливается, поэтому ему грозят более крупные штрафы, более длительный тюремный срок и более долгая приостановка прав, чем за первое DWI."],"explanation":"Texas law increases DWI penalties for repeat offenses, so a second conviction brings tougher consequences than the first. Option A wrongly states the first-offense maximums ($2,000 / 1 year) apply unchanged, and option C confuses the 180-day ALR suspension for refusing a test with the criminal DWI penalty."},"20":{"q":"Маркуса останавливают по дороге домой с вечеринки. Ему 27 лет, это его первый в жизни арест за вождение в состоянии опьянения (DWI), и тест на алкоголь показывает уровень BAC 0,16%. Его друг говорит, что наказание будет точно таким же, как при любом другом первом нарушении DWI. Почему друг ошибается?","options":["Потому что уровень BAC 0,15% или выше влечёт за собой ужесточение наказания даже при первом нарушении.","Потому что отказ от теста на дыхание всегда удваивает стандартный штраф за первое нарушение.","Потому что любое первое нарушение DWI автоматически квалифицируется как тяжкое преступление (felony).","Потому что наказание ужесточается только если в автомобиле находится ребёнок младше 15 лет."],"explanation":"In Texas, penalties for a first DWI increase when the driver's BAC is 0.15% or higher, so Marcus's 0.16% reading means enhanced penalties. A child passenger under 15 (D) is a separate felony enhancement, but it does not apply here since Marcus was alone."},"21":{"q":"По дороге домой с вечеринки Маркуса останавливают, и его анализ показывает уровень алкоголя в крови 0,10%. Это его первое нарушение DWI (вождение в нетрезвом виде), но на заднем сиденье пристёгнута его 8-летняя племянница. Как наличие ребёнка-пассажира меняет классификацию этого правонарушения?","options":["Это никак не влияет на обвинение, потому что это всё равно его первое нарушение","Вождение в нетрезвом виде с ребёнком-пассажиром младше 15 лет делает это правонарушение тяжким преступлением (фелонией)","Это добавляет автоматическое лишение прав на 180 дней по правилу об открытой таре","Это повышает максимальный штраф до 500 долларов, потому что вовлечён несовершеннолетний"],"explanation":"In Texas, DWI with a child passenger under age 15 is a felony, regardless of whether it is a first offense. The 180-day suspension belongs to refusing a chemical test, and the $500 figure is the fine for a minor's own first DUI, not a penalty tied to carrying a child passenger."},"22":{"q":"Водителя в Техасе останавливают, он проходит проверку на трезвость и показывает уровень алкоголя в крови 0,05%, поэтому офицер не предъявляет ему обвинение в вождении в нетрезвом виде (DWI). Однако офицер замечает наполовину пустую бутылку пива в подстаканнике рядом с водителем. Как закон Техаса трактует эту открытую емкость с алкоголем в пассажирской зоне?","options":["Это игнорируется, поскольку его уровень алкоголя в крови был ниже допустимого предела 0,08%.","Это автоматически лишает его прав на 180 дней в рамках подразумеваемого согласия.","Это отдельное правонарушение, не связанное с обвинением в вождении в нетрезвом виде (DWI).","Это правонарушение только в том случае, если в автомобиле находится ребенок младше 15 лет."],"explanation":"Having an open container of alcohol in the passenger area is a separate offense in Texas, independent of whether a DWI charge applies or what the driver's BAC was. The 180-day suspension relates to refusing a chemical test under implied consent, and the child-passenger rule concerns the felony DWI enhancement, not open containers."},"23":{"q":"Маркусу 18 лет, и его останавливают, когда он едет домой с вечеринки. Тест дыхания показывает содержание алкоголя в крови (BAC) 0,02%, и его осуждают за первое DUI (вождение в состоянии алкогольного опьянения) как несовершеннолетнего. Помимо приостановки действия водительских прав, общественных работ и курса по информированию об алкоголе, какой максимальный штраф ему грозит за это первое нарушение?","options":["До 2000 долларов — тот же штраф, что и за первое DWI для взрослого","Никакого штрафа, поскольку BAC был ниже взрослого предела 0,08%","До 1000 долларов, удвоено из-за того, что был обнаружен алкоголь","До 500 долларов"],"explanation":"Under Texas zero-tolerance law, a minor's first DUI (alcohol) carries a fine of up to $500, along with license suspension, community service, and an alcohol-awareness course. The $2,000 figure is the maximum for an adult first DWI, and no fine being charged is wrong because any detectable alcohol is illegal for a driver under 21."},"24":{"q":"Маркусу 19 лет, его останавливают по дороге домой с вечеринки. Полицейский чувствует запах алкоголя, а тест на алкоголь показывает уровень BAC 0,03%. Это первое нарушение Маркуса, связанное с алкоголем. Что произойдет с его правом на вождение по законам Техаса?","options":["Его права будут приостановлены, поскольку любое обнаруживаемое количество алкоголя у водителя младше 21 года является DUI и влечет приостановление прав.","С его правами ничего не случится, поскольку его BAC ниже законного предела 0,08%.","Его права будут приостановлены на 180 дней именно за отказ от теста на алкоголь.","Ему грозит обвинение в тяжком преступлении и приостановление прав на год, поскольку его BAC был измерен."],"explanation":"Texas has zero tolerance for drivers under 21, so any detectable alcohol (above 0.00%) is a DUI for a minor and carries a license suspension. The 0.08% limit (B) applies only to adults 21+, the 180-day suspension (C) is for refusing a test, and a felony (D) does not result from a minor's first DUI."},"25":{"q":"Маркуса, 19 лет, останавливают в Остине поздно ночью. Офицер чувствует небольшой запах алкоголя в его дыхании, и тест подтверждает содержание алкоголя в крови (BAC) 0,03%. Это его первое нарушение. Согласно закону Техаса о нулевой терпимости, что будет включено в его наказание?","options":["Только письменное предупреждение, поскольку его BAC значительно ниже взрослого предела 0,08%","Штраф до 500 долларов, приостановление действия водительских прав, общественные работы и курс по информированию об алкоголе","До 180 дней тюрьмы и штраф 2000 долларов, как при DWI для взрослого","Автоматическое приостановление на 180 дней за отказ от теста на алкоголь"],"explanation":"Because Marcus is under 21, any detectable alcohol is a DUI by a minor under zero-tolerance, and a first offense carries a fine up to $500, license suspension, community service, and an alcohol-awareness course. The 0.08% adult limit and adult DWI jail/fine penalties do not apply to a minor's first DUI, and the 180-day suspension is for refusing the test, which he did not refuse."},"26":{"q":"Маркусу 19 лет, его остановили, когда он уезжал с вечеринки в Остине. Тест дыхания показал концентрацию алкоголя в крови (BAC) 0,03%, и его осудили за первое DUI несовершеннолетним. Какой из следующих пунктов является обязательной частью его наказания согласно закону Техаса о нулевой терпимости?","options":["Ничего дополнительно, потому что его BAC был ниже взрослого предела 0,08%","Автоматическое лишение прав на 180 дней исключительно за прохождение теста дыхания","Прохождение курса информирования об алкоголе","Обязательный минимум 3 дня тюремного заключения"],"explanation":"A minor's first DUI for alcohol requires completion of an alcohol-awareness course (plus a fine up to $500, license suspension, and community service). Option A is wrong because under-21 zero tolerance makes ANY detectable alcohol illegal, and the 3-day jail minimum (D) and the 180-day suspension for refusing a test (B) belong to adult DWI and refusal rules, not a minor's first DUI."},"27":{"q":"Маркус получил три штрафа за превышение скорости и один штраф за проезд на красный свет за последние два года. Он беспокоится о том, что эти нарушения правил движения означают для его водительского досье в Техасе помимо уже оплаченных штрафов. Какое последствие накопления этих нарушений правил дорожного движения наиболее точно?","options":["После оплаты штрафов больше ничего не происходит; нарушения не влияют на его досье.","Каждое нарушение автоматически обязывает его иметь страховку финансовой ответственности SR-22.","Нарушения влекут автоматическое лишение прав на 180 дней после второго штрафа.","Нарушения добавляют баллы в его досье, и при их избытке возможны доплаты (surcharges) и лишение прав."],"explanation":"Traffic convictions add points to your Texas driving record, and accumulating too many can result in surcharges and license suspension. SR-22 is tied to serious offenses like a DWI rather than ordinary tickets, and the automatic 180-day suspension applies to refusing a breath/blood test under implied consent, not to routine moving violations."},"28":{"q":"Маркус накопил несколько обвинительных приговоров за нарушения ПДД за последние два года по своим водительским правам штата Техас. На последнем судебном заседании судья предупреждает его, что дальнейшее накопление приговоров повлечёт за собой дополнительные последствия помимо отдельных штрафов. Согласно системе баллов/доплат (surcharge) Техаса, к чему в итоге может привести слишком большое число обвинительных приговоров?","options":["Доплатам (surcharges) и приостановке действия прав","Автоматической приостановке на 180 дней за отказ от теста на дыхание","Обязательной страховке SR-22 только если один приговор связан с открытой ёмкостью алкоголя","Уголовным обвинениям, потому что повторные приговоры приравниваются к DWI с ребёнком"],"explanation":"Under the Texas point/surcharge system, traffic convictions add points to your record, and too many convictions can lead to surcharges and license suspension. The 180-day suspension applies specifically to refusing a breath or blood test (implied consent), not to accumulating ordinary convictions, so that option is a misplaced fact."},"29":{"q":"Маркус был осужден за первое вождение в нетрезвом виде (DWI) в Техасе год назад. Теперь он отбыл срок приостановления прав и оплатил штраф, но его страховая компания отказала ему, а единственные полисы, которые он может найти, стоят почти втрое дороже, чем он платил раньше. Он звонит в DPS, чтобы узнать, почему его ситуация с вождением все еще затронута спустя столько времени после завершения дела. Какое наиболее точное объяснение он получит?","options":["Как только штраф оплачен, а срок приостановления отбыт, DWI автоматически удаляется из его записи, поэтому любые высокие тарифы — это не связанная с этим ошибка в счете.","Осуждение за DWI остается в его записи и резко повышает стоимость страховки, и от него могут потребовать оформить страховку финансовой ответственности SR-22 для восстановления права на вождение.","Высокая стоимость — это лишь временная надбавка на 180 дней, связанная с его отказом от теста на алкоголь в выдыхаемом воздухе, и она исчезнет после окончания этого периода.","В его записи теперь указано DWI, но страховщикам в Техасе по закону запрещено повышать тарифы на основании одного первого нарушения."],"explanation":"A DWI conviction stays on the driver's record and sharply raises insurance costs, and an SR-22 financial responsibility filing may be required to reinstate driving privileges. Option A is wrong because completing penalties does not erase the conviction, and option C confuses this with the separate 180-day ALR suspension for refusing a test."},"30":{"q":"Маркус отбыл назначенное судом наказание за первое осуждение за вождение в нетрезвом виде (DWI), и срок приостановки действия его прав на один год теперь истёк. Когда он приходит в офис DPS, чтобы восстановить право управления автомобилем, служащий говорит ему, что сначала он должен подать определённую форму, подтверждающую наличие у него достаточного страхового покрытия ответственности на будущее. Как называется это требование?","options":["Декларация об открытой таре, подтверждающая, что он не держит алкоголь в пассажирской зоне","Отказ от подразумеваемого согласия, признающий будущие тесты дыхания или крови","Страхование финансовой ответственности SR-22","Сертификат о прохождении курса по информированию об алкоголе"],"explanation":"After a DWI, Texas may require SR-22 financial responsibility insurance to prove coverage before driving privileges are reinstated. The alcohol-awareness course is tied to a minor's DUI penalty, not the insurance reinstatement requirement, and implied consent and open container are unrelated to proving financial responsibility."},"31":{"q":"Вам 28 лет, и за ужином у друга вы выпили два пива. Вы чувствуете себя совершенно нормально, и вам предстоит 25-минутная поездка домой по тихим дорогам. Какой выбор самый безопасный?","options":["Поехать домой, ведь два напитка всегда удерживают взрослого ниже законного предела 0,08%","Подождать около 20 минут, выпить кофе и поехать, когда почувствуете бодрость","Поехать сейчас, ведь вы не считаетесь юридически пьяным, пока ваше суждение явно не нарушено","Вообще не садиться за руль; вызвать службу такси, попросить трезвого водителя или остаться на месте"],"explanation":"The safest choice is always zero alcohol before driving, so arranging a sober ride or staying put is correct. Two beers will not reliably keep you under 0.08%, and only time (not coffee) lowers BAC, so the other options are dangerous mistakes."},"32":{"q":"Вы встречаетесь с друзьями в баре после работы и выпиваете несколько напитков за два часа. Вы чувствуете действие алкоголя и понимаете, что не в состоянии безопасно ехать домой. Как безопаснее всего добраться домой?","options":["Вызвать службу такси, отдать ключи непьющему другу или просто остаться на месте, пока не протрезвеете","Выпить несколько чашек крепкого кофе и подождать около 30 минут, прежде чем ехать домой","Плотно поесть и принять холодный душ, чтобы быстрее протрезветь перед поездкой","Подождать по одному часу на каждый напиток, сидя в машине, а затем ехать домой самому"],"explanation":"The safe, always-true choices are to use a ride service, designate a sober driver, or stay put until sober. Coffee, food, and a cold shower do NOT speed up sobering; only time lowers BAC, and the answer to alcohol is not to drive at all rather than wait it out in your car and then drive."},"33":{"q":"Маркусу 24 года, и он едет домой на собственной машине после званого ужина. Полицейский останавливает его, и тест на алкоголь показывает уровень BAC ровно 0,08%. При таком показателе кем по закону штата Техас считается Маркус?","options":["Он не превышает допустимый предел, потому что порог 0,08% применяется только к водителям коммерческого транспорта","Он управляет транспортом в состоянии опьянения (DWI), потому что для взрослых от 21 года BAC на уровне 0,08% или выше является установленным законом порогом","Он виновен только в том случае, если у него также есть видимые признаки опьянения, поскольку одного показателя 0,08% недостаточно","Он совершил DUI по правилу нулевой терпимости, поскольку любое обнаруживаемое количество алкоголя незаконно"],"explanation":"For adults 21 and older, driving at or above 0.08% BAC is Driving While Intoxicated (DWI), so Marcus's exact 0.08% reading meets the threshold. The 0.04% commercial limit and the Zero Tolerance rule for drivers under 21 do not apply to a 24-year-old in his personal vehicle, and no additional visible impairment is required at or above 0.08%."},"34":{"q":"Маркусу 19 лет. После выпускной вечеринки его останавливают, и тест на дыхание показывает уровень алкоголя в крови (BAC) 0,03%. Он утверждает, что его нельзя обвинить, потому что его показатель значительно ниже взрослого лимита 0,08%. Что верно в его ситуации согласно законам Техаса?","options":["Он прав; обвинение не предъявляется, потому что 0,03% ниже лимита DWI в 0,08%.","Его можно обвинить только если его BAC достигает 0,04%, лимита для коммерческих водителей.","Поскольку ему меньше 21 года, применяется политика нулевой терпимости, поэтому любой обнаруживаемый алкоголь делает это DUI несовершеннолетним.","Ему грозит обвинение в DWI как тяжкое преступление, потому что 0,03% считается высоким BAC для несовершеннолетнего."],"explanation":"Политика нулевой терпимости в Техасе делает любой обнаруживаемый алкоголь (BAC выше 0,00) незаконным для водителей младше 21 года, поэтому Маркусу предъявляется обвинение в DUI как несовершеннолетнему, независимо от того, что у него менее 0,08%. Взрослый лимит 0,08% и коммерческий лимит 0,04% не применяются к несовершеннолетним, и 0,03% не является ситуацией тяжкого преступления с высоким BAC."},"35":{"q":"Марию останавливают в Остине за то, что она виляла по полосам. Это её первый в жизни арест за вождение в состоянии опьянения (DWI), её BAC составляет 0,10%, а её 9-летний племянник пристёгнут на заднем сиденье. Как присутствие ребёнка меняет юридическую серьёзность её DWI?","options":["Ничего не меняется; пассажир-ребёнок влияет только на размер штрафа, который возрастает максимум до 2000 долларов","Её права автоматически приостанавливают на 180 дней, потому что в автомобиле находился ребёнок","Это остаётся стандартным проступком за первое нарушение, но она также должна пройти курс по информированию об алкоголе","Поскольку в машине находился ребёнок-пассажир младше 15 лет, правонарушение переходит из категории проступка в категорию тяжкого преступления (фелония)"],"explanation":"Under Texas law, a DWI committed with a child passenger younger than 15 in the vehicle is elevated to a felony, regardless of it being a first offense. Option B confuses this with the 180-day ALR suspension for refusing a chemical test, and the $2,000 fine in A is the standard first-offense misdemeanor penalty, not the felony enhancement triggered by the child."},"36":{"q":"Вас законно арестовали за вождение в нетрезвом виде (DWI) в Остине. Офицер просит вас пройти тест на алкоголь по дыханию, но вы отказываетесь, заявляя, что согласитесь только сдать анализ крови. Что верно в вашей ситуации согласно закону Техаса о подразумеваемом согласии?","options":["Управляя автомобилем в Техасе, вы дали подразумеваемое согласие на тест по дыханию ИЛИ по крови, поэтому тип теста не ограничивается одним; отказ от запрошенного теста может повлечь автоматическое приостановление прав.","Подразумеваемое согласие распространяется только на тест по дыханию, поэтому вы вправе потребовать вместо него анализ крови без последствий.","Подразумеваемое согласие применяется только к анализу крови, поэтому отказ от теста по дыханию не влечёт никаких последствий.","Поскольку вы предложили альтернативу, печень переработает алкоголь в течение часа и тест не нужен."],"explanation":"Texas implied consent covers a breath OR blood test, not just one type, so you can't limit it to your preferred test; refusing the lawfully requested test triggers an automatic 180-day suspension under ALR. Options B and C wrongly restrict implied consent to a single test type, and D confuses the unrelated fact that the liver processes about one drink per hour."},"37":{"q":"После пары кружек пива за ужином водитель замечает, что встречные фары теперь кажутся размытыми, и ему трудно различать края своей полосы и пешехода, сходящего с тротуара. Какой эффект алкоголя лучше всего объясняет то, что он испытывает за рулём?","options":["Алкоголь действует как стимулятор, обостряющий концентрацию, поэтому размытость вызвана его фарами, а не алкоголем","Алкоголь является депрессантом, который снижает зрение, из-за чего объекты труднее видеть чётко и сужается то, что он способен заметить","Алкоголь влияет на зрение только тогда, когда водитель превышает установленный предел 0,08%, поэтому ниже этого его зрение не страдает","Алкоголь ускоряет реакцию, что лишь делает близкие объекты размытыми на высокой скорости"],"explanation":"Alcohol is a depressant that reduces vision among the abilities it impairs, so blurry headlights and trouble seeing the lane and pedestrian are direct effects of the alcohol. Option C is wrong because alcohol can impair vision and driving even below 0.08%, and A and D misstate alcohol as a stimulant or claim it speeds reaction time, when it actually slows reactions."},"38":{"q":"Выпив три бокала пива в гостях у друга, Маркус садится за руль. По дороге домой он замечает, что постоянно съезжает со своей полосы, а его руки кажутся неуклюжими и медленными, когда он пытается делать небольшие корректировки руля. Какое воздействие алкоголя на его организм лучше всего объясняет, почему его управление рулём стало небрежным и неточным?","options":["Алкоголь ускоряет его реакцию, поэтому он чрезмерно корректирует руль","Алкоголь действует как стимулятор, делая его мышцы напряжёнными и резкими","Алкоголь снижает его координацию, затрудняя плавное и точное управление рулём","Алкоголь уже выветрился, потому что три бокала пива ниже допустимого предела"],"explanation":"Alcohol is a depressant that reduces coordination, which is exactly why smooth, precise steering becomes difficult. Option A is wrong because alcohol slows reaction time rather than speeding it up, and option B is wrong because alcohol is a depressant, not a stimulant."},"39":{"q":"Поздно ночью офицер останавливает Маркуса за то, что он вилял между полосами. После полевых тестов на трезвость офицер законно арестовывает Маркуса за вождение в состоянии опьянения (DWI), а затем просит его предоставить пробу дыхания. Согласно закону Техаса о подразумеваемом согласии, что сделало законным требование офицера пройти этот тест на алкоголь в выдыхаемом воздухе?","options":["Уровень алкоголя в крови Маркуса уже был измерен на уровне 0,08% или выше до какого-либо ареста","Маркус подписал отказ от подразумеваемого согласия при продлении водительских прав","Офицер видел, как Маркус вилял между полосами, и одного этого достаточно, чтобы обязать пройти тест","Маркус был законно арестован за вождение в состоянии опьянения (DWI), что активирует подразумеваемое согласие на тест дыхания или крови"],"explanation":"In Texas, the lawful trigger for implied consent testing is being lawfully arrested for DWI, so option D is correct. Observing bad driving (C) may justify the stop or arrest but does not by itself compel a test, and there is no separately signed waiver at license renewal (B)."}},"learn-alcohol-and-penalties":{"0":{"q":"В Техасе каков предел содержания алкоголя в крови (BAC) для DWI для взрослого водителя в возрасте 21 года и старше?","options":["0,08%","0,04%","0,10%","0,05%"],"explanation":"In Texas, an adult age 21 or older is legally intoxicated (DWI) at a BAC of 0.08% or higher."},"1":{"q":"В Техасе как называется правонарушение при вождении с содержанием алкоголя в крови 0,08% или выше?","options":["Превышение скорости","Вождение в состоянии опьянения (DWI)","Неосторожное вождение","Нарушение с открытой тарой"],"explanation":"Driving at or above 0.08% BAC is the offense called Driving While Intoxicated (DWI)."},"2":{"q":"Могут ли водителя обвинить в вождении в нетрезвом виде (DWI), если его BAC ниже 0,08%?","options":["Нет, никогда ниже 0,08%","Только коммерческих водителей","Да, если он под воздействием алкоголя или наркотиков","Только если он откажется от теста"],"explanation":"A driver can still be charged with DWI below 0.08% BAC if impaired by alcohol or drugs."},"3":{"q":"Каков предел содержания алкоголя в крови (BAC) для водителя коммерческого транспорта в Техасе?","options":["0,08%","0,10%","0,02%","0,04%"],"explanation":"A commercial driver's BAC limit is 0.04%, lower than the standard adult limit of 0.08%."},"4":{"q":"В Техасе каков допустимый уровень алкоголя в крови для водителя младше 21 года?","options":["Любое значение выше 0,00 незаконно","0,08 BAC","0,04 BAC","0,05 BAC"],"explanation":"Texas uses Zero Tolerance, so any detectable alcohol (a BAC above 0.00) is illegal for a driver under 21."},"5":{"q":"Что совершает несовершеннолетний, управляя автомобилем с любым обнаруживаемым количеством алкоголя?","options":["Ничего противозаконного","DUI (вождение под воздействием алкоголя) несовершеннолетним","Нарушение правил парковки","Коммерческое DWI"],"explanation":"Under Texas Zero Tolerance, any detectable alcohol means a minor commits DUI of alcohol by a minor."},"6":{"q":"Что в Техасе означает DUI для несовершеннолетнего?","options":["Опасное вождение в помещении","Вождение по страховке","Вождение в состоянии опьянения (Driving Under the Influence)","Вождение с умыслом"],"explanation":"DUI stands for Driving Under the Influence, the offense used for minors, distinct from the adult DWI."},"7":{"q":"В Техасе закон о нулевой терпимости применяется к водителям, не достигшим какого возраста?","options":["16 лет","18 лет","25 лет","21 года"],"explanation":"Texas's Zero Tolerance law makes any detectable alcohol illegal for drivers under 21 years of age."},"8":{"q":"К какому типу веществ относится алкоголь?","options":["Депрессант","Стимулятор","Обезболивающее","Витамин"],"explanation":"Alcohol is a depressant that slows your reaction time and impairs your judgment."},"9":{"q":"Как алкоголь влияет на время реакции водителя?","options":["Ускоряет его","Замедляет его","Не влияет на него","Улучшает его"],"explanation":"Alcohol is a depressant that slows your reaction time."},"10":{"q":"Что алкоголь ухудшает, когда вы за рулём?","options":["Уровень топлива","Давление в шинах","Ваше суждение","Ваши фары"],"explanation":"Alcohol impairs judgment, which is the first driving ability affected."},"11":{"q":"Как алкоголь влияет на координацию водителя?","options":["Он улучшает координацию","Он не влияет на координацию","Он влияет на координацию только ночью","Он снижает координацию"],"explanation":"Alcohol is a depressant that reduces a driver's coordination."},"12":{"q":"Как алкоголь влияет на зрение водителя?","options":["Он ухудшает зрение","Он улучшает зрение","Он не влияет на зрение","Он обостряет ночное зрение"],"explanation":"Alcohol reduces vision, making it harder to see clearly while driving."},"13":{"q":"На какую способность к вождению алкоголь влияет в первую очередь?","options":["Зрение","Рассудительность","Слух","Хват руля"],"explanation":"Alcohol affects judgment before other driving abilities."},"14":{"q":"Что является единственным способом снизить концентрацию алкоголя в крови (BAC)?","options":["Выпить кофе","Принять холодный душ","Прошествие времени","Съесть плотную еду"],"explanation":"Only the passage of time lowers BAC; coffee, food, and showers do not speed it up."},"15":{"q":"Что единственное снижает уровень алкоголя в крови?","options":["Питьё кофе","Плотный приём пищи","Холодный душ","Ожидание, пока пройдёт время"],"explanation":"Only time lowers your BAC; coffee, food, and showers do not speed up sobering."},"16":{"q":"Что единственное снижает содержание алкоголя в крови (BAC)?","options":["Время","Прием пищи","Питье кофе","Холодный душ"],"explanation":"Only time lowers BAC; food, coffee, and showers do not speed up sobering."},"17":{"q":"Что единственное снижает концентрацию алкоголя в крови (BAC) человека?","options":["Питьё кофе","Время","Холодный душ","Свежий воздух"],"explanation":"Only time lowers BAC; coffee, a cold shower, and fresh air do not speed up sobering."},"18":{"q":"Что является единственным, что снижает уровень алкоголя в крови?","options":["Свежий воздух","Питьё кофе","Время","Холодный душ"],"explanation":"Only time lowers BAC; fresh air, coffee, and a cold shower do not speed up sobering."},"19":{"q":"Примерно сколько алкоголя ваша печень перерабатывает за один час?","options":["Примерно четыре порции","Примерно три порции","Примерно две порции","Примерно одну порцию"],"explanation":"The liver processes about one standard drink per hour, and nothing can speed it up."},"20":{"q":"Может ли что-нибудь заставить печень перерабатывать алкоголь быстрее обычного?","options":["Нет, ничто это не ускоряет","Да, кофе","Да, холодный душ","Да, еда"],"explanation":"Nothing can make the liver process alcohol faster than its normal rate."},"21":{"q":"Что происходит, когда вы сочетаете наркотики или лекарства с алкоголем?","options":["Это нейтрализует алкоголь","Это многократно усиливает ухудшение состояния","Это ускоряет отрезвление","Это не имеет эффекта"],"explanation":"Mixing drugs (illegal, prescription, or over-the-counter) with alcohol multiplies impairment."},"22":{"q":"Могут ли рецептурные или безрецептурные лекарства усиливать опьянение при приёме с алкоголем?","options":["Нет, только запрещённые наркотики","Нет, они нейтрализуют алкоголь","Да, они могут многократно усиливать опьянение","Нет, они не влияют"],"explanation":"Even prescription and over-the-counter drugs can multiply impairment when combined with alcohol."},"23":{"q":"В Техасе на что вы соглашаетесь, садясь за руль, если вас законно арестовали за вождение в нетрезвом виде (DWI)?","options":["На проверку зрения","На экзамен по вождению","На проверку слуха","На анализ дыхания или крови"],"explanation":"By driving in Texas you give implied consent to a breath or blood test if lawfully arrested for DWI."},"24":{"q":"В Техасе подразумеваемое согласие распространяется на какой тест?","options":["Тест дыхания или крови","Проверку зрения","Проверку слуха","Письменный тест"],"explanation":"By driving in Texas, you give implied consent to a breath or blood test if lawfully arrested for DWI."},"25":{"q":"Когда применяется подразумеваемое согласие на тестирование в Техасе?","options":["Когда водителя останавливают за превышение скорости","Когда водитель законно арестован за вождение в нетрезвом виде","Когда водитель неправильно паркуется","Когда водитель продлевает права"],"explanation":"By driving in Texas you give implied consent to a breath or blood test if you are lawfully arrested for DWI."},"26":{"q":"Отказ от теста дыхания или крови приводит к автоматическому приостановлению водительских прав на сколько дней при первом отказе?","options":["30 дней","90 дней","180 дней","365 дней"],"explanation":"A first refusal of the breath or blood test results in an automatic 180-day license suspension."},"27":{"q":"На основании какого закона налагается автоматическое приостановление действия прав за отказ от прохождения теста?","options":["Закон об отмене подразумеваемого согласия","Закон об открытой таре","Закон о нулевой терпимости","Административный отзыв прав (ALR)"],"explanation":"Refusing a breath or blood test triggers an automatic license suspension under Administrative License Revocation (ALR)."},"28":{"q":"Является ли приостановка прав по программе ALR за отказ от теста отдельной от наказаний за осуждение по DWI?","options":["Да, она отдельная","Нет, она их заменяет","Нет, только при осуждении","Да, но только для несовершеннолетних"],"explanation":"The ALR suspension for refusing a test is separate from any DWI conviction penalties."},"29":{"q":"Каков максимальный штраф за первое вождение в нетрезвом виде (DWI) в Техасе?","options":["До 500 долларов","До 2 000 долларов","До 5 000 долларов","До 10 000 долларов"],"explanation":"A first DWI in Texas carries a fine of up to $2,000."},"30":{"q":"Какой срок тюремного заключения может повлечь за собой первое нарушение DWI в Техасе?","options":["От 1 до 30 дней","От 2 до 90 дней","От 3 до 180 дней","От 5 до 365 дней"],"explanation":"A first DWI in Texas carries jail time of 3 days to 180 days."},"31":{"q":"Каков минимальный срок тюремного заключения за первое вождение в состоянии алкогольного опьянения (DWI) в Техасе?","options":["30 дней","10 дней","1 день","3 дня"],"explanation":"A first DWI in Texas carries a minimum jail time of 3 days."},"32":{"q":"Каков максимальный срок тюремного заключения за первое вождение в нетрезвом виде (DWI) в Техасе?","options":["180 дней","30 дней","1 год","10 дней"],"explanation":"A first DWI in Texas carries a maximum jail term of 180 days."},"33":{"q":"В Техасе на какой срок могут приостановить ваши права за первое DWI (вождение в состоянии опьянения)?","options":["До 30 дней","До 1 года","До 5 лет","Никогда не приостанавливают"],"explanation":"A first DWI in Texas carries a license suspension of up to 1 year."},"34":{"q":"Что происходит со штрафами за вождение в нетрезвом виде (DWI) в Техасе при повторных нарушениях?","options":["Они отменяются","Они остаются прежними","Они увеличиваются","Они становятся необязательными"],"explanation":"In Texas, penalties increase for repeat DWI offenses."},"35":{"q":"В Техасе при каком уровне BAC (содержания алкоголя в крови) усиливаются наказания за DWI?","options":["0,04% или выше","0,06% или выше","0,08% или выше","0,15% или выше"],"explanation":"A high BAC of 0.15% or above increases the penalties for DWI."},"36":{"q":"В Техасе какой высокий уровень BAC увеличивает наказания за DWI?","options":["0,15%","0,08%","0,04%","0,02%"],"explanation":"A BAC of 0.15% or higher increases the penalties for a Texas DWI."},"37":{"q":"В Техасе что увеличивает наказание за вождение в нетрезвом виде при первом нарушении?","options":["Медленная езда","Наличие ребёнка-пассажира","Использование ремня безопасности","Вождение ночью"],"explanation":"Penalties increase when there is a child passenger in the vehicle."},"38":{"q":"В Техасе, чем является вождение в нетрезвом виде (DWI) с ребёнком младше 15 лет в машине?","options":["Только предупреждением","Штрафом за парковку","Уголовным преступлением (фелония)","Не является нарушением"],"explanation":"In Texas, driving while intoxicated with a child under 15 in the vehicle is a felony."},"39":{"q":"В Техасе вождение в нетрезвом виде (DWI) становится тяжким преступлением, если в машине есть пассажир-ребёнок младше какого возраста?","options":["Младше 8 лет","Младше 10 лет","Младше 12 лет","Младше 15 лет"],"explanation":"In Texas, DWI with a child passenger under 15 years old is a felony."},"40":{"q":"Является ли в Техасе наличие открытой емкости с алкоголем в пассажирской зоне отдельным правонарушением?","options":["Да, это отдельное правонарушение","Нет, это всегда разрешено","Только для пассажиров, никогда для водителя","Только на автомагистралях"],"explanation":"In Texas, having an open container of alcohol in the passenger area is a separate offense."},"41":{"q":"Где в транспортном средстве применяется правонарушение об открытой таре с алкоголем?","options":["Только в багажнике","В пассажирском салоне","На крыше","Под капотом"],"explanation":"The open container offense applies to alcohol in the passenger area of the vehicle."},"42":{"q":"Каков максимальный штраф за первое вождение в нетрезвом виде (алкоголь) для несовершеннолетнего в Техасе?","options":["До $100","До $250","До $500","До $2 000"],"explanation":"A minor's first DUI for alcohol carries a fine of up to $500."},"43":{"q":"Что включает в себя первое DUI несовершеннолетнего за алкоголь?","options":["Вообще никакого наказания","Только письмо с предупреждением","Бесплатный урок вождения","Приостановление действия водительских прав"],"explanation":"A minor's first DUI for alcohol includes a license suspension."},"44":{"q":"Какое наказание предусмотрено за первое DUI (алкоголь) несовершеннолетнего в Техасе?","options":["Общественные работы","Бесплатные курсы вождения","Скидка на новые права","Удаление лишних баллов с прав"],"explanation":"A minor's first alcohol DUI in Texas includes community service."},"45":{"q":"Что обязан пройти несовершеннолетний в Техасе после первого DUI за алкоголь?","options":["Курс безопасного вождения","Курс по информированию об алкоголе","Проверку зрения","Курс первой помощи"],"explanation":"A minor's first alcohol DUI requires completing an alcohol-awareness course."},"46":{"q":"Что добавляют нарушения правил дорожного движения в вашу водительскую историю?","options":["Бесплатные уроки вождения","Дополнительные годы прав","Баллы","Денежные награды"],"explanation":"Traffic convictions add points to your driving record."},"47":{"q":"К чему может привести слишком большое число обвинительных приговоров за нарушения ПДД?","options":["Снижение страховых ставок","Бесплатный курс вождения","Удаление дополнительных штрафных баллов","Доплаты (surcharges)"],"explanation":"Too many convictions can lead to surcharges and even license suspension."},"48":{"q":"К чему может привести слишком много нарушений правил дорожного движения?","options":["Приостановление действия водительских прав","Бесплатное продление прав","Расширение водительских привилегий","Снижение стоимости страховки"],"explanation":"Too many convictions can add surcharges and lead to license suspension."},"49":{"q":"Что происходит с осуждением за вождение в нетрезвом виде (DWI) в Техасе со временем?","options":["Оно стирается через месяц","Оно остаётся в вашей записи","Оно исчезает, когда вы оплачиваете штраф","Оно удаляется после одной безопасной поездки"],"explanation":"A DWI conviction stays on your record and raises your insurance costs."},"50":{"q":"Как осуждение за вождение в нетрезвом виде (DWI) влияет на стоимость автострахования?","options":["Снижает её","Не влияет","Резко повышает её","Отменяет все сборы"],"explanation":"A DWI conviction stays on your record and sharply raises insurance costs."},"51":{"q":"Какая страховка может потребоваться для восстановления права управления автомобилем в Техасе?","options":["Туристическая страховка","Страховка для домашних животных","Медицинская страховка","Страховка финансовой ответственности SR-22"],"explanation":"SR-22 financial responsibility insurance may be required to reinstate your driving privileges."},"52":{"q":"Что такое SR-22?","options":["Форма страховки финансовой ответственности","Вид водительских прав","Штраф за нарушение ПДД","Тест на содержание алкоголя в крови"],"explanation":"SR-22 is a form of financial responsibility insurance that may be required to reinstate driving privileges."},"53":{"q":"Какое количество алкоголя безопаснее всего выпить перед вождением?","options":["Один напиток","Ноль алкоголя","Два напитка","Одно пиво"],"explanation":"The safest choice is zero alcohol before driving."},"54":{"q":"Как можно избежать вождения в нетрезвом виде?","options":["Сначала выпить кофе","Ехать медленно","Назначить трезвого водителя","Открыть окна"],"explanation":"Choosing a sober driver lets you avoid driving after drinking."},"55":{"q":"Что можно использовать, чтобы не садиться за руль в нетрезвом виде?","options":["Чашку кофе","Холодный душ","Свежий воздух","Службу такси"],"explanation":"Using a ride service lets you avoid drinking and driving."},"56":{"q":"Какой способ помогает избежать вождения в нетрезвом виде?","options":["Остаться на месте вместо того, чтобы ехать","Ехать очень медленно","Сначала выпить немного воды","Открыть окна машины"],"explanation":"Staying put instead of driving keeps you from drinking and driving."},"57":{"q":"Какой уровень алкоголя в крови является незаконным для водителя младше 21 года в Техасе?","options":["0,08% или выше","Любое количество выше 0,00","0,04% или выше","0,15% или выше"],"explanation":"Texas has zero tolerance, so any detectable alcohol above 0.00 is illegal for a minor."},"58":{"q":"Алкоголь является депрессантом, так что он делает с организмом?","options":["Ускоряет время реакции","Улучшает координацию","Замедляет функции организма","Обостряет зрение"],"explanation":"As a depressant, alcohol slows down the body's functions instead of stimulating them."},"59":{"q":"Каков максимальный штраф за первое осуждение за вождение в состоянии алкогольного опьянения (DWI) в Техасе?","options":["200 долларов","500 долларов","1 000 долларов","2 000 долларов"],"explanation":"A first DWI conviction in Texas carries a fine of up to $2,000."}}},"tr":{"road-signs":{"0":{"q":"Alacakaranlıkta, size bakan tabelanın çok solduğu ve üzerindeki hiçbir yazıyı artık okuyamadığınız bir kavşağa yaklaşıyorsunuz. Yine de tabelanın sekiz kenarlı olduğunu net bir şekilde görebiliyorsunuz. Bu kavşakta ne yapmalısınız?","options":["Tamamen durmalısınız, çünkü sekiz kenarlı (sekizgen) bir tabela her zaman DUR anlamına gelir.","Yavaşlayıp yol vermeli, yalnızca başka trafik varsa durmalısınız.","Yavaşlayıp dikkatle ilerlemelisiniz, çünkü bu şekil yalnızca ileride bir tehlikeyi uyarır.","Onu bir okul geçidi olarak değerlendirmeli ve yola çıkabilecek çocuklara karşı hazırlıklı olmalısınız."],"explanation":"The octagon is the only eight-sided sign and always means STOP, so the shape alone tells you to come to a full stop even when the lettering is unreadable. Yielding is signaled by an inverted triangle, not an octagon, which makes that option the trap."},"1":{"q":"Bir hızlanma şeridinden otoyola katılıyorsunuz ve önünüzde ters (tepesi aşağı) üçgen şeklinde kırmızı-beyaz bir tabela görüyorsunuz. Bu tabela sizden ne yapmanızı ister?","options":["Tamamen durup otoyol her iki yönde de boşalana kadar durakta beklemek","Otoyoldaki trafiğe yol vermek, yalnızca güvenli şekilde katılmak için gerekirse yavaşlamak veya durmak","Katılırken geçiş üstünlüğü sizde olduğu için belirtilen azami hızda devam etmek","Onu ileride bir tehlike uyarısı olarak görüp yol vermeden dikkatlice devam etmek"],"explanation":"An inverted triangle is a YIELD sign: you must give the right of way to traffic already on the highway and slow or stop only if needed to merge safely. A full stop every time (A) describes an octagonal STOP sign, and a diamond-shaped warning sign (D) does not require yielding the right of way."},"2":{"q":"İki şeritli kırsal bir karayolunda gidiyorsunuz ve önünüzdeki yavaş traktörü geçmek istiyorsunuz. Tam karşı şeride çıkmadan önce, yolun SOL banketine yerleştirilmiş, yan yatmış bir üçgen (yatay köşeli) şeklinde bir tabela fark ediyorsunuz. Bu tabela size ne söylüyor?","options":["Kendi şeridinize geri dönmeden önce karşıdan gelen trafiğe yol verin","İleride okul bölgesi veya okul geçidi var, hızınızı azaltın","Geçiş Yasağı Bölgesine giriyorsunuz ve traktörü burada geçmemelisiniz","İleride bir tehlike veya durum var, yavaşlayın ve dikkatli ilerleyin"],"explanation":"A pennant (a horizontal triangle) posted on the LEFT side of the road marks a No Passing Zone, so you must not pass the tractor. A yield is an inverted (upside-down) triangle, and a diamond is the warning shape, so those options confuse other sign shapes with the pennant."},"3":{"q":"Alacakaranlıkta tanımadığınız iki şeritli bir karayolunda araç kullanıyorsunuz. İleride sağ banketin üzerinde sarı, baklava (eşkenar dörtgen) şeklinde bir tabela görüyorsunuz ama üzerindeki yazıyı veya sembolü okuyamayacak kadar uzaktasınız. Yalnızca şekline bakarak hemen ne anlamalısınız?","options":["Hız sınırı gibi uymanız gereken bir kuralı bildiren düzenleyici bir tabeladır","İleride bir okul bölgesini veya okul geçidini işaret eder","Bir sonraki kasabaya yön veya mesafe bilgisi veren bir yönlendirme tabelasıdır","İleride bir tehlikeye veya yol koşullarındaki bir değişikliğe karşı sizi uyaran bir uyarı tabelasıdır"],"explanation":"A diamond shape always means a warning sign, telling you a hazard or condition lies ahead. Regulatory laws use vertical rectangles (A) and guide/direction information uses horizontal rectangles (C), while school zones use a pentagon (B)."},"4":{"q":"Tanımadığınız bir yerleşim bölgesinde araç kullanırken, ucu yukarı bakan sarı-yeşil, beş kenarlı bir tabela görüyorsunuz. Yalnızca şekline bakarak, bu tabela sizi ne konuda uyarıyor?","options":["Bir okul bölgesine veya okul geçidine yaklaşıyorsunuz","İleride bir demir yolu geçidi var","Geçişin yasak olduğu bir bölgeye giriyorsunuz","İleride genel bir tehlike veya yol durumu var"],"explanation":"A pentagon (5-sided, point up) shape always means a school zone or school crossing. A round sign warns of a railroad crossing ahead, so option B confuses two different sign shapes."},"5":{"q":"Kırsal, iki şeritli bir karayolunda ilerliyorsunuz ve sağ banket üzerinde, herhangi bir ray görünmeden çok önce yerleştirilmiş, üzerinde siyah bir 'X' ve 'RR' harfleri olan yuvarlak, sarı bir tabela fark ediyorsunuz. Bu tabela size ne anlatıyor?","options":["Rayların kendisine ulaştınız ve aracınızı rayların üzerinde durdurmanız gerekiyor","İleride bir demiryolu geçidi var, bu yüzden yavaşlamaya ve trenlere dikkat etmeye hazır olun","Bir okul bölgesine giriyorsunuz ve çocuklar için hızınızı düşürmelisiniz","Burası geçiş yasağı bölgesidir ve burada diğer araçları geçemezsiniz"],"explanation":"A round (circular) sign is the advance warning that a railroad crossing lies ahead, so you should slow down and watch for trains. The crossing itself is marked by the X-shaped Crossbuck (not this round sign), and the pentagon shape, not the circle, signals a school zone."},"6":{"q":"Kırsal bir yolda araç kullanıyorsunuz ve demiryolu raylarının tam kendisine yaklaşıyorsunuz; burada üzerinde 'DEMIRYOLU GEÇIDI' yazan beyaz, X şeklinde bir levha görüyorsunuz. Bu geçitte dur tabelası, bariyer veya yanıp sönen ışık yok. Bu levhayı nasıl değerlendirmelisiniz?","options":["X şeklindeki çapraz levha yasal olarak dur tabelası işlevi gördüğü için her seferinde tamamen durmalısınız","Bir tren görünmediği sürece görmezden gelmelisiniz, çünkü bu çapraz levha sadece rayların önüne yerleştirilmiş bir uyarı işaretidir","Onu bir yol ver levhası gibi değerlendirin: yavaşlayın, her iki yöne de bakın ve yalnızca bir tren yaklaşıyorsa durun","Normal hızınızla devam edin, çünkü daha önceki yuvarlak ön uyarı levhası size gereken her şeyi zaten söyledi"],"explanation":"X şeklindeki çapraz levha demiryolu geçidinin kendisini işaret eder ve bir yol ver levhası gibi değerlendirilmelidir; yani yavaşlayıp tren olup olmadığını kontrol eder ve yalnızca bir tren yaklaşıyorsa durursunuz. Bu bir dur tabelası değildir (A) ve yuvarlak ön uyarı levhasının (B, D) aksine, çapraz levha rayların önünde değil, tam kendisinde bulunur."},"7":{"q":"Tanımadığınız bir yolda araç kullanıyorsunuz ve yasal olarak ne kadar hızlı gidebileceğinizi bilmeniz gerekiyor. İleride dikey dikdörtgen şeklinde (enine göre daha uzun) bir tabela görüyorsunuz. Yalnızca şekline bakarak, bu büyük olasılıkla ne tür bir tabeladır?","options":["Bir sonraki kasabaya yön ve mesafeleri gösteren bir rehber veya bilgi tabelası","İleride bir tehlike veya değişen bir koşula karşı sizi uyaran bir uyarı tabelası","İleride yol ekipleri olduğunu bildiren bir inşaat veya çalışma alanı tabelası","Hız sınırı gibi uymanız gereken bir yasayı belirten bir düzenleyici tabela"],"explanation":"A vertical rectangle is a regulatory sign that tells you a law you must obey, such as the posted speed limit. A horizontal rectangle (option A) is the guide/information shape, and a diamond (option B) is the warning shape, so neither matches a vertical rectangle."},"8":{"q":"Otoyolda gideceğiniz şehre çıkışı arıyorsunuz. İleride yatay dikdörtgen şeklinde (boyundan daha geniş) geniş bir tabela görüyorsunuz. Yalnızca şekline bakarak, bu tabelanın size hangi bilgiyi vermesini beklersiniz?","options":["Hangi çıkışı kullanacağınız ve şehrinizin ne kadar uzakta olduğu gibi yerlere yön ve mesafe bilgileri","Belirtilen hız sınırı gibi uymanız gereken bir trafik kuralı","Keskin viraj gibi ileride bir tehlike veya durum hakkında bir uyarı","Devam etmeden önce tamamen durma emri"],"explanation":"A horizontal rectangle is a guide/information sign, giving directions and distances. A vertical rectangle (not horizontal) is the regulatory shape for laws like speed limits, warnings use a diamond, and only an octagon means stop."},"9":{"q":"Gece araba kullanırken bir sokağa dönüyorsunuz ve farlarınız tam önünüzde beyaz harflerle WRONG WAY (TERS YÖN) yazan kırmızı bir levhayı aydınlatıyor. Bu levha size ne yapmanızı söylüyor?","options":["İlerde bir tehlike veya olağandışı bir durum olduğu için yavaşlayın","Durun; karşıdan gelen trafiğe karşı gidiyorsunuz ve bu yönde devam etmemelisiniz","Devam edin, ancak bir sonraki çıkıştaki benzin ve yemek gibi sürücü hizmetlerine yol verin","Bir inşaat veya çalışma alanına girdiğiniz için dikkatli ilerleyin"],"explanation":"WRONG WAY is a red sign, and red means stop, yield, or prohibited, so you must not continue in that direction because you are heading into oncoming traffic. Option A describes a yellow warning sign and option D describes an orange construction sign, neither of which is red."},"10":{"q":"Alacakaranlıkta tanımadığınız iki şeritli bir karayolunda araç kullanırken farlarınız, sağa doğru kıvrılan eğri bir ok bulunan sarı elmas şeklindeki bir işarete çarpar. Rengine göre bu işaret size ne anlatıyor?","options":["Uymanız gereken bir kural: ileride keskin bir sağa dönüş zorunludur","Sağdaki virajın arkasında bir inşaat ekibi çalışıyor","Genel uyarı: ileride yolda bir viraj var, bu yüzden yavaşlayın","Sizi sağdaki bir varış noktasına yönlendiren bir kılavuz işareti"],"explanation":"Yellow signs are general warning signs alerting you to a hazard or condition ahead, such as a curve, so you should reduce speed. The construction trap is wrong because work-zone warnings are orange, and the regulatory/guide traps are wrong because those use white/green, not yellow."},"11":{"q":"Otoyolda giderken ileride turuncu zeminli, baklava (eşkenar dörtgen) şeklinde \"İLERİDE YOL ÇALIŞMASI\" yazan bir levha görüyorsunuz. Bu levhanın turuncu rengi size ne anlatır?","options":["Yaklaştığınız bir dinlenme veya manzara alanını işaret eder","İleride benzin, yemek veya konaklama gibi sürücü hizmetleri olduğunu gösterir","Yoldaki bir viraj veya yokuş hakkında genel bir uyarıdır","Bir inşaat veya çalışma bölgesine giriyorsunuz"],"explanation":"Orange signs always indicate a construction or work zone, so you should slow down and be alert for workers and equipment. Brown is used for recreation/scenic areas and yellow is used for general warnings like curves or hills, which is why those options are wrong."},"12":{"q":"Kırsal bir otoyolda gideceğiniz şehrin çıkışını arıyorsunuz. İleride beyaz harflerle \"Lubbock 45 / Amarillo 120\" yazan ve ok bulunan büyük yeşil bir tabela görüyorsunuz. Bu tabela size ne söyler?","options":["Bu, size o şehirlere giden yönleri ve mesafeleri veren bir kılavuz tabelasıdır","Bu, ileride o şehirlerde tehlikeli yol koşulları olduğunu bildiren bir uyarı tabelasıdır","O şehirlerde bulunan benzin ve yemek gibi sürücü hizmetlerini gösterir","Bu, sizi o şehirlerden birine doğru çıkış yapmaya zorlayan bir düzenleyici tabeladır"],"explanation":"Green signs are guide signs that indicate permitted movements, directions, and distances, so this sign is simply telling you the way and mileage to each city. Warning information would be on a yellow sign, and motorist-services signs are blue, so those choices place the wrong color and meaning together."},"13":{"q":"Yakıtınız azken ve açken, tanımadığınız bir otoyolda ilerlerken, ileride mavi zemin üzerinde bir benzin pompası ile çatal bıçak sembolleri bulunan bir tabela fark ediyorsunuz. Bu tabela size ne anlatıyor?","options":["Bir sonraki şehre olan yönü ve mesafeyi gösteren bir rehber tabelasıdır","Sizi benzin ve yemek gibi yakındaki sürücü hizmetlerine yönlendiriyor","Yol kenarında ileride bir tehlike veya duruma karşı sizi uyarıyor","Bir sonraki çıkışta bulunan bir dinlenme veya manzara alanını işaret ediyor"],"explanation":"Blue signs indicate motorist services such as gas, food, lodging, and hospital, so the blue background with the fuel and dining symbols points you to those services. Green signs (not blue) handle directions and distances, and brown signs mark recreational or scenic areas."},"14":{"q":"Kırsal bir karayolunda giderken, ileride kahverengi zeminli ve beyaz sembollerle bir eyalet parkını ve tarihi bir savaş alanını gösteren kare bir tabela görüyorsunuz. Bu tabela size ne anlatıyor?","options":["Benzin, yiyecek ve konaklama gibi sürücü hizmetlerine yaklaşıyorsunuz","İlerde bir inşaat veya çalışma alanı var, bu yüzden yavaşlamalısınız","Parklar ve tarihi yerler gibi rekreasyon, kültürel veya manzaralı alanlara yaklaşıyorsunuz","Belirtilen hız sınırı gibi düzenleyici bir yasaya uymanız gerekiyor"],"explanation":"Brown signs indicate recreation, cultural, or scenic areas like parks and historic sites, so option C is correct. Blue signs (not brown) mark motorist services such as gas and food, which makes that the trap answer."},"15":{"q":"Gece tanımadığınız bir otoyolda araç kullanıyorsunuz. İlerideki bir tabela, üzerinde siyah harflerle \"45\" yazan dikey beyaz bir dikdörtgen. Bu tabela size ne söyler?","options":["Bir sonraki çıkışa olan mesafeyi gösteren bir yönlendirme tabelasıdır.","45 fit ileride bir tehlike hakkında uyarı tabelasıdır.","Geçici çalışma alanı limiti belirleyen bir inşaat alanı tabelasıdır.","Azami yasal hızı 45 mil/saat olarak belirleyen bir düzenleyici tabeladır."],"explanation":"White signs with black lettering are regulatory signs, and a white rectangle with a number sets the maximum legal speed (45 mph). Guide/distance signs are green and warning signs are yellow, so those options place real facts on the wrong color of sign."},"16":{"q":"Tanımadığınız bir mahalleden geçerken, üzerinde yürüyen iki çocuk resmi bulunan parlak floresan sarı-yeşil zeminli eşkenar dörtgen şeklinde bir levhaya yaklaşıyorsunuz. Bu levha sizi ne konusunda uyarıyor?","options":["İleride yayalar, bisikletliler veya okul geçidi","İleride inşaat veya çalışma alanı","İleride bir dinlenme veya manzaralı alan","İleride genel bir viraj veya yokuş tehlikesi"],"explanation":"Fluorescent yellow-green is reserved for pedestrian, bicycle, and school warnings, so this sign means people may be crossing ahead. Orange signals construction zones and brown marks recreation/scenic areas, so those colors would not appear on this warning."},"17":{"q":"Alacakaranlıkta tanımadığınız bir kavşağa doğru ilerliyorsunuz. Karşınızdaki tabela o kadar solmuş ki üzerindeki yazıyı artık okuyamıyorsunuz, ama hâlâ şeklini ve rengini seçebiliyorsunuz. Bunun bir DUR tabelası olduğunu ve tamamen durmanız gerektiğini anlamak için hangi şekil ve rengi aramalısınız?","options":["Kırmızı, ters (tepesi aşağı) bir üçgen","Kırmızı, sekiz kenarlı bir sekizgen","Sarı bir baklava (eşkenar dörtgen)","Beyaz dikey bir dikdörtgen"],"explanation":"A STOP sign is the only red, eight-sided octagon, so its shape and color identify it even when the word is unreadable. A red inverted triangle is a YIELD sign (give the right of way, not necessarily a full stop), which is the trap."},"18":{"q":"Yoğun bir otoyola bir giriş rampasından katılıyorsunuz. Rampanın sonunda, aşağıyı gösteren bir üçgen şeklinde, kırmızı ve beyaz renkli bir tabela görüyorsunuz. Bu tabela sizden ne yapmanızı ister?","options":["Tamamen durun, çünkü yasal olarak 'dur' anlamına gelen tek tabela şekli budur","Sinyal lambası çalışmadığı için kavşağı her yönden duraklı kavşak gibi kabul edin","Yavaşlayın ve otoyol trafiğine yol verin, yalnızca gerekirse durun","Girmeyin, çünkü kırmızı-beyaz bir tabela her zaman yolun size kapalı olduğu anlamına gelir"],"explanation":"A red-and-white inverted (downward-pointing) triangle is a YIELD sign, which means give the right of way and slow or stop only if needed. The full-stop trap describes the red octagon STOP sign, and the 'do not enter' trap confuses YIELD with a prohibitory sign."},"19":{"q":"Şehir merkezinde bir otopark arıyorsunuz ve bir rampaya yaklaştığınızda üzerinde 'GİRİLMEZ' (DO NOT ENTER) yazan kırmızı bir levha görüyorsunuz. Bu kırmızı levha sizden ne yapmanızı ister?","options":["Yavaşlayıp dikkatle ilerleyin, çünkü kırmızı levhalar yalnızca ileride bir tehlikeyi işaret eder","Rampadaki tüm araçlara yol verin, ardından yol açıksa girin","Tam olarak durun, ardından karşıdan gelen araçları kontrol ettikten sonra devam edin","Rampaya girmeyin; bu giriş sizin gidiş yönünüze kapalıdır"],"explanation":"DO NOT ENTER is a red sign meaning do not proceed, because that entrance is closed to your direction of travel. Yielding (B) or stopping then continuing (C) are wrong because the sign prohibits entry entirely rather than allowing you to proceed after caution."},"20":{"q":"Bir sokağa dönüyorsunuz ve sağa doğru yatay bir ok ile ONE WAY (tek yön) yazan dikdörtgen bir tabela görüyorsunuz. Bu sokakta sola gitmek istiyordunuz. Ne yapmalısınız?","options":["Sola dönmeyin; yalnızca okun gösterdiği yöne, yani sağa doğru ilerleyin","Sola dönün, ancak ortak kullanılan bir sokak olduğundan önce karşıdan gelen trafiğe yol verin","Köşede ayrıca DO NOT ENTER (girilmez) tabelası yoksa sadece o zaman sola dönün","Bunu bir uyarı olarak kabul edip dikkatlice yavaşça sola ilerleyin"],"explanation":"A ONE WAY sign means traffic may travel only in the direction the arrow points, so you must go right and cannot turn left onto that street. Turning left would send you against legal traffic flow, so the options allowing a left turn are wrong."},"21":{"q":"Açık ve kuru bir günde araç kullanırken üzerinde siyah 65 sayısı bulunan beyaz dikdörtgen bir levhanın yanından geçiyorsunuz. Hafif yağmur başlıyor ve yol kayganlaşıyor. Bu levha, değişen bu havada hızınız hakkında size ne söyler?","options":["65, yağmura bakılmaksızın korumanız gereken asgari hızdır","65, ideal koşullar için azami yasal hızdır, bu yüzden ıslak yolda artık bunun altına inmelisiniz","Beyaz dikdörtgen yalnızca bir yönlendirme levhasıdır, bu nedenle 65 sadece tavsiye niteliğindedir ve bağlayıcı değildir","Yağmur yağdığı için, durmanıza daha fazla yer tanımak amacıyla sınır otomatik olarak yükselir"],"explanation":"A SPEED LIMIT sign is a white rectangle with black numbers showing the maximum legal speed in ideal conditions, so in rain you must drive slower than the posted number. It is not a minimum, it is a regulatory (not guide) sign, and the limit never rises in bad weather."},"22":{"q":"Bir kavşağa yaklaşıyorsunuz ve U dönüşü yapmak istiyorsunuz. Sinyalin üstünde, kırmızı bir daire içinde U dönüşü okunu ve onu çaprazlama kesen kırmızı bir çizgiyi gösteren beyaz kare bir levha bulunuyor. Bu levha sizden ne yapmanızı ister?","options":["Yalnızca buradaki U dönüşlerinin zor olduğunu uyarır, bu yüzden güvenliyse U dönüşü yapabilirsiniz","U dönüşüne izin verir ancak yalnızca korumalı yeşil okta","Bu kavşakta U dönüşünü yasaklar, bu yüzden U dönüşü yapmamalısınız","U dönüşünü tamamlamadan önce karşıdan gelen trafiğe yol vermeniz gerektiği anlamına gelir"],"explanation":"A red circle with a slash is a regulatory 'No' sign, and a U-turn arrow inside it means U-turns are prohibited here. The trap answers treat a mandatory prohibition as a mere warning or a conditional/yield situation, but the red circle and slash means the movement is flatly illegal."},"23":{"q":"Gece, tanımadığınız iki şeritli bir yolda araç kullanıyorsunuz. Yolun ortasına, sizin şeridiniz ile solunuzdaki şerit arasına çizilmiş çizgi sarı renkte. Bu renk, o çizginin diğer tarafındaki şeritteki trafik hakkında size ne anlatır?","options":["Bu tek yönlü bir yoldur, bu yüzden karşı yönden trafik gelmez","Sarı çizgi yalnızca yol kenarını işaretler, bir trafik şeridini değil","O şeritteki trafik sizinle aynı yönde ilerliyor","O şeritteki trafik karşı yönde, size doğru ilerliyor"],"explanation":"Sarı çizgiler zıt yönlerde ilerleyen trafiği ayırır; bu nedenle sarı orta çizginin karşısındaki şerit karşıdan gelen trafiği taşır. Beyaz çizgiler (sarı değil) aynı yöndeki trafiği ayırır ve yol kenarını işaretler; bu yüzden aynı yön ve yol kenarı seçenekleri yanlıştır."},"24":{"q":"Geniş bir otoyolda ilerliyorsunuz ve solunuzda şeridinize paralel uzanan uzun, kesintisiz beyaz bir çizgiye yaklaşıyorsunuz; çizginin diğer tarafında aynı yönde akan başka trafik var. Bu beyaz çizgi yanınızdaki trafik hakkında size ne söyler?","options":["Yanınızdaki trafik sizinle aynı yönde ilerliyor ve çizgi bu çizgiyi geçerek şerit değiştirmenizi caydırıyor.","Yanınızdaki trafik ters yönde ilerliyor, bu yüzden çizgiyi geçmek sizi karşıdan gelen araçların arasına sokar.","Çizgi yolun kenarını işaretler, bu yüzden ötesinde hiç trafik şeridi yoktur.","Çizgi, kesik sarı çizgi gibi, sollamanın yalnızca ön taraf açık olduğunda yapılabileceği anlamına gelir."],"explanation":"White lines separate lanes of traffic moving in the SAME direction, and a solid white line discourages crossing or changing lanes. Yellow lines (B) separate opposite directions, white edge lines mark the pavement edge but here it sits between two same-direction lanes (C), and broken-line passing rules apply to yellow lines, not this solid white one (D)."},"25":{"q":"İki şeritli bir karayolunda ilerliyorsunuz ve önünüzdeki yavaş traktörü geçmek istiyorsunuz. Yaklaşırken, merkezin sizin tarafınızdaki şerit çizgisinin tek bir sürekli sarı çizgi olduğunu, karşı tarafta ise kesik sarı çizgi bulunduğunu fark ediyorsunuz. Bu size geçiş hakkında ne söyler?","options":["Geçebilirsiniz, çünkü diğer taraftaki kesik sarı çizgi her iki yöndeki trafik için geçerlidir.","Geçemezsiniz, çünkü sizin tarafınızdaki sürekli sarı çizgi geçişi yasaklar.","İşaretler tavsiye niteliğinde olduğundan yalnızca belirlenen hız sınırının altındaki hızlarda geçebilirsiniz.","Herhangi bir sarı çizgiyi geçmeden önce tamamen durmalısınız."],"explanation":"A solid yellow line on your side of the road means passing is prohibited for you, even if the opposite side has a broken (dashed) yellow line that permits passing for oncoming traffic. The broken line only allows passing for drivers on that side, and yellow markings are regulatory, not merely advisory."},"26":{"q":"İki şeritli bir karayolunda gidiyorsunuz ve öndeki yavaş traktörü geçmek istiyorsunuz. Ortadaki çizginin sizin tarafınızda yol, kesik (aralıklı) sarı çizgiyle işaretlenmiş, karşı şerit boş ve önünüzde uzun, açık bir görüş var. Bu işaret geçiş hakkında size ne söyler?","options":["Hiçbir nedenle sarı çizgiyi geçemezsiniz, bu yüzden traktörün arkasında kalın","Kesik çizgi yolun kenarını işaretler, bu yüzden sola geçmeyin","Geçişe izin verilir ve yol açıkken geçmek için karşı şeride geçebilirsiniz","Şerit değiştirebilirsiniz çünkü kesik çizgiler her zaman aynı yönde giden trafiği ayırır"],"explanation":"Sizin tarafınızdaki kesik (aralıklı) sarı çizgi, öndeki yol açıkken geçişe izin verildiği anlamına gelir, bu yüzden traktörü geçmek için çizgiyi geçebilirsiniz. D seçeneği tuzaktır: kesik beyaz çizgiler aynı yöndeki trafiği ayırır, ancak sarı çizgiler her zaman karşı yöndeki trafiği ayırır, bu yüzden belirttiği kural burada yanlış uygulanmıştır."},"27":{"q":"Ortasında çift düz sarı çizgi bulunan iki şeritli bir yolda gidiyorsunuz. Önünüzde yavaş bir traktör var, yol boş ve görüş mesafesi iyi. Solunuzda, ziyaret etmek istediğiniz eve giden bir yol var. Çift düz sarı çizgi burada size ne yapma izni verir?","options":["Traktörü geçin, çünkü yol boş ve görüş iyi","Traktörü geçin, çünkü çift sarı çizgi yalnızca karşı yönden gelen trafiği kısıtlar","Hiçbir şey beklemenizi gerektirmez; kesik beyaz çizgide olduğu gibi serbestçe şerit değiştirebilirsiniz","Çizgiyi yalnızca sola, eve giden yola dönmek için geçin, ancak traktörü geçmek için değil"],"explanation":"Çift düz sarı çizgi her iki yönde de geçişin yasak olduğu anlamına gelir, bu yüzden görüş iyi olsa bile traktörü geçemezsiniz; çizgiyi yalnızca dönüş yapmak için (örneğin eve giden yola) geçebilirsiniz. Yol boş ve 'yalnızca karşı yön' seçenekleri tuzaktır çünkü yasak görüşten bağımsız olarak her iki yönde de geçerlidir."},"28":{"q":"Tüm trafiğin aynı yönde aktığı üç şeritli bir otoyolda sürüş yapıyorsunuz. Bir çıkışa yaklaşırken, sağınızdaki şerit çizgisinin kesik beyaz çizgiden tek bir düz beyaz çizgiye dönüştüğünü fark ediyorsunuz. Bu düz beyaz çizgi, burada şerit değiştirme konusunda size ne söyler?","options":["Bu noktada şerit değiştirmek için çizgiyi geçmenizi caydırır","Yol açık olduğunda istediğiniz zaman serbestçe şerit değiştirmenize izin verir","Zıt yönlerde hareket eden trafiği ayırır","Yalnızca karşıdan gelen trafik olmadığında geçişe izin verildiği anlamına gelir"],"explanation":"A solid white line discourages lane changes, so you should stay in your lane rather than cross it near the exit, whereas a broken white line is what allows lane changes when clear (option B). White lines separate same-direction traffic, so the opposite-direction and oncoming-traffic options describe yellow-line rules, not this marking."},"29":{"q":"Bir kavşakta kırmızı ışığa yaklaşıyorsunuz ve sağa dönmek istiyorsunuz. Kırmızıda dönüşü yasaklayan bir işaret yok ve yaya geçidi ile karşıdan gelen trafik boş. Doğru hareket nedir?","options":["Yol boş olduğu için yavaşlayın ama durmadan kırmızı ışıkta geçin","Önce çizginin arkasında tamamen durun, sonra güvenli olduğunda sağa dönün","Sağa dönebilmek için yeşil oka kadar bekleyin","Kırmızı ışığı yol ver olarak değerlendirip tamamen durmadan dönüşe girin"],"explanation":"Sabit kırmızı ışık çizginin arkasında tam bir duruş gerektirir ve kırmızıda sağa dönüş, yasaklayan bir işaret yoksa yalnızca bu tam duruştan sonra serbesttir. Durmadan geçmek (A) veya durmadan yol vermek (D) zorunlu tam duruşu atlar; izin verilen kırmızıda sağa dönüş için yeşil ok (C) gerekmez."},"30":{"q":"Hız sınırında bir kavşağa yaklaşırken karşınızdaki sinyal yeşilden sabit SARI'ya döner. Hala biraz geridesiniz ve yumuşak bir şekilde fren yapmak için bolca yeriniz var. Bu sinyal ne anlama gelir ve ne yapmalısınız?","options":["Işık tekrar yeşile dönmek üzere; değişmeden önce kavşağı geçmek için hızlanın","İleride viraj veya birleşme gibi bir tehlike uyarısıdır; yavaşlayın ama geçmeye devam edebilirsiniz","Işık kırmızıya dönmek üzere; güvenli bir şekilde yapabiliyorsanız çizginin önünde durun","Kavşağı dört yönlü dur olarak kabul edin, tamamen durun, ardından sıra sizdeyken devam edin"],"explanation":"A steady yellow light warns that the signal is about to turn red, so you must stop before the line if you can do so safely, which you can from this distance. Option D describes a dark/non-working signal, and option B confuses the signal with a yellow warning sign, not a traffic light."},"31":{"q":"Sabit YEŞİL ışıkta bir kavşağa geliyorsunuz ve sola dönüş sinyali veriyorsunuz. Karşıdan araçlar yaklaşıyor ve geçmeniz gereken yaya geçidine bir yaya adım atıyor. Ne yapmalısınız?","options":["Yeşil ışık size korumalı dönüş hakkı verdiği için hemen ilerleyin.","Çizginin arkasında tamamen durun ve dönmeden önce yeşil ok bekleyin.","Karşıdan gelen araçların dönen araca yol vermesi gerektiğinden, onların önünden hızlıca dönün.","Bekleyin, yayaya ve karşıdan gelen trafiğe yol verin, ardından yol açık olduğunda dönüşü tamamlayın."],"explanation":"A steady green means go only if the way is clear; when turning you must yield to pedestrians and oncoming traffic, so you wait until both are clear before turning. A plain green is not a protected turn (only a green arrow is), and oncoming traffic does not yield to you, so the other answers are wrong."},"32":{"q":"Gece bir kavşağa yaklaşıyorsunuz ve sizin yönünüzdeki üstteki trafik ışığı kırmızı yanıp sönüyor. Görünürde başka araç yok. Ne yapmalısınız?","options":["Tam olarak durun, ardından yol açık olduğunda devam edin; bunu bir DUR işareti gibi değerlendirin","Yavaşlayın ve durmadan dikkatle ilerleyin","Yanıp sönen ışık sinyalin geçersiz olduğu anlamına geldiğinden, geçmeye devam edin","Durun ve gitmeden önce ışığın sabit yeşile dönmesini bekleyin"],"explanation":"A flashing red light must be treated exactly like a STOP sign: come to a full stop, then proceed when it is safe. Slowing without stopping (B) is the rule for a flashing yellow light, not a flashing red one."},"33":{"q":"Gece bir kavşağa yaklaşıyorsunuz ve size bakan trafik sinyali yanıp sönen sarı ışık gösteriyor. Ne yapmalısınız?","options":["Çizginin arkasında tamamen durup, yol açık olduğunda devam edin, bunu dur işareti gibi kabul edin","Yavaşlayın ve kavşaktan dikkatlice geçin","Tamamen durun ve ışık yeşile dönene kadar durmaya devam edin","Kavşağı dört yönlü dur olarak kabul edin ve sağınızdaki sürücüye yol verin"],"explanation":"A flashing yellow light means slow down and proceed with caution, so option B is correct. Option A describes a flashing RED light (treated as a stop sign), and option D describes a dark or non-working signal, which are the wrong responses for a flashing yellow."},"34":{"q":"Bir kavşakta sola dönüş şeridinde durmuş durumdasınız. Yönünüze ait ana sinyal sabit kırmızı yanıyor, ancak yanındaki ayrı bir sola dönüş sinyali sola işaret eden sabit YEŞİL OK gösteriyor. Bu, sola dönüşünüz için ne anlama gelir?","options":["Beklemelisiniz, çünkü sabit kırmızı ışık kavşaktaki tüm hareketleri kontrol eder","Sola yalnızca karşıdan gelen trafiğe yol verdikten sonra dönebilirsiniz, çünkü yeşil her zaman karşıdan gelen araçlara yol vermek anlamına gelir","Korumalı bir dönüş hakkınız var ve okun gösterdiği yönde sola dönebilirsiniz","Kavşağı tüm yönlerden dur olarak değerlendirmeli ve sıranızda geçmelisiniz"],"explanation":"A green arrow signals a protected turn in the direction it points, so you may turn left with the right of way even though the main signal is red. Option B describes a steady green ball (yield to oncoming traffic), not a green arrow, and option A wrongly lets the red ball override the dedicated turn arrow."},"35":{"q":"Bir kavşakta sola dönüş şeridinde durmuş durumdasınız. Sola dönüş için ayrı sinyal, sola işaret eden sabit kırmızı bir ok gösteriyor, düz gidecek trafik için sinyal ise yeşil. Ne yapmalısınız?","options":["Sola dönün, çünkü düz giden şeritler için yanan yeşil ışık size geçiş hakkı verir","Tam olarak durduktan sonra sola dönün, kırmızı ışıkta sağa dönüş gibi","Kırmızı oku yanıp sönen sarı gibi kabul edip dikkatlice sola dönün","Durmaya devam edin ve bekleyin, çünkü kırmızı ok o yönde sola dönüşe izin verilmediği anlamına gelir"],"explanation":"A red arrow means no turn is permitted in the direction the arrow points, so you must stay stopped until the arrow changes. The green light for the through lanes does not apply to your protected turn, and a red arrow does not allow a turn after stopping the way a steady red ball can."},"36":{"q":"Bir elektrik kesintisi sırasında yoğun bir dört yönlü kavşağa yaklaşıyorsunuz ve normalde burayı kontrol eden trafik ışığı tamamen sönmüş, hiçbir ışık göstermiyor. Çevrede ne polis memuru ne de geçici işaret var. Nasıl ilerlemelisiniz?","options":["Kavşağı her yönden DUR olarak değerlendirin; tamamen durun ve normal geçiş hakkı kurallarına göre yol verin.","Sönük ışık yanıp sönen sarı ışık gibi çalıştığından, durmadan yavaşlayıp dikkatle ilerleyin.","Çalışmayan bir ışık kavşağın aktif kontrolü olmadığı anlamına geldiğinden normal hızda geçin.","Yalnızca çapraz trafik varsa durun, ardından sizden sonra gelen sürücülerden önce geçin."],"explanation":"A dark or non-working signal must be treated as an all-way STOP, so you stop fully and follow normal right-of-way rules. Option B is wrong because a dark signal is not the same as a flashing yellow (slow and proceed with caution); a dead signal requires a complete stop from every direction."},"37":{"q":"Otoyolda giderken ileride elmas şeklinde iki uyarı işareti görüyorsunuz. Birincisi kıvrımlı bir yol gösteren parlak sarı, ikincisi ise kürekli bir işçi gösteren parlak turuncu. İkinci işaretin turuncu rengi size özellikle ne söyler?","options":["İleride sarı işaretle aynı şekilde genel bir viraj veya tepe tehlikesi var","Bir inşaat veya çalışma bölgesine yaklaşıyorsunuz","İleride bir yaya veya okul geçidi var","Yol kapalı olduğu için durmalısınız"],"explanation":"Orange signs indicate a construction or work zone, distinguishing them from standard yellow general-warning signs (curve, hill, merge). Option A confuses orange with the yellow general-warning color, and pedestrian/school warnings use fluorescent yellow-green, not orange."},"38":{"q":"Alacakaranlıkta tanımadığınız iki şeritli bir yolda araç kullanıyorsunuz. Şeridiniz ile solunuzdaki şerit arasındaki orta çizgi, kesintisiz SARI bir çizgidir. Bu renk, solunuzdaki şeritteki trafik hakkında size ne söyler?","options":["Her iki yönden trafiğin kullanabileceği bir dönüş şerididir","Asfaltlanmış banket olduğundan üzerinde geçiş trafiği yoktur","Sizinkine ters yönde hareket eden trafiği taşır","Sizinle aynı yönde hareket eden trafiği taşır"],"explanation":"Yellow lines separate traffic moving in opposite directions, so the yellow center line means the lane to your left carries oncoming traffic. White lines (option D) would indicate traffic moving in the same direction, which is the trap here."},"39":{"q":"Alacakaranlıkta tanımadığınız bir kasabadan geçerken, net görebildiğiniz ancak yazıları henüz okunamayan bir yol kenarı levhasına yaklaşıyorsunuz. Düz beyaz zeminli ve siyah yazılı uzun, dikey bir dikdörtgen. Daha onu okuyamadan, levhanın şekli ve rengi amacı hakkında size ne söyler?","options":["İleride yönleri, mesafeleri veya hizmetleri gösteren bir kılavuz levhasıdır","İleride bir tehlike veya değişen koşul konusunda sizi uyaran bir uyarı levhasıdır","Aktif bir çalışma alanını işaretleyen bir inşaat levhasıdır","Uymanız gereken bir kuralı belirten bir düzenleyici levhadır"],"explanation":"A vertical rectangle that is white with black lettering is a regulatory sign, meaning it states a law (such as a speed limit) that you must obey. Guide signs are green or horizontal rectangles, warning signs are yellow diamonds, and construction signs are orange, so those choices misread the white-and-black vertical rectangle."}},"learn-road-signs":{"0":{"q":"DUR işareti hangi şekildedir?","options":["Sekizgen (8 kenarlı)","Eşkenar dörtgen","Daire","Dikey dikdörtgen"],"explanation":"A STOP sign is the only octagonal (8-sided) sign and requires a full stop."},"1":{"q":"Ters (baş aşağı) üçgen şeklindeki bir işaret ne anlama gelir?","options":["Dur","Yol ver","Geçiş yasağı","Okul bölgesi"],"explanation":"An inverted triangle means YIELD, so give the right of way and slow or stop if needed."},"2":{"q":"Flama işareti (yolun sol tarafında yatay üçgen) ne anlama gelir?","options":["İleride okul bölgesi","Tamamen dur","Geçme Yasağı Bölgesi","Demir yolu geçidi"],"explanation":"A pennant, a horizontal triangle placed on the left side of the road, marks a No Passing Zone."},"3":{"q":"Elmas (baklava) şeklindeki bir tabela size ne anlatır?","options":["Tam olarak durmanız gerekir","Tek yönlü bir yola giriyorsunuz","Hız sınırına ulaştınız","İleride bir tehlike veya durum vardır"],"explanation":"A diamond-shaped sign is a warning sign that indicates a hazard or condition ahead."},"4":{"q":"Beşgen şeklindeki bir işaret (5 kenar, ucu yukarı) neyi gösterir?","options":["Okul bölgesi veya okul geçidi","Demir yolu geçidi","Geçme yasağı bölgesi","Dur kavşağı"],"explanation":"A pentagon (5 sides, point up) marks a school zone or school crossing."},"5":{"q":"Yuvarlak (dairesel) bir trafik levhası sizi ne konusunda uyarır?","options":["İleride bir okul bölgesi","İleride bir demiryolu geçidi","Geçmenin yasak olduğu bir bölge","Bir inşaat bölgesi"],"explanation":"A round (circular) sign is an advance warning that a railroad crossing is ahead."},"6":{"q":"Çarpı (X) şeklindeki crossbuck işareti ne anlama gelir?","options":["Tamamen dur","İleride yol çalışması","Demir yolu geçidi; yol verir gibi davranın","İleride okul bölgesi"],"explanation":"A crossbuck (X shape) marks the railroad crossing itself and should be treated like a yield."},"7":{"q":"Dikey dikdörtgen bir levha ne anlama gelir?","options":["İleride tehlike uyarısı","Okul bölgesi geçidi","İleride demir yolu geçidi","Uymanız gereken bir kural"],"explanation":"A vertical rectangle is a regulatory sign indicating a law you must obey, such as a speed limit."},"8":{"q":"Yatay dikdörtgen ne tür bir levhadır?","options":["Yön ve mesafe gösteren bir kılavuz veya bilgi levhası","Bir dur levhası","İleride tehlike için uyarı levhası","Bir okul bölgesi levhası"],"explanation":"A horizontal rectangle is a guide or information sign that gives directions and distances."},"9":{"q":"Hangi tabela şekli yalnızca DUR için kullanılır?","options":["Eşkenar dörtgen","Sekizgen","Üçgen","Dikdörtgen"],"explanation":"The octagon (8 sides) is the only sign shape reserved exclusively for STOP."},"10":{"q":"Bir trafik işaretinde kırmızı renk ne anlama gelir?","options":["İnşaat bölgesi","Sürücü hizmetleri","Dur, yol ver veya yasak","Genel uyarı"],"explanation":"Red is used on STOP, YIELD, DO NOT ENTER, and WRONG WAY signs to mean stop, yield, or prohibited."},"11":{"q":"Sarı bir yol işareti ne anlama gelir?","options":["İlerde yapım çalışması bölgesi","Dur veya girilmez","Yakında sürücü hizmetleri","İlerde genel uyarı"],"explanation":"Yellow signals a general warning, such as a curve, hill, merge, or signal ahead."},"12":{"q":"Turuncu bir yol işareti ne anlama gelir?","options":["İnşaat veya çalışma bölgesi","Dur veya yol ver","Sürücü hizmetleri","Dinlenme alanı"],"explanation":"Orange signs warn of construction or a work zone ahead."},"13":{"q":"Yeşil bir trafik levhası ne anlama gelir?","options":["Dur veya yol ver","Yönlendirme ve yön bilgisi","İnşaat alanı","Genel uyarı"],"explanation":"Green signs give guide information like directions and distances."},"14":{"q":"Mavi bir trafik levhası ne anlama gelir?","options":["İleride inşaat alanı","Dur veya yol ver","Benzin ve yemek gibi sürücü hizmetleri","Dinlenme alanları"],"explanation":"Blue signs show motorist services such as gas, food, lodging, and hospital."},"15":{"q":"Hangi renk trafik işareti dinlenme, kültürel veya manzara alanlarını gösterir?","options":["Mavi","Yeşil","Sarı","Kahverengi"],"explanation":"Brown signs mark recreation, cultural, or scenic areas."},"16":{"q":"Siyah harfli beyaz bir tabela ne anlama gelir?","options":["Hız sınırı gibi düzenleyici","İnşaat veya çalışma alanı","Dinlenme veya manzara alanı","İleride genel uyarı"],"explanation":"A white sign with black letters is regulatory, such as a speed limit or lane use sign."},"17":{"q":"Floresan sarı-yeşil bir işaret neyi uyarır?","options":["İnşaat çalışma bölgeleri","Yaya, bisiklet ve okul bölgeleri","Benzin ve yemek gibi sürücü hizmetleri","Dinlenme ve manzaralı alanlar"],"explanation":"Fluorescent yellow-green signs warn of pedestrian, bicycle, and school crossings."},"18":{"q":"WRONG WAY (Yanlış Yön) işareti hangi renktir?","options":["Sarı","Yeşil","Kırmızı","Mavi"],"explanation":"A WRONG WAY sign is red, signaling you must not proceed."},"19":{"q":"Birleşme uyarı işareti hangi renktedir?","options":["Turuncu","Mavi","Yeşil","Sarı"],"explanation":"Yellow is used for general warning signs, including merge signs."},"20":{"q":"DUR (STOP) işareti hangi şekildedir?","options":["Sekizgen (8 kenar)","Eşkenar dörtgen","Daire","Kare"],"explanation":"A STOP sign is a red octagon, the only sign with that shape."},"21":{"q":"YOL VER işareti hangi renktedir?","options":["Sarı ve siyah","Kırmızı ve beyaz","Yeşil ve beyaz","Mavi ve beyaz"],"explanation":"A YIELD sign is a red-and-white inverted triangle."},"22":{"q":"GİRİLMEZ ve YANLIŞ YÖN tabelaları hangi renktir?","options":["Sarı","Yeşil","Kırmızı","Mavi"],"explanation":"DO NOT ENTER and WRONG WAY signs are red and mean do not proceed."},"23":{"q":"TEK YÖN (ONE WAY) levhası size ne söyler?","options":["Dönmeden önce tamamen durun","İleride yol kapalı","Burada geçiş serbesttir","Yalnızca okun gösterdiği yönde ilerleyin"],"explanation":"A ONE WAY sign means you may travel only in the direction the arrow points."},"24":{"q":"HIZ SINIRI levhası neyi gösterir?","options":["İdeal koşullarda yasal azami hızı","Asla altına inilemeyecek asgari hızı","Keskin virajlar için önerilen hızı","Sadece gece sürüşü için olan hızı"],"explanation":"A SPEED LIMIT sign is a white rectangle with black numbers showing the maximum legal speed in ideal conditions."},"25":{"q":"Yasaklayıcı \"Hayır\" işaretleri hangi tasarımı kullanır?","options":["Sarı bir baklava","Çapraz çizgili kırmızı bir daire","Yeşil bir dikdörtgen","Mavi bir kare"],"explanation":"Regulatory \"No\" signs, such as no U-turn or no left turn, use a red circle with a slash."},"26":{"q":"HIZ SINIRI işaretindeki sayı ne anlama gelir?","options":["Yasal asgari hız","Ortalama trafik hızı","Yasal azami hız","Kamyonlar için önerilen hız"],"explanation":"The number on a SPEED LIMIT sign is the maximum legal speed under ideal conditions."},"27":{"q":"Levhada yazan hız sınırı neyi gösterir?","options":["Sürebileceğiniz en düşük hızı","Her hava için hızı","Sadece geceleri geçerli hızı","İdeal koşullar için azami hızı"],"explanation":"The posted speed limit is the maximum for ideal conditions, so drive slower in poor conditions."},"28":{"q":"Yoldaki sarı çizgiler neyi ayırır?","options":["Zıt yönlerde hareket eden trafiği","Aynı yönde hareket eden trafiği","Park yerlerini","Bisiklet şeritlerini"],"explanation":"Yellow lines separate traffic moving in opposite directions."},"29":{"q":"Yoldaki beyaz çizgiler neyi gösterir?","options":["İleride okul bölgesi","Aynı yönde hareket eden trafik","Zıt yönlerde hareket eden trafik","Geçiş yasağı bölgesi"],"explanation":"White lines separate lanes of traffic moving in the same direction and mark the road edge."},"30":{"q":"Yolun sizin tarafınızdaki düz sarı çizgi ne anlama gelir?","options":["Geçiş serbesttir","İleride yol biter","Geçiş yasaktır","Tek yönlü yol"],"explanation":"A solid yellow line on your side means you may not pass."},"31":{"q":"Kesik (kesikli) sarı çizgi ne anlama gelir?","options":["Bu çizgi asla geçilemez","Her iki yönde de geçiş yasaktır","Yolun kenarını işaretler","Yol açık olduğunda geçiş yapmaya izin verilir"],"explanation":"A broken (dashed) yellow line means passing is allowed when the way is clear."},"32":{"q":"Çift düz sarı çizgi ne anlama gelir?","options":["Her iki yönde de geçiş yasak","Her iki yönde geçiş serbest","Şeritler aynı yöne gider","İleride yol kenarı"],"explanation":"A double solid yellow line means no passing in either direction; do not cross except to turn."},"33":{"q":"Yoldaki düz beyaz çizgi ne anlama gelir?","options":["Geçiş yapmaya izin verilir","Şerit değiştirmek önerilmez","Trafik zıt yönlerde akar","Durmanız gerekir"],"explanation":"A solid white line discourages lane changes."},"34":{"q":"Kesik beyaz çizgi neye izin verir?","options":["Tamamen durmaya","Karşıdan gelen trafiği geçmeye","Şerit değiştirmeye","Asla geçmemeye"],"explanation":"A broken white line separates lanes going the same way and allows lane changes."},"35":{"q":"Yol kaplamasındaki beyaz çizgiler neyi işaretler?","options":["Bir demir yolu geçidini","İleride bir okul bölgesini","Zıt yönlerde giden trafiği","Yolun kenarını"],"explanation":"White lines mark the edge of the road and separate traffic moving in the same direction."},"36":{"q":"Aynı yönde giden trafik şeritlerini ayıran çizgiler ne renktir?","options":["Beyaz","Sarı","Kırmızı","Mavi"],"explanation":"White lines separate traffic moving in the same direction, while yellow lines separate opposite directions."},"37":{"q":"Sabit kırmızı trafik ışığında ne yapmalısınız?","options":["Yavaşlayıp devam etmek","Çizginin arkasında tamamen durmak","Kavşağı geçmek için hızlanmak","Korna çalıp geçmek"],"explanation":"A steady red light means you must stop completely behind the line and remain stopped."},"38":{"q":"Sabit kırmızı ışıkta sağa ne zaman dönebilirsiniz?","options":["Hiçbir zaman, asla","Önce durmadan","Tam olarak durduktan sonra, bir işaret yasaklamadıkça","Yalnızca ok gösterildiğinde"],"explanation":"At a steady red light you may turn right after coming to a full stop, unless a sign prohibits it."},"39":{"q":"Sabit sarı trafik ışığı ne anlama gelir?","options":["Kırmızıya yetişmek için hızlanın","Işık bozuk; istediğiniz zaman geçin","Sadece arkanızda araç varsa durun","Işık birazdan kırmızıya dönecek; güvenliyse durun"],"explanation":"A steady yellow light warns that the signal is about to turn red, so stop if you can do so safely."},"40":{"q":"Sabit YEŞIL trafik ışığı ne anlama gelir?","options":["Yol açıksa geçin","Tamamen durun","Yavaşlayın ve durmaya hazırlanın","Sadece korumalı dönüş yapın"],"explanation":"A steady green light means you may go if the way is clear."},"41":{"q":"Sabit yeşil ışıkta dönüş yaparken kime yol vermelisiniz?","options":["Kimseye","Yayalara ve karşıdan gelen trafiğe","Sadece park halindeki araçlara","Arkanızdaki trafiğe"],"explanation":"At a steady green light, you must yield to pedestrians and oncoming traffic when turning."},"42":{"q":"Yanıp sönen kırmızı trafik ışığına nasıl davranmalısınız?","options":["Yeşil ışık gibi","Yol ver işareti gibi","Dur işareti gibi","Sarı ışık gibi"],"explanation":"A flashing red light means you must stop completely, just like at a stop sign."},"43":{"q":"Yanıp sönen sarı trafik ışığı ne anlama gelir?","options":["Tamamen durmak","Kavşağı geçmek için hızlanmak","Işık bozuk, hareket etmeyin","Yavaşlayın ve dikkatlice ilerleyin"],"explanation":"A flashing yellow light means slow down and proceed with caution."},"44":{"q":"Yeşil ok trafik ışığı ne anlama gelir?","options":["Okun gösterdiği yönde korumalı dönüş","O yönde dönüş yok","Dönmeden önce dur","Yavaşla ve dikkatli ol"],"explanation":"A green arrow means a protected turn in the direction the arrow points."},"45":{"q":"Kırmızı ok sinyali ne anlama gelir?","options":["O yöne hızlıca dönün","O yöne dönüşe izin verilmez","Dönmeden önce yol verin","Yalnızca durduktan sonra dönün"],"explanation":"A red arrow means you may not turn in that direction."},"46":{"q":"Kararmış veya çalışmayan bir trafik sinyaline nasıl davranmalısınız?","options":["Durmadan geçin","Yol ver işareti gibi kabul edin","Her yönden dur işareti gibi kabul edin","Kavşağı geçmek için hızlanın"],"explanation":"A dark or non-working signal should be treated as an all-way stop."},"47":{"q":"DUR (STOP) levhası hangi şekildedir?","options":["Baklava (eşkenar dörtgen)","Yuvarlak","Üçgen","Sekizgen"],"explanation":"A STOP sign is the only octagonal (8-sided) sign, so its shape alone tells you to stop."},"48":{"q":"Hız sınırı levhası ne renktir?","options":["Siyah yazılı beyaz","Siyah yazılı sarı","Beyaz yazılı kırmızı","Beyaz yazılı yeşil"],"explanation":"A speed limit sign is white with black lettering because it is regulatory, not a warning."},"49":{"q":"Manzara alanı tabelası hangi renktir?","options":["Mavi","Kahverengi","Yeşil","Sarı"],"explanation":"Brown signs mark recreation, cultural, and scenic areas."},"50":{"q":"Hastane ve yemek gibi sürücü hizmetleri tabelaları hangi renktir?","options":["Kırmızı","Yeşil","Mavi","Kahverengi"],"explanation":"Blue signs show motorist services such as gas, food, lodging, and hospitals."},"51":{"q":"Çalışma alanı veya inşaat işareti hangi renktedir?","options":["Sarı","Yeşil","Mavi","Turuncu"],"explanation":"Work zone and construction signs are orange, which sets them apart from yellow general-warning signs."},"52":{"q":"Okul geçidi uyarı levhası ne renktir?","options":["Floresan sarı-yeşil","Mavi","Kahverengi","Turuncu"],"explanation":"Fluorescent yellow-green is the color for pedestrian, bicycle, and school warnings."},"53":{"q":"STOP (DUR), YIELD (YOL VER), DO NOT ENTER (GIRILMEZ) ve WRONG WAY (YANLIS YON) levhalarinin ortak rengi nedir?","options":["Sari","Kirmizi","Yesil","Mavi"],"explanation":"Red is the color shared by STOP, YIELD, DO NOT ENTER, and WRONG WAY signs."},"54":{"q":"Çift düz sarı çizgiyi ne zaman geçebilirsiniz?","options":["Başka bir aracı geçmek için","Yol boşken her zaman","Sadece dönmek için","Hiçbir nedenle asla"],"explanation":"A double solid yellow line may be crossed only to turn, not to pass."},"55":{"q":"Yeşil ok trafik işareti ne anlama gelir?","options":["Durun ve trafiği bekleyin","Yavaşlayın ve yol verin","Dönüş yasak","Karşı trafik durmuş, korumalı dönüş"],"explanation":"A green arrow gives a protected turn because oncoming traffic is stopped during that movement."},"56":{"q":"Yolun sizin tarafınızdaki kesik sarı çizgi ne anlama gelir?","options":["İleride yol açıksa geçiş yapmaya izin verilir","Geçiş yapmaya asla izin verilmez","Durmanız gerekir","Yol tek yönlüdür"],"explanation":"A broken yellow line on your side means you may pass when the road ahead is clear."},"57":{"q":"Demir yolu geçidi ön uyarı levhası hangi şekildedir?","options":["Eşkenar dörtgen","Yuvarlak","Sekizgen","Çapraz işaret (X şekli)"],"explanation":"The railroad advance-warning sign is round, while the sign at the crossing itself is a crossbuck."},"58":{"q":"Yanıp sönen kırmızı trafik ışığında ne yapmalısınız?","options":["Yavaşlayın ve devam edin","Geçmek için hızlanın","Tam olarak durun","Yol açıksa görmezden gelin"],"explanation":"A flashing red light means come to a complete stop, just like at a STOP sign."},"59":{"q":"Sola dönüş okunun üzerindeki kırmızı daire ve çapraz çizgi ne anlama gelir?","options":["Sadece sola dönüş","Sol şerit bitiyor","İleride sola dönüş","Sola dönüş yasak"],"explanation":"A red circle and slash over a left-turn arrow means no left turn is allowed."}},"rules-of-the-road":{"0":{"q":"Teksas'ta saatte 70 mil hız sınırı olan kırsal bir karayolunda gidiyorsunuz. Aniden yoğun bir sis bastırıyor ve önünüzde ancak iki araç boyu kadar görebiliyorsunuz. Teksas yasalarına göre hangi hızda gitmenize izin verilir?","options":["Saatte 70 milden daha yavaş — sis için makul ve güvenli bir hızda, çünkü levhadaki sınır yalnızca ideal koşullar için geçerli olan azami hızdır","Saatte 70 mile kadar, çünkü bu yasal olarak levhada belirtilen sınırdır ve her zaman levhadaki hızda gidebilirsiniz","Tam olarak saatte 50 mil, çünkü Teksas yasaları görüş mesafesi kötü olduğunda hızı saatte 20 mil düşürmeyi zorunlu kılar","Saatte 75 mile kadar, çünkü kırsal Teksas eyaletlerarası yolları koşullardan bağımsız olarak saatte 75 mile izin verir"],"explanation":"Teksas'ın temel hız yasasına (prima facie) göre, mevcut koşullar için makul ve güvenli olandan asla daha hızlı gidemezsiniz; bu nedenle yoğun siste levhadaki 70 mil hızın epey altına inmelisiniz. Levhadaki tam hızda gitmek (B) tuzaktır: levhadaki sayı iyi koşullar için bir azami değerdir, bir garanti değil; 20 mil ve 75 mil rakamları (C, D) ise yanlış bağlama çekilmiş gerçek kurallardır."},"1":{"q":"İşaretli bir karayolundan bir şehrin kentsel bölgesindeki bir yerleşim sokağına dönüyorsunuz. Blok boyunca hiçbir yerde hız sınırı işareti görmüyorsunuz. Burada yasal azami hız olarak hangi hızı varsaymalısınız?","options":["20 mph, çünkü evlerin bulunduğu herhangi bir alanda varsayılan budur","30 mph, işaret bulunmadığında kentsel bölge için yaygın varsayılan sınır","70 mph, çünkü bu karayolları için varsayılandır ve başka bir işaret bunu geçersiz kılmıyor","İşaret eksik olduğu için, güvenli sürdüğünüz sürece bir sınır yoktur"],"explanation":"Where no sign is posted, the common default speed limit in an urban district is 30 mph, so you should treat 30 mph as the legal maximum. The 20 mph figure is the typical reduced limit for active school zones, not residential streets generally, and 70 mph is the daytime default for numbered highways, not a city street."},"2":{"q":"Öğleden sonra, numaralı bir Teksas karayolunda araç kullanıyorsunuz. Hava açık ve kuru, ancak birkaç mildir tek bir hız sınırı levhası görmediniz. Temel hız yasasına göre yasal olarak sürebileceğiniz azami hız nedir?","options":["Saatte 75 mil, çünkü tüm kırsal Teksas karayollarındaki sınır budur","Saatte 30 mil, çünkü levha olmayan yerlerde varsayılan sınır budur","Saatte 70 mil, numaralı karayollarında gündüz varsayılan sınırı","Saatte 85 mil, Teksas'ta herhangi bir yerde izin verilen en yüksek hız"],"explanation":"Where no sign is posted, the default daytime limit on numbered highways in Texas is 70 mph. The 30 mph trap is the default for urban districts, not numbered highways, and 75 and 85 mph apply only to specific posted Interstates and tollways, not as a general default."},"3":{"q":"Teksas'ta hız sınırı 75 mph olarak belirlenmiş kırsal bir Eyaletler Arası otoyolda (Interstate) seyrediyorsunuz. Birkaç mil sonra Teksas'a özgü bir paralı yola (tollway) geçiyorsunuz ve şimdi tabelalarda 85 mph yazıyor. Trafik az, zemin kuru ve görüş açık. Bu paralı yol bölümünde yasal olarak gidebileceğiniz azami hız nedir?","options":["70 mph, çünkü numaralı karayolları için eyalet genelindeki gündüz azami hızı budur","75 mph, çünkü az önce ayrıldığınız Eyaletler Arası otoyoldaki sınır buydu","80 mph, çünkü Teksas yasası tüm yolları 80 mph ile sınırlar","85 mph, çünkü bu, bu özel paralı yolda tabelalarda belirtilen hızdır"],"explanation":"Teksas yollarında, koşullar güvenli olduğunda tabelada belirtilen hız sınırına kadar yasal olarak gidebilirsiniz ve Teksas'a özgü bazı paralı yollarda hız sınırı 80 ila 85 mph kadar yüksek olabilir. 70 ve 75 mph seçenekleri başka yollar için gerçek sınırlardır ancak bu paralı yoldaki daha yüksek tabela değerini geçersiz kılmaz."},"4":{"q":"Sabah 7:45'te bir ilkokulun önünden geçiyorsunuz. Yerleştirilmiş okul bölgesi tabelasında 'YANIP SÖNERKEN 20 MPH' yazıyor ve üzerindeki sarı ışıklar yanıp sönüyor. Burada doğru hız nedir?","options":["20 mph, çünkü ışıklar yanıp sönerken yerleştirilmiş düşürülmüş okul bölgesi sınırına uymak zorundasınız","30 mph, varsayılan kentsel hız sınırı, çünkü okul bölgesi sınırı yalnızca kaldırım tarafındaki şeride uygulanır","Normal sınırın altında güvenli herhangi bir hız, çünkü yanıp sönen ışıklar yalnızca bir uyarıdır, kanun değildir","70 mph, gündüz karayolu sınırı, çünkü düşürülmüş sınır yalnızca çocuklar binadan çıktıktan sonra geçerlidir"],"explanation":"When school-zone lights are flashing (or children are present), you must obey the posted reduced limit, typically 20 mph. The 30 mph default applies only on ordinary urban streets without a posted school-zone sign, so it is the wrong limit here."},"5":{"q":"Sabah bir ilkokulun önünden geçiyorsunuz. Okul bölgesi ışıkları yanıp sönüyor ve kaldırımda çocuklar var. Telefonunuz işten gelen bir aramayla çalıyor. Texas yasası sizden ne yapmanızı gerektirir?","options":["Aramayı yanıtlayın, çünkü okul bölgesi hız sınırı yalnızca ne kadar hızlı sürebileceğinizi kısıtlar","Elde tutulan telefonu kullanmayın, çünkü aktif bir okul bölgesinde elde tutulan telefon kullanmak yasa dışıdır","Aramayı yanıtlayın ancak konuşurken hızınızı belirlenen sınırın 20 mil/saat altına düşürün","Aramayı güvenle yanıtlamak için okul yaya geçidinin 15 fit içinde kenara çekilin"],"explanation":"In an active school zone (lights flashing or children present), Texas law prohibits using a handheld phone, so you must not answer the call. Option A is wrong because the rule covers phone use, not just speed; the 20-mph-below figure in C is the Move Over/Slow Down rule for stopped emergency vehicles, not school zones."},"6":{"q":"İki şeritli bir yolda belirtilen 55 mil/saat hız sınırında giderken yoğun bir sis bastırıyor ve görüş mesafesi keskin bir şekilde düşüyor. Ne yapmalısınız?","options":["Yasal olarak belirtilen sınır bu olduğu ve bu hızda gitme hakkınız olduğu için 55 mil/saat hızı koruyun","Uzun farlarınızı açın ve daha uzağı görebilmek için mevcut hızınızı koruyun","Azalan görüş ve yol koşullarına uyacak şekilde hızınızı belirtilen sınırın altına düşürün","Sağ banket şeridine çekip sis tamamen dağılana kadar orada park edin"],"explanation":"Texas's basic speed law requires you to never drive faster than is safe for conditions, so you must slow below the posted limit in fog. Keeping 55 mph (A) ignores that the posted number is only a maximum for ideal conditions, and high beams (B) actually reflect off fog and worsen visibility."},"7":{"q":"Hiçbir yönde dur işareti, yol ver işareti veya trafik ışığı bulunmayan sakin bir yerleşim bölgesi kavşağına yaklaşıyorsunuz. Yan yoldaki bir kamyonet, sizden birkaç saniye önce kavşağa açıkça ulaşmış ve düz devam etmek için bekliyor. Ne yapmalısınız?","options":["Önce siz geçin, çünkü kamyonet sağındaki araca yol vermek zorundadır","Önce siz geçin, çünkü ana yoldaki trafiğin geçiş üstünlüğü vardır","İkiniz de bunu her yönden durulan bir kavşak gibi kabul etmelisiniz ve sağdaysanız siz geçersiniz","Kamyonete yol verin ve önce onun geçmesine izin verin, çünkü kavşağa sizden önce ulaştı"],"explanation":"At an uncontrolled intersection, you must yield to the vehicle that arrived first, so the pickup truck goes through before you. The 'yield to the driver on your right' rule only applies when two vehicles reach the intersection at the same time, which is not the case here."},"8":{"q":"Hiçbir yönde dur tabelası, yol ver tabelası veya trafik ışığı bulunmayan bir mahalle kavşağına yaklaşıyorsunuz. Başka bir araç tam sizinle aynı anda sağınızdan kavşağa geliyor ve ikiniz de düz gitmek istiyorsunuz. Ne yapmalısınız?","options":["Sağınızdaki aracın önce geçmesine izin verin, ardından kavşağı boşalttığında ilerleyin.","Önce siz geçin, çünkü sağdaki araç soldaki araca yol vermek zorundadır.","Hemen ilerleyin, çünkü düz giden sürücünün dönen sürücüye karşı her zaman geçiş üstünlüğü vardır.","İkiniz de tamamen durmalı ve beklemelisiniz, çünkü kontrolsüz bir kavşak her yönden dur tabelalı bir kavşakla aynı kabul edilir."],"explanation":"At an uncontrolled intersection where two vehicles arrive at the same time, you must yield to the driver on your right. The car is on your right, so it goes first; the idea that the left vehicle has priority or that you must treat it as an all-way stop is incorrect."},"9":{"q":"Bir kavşakta sola dönmek için yeşil ışıkta beklemektesiniz. Karşı yönden düz giden bir araç yaklaşıyor ve bir yaya dönmek istediğiniz caddeyi geçmeye başlıyor. Sola dönüşünüzü tamamlamadan önce ne yapmalısınız?","options":["Yeşil ışık size geçiş hakkı verdiği için karşıdan gelen araç gelmeden önce hızlıca dönün","Hem karşıdan gelen araca hem de yayaya yol verin, ardından güvenli olduğunda dönüşünüzü tamamlayın","Sadece karşıdan gelen araca yol verin, çünkü yayalar araçların kavşağı boşaltmasını beklemelidir","Sağınızdaki sürücü size yol vermek zorunda olduğu için önce siz geçin"],"explanation":"When making a left turn you must yield to oncoming traffic and to pedestrians, so you wait for both the approaching car and the crossing pedestrian before turning. A green light does not give a left-turning driver priority over oncoming traffic, and pedestrians in a crosswalk always have the right of way."},"10":{"q":"Yoğun bir ana caddeye çıkan ve bir T-kavşağı oluşturan bir yerleşim sokağında araç kullanıyorsunuz. Kavşakta dur işareti, trafik ışığı veya başka bir kontrol yok. Sokağınızın sonuna ulaştığınızda, ana caddede solunuzdan bir araç yaklaşıyor. Ne yapmalısınız?","options":["Önce siz geçin, çünkü kontrolsüz bir kavşakta yol hakkı her zaman sağdaki araca aittir","Önce siz geçin, çünkü ana caddedeki araç, yan yoldan giren trafiğe yol vermek zorundadır","Ana caddedeki araca yol verin, çünkü ana yoldaki (T'nin üst kısmı) trafik yol hakkına sahiptir","Yalnızca diğer araç dönüş sinyali verirse yol verin, aksi takdirde kavşağa önce siz girebilirsiniz"],"explanation":"At a T-intersection, the road that ends (the stem of the T) must yield to traffic on the through road that forms the top of the T, so you wait for the approaching car. The right-on-arrival rule applies only to vehicles arriving together at an equal, uncontrolled crossing, not to a side road meeting a through road."},"11":{"q":"Teksas'ta tek şeritli bir dönel kavşağa yaklaşıyorsunuz ve solunuzda çember içinde zaten iki araç dönüyor. Doğru ve güvenli bir şekilde girmek için ne yapmalısınız?","options":["Hemen girin ve sola (saat yönünde) dönün, çünkü çemberdeki trafik giren araçlara yol vermek zorundadır","Tamamen durun ve girmeden önce çemberdeki tüm trafiğin çıkmasını bekleyin","Çemberdeki araçlara yol verin, ardından uygun bir boşluk olduğunda sola (saat yönünde) girin","Çemberde zaten bulunan araçlara yol verin, ardından uygun bir boşluk olduğunda sağa (saat yönünün tersine) girin"],"explanation":"At a roundabout you must yield to traffic already in the circle and enter to the right, traveling counter-clockwise. Option C uses the correct yield rule but the wrong direction, and you do not need a full stop or to wait for the circle to empty if a safe gap is available."},"12":{"q":"Tek yönlü, iki şeritli bir şehir caddesinin sağ şeridinde giderken bir siren duyuyorsunuz ve arkadan acil durum ışıkları yanan bir ambulansın yaklaştığını görüyorsunuz. Sağınızda boş bir kaldırım kenarı var. Ne yapmalısınız?","options":["Sağa çekip ambulans geçene kadar durmalısınız.","Hızınızı koruyup şeridinizde kalın ki ambulans sizi soldan geçebilsin.","Bir şerit sağa geçin veya hızı limitten 20 mil/saat aşağıya düşürüp sürmeye devam edin.","Ambulans size yetişmeden öndeki kavşağı geçmek için hızlanın."],"explanation":"When an emergency vehicle approaches with lights and siren, you must pull over to the right and stop until it passes. Option C describes the separate Move Over/Slow Down law for stopped emergency vehicles on the roadside, not for an emergency vehicle responding behind you, and the other choices fail to yield."},"13":{"q":"Houston'da yoğun bir kavşakta sağa dönmek için yeşil ışıkta durmuş bekliyorsunuz. Bir yaya kaldırımdan yeni indi ve dönmek istediğiniz şeride doğru yaya geçidinden geçiyor. Ne yapmalısınız?","options":["Yeşil ışığınız olduğu için, yaya yolunuza ulaşmadan önce hızlıca dönüşünüzü yapın","Yaya geçidindeki yayaya yol verin ve o güvenli bir şekilde yolunuzu boşaltana kadar bekleyin","Önce korna çalıp yayayı acele etmesi için uyararak ilerleyin","Yayanın aracınızın arkasından geçmesi gerektiğini anlaması için yaya geçidine doğru ilerleyin"],"explanation":"Pedestrians in a crosswalk always have the right of way, so you must yield and wait until they have safely cleared your path before turning, even on a green light. Having a green signal does not allow you to turn through a pedestrian who is already lawfully crossing, and honking or edging forward does not transfer that right of way to you."},"14":{"q":"Yeşil ışıkta durmuş, sağa dönüş yapmak için bekliyorsunuz. Koyu renk gözlük takan bir yaya, önünde beyaz bir baston sallayarak kaldırımdan yaya geçidine adım atıyor ve açıkça sizin yolunuzdan karşıya geçiyor. Ne yapmalısınız?","options":["Yeşil ışık aracınıza karşıdan karşıya geçen yayalara göre geçiş üstünlüğü verdiğinden, dönüşü yavaşça tamamlayın","Yayayı uyarmak için kornaya basın, ardından o şeridinize ulaşmadan sağa dönüşünüzü tamamlayın","Tamamen durun ve yol verin, beyaz bastonlu yayanın siz dönmeden önce güvenle karşıya geçmesine izin verin","Yalnızca yaya zaten sizin şeridinizdeyse bekleyin, aksi halde önünden dolanarak dönün"],"explanation":"Texas law requires drivers to yield to a blind pedestrian using a white cane or guide dog, and pedestrians in a crosswalk always have the right of way. A green light does not override your duty to yield to a pedestrian lawfully in the crosswalk, so you must stop and let them cross."},"15":{"q":"Bir kavşakta yeşil ışığa yaklaşıyorsunuz ve düz devam etmek üzeresiniz. Yandaki sokaktan, farları yanan ve küçük bayrakları olan bir araç dizisi bir cenaze arabasını takip ederek, cenaze töreni alayı olarak kendi kırmızı ışıklarına rağmen kavşağa yavaşça giriyor. Ne yapmalısınız?","options":["Alay kırmızı ışıkla karşı karşıya olduğu ve size yol vermesi gerektiği için yeşil ışığınızda geçin","Korna çalıp sıranızı almak için öne ilerleyin, ardından alay araçları arasındaki bir boşluğa girin","Acil durum aracında olduğu gibi sağa çekip tüm alay geçene kadar tamamen durun","Yol verin ve devam etmeden önce tüm cenaze alayının kavşaktan geçmesini bekleyin"],"explanation":"A funeral procession has the right of way at intersections, so you must yield and let the whole procession pass even though you have a green light. Proceeding on green ignores the procession's right of way, and pulling fully to the right is the rule for emergency vehicles with lights and siren, not a funeral procession."},"16":{"q":"Bir şehir caddesinde sürüyorsunuz ve bir sonraki kavşakta sağa dönmeyi planlıyorsunuz. Diğer sürücülerin niyetinizi zamanında anlaması için doğru şekilde sinyal vermek istiyorsunuz. Dönüşten önce hangi noktada sinyal vermeye başlamalısınız?","options":["Döneceğiniz kavşaktan en az 100 fit önce","Döneceğiniz kavşaktan en az 20 fit önce","Yalnızca kaldırıma yakın sağ şeride geçtikten sonra","Döneceğiniz kavşaktan en az 30 fit önce"],"explanation":"Texas law requires you to signal at least 100 feet before making a turn or changing lanes so other drivers have enough warning. The 20-foot and 30-foot distances are real Texas rules (no parking within 20 feet of a crosswalk, 30 feet of a stop sign), but they do not apply to signaling for a turn."},"17":{"q":"İki şeritli, tek yönlü bir caddede ilerliyorsunuz ve yaklaşan kavşakta sağa dönmeniz gerekiyor. Dönüşler için şerit kullanımını kısıtlayan bir işaret yok. Dönüşü doğru yapmak için hangi şeritte olmalısınız ve aracınız nerede konumlanmalı?","options":["Sol şeritte, dönerken orta çizgiye yakın kalarak","Sağ şeritte, dönerken kaldırım kenarına yakın","Dönüşten en az 100 fit önce sinyal verdiğiniz sürece her iki şeritte de","Sağ şeritte, ancak bisikletlilere yer bırakmak için kaldırım kenarından uzak durarak"],"explanation":"A right turn must be made from the right lane, keeping close to the curb. Option A describes the correct setup for a left turn, and signaling distance (Option C) does not change the lane and curb requirement for a right turn."},"18":{"q":"İki yönlü bir yolda bir kavşağa yaklaşıyorsunuz ve ara sokağa sola dönmeyi planlıyorsunuz. Sizin yönünüzde iki şerit var. Aracınızı dönüş için doğru konumlandırmak amacıyla kavşaktan önce hangi şeride geçmelisiniz?","options":["Bordüre yakın kalarak sağ şeride","En az 100 fit önceden sinyal verdiğiniz sürece herhangi bir şeride","Orta çizgiye en yakın olan sol şeride","Kavşağa kadar ilerlemek için kullanılan, çift yönlü sola dönüş orta şeridine"],"explanation":"A left turn must be made from the left lane, the one nearest the center line, so you cross the least amount of opposing traffic. The right lane is for right turns, and a two-way left-turn lane is only for turning, not for traveling up to an intersection on a two-way street with regular through lanes."},"19":{"q":"Sağa dönmek niyetiyle sağ şeritte kırmızı ışıkta tamamen durdunuz. Kavşakta kırmızıda dönüşü yasaklayan bir işaret yok ve çapraz trafik boş. Ne yapmalısınız?","options":["Dönmeden önce ışığın yeşile dönmesini bekleyin, çünkü kırmızı ışıkta sağa dönüş asla izinli değildir.","Sola dönüşte olduğu gibi, yalnızca karşı yönden gelen trafiğe yol verdikten sonra dönün.","Şerit çapraz trafikten zaten boş olduğu için durmadan dönün.","Yasaklayan bir işaret olmadığı ve trafik boş olduğu için, tam durduktan sonra sağa dönüşünüzü yapın."],"explanation":"In Texas, a right turn on red is allowed after coming to a full stop, unless a sign prohibits it; with no such sign and clear traffic, you may turn. Option C is wrong because a complete stop is always required first, and the oncoming-traffic yield in B applies to left turns, not a right turn on red."},"20":{"q":"Tek yönlü bir sokakta kırmızı ışıkta durdunuz ve trafiği sola akan başka bir tek yönlü sokağa sola dönmeyi planlıyorsunuz. Kavşakta dönüşü yasaklayan herhangi bir levha yok. Yasal olarak ne yapabilirsiniz?","options":["Tam olarak durduktan sonra, yol açık olduğunda sola dönmek","Her iki sokak da tek yönlü olduğundan durmadan sola dönmek","Yeşil ışığı beklemek, çünkü Texas'ta kırmızıda sola dönüşe asla izin verilmez","Sola kırmızıda dönmek, ancak yalnızca çift yönlü bir sokaktan geliyorsanız"],"explanation":"A left turn on red is allowed only from a one-way street onto a one-way street, and only after a full stop when no sign prohibits it. You may not roll through without stopping (B), and the turn is permitted in Texas in this exact situation, so waiting for green is not required (C)."},"21":{"q":"Tek yönlü üç şeritli bir caddenin orta şeridinde ilerliyorsunuz ve yaklaşan kavşakta sağa dönmeniz gerekiyor. Dönüşü hangi şeritten tamamlamalısınız?","options":["Orta şeritten, çünkü zaten yolun ortasında konumlanmış durumdasınız","En sağdaki şeritten, yani döndüğünüz yöne en yakın şeritten","En soldaki şeritten, çünkü tek yönlü bir caddede tüm dönüşler soldan başlamalıdır","Herhangi bir şeritten, çünkü tek yönlü bir caddede şerit konumu önemli değildir"],"explanation":"On a one-way street you turn from the lane nearest the direction you are turning, so a right turn must be made from the rightmost lane. Option C confuses this with the left-turn rule, and the left lane is correct only when turning left."},"22":{"q":"İki şeritli bir karayolunda, yavaş giden bir kamyonu geçmek için sol şeride giriyorsunuz. Hızlanıp onu geçtikten sonra tekrar sağ şeride dönmek istiyorsunuz. Şeridinize ne zaman dönmek güvenlidir?","options":["Ön tamponunuz kamyonun önünü geçer geçmez","Yalnızca kamyon, dönmeniz için farlarını yakıp söndürerek işaret verdikten sonra","Geçtiğiniz kamyonu dikiz aynanızda görebildiğinizde","Kamyonun en az 100 fit ötesine geçtikten sonra"],"explanation":"You may return to your lane only when you can see the passed vehicle in your rearview mirror, which confirms you have enough space ahead of it to merge safely. Clearing only your front bumper (A) leaves too little room and could cut the truck off, and there is no rule about a 100-foot distance for merging back."},"23":{"q":"İki şeritli bir kırsal yolda yavaş bir traktörün arkasında ilerliyorsunuz. Bir tepenin zirvesine yaklaşırken önünüzdeki yol görünmüyor ve karşıdan bir araç gelip gelmediğini göremiyorsunuz. Traktörü geçme konusunda ne yapmalısınız?","options":["Traktör hız sınırının çok altında gittiği için tepedeyken hızlıca geçin","Karşı şeride girmemek için sağ banketten geçin","Şimdi geçin, ancak karşıdan gelen trafiği uyarmak için kornaya bastıktan sonra","Geçmeyin; tepeyi geçene ve önünüzdeki yolu net görene kadar bekleyin"],"explanation":"You must not pass on a hill where your view of oncoming traffic is blocked, so you should wait until you can see the road ahead clearly. Passing on the hill (A), sounding the horn (C), or using the right shoulder (B) are all unsafe and illegal because you still cannot verify the lane is clear and passing must be done on the left."},"24":{"q":"İki şeritli kırsal bir karayolunda yavaş bir kamyonun arkasında gidiyorsunuz ve sollamak istiyorsunuz. İleride sağ banket üzerinde sarı, flama biçiminde (sivri üçgen) bir tabela görüyorsunuz. Bu tabela sollama hakkında size ne söyler?","options":["Sollamanın yasak olduğu bir bölgeye giriyorsunuz, bu yüzden burada kamyonu sollamamalısınız","Bu bir Yol Ver tabelasıdır, bu yüzden karşı yönden gelen trafik boşaldığında sollayabilirsiniz","İleride sollama için kullanabileceğiniz iki yönlü sola dönüş şeridini gösterir","Yalnızca bir hemzemin geçit uyarısıdır ve sollama hâlâ serbesttir"],"explanation":"A pennant-shaped sign on the right side of the road marks the start of a No Passing Zone, so you must not pass here. A Yield sign is a downward-pointing triangle facing oncoming drivers, not a side-mounted pennant, which makes option B the trap."},"25":{"q":"Üç şeritli bir Teksas otoyolunda, sol şeritte, belirlenen hız sınırında ilerliyorsunuz. Arkanızdan daha hızlı bir araç yaklaşıyor ve sizi geçmek istiyor. Ne yapmalısınız?","options":["Zaten yasal sınırda gittiğiniz için hızınızı koruyup sol şeritte kalmalısınız","Daha hızlı aracın geçmesi için sağınızdaki bir şeride geçin, sonra sağda kalın","Arkadaki aracın sizi geçmesine gerek kalmaması için sınırın üzerine hızlanın","Sol şeritte durup daha hızlı araca el işaretiyle sizi geçmesini söyleyin"],"explanation":"In Texas you must keep right except to pass, and slower traffic keeps right, so you should move into a lane to your right and let the faster vehicle pass. Staying in the left lane just because you are at the limit is wrong, and speeding up or stopping would create a hazard."},"26":{"q":"Gece, tanımadığınız iki şeritli bir yolda araç kullanıyorsunuz. Solunuzda, trafiği taşıyan şeridin yanında kesiksiz sarı bir çizgi uzanıyor ve bu çizginin diğer tarafında size doğru gelen araçların farlarını görüyorsunuz. Bu sarı orta çizgi yol hakkında size ne anlatır?","options":["Diğer taraftaki şerit sizinle aynı yönde gidiyor, bu yüzden uygun olduğunda karşıya geçip katılabilirsiniz","Yol tek yönlüdür ve sarı çizgi yalnızca yolun en dış kenarını işaretler","Çizginin diğer tarafındaki trafik ters yönde, size doğru hareket ediyor","Sarı çizgi yalnızca banket işaretidir ve onun ötesinde bir trafik şeridi yoktur"],"explanation":"Yellow center lines divide traffic moving in opposite directions, which is why you see oncoming headlights across that line. White lines (not yellow) separate lanes traveling the same direction, so options suggesting same-direction or one-way travel are wrong."},"27":{"q":"Dört şeritli bir yolda sürüş yaparken, kendi şeridinizi hemen solunuzdaki şeritten ayıran çizginin düz beyaz, yolun tam ortasındaki çizginin ise sarı olduğunu fark ediyorsunuz. Sizinle solunuzdaki şerit arasındaki beyaz çizgi o komşu şerit hakkında size ne anlatır?","options":["O şeritteki trafik ters yönde ilerlemektedir, bu yüzden ona asla geçmemelisiniz","Solunuzdaki şerit, yalnızca sola dönüş için ayrılmış çift yönlü bir orta dönüş şerididir","Beyaz çizgiler her zaman yalnızca tavsiye niteliğinde olduğundan, istediğiniz zaman serbestçe o şeride geçebilirsiniz","O şeritteki trafik sizinle aynı yönde ilerlemektedir"],"explanation":"White lines separate lanes of traffic traveling in the same direction, so the lane to your left carries traffic going your way. Yellow lines (option A) divide opposite-direction traffic and mark the center of the road, which is the trap here."},"28":{"q":"Şeridinizde trafik sıkışınca, her iki ucunda sol dönüş okları bulunan orta şeride geçip yavaş araçları geçmek için yarım blok boyunca ileri doğru sürüyorsunuz. Bu neden yasa dışıdır?","options":["İki yönlü sol dönüş şeridi yalnızca sol dönüş yapmak içindir ve kısa süreliğine bile olsa seyahat etmek için kullanılamaz.","Orta sol dönüş şeridinde yalnızca 200 fitten az kalmanız koşuluyla seyahat edebilirsiniz.","Orta şerit bir geçiş şerididir, ancak yalnızca sağdan geçmek için kullanabilirsiniz.","En az 100 fit önceden sinyal vermeniz koşuluyla orta şeritte sürmek serbesttir."],"explanation":"A two-way left-turn lane (the center lane marked with arrows) is only for preparing to turn left, never for driving through traffic. Option B invents a distance allowance, and the 100-foot signal rule in D applies to turns and lane changes, not to using this lane for travel."},"29":{"q":"Bir kavşakta dur işaretine yaklaşıyorsunuz. Yaya geçidinden birkaç metre önce zemine net biçimde çizilmiş beyaz bir dur çizgisi var, ancak buradan çapraz trafiği görüş açınız park etmiş bir kamyonla kısmen kapalı. Doğru işlem nedir?","options":["Dur çizgisini yavaşça geçip yalnızca yaya geçidinde çapraz trafiği görebildiğinizde durmak","Önce dur çizgisinin gerisinde tamamen durmak, ardından görebilmek için gerekirse ileri kayıp tekrar durmak","Çizgide yaklaşık 5 mil/saate yavaşlamak; tam duruş yalnızca başka bir araç varsa gereklidir","Çapraz trafiği en iyi şekilde görmek için yaya geçidinin üzerinde durmak"],"explanation":"Texas law requires a full stop at a stop sign behind the stop line or crosswalk, so you must stop there first even if your view is blocked, then creep forward and stop again to see. Rolling through the line, stopping on the crosswalk, or only slowing down all violate the stop-line requirement."},"30":{"q":"Her yönde tek şeritli ve orta refüjü olmayan iki şeritli bir yolda gidiyorsunuz. Önünüzde, sizinle aynı yönde, bir okul otobüsü duruyor, yanıp sönen kırmızı ışıklarını yakıyor ve dur kolunu açıyor. Ne yapmalısınız?","options":["Hızınızı limitin 20 mil/saat altına düşürün ve otobüsü soldan dikkatlice geçin","Yalnızca otobüsün yakınında çocuk görünmüyorsa düşük hızla devam edin","Tamamen durun ve kırmızı ışıklar yanıp sönmeyi bırakana ve dur kolu içeri çekilene kadar durmaya devam edin","Yalnızca otobüsün arkasındaysanız durun; bu yoldaki karşı yönden gelen trafik devam edebilir"],"explanation":"On a road with no physical median or barrier, all traffic from both directions must stop for a school bus showing flashing red lights and an extended stop arm, and stay stopped until the lights stop and the arm folds in. Option D states the median exception, but here there is no median, so traffic from both directions must stop; the 20-mph-below rule in A applies to stopped emergency/utility vehicles, not school buses."},"31":{"q":"Geç kaldınız ve işlek bir şehir merkezi caddesinde bordür kenarında boş bir park yeri gördünüz. Bu yerin hemen önünde bir yangın musluğu var. Yasal şekilde park etmek için aracınızı yangın musluğundan ne kadar uzakta tutmanız gerekir?","options":["En az 30 fit — dur tabelası veya sinyalinden gerekli olan mesafeyle aynı","En az 20 fit — bir kavşaktaki yaya geçidinden gerekli olan mesafeyle aynı","Kaldırımı kapatmadığınız sürece yangın musluğuna kadar yanaşıp park etmek sorun değildir","En az 15 fit"],"explanation":"Teksas yasası, itfaiyecilerin acil durumda erişebilmesi için yangın musluğunun 15 fit yakınına park etmeyi yasaklar. 30 fit ve 20 fit mesafeleri Teksas'ta gerçek mesafelerdir, ancak bunlar sırasıyla dur tabelaları/sinyalleri ve yaya geçitleri için geçerlidir, yangın muslukları için değil."},"32":{"q":"Bir kavşağa yakın, kalabalık bir şehir merkezi caddesinde park yeri arıyorsunuz. Yan sokağın ana yolla birleştiği yerde işaretli bir yaya geçidi var. Yasalara uygun park etmek için aracınız bu yaya geçidinden ne kadar uzakta durmalıdır?","options":["Yaya geçidinden en az 20 fit uzakta","Yaya geçidinden en az 15 fit uzakta","Yaya geçidinden en az 30 fit uzakta","Yaya geçidinden en az 10 fit uzakta"],"explanation":"Texas law prohibits parking within 20 feet of a crosswalk at an intersection so drivers turning into the street can see crossing pedestrians. The 15-foot figure is the no-parking distance for a fire hydrant, and 30 feet applies to a stop sign or signal, so both are real rules placed in the wrong situation."},"33":{"q":"Yoğun bir şehir merkezi caddesinde park yeri arıyorsunuz. Köşenin hemen yanında, bir dur işaretinin bulunduğu yerde boş bir kaldırım kenarı görüyorsunuz. Yasalara uygun şekilde park etmek için aracınız bu dur işaretinden en az ne kadar geride olmalıdır?","options":["En az 15 fit (yaklaşık 4,5 metre)","En az 30 fit (yaklaşık 9 metre)","En az 20 fit (yaklaşık 6 metre)","En az 50 fit (yaklaşık 15 metre)"],"explanation":"In Texas you may not park within 30 feet of a stop sign or traffic signal so your vehicle does not block other drivers' view of it. The 15-foot rule applies to fire hydrants and the 20-foot rule to crosswalks at an intersection, so those distances are traps from other parking rules."},"34":{"q":"Geç kaldınız ve sadece bir dakika kahve almak için arabanızı bırakmak istiyorsunuz. Etrafa bakınca sokak boyunca birkaç boş yer görüyorsunuz. Bunlardan hangisi YASAL bir park yeridir?","options":["İşaretli yaya geçidinin ortasında, çünkü arabanızın yalnızca bir kısmı dışarı taşıyor","Bir konut garaj yolunun tam önünde, çünkü sadece bir dakika gideceksiniz","İki yönlü bir caddenin sizin tarafınızdaki sağ bordürü boyunca, herhangi bir garaj yolu, yaya geçidi veya yangın musluğundan uzakta","Tek boş yer olan sol bordürde, gelen trafiğe dönük şekilde"],"explanation":"Parking is legal only when you are on the correct (right) side of the street and not blocking a driveway, crosswalk, sidewalk, hydrant, or traffic. Options A and B are prohibited because you may never park on a crosswalk or in front of a driveway, and D is illegal because parking against the left curb means facing the wrong way on a two-way street."},"35":{"q":"Yokuş yukarı çıkan dik bir caddede park ediyorsunuz ve yolun sağ kenarında bir bordür var. Araçtan inmeden önce ön tekerlekleri hangi yöne çevirmelisiniz?","options":["Bordüre doğru, böylece araç kayarsa lastikler ona dayanır","Düz, çünkü bordür tek başına aracı yerinde tutar","Lastikleri bordürden uzak tutmak için keskin bir şekilde yolun ortasına, sola","Bordürden uzağa, böylece kayan araç geri bordüre doğru gider"],"explanation":"When parking uphill with a curb, turn the wheels away from the curb so that if the car rolls back, the front tire catches against the curb and stops it. Turning toward the curb is correct only when parking downhill, and the curb by itself is never a substitute for properly aimed wheels and a set parking brake."},"36":{"q":"Aracınızı bordürlü bir sokakta yokuş aşağı bakacak şekilde park ediyorsunuz. Araçtan inmeden önce ön tekerlekleri hangi yöne çevirmelisiniz?","options":["Bordüre doğru, böylece araç hareket ederse bordüre çarparak durur","Bordürden uzağa, böylece araç hareket ederse bordüre doğru yuvarlanır","Düz, çünkü el freni aracı tutacaktır","Sadece aynı zamanda yolun yanlış tarafındaysanız bordüre doğru"],"explanation":"When parking downhill next to a curb, turn the front wheels toward the curb so that if the car rolls, the curb blocks it. Turning the wheels away from the curb is the correct method for parking uphill, not downhill, which makes that option a common reversal trap."},"37":{"q":"Bir telefon görüşmesi yapmak için düz bir kır yolunun çakıllı banketine çekiyorsunuz. Burada bordür yok, sadece sağınıza doğru aşağı eğimli toprak bir banket var. Aracınızdan inmeden önce ön tekerlekleri hangi yöne çevirmelisiniz?","options":["Düz bırakın, çünkü yol düz ve dayanacak bir bordür yok","Bankete doğru (sağa), böylece araç hareket ederse yoldan dışarı doğru kaysın","Yolun ortasına doğru (sola), böylece trafik ön tekerleklerinizi görebilsin","Düz yolda fark etmez; sadece el frenini çekip tekerlekleri olduğu gibi bırakın"],"explanation":"When parking where there is no curb, you should always turn the front wheels toward the shoulder (to the right) so the vehicle would roll away from traffic and off the road if it starts to move. Turning them straight or toward the road is wrong because, even on ground that looks flat, a rolling vehicle could drift into the travel lane and into oncoming traffic."},"38":{"q":"Teksas'ta iki şeritli bir karayolunda 65 mil/saat hızla giderken, ileride sağ banketde durmuş, sarı ışıkları yanıp sönen bir TxDOT bakım kamyonu görüyorsunuz. Sol şeritte yoğun trafik var, bu yüzden güvenli bir şekilde şerit değiştiremiyorsunuz. Move Over/Slow Down (Şerit Değiştir/Yavaşla) yasası sizden ne yapmanızı ister?","options":["Hızınızı koruyun ancak geçerken işçileri uyarmak için kornaya basın","Kamyonun arkasında tamamen durun ve bir işçi sizi el işaretiyle geçirene kadar bekleyin","Durmuş kamyonu geçene kadar 45 mil/saate (hız sınırının 20 mil/saat altına) yavaşlayın","20 mil/saate yavaşlayın ve yalnızca banket boş olduğunda ilerleyin"],"explanation":"When you cannot safely move over a lane, Texas's Move Over/Slow Down law requires you to slow to 20 mph below the posted speed limit, which is 45 mph in a 65 mph zone. Option D wrongly uses 20 mph itself (a school-zone figure) instead of 20 mph below the limit, and stopping or just honking is not required."}},"learn-rules-of-the-road":{"0":{"q":"Teksas'ın temel hız yasasına göre ne kadar hızlı sürebilirsiniz?","options":["Asla mevcut koşullar için güvenli olandan daha hızlı değil","Her zaman tam olarak belirtilen hız sınırında","Aracınızın izin verdiği kadar hızlı","Trafik azsa sınırın 10 mil/saat üzerinde"],"explanation":"Texas's basic speed law means you must never drive faster than is safe for the current conditions."},"1":{"q":"Teksas'ta, levha bulunmayan bir kentsel bölgede varsayılan hız sınırı nedir?","options":["20 mil/saat","30 mil/saat","45 mil/saat","55 mil/saat"],"explanation":"Where unposted, the default speed limit in a Texas urban district is 30 mph."},"2":{"q":"Numaralı bir karayolunda gündüz, levha yoksa varsayılan hız sınırı nedir?","options":["30 mil/saat","55 mil/saat","70 mil/saat","85 mil/saat"],"explanation":"Where unposted, the default daytime speed limit on numbered highways is 70 mph."},"3":{"q":"Bazı Teksas paralı yollarında izin verilen en yüksek hız sınırı nedir?","options":["65 mph","70 mph","75 mph","85 mph"],"explanation":"Some specific Texas tollways are posted with speed limits as high as 85 mph."},"4":{"q":"Okul bölgesinde ışıklar yanıp sönerken veya çocuklar varken ne yapmalısınız?","options":["Belirtilen düşürülmüş hız sınırına uyun","Normal hız sınırında sürün","Bölgeyi geçmek için hızlanın","Tamamen durun ve bekleyin"],"explanation":"In a school zone you must obey the posted reduced limit (often 20 mph) when lights flash or children are present."},"5":{"q":"Teksas'ta aktif bir okul bölgesinde elde tutulan telefon kullanmak yasal mı?","options":["Evet, her zaman","Hayır, yasa dışıdır","Sadece akşam 9'dan sonra","Sadece yakında park halindeyken"],"explanation":"Using a handheld phone in an active school zone is illegal in Texas."},"6":{"q":"Sürüş hızınızı ne zaman azaltmalısınız?","options":["Sadece kuru, boş otoyollarda","Sadece yaya olmadığında","Yağmurda, siste, yoğun trafikte, virajlarda ve yayaların yakınında","Sadece geceleri düz yollarda"],"explanation":"You should always reduce speed in rain, fog, heavy traffic, on curves, and near pedestrians."},"7":{"q":"Kontrolsüz bir kavşakta hangi araç geçiş hakkına sahiptir?","options":["Daha hızlı olan araç","Daha büyük olan araç","Soldaki araç","İlk gelen araç"],"explanation":"At an uncontrolled intersection, you yield to the vehicle that arrived first."},"8":{"q":"Kontrolsüz bir kavşakta, iki araç aynı anda geldiğinde geçiş hakkı kimindir?","options":["Sağdaki sürücü","Soldaki sürücü","Daha hızlı araç","Daha büyük araç"],"explanation":"When two vehicles arrive at the same time, yield to the driver on your right."},"9":{"q":"Sola dönerken kime yol vermelisiniz?","options":["Sadece yayalara","Karşıdan gelen trafiğe ve yayalara","Sadece arkanızdaki trafiğe","Kimseye, geçiş hakkı sizindir"],"explanation":"When turning left, you must yield to oncoming traffic and to pedestrians."},"10":{"q":"T şeklindeki kavşakta hangi trafiğin geçiş hakkı vardır?","options":["Sola dönen trafiğin","Soldaki aracın","Ana yoldaki trafiğin","En son gelen aracın"],"explanation":"Traffic on the through road (the top of the T) has the right of way."},"11":{"q":"Dönel kavşakta geçiş hakkı kimindir?","options":["Girmeyi bekleyen sürücüler","Daha hızlı olan araç","İlk korna çalan","Halihazırda kavşakta olan trafik"],"explanation":"At a roundabout, you must yield to traffic already in the circle before entering."},"12":{"q":"Işıkları ve sireni açık bir acil durum aracı yaklaşırken ne yapmalısınız?","options":["Sağa çekip geçene kadar durun","Yoldan çıkmak için hızlanın","Şeridinizin ortasında durun","Önünden sola dönün"],"explanation":"Pull over to the right and stop until the emergency vehicle has passed."},"13":{"q":"Yaya geçidinde geçiş hakkı kimindir?","options":["En yakın araç","Yayalar","Daha hızlı araç","Dönüş yapan araçlar"],"explanation":"Pedestrians in a crosswalk always have the right of way."},"14":{"q":"Beyaz baston taşıyan veya rehber köpek kullanan kişiye yol vermeniz gerekir?","options":["Park etmiş bir araca","Bir yol işçisine","Kör bir yayaya","Bir bisikletliye"],"explanation":"You must yield to a blind pedestrian carrying a white cane or using a guide dog."},"15":{"q":"Cenaze töreni alayı sırasında kavşaklarda kimin geçiş hakkı vardır?","options":["Çapraz trafik","Önce gelen","Sağdaki sürücü","Cenaze töreni alayı"],"explanation":"A funeral procession has the right of way at intersections."},"16":{"q":"Dönüş veya şerit değişiminden ne kadar önce sinyal vermelisiniz?","options":["En az 100 fit","En az 25 fit","En az 250 fit","En az 500 fit"],"explanation":"In Texas, you must signal at least 100 feet before a turn or lane change."},"17":{"q":"Sağa dönüş yapmak için hangi şeridi kullanmalısınız?","options":["Sol şeridi","Sağ şeridi, kaldırıma yakın","Orta şeridi","Boş olan herhangi bir şeridi"],"explanation":"A right turn should be made from the right lane, close to the curb."},"18":{"q":"Sola dönüş hangi şeritten yapılmalıdır?","options":["Sağ şeritten","Orta şeritten","Sol şeritten","Boş olan herhangi bir şeritten"],"explanation":"A left turn should be made from the left lane."},"19":{"q":"Teksas'ta kırmızı ışıkta sağa dönüş ne zaman izinlidir?","options":["Hiçbir koşulda asla","Sadece geceleri","Önce durmadan","Tam durduktan sonra, bir tabela yasaklamadıkça"],"explanation":"A right turn on red is allowed after coming to a full stop, unless a sign prohibits it."},"20":{"q":"Teksas'ta kırmızı ışıkta sola dönüş ne zaman izinlidir?","options":["Tam durduktan sonra, tek yönlü bir caddeden tek yönlü bir caddeye","Tam durduktan sonra, herhangi bir caddeden","Tam durduktan sonra, iki yönlü bir caddeye","Hiçbir koşulda asla"],"explanation":"In Texas, a left turn on red is only allowed from a one-way street onto a one-way street after stopping fully."},"21":{"q":"Tek yönlü bir yolda hangi şeritten dönmelisiniz?","options":["Orta şeritten","Döndüğünüz yöne en yakın şeritten","Boş olan herhangi bir şeritten","Dönüşünüze en uzak şeritten"],"explanation":"On a one-way street, turn from the lane nearest the direction you are turning."},"22":{"q":"Başka bir aracı hangi taraftan geçmelisiniz?","options":["Sağdan","Her iki taraftan","Soldan","Banketten"],"explanation":"You should pass on the left and return to your lane only when you can see the passed vehicle in your mirror."},"23":{"q":"Başka bir aracı NEREDE geçmemelisiniz?","options":["Düz, dümdüz bir yolda","Şerit boş olduğunda","Geniş bir caddede","Yokuşta veya virajda"],"explanation":"You must not pass on a hill or curve because you cannot see oncoming traffic."},"24":{"q":"Başka bir aracı NEREDE geçmemelisiniz?","options":["Kavşakta veya demir yolu geçidinde","Uzun, düz ve dümdüz bir yolda","Açıkça işaretlenmiş bir geçiş şeridinde","Kesik sarı çizginin sizin tarafınızda olduğu yerde"],"explanation":"It is unsafe and illegal to pass at an intersection or railroad crossing."},"25":{"q":"Başka bir aracı ne zaman geçebilirsiniz?","options":["Sizin tarafınızda kesintisiz sarı çizgi varken","Sizin tarafınızdaki çizgi kesik olduğunda","Tepede veya virajda","Demiryolu geçidinde"],"explanation":"You may pass when the yellow line on your side is broken, but not where a solid yellow line is on your side."},"26":{"q":"Geçmenin yasak olduğu bölgeyi işaret eden levha hangi şekildedir?","options":["Yuvarlak","Kare","Flama (üçgen)","Eşkenar dörtgen"],"explanation":"A No Passing Zone is marked by a pennant-shaped (triangular) sign, where passing is not allowed."},"27":{"q":"Çok şeritli bir yolda yavaş trafik hangi şeridi kullanmalıdır?","options":["Sol şeridi","Orta şeridi","İstedikleri herhangi bir şeridi","Sağ şeridi"],"explanation":"Keep right except to pass; slower traffic stays in the right lane."},"28":{"q":"Yoldaki sarı orta çizgiler neyi ayırır?","options":["Ters yönlerde hareket eden trafiği","Aynı yönde hareket eden trafiği","Park yerlerini seyir şeritlerinden","Bisiklet yollarını kaldırımlardan"],"explanation":"Yellow center lines divide traffic moving in opposite directions."},"29":{"q":"Yoldaki beyaz çizgiler neyi ayırır?","options":["Ters yönlerde giden trafiği","Aynı yönde giden trafik şeritlerini","Park yerlerini yoldan","Yolu kaldırımdan"],"explanation":"White lines separate lanes of traffic moving in the same direction."},"30":{"q":"Sol dönüş oklarıyla işaretlenmiş orta şerit ne için kullanılır?","options":["Diğer araçları geçmek için","Düz trafikte ilerlemek için","Sadece sola dönmek için","Aracı park etmek için"],"explanation":"A two-way left-turn lane is only for turning left, not for travel."},"31":{"q":"Dur işaretinde tam olarak nerede durmalısınız?","options":["Kavşağın ortasında","Güvenli hissettiğiniz herhangi bir yerde","Yaya geçidini geçtikten sonra","Dur çizgisinin veya yaya geçidinin arkasında"],"explanation":"At a stop sign you must come to a full stop behind the stop line or crosswalk."},"32":{"q":"Duran bir okul otobüsü için ne zaman durmalısınız?","options":["Kırmızı ışıkları yanıp sönerken ve dur kolu açıkken","Sadece çocuklar yoldan geçerken","Sadece tam arkasındaysanız","Asla, yavaşça geçebilirsiniz"],"explanation":"You must stop for a stopped school bus when its red lights are flashing and its stop arm is out."},"33":{"q":"Kırmızı ışıkları yanıp sönen, durmuş bir okul otobüsü için ne zaman durmalısınız?","options":["Yalnızca otobüsün arkasındaysanız","Yolları bir refüj ayırmadıkça her iki yönden de","Asla, sadece yavaşlayın","Yalnızca çocuklar geçiyorsa"],"explanation":"You must stop from both directions unless a physical median or barrier separates the roadways."},"34":{"q":"Bir yangın musluğuna ne kadar yakın park edebilirsiniz?","options":["5 fit içinde","10 fit içinde","15 fitten daha yakın değil","Hemen yanına"],"explanation":"You may not park within 15 feet of a fire hydrant."},"35":{"q":"Bir kavşaktaki yaya geçidine ne kadar mesafede park edemezsiniz?","options":["5 fit","10 fit","15 fit","20 fit"],"explanation":"You may not park within 20 feet of a crosswalk at an intersection."},"36":{"q":"Bir dur işaretine ne kadar yakın park edebilirsiniz?","options":["30 feetten daha yakın değil","5 feetten daha yakın değil","10 feetten daha yakın değil","15 feetten daha yakın değil"],"explanation":"In Texas, you may not park within 30 feet of a stop sign or signal."},"37":{"q":"Aracınızı nereye park edemezsiniz?","options":["İşaretli bir park yerine","Yaya geçidine veya kaldırıma","Sağ kaldırım kenarı boyunca","Bir otoparka"],"explanation":"It is illegal to park on a crosswalk or sidewalk."},"38":{"q":"Park etmek nerede yasaktır?","options":["Sakin bir ara sokakta","İşaretli bir otoparkta","Bir araç giriş yolunun önünde","Bir parkmetrenin yanında"],"explanation":"You may not park in front of a driveway."},"39":{"q":"Park etmek nerede yasaktır?","options":["Caddenin sağ tarafında","İşaretli bir park yerinde","Parkmetrenin yanında","Caddenin yanlış tarafında"],"explanation":"You may not park on the wrong side of the street."},"40":{"q":"Nerede park etmenize izin verilmez?","options":["Trafiği engelleyeceğiniz yerde","İşaretli bir park yerinde","Bir otoparkta","Kendi garaj yolunuzda"],"explanation":"You may not park where you would be blocking traffic."},"41":{"q":"Yokuş yukarı bir bordür yanına park ederken tekerlekleri hangi yöne çevirmelisiniz?","options":["Düz ileri","Bordürden uzağa","Bordüre doğru","Fark etmez"],"explanation":"When parking uphill with a curb, turn your wheels away from the curb so the car rolls into the curb if it moves."},"42":{"q":"Bordür yanında yokuş aşağı park ederken ön tekerleklerinizi hangi yöne çevirmelisiniz?","options":["Düz ileriye","Bordürden uzağa","Bordüre doğru","Fark etmez"],"explanation":"When parking downhill with a curb, turn your wheels toward the curb so the car rolls into it if it moves."},"43":{"q":"Bordür olmayan bir yokuşta park ederken tekerleklerinizi hangi yöne çevirirsiniz?","options":["Dümdüz ileri","Yolun ortasına doğru","Fark etmez","Bankete doğru (sağa)"],"explanation":"Without a curb, always turn your wheels toward the shoulder/right so the car rolls off the road if it moves."},"44":{"q":"\"Şerit Değiştir\" yasasına göre, yanıp sönen ışıkları olan duran bir acil durum aracı için ne kadar yavaşlamalısınız?","options":["Hız sınırının 20 mil/saat altına","Hız sınırının 5 mil/saat altına","Hız sınırının 10 mil/saat altına","Tamamen durana kadar"],"explanation":"You must move over a lane or slow to 20 mph below the speed limit for stopped emergency vehicles."},"45":{"q":"Kontrolsüz bir kavşakta geçiş hakkı kimindir?","options":["Daha hızlı araç","Önce gelen araç","Daha büyük araç","Soldaki araç"],"explanation":"At an uncontrolled intersection, yield to the vehicle that arrived first."},"46":{"q":"Dönüş veya şerit değiştirmeden ne kadar önce sinyal vermelisiniz?","options":["En az 25 fit","En az 50 fit","En az 100 fit","En az 200 fit"],"explanation":"In Texas, you must signal at least 100 feet before turning or changing lanes."},"47":{"q":"Okul bölgesinde genellikle hangi hız sınırı belirtilir?","options":["40 mil/saat","55 mil/saat","70 mil/saat","20 mil/saat"],"explanation":"The reduced school zone speed limit is commonly posted at 20 mph."},"48":{"q":"Geçtikten sonra, şeridinize ne zaman güvenle dönebilirsiniz?","options":["Geçtiğiniz aracı dikiz aynanızda görebildiğinizde","Geçişi bitirir bitirmez","Geçtiğiniz araç korna çaldığında","30 saniye bekledikten sonra"],"explanation":"You may return to your lane once you can see the passed vehicle in your rearview mirror."},"49":{"q":"Dönel kavşakta dairenin etrafında hangi yönde sürersiniz?","options":["Saat yönünde","Saat yönünün tersine","Her iki yönde","Düz karşıya"],"explanation":"In a roundabout, traffic moves around the circle counter-clockwise."},"50":{"q":"Bir yangın musluğuna ne kadar yakın park edebilirsiniz?","options":["Sınır yok","5 fit","15 fit","50 fit"],"explanation":"You may not park within 15 feet of a fire hydrant."},"51":{"q":"Şerit Değiştir / Yavaşla yasası, yanıp sönen ışıklı hangi tür aracı da korur?","options":["Dağıtım minibüsleri","Okul otobüsleri","Şehir otobüsleri","Altyapı hizmet araçları"],"explanation":"The Move Over / Slow Down law also covers utility vehicles, along with emergency, tow, and TxDOT vehicles."},"52":{"q":"Teksas'ta yola konulan en yüksek hız sınırı nedir?","options":["80 ila 85 mil/saat","55 mil/saat","65 mil/saat","70 mil/saat"],"explanation":"Some specific Texas tollways are posted at 80 to 85 mph, the highest posted limits in the state."},"53":{"q":"Kırmızı ışıkta sağa dönmeden önce ne yapmalısınız?","options":["Hızlanıp hızlıca katılmak","Önce tam olarak durmak","Diğer sürücüleri uyarmak için korna çalmak","Farlarınızı kapatmak"],"explanation":"A right turn on red is allowed only after coming to a full stop, unless a sign prohibits it."},"54":{"q":"Geçme Yasağı Bölgesi işareti hangi şekildedir?","options":["Yuvarlak","Kare","Flama (üçgen)","Baklava (eşkenar dörtgen)"],"explanation":"A No Passing Zone is marked by a pennant-shaped (triangular) sign."},"55":{"q":"T kavşağında geçiş hakkı kimindir?","options":["T'nin sapından gelen trafik","Daha hızlı olan araç","Soldaki araç","Ana yoldaki trafik"],"explanation":"Traffic on the through road (top of the T) has the right of way."},"56":{"q":"Yokuş aşağı park ederken ön tekerlekleri hangi yöne çevirmelisiniz?","options":["Kaldırıma doğru","Kaldırımdan uzağa","Düz","Fark etmez"],"explanation":"Turning the wheels toward the curb lets the curb block the vehicle if it rolls."},"57":{"q":"Temel hız yasasına göre, yasal azami hız tabeladaki sayıdan daha düşük olabilir mi?","options":["Hayır, tabeladaki sayı her zaman yasal azami hızdır","Evet, koşullar tabeladaki hızı güvensiz hale getirdiğinde","Hayır, yalnızca polis düşürebilir","Evet, ama yalnızca geceleri"],"explanation":"The basic speed law requires a speed safe for conditions, so the legal limit can fall below the posted number when conditions make it unsafe."},"58":{"q":"Sola dönüş yaparken kime yol vermelisiniz?","options":["Sadece karşıdan gelen araçlara","Sadece yayalara","Karşıdan gelen araçlara ve yayalara","Hiç kimseye"],"explanation":"A driver turning left must yield to both oncoming vehicles and pedestrians before completing the turn."},"59":{"q":"Kenara Çek / Yavaşla yasasına göre, yanıp sönen ışıkları olan duran bir acil durum aracının yanından geçerken sürücünün iki seçeneği nedir?","options":["Tamamen durmak veya iki kez korna çalmak","Dörtlüleri yakmak veya uzun farları yakıp söndürmek","Hızlanmak veya şerit değiştirmek","Bir şerit yana çekmek veya hız limitinin 20 mil/saat altına yavaşlamak"],"explanation":"The Move Over / Slow Down law lets you move over one lane away or slow to 20 mph below the speed limit."}},"signals-and-markings":{"0":{"q":"Bir kavşağa yaklaşıyorsunuz ve size bakan trafik sinyali sabit yeşil yanıyor. Karşıdan gelen trafiği keserek sola dönmek istiyorsunuz, ancak birkaç araç kavşaktan size doğru geliyor. Yasal olarak ne yapmanıza izin verilir?","options":["Düz devam edebilir veya dönüşünüzü yapabilirsiniz, ancak önce karşıdan gelen araçlara ve kavşakta zaten bulunan araçlara yol vermelisiniz.","Hemen sola dönün, çünkü sabit yeşil ışık size korumalı bir dönüş hakkı verir ve karşıdan gelen trafik sizin için durmak zorundadır.","Çizginin arkasında tamamen durun ve bekleyin, yeşili karşıdan gelen araçlar geçene kadar yanıp sönen kırmızı gibi kabul edin.","Yavaşlayın ve yol vermeden dikkatlice ilerleyin, çünkü sabit yeşil yanıp sönen sarı ile aynı şekilde çalışır."],"explanation":"A steady green means go only when the intersection is clear; you may proceed straight or turn, but you must yield to oncoming traffic and vehicles already in the intersection. Option B is the trap: only a green arrow gives a protected turn where oncoming traffic is stopped, not a steady green light."},"1":{"q":"Yeşil ışık sabit sarıya dönerken hız sınırında bir kavşağa doğru ilerliyorsunuz. Hâlâ yaklaşık yarım blok uzaktasınız ve arkanızdaki yol boş. Ne yapmalısınız?","options":["Işık kırmızıya dönmeden kavşaktan geçmek için hızlanın","Işık kırmızıya dönmek üzere olduğundan, güvenli bir şekilde yapabiliyorsanız kavşaktan önce durun","Bunu yanıp sönen sarı gibi kabul edip durmadan dikkatlice geçin","Tamamen durun ve ardından yanıp sönen kırmızıda olduğu gibi yol açık olduğunda devam edin"],"explanation":"A steady yellow light warns that the signal is about to turn red, so you should stop if you can do so safely and never speed up to beat the light. Option C describes a flashing yellow (caution) and Option D describes a flashing red (stop sign), which are different signals."},"2":{"q":"Bir kavşağa yaklaşıyorsunuz ve siz işaretli durma çizgisinden henüz kısa bir mesafedeyken size bakan trafik ışığı sabit kırmızıya dönüyor. Dönüşü yasaklayan bir tabela yok ve düz devam etmek istiyorsunuz. Ne yapmalısınız?","options":["Işık yakında değişebileceği için hızınızı azaltıp durmadan kavşaktan dikkatlice geçin","Yalnızca çapraz trafik varsa durun, sonra kırmızı ışıkta düz devam edin","Durma çizgisinin arkasında tamamen durun ve ışık yeşile dönene kadar durmaya devam edin","Sinyali dur tabelası gibi kabul edin, tamamen durun, ardından yol açık olduğunda düz devam edin"],"explanation":"Sabit kırmızı ışık, durma çizgisinin arkasında tamamen durmanızı ve ışık yeşile dönene kadar durmaya devam etmenizi gerektirir. D seçeneği sabit kırmızıyı değil, yanıp sönen kırmızı ışığı (dur tabelası gibi işlem gören) tanımlar; bu nedenle sabit kırmızıda düz devam etmek yanlıştır."},"3":{"q":"Sağ şeritte, sabit kırmızı ışığın olduğu bir kavşağa yaklaşıyorsunuz. Sağa dönmek istiyorsunuz. Dönüşü yasaklayan bir işaret yok ve çapraz trafikte bir boşluk var. Ne yapmalısınız?","options":["Çapraz trafikte boşluk olduğu için yavaşlayıp durmadan sağa dönün","Bunu bir dur işareti gibi kabul edin ve yalnızca yeşil ok yandığında sağa dönün","Sağa dönmeden önce ışığın yeşile dönmesini bekleyin, çünkü kırmızıda asla dönüş yapamazsınız","Çizginin arkasında tamamen durun, ardından yol açık olduğundan ve yasaklayan işaret bulunmadığından sağa dönün"],"explanation":"At a steady red light you must stop completely behind the line, and a right turn is permitted only after that full stop when the way is clear and no sign prohibits it. Option A skips the required full stop, and option C wrongly claims right-on-red is never allowed."},"4":{"q":"Gece geç saatte bir kavşağa yaklaşıyorsunuz ve üstteki trafik ışığı her yönde kırmızı yanıp sönüyor. Etrafta başka hiçbir araç yok. Ne yapmalısınız?","options":["Tamamen durun, ardından güvenli olduğunda kavşaktan geçin.","Yavaşlayın, iki yöne de bakın ve yol açık olduğu için durmadan geçin.","Durun ve yanıp sönen kırmızı sabit yeşile dönene kadar durmaya devam edin.","Bunu bir yol ver işareti olarak kabul edin ve yalnızca başka bir araç yaklaşıyorsa geçin."],"explanation":"A flashing red light means the same thing as a stop sign: you must come to a full stop and then proceed when it is safe. Option B is wrong because a flashing red always requires a complete stop (rolling through is the rule for a flashing yellow), and option C is wrong because a flashing red signal will not turn green."},"5":{"q":"Gece geç saatte, trafik ışığının normal döngüsünde çalışmadığı ve bunun yerine şeridinizin üzerinde sürekli yanıp sönen SARI ışık gösterdiği bir kavşağa yaklaşıyorsunuz. Ne yapmalısınız?","options":["Dur işaretinde olduğu gibi çizginin arkasında tamamen durun, ardından yol açık olduğunda devam edin.","Hızınızı azaltın ve durmadan, çapraz trafiğe dikkat ederek kavşaktan dikkatlice geçin.","Sinyal normal döngüsünde çalışmadığı için kavşağı her yönden duraklı kavşak olarak değerlendirin.","Durun ve sinyal sabit yeşil ışığa dönene kadar durmaya devam edin."],"explanation":"A flashing YELLOW light means caution, so you slow down and proceed carefully through the intersection without coming to a stop. A flashing RED light is the one that means a full stop like a stop sign, and a completely dark or non-working signal is the one treated as an all-way stop, so those are the wrong responses here."},"6":{"q":"Bir kavşakta sola dönmek için bekliyorsunuz. Sinyaliniz sabit kırmızı ışıktı, ancak az önce gitmek istediğiniz yönü gösteren yeşil sola dönüş OKUNA dönüştü. Bu, nasıl ilerlemeniz gerektiği konusunda size ne söyler?","options":["Sola dönebilirsiniz, ancak önce geçiş hakkına sahip olan karşıdan gelen trafiğe yol vermelisiniz","Tam olarak durmalı ve beklemelisiniz, çünkü ok sinyali o yönde dönüşe izin verilmediği anlamına gelir","Şimdi sola dönebilirsiniz ve karşıdan gelen trafik durdurulmuştur, bu size korumalı bir dönüş sağlar","Sola yalnızca yavaşlayıp kontrol ettikten sonra dönebilirsiniz, çünkü ok yanıp sönen sarı uyarı sinyali gibi çalışır"],"explanation":"A green ARROW means a protected turn in the arrow's direction, so oncoming traffic is being held by a red light and you may turn without yielding. Option A describes a steady green light (a permitted turn requiring you to yield), and option B incorrectly describes a red arrow, so both are wrong."},"7":{"q":"Yoğun bir kavşakta sola dönüş şeridinde sola dönmek için bekliyorsunuz. Şeridinize ait sinyal sola dönük sabit kırmızı bir OK gösterirken, düz gidecek trafik için olan normal yuvarlak sinyal yeşil yanıyor. Ne yapmalısınız?","options":["Dikkatlice sola dönün, çünkü düz şeritler için yeşil ışık karşıdan gelen trafiğin korumalı bir şekilde durduğu anlamına gelir","Kırmızı oku yanıp sönen kırmızı gibi kabul edip tamamen durduktan sonra sola dönüş yapın","Karşıdan gelen trafiğe yol verdikten sonra sola dönün, çünkü yol açık olduğunda kırmızı okta sola dönüşe her zaman izin verilir","Durmaya devam edin ve bekleyin, çünkü kırmızı ok sinyal değişene kadar o yöne dönüşe izin verilmediği anlamına gelir"],"explanation":"A red arrow means no turn is allowed in the direction it points, so you must wait until the signal changes, regardless of what the round signal for other lanes shows. A red arrow is not the same as a flashing red, and there is no 'turn after yielding' permitted on a steady red arrow."},"8":{"q":"Bir elektrik kesintisi sırasında işlek bir dört yönlü kavşağa yaklaşıyorsunuz. Trafik ışıkları tamamen sönmüş ve hiç çalışmıyor. Ne yapmalısınız?","options":["Kavşağı her yönde DUR (all-way STOP) gibi kabul edin; geçmeden önce durup sırayla yol verin","Yavaşlayın ve durmadan dikkatlice kavşaktan geçin","Kendi yönünüzün geçiş üstünlüğü olduğunu varsayıp normal hızda devam edin","Yalnızca kavşakta zaten bir araç varsa durun, aksi halde hareket etmeye devam edin"],"explanation":"A dark or non-working signal must be treated as an all-way STOP, so every driver stops and yields in turn. Slowing without stopping (B) is the rule for a flashing yellow light, not a dead signal, and the other options wrongly assume right of way."},"9":{"q":"Yeşil ışıkta durdunuz ve bir yan sokağa sağa dönmek istiyorsunuz. Geçmeyi planladığınız yaya geçidine bakan yaya sinyalinde sabit beyaz yürüyen insan sembolü yanıyor. Bu sembol köşedeki insanlar hakkında size ne söyler?","options":["Yayalar beklemek zorundadır, bu yüzden yaya geçidini kontrol etmeden dönebilirsiniz","Yayalar yasal olarak geçmeye başlayabilir, bu yüzden dönmeden önce onlara yol vermelisiniz","Yayalar yalnızca geçişi tamamlayabilir ama başlayamaz, bu yüzden geçitte çok az kişi olur","Yaya geçidi yayalara kapalıdır ve dönen araçlara ayrılmıştır"],"explanation":"A WALK signal or walking-person symbol means pedestrians may cross, so they have the right of way and you must yield before turning. Option C describes a flashing DON'T WALK/raised hand (finish but don't start), not the steady walking-person symbol."},"10":{"q":"Şehir merkezindeki bir kavşağa yaklaşıp kırmızı ışıkta duruyorsunuz. Beklerken, karşı taraftaki yaya sinyalinin, bir kişi hâlâ sizin köşenizde dururken yanıp sönen kalkık el sembolünden sabit kalkık el sembolüne geçtiğini görüyorsunuz. Bu sabit kalkık el o yayaya ne yapmasını söyler?","options":["Işık değişmeden geçişi tamamlamak için acele etmesi gerektiği anlamına gelir","Yaya geçidinin kapalı olduğu ve başka bir kavşağı kullanması gerektiği anlamına gelir","Caddeyi geçmeye başlamaması gerektiği anlamına gelir","YÜRÜ aşaması başladığı için geçişe başlayabileceği anlamına gelir"],"explanation":"A steady DON'T WALK signal or steady raised-hand symbol means do not start to cross. The flashing raised hand (option A) is what tells someone already in the crosswalk to finish crossing, but a steady hand means do not begin."},"11":{"q":"Bir şehir caddesinde sağa dönmek için yeşil ışıkta durmuş bekliyorsunuz. Geçmeniz gereken yaya geçidine bir yaya tam da karşısındaki yaya sinyali yanıp sönen kaldırılmış el (GEÇMEYİN) sembolünü göstermeye başladığı anda kaldırımdan iniyor. Bu yanıp sönen sinyal, yayanın geçitte bulunma yasal hakkı hakkında size ne söyler?","options":["Yaya hemen durup kaldırıma geri dönmek zorundadır, bu yüzden o geri çekilir çekilmez dönebilirsiniz","Yanıp sönen el, sabit el ile aynı anlama gelir, bu yüzden yayanın girme hakkı yoktu ve siz devam edebilirsiniz","Yanıp sönen el, yanıp sönen sarı ışık gibi yalnızca bir uyarıdır, bu yüzden hem yaya hem de siz birlikte devam edebilirsiniz","Geçitte zaten bulunan bir yaya geçişini tamamlayabilir; yanıp sönen el yalnızca yeni hiç kimsenin geçmeye başlamaması gerektiği anlamına gelir"],"explanation":"A flashing DON'T WALK or flashing raised-hand symbol means anyone already in the crosswalk should finish crossing, while no new pedestrian should start; you must yield until they finish. The steady-hand meaning (B) and the flashing-yellow caution rule (C) are real facts placed in the wrong context."},"12":{"q":"Her şeridin üzerinde şerit kullanım sinyallerinin asılı olduğu çok şeritli bir otoyolda araç kullanıyorsunuz. Girmek istediğiniz şeridin üzerinde sabit yeşil bir aşağı ok görüyorsunuz. Bu, o şerit hakkında size ne söyler?","options":["Şerit açıktır ve o şeritte sürebilirsiniz","Şerit kapalıdır ve şeritten çıkmanız gerekir","Şerit kullanım amacını değiştiriyor, bu yüzden kapanmadan önce şeritten çıkın","Şerit yalnızca HOV veya araç paylaşımı araçlarına ayrılmıştır"],"explanation":"A lane-use green down-arrow means the lane is open for travel, so you may drive in it. A red X means the lane is closed and a yellow X means the lane is changing use and you should move out of it, but neither of those signals is shown here."},"13":{"q":"Çok şeritli bir otoyolda giderken yukarıdaki şerit kontrol sinyallerine bakıyorsunuz. Şeridinizin üzerinde sabit bir kırmızı X yanıyor, sağınızdaki şeritte ise sabit bir yeşil aşağı ok gösteriliyor. Ne yapmalısınız?","options":["Şeridinizde kalın ve dikkatli ilerleyin, çünkü kırmızı X yalnızca yaklaşan bir tehlikeyi uyarır","Sağınızdaki şeride geçin, çünkü kırmızı X şeridinizin kapalı olduğu, yeşil aşağı ok ise o şeridin açık olduğu anlamına gelir","Şeridinizde tamamen durun ve bekleyin, kırmızı X'i yanıp sönen kırmızı sinyal gibi kabul ederek","Şeridinizde kalın ama hemen şeritten çıkın, çünkü kırmızı X şeridin kullanımının değiştiği anlamına gelir"],"explanation":"A lane-use red X means the lane is closed, so you must leave it, and a green down-arrow means the lane beneath it is open for travel. The trap options confuse the red X with a flashing red (stop) signal or with a yellow X, which is the signal that means the lane is changing use and you should move out of it."},"14":{"q":"Çok şeritli bir yolda orta şeritte ilerlerken, şeridinizin üzerindeki şerit kullanım sinyali sabit sarı X'e dönüşüyor. Bu sinyal ne yapmanız gerektiği anlamına gelir?","options":["Şeritte hemen durun, çünkü sarı X yukarıdaki sabit kırmızı ışık gibi çalışır","Şeritte kalın ama neredeyse durana kadar yavaşlayın, çünkü sarı X yalnızca ileride sıkışıklık olduğunu uyarır","Şeritten güvenli bir şekilde çıkmaya hazırlanın, çünkü şeridin kullanımı değişiyor ve yönünüze kapanmak üzere","Normal şekilde devam edin, çünkü sarı X yalnızca şeridin geçiş trafiğine açık olduğunu doğrular"],"explanation":"An overhead lane-use yellow X means the lane is changing use, so you should prepare to safely move out of it before it closes. Stopping in the lane (A) is wrong because a yellow X is not a red light, and continuing as if the lane is open (D) confuses it with a green down-arrow, which is the signal for an open lane."},"15":{"q":"Yavaş bir traktörün arkasında iki şeritli kırsal bir karayolunda gidiyorsunuz. Onu geçmek istiyorsunuz, ancak yolun sizin tarafınızda ortaya boyanmış kesiksiz sarı bir çizgi fark ediyorsunuz. Bu işaret burada geçiş yapmak hakkında size ne söyler?","options":["Geçebilirsiniz çünkü sarı çizgiler yol açıkken her zaman geçişe izin verir","Yalnızca yanında kesik beyaz bir çizgi de varsa geçebilirsiniz","Çizgi sarı olduğu için her iki yönde de geçişe izin verilir","Geçemezsiniz; sizin tarafınızdaki kesiksiz sarı çizgi geçişin yasak olduğu anlamına gelir"],"explanation":"A solid yellow line on your side of the centerline means no passing, so you must stay behind the tractor until the marking changes. Option A confuses this with a broken yellow line (passing allowed when safe), and the white-line and both-directions ideas do not apply to a solid yellow line on your side."},"16":{"q":"İki şeritli kırsal bir karayolunda yavaş bir traktörün arkasından gidiyorsunuz. Yolun ortasında sizin tarafınızda kesik (kesikli) sarı çizgi var, ileride yol düz ve görüş açık, karşıdan gelen trafik görünmüyor. Bu yol işareti traktörü geçmeniz konusunda size ne söyler?","options":["Geçiş güvenli olduğunda izinlidir, bu yüzden traktörü geçmek için çizgiyi aşabilirsiniz","Sizin tarafınızda geçiş yasaktır çünkü herhangi bir sarı çizgi geçiş yok demektir","Çizgiyi yalnızca sola dönmek için aşabilirsiniz, geçmek için değil","Geçiş yalnızca sağ banketten yapılabilir, asla orta çizgiyi aşarak yapılamaz"],"explanation":"A broken (dashed) yellow line on your side of the center means passing is permitted when it is safe to do so, which it is here with clear visibility and no oncoming traffic. The trap in B confuses this with a solid yellow line (no passing), and the turn-only restriction in C applies to a double solid yellow line."},"17":{"q":"İki şeritli bir yolda gidiyorsunuz ve ortasında yan yana iki sürekli sarı çizgiyle işaretlenmiş bir bölüme geliyorsunuz. Önünüzde yavaş bir traktör var ve yol her iki yönde de açık. Solunuzda, dönüş yapabileceğiniz bir araç girişi bulunuyor. Bu işaret size ne yapma izni verir?","options":["Traktörü geçin, çünkü yol her iki yönde de açık ve ileriyi uzaktan görebiliyorsunuz","Şeridinizde kalın ve geçiş yapmayın, ancak sola dönüp araç girişine girmek için çizgileri geçebilirsiniz","Traktörü geçin, çünkü çift sürekli sarı çizgi geçişi yalnızca karşı yön için kısıtlar","Geçiş yapmak için çizgileri serbestçe geçin, çünkü sürekli sarı çizgi geçişi yalnızca önermez ama yasaklamaz"],"explanation":"A double solid yellow line means no passing in either direction, so you must stay in your lane, but you may still cross it to turn (such as into a driveway). Passing is never allowed here regardless of visibility, and the rule applies to both directions, not just oncoming traffic."},"18":{"q":"Tüm trafiğin aynı yönde ilerlediği çok şeritli bir otoyolda araç kullanıyorsunuz. Kendi şeridinizle hemen sağınızdaki şerit arasına çizilmiş bir çizgi fark ediyorsunuz. Bu çizgi büyük olasılıkla hangi renktedir?","options":["Sarı, çünkü sarı çizgiler her zaman her şeridin kenarlarını işaretler","Sarı, çünkü çizgi orada geçişin yasak olduğunu uyarır","Beyaz, çünkü beyaz çizgiler aynı yönde ilerleyen trafik şeritlerini ayırır","Çift sürekli sarı, çünkü yandaki şeride geçmeyi engeller"],"explanation":"White lines separate lanes of traffic that travel in the same direction, so the line between two same-direction lanes is white. Yellow lines are used to separate traffic moving in opposite directions or to mark no-passing zones, which does not apply here."},"19":{"q":"Tüm trafiğin aynı yönde aktığı çok şeritli bir yolda sürüş yapıyorsunuz. Solunuzdaki şerit, sizinkinden kesik (kesintili) beyaz bir çizgiyle ayrılmış. Şeridinizde önünüzdeki trafik yavaşlıyor ve sol şerit boş. Bu işaretleme size sol şeride geçmek hakkında ne söyler?","options":["Onu geçemezsiniz; beyaz çizgi her zaman kendi şeridinizde kalmanız gerektiği anlamına gelir","Geçiş yalnızca dönüş yapmak için izinlidir, çift sürekli sarı çizgiyi ele aldığınız gibi","Burada geçiş yalnızca çizgi karşı yönden gelen trafiği ayırdığı için izinlidir","Yol boş ve güvenli olduğunda onu geçerek şerit değiştirebilirsiniz"],"explanation":"A broken white line separates lanes going the same direction and permits a lane change when it is safe, so moving into the clear left lane is allowed. Option A describes a solid white line, and option B describes a double solid yellow line, so both apply the wrong marking's rule here."},"20":{"q":"Tüm şeritlerin aynı yönde aktığı dört şeritli bir otoyolda araç kullanıyorsunuz. Bir otoyol giriş rampasına yaklaşırken, tek bir kesintisiz beyaz çizgi şeridinizi sağınızdaki şeritten ayırıyor. Daha iyi bir konum almak için o şeride geçmek istiyorsunuz. Bu işaret size ne söyler?","options":["Şeridinizde kalın; kesintisiz beyaz çizgiyi geçmek önerilmez","Sağ şerit boş olduğunda istediğiniz zaman serbestçe geçebilirsiniz","Çift kesintisiz çizgi gibi, her iki yönde de geçiş yasaktır","Bu, yolun sağ kenarını işaretler, bu yüzden onu geçerek sürmeyin"],"explanation":"A solid white line separates lanes going the same direction and means stay in your lane, as crossing it is discouraged. A broken white line is what allows a free lane change (option B), and a solid white edge line marks the road's right edge (option D), so those facts are placed here in the wrong context."},"21":{"q":"Geceleyin, görüş mesafesinin düşük olduğu, tanımadığınız kırsal bir karayolunda araç kullanıyorsunuz. Sağ tarafınızda, gidiş yönünüze paralel olarak kaplama boyunca uzanan kesintisiz beyaz bir çizgi fark ediyorsunuz. Bu çizgi size ne anlatır?","options":["Yolun ortasını işaretler ve sollamak için onu geçmemeniz gerekir","Yolun sağ kenarını işaretler ve kaplamada kalmanıza yardımcı olur","Tek yönlü bir yolda yolun sol kenarını işaretler","İçinde araç kullanmamanız gereken bir bisiklet şeridini gösterir"],"explanation":"A solid white edge line marks the right edge of the road, which is especially useful for staying on the pavement at night or in poor visibility. The trap in C confuses edge colors: a yellow line marks the left edge, while white marks the right edge."},"22":{"q":"Gece tanımadığınız iki yönlü bir yolda araç kullanıyorsunuz. Farlarınız, şeridinizin en sol tarafında, tam kaldırımın sınırında uzanan düz sarı bir çizgiyi aydınlatıyor. Bu çizgi size ne anlatıyor?","options":["Yolun sağ kenarını işaretler, yani kaldırım hemen solunuzda biter","Geçiş yasağı çizgisidir, bu yüzden sollamak için yolun ortasını geçmemelisiniz","Yolun sol kenarını işaretler, yani solunuzda kaldırımın nerede bittiğini gösterir","Sizinle aynı yönde ilerleyen trafik şeritlerini ayırır"],"explanation":"A yellow edge line marks the left edge of the roadway, showing the driver where the pavement ends on the left side. The line being yellow does not make it a center no-passing line, and the right edge of the road is marked with a solid white line, not yellow."},"23":{"q":"Kırmızı ışıkta bir kavşağa yaklaşıyorsunuz. Yaya geçidinden önce, şeridinizin karşısına çizilmiş geniş beyaz bir çizgi fark ediyorsunuz. Aracınızı tam olarak nerede durdurmalısınız?","options":["Tamponunuz çizgiyle hizalanacak şekilde geniş beyaz çizginin üzerinde","Geniş beyaz çizgiyi biraz geçerek ama yaya geçidine girmeden önce","Yeşil ışıktan önce tamamen durduğunuz sürece kavşağın herhangi bir yerinde","Nerede duracağınızı gösteren durma çizgisi olan geniş beyaz çizginin arkasında"],"explanation":"The wide white line is a stop line, and you must stop behind it, not on or beyond it. Stopping on the line or past it into the crosswalk blocks pedestrians and is incorrect even though you are technically stopped."},"24":{"q":"Yeşil ışıkta bir kavşağa yaklaşırken, yola çizilmiş beyaz işaretler ve üzerine adım atan bir yaya görüyorsunuz. Nerede durmalısınız?","options":["Yayanın geçmesi için beyaz yaya geçidi işaretlerinin önünde","Yayaya yer bıraktığınız sürece yaya geçidi işaretlerinin üzerinde","İstediğiniz yerde, çünkü yeşil ışık her zaman geçiş üstünlüğünüz olduğu anlamına gelir","Şeride çizilmiş elmas sembolünün arkasında"],"explanation":"A crosswalk is marked by white lines for pedestrians, and you must stop before it to let them cross safely. Stopping on top of it blocks the pedestrian, and a green light still requires yielding to people already in the crosswalk; the diamond symbol marks an HOV/carpool lane, not a stopping point."},"25":{"q":"Yoğun saatlerde bir Teksas otoyolunda tek başınıza araç kullanıyorsunuz. En soldaki şerit, kaldırıma düzenli aralıklarla boyanmış büyük elmas sembolleri içeriyor. Bu işaret size o şerit hakkında ne söyler?","options":["Bisiklet şerididir, bu yüzden içinde araç sürmemeli veya park etmemelisiniz","Tek başınıza kullanmanıza izin verilmeyebilecek, ayrılmış bir HOV/araç paylaşımı veya özel kullanım şerididir","Üstteki kırmızı X sinyaliyle aynı şekilde tüm trafiğe kapalıdır","Bir kenar şerididir ve elmaslar yol yüzeyinin nerede bittiğini gösterir"],"explanation":"A diamond symbol painted in a lane marks a reserved HOV/carpool or special-use lane, which often requires a minimum number of occupants, so driving alone may not be permitted. A bike lane is marked differently, and a closed lane is shown by an overhead red X, not pavement diamonds."},"26":{"q":"Geç kaldınız ve normal trafik şeridinin sağında boş bir asfalt bölümü görüyorsunuz. Düz beyaz bir çizgiyle ayrılmış ve üzerinde boyalı bir bisiklet sembolü var, ancak şu anda içinde hiç bisikletli yok. Ne yapmalısınız?","options":["Şu anda boş olduğu için yavaş trafiği geçmek üzere içinde sürün","İçine girip trafik açılana kadar park edin","Tamamen dışında kalın; burası bisikletlere ayrılmış bir bisiklet şeridi, sürmek veya park etmek için değil","Araçta yolcularınız olduğu için onu paylaşımlı araç şeridi olarak kullanın"],"explanation":"A lane marked with a bicycle symbol is a bike lane reserved for bicycles, and you must not drive or park in it even when no cyclists are present. Options A and B are the trap (driving and parking are both prohibited), and D confuses the bike lane with an HOV/carpool lane, which is marked with a diamond symbol instead."},"27":{"q":"Geç kaldınız ve aracınızı birkaç dakikalığına bırakmanız gerekiyor. Tek boş yer, yakınında hiçbir levha bulunmayan, düz sarıya boyanmış bir bordür boyunca. Bu sarı bordür, orada park etmek konusunda size ne söyler?","options":["Park etmek sorun değil çünkü bunu kısıtlayan bir levha yok","Yolun sol kenarını işaretler, bu yüzden sağında park etmeye izin verilir","Yalnızca HOV veya araç paylaşımı (carpool) araçlarına ayrılmıştır","Park etme yasağını veya yükleme kısıtlamasını gösterir, bu yüzden oraya park etmemelisiniz"],"explanation":"A yellow curb signals a no-parking or loading restriction even when no sign is present, though exact meanings can vary by city, so you should not leave your car there. The left-edge yellow line refers to roadway center markings, not curbs, and HOV reservations are shown by a diamond symbol in a lane, not by a painted curb."},"28":{"q":"Tanımadığınız bir yolda ilerliyorsunuz ve önünüzdeki yol yüzeyinde büyük bir \"RXR\" sembolü ve ardından şeridinizin karşısında geniş bir beyaz çizgi görüyorsunuz. Bariyerler hâlâ açık, ancak bir tren kornası duyuyor ve yaklaşan bir tren görüyorsunuz. Ne yapmalısınız?","options":["Beyaz çizginin arkasında durup beklemelisiniz, çünkü RXR bir demiryolu geçidini işaret eder ve bir tren yaklaşırken durmanız gerekir","Bariyerler hâlâ açık olduğu ve tren geçilebileceği için beyaz çizgiyi isteğe bağlı sayıp yavaşça geçmelisiniz","Yalnızca çizgi sarı olsaydı durmalısınız, çünkü sizin tarafınızdaki sarı çizgi sollama yapılamayacağı anlamına gelir","Elmas sembolü geçen trafik için özel kullanım şeridi anlamına geldiğinden durmadan devam etmelisiniz"],"explanation":"The large RXR painted on the pavement marks a railroad crossing, and the wide white line is a stop line; you must stop behind it when a train is approaching. The traps misuse other real facts: a solid yellow line means no passing, and a diamond marks an HOV/special-use lane, neither of which applies at a railroad crossing."},"29":{"q":"Bir kavşakta sola dönmek için beklerken ışığınız sabit yeşile döndü. Karşı yönden yaklaşan bir araç var ve kavşağa yakın. Ne yapmalısınız?","options":["Sabit yeşil ışık size karşı trafikten önce ilerleme hakkı verdiği için hemen sola dönün.","Karşıdan gelen araca yol verin, ardından güvenli olduğunda sola dönüşünüzü tamamlayın.","Yeşil ok bekleyin, çünkü sabit yeşil ışık sola dönüşe izin vermez.","Çizginin arkasında tam olarak durun ve sabit yeşil önce durmayı gerektirdiği için yalnızca karşıdan gelen araç geçtikten sonra ilerleyin."],"explanation":"At a steady green light you may proceed or turn, but you must first yield to oncoming traffic and pedestrians rather than turn without regard to other vehicles. A green arrow gives a protected turn and a stop is required only at red or yellow, so options C and D misapply other signal rules."},"30":{"q":"Belirlenen hız sınırında bir kavşağa yaklaşırken ışık yeşilden sabit sarıya döner. Önünüzde çizginin önünde güvenle durmak için yeterli mesafe var. Ne yapmalısınız?","options":["Işık kırmızıya dönmeden önce kavşağı geçmek için hızlanın","Yalnızca bir levha söylüyorsa durun, aksi halde sarıda hızınızı koruyarak geçin","Yavaşlayın ve çizginin arkasında güvenle durun, çünkü sarı kırmızının geleceğini uyarır","Sarıyı yanıp sönen sarı gibi kabul edip durmadan dikkatle geçin"],"explanation":"A steady yellow means the light is about to turn red, so you should stop if you can do so safely rather than speed up to beat the light. Accelerating through (A) is the exact mistake the yellow warns against, and a flashing yellow (D) is a different signal that means caution and does not require stopping."},"31":{"q":"Gece geç saatte bir kavşağa yaklaşırken trafik sinyali sizin yönünüzde yanıp sönen sarı ışığa geçiyor. Görünürde karşıdan gelen trafik yok. Ne yapmalısınız?","options":["Durma çizgisinin arkasında tamamen durun, ardından kavşak boş olduğunda geçin","Tamamen durun, bunu her yönden duraklı bir kavşak olarak kabul edin ve sağınızdaki herhangi bir araca yol verin","Işık kırmızıya dönmeden önce kavşağı geçmek için hızlanın","Yavaşlayın ve durmadan dikkatlice kavşaktan geçin"],"explanation":"A flashing yellow light means caution: you slow down and proceed carefully without needing to stop. A full stop is required at a flashing red (which is treated like a stop sign), so options requiring a complete stop confuse the flashing red rule with the flashing yellow."},"32":{"q":"Alacakaranlıkta tanımadığınız iki şeritli bir yolda araç kullanıyorsunuz. Yolun ortasındaki, sizin şeridinizi yanındaki şeritten ayıran çizgi sarı. Bu renk, o çizginin diğer tarafındaki şeritteki trafik hakkında size ne söyler?","options":["Trafik ters yönde, size doğru hareket etmektedir","Trafik sizinle aynı yönde hareket etmektedir","HOV veya carpool (ortak araç) kullanımına ayrılmış bir şerittir","Yolun sağ kenarıdır"],"explanation":"Yellow center lines separate traffic moving in opposite directions, so the lane across a yellow line carries oncoming traffic. White lines, not yellow, separate traffic moving in the same direction, which makes B the trap."},"33":{"q":"Yaya geçidine yürüyerek geliyorsunuz ve karşıya geçmek istiyorsunuz. Kaldırım kenarına ulaştığınızda yaya sinyali yanıp sönen DON'T WALK / kalkık ele dönüşüyor. Bu sizin için ne anlama gelir?","options":["Şimdi geçmeye başlamayın, ancak zaten geçitteyseniz geldiğiniz kaldırıma geri dönmelisiniz","Şimdi geçmeye başlamayın; yalnızca zaten geçitte olanlar devam edip geçişi tamamlamalıdır","Geçmeye başlayabilirsiniz çünkü yanıp sönme, yanıp sönen sarı sinyal gibi dikkat anlamına gelir","Dikkatlice geçmeye başlayabilirsiniz, ancak önce geçidin kenarında durduktan sonra"],"explanation":"A flashing DON'T WALK warns pedestrians not to begin crossing; those already in the crosswalk should finish crossing. Option C wrongly borrows the flashing-yellow 'caution, proceed' meaning, and A invents a rule about turning back that the handbook does not state."},"34":{"q":"Kırmızı ışıkta durmuş, sağa dönmek istiyorsunuz. Kavşakta 'KIRMIZIDA DÖNÜŞ YOK' (NO TURN ON RED) yazan bir tabela görüyorsunuz. Tamamen durduktan ve karşıdan gelen ile yan trafiğin boş olduğunu gördükten sonra ne yapmalısınız?","options":["Sağa dön, çünkü tam duruş kırmızıda sağa dönüş için yasal şartı yerine getirir","Şerit boş olduğu ve usulüne uygun yol verdiğin için yavaşça sağa dön","Durmaya devam et ve sağa dönmeden önce yeşil ışığı bekle","Kırmızı ışığı yanıp sönen kırmızı gibi kabul et ve trafik boşalınca geç"],"explanation":"When a posted sign prohibits turning right on red, you may not turn regardless of stopping or a clear path, so you must wait for the green light. Stopping fully only permits a right on red when no sign forbids it, and a steady red is never treated like a flashing red."},"35":{"q":"Texas sürücü belgesi bilgi sınavına hazırlanıyorsunuz ve internette okuduğunuz belirli bir yol işareti kuralının gerçekten doğru olduğundan ve şu anda Texas'ta uygulandığından emin olmak istiyorsunuz. Resmi kuralların gerçekte ne olduğunu doğrulamak için hangi kaynağa güvenmelisiniz?","options":["Birçok eyaletin kurallarını özetledikleri için çevrimiçi sürücü sınavı sitelerinin çoğunun üzerinde anlaştığı şey","Yalnızca federal MUTCD, çünkü ulusal standartlar Texas'a özgü tüm rehberliğin yerini tamamen alır","Komşu bir eyaletin sürücü el kitabı, çünkü yol işaretleri tüm ABD eyaletlerinde aynıdır","Texas'ta geçerli olan MUTCD ulusal standartları ile birlikte Texas Sürücü El Kitabı (DPS, DL-7)"],"explanation":"The authoritative source of truth is the Texas Driver Handbook (DPS, DL-7) combined with the MUTCD national standards that apply in Texas. The MUTCD alone is not enough because it works together with the state handbook, and quiz sites or another state's handbook are not official Texas sources."},"36":{"q":"İki şeritli bir yolda gidiyorsunuz ve yolun ortasında çift düz sarı çizgi var. Önünüzde yavaş bir traktör var ve hemen ardında, sola dönüp park alanına girmeniz gereken girişi görüyorsunuz. Bu çift düz sarı çizgiyle yasal olarak ne yapabilirsiniz?","options":["Park alanına sola dönmek için çizgiyi geçebilirsiniz, ancak traktörü geçmek için geçemezsiniz","İleride şerit boş olduğundan, traktörü geçmek için çizgiyi geçebilirsiniz","Çift sarı çizgi yalnızca karşıdan gelen trafiği ilgilendirdiği için çizgiyi serbestçe geçebilirsiniz","Onu kesik sarı çizgi gibi kabul edip güvenli olduğunda öne geçebilirsiniz"],"explanation":"A double solid yellow line means no passing in either direction; you may cross it only to make a turn, such as turning left into a driveway or parking lot. Passing the tractor (B and D) is prohibited, and the line applies to drivers on both sides, not just oncoming traffic (C)."},"37":{"q":"Yola çizilmiş büyük bir RXR sembolü ve geniş beyaz bir durma çizgisiyle işaretlenmiş bir demiryolu geçidine yaklaşıyorsunuz. Yanıp sönen ışık veya bariyer yok, görünürde tren yok ve hiçbirinin yaklaşmadığını net bir şekilde görüp duyabiliyorsunuz. Ne yapmalısınız?","options":["Durma çizgisinde tamamen durup bekleyin, çünkü her demiryolu geçidi tam duruş gerektirir","Durmadan rayların üzerinden geçin, ancak bir tren yaklaşırsa işaretli durma çizgisinde durmaya hazır olun","Yavaşlayın ve geçidi tüm yönlere durma işaretli bir kavşak gibi değerlendirip önce sağınızdaki trafiğe yol verin","Geçmeye devam etmeden önce her iki yöne bakmak için kısa süreliğine rayların üzerinde durun"],"explanation":"At this type of railroad crossing you stop only if a train is approaching, and the stop must be made at the marked stop line; with no train coming you may proceed across without stopping. Option A is wrong because a stop is not required at every crossing when no train is near, and stopping on the tracks (D) is always dangerous."},"38":{"q":"Çok şeritli bir otoyolda giderken, tam şeridinizin üzerindeki tepe sinyalinin yeşil aşağı oktan sabit sarı X'e döndüğünü fark ediyorsunuz. Bu ne anlama gelir ve ne yapmalısınız?","options":["Şeridiniz artık yalnızca duran trafik için kapalıdır; şerit içinde tamamen durun ve bekleyin.","Bu, yanıp sönen sarı ışık gibi bir uyarı sinyalidir; yavaşlayın ancak mevcut şeridinizde kalın.","Şeridinizin kullanımı değişiyor; bu şeritten güvenli bir şekilde, yeşil aşağı okla işaretli açık bir şeride geçin.","İleride yayalar geçiyor; sinyal değişene kadar şeridinizde kalın ve yol verin."],"explanation":"A yellow X overhead lane-control signal means the lane is changing use and you should move out of it safely, while a green down-arrow marks a lane that is open. The caution answer confuses this with a flashing yellow traffic light, which applies to intersections, not overhead lane control."},"39":{"q":"Bir kavşakta sola dönüş şeridinde bekliyorsunuz. Önünüzdeki sinyal, düz giden şeritler için sabit kırmızı ışıkla birlikte sabit yeşil SOL ok gösteriyor. Karşıdan gelen trafiğe yol vermeden sola dönüşe neden başlayabilirsiniz?","options":["Çünkü yeşil ok önce tam durmanız, sonra yalnızca yol açıksa dönmeniz gerektiği anlamına gelir","Çünkü yeşil ok yalnızca uyarı verir, bu yüzden yavaşlayıp dönmeden önce karşıdan gelen araçlara yol vermelisiniz","Çünkü karşıdan gelen trafikte yanıp sönen sarı ışık vardır ve onlara kavşaktan dikkatlice geçmelerini söyler","Çünkü yeşil ok korumalı dönüş sağlar: karşıdan gelen trafik kırmızı ışıkla karşı karşıyadır ve ok yandığı sürece durmuştur"],"explanation":"A green arrow grants a protected turn in the arrow's direction because oncoming traffic faces a red signal and is stopped, so you may turn without yielding. A green arrow is not a stop-and-go or caution signal, and oncoming drivers are stopped by red, not waved through by a flashing yellow."}},"learn-signals-and-markings":{"0":{"q":"Sabit yeşil trafik ışığı ne anlama gelir?","options":["Kavşak boşsa geçin","Çizginin arkasında tamamen durun","Yavaşlayın ve güvenliyse durun","Onu dur işareti olarak kabul edin"],"explanation":"A steady green light means you may go if the intersection is clear, proceeding straight or turning after yielding."},"1":{"q":"Sabit yeşil ışıkta dönüş yapmadan önce ne yapmalısınız?","options":["Dönüşü tamamlamak için hızlanmak","Diğer araçlara ve yayalara yol vermek","Önce her zaman tamamen durmak","Yeşil okun yanmasını beklemek"],"explanation":"At a steady green light you may turn only after yielding to other traffic and pedestrians."},"2":{"q":"Sabit sarı trafik ışığı ne anlama gelir?","options":["Kavşağı geçmek için hızlanın","Işık az önce yeşile döndü","Işık kırmızıya dönmek üzere","Geçiş hakkı sizindir"],"explanation":"A steady yellow light warns that the signal is about to turn red, so stop if you can do so safely."},"3":{"q":"Sabit sarı trafik ışığında ne yapmalısınız?","options":["Kırmızıya yetişmek için hızlanın","Her zaman tamamen durun","Görmezden gelip sürmeye devam edin","Güvenli bir şekilde durabiliyorsanız durun"],"explanation":"A steady yellow light means the light is about to turn red, so stop if you can do so safely and do not speed up."},"4":{"q":"Sabit kırmızı ışık ne anlama gelir?","options":["Yeşil yanana kadar tamamen durun","Yavaşlayın ve dikkatle ilerleyin","Kavşağı boşaltmak için hızlanın","Kavşak boşsa geçin"],"explanation":"A steady red light means stop completely behind the line and stay stopped until the light turns green."},"5":{"q":"Sağa dönüşe izin verilen kırmızı ışıkta önce ne yapmalısınız?","options":["Hızlanıp sağa dönün","Tamamen durun, yol açıksa dönün","Durmadan dönün","Yeşil ok bekleyin"],"explanation":"At a red light where right turns are permitted, you must stop completely, then turn right if it is clear and not prohibited by a sign."},"6":{"q":"Yanıp sönen kırmızı ışıkta ne yapmalısınız?","options":["Hızlanıp geçmek","Yavaşlayıp devam etmek","Tamamen durmak, sonra güvenliyse geçmek","Yakında araç yoksa görmezden gelmek"],"explanation":"A flashing red light means the same as a stop sign: stop fully, then go when it is safe."},"7":{"q":"Yanıp sönen sarı trafik ışığı ne anlama gelir?","options":["Tamamen durun, sonra geçin","Işık birazdan kırmızıya dönecek","İleride şerit kapalı","Dikkat: yavaşlayın ve dikkatlice geçin"],"explanation":"A flashing yellow light means caution, so slow down and proceed carefully without stopping."},"8":{"q":"Yeşil ok işareti ne anlama gelir?","options":["Okun gösterdiği yönde korumalı dönüş","Dur ve bir sonraki ışığı bekle","Yavaşla ve karşıdan gelen trafiğe yol ver","O yönde dönüş yapılamaz"],"explanation":"A green arrow means a protected turn in the arrow's direction, and oncoming traffic is stopped."},"9":{"q":"Kırmızı ok işareti ne anlama gelir?","options":["Yol açıksa şimdi dön","O yöne dönüş yok; bekleyin","Hızlı dönmek için hızlanın","Sadece kamyonlar için dönüş"],"explanation":"A red arrow means no turn is allowed in that direction, so you must wait."},"10":{"q":"Sönük veya çalışmayan bir trafik ışığında nasıl davranmalısınız?","options":["Hızlanarak geçin","Yeşil ışık gibi kabul edin","Tüm yönlerin durduğu bir dur işareti gibi kabul edin","Kavşağı görmezden gelin"],"explanation":"A dark or non-working signal should be treated as an all-way stop."},"11":{"q":"WALK (Yürü) sinyali ne anlama gelir?","options":["Arabalar hızlanmalı","Bisikletler durmalı","Sürücüler sola dönebilir","Yayalar geçebilir"],"explanation":"A WALK signal or walking-person symbol means pedestrians may cross."},"12":{"q":"Sabit DON'T WALK (Geçme) işareti veya sabit kaldırılmış el sembolü ne anlama gelir?","options":["Karşıdan karşıya geçmeye başlamayın","Şimdi geçmeye başlayın","Sadece koşarak geçin","Aracınızı durdurun"],"explanation":"A steady DON'T WALK signal or steady raised-hand symbol means pedestrians should not start to cross."},"13":{"q":"Yanıp sönen \"GEÇMEYİN\" veya kaldırılmış el işareti ne anlama gelir?","options":["Hemen karşıya geçmeye başlayın","Başladıysanız geçişi tamamlayın, ama başlamayın","Caddeden hızlıca koşarak geçin","Sadece bir araba el sallayınca geçin"],"explanation":"A flashing DON'T WALK means finish crossing if you have already started, but do not begin to cross."},"14":{"q":"Şerit kullanım sinyalinde yeşil aşağı ok ne anlama gelir?","options":["Şerit kapalıdır","Şeritten çıkın","Şerit açıktır","Yavaşlayın ve durun"],"explanation":"A green down-arrow on a lane-use signal means the lane is open."},"15":{"q":"Şerit kullanım sinyalinde kırmızı X ne anlama gelir?","options":["Şerit açıktır","Şeritte yavaşlayın","Yakında şeritten çıkın","Şerit kapalıdır"],"explanation":"A red X on a lane-use signal means the lane is closed."},"16":{"q":"Şerit kullanım sinyalinde, şeridinizin üzerindeki sarı X ne anlama gelir?","options":["Şerit kullanımı değişiyor, şeritten çıkın","Şerit açık, kullanabilirsiniz","Şerit kapalı, asla kullanmayın","Durun ve şeritte bekleyin"],"explanation":"A yellow X means the lane is changing use, so you should move out of it."},"17":{"q":"Yolun sizin tarafınızdaki düz sarı çizgi ne anlama gelir?","options":["Geçiş yapmaya izin verilir","Geçiş yasaktır","Şerit kapalıdır","İlerde dur"],"explanation":"A solid yellow line on your side of the road means you may not pass."},"18":{"q":"Kesik (kesikli) sarı çizgi ne anlama gelir?","options":["Geçiş yasaktır","Dur ve bekle","Güvenli olduğunda geçiş yapılabilir","Şerit kapalıdır"],"explanation":"A broken (dashed) yellow line means passing is allowed when it is safe to do so."},"19":{"q":"Çift düz sarı çizgi ne anlama gelir?","options":["Her iki yönde geçiş serbesttir","Şeritler aynı yöne gider","Yol açıkken geçebilirsiniz","Her iki yönde de geçiş yasaktır"],"explanation":"A double solid yellow line means no passing in either direction; do not cross it except to turn."},"20":{"q":"Yoldaki beyaz çizgiler neyi ayırır?","options":["Aynı yöne giden şeritleri","Ters yöne giden şeritleri","Park yerlerini","Sadece bisiklet şeritlerini"],"explanation":"White lines separate lanes of traffic traveling in the same direction."},"21":{"q":"Kesik beyaz çizgi ne anlama gelir?","options":["Geçiş yapmak yasaktır","Şerit değiştirmeye izin verilir","İleride yol kenarı var","Burada durun ve bekleyin"],"explanation":"A broken white line means you may change lanes when it is safe."},"22":{"q":"Düz beyaz çizgi ne anlama gelir?","options":["Diğer araçları geçebilirsiniz","Şerit değiştirmeye izin verilir","Kendi şeridinizde kalın","Trafik ters yönde akar"],"explanation":"A solid white line means stay in your lane; crossing it is discouraged."},"23":{"q":"Yoldaki sarı çizgiler neyi ayırır?","options":["Aynı yönde giden trafiği","Bisiklet yollarını araç şeritlerinden","Park yerlerini","Zıt yönlerde giden trafiği"],"explanation":"Yellow lines separate traffic moving in opposite directions, while white lines separate traffic moving in the same direction."},"24":{"q":"Düz beyaz kenar çizgisi neyi belirtir?","options":["Yolun sağ kenarını","Yolun sol kenarını","Yolun ortasını","Geçiş bölgesini"],"explanation":"A solid white edge line marks the right edge of the road."},"25":{"q":"Yol uzerindeki sari kenar cizgisi neyi gosterir?","options":["Yolun sag kenarini","Yolun sol kenarini","Bisiklet seridinin ortasini","Yaya gecidini"],"explanation":"A yellow edge line marks the left edge of the road."},"26":{"q":"Durma çizgisi nedir?","options":["Yayaların yürümesi için bir çizgi","Bisiklet şeridini gösteren bir çizgi","Nerede duracağınızı gösteren geniş beyaz çizgi","İki yönlü trafiği ayıran bir çizgi"],"explanation":"A stop line is a wide white line that shows where to stop, and you must stop behind it."},"27":{"q":"Beyaz çizgilerle işaretlenmiş bir yaya geçidi ne anlama gelir?","options":["Yolun kenarını gösterir","Bir paylaşımlı araç şerididir","Trafiğe kapalıdır","Yayalar içindir; ondan önce durun"],"explanation":"A crosswalk has white markings for pedestrians, and you must stop before it."},"28":{"q":"Bir şeride boyanmış elmas sembolü ne anlama gelir?","options":["Ayrılmış HOV veya araç paylaşım şeridi","Sadece kamyonlar için şerit","İleride bisiklet şeridi","Şerit kapalı"],"explanation":"A diamond symbol marks a reserved HOV, carpool, or special-use lane."},"29":{"q":"Bisiklet şeridi ne için işaretlenmiştir?","options":["Araç park etmek için","Bisikletler için","Sola dönmek için","Acil durum araçları için"],"explanation":"A bike lane is marked for bicycles, and you should not drive or park in it."},"30":{"q":"Sarı bir kaldırım kenarı genellikle ne anlama gelir?","options":["Her zaman ücretsiz park","Engelliye ayrılmış park","Park yasağı veya yükleme kısıtlaması","Sadece otobüs durağı"],"explanation":"A yellow curb indicates a no-parking or loading restriction, though curb colors vary by city."},"31":{"q":"Hangi yol işareti demiryolu geçidini uyarır?","options":["Elmas sembolü","Çift sarı çizgi","Beyaz yaya geçidi","Büyük RXR harfleri"],"explanation":"A railroad crossing is marked on the pavement with a large RXR and a stop line."},"32":{"q":"Sabit sarı trafik ışığında ne yapmalısınız?","options":["Güvenli bir şekilde yapabiliyorsanız durun","Işığı geçmek için hızlanın","Her zaman tamamen durun","Tam durun, sonra geçin"],"explanation":"A steady yellow light means the light is about to turn red, so stop if you can do so safely and do not speed up."},"33":{"q":"Sabit kırmızı ışıkta nerede durmalısınız?","options":["Çizginin üzerinde","Çizginin gerisinde","Çizgiyi geçerek","Yaya geçidinde"],"explanation":"At a steady red light you must stop behind the line, not on or beyond it."},"34":{"q":"Yeşil ok sinyali ne anlama gelir?","options":["Yavaşla ve tüm trafiğe yol ver","Dur ve dönmeden önce bekle","Okun yönünde korumalı dönüş","Dönüş yapılamaz"],"explanation":"A green arrow means a protected turn in the arrow's direction because oncoming traffic is stopped."},"35":{"q":"Yanıp sönen kırmızı ışıkta ne yapmalısınız?","options":["Geçmek için hızlanın","Yavaşlayıp dikkatle ilerleyin","Yok sayıp devam edin","Dur tabelası gibi tamamen durun"],"explanation":"A flashing red light means make a full stop and go when safe, just like a stop sign."},"36":{"q":"Kırmızı ışıkta, izin verilen sağa dönüş ne zaman yapılabilir?","options":["Yol açık olduğunda ve bunu yasaklayan bir işaret olmadığında","Durmadan her zaman","Yalnızca başka bir araç önce döndüğünde","Kırmızı ışıkta asla"],"explanation":"At a red light you may turn right only when the way is clear and no sign prohibits it."},"37":{"q":"Karşıdan karşıya geçerken YÜRÜMEYİN işareti yanıp sönmeye başlarsa ne yapmalısınız?","options":["Olduğunuz yerde durun","Karşıya geçmeyi tamamlayın","Kaldırıma geri dönün","Hızlıca koşarak geçin"],"explanation":"If the signal flashes while you are crossing, finish crossing rather than turn back."},"38":{"q":"Bir şerit üzerindeki kırmızı X ne anlama gelir?","options":["Şerit açıktır","Şeritten çıkmalısınız","Şerit kapalıdır","Yayalar geçebilir"],"explanation":"A red X means the lane is closed, while a yellow X means the lane is changing use and you must move out of it."},"39":{"q":"Kesik (kesintili) sarı orta çizgi ne anlama gelir?","options":["Sizin tarafınızda geçiş yasak","Her iki yönde de geçiş yasak","Şeritler aynı yöne gider","Güvenli olduğunda geçişe izin verilir"],"explanation":"A broken (dashed) yellow centerline means passing is allowed when it is safe."},"40":{"q":"Çift sarı sürekli çizgiyi ne zaman geçebilirsiniz?","options":["Sadece dönüş yapmak için","Sadece yavaş araçları geçmek için","Yol boş olduğunda her zaman","Sadece geceleri"],"explanation":"A double solid yellow line may be crossed only to make a turn."},"41":{"q":"Düz beyaz çizgide ne yapmalısınız?","options":["Diğer araçları geçin","Kendi şeridinizde kalın","U dönüşü yapın","Aracınızı park edin"],"explanation":"A solid white line means you should stay in your lane, as crossing it is discouraged."},"42":{"q":"Bir durma çizgisinde nerede durmalısınız?","options":["Çizginin üzerinde","Çizgiyi geçerek","Çizginin gerisinde","Yaya geçidinde"],"explanation":"A stop line shows where to stop, and you must stop behind it."},"43":{"q":"Yaya geçidi işaretleri hangi renktir?","options":["Kırmızı","Mavi","Yeşil","Beyaz"],"explanation":"Crosswalk markings are white and are for pedestrians."},"44":{"q":"Bir şeride çizilmiş elmas (eşkenar dörtgen) sembolü ne anlama gelir?","options":["Şerit, ortak araç kullanımı ve yüksek doluluklu araçlar (HOV) için ayrılmıştır","Şerit bir bisiklet şerididir","Şerit tüm trafiğe kapalıdır","Şerit yalnızca dönüş içindir"],"explanation":"A diamond symbol marks a lane reserved for carpools and high-occupancy (HOV) vehicles."},"45":{"q":"Bisiklet şeridinde ne yapabilirsiniz?","options":["İçinde araç kullanmak","Ne araç kullanmak ne de park etmek","İçine park etmek","Durup içinde beklemek"],"explanation":"You may not drive in a bike lane, and you may not park in a bike lane."},"46":{"q":"Yolun sizin tarafınızdaki düz sarı çizgi ne anlama gelir?","options":["Geçiş serbesttir","Şerit kapalıdır","Geçiş yasaktır","Dur ve bekle"],"explanation":"A solid yellow line on your side means no passing."},"47":{"q":"Teksas'ta hangi trafik işareti ve sinyal standartları geçerlidir?","options":["Sadece şehir kuralları","Sadece ilçe kuralları","Belirlenmiş standart yok","Ortak ulusal standartlar"],"explanation":"Texas follows the shared national MUTCD standards for signs and signals."},"48":{"q":"Sabit yeşil trafik ışığı ne anlama gelir?","options":["Yalnızca kavşak boşsa ilerleyin","Çizginin arkasında tamamen durun","Yavaşlayın ve durmaya hazırlanın","O yönde dönüş yapılamaz"],"explanation":"A steady green light means go, but only proceed if the intersection is clear."},"49":{"q":"Bir şeridin üzerindeki kırmızı X şerit kullanım işareti ne anlama gelir?","options":["Şerit açıktır","Şerit kapalıdır","Şerit dönüş içindir","Şerit park etmek içindir"],"explanation":"A red X means the lane is closed, while a green down-arrow means the lane is open."},"50":{"q":"Yolun sizin tarafınızdaki düz sarı çizgi ne anlama gelir?","options":["Geçiş yapmak serbesttir","Şerit kapalıdır","Geçiş yasaktır","Dur ve bekle"],"explanation":"A solid yellow line on your side means no passing, while a broken yellow line allows passing when safe."},"51":{"q":"Zıt yönlerde giden trafiği ayıran çizgilerin rengi nedir?","options":["Mavi","Yeşil","Beyaz","Sarı"],"explanation":"Yellow lines separate traffic moving in opposite directions and show passing rules."},"52":{"q":"Aynı yönde giden şeritleri ayıran çizgiler hangi renktir?","options":["Beyaz","Sarı","Kırmızı","Mavi"],"explanation":"White lines separate lanes of traffic traveling in the same direction."},"53":{"q":"Bir tren yaklaşırsa demir yolu geçidi (RXR) işaretinde ne yapmalısınız?","options":["Önce geçmek için hızlanın","Durma çizgisinde durun","Korna çalıp devam edin","Şerit değiştirin"],"explanation":"At a railroad crossing marked RXR with a stop line, you must stop if a train approaches."},"54":{"q":"Trafik ışığı tamamen sönükken veya çalışmıyorken kavşakta ne yapmalısınız?","options":["Hızlanıp çabucak geçin","Yavaşlamadan ilerleyin","Her yönden duraklı kavşak gibi davranın","Işık yanana kadar bekleyin"],"explanation":"A dark or non-working signal should be treated as an all-way stop."},"55":{"q":"Pedestrians için sabit kaldırılmış el (YÜRÜME) işareti ne anlama gelir?","options":["Daha hızlı geçin","Şimdi koşarak geçin","Geçmeye başlayın","Geçmeye başlamayın"],"explanation":"A steady raised-hand (DON'T WALK) signal means pedestrians should not start to cross."},"56":{"q":"Sarı bir kaldırım kenarı genellikle ne anlama gelir?","options":["Park yasağı veya yükleme kısıtlaması","Her zaman ücretsiz park","Sadece otobüslere ayrılmış","Beklemek için güvenli bir yer"],"explanation":"A yellow curb generally indicates a no-parking or loading restriction, though curb colors can vary by city."},"57":{"q":"Sabit kırmızı okta ne yapmalısınız?","options":["Okun yönünde dönün","Bekleyin; o yöne dönmeyin","Dönüşte hızlanın","Yol verip serbestçe dönün"],"explanation":"A red arrow means you cannot turn in that direction and must wait until the signal changes."},"58":{"q":"Yoldaki kesik beyaz çizgi ne yapmanıza izin verir?","options":["Karşıdan gelen aracı geçmek","Yolun ortasında durmak","Güvenli olduğunda şerit değiştirmek","Yol kenarına park etmek"],"explanation":"A broken white line allows you to change lanes when it is safe, while a solid white line means stay in your lane."},"59":{"q":"Bir durma çizgisi neye benzer?","options":["Yeşil kesik çizgi","Küçük noktalar dizisi","Çift sarı çizgi","Şeridi enine kesen geniş beyaz çizgi"],"explanation":"A stop line is a wide white line painted across the lane to show where to stop."}},"safe-driving":{"0":{"q":"Kuru bir otoyolda bir sedanı takip ediyorsunuz. Aracın arka tamponu yol kenarındaki bir tabelayı geçerken saymaya başlıyorsunuz; aynı tabelaya 2 saniyeden biraz kısa bir sürede ulaşıyorsunuz. Bu size ne anlatır ve ne yapmalısınız?","options":["Çok yakından takip ediyorsunuz; gaz pedalını bırakarak araları en az 3 saniyeye çıkarın.","Mesafeniz güvenli, çünkü kuru yolda önerilen asgari süre 2 saniyedir.","Mesafeniz iyi; üç saniye kuralı yalnızca yağmur, sis veya buzda geçerlidir.","Hemen sert fren yaparak geri çekilmelisiniz, çünkü kamyonun kör noktasındasınız."],"explanation":"The three-second rule says that if you reach the fixed point in less than 3 seconds after the car ahead, you are too close, so easing off the gas to restore a 3-second gap is correct. Two seconds is not the safe minimum, the 3-second rule applies in all conditions (you add more seconds for bad weather), and braking hard or worrying about a truck's No-Zone does not fit this car-following scenario."},"1":{"q":"Normalde önünüzdeki araçla aranızda 3 saniyelik bir boşluk bırakırsınız. Bu gece otoyolda şiddetli yağmur başlıyor ve yoğun bir sis çöküyor. Takip mesafenizle ilgili ne yapmalısınız?","options":["Aynı 3 saniyelik boşluğu koruyun, çünkü üç saniye kuralı zaten tüm sürüş koşullarını kapsar","Boşluğu 3 saniyeden fazlaya çıkarın, çünkü yağmur ve sis yol tutuşunu ve görüşü azaltır","Sisin içinden öndeki aracın stop lambalarını net görebilmek için boşluğu azaltın","Uzun farlarınızı açın ve fren ışıklarına daha hızlı tepki vermek için 2 saniyelik boşluk tutun"],"explanation":"The three-second rule is a minimum for good conditions; in rain, fog, ice, or at high speed you must add more seconds because traction and visibility are reduced. Shortening the gap or relying on high beams (which reflect back off fog) only increases your danger."},"2":{"q":"Teksas'ta bir otoyolda giderken bir kamyonet arkanıza iyice yaklaşıyor ve tamponunuzdan yalnızca birkaç metre uzakta kalarak açıkça sizi sıkıştırıyor. Aracınızın etrafındaki boşluğu yönetmenin en güvenli yolu nedir?","options":["Arkanızdakini uzaklaşması için uyarmak amacıyla frene birkaç kez hafifçe basın","Sizi sıkıştıran aracın daha geride kalması için hızlanın","Önünüzdeki araçla aranızdaki takip mesafesini artırın, böylece kademeli olarak fren yapmak için daha fazla alanınız olur","Öndeki araca tam üç saniye mesafede kalın, çünkü bu kural zaten her durumu kapsar"],"explanation":"When you are being tailgated, you should increase your following distance to the vehicle ahead so you can slow down or stop gradually instead of braking hard, giving the tailgater more time to react. Three seconds is only a minimum baseline and should be increased behind motorcycles, large trucks, and when tailgated, so option D is wrong, and brake-tapping or speeding up only raises the risk of a crash."},"3":{"q":"Çok şeritli bir otoyolda bir tır ile yan yana, kamyon şoförünün yan aynalarını göremediğiniz bir şekilde kabinin hemen arkasında ilerliyorsunuz. Bu konum size ne anlatır ve ne yapmalısınız?","options":["Kamyon şoförü sizi gayet iyi görüyor, bu yüzden sabit bir hız koruduğunuz sürece orada kalabilirsiniz","Römorka daha çok yaklaşmalısınız, çünkü en güvenli yer arka tekerleklerin hemen yanıdır","Geçmeden önce kamyon şoförünün orada olduğunuzu bilmesi için uzun farlarınızı çakmalısınız","Şoförün aynalarını göremediğiniz için tırın kör noktasındasınız (No-Zone), bu yüzden oradan çıkmak için hızlanın ya da geride kalın"],"explanation":"If you can't see a large truck's side mirrors, the driver can't see you, meaning you are sitting in a No-Zone blind spot; the safe response is to clear it quickly by speeding up to pass or easing back. Staying put, moving beside the rear wheels, or relying on high-beam flashes all leave you in the blind spot where the driver cannot see you."},"4":{"q":"Bir Texas otoyolunda araç kullanırken ileride arızalı bir araç fark ediyor ve aracınızı tamamen durduruyorsunuz. Geriye dönüp düşündüğünüzde, durmanın beklediğinizden daha uzun sürdüğünü fark ediyorsunuz. Tehlikenin ortaya çıktığı andan tamamen durana kadar aracınızın kat ettiği toplam mesafeyi oluşturan üç mesafe hangisidir?","options":["Algılama mesafesi + tepki mesafesi + frenleme mesafesi","Algılama mesafesi + tepki mesafesi + takip mesafesi","Tepki mesafesi + frenleme mesafesi + kızaklama (hidroplanlama) mesafesi","Takip mesafesi + frenleme mesafesi + far görüş mesafesi"],"explanation":"Total stopping distance is the sum of perception distance (seeing the hazard), reaction distance (moving your foot to the brake), and braking distance (the car slowing to a stop). Following distance, hydroplaning, and headlight sight distance are real safe-driving concepts but are not components of the stopping-distance formula."},"5":{"q":"Kuru bir otoyolda önünüzde aniden bir geyik yola çıkıyor. Gözleriniz geyiği fark ettiği andan, ayağınızın gerçekten frene basmaya başladığı ana kadar aracınız ileri doğru yuvarlanmaya devam eder. Ortalama bir sürücü için bu tepki süresi tipik olarak yaklaşık ne kadar sürer?","options":["Yaklaşık 1,5 saniye","Yaklaşık dörtte üç (¾) saniye","Yaklaşık 3 saniye","Yaklaşık 35 saniye"],"explanation":"The average driver's reaction time is about ¾ of a second, so the car keeps moving during that interval before braking begins. Option A (about 1.5 s) is the combined perception-plus-reaction time, and 3 seconds is the safe-following-distance rule, not reaction time."},"6":{"q":"Texas otoyolunda araç kullanırken, çok ileride aniden yola bir geyik çıkıyor. Aracınız yavaşlamaya başlamadan önce iki şey olmalıdır: gözleriniz ve beyniniz geyiği algılamalı, ardından ayağınızı frene götürmelisiniz. Frenler gerçekten devreye girmeden önce bu algılama-artı-tepki süreci toplamda yaklaşık ne kadar sürer?","options":["Yaklaşık 1.000 fit, geceleyin önünüzü görebilmeniz gereken mesafenin aynısı","Yaklaşık 3 saniye, çünkü her zaman korumanız gereken güvenli takip mesafesi budur","Toplamda yaklaşık 1,5 saniye, henüz herhangi bir fren mesafesi eklenmeden önce","Yaklaşık 35 mph, ıslak yolda su kızağının (hidroplanlama) başlayabileceği hız"],"explanation":"The combined perception-plus-reaction time is roughly 1.5 seconds, and this happens before braking distance is even added to the total stopping distance. The 3-second answer confuses the separate three-second following-distance rule with reaction time, and the other options misplace unrelated facts (night visibility distance and hydroplaning speed)."},"7":{"q":"Kuru bir Teksas otoyolunda, frene bastıktan sonra 30 mil/saat hızdan durmak için normalde yaklaşık 45 fit fren mesafesine ihtiyacınız var. Trafik açılıyor ve hızınızı 30 mil/saatten 60 mil/saate çıkarıyorsunuz. Durmak için şimdi yaklaşık ne kadar fren mesafesine ihtiyacınız olmasını beklemelisiniz?","options":["Yaklaşık aynı 45 fit, çünkü fren mesafesi hızla pek değişmez","Yaklaşık 90 fit, çünkü hızı iki katına çıkarmak fren mesafesini iki katına çıkarır","Yaklaşık 68 fit, çünkü fren mesafesi yalnızca yaklaşık yarı oranında artar","Yaklaşık 180 fit, çünkü hızı iki katına çıkarmak fren mesafesini kabaca dört katına çıkarır"],"explanation":"Braking distance increases with the square of speed, so doubling speed from 30 to 60 mph roughly quadruples it (45 feet x 4 = about 180 feet). Option B is the common trap of assuming the relationship is simply linear (double speed = double distance)."},"8":{"q":"Saatte 30 mil hız sınırlı bir yerleşim caddesinden ayrılıp, hızınızı saatte 60 mile katladığınız bir otoyola katılıyorsunuz. Aniden önünüzdeki yola bir çocuk topu yuvarlanıyor. Saatte 30 milde durmaya kıyasla, daha yüksek hızınız durma yeteneğinizi nasıl değiştirir?","options":["Fren mesafeniz yaklaşık dört katına çıkar, bu yüzden durmak çok daha uzun mesafe alır ve olası bir kaza çok daha sert olur","Fren mesafeniz yaklaşık iki katına çıkar, hızınızdaki artışla aynı oranda","Durma mesafeniz yaklaşık aynı kalır çünkü tepki süreniz hâlâ yaklaşık dörtte üç saniyedir","Durma mesafeniz kısalır çünkü daha yüksek hız frenlere çalışması için daha fazla enerji verir"],"explanation":"Braking distance increases with the square of speed, so doubling your speed from 30 to 60 mph roughly quadruples the braking distance and a crash carries far more energy. Doubling speed does not merely double braking distance, and a faster speed never shortens stopping distance even though reaction time stays about three-quarters of a second."},"9":{"q":"Otoyolda sürekli yağmur yağıyor ve şeritte birikmiş su var. Yaklaşık 40 mil/saat hızla giderken direksiyonun hafiflediğini ve ön lastiklerin suyun üzerinde kayar gibi olduğunu hissediyorsunuz. Yol tutuşunu yeniden kazanmanın en güvenli yolu nedir?","options":["Lastikleri yavaşlatıp tekrar yola tutunmalarını sağlamak için sert şekilde fren yapmak","Gazdan ayağınızı çekmek, direksiyonu düz tutmak ve sert fren yapmamak","Aracın ön tarafının gitmesini istediğiniz yöne direksiyon kırmak ve frene aralıklı basmak","Uzun farları açmak ve takip mesafenize bir saniye eklemek"],"explanation":"You are hydroplaning, which can begin near 35 mph as water builds under the tires; easing off the gas, steering straight, and avoiding hard braking lets the tires settle back onto the road. Braking firmly (A) can lock the tires and worsen the slide, and steering/pumping advice (C) is the procedure for a skid, not hydroplaning."},"10":{"q":"Teksas otoyolunda şiddetli sağanak yağış altında saatte 45 mil hızla giderken aniden direksiyonun hafiflediğini ve aracın su üzerinde yüzer gibi kaymaya başladığını hissediyorsunuz. Ne yapmalısınız?","options":["Lastiklerin tekrar yola tutunması için fren pedalına sıkıca basıp bırakın","Aracın ön tarafının gitmesini istediğiniz yöne direksiyonu çevirin ve hafifçe fren yapın","Gazdan ayağınızı çekin, direksiyonu sabit ve dümdüz tutun ve sert frenden kaçının","Hemen sert fren yapın ve hızı düşürmek için küçük vitese geçin"],"explanation":"When hydroplaning, the tires lose contact with the road, so you should ease off the gas, hold the wheel straight, and avoid braking hard until traction returns. Braking hard (A, D) can cause a skid, and the steer-where-you-want technique (B) applies to correcting a skid, not recovering from hydroplaning."},"11":{"q":"Üç hafta yağmursuz geçtikten sonra, şehirde araç kullanırken hafif bir çiseleme başlıyor. Yol yüzeyi neredeyse ıslak görünüyor ve çevrenizdeki trafik normal hız sınırında ilerlemeye devam ediyor. Şu anda yol tutuşu konusunda neden özellikle dikkatli olmalısınız?","options":["Hafif yağmur yol tutuşunu azaltamaz, bu yüzden tek gerçek tehlike yolda su biriktiren şiddetli sağanaklardır","Bir yağmurun bu kadar erken aşamasında kayganlaşan tek yüzeyler köprüler ve üst geçitlerdir","Yol, yaklaşık 35 mil/saatte su kızağı başlatacak kadar su biriktiğinde en kaygan hale gelir","Kurak dönemde biriken yağ ve gres, ilk hafif yağmurla karışarak yolu şu anda en kaygan hale getirir"],"explanation":"The first rain after a dry spell is the most slippery because accumulated oil and grease mix with the water before being washed away, so a light early drizzle is more dangerous than it looks. Option C is a real fact about hydroplaning but describes a different hazard that needs water to build up, not the slick oily film of the first rain."},"12":{"q":"Açık bir sabahta hava donma noktasının hemen altında ve kırsal bir karayolunda araç kullanıyorsunuz. Önünüzdeki yol yüzeyi kuru görünüyor ve iyi bir yol tutuşu hissediyorsunuz. Bir dere üzerindeki köprüye yaklaşırken ne yapmalısınız?","options":["Gaza basmayı bırakıp köprüden önce yavaşlamalısınız, çünkü köprüler ve üst geçitler yolun geri kalanından önce buz tutar","Hızınızı koruyun, çünkü arkanızdaki kuru yol köprü yüzeyinin de güvenli olduğunu kanıtlar","Yüzeyin kaygan olup olmadığını test etmek için köprüye varır varmaz sert fren yapın","Köprüdeki buzu daha erken görebilmek için uzun farlara geçin"],"explanation":"Bridges and overpasses are exposed to cold air on all sides, so they freeze before regular pavement; easing off the gas and slowing down before the bridge is the safe response. Maintaining speed because the road behind feels dry ignores that the bridge can be icy even when the surrounding road is not, and braking hard on a possibly icy surface can cause a skid."},"13":{"q":"Açık, çok soğuk bir kış sabahı, yaklaşık -1°C. Otoyolda ilerliyorsunuz ve bir üst geçide yaklaşıyorsunuz. İlerideki yol biraz daha koyu ve ıslak görünüyor ama belirgin bir buz görmüyorsunuz. Bu durumu ele almanın en güvenli yolu nedir?","options":["Yol sadece ıslak görünüyor, bu yüzden hızınızı koruyun ve kaymaya başlarsanız sert fren yapın","Koyu, ıslak görünen kısmı olası buzlanma (siyah buz) olarak kabul edin; üst geçitten önce kademeli olarak yavaşlayın ve ani fren ya da direksiyon hareketinden kaçının","Islak zeminin daha fazla ışık yansıtması ve yüzeyi daha iyi görebilmeniz için uzun farlara geçin","Kaygan yüzeyde daha az zaman geçirmek için hızlanarak üst geçidi çabucak geçin"],"explanation":"Bridges and overpasses freeze first, and black ice is hard to see, so a dark, wet-looking patch in freezing temperatures should be treated as ice by slowing gradually and avoiding sudden braking or steering. Maintaining speed (A) assumes the surface is only wet, and speeding up (D) increases the risk of a skid you cannot control."},"14":{"q":"Texas'ta nemli bir otoyolda giderken aracınızın arkası aniden sağa kayıyor ve arka kısım savrulmaya başlıyor. Kontrolü yeniden sağlamak için ne yapmalısınız?","options":["Aracı hemen yavaşlatmak için frene sert basın, ardından direksiyonu düzeltin","Aracı ileri çekip kaymadan çıkarmak için gaza sabit basınç uygulamaya devam edin","Ayağınızı gazdan çekin ve aracın ön kısmının gitmesini istediğiniz yöne doğru direksiyonu çevirin, frene sert basmadan","Daha düşük bir vitese geçin ve tutuş geri gelene kadar fren pedalını tekrar tekrar pompalayın"],"explanation":"In a skid you should ease off the gas and steer in the direction you want the front of the car to go, never slamming the brakes, which would only worsen the loss of traction. Hard braking (A) and pumping the brake while downshifting (D) are recovery steps for other emergencies, not skids, and holding the gas (B) keeps the wheels spinning."},"15":{"q":"Gece kırsal bir karayolunda araç kullanırken aniden yoğun bir sis tabakasına giriyorsunuz ve önünüzdeki yolu güçlükle görebiliyorsunuz. Ne yapmalısınız?","options":["Uzun farları açın ki daha parlak ışık sisin içinden daha uzağa ulaşsın","Mevcut hızınızı koruyun ama görünür kalmak için dörtlü flaşörlerinizi açın","Yolun sağ kenarına doğru yönelin ve parlamadan gözlerinizi kaçırın","Kısa farlara geçin, hızınızı azaltın ve görüş çok kötüleşirse güvenli bir şekilde kenara çekin"],"explanation":"In fog or smoke you should use low beams because high beams reflect off the moisture and glare back at you, and you should slow down or pull off safely. High beams (A) make visibility worse, and looking to the right edge (C) is the response for oncoming headlight glare, not fog."},"16":{"q":"Açık bir öğleden sonra evinize doğru giderken şiddetli bir fırtına bastırıyor. Görüş mesafesi o kadar düşüyor ki, gün batımına daha çok varken bile yaklaşık 800 fit ileredeki bir yol levhasını zar zor seçebiliyorsunuz. Farlarınızla ilgili ne yapmalısınız?","options":["Farlarınızı açın, çünkü günün hangi saati olursa olsun yaklaşık 1.000 fit ileriyi göremediğiniz her durumda farları kullanmanız gerekir.","Farları kapalı tutun, çünkü farları kullanma kuralı yalnızca gün batımı ile gün doğumu arasında geçerlidir.","Yağmuru delip görüş mesafenizi artırmak için uzun farlarınızı açın.","Farları kapalı tutun ama yavaşlayın, çünkü farlar yalnızca yaklaşık 500 fit ileriyi göremediğinizde gereklidir."],"explanation":"Texas requires headlights from sunset to sunrise AND any time you cannot see about 1,000 feet ahead, so the reduced visibility means you must turn them on even in daylight. High beams reflect off rain and fog and make it harder to see, and 500 feet is the dimming distance for oncoming traffic, not the visibility threshold for using lights."},"17":{"q":"Geceleyin karanlık, iki şeritli bir kırsal yolda uzun farlarınız açık şekilde sürüyorsunuz. Karşı şeritte size yaklaşan bir aracı fark ediyorsunuz ve şu anda 500 fitten biraz daha yakın olduğunu tahmin ediyorsunuz. Ne yapmalısınız?","options":["Karşıdan gelen araç önce farlarını kısana kadar uzun farlarınızı açık tutun","Uzun farlarınızı şimdi kısa farlara düşürün","Yalnızca başka bir aracın 300 fit gerisindeyseniz kısa farlara geçin","Karşıdan gelen sürücüyü uyarmak için uzun farlarınızı çakın, sonra uzun farla devam edin"],"explanation":"Teksas, karşıdan gelen bir araca 500 fit mesafe içindeyken uzun farları kısaya düşürmenizi gerektirir, bu nedenle şimdi geçmelisiniz. Diğer sürücüyü beklemek (A) veya far çakmak (D) yolda göz alıcı parlamayı sürdürür ve 300 fit kuralı (C) karşıdan gelen trafiğe değil, bir aracın arkasından gitmeye uygulanır."},"18":{"q":"Gece, karanlık bir kırsal otoyolda uzun farlarınız açık şekilde gidiyorsunuz. Önünüzdeki daha yavaş bir araca yetişiyor ve aradaki mesafeyi yavaşça kapatarak yaklaşık 250 fit (75 metre) arkasına geliyorsunuz; karşıdan gelen trafik görünmüyor. Uzun farlarınızla ne yapmalısınız?","options":["Uzun farları açık tutun, çünkü kısmaya ilişkin kural yalnızca karşıdan gelen araçlar için geçerlidir","Önünüzdeki araca 100 fit kala kadar uzun farları açık bırakın, sonra kısa fara geçin","Şimdi kısa fara geçin, çünkü başka bir aracı takip ederken 300 fit içindeyken farları kısmanız gerekir","Uzun farları açık tutun ama parlamadan kaçınmak için yolun sağ kenarına bakın"],"explanation":"Texas law requires you to dim your high beams to low when within 300 feet behind another vehicle, so at 250 feet you must already be on low beams. The high beams glare in the lead driver's mirrors; the 500-foot rule (A) applies to oncoming traffic, and looking to the right edge (D) is the technique for when you are blinded, not for following."},"19":{"q":"Gece karanlık, iki şeritli bir otoyolda giderken karşıdan gelen bir araç uzun farlarını kısmıyor ve parlama yolun ilerisini görmenizi zorlaştırıyor. Araç geçene kadar kontrolü korumak için ne yapmalısınız?","options":["Diğer sürücünün ne kadar parlak olduğunu görüp farları kısması için kendi uzun farlarınızı açın","Hemen sert fren yapın ve gözleriniz toparlanana kadar şeridinizde durun","Diğer aracın tam olarak nerede olduğunu izleyebilmek için karşıdan gelen farlara doğrudan bakın","Yavaşlayın ve araç geçene kadar şeridinizin sağ kenarına doğru bakın"],"explanation":"When blinded by oncoming high beams, you should look toward the right edge of the road to avoid the glare while still guiding your car. Flashing your own high beams or staring into the lights only worsens the blindness, and stopping hard in a travel lane risks a rear-end collision."},"20":{"q":"Gece, kırsal bir karayolunda kısa farlarınız açık şekilde ilerliyorsunuz. Önünüzdeki yol yalnızca farlarınızın ulaştığı mesafe kadar aydınlanmış durumda ve o kadar hızlı gidiyorsunuz ki, aydınlık bölgeye aniden giren bir geyik, siz tepki verip frene basamadan durma mesafenizin içinde kalırdı. Hangi hatayı yapıyorsunuz?","options":["Farlarınızın önüne geçiyorsunuz; yani önünüzdeki aydınlık mesafe içinde duramayacak kadar hızlı gidiyorsunuz","Koşullara göre üç saniye kuralını yanlış uyguluyorsunuz","Karşıdan gelen bir araçın 500 fit yakınında uzun farlarınızı kısatmadınız","Hızınız bu zemin için güvenli sınırı aştığı için su üzerinde kayma (hidroplanaj) yaşıyorsunuz"],"explanation":"Overdriving your headlights means traveling so fast that you cannot stop within the distance your headlights illuminate ahead, which is exactly the scenario described. The three-second rule applies to spacing behind another vehicle, dimming high beams concerns glare to others, and hydroplaning involves water on the road—none fit a dry night road with a fixed lighted distance."},"21":{"q":"Uzun bir yokuştan inerken fren pedalına basıyorsunuz ve pedal neredeyse hiç direnç göstermeden tabana kadar iniyor. Araç hızlanmaya devam ediyor. Yavaşlamanın ve durmanın en iyi yolu nedir?","options":["Direksiyonu sıkıca tutun, gazdan ayağınızı çekin, sert fren yapmayın, sonra yavaşça kenara çekin","Fren pedalına pompalayın, daha düşük bir vitese geçin ve el frenini kademeli olarak çekin","Ayağınızı gazdan çekin ve aracın önünü gitmesini istediğiniz yöne doğru çevirin","El frenini bir anda sonuna kadar çekin ve hızı kesmek için motoru kapatın"],"explanation":"When the brakes fail, pumping the pedal may restore some pressure, shifting to a lower gear uses engine braking to slow you, and applying the parking brake gradually brings you to a stop. Option A is the correct response to a tire blowout, and pulling the parking brake all the way up at once (D) can cause a skid."},"22":{"q":"Bir Teksas otoyolunda saatte 60 mil hızla giderken yüksek bir patlama sesi duyuyorsunuz ve direksiyon aniden bir tarafa doğru sert şekilde çekiyor. Ön lastiğinizin patladığını fark ediyorsunuz. Kontrolü yeniden sağlamanın en güvenli yolu nedir?","options":["Araç daha fazla savrulmadan mümkün olduğunca hızlı durmak için hemen sert şekilde fren yapın","Çekişi dengelemek için direksiyonu ters tarafa ani çevirin, sonra sert frenle banketi alın","Direksiyonu sıkıca tutun, ayağınızı gazdan yavaşça çekin ve aracın kademeli olarak yavaşlamasına izin verdikten sonra yoldan çıkın","Fren pedalına basıp bırakarak pompalayın ve aracı yavaşlatmak için alt vitese geçin"],"explanation":"In a blowout you hold the wheel firmly, ease off the gas, and avoid braking hard, then pull off slowly once the car has slowed. Braking hard (A) or jerking the wheel (B) can cause a complete loss of control, and pumping the pedal with a lower gear (D) is the technique for brake failure, not a tire blowout."},"23":{"q":"Kırsal bir hemzemin geçitte demir yolu rayları üzerinden geçerken aracınızın motoru duruyor. Araç yeniden çalışmıyor ve uzakta bir trenin yaklaştığını görüyorsunuz. Ne yapmalısınız?","options":["Emniyet kemeriniz bağlı şekilde araçta kalıp aracı raylardan çıkarmak için fren pedalına hızlıca basın","Dörtlü flaşörlerinizi yakın ve tren geçene kadar araçta bekleyin","Küçük vitese geçip tren geçide ulaşmadan önce karşıya geçmeye çalışın","Herkesi araçtan çıkarın ve raylardan iyice uzaklaşın, ardından yardım çağırın"],"explanation":"If your vehicle stalls on railroad tracks, the only priority is getting everyone out and well away from the tracks before calling for help, because you can never safely beat an approaching train. Pumping the brake, waiting in the car, or trying to drive across all keep people in the path of the train."},"24":{"q":"Kırsal iki şeritli bir karayolunda motorunuz aniden güç kaybediyor ve yol kenarına kadar boşta kayarak gelmeyi başarıyorsunuz. Geniş bir asfalt banket mevcut. Yardım beklerken durmanın ve kendinizi korumanın doğru yolu nedir?","options":["Tamamen bankete çekin, dörtlü flaşörlerinizi açın ve aracınızın arkasına uyarı cihazları yerleştirin.","Diğer sürücüler sizi net görsün diye el frenini çekerek kendi şeridinizde durun ve farlarınızı açın.","Aracın arkasını şeritte bırakın, fren pedalına basıp basıp bırakın ve görünür kalmak için küçük vitese geçin.","Aracı yarısı bankette olacak şekilde park edin, dışarı çıkın ve şeritte durarak trafiği etrafınızdan geçmeye yönlendirin."],"explanation":"If you must stop on the road, pull fully onto the shoulder, turn on your hazard flashers, and use warning devices so approaching traffic is alerted. Stopping in the lane or leaving part of the car in traffic exposes you to a rear-end crash, and pumping the brake/shifting down is the procedure for brake failure, not a stopped breakdown."},"25":{"q":"Uzun bir yolculukta altı saattir araç kullanıyorsunuz ve sürekli esnediğinizi, aracın şerit çizgisine doğru kaydığını ve son birkaç kilometreyi hatırlamakta zorlandığınızı fark ediyorsunuz. Varış noktanıza hâlâ iki saat var. Ne yapmalısınız?","options":["Uyanık kalmak için camı açıp radyonun sesini açın, sonra varış noktanıza kadar sürmeye devam edin","Güvenli bir dinlenme tesisinde durup kestirin veya geceyi orada geçirin, çünkü uyku hâli tıpkı alkol gibi tepki sürenizi ve muhakemenizi yavaşlatır","Takip mesafenizi üç saniye kuralına çıkarın ve kalan iki saat boyunca sürmeye devam edin","Daha ileriyi görmek için uzun farları açın ve son iki saati zorlayarak tamamlayın"],"explanation":"Fatigue slows reaction time and impairs judgment much like drugs or alcohol, so the only safe choice is to stop and rest rather than drive drowsy. Tricks like fresh air, loud music, or a longer following distance do not cure drowsiness, and high beams have nothing to do with the danger of falling asleep at the wheel."},"26":{"q":"Teksas'ta kırmızı ışıkta durmuşken telefonunuza bir kısa mesaj geliyor. Işık hâlâ kırmızı ve trafik yoğun. Ne yapmalısınız?","options":["Duruyorken hemen şimdi hızlıca yanıt verin, çünkü ışık yeşile dönmeden önce halletmek en güvenli andır","Yazmadığınız sürece mesaj okumak serbest olduğu için sadece ekrana göz atıp okuyun","Telefona dokunmayın ve güvenli bir şekilde park edene kadar bekleyin, çünkü araç kullanırken mesajlaşmak Teksas'ta yasa dışıdır ve büyük bir dikkat dağıtıcıdır","Yanıt verin, ancak önce geçici olarak meşgul olduğunuzu sürücülere bildirmek için dörtlü flaşörlerinizi yakın"],"explanation":"Texting while driving is illegal in Texas and is a major distraction, so you should not text from behind the wheel even when stopped at a light; wait until you are safely parked. Reading or replying at a red light is still using the phone to text, and hazard flashers are for a disabled or stopped-on-the-road vehicle, not for excusing phone use."},"27":{"q":"Texas'ta iki arkadaşınızı bir maça götürüyorsunuz. Biri öne oturuyor, diğeri arka koltuğa geçiyor ve \"Kemeri takmayacağım, sadece on dakika arkada gideceğim\" diyor. Yola çıkmadan önce ne yapmalısınız?","options":["Arka koltuktaki yolcunun kemersiz gitmesine izin verin, çünkü emniyet kemeri kuralları sadece sürücü ve ön koltuk yolcuları için geçerlidir","Yolculuk kısa olduğu ve yavaş mahalle sokaklarında kalacağınız için buna izin verin","Kemersiz gitmek zorunda kalmaması için telefonunuzu ona verin ki başka bir araç için birine mesaj atsın","Yola çıkmadan önce kemerini bağlaması için ısrar edin, çünkü Texas yasası sürücünün ve tüm yolcuların emniyet kemeri takmasını zorunlu kılar"],"explanation":"Texas law requires a seat belt for the driver and every passenger, including those in the back seat, regardless of how short the trip is. Options A and B rely on common myths (rear seats are exempt, or short/slow trips don't count), and texting while driving is itself illegal and unsafe."},"28":{"q":"Kuru bir otoyolda bir kamyonetin arkasında gidiyorsunuz. Takip mesafenizi kontrol etmek için kamyonetin yoldaki bir üst geçit gölgesini geçmesini izliyor, sonra arabanızın ön kısmı aynı noktaya ulaşana kadar sayıyorsunuz. Takip mesafenizin yeterli sayılması için bu sayım ne kadar olmalıdır?","options":["Kamyonet noktayı geçtikten sonra üç saniye veya daha fazla","Kamyonet noktayı geçtikten sonra üç saniyeden az","Ortalama tepki süresine denk gelen yaklaşık dörtte üç saniye","Kamyonetin arkasında tam olarak 500 fit boşluk"],"explanation":"With the three-second rule, you pick a fixed point and count; reaching it in three seconds or more after the vehicle ahead means your following distance is adequate. Reaching it in less than three seconds means you are too close, while three-quarters of a second describes average reaction time and 500 feet is the high-beam dimming distance, not a following gap."},"29":{"q":"Kuru bir otoyolda bir kamyonetin arkasından gidiyorsunuz ve üç saniye kuralını kullanarak güvenli takip mesafesi koruyup korumadığınızı kontrol etmek istiyorsunuz. Kamyonetin arka tamponu önünüzdeki bir yol tabelasını henüz geçti. Kuralı doğru uygulamak için ne yapmalısınız?","options":["Kamyonet tabelayı geçtiğinde saymaya başlayın ve üç saniye sonra durun, ardından kamyonetin hâlâ o mesafe içinde olduğundan emin olun.","Kamyonetin arkası tabelayı geçtiğinde saymaya başlayın ve ön tamponunuz aynı tabelaya ulaştığında durun; üç saniyeden azsa çok yakın takip ediyorsunuz demektir.","Ön tamponunuzla kamyonetin arka tamponu arasında üç araç boyu mesafe ölçün.","Kamyonetin tabelayı geçtiği andan tamamen durana kadar geçen saniyeleri sayın."],"explanation":"The three-second rule works by picking a fixed point and counting the seconds between when the vehicle ahead passes it and when you pass the same point; under three seconds means you're following too closely. Fixed car-length spacing (C) and timing the lead vehicle's stop (D) are not how the rule works."},"30":{"q":"Açık bir otoyolda gidiyorsunuz ve önünüzde yola aniden bir geyik atlıyor. Onu görüyor, durmaya karar veriyor ve frene basıyorsunuz. Ayağınız fren pedalına bastıktan sonra aracınızın tamamen durana kadar kat etmeye devam ettiği mesafeye ne ad verilir?","options":["Toplam durma mesafesi, yani geyiği gördüğünüz andan aracın durduğu ana kadarki tüm mesafe","Tepki mesafesi, frene basmaya karar verirken kat edilen mesafe","Frenleme mesafesi, toplam durma mesafesinin üç bileşeninden biri","Algılama mesafesi, gözleriniz geyiği fark etmeden önce kat edilen mesafe"],"explanation":"Braking distance is the distance the vehicle travels from the moment the brakes are applied until it stops, and it is one of the three components of total stopping distance (perception + reaction + braking). Total stopping distance is the sum of all three, not just the part after braking begins, so that option is the trap."},"31":{"q":"Otoyol hızında giderken çok ileride bir geyik aniden şeridinize giriyor. Ayağınız fren pedalına değmeden önce bile aracınız belli bir mesafe almıştır. Toplam durma mesafesinin hangi bileşenleri, frenler gerçekten uygulanMADAN ÖNCE gerçekleşen bu yol alımını oluşturur?","options":["Frenleme mesafesi ve tepki mesafesi","Algılama mesafesi ve frenleme mesafesi","Yalnızca frenleme mesafesi, çünkü tekerlekler kilitlenene kadar araç hareket etmeye devam eder","Algılama mesafesi ve tepki mesafesi"],"explanation":"Total stopping distance is perception distance plus reaction distance plus braking distance, and only perception and reaction distance occur before the brakes are applied; braking distance is the travel after the brakes engage, so any option containing braking distance is wrong."},"32":{"q":"Şiddetli bir yağmur fırtınasında Teksas'ta bir otoyolda yaklaşık 40 mil/saat hızla giderken aniden direksiyonun hafiflediğini ve aracın direksiyona yanıt vermeden su üzerinde kaymaya başladığını hissediyorsunuz. En güvenli tepki nedir?","options":["Ayağınızı gazdan yavaşça çekin, direksiyonu düz tutun ve lastikler tekrar yola tutununcaya kadar aracın yavaşlamasına izin verin","Hızı kesip tutuşu hızla geri kazanmak için frene sıkıca ve düzenli şekilde basın","Su tabakasından çıkmak için direksiyonu sert bir şekilde banket yönüne çevirin","Kaymayı kontrol etmek için fren pedalına hızlıca pompalayın ve daha düşük bir vitese geçin"],"explanation":"During hydroplaning the tires ride on a layer of water and lose contact with the road, so you should ease off the gas, steer straight, and avoid braking hard until traction returns. Braking firmly (B) or pumping the brakes (D) is a real technique for other emergencies like brake failure, but hard braking during hydroplaning can cause you to skid out of control."},"33":{"q":"Açık bir kış sabahı, hava sıfırın hemen altında. Asfalt yol kuru görünüyor ama uzun bir üst geçide yaklaşıyorsunuz. Güvenli sürmek için ne beklemeli ve ne yapmalısınız?","options":["Üst geçit yolun en sıcak kısmıdır, bu yüzden üzerinde mevcut hızınızı koruyabilirsiniz","Yol kuru görünse bile üst geçit buzlu olabilir, bu yüzden ona ulaşmadan önce yavaşlayın","Üst geçitteki ana tehlike su kaymasıdır, bu yüzden gazdan ayağınızı çekip direksiyonu düz tutun","Önünüzdeki buzu fark etmek için üst geçitte uzun farları kullanın"],"explanation":"Bridges and overpasses freeze before the rest of the roadway because cold air reaches them from all sides, so they can be icy even when the surrounding pavement looks dry; slowing before the overpass is the safe move. Hydroplaning involves water on the road near 35 mph, not freezing, and high beams do not help here, so those are the traps."},"34":{"q":"Bir Teksas otoyolunda öğleden sonra saat 14:00'te aniden şiddetli bir sağanak başlar. Yağmur o kadar yoğundur ki birkaç yüz feet ileride giden aracın arka farlarını zar zor seçebiliyorsunuz ve artık yolun 1.000 feet ilerisini bile net göremediğinizi tahmin ediyorsunuz. Farlarınız konusunda ne yapmalısınız?","options":["Gündüz olduğu için farlarınızı kapalı bırakın ve hareket halindeyken yalnızca dörtlü flaşörlerinizi açın","Öndeki şiddetli yağmurun mümkün olduğunca uzağa aydınlatılması için uzun farlarınızı açın","Farlarınızı açın, çünkü gündüz bile olsa yaklaşık 1.000 feet ileriyi göremediğiniz her durumda onları kullanmanız gerekir","Farlarınızı kapalı tutun ama diğer sürücülere görünür kalmak için iç tavan lambanızı açın"],"explanation":"Teksas'ta yaklaşık 1.000 feet ileriyi göremediğiniz her durumda, şiddetli yağmur gibi gündüz koşulları dahil, farları kullanmanız gerekir, bu yüzden onları açmak doğrudur. Uzun farlar yanlıştır çünkü yağmurda veya siste geri yansıyarak görüşü azaltır ve dörtlü flaşörler ya da tavan lambası sürüş sırasında farların yerini tutmaz."},"35":{"q":"Gece, karanlık iki şeritli bir karayolunda uzun farlarınız açık şekilde gidiyorsunuz. İleride karşı şeritten size doğru bir araba geliyor ve aynı anda kendi şeridinizde hemen önünüzdeki daha yavaş bir kamyona yavaş yavaş yetişiyorsunuz. Teksas yasası uzun farlarınızla ilgili ne yapmanızı gerektirir?","options":["Karşıdan gelen araba için uzun farları açık tutun ama öndeki kamyon için kısa yapın, çünkü önünüzdeki trafik daha önemlidir","Sadece 500 fit içindeki karşıdan gelen araba için kısa yapın; başka bir aracın arkasında uzun farlar her mesafede kullanılabilir","Sadece 300 fit içindeki öndeki kamyon için kısa yapın; karşıdan gelen trafiğe doğru uzun farlar her mesafede kullanılabilir","Karşıdan gelen araba 500 fit içindeyken ve öndeki kamyon 300 fit içindeyken uzun farları kısa yapın"],"explanation":"Texas law requires dimming high beams to low within 500 feet of an oncoming vehicle and within 300 feet when approaching another vehicle from behind, so in this scenario both situations require low beams. Options that excuse you from dimming for one of the two vehicles ignore half the rule and would blind another driver."},"36":{"q":"Teksas'ta bir eyaletlerarası otoyolda saatte 65 mil hızla giderken yüksek bir patlama sesi duyuyorsunuz ve direksiyon aniden bir tarafa doğru sertçe çekiyor—ön lastiklerden biri patladı. Ne yapmalısınız?","options":["Aracı düz tutmak için direksiyonu sıkıca kavrayın, gaz pedalından kademeli olarak ayağınızı çekin ve yavaşladıktan sonra yavaşça yoldan çıkın","Aracı mümkün olduğunca çabuk durdurmak için hemen ve sertçe frene basın","Ayağınızı gaz pedalından çekin ve aracın önünü gitmesini istediğiniz yöne doğru direksiyonu çevirin","Fren pedalına pompalayarak basın ve aracı yavaşlatmak için düşük vitese geçin"],"explanation":"During a blowout you must hold the wheel firmly and gradually ease off the gas before pulling off slowly—braking hard (B) can cause you to lose control. Steering toward where you want the front to go (C) is the fix for a skid, and pumping the brakes with a lower gear (D) is the procedure for brake failure, not a blowout."}},"learn-safe-driving":{"0":{"q":"Üç saniye kuralı ne için kullanılır?","options":["Öndeki araçla güvenli takip mesafesi bırakmak için","Yağ değişimi zamanını bilmek için","El frenini çekmek için","Sinyal verme süresini ayarlamak için"],"explanation":"The three-second rule helps you keep a safe following distance behind the car ahead."},"1":{"q":"Üç saniye kuralını nasıl kullanırsınız?","options":["Önünüzde üç araç boyu sayın","Sabit bir noktaya ulaşma saniyelerini sayın","Saatte üç mil daha yavaş sürün","Her duruşta üç saniye bekleyin"],"explanation":"Pick a fixed point ahead and count the seconds it takes to reach it after the car ahead passes it."},"2":{"q":"Takip mesafenize ne zaman daha fazla saniye eklemelisiniz?","options":["Kuru, açık yollarda","Trafik az olduğunda","Yağmur, sis, buz veya yüksek hızda","Yavaş sürerken"],"explanation":"Add more seconds to your following distance in rain, fog, ice, or at high speed."},"3":{"q":"Üç saniyelik takip mesafesine ne zaman ekstra saniye eklemelisiniz?","options":["Sadece güneşli günlerde","Yol kuru ve boş olduğunda","Trafik az olduğunda","Yağmur, sis, buz veya yüksek hızda"],"explanation":"Rain, fog, ice, and high speed all require adding extra seconds to your following distance."},"4":{"q":"Takip mesafenizi ne zaman artırmalısınız?","options":["Bir motosiklet veya büyük kamyon arkasında giderken","Yol kuru ve temiz olduğunda","Trafik az olduğunda","Acelesi olduğunuzda"],"explanation":"Increase your following distance behind motorcycles, large trucks, or when being tailgated."},"5":{"q":"Başka bir sürücü size çok yakın takip ederken ne yapmalısınız?","options":["Onu uyarmak için aniden fren yapın","Öndeki araçla aranızdaki mesafeyi artırın","Ondan kaçmak için hızlanın","Yolun ortasında durun"],"explanation":"Increasing your following distance gives you more room to stop safely when being tailgated."},"6":{"q":"Büyük kamyon ve otobüslerin etrafındaki büyük kör noktalara ne ad verilir?","options":["Yavaşlama bölgeleri","Güvenli bölgeler","No-Zones (kör noktalar)","Kaza bölgeleri"],"explanation":"Large trucks and buses have big blind spots called No-Zones, and if you can't see the driver's mirrors, they can't see you."},"7":{"q":"Bir kamyon veya otobüs sürücüsünün aynalarını göremiyorsanız, bu ne anlama gelir?","options":["Sağdan geçebilirsiniz","Sürücü sizi net görür","Kendi aynalarınız bozuktur","Sürücü sizi göremez"],"explanation":"Large trucks and buses have big blind spots, so if you can't see the driver's mirrors, the driver can't see you."},"8":{"q":"Toplam durma mesafesini hangi üç mesafe oluşturur?","options":["Algılama mesafesi, tepki mesafesi ve frenleme mesafesi","Hız mesafesi, hava durumu mesafesi ve frenleme mesafesi","Takip mesafesi, kör nokta mesafesi ve tepki mesafesi","Gündüz mesafesi, gece mesafesi ve algılama mesafesi"],"explanation":"Total stopping distance equals perception distance plus reaction distance plus braking distance."},"9":{"q":"Toplam durma mesafesinin üç parçası nedir?","options":["Hız, ağırlık ve lastik mesafesi","Algılama, tepki ve frenleme mesafesi","Direksiyon, sinyal ve frenleme mesafesi","Görüş, hava durumu ve tepki mesafesi"],"explanation":"Total stopping distance is made up of perception distance, reaction distance, and braking distance."},"10":{"q":"Ortalama bir sürücünün tepki süresi yaklaşık ne kadardır?","options":["Yaklaşık 3 saniye","Yaklaşık 2 saniye","Yaklaşık saniyenin dörtte üçü","Yaklaşık 5 saniye"],"explanation":"The average driver's reaction time is about three-fourths (3/4) of a second."},"11":{"q":"Birleşik algılama artı tepki süresi yaklaşık ne kadardır?","options":["Yaklaşık 0,5 saniye","Yaklaşık 3 saniye","Yaklaşık 5 saniye","Yaklaşık 1,5 saniye"],"explanation":"The combined perception-plus-reaction time is roughly 1.5 seconds."},"12":{"q":"Hızınızı iki katına çıkarırsanız, fren mesafesi yaklaşık olarak:","options":["Dört katına çıkar (yaklaşık 4 kat olur)","İki katına çıkar (yaklaşık 2 kat olur)","Aynı kalır","Yarıya iner"],"explanation":"Braking distance increases with the square of speed, so doubling speed roughly quadruples it."},"13":{"q":"Hızınızı iki katına çıkarırsanız, fren mesafeniz yaklaşık ne kadar artar?","options":["Aynı kalır","Yaklaşık dört katı","Yaklaşık iki katı","Yaklaşık üç katı"],"explanation":"Doubling your speed roughly quadruples your braking distance."},"14":{"q":"Daha hızlı sürmek durmayı nasıl etkiler?","options":["Durmayı kolaylaştırır","Durma üzerinde etkisi yoktur","Durmak daha uzun sürer","Çarpışmanın etkisini azaltır"],"explanation":"The faster you go, the longer it takes to stop and the harder a crash, because of the speed-energy relationship."},"15":{"q":"Islak yollarda neden yavaşlamalısınız?","options":["Yakıt tasarrufu için","Daha yakın takip etmek için","Farları daha parlak yapmak için","Çünkü yol tutuşu azalır"],"explanation":"Wet roads reduce traction, so slowing down helps you stay in control."},"16":{"q":"Islak yolda kızaklama (su kaymasi) yaklaşık hangi hızda başlayabilir?","options":["Yaklaşık 35 mil/saat","Yaklaşık 5 mil/saat","Yaklaşık 15 mil/saat","Yaklaşık 70 mil/saat"],"explanation":"Hydroplaning can begin near 35 mph as water builds up under the tires."},"17":{"q":"Su kaymasi (hidroplanlama) nedir?","options":["Lastiklerin yagmurda yola daha iyi tutunmasi","Lastiklerin su uzerinde yolla temasini kaybetmesi","Frenlerin uzun bir inişte aşiri isinmasi","Farlarin islak yoldan yansimasi"],"explanation":"Hydroplaning happens when water builds up under the tires and they lose contact with the road surface."},"18":{"q":"Aracınız kızağa girmeye başlarsa ne yapmalısınız?","options":["Hemen sert şekilde frene basın","Tutuş kazanmak için hızlanın","Gazı bırakın ve düz gidin","Direksiyonu sert şekilde çevirin"],"explanation":"If you hydroplane, ease off the gas, do not brake hard, and steer straight."},"19":{"q":"Kuru bir dönemden sonraki ilk yağmur neden en kaygandır?","options":["Yol her zamankinden daha soğuktur","Yağmur tüm kiri yıkar","Lastikler yağışlı havada hava kaybeder","Yol üzerindeki suya yağ karışır"],"explanation":"The first rain mixes with built-up oil on the road, making it the most slippery."},"20":{"q":"Buzlu havada yolun hangi kısmı önce donar?","options":["Köprüler ve üst geçitler","Tepe noktaları","Tüneller","Otoparklar"],"explanation":"Bridges and overpasses freeze before the rest of the road in icy conditions."},"21":{"q":"Buzlanma neden tehlikelidir?","options":["Hızla erir","Yolda görmek zordur","Keskin kokar","Yüksek ses çıkarır"],"explanation":"Black ice is dangerous because it is hard to see on the road."},"22":{"q":"Aracınız kaymaya başlarsa ne yapmalısınız?","options":["Frene sert basın","Gaza daha çok basın","Gazdan ayağınızı çekin ve gitmek istediğiniz yöne direksiyon kırın","Gözlerinizi kapatıp tutunun"],"explanation":"In a skid, take your foot off the gas, don't slam the brakes, and steer in the direction you want the front of the car to go."},"23":{"q":"Bir kaymadan kurtulmak için nasıl direksiyon kırmalısınız?","options":["Yolun kenarına doğru","Kaymanın ters yönüne","Gitmek istediğiniz yönden uzağa","Aracın önünün gitmesini istediğiniz yöne"],"explanation":"To recover from a skid, steer in the direction you want the front of the car to go."},"24":{"q":"Kayma sırasında ayağınızla ne yapmalısınız?","options":["Ayağınızı gaz pedalından çekin","Gaz pedalına daha sert basın","Fren pedalına sertçe basın","Gaza sabit basınç uygulayın"],"explanation":"Easing off the gas helps you regain traction during a skid."},"25":{"q":"Sis veya dumanda hangi farları kullanmalısınız?","options":["Uzun farlar","Kısa farlar","Far yok","Sadece dörtlü flaşörler"],"explanation":"Use low beams in fog or smoke because high beams reflect back and reduce your visibility."},"26":{"q":"Sis veya dumanda ne yapmalısınız?","options":["İçinden geçmek için hızlanın","Uzun farları açın","Yavaşlayın veya güvenli bir şekilde yolun kenarına çekilin","Farları kapatın"],"explanation":"In fog or smoke you should slow down or pull off the road safely."},"27":{"q":"Siste hangi farları kullanmalısınız?","options":["Sadece dörtlü flaşörleri","Hiç far kullanmayın","Uzun farları","Kısa farları"],"explanation":"In fog you should use low beams because high beams reflect off the fog and reduce your visibility."},"28":{"q":"Farları ne zaman kullanmalısınız?","options":["Gün batımından gün doğumuna kadar","Sadece şiddetli yağmurda","Sadece otoyolda","Sadece park ederken"],"explanation":"Texas law requires headlights from sunset to sunrise."},"29":{"q":"Görüşe bağlı olarak farlarınızı ne zaman açmalısınız?","options":["En az 100 fit ileriyi göremediğinizde","En az 1.000 fit ileriyi göremediğinizde","En az 50 fit ileriyi göremediğinizde","En az 5.000 fit ileriyi göremediğinizde"],"explanation":"Use your headlights any time you cannot see at least about 1,000 feet ahead."},"30":{"q":"Karşıdan gelen bir araç için uzun farları kısa farlara ne zaman düşürmelisiniz?","options":["100 feet içinde","250 feet içinde","500 feet içinde","1.000 feet içinde"],"explanation":"You must dim your high beams to low beams when within 500 feet of an oncoming vehicle."},"31":{"q":"Başka bir aracı takip ederken, uzun farlarınızı kısaya hangi mesafede düşürmelisiniz?","options":["Arkadan 100 fit içinde","Arkadan 150 fit içinde","Arkadan 200 fit içinde","Arkadan 300 fit içinde"],"explanation":"You must dim your high beams to low beams when within 300 feet behind another vehicle."},"32":{"q":"Karşıdan gelen bir araca kaç fit kala uzun farları kısmanız gerekir?","options":["500 fit","100 fit","250 fit","1.000 fit"],"explanation":"You must dim your high beams to low within 500 feet of an oncoming vehicle."},"33":{"q":"Takip ettiğiniz bir aracın kaç fit yakınında uzun farlarınızı kısmanız gerekir?","options":["100 fit","300 fit","500 fit","1.000 fit"],"explanation":"You must dim your high beams to low when within 300 feet behind another vehicle."},"34":{"q":"Karşıdan gelen aracın uzun farları sizi kör ederse nereye bakmalısınız?","options":["Doğrudan farlara","Yukarı, gökyüzüne","Yolun sağ kenarına","Aşağı, gösterge paneline"],"explanation":"Looking toward the right edge of the road helps you avoid the glare and stay in your lane."},"35":{"q":"\"Farlarınızı aşmak\" ne anlama gelir?","options":["Uzun farları çok sık kullanmak","Farları açmayı unutmak","Tek far yanmadan sürmek","Aydınlatılan alanda duramayacak kadar hızlı gitmek"],"explanation":"Overdriving your headlights means going so fast you cannot stop within the distance lighted by your headlights."},"36":{"q":"Frenleriniz tutmazsa ne yapmalısınız?","options":["Pedala basıp bırakın, düşük vitese geçin, el frenini kademeli kullanın","Motoru kapatın ve direksiyonu sert çevirin","Bir sonraki çıkışa ulaşmak için hızlanın","Gözlerinizi kapatıp korna çalın"],"explanation":"If your brakes fail, pump the brake pedal, shift to a lower gear, and use the parking brake gradually."},"37":{"q":"Fren arızasında el frenini nasıl uygulamalısınız?","options":["Birden bire","Yavaş yavaş","Asla kullanmayın","Sadece durduktan sonra"],"explanation":"During brake failure, apply the parking brake gradually rather than all at once."},"38":{"q":"Frenleriniz arıza yaparsa, önerilen tepki nedir?","options":["Hareket halinde kalmak için hızlanmak","Farlarınızı kapatmak","Daha düşük vitese geçmek","Kornaya yüksek sesle basmak"],"explanation":"Shifting to a lower gear helps slow the vehicle when your brakes fail."},"39":{"q":"Lastiğiniz patlarsa ne yapmalısınız?","options":["Hemen sert şekilde fren yapın","Kontrolü korumak için hızlanın","Direksiyonu bırakın","Direksiyonu sıkıca tutun ve gazdan ayağınızı çekin"],"explanation":"In a blowout, hold the wheel firmly, ease off the gas, and do not brake hard."},"40":{"q":"Lastik patlamasından sonra, kontrolü sağladığınızda yoldan nasıl çıkmalısınız?","options":["Yavaşça yoldan çıkın","Sert fren yapıp hızlıca durun","Hızlanıp şeride girin","Kendi şeridinizde kalın"],"explanation":"After a tire blowout, once you have control you should pull off the road slowly."},"41":{"q":"Lastik patladığında ne yapmalısınız?","options":["Hemen sert fren yapın","Sert fren yapmayın","Hızla hızlanın","Direksiyonu bırakın"],"explanation":"During a tire blowout, do not brake hard; ease off the gas and pull off slowly."},"42":{"q":"Aracınız tren rayları üzerinde stop ederse ne yapmalısınız?","options":["Araçta kalıp beklemek","Çalıştırıp treni geçmeye çalışmak","Herkesi çıkarıp uzaklaştırın, sonra yardım çağırın","Aracı raylar boyunca itmek"],"explanation":"Get everyone out and away from the tracks, then call for help; never try to beat a train."},"43":{"q":"Demir yolu raylarında asla ne yapmaya çalışmamalısınız?","options":["Rayların önünde durmak","Her iki yöne bakmak","Raylara yaklaşırken yavaşlamak","Trenden önce geçmeye çalışmak"],"explanation":"You should never try to beat a train across railroad tracks."},"44":{"q":"Yolda durmanız gerekiyorsa ne yapmalısınız?","options":["Bankete çekip dörtlüleri yakın","Şeridinizde durup bekleyin","Yarısı trafik şeridinde olacak şekilde park edin","Farlarınızı kapalı tutun"],"explanation":"Pull fully onto the shoulder, turn on hazard flashers, and use warning devices."},"45":{"q":"Acil durumda yol kenarında durduğunuzda neyi açmalısınız?","options":["Uzun farlarınızı","Dörtlü flaşörlerinizi (tehlike uyarı ışıkları)","İç tavan lambanızı","Hiçbir şey"],"explanation":"When stopped on the roadside in an emergency, turn on your hazard (emergency) flashers."},"46":{"q":"Acil durumda yolda dururken aracınızı ne kadar uzağa çekmelisiniz?","options":["Şeridinizde kalın","Yarı yarıya banketin üzerine","Tamamen banketin üzerine","Orta çizginin üzerine"],"explanation":"Pull fully onto the shoulder so your vehicle is clear of traffic."},"47":{"q":"Yorgunluk, uyuşturucu ve alkol sürücüye ne yapar?","options":["Tepki süresini iyileştirir","Muhakemeyi keskinleştirir","Hiçbir etkisi yoktur","Tepki süresini yavaşlatır ve muhakemeyi bozar"],"explanation":"Fatigue, drugs, and alcohol all slow reaction time and impair judgment."},"48":{"q":"Ne zaman araç kullanmaktan kaçınmalısınız?","options":["Etkisi altındayken veya uykuluyken","İyi dinlenmişken","Yol açıkken","Trafik azken"],"explanation":"You should never drive while impaired or drowsy because it slows your reaction time and judgment."},"49":{"q":"Yorgunluk (uyku hali) sürüşünüzü nasıl etkiler?","options":["Odaklanmanızı artırır","Uyuşturucu ve alkol gibi tepki sürenizi ve muhakemenizi yavaşlatır","Sürüş üzerinde hiçbir etkisi yoktur","Daha hızlı fren yapmanızı sağlar"],"explanation":"Fatigue slows your reaction time and judgment just like drugs and alcohol."},"50":{"q":"Hangi etkinlik sürüş sırasında önemli bir dikkat dağıtıcıdır?","options":["Emniyet kemerinizi takmak","Aynalarınızı kontrol etmek","Mesaj atmak veya elde telefon kullanmak","Yağmurda yavaşlamak"],"explanation":"Texting and handheld phone use is a major distraction and texting while driving is illegal in Texas."},"51":{"q":"Teksas'ta araç kullanırken mesaj yazmak yasal mıdır?","options":["Evet, her zaman yasaldır","Evet, sadece otoyollarda","Evet, trafik yavaşsa","Hayır, yasa dışıdır"],"explanation":"Texting while driving is illegal in Texas."},"52":{"q":"Araç kullanırken emniyet kemerinizi ne zaman takmalısınız?","options":["Her zaman","Sadece otoyollarda","Sadece geceleri","Sadece yağmurda"],"explanation":"Texas law requires you to always wear your seat belt while driving."},"53":{"q":"Teksas'ta emniyet kemerini kimler takmalıdır?","options":["Sadece sürücü","Sürücü ve tüm yolcular","Sadece ön koltuktakiler","Sadece 12 yaş altı çocuklar"],"explanation":"Texas law requires the driver and all passengers to wear seat belts."},"54":{"q":"Tepki mesafesi nedir?","options":["Lastiklerinizin fren izi bıraktığı mesafe","Diğer araçların arkasında bıraktığınız mesafe","Bir tehlikeyi gördükten sonra tepki verirken aracınızın kat ettiği mesafe","Frenlerinizin aracı durdurduğu mesafe"],"explanation":"Reaction distance is how far your vehicle travels while you react after perceiving a hazard."},"55":{"q":"Fren mesafesi nedir?","options":["Yola baktığınız süre","Dönüşten önce sürdüğünüz mesafe","Park etmiş iki araç arasındaki boşluk","Aracınızın frene basmaktan durana kadar gittiği mesafe"],"explanation":"Braking distance is how far your vehicle travels from when you apply the brakes until it fully stops."},"56":{"q":"Aracınız kızaklamaya (hidroplanlama) başlarsa ne yapmalısınız?","options":["Gazdan ayağınızı çekin ve düz gidin","Hemen sert fren yapın","Hızla hızlanın","Direksiyonu sertçe çevirin"],"explanation":"During hydroplaning, ease off the gas and steer straight instead of braking hard."},"57":{"q":"Üç saniye kuralı neyi korumanıza yardımcı olur?","options":["Temiz bir ön cam","Güvenli bir takip mesafesi","Dolu bir yakıt deposu","Doğru lastik basıncı"],"explanation":"The three-second rule helps you keep a safe following distance behind the vehicle ahead."},"58":{"q":"Gündüz farlarınızı ne zaman açmalısınız?","options":["Sadece otoyolda","Sadece dışarısı karanlık olduğunda","Yaklaşık 1.000 fit ileriyi göremediğinizde","Gündüz asla"],"explanation":"Turn on headlights whenever visibility drops and you cannot see about 1,000 feet ahead, even in daytime rain or fog."},"59":{"q":"Acil durumda yol kenarında durduğunuzda ne yapmalısınız?","options":["Şeritte kalıp beklemek","Tüm ışıkları kapatmak","Hızla uzaklaşmak","Diğer sürücüler için uyarı cihazları koymak"],"explanation":"Warning devices alert other drivers that your vehicle is stopped on the roadside."}},"alcohol-and-penalties":{"0":{"q":"34 yaşındaki Marcus, Houston'da bir arkadaşının barbeküsünden ayrılırken kenara çekilir. Memur içki içtiğinden şüphelenir ve nefes testi yapmasını ister. Texas'ta yetişkin bir sürücü olarak Marcus, hangi kan alkol seviyesinde (BAC) yasal olarak Alkollü Araç Kullanma (DWI) suçunu işlemiş sayılır?","options":["%0,08 BAC veya daha yüksek","%0,04 BAC veya daha yüksek","%0,15 BAC veya daha yüksek","%0,00'ın üzerinde tespit edilebilir herhangi bir miktar"],"explanation":"For an adult driver age 21 or older, the Texas DWI limit is 0.08% BAC. 0.04% is the limit for commercial drivers, and any detectable amount (above 0.00%) applies only to drivers under 21 under Zero Tolerance."},"1":{"q":"26 yaşındaki Marcus, Austin'de şeritler arasında savrularak ilerlerken durduruluyor. 0,08% BAC (kandaki alkol oranı) gösteren nefes testini geçiyor ve memura kendini gayet iyi hissettiğini ve dikkatli sürdüğünü söylüyor. Texas yasalarına göre Marcus bu sonuca dayanarak hangi suçu işlemiştir?","options":["Hiçbir şey, çünkü 0,08% yasal sınırdır ve ancak sonuç 0,08%'i aştığında sınırı geçmiş olur","Alkollü Araç Kullanma (DWI), çünkü bir yetişkin için 0,08% BAC veya üzerinde araç kullanmak DWI'dır","Alkolün Etkisi Altında Araç Kullanma (DUI), çünkü tespit edilebilir herhangi bir miktar alkol bir yetişkini DUI'dan suçlu kılar","Hiçbir şey, çünkü memura kendini iyi hissettiğini söyledi ve gerçek bir alkol etkisi göstermedi"],"explanation":"For an adult 21 or older, driving at or above 0.08% BAC is the offense of Driving While Intoxicated (DWI), so reaching exactly 0.08% counts. The Zero Tolerance DUI for any detectable alcohol applies only to drivers under 21, and feeling 'fine' does not change the legal BAC limit."},"2":{"q":"30 yaşındaki bir sürücü, şeritler arasında savrularak gittikten sonra durdurulur. Nefes testi %0,06 BAC gösterir, ancak memur alkol etkisiyle uyumlu peltek konuşma ve zayıf koordinasyon gözlemler. Teksas yasalarına göre ne olabilir?","options":["Hiçbir şey, çünkü %0,06 yetişkin sınırı olan %0,08'in altındadır, dolayısıyla DWI uygulanamaz","Nefes testi %0,08'in altında çıktığında sürücü otomatik olarak aklanır","BAC %0,08'in altında olsa bile, alkolün etkisi altında olduğu için sürücü yine de DWI ile suçlanabilir","Sürücüye yalnızca açık kap ihlali kesilebilir, DWI değil"],"explanation":"In Texas, a driver can be charged with DWI below 0.08% BAC if alcohol or drugs impair them, so the observed impairment supports a DWI charge. The 0.08% figure is a per se limit, not a safe harbor, so being under it does not automatically clear the driver."},"3":{"q":"Marcus bir nakliye şirketi için ticari bir TIR kullanıyor. Uzun bir vardiyadan sonra akşam yemeğinde iki bira içiyor ve daha sonra yapılan nefes testi 0,05% BAC gösteriyor. Yasal sınırın oldukça altında olduğunu ve aracını kullanmaya devam edebileceğini iddia ediyor. Haklı mı ve ilgili sınır nedir?","options":["Haklı; Teksas'ta tüm sürücüler için sınır 0,08% BAC olduğundan 0,05% yasaldır.","Haklı çünkü 0,08% altındaki herhangi bir BAC asla suçlamaya yol açamaz.","Sınırı aşmıştır çünkü Teksas'ta sıfır tolerans vardır ve onun için tespit edilebilir herhangi bir alkol yasa dışıdır.","Sınırı aşmıştır; ticari sürücüler için 0,04% BAC daha düşük bir sınır vardır ve 0,05% bunu aşmaktadır."],"explanation":"Commercial drivers in Texas are held to a lower limit of 0.04% BAC, so Marcus's 0.05% reading puts him over the limit. The 0.08% figure (A) is the standard adult limit, not the commercial one, and zero tolerance (C) applies only to drivers under 21, not commercial drivers."},"4":{"q":"Marcus 19 yaşında ve bir bira içtiği arkadaşının partisinden eve dönüyor. Bir polis memuru onu yasal olarak durduruyor ve nefes testi %0,03 kandaki alkol oranı (BAC) gösteriyor. Teksas yasalarına göre yasal durumu nedir?","options":["Araç kullanması yasa dışıdır — Teksas Sıfır Tolerans kuralı uyarınca, 21 yaşından küçük bir sürücü için tespit edilebilen herhangi bir alkol (0,00'ın üzerinde bir BAC) küçük tarafından DUI sayılır.","Araç kullanması yasaldır çünkü %0,03 BAC değeri %0,08 DWI sınırının altındadır.","Araç kullanması yasaldır çünkü %0,03 BAC değeri %0,04 ticari sürücü sınırının altındadır.","Araç kullanması yasaldır çünkü sadece bir içki içti ve karaciğer saatte bir standart içki işler."],"explanation":"For drivers under 21, Texas has Zero Tolerance, so ANY detectable alcohol (a BAC above 0.00) is illegal and is a DUI by a minor. The 0.08% adult DWI limit and the 0.04% commercial limit do not apply to a 19-year-old minor, making those traps wrong."},"5":{"q":"19 yaşındaki bir sürücü bir partiden ayrılır ve Teksas'ta kenara çekilir. Nefes testi, yetişkin sınırı olan %0,08'in çok altında %0,03 BAC (kandaki alkol oranı) gösterir. Sürücü, varsa, hangi suçu işlemiştir?","options":["Hiçbir şey, çünkü BAC yetişkin sınırı olan %0,08'in altında","Reşit olmayan biri tarafından alkol etkisi altında araç kullanma (DUI), çünkü 21 yaş altında tespit edilebilir herhangi bir alkol yasa dışıdır","DWI, çünkü sürücü herhangi bir BAC değerinde otomatik olarak sarhoş sayılır","Hiçbir şey, ancak sürücünün ehliyeti zımni rıza nedeniyle 180 gün askıya alınır"],"explanation":"Texas has a Zero Tolerance law for drivers under 21: any detectable alcohol (a BAC above 0.00) is a DUI of alcohol by a minor, regardless of the 0.08% adult DWI limit. Option A wrongly applies the adult threshold to a minor, and the 180-day suspension in D is the penalty for refusing a test, not for a 0.03% reading."},"6":{"q":"Bir partide Marcus birkaç bira içti ve kendini sakin ve rahat hissediyor, bu yüzden bir arkadaşına içtikten sonra aslında daha güvenli ve daha dikkatli bir sürücü olduğunu söylüyor. Arkadaşı bunun tehlikeli olduğu konusunda onu uyarıyor. Rahat hissetmesine rağmen alkol Marcus'u neden daha tehlikeli bir sürücü yapar?","options":["Alkol, kalbini hızlandıran ve direksiyon başında aşırı saldırgan yapan bir uyarıcıdır","Alkol sürücüleri yalnızca kandaki alkol oranı yasal sınır olan %0,08'e ulaştığında etkiler, bu yüzden iki bira onu etkileyemez","Alkol, rahat hissetse bile tepki süresini yavaşlatan ve muhakemesini bozan bir depresandır","Alkol görüşünü ve koordinasyonunu keskinleştirir ancak trafik işaretlerine uyma yeteneğini köreltir"],"explanation":"Alcohol is a depressant, so it slows reaction time and impairs judgment even when the drinker feels calm and relaxed. It is not a stimulant (A is the wrong category), and a driver can be impaired well below 0.08% (B is false), making C correct."},"7":{"q":"Birkaç içki içtiği bir partiden eve dönerken Marcus, şeridinde sürekli kaydığını, sinyal koluna uzanırken beceriksizleştiğini ve öndeki araç fren yaptığında bir an geç tepki verdiğini fark ediyor. Alkolün hangi etki kombinasyonu yaşadıklarını en iyi açıklar?","options":["Serin gece havası alkolü tekrar kan dolaşımına hızlandırdığı için kandaki alkol düzeyi yükseliyor.","Alkol bir uyarıcı gibi davranır, bu yüzden odağını keskinleştirir ama kas hareketlerini sinirli ve hızlı yapar.","Etkiler yalnızca yorgunluktan kaynaklanıyor; son içkisinden bu yana bir saatten fazla geçtiği için alkolün kendisi etkisini yitirdi.","Alkol tepki süresini yavaşlattı, muhakemesini bozdu ve koordinasyonu ile görüşünü azalttı."],"explanation":"Alcohol is a depressant that slows reaction time, impairs judgment, and reduces coordination and vision, which matches Marcus's lane drifting, fumbling, and delayed braking. Alcohol is not a stimulant and does not sharpen focus, and only time lowers BAC, so fresh air and the passage of one hour do not undo the impairment."},"8":{"q":"Bir arkadaşının evinde iki bira içtikten sonra Marcus kendini fiziksel olarak iyi hissediyor, elleri titremiyor ve konuşması normal, bu yüzden eve güvenle gidebileceğine karar veriyor ve normalde duracağı sarı ışığa yetişmek için hızını bile artırıyor. Bu riskli karara yol açan, alkolün İLK olarak hangi yeteneğini bozmuş olması en olasıdır?","options":["Muhakemesini (durumu sağlıklı değerlendirme yetisi) — alkolün etkilediği ilk sürüş yeteneği budur","Görüşünü; çünkü alkolün etkilediği ilk yetenek her zaman görüştür","Koordinasyonunu; çünkü ellerinin titrememesi muhakemesinin hâlâ yerinde olduğunu kanıtlar","Tepki süresini; çünkü alkol her şeyden önce buna etki eder"],"explanation":"Muhakeme, alkolün etkilediği ilk sürüş yeteneğidir; bu yüzden Marcus fiziksel olarak iyi hissetmesine rağmen sarı ışıkta hızlanma gibi riskli bir karar verdi. Görüş, koordinasyon ve tepki süresi de alkolden etkilenir, ancak bunlar muhakemeden önce değil, sonra etkilenir."},"9":{"q":"Bir partide arkadaşınız son iki saatte birkaç içki içti ve şimdi arabayla eve gitmek istiyor. İki büyük fincan sade kahve içtiğini, doyurucu bir yemek yediğini ve 'kafasını toparlamak' için soğuk havaya çıktığını söyleyerek kendini gayet iyi hissettiğinde ısrar ediyor. Güvenli bir şekilde araç kullanma yeteneği konusunda ona ne söylemelisiniz?","options":["Kahve ve soğuk hava, vücudunun alkolü işlemesini hızlandırdı, bu yüzden artık güvenle araç kullanabilir.","Bunların hiçbiri kandaki alkol oranını düşürmez; ayılmayı yalnızca zamanın geçmesi sağlar, bu yüzden araç kullanmamalı.","Doyurucu bir yemek, kanındaki mevcut alkolü emer, bu yüzden alkol oranı artık yasal seviyeye geri döndü.","Kendini zinde hissettiği için muhakemesi ve tepki süresi tamamen geri geldi ve yasal olarak araç kullanabilir."],"explanation":"Only the passage of time lowers BAC, because the liver processes alcohol at a fixed rate of about one drink per hour. Coffee, food, cold air, and feeling alert do not speed up sobering or reduce impairment, so he should not drive."},"10":{"q":"Bir partide arkadaşınız son iki saatte birkaç bira içti ve şimdi eve araba kullanarak gitmek istiyor. Önce sert bir kahve içerse, doyurucu bir yemek yerse ve soğuk bir duş alırsa araba kullanmasında sakınca olmayacağını söylüyor. Alkolün vücuttan nasıl atıldığına dair bildiklerinize göre en doğru yanıt nedir?","options":["Kahve ve soğuk duş onu hızla ayıltır, bu yüzden tekrar zinde hissettiğinde araba kullanabilir.","Doyurucu bir yemek kandaki alkolü emer ve BAC'sini güvenle araç kullanacak kadar düşürür.","Bunların hiçbiri ayılmayı hızlandırmaz; yalnızca zaman BAC'yi düşürür, bu yüzden araba kullanmamalıdır.","Eve giderken alacağı temiz hava alkolü sisteminden temizler, bu yüzden kısa bir yolculuk sorun değildir."],"explanation":"Only the passage of time lowers BAC because the liver processes about one standard drink per hour, and nothing makes it faster. Coffee, food, a cold shower, and fresh air may make a person feel more alert but do not reduce intoxication, so they are dangerous myths."},"11":{"q":"Marcus, gece yarısı sona eren bir partide dört standart içki içti. Sabah 1:30'da eve gitmeden önce iki büyük kahve içiyor, doyurucu bir yemek yiyor ve soğuk bir duş alıyor. Kendini zinde hissediyor. Güvenli araç kullanma yeteneği hakkında doğru olan nedir?","options":["Kahve ve yemek kan alkol düzeyini yeterince düşürdü, artık güvenle araç kullanabilir","Soğuk duş karaciğerini hızlandırdı, bu yüzden alkolün çoğu çoktan vücuttan atıldı","Zinde hissettiği ve muhakemesi açık olduğu için araç kullanmasında sakınca yok","Kan alkol düzeyini yalnızca zaman düşürebilir; karaciğeri saatte yaklaşık bir içki temizler, bu yüzden muhtemelen hâlâ etki altındadır"],"explanation":"The liver processes only about one standard drink per hour and nothing speeds it up, so after roughly 90 minutes Marcus has cleared at most one or two of his four drinks. Coffee, food, and a cold shower do not lower BAC, and feeling alert is misleading because judgment is the first ability alcohol impairs."},"12":{"q":"Marcus akşam yemeğinde bir bira içti ve sadece hafifçe keçiflendiğini hissediyor. Aynı gün daha önce, uyku yapabileceği uyarısı taşıyan reçetesiz bir alerji hapı almıştı. Bir biranın yasal sınırın çok altında olduğunu düşünüyor ve eve sürerek dönebileceğine karar veriyor. Onun durumundaki gerçek tehlike nedir?","options":["Reçetesiz ilaç alkolle birleştiğinde bozulmayı katlayarak artırabilir ve onu tek bir biranın düşündüreceğinden çok daha tehlikeli bir sürücü yapabilir","Hiçbir sorun yok, çünkü reçetesiz ilaçlar yasaldır ve sürüş yeteneğini etkileyemez","Yola çıkmadan önce birleşik etkileri gidermek için daha fazla yemek yer ve kahve içerse güvendedir","Yalnızca BAC değeri bir biranın ulaşamayacağı %0,04 ticari sürücü sınırına ulaşırsa risk altındadır"],"explanation":"Drugs of any kind—including legal over-the-counter medicines—combined with alcohol multiply impairment, so Marcus can be far more impaired than one beer alone would suggest. Coffee and food do not speed sobering, and the 0.04% limit applies only to commercial drivers, not Marcus."},"13":{"q":"Marcus gece geç saatte Austin'de kenara çekiliyor ve DWI (alkollü araç kullanma) suçundan yasal olarak tutuklanıyor. Karakolda memur ondan nefes örneği vermesini istiyor. Marcus hiçbir teste asla rıza göstermediğini söyleyip reddediyor. Texas yasalarına göre, hangi temele dayanarak zaten rıza göstermiş sayılıyordu?","options":["Karakolda tutuklama belgelerini imzaladığında rıza gösterdi, bu yüzden test artık zorunludur.","Texas'ta araç kullanarak, DWI suçundan yasal olarak tutuklandığında nefes veya kan testine zımni rıza vermiş oldu.","Yalnızca durdurma sırasında kandaki alkol oranı zaten %0,08 veya daha yüksek ölçüldüğü için rıza göstermiş oldu.","Texas sürücü belgesi başvurusu yaptığında rıza gösterdi, bu da tüm retleri kalıcı olarak geçersiz kılar."],"explanation":"Texas law states that by driving in the state you give implied consent to a breath or blood test if lawfully arrested for DWI, so consent already exists at the time of arrest. Option A is wrong because consent comes from the act of driving, not signing paperwork, and a 0.08% reading or the license application does not establish it."},"14":{"q":"Marcus, gece geç saatte durdurulduktan sonra alkollü araç kullanma (DWI) suçundan yasal olarak tutuklanır. Karakolda görevli ondan nefes örneği vermesini ister, ancak Marcus test olmadan aleyhine kanıt olmayacağına inanarak reddeder. DWI suçlamasının kendisini bir kenara bırakırsak, yalnızca testi reddettiği için sürücü belgesine ne olur?","options":["Belgesine hiçbir şey olmaz, çünkü zımni rıza ilkesi uyarınca bir sürücünün nefes veya kan testini hiçbir sonuç olmadan reddetme hakkı her zaman vardır","Bu ilk ret nedeniyle belgesi 1 yıla kadar askıya alınır","Bu ilk ret nedeniyle belgesi otomatik olarak 180 gün askıya alınır","Testi reddettiği için 2.000 dolar para cezası ve 180 güne kadar hapis cezasıyla karşı karşıya kalır"],"explanation":"Under Texas implied consent, refusing a lawful breath or blood test triggers an automatic 180-day license suspension for a first refusal under Administrative License Revocation, separate from any DWI charge. The 'up to 1 year' suspension and the $2,000 fine/jail time are penalties for a DWI conviction, not for refusing the test, and refusal does carry consequences."},"15":{"q":"Marcus, yol kenarındaki ayıklık kontrolünü geçemedikten sonra Teksas'ta usulüne uygun olarak alkollü araç kullanmaktan (DWI) tutuklanır. Karakolda, test sonucu olmadan eyaletin bir davasının olmayacağını ve ehliyetinin güvende olduğunu düşünerek nefes veya kan örneği vermeyi reddeder. Birkaç ay sonra DWI suçlaması mahkemede düşürülür. Sürüş ayrıcalıklarının durumu nedir?","options":["DWI suçlaması düşürüldüğü için hiçbir askıya alma uygulanmaz ve ehliyeti tamamen geçerli kalır.","Ehliyeti, ilk DWI mahkumiyetine bağlı standart ceza olan en fazla 1 yıl boyunca askıya alınır.","Reddetme nedeniyle yalnızca 2.000 dolar para cezasıyla karşı karşıyadır, ancak ehliyeti askıya alınmaz.","Reddetme nedeniyle ehliyeti, düşürülen DWI suçlamasından ayrı olarak, İdari Ehliyet İptali (ALR) kapsamında otomatik olarak 180 gün boyunca askıya alınır."],"explanation":"Refusing a breath or blood test triggers an automatic 180-day ALR suspension that is entirely separate from the DWI case, so it stands even though the DWI charge was dismissed. Option B wrongly applies the up-to-1-year suspension tied to a DWI conviction, which never occurred here, and the dismissal does not erase the refusal-based ALR suspension."},"16":{"q":"Houston'daki bir barda 24 yaşındaki Marcus birkaç içki içer, sonra eve doğru araba kullanır ve kandaki alkol seviyesi (BAC) 0,11% iken durdurulur. Tutuklanır ve daha önce hiç suçu olmadan ve arabada yolcu bulunmadan ilk DWI (sarhoş araç kullanma) suçundan mahkûm edilir. Mahkeme bu ilk DWI mahkûmiyeti için en fazla ne kadar para cezası verebilir?","options":["2.000 dolara kadar","500 dolara kadar","4.000 dolara kadar","10.000 dolara kadar"],"explanation":"A first DWI in Texas carries a fine of up to $2,000, along with possible jail time and license suspension. The $500 figure is the maximum fine for a minor's first DUI, and the higher amounts apply to repeat or aggravated offenses, not a standard first DWI."},"17":{"q":"Marcus, bir arkadaşının partisinden ayrılırken kanındaki alkol oranı %0,10 iken durdurulduktan sonra Teksas'taki ilk alkollü araç kullanma (DWI) suçundan mahkum edildi. Hakim şimdi ilk DWI için Teksas yasalarının belirlediği aralık içinde hapis cezasını belirliyor. Hakimin verebileceği olası hapis süresi nedir?","options":["1 yıla kadar hapis","3 günden 180 güne kadar hapis","Hapis yerine sabit 180 günlük ehliyet askıya alma","Hapis yok, sadece 500 dolar para cezası"],"explanation":"Under Texas law, a first DWI carries 3 days to 180 days in jail, so the judge's range is set by that statute. The 1-year figure is the license suspension (not jail), the 180-day suspension applies to refusing a chemical test under ALR, and the $500 fine is a minor's first DUI penalty."},"18":{"q":"28 yaşındaki Marcus, Cuma gecesi bir partiden ayrılırken kenara çekilir. Nefes testini yapar, 0,10% BAC üfler ve Teksas'ta ilk DWI (alkollü araç kullanma) suçundan mahkum olur. Yanında çocuk yolcusu yoktur ve önceki bir suçu da yoktur. Hüküm verilirken, bu ilk DWI mahkumiyeti için sürücü belgesi en fazla ne kadar süreyle askıya alınabilir?","options":["180 gün — nefes testini reddetmek için verilen süreyle aynı","Askıya alma yok, çünkü BAC değeri 0,15%'in altındaydı","1 yıla kadar","2 yıla kadar — herhangi bir DWI için standart süre"],"explanation":"A first DWI conviction in Texas carries a license suspension of up to 1 year. The 180-day figure is the separate automatic suspension for refusing a chemical test under implied consent, not the penalty for a DWI conviction, so option A is a trap."},"19":{"q":"Marcus geçen yıl Teksas'ta alkollü araç kullanmaktan (DWI) mahkum oldu, para cezasını ödedi ve cezasını çekti. Bu gece tekrar durduruldu ve ikinci kez DWI'den tutuklandı. İlk mahkumiyetine kıyasla bu tekrarlı suç için ne beklemelidir?","options":["Cezalar ilk DWI ile tamamen aynıdır: en fazla 2.000 dolar para cezası ve 1 yıla kadar ehliyet askıya alma.","Ek ceza yoktur çünkü Teksas yalnızca en son DWI mahkumiyetini dikkate alır.","Ehliyeti otomatik olarak 180 gün askıya alınır ve bu diğer tüm DWI cezalarının yerine geçer.","Cezalar tekrarlı suç için artar, bu yüzden ilk DWI'ye göre daha ağır para cezaları, daha uzun hapis süresi ve daha uzun askıya alma ile karşılaşır."],"explanation":"Texas law increases DWI penalties for repeat offenses, so a second conviction brings tougher consequences than the first. Option A wrongly states the first-offense maximums ($2,000 / 1 year) apply unchanged, and option C confuses the 180-day ALR suspension for refusing a test with the criminal DWI penalty."},"20":{"q":"Marcus bir partiden eve dönerken durduruluyor. 27 yaşında, bu hayatındaki ilk DWI (alkollü araç kullanma) tutuklaması ve nefes testi BAC değerini %0,16 gösteriyor. Arkadaşı, cezaların diğer herhangi bir ilk suç DWI ile tamamen aynı olacağını söylüyor. Arkadaşı neden yanılıyor?","options":["Çünkü %0,15 veya daha yüksek bir BAC, ilk suçta bile cezaların artmasına neden olur.","Çünkü nefes testini reddetmek, standart ilk suç cezasını her zaman ikiye katlar.","Çünkü herhangi bir ilk suç DWI otomatik olarak ağır suç (felony) olarak işlem görür.","Çünkü cezalar yalnızca araçta 15 yaşından küçük bir çocuk varsa artar."],"explanation":"In Texas, penalties for a first DWI increase when the driver's BAC is 0.15% or higher, so Marcus's 0.16% reading means enhanced penalties. A child passenger under 15 (D) is a separate felony enhancement, but it does not apply here since Marcus was alone."},"21":{"q":"Partiden eve dönerken Marcus durdurulur ve kandaki alkol oranı (BAC) %0,10 olarak ölçülür. Bu onun ilk DWI (alkollü araç kullanma) suçudur, ancak arka koltukta 8 yaşındaki yeğeni emniyet kemeri takılı şekilde oturmaktadır. Yolcu olarak bir çocuğun bulunması bu suçun nasıl sınıflandırıldığını nasıl değiştirir?","options":["Suçlamayı hiçbir şekilde etkilemez çünkü bu yine de onun ilk suçudur","15 yaşından küçük bir çocuk yolcuyla alkollü araç kullanmak bu suçu ağır suç (felony) haline getirir","Açık kap kuralı uyarınca otomatik 180 günlük ehliyet askıya alma cezası ekler","Bir reşit olmayan kişi söz konusu olduğu için azami para cezasını 500 dolara çıkarır"],"explanation":"In Texas, DWI with a child passenger under age 15 is a felony, regardless of whether it is a first offense. The 180-day suspension belongs to refusing a chemical test, and the $500 figure is the fine for a minor's own first DUI, not a penalty tied to carrying a child passenger."},"22":{"q":"Teksas'ta bir sürücü kenara çekilir, ayıklık testini geçer ve kandaki alkol oranı (BAC) %0,05 çıkar, bu yüzden memur ona alkollü araç kullanma (DWI) suçlaması yöneltmez. Ancak memur, sürücünün yanındaki bardak tutucuda yarısı boş bir bira şişesi fark eder. Teksas yasaları, yolcu bölümündeki bu açık alkol kabını nasıl değerlendirir?","options":["Kandaki alkol oranı yasal sınır olan %0,08'in altında olduğu için göz ardı edilir.","Zımni rıza kapsamında ehliyetini otomatik olarak 180 gün boyunca askıya alır.","Herhangi bir DWI suçlamasından ayrı bir suçtur.","Yalnızca araçta 15 yaşından küçük bir çocuk varsa suç teşkil eder."],"explanation":"Having an open container of alcohol in the passenger area is a separate offense in Texas, independent of whether a DWI charge applies or what the driver's BAC was. The 180-day suspension relates to refusing a chemical test under implied consent, and the child-passenger rule concerns the felony DWI enhancement, not open containers."},"23":{"q":"Marcus 18 yaşında ve bir partiden eve giderken trafikte durduruluyor. Nefes testi %0,02 kan alkol düzeyi (BAC) gösteriyor ve reşit olmayan biri olarak ilk DUI (alkol) suçundan mahkum ediliyor. Ehliyet askıya alınması, kamu hizmeti ve alkol farkındalık kursunun yanı sıra, bu ilk suç için karşılaşabileceği azami para cezası nedir?","options":["2.000 dolara kadar, yetişkin bir kişinin ilk DWI cezasıyla aynı tutar","Hiç para cezası yok, çünkü BAC yetişkin sınırı olan %0,08'in altındaydı","1.000 dolara kadar, alkol tespit edildiği için iki katına çıkarılmış","500 dolara kadar"],"explanation":"Under Texas zero-tolerance law, a minor's first DUI (alcohol) carries a fine of up to $500, along with license suspension, community service, and an alcohol-awareness course. The $2,000 figure is the maximum for an adult first DWI, and no fine being charged is wrong because any detectable alcohol is illegal for a driver under 21."},"24":{"q":"Marcus 19 yaşında ve bir partiden eve dönerken kenara çekiliyor. Polis memuru alkol kokusu alıyor ve nefes testi %0,03 BAC gösteriyor. Bu Marcus'un alkolle ilgili ilk suçu. Teksas yasalarına göre sürüş ayrıcalıklarına ne olur?","options":["Ehliyeti askıya alınır, çünkü 21 yaşından küçük bir sürücüde tespit edilebilen herhangi bir alkol, askıya alma cezası gerektiren bir DUI'dir.","Ehliyetine bir şey olmaz, çünkü BAC değeri %0,08 yasal sınırının altındadır.","Nefes testini reddettiği için ehliyeti özellikle 180 gün askıya alınır.","BAC değeri ölçüldüğü için ağır suç suçlaması ve bir yıllık askıya alma cezasıyla karşı karşıyadır."],"explanation":"Texas has zero tolerance for drivers under 21, so any detectable alcohol (above 0.00%) is a DUI for a minor and carries a license suspension. The 0.08% limit (B) applies only to adults 21+, the 180-day suspension (C) is for refusing a test, and a felony (D) does not result from a minor's first DUI."},"25":{"q":"19 yasindaki Marcus, gece geç saatte Austin'de kenara cektirilir. Memur nefesinde az miktarda alkol tespit eder ve bir test 0,03% kandaki alkol oranini (BAC) dogrular. Bu onun ilk sucu. Teksas'in sifir tolerans yasasi uyarinca cezasi asagidakilerden hangisini icerecektir?","options":["Sadece yazili bir uyari, cunku BAC degeri yetiskin 0,08% sinirinin oldukca altindadir","500 dolara kadar para cezasi, ehliyet askiya alma, kamu hizmeti ve bir alkol farkindalik kursu","Bir yetiskin DWI'si gibi 180 gune kadar hapis ve 2000 dolar para cezasi","Nefes testini reddetmek icin otomatik 180 gunluk askiya alma"],"explanation":"Because Marcus is under 21, any detectable alcohol is a DUI by a minor under zero-tolerance, and a first offense carries a fine up to $500, license suspension, community service, and an alcohol-awareness course. The 0.08% adult limit and adult DWI jail/fine penalties do not apply to a minor's first DUI, and the 180-day suspension is for refusing the test, which he did not refuse."},"26":{"q":"19 yaşındaki Marcus, Austin'de bir partiden ayrılırken kenara çekiliyor. Nefes testi %0,03 BAC gösteriyor ve reşit olmayan biri olarak ilk DUI suçundan hüküm giyiyor. Texas sıfır tolerans yasasına göre, aşağıdakilerden hangisi cezasının zorunlu bir bileşenidir?","options":["Hiçbir şey, çünkü BAC değeri yetişkin sınırı olan %0,08'in altındaydı","Yalnızca nefes testi yaptırdığı için otomatik 180 günlük ehliyet askıya alma","Bir alkol farkındalık kursunu tamamlamak","Zorunlu asgari 3 gün hapis cezası"],"explanation":"A minor's first DUI for alcohol requires completion of an alcohol-awareness course (plus a fine up to $500, license suspension, and community service). Option A is wrong because under-21 zero tolerance makes ANY detectable alcohol illegal, and the 3-day jail minimum (D) and the 180-day suspension for refusing a test (B) belong to adult DWI and refusal rules, not a minor's first DUI."},"27":{"q":"Marcus son iki yılda üç hız ihlali ve bir kırmızı ışıkta geçme cezası aldı. Halihazırda ödediği para cezalarının ötesinde, bu hareketli ihlallerin Teksas sürücü siciline ne anlama geldiğinden endişe ediyor. Bu trafik mahkumiyetlerinin birikmesinin en doğru sonucu nedir?","options":["Para cezaları ödendikten sonra başka bir şey olmaz; ihlallerin sicile hiçbir etkisi yoktur.","Her mahkumiyet otomatik olarak SR-22 mali sorumluluk sigortası taşımasını gerektirir.","İhlaller ikinci cezadan sonra otomatik 180 günlük ehliyet askıya alınmasını tetikler.","İhlaller siciline puan ekler ve fazla olması ek ücretlere (surcharge) ve ehliyetin askıya alınmasına yol açabilir."],"explanation":"Traffic convictions add points to your Texas driving record, and accumulating too many can result in surcharges and license suspension. SR-22 is tied to serious offenses like a DWI rather than ordinary tickets, and the automatic 180-day suspension applies to refusing a breath/blood test under implied consent, not to routine moving violations."},"28":{"q":"Marcus, Teksas sürücü belgesiyle son iki yılda birkaç trafik mahkumiyeti biriktirdi. Son mahkeme duruşmasında hakim, mahkumiyet biriktirmeye devam etmenin ayrı para cezalarının ötesinde ek sonuçlar doğuracağı konusunda onu uyarır. Teksas puan/ek ücret (surcharge) sistemine göre, çok fazla mahkumiyet sonunda neye yol açabilir?","options":["Ek ücretlere (surcharges) ve sürücü belgesinin askıya alınmasına","Nefes testini reddetmek için otomatik 180 günlük askıya alınmaya","Yalnızca bir mahkumiyet açık alkol kabıyla ilgiliyse zorunlu SR-22 sigortasına","Tekrarlanan mahkumiyetler çocuklu DWI olarak işlem gördüğü için ağır ceza suçlamalarına"],"explanation":"Under the Texas point/surcharge system, traffic convictions add points to your record, and too many convictions can lead to surcharges and license suspension. The 180-day suspension applies specifically to refusing a breath or blood test (implied consent), not to accumulating ordinary convictions, so that option is a misplaced fact."},"29":{"q":"Marcus bir yıl önce Teksas'ta ilk alkollü araç kullanma (DWI) suçundan mahkum edildi. Şimdi ehliyet askı süresini tamamladı ve cezasını ödedi, ancak otomobil sigorta şirketi onu bıraktı ve bulabildiği tek poliçeler daha önce ödediğinin neredeyse üç katı fiyat veriyor. Dava bittikten bu kadar uzun süre sonra sürüş durumunun neden hala etkilendiğini sormak için DPS'yi arıyor. Alacağı en doğru açıklama nedir?","options":["Cezası ödenip askı süresi dolduğunda DWI otomatik olarak kaydından silinir, dolayısıyla yüksek ücretler ilgisiz bir faturalandırma hatasıdır.","DWI mahkumiyeti kaydında kalır ve sigorta maliyetlerini keskin biçimde artırır; ayrıca sürüş ayrıcalıklarını yeniden kazanmak için SR-22 mali sorumluluk sigortası taşıması gerekebilir.","Yüksek maliyet, yalnızca nefes testini reddetmesine bağlı geçici 180 günlük bir ek ücrettir ve bu süre bittiğinde ortadan kalkacaktır.","Kaydında artık DWI görünüyor, ancak Teksas'taki sigortacıların tek bir ilk suça dayanarak ücretleri artırması yasal olarak yasaktır."],"explanation":"A DWI conviction stays on the driver's record and sharply raises insurance costs, and an SR-22 financial responsibility filing may be required to reinstate driving privileges. Option A is wrong because completing penalties does not erase the conviction, and option C confuses this with the separate 180-day ALR suspension for refusing a test."},"30":{"q":"Marcus, ilk DWI (alkollü araç kullanma) mahkumiyeti için mahkeme cezasını tamamladı ve bir yıllık ehliyet askıya alma süresi artık sona erdi. Sürüş ayrıcalıklarını yeniden kazanmak için DPS ofisine gittiğinde, memur ona önce ileriye dönük yeterli sorumluluk teminatına sahip olduğunu kanıtlayan belirli bir formu doldurması gerektiğini söyler. Bu gerekliliğin adı nedir?","options":["Yolcu bölümünde alkol bulundurmadığını gösteren açık kap beyanı","Gelecekteki nefes veya kan testlerini kabul eden bir zımni rıza feragatnamesi","SR-22 mali sorumluluk sigortası","Alkol farkındalık kursu tamamlama belgesi"],"explanation":"After a DWI, Texas may require SR-22 financial responsibility insurance to prove coverage before driving privileges are reinstated. The alcohol-awareness course is tied to a minor's DUI penalty, not the insurance reinstatement requirement, and implied consent and open container are unrelated to proving financial responsibility."},"31":{"q":"28 yaşındasınız ve bir arkadaşınızın evinde akşam yemeğiyle birlikte iki bira içtiniz. Kendinizi gayet iyi hissediyorsunuz ve sakin yollardan eve 25 dakikalık bir yolculuğunuz var. En güvenli seçim hangisidir?","options":["Eve sürün, çünkü iki içki bir yetişkini her zaman 0,08% yasal sınırın altında tutar","Yaklaşık 20 dakika bekleyin, biraz kahve için ve kendinizi zinde hissedince sürün","Şimdi sürün, çünkü muhakemeniz gözle görülür şekilde etkilenmedikçe yasal olarak sarhoş sayılmazsınız","Hiç araç kullanmayın; bir taksi hizmeti ayarlayın, ayık bir sürücü bulun ya da olduğunuz yerde kalın"],"explanation":"The safest choice is always zero alcohol before driving, so arranging a sober ride or staying put is correct. Two beers will not reliably keep you under 0.08%, and only time (not coffee) lowers BAC, so the other options are dangerous mistakes."},"32":{"q":"İş çıkışı arkadaşlarınızla bir barda buluşuyorsunuz ve iki saat içinde birkaç içki içiyorsunuz. Alkolün etkisini hissediyorsunuz ve eve güvenli bir şekilde araç kullanacak durumda olmadığınızı biliyorsunuz. Eve gitmek için en güvenli yol nedir?","options":["Bir taksi/araç çağırma hizmetini arayın, anahtarlarınızı içki içmemiş bir arkadaşınıza verin ya da ayılana kadar olduğunuz yerde kalın","Birkaç fincan sert kahve için ve eve gitmeden önce yaklaşık 30 dakika bekleyin","Araç kullanmadan önce daha hızlı ayılmak için doyurucu bir yemek yiyin ve soğuk bir duş alın","Arabanızda otururken her içki için bir saat bekleyin, sonra kendiniz eve gidin"],"explanation":"The safe, always-true choices are to use a ride service, designate a sober driver, or stay put until sober. Coffee, food, and a cold shower do NOT speed up sobering; only time lowers BAC, and the answer to alcohol is not to drive at all rather than wait it out in your car and then drive."},"33":{"q":"Marcus 24 yaşında ve bir akşam yemeği partisinden sonra kendi arabasıyla eve gidiyor. Bir polis memuru onu durduruyor ve nefes testi BAC değerinin tam olarak %0,08 olduğunu gösteriyor. Bu değerde Marcus, Texas yasalarına göre hukuken ne olarak kabul edilir?","options":["Yasal sınırın altındadır çünkü %0,08 eşiği yalnızca ticari sürücüler için geçerlidir","Sarhoş Araç Kullanma (DWI) suçunu işlemektedir, çünkü 21 yaş ve üzeri yetişkinler için %0,08 ve üzeri BAC yasal eşiktir","Yalnızca gözle görülür sarhoşluk belirtileri de gösterirse suçludur, çünkü tek başına %0,08 yeterli değildir","Sıfır Tolerans kapsamında DUI suçunu işlemiştir, çünkü tespit edilebilir herhangi bir miktarda alkol yasa dışıdır"],"explanation":"For adults 21 and older, driving at or above 0.08% BAC is Driving While Intoxicated (DWI), so Marcus's exact 0.08% reading meets the threshold. The 0.04% commercial limit and the Zero Tolerance rule for drivers under 21 do not apply to a 24-year-old in his personal vehicle, and no additional visible impairment is required at or above 0.08%."},"34":{"q":"Marcus 19 yaşında. Bir mezuniyet partisinden sonra kenara çekilir ve nefes testi %0,03 BAC (kandaki alkol seviyesi) gösterir. Okuması yetişkin %0,08 sınırının çok altında olduğu için suçlanamayacağını savunuyor. Texas yasalarına göre durumu hakkında doğru olan nedir?","options":["Haklı; %0,03, %0,08 DWI sınırının altında olduğu için herhangi bir suçlama uygulanmaz.","Yalnızca BAC'si ticari sürücü sınırı olan %0,04'e ulaşırsa suçlanabilir.","21 yaşının altında olduğu için Sıfır Tolerans uygulanır, bu nedenle tespit edilebilir herhangi bir alkol bunu reşit olmayan biri tarafından DUI haline getirir.","%0,03 reşit olmayan biri için yüksek BAC sayıldığından ağır suç DWI suçlamasıyla karşı karşıyadır."],"explanation":"Texas Sıfır Tolerans politikası, 21 yaşından küçük sürücüler için tespit edilebilir herhangi bir alkolü (%0,00'ın üzerinde BAC) yasadışı kılar, bu nedenle Marcus %0,08'in altında olmasına rağmen reşit olmayan biri olarak DUI ile suçlanır. Yetişkin %0,08 ve ticari %0,04 sınırları reşit olmayanlara uygulanmaz ve %0,03 yüksek BAC ağır suç durumu değildir."},"35":{"q":"Maria, Austin'de şeritler arasında savrulduğu için durduruldu. Bu, hayatındaki ilk DWI (alkollü araç kullanma) tutuklaması, kan alkol düzeyi (BAC) %0,10 ölçüldü ve 9 yaşındaki yeğeni arka koltukta kemeri takılı oturuyor. Çocuğun varlığı, DWI suçunun hukuki ağırlığını nasıl değiştirir?","options":["Hiçbir şey değişmez; çocuk yolcu yalnızca para cezası tutarını etkiler ve bu en fazla 2.000 dolara yükselir","Araçta bir çocuk bulunduğu için ehliyeti otomatik olarak 180 gün askıya alınır","Standart bir ilk suç kabahati olarak kalır, ancak ayrıca bir alkol farkındalık kursunu tamamlaması gerekir","15 yaşından küçük bir çocuk yolcu bulunduğu için suç, kabahat düzeyinden ağır suç (felony) düzeyine yükseltilir"],"explanation":"Under Texas law, a DWI committed with a child passenger younger than 15 in the vehicle is elevated to a felony, regardless of it being a first offense. Option B confuses this with the 180-day ALR suspension for refusing a chemical test, and the $2,000 fine in A is the standard first-offense misdemeanor penalty, not the felony enhancement triggered by the child."},"36":{"q":"Austin'de alkollü araç kullanmaktan (DWI) yasal olarak tutuklandınız. Memur sizden nefes testi yapmanızı istiyor, ancak siz reddedip yalnızca kan örneği vermeyi kabul edeceğinizi söylüyorsunuz. Teksas örtülü rıza yasasına göre durumunuzla ilgili doğru olan nedir?","options":["Teksas'ta araç kullanarak nefes VEYA kan testine örtülü rıza vermiş olursunuz, bu nedenle test türü tek bir testle sınırlı değildir; istenen testi reddetmek otomatik ehliyet askıya alınmasını tetikleyebilir.","Örtülü rıza yalnızca nefes testini kapsar, bu yüzden ceza olmadan onun yerine kan testi talep etme hakkınız vardır.","Örtülü rıza yalnızca kan testine uygulanır, bu yüzden nefes testini reddetmenin hiçbir sonucu yoktur.","Bir alternatif sunduğunuz için karaciğer alkolü bir saat içinde işleyecek ve teste gerek kalmayacak."],"explanation":"Texas implied consent covers a breath OR blood test, not just one type, so you can't limit it to your preferred test; refusing the lawfully requested test triggers an automatic 180-day suspension under ALR. Options B and C wrongly restrict implied consent to a single test type, and D confuses the unrelated fact that the liver processes about one drink per hour."},"37":{"q":"Akşam yemeğinde birkaç bira içtikten sonra bir sürücü, karşıdan gelen farların artık bulanık göründüğünü ve şeridinin kenarlarını ve kaldırımdan inen bir yayayı görmekte zorlandığını fark ediyor. Direksiyon başında yaşadığı durumu en iyi hangi alkol etkisi açıklar?","options":["Alkol odaklanmayı keskinleştiren bir uyarıcı gibi davranır, bu yüzden bulanıklık alkolden değil farlarından kaynaklanıyor olmalı","Alkol, görüşü azaltan bir depresandır; nesnelerin net görülmesini zorlaştırır ve fark edebildiği alanı daraltır","Alkol görüşü yalnızca sürücü yasal sınır olan %0,08'in üzerine çıktığında etkiler, bu yüzden bunun altında görüşü etkilenmez","Alkol tepki süresini hızlandırır, bu da yalnızca yüksek hızda yakındaki nesnelerin bulanık görünmesine neden olur"],"explanation":"Alcohol is a depressant that reduces vision among the abilities it impairs, so blurry headlights and trouble seeing the lane and pedestrian are direct effects of the alcohol. Option C is wrong because alcohol can impair vision and driving even below 0.08%, and A and D misstate alcohol as a stimulant or claim it speeds reaction time, when it actually slows reactions."},"38":{"q":"Bir arkadaşının evinde üç bira içtikten sonra Marcus direksiyon başına geçer. Eve giderken sürekli şeridinden kaydığını ve küçük direksiyon düzeltmeleri yapmaya çalıştığında ellerinin beceriksiz ve yavaş hissettirdiğini fark eder. Alkolün vücudu üzerindeki hangi etkisi, direksiyon kullanımının özensiz ve hatalı hale gelmesini en iyi açıklar?","options":["Alkol tepki süresini hızlandırır, bu yüzden direksiyonu aşırı düzeltiyor","Alkol bir uyarıcı gibi davranarak kaslarını gergin ve sarsıntılı yapar","Alkol koordinasyonunu azaltır, bu da yumuşak ve hassas direksiyon kullanımını zorlaştırır","Alkol etkisini yitirdi çünkü üç bira yasal sınırın altındadır"],"explanation":"Alcohol is a depressant that reduces coordination, which is exactly why smooth, precise steering becomes difficult. Option A is wrong because alcohol slows reaction time rather than speeding it up, and option B is wrong because alcohol is a depressant, not a stimulant."},"39":{"q":"Bir memur, gece geç saatte şeritler arasında zikzak çizdiği için Marcus'u kenara çeker. Saha ayıklık testlerinden sonra memur, Marcus'u alkollü araç kullanmaktan (DWI) yasalara uygun şekilde tutuklar ve ardından ondan bir nefes örneği vermesini ister. Teksas zımni rıza yasasına göre, memurun bu nefes testini talep etmesini yasal kılan şey neydi?","options":["Marcus'un kandaki alkol oranı, herhangi bir tutuklamadan önce zaten %0,08 veya üzerinde ölçülmüştü","Marcus, sürücü belgesini yenilerken bir zımni rıza feragatnamesi imzaladı","Memur, Marcus'un şeritler arasında zikzak çizdiğini gördü ki bu tek başına bir testi zorunlu kılmaya yeter","Marcus, alkollü araç kullanmaktan (DWI) yasalara uygun şekilde tutuklandı; bu da nefes veya kan testine zımni rızayı tetikler"],"explanation":"In Texas, the lawful trigger for implied consent testing is being lawfully arrested for DWI, so option D is correct. Observing bad driving (C) may justify the stop or arrest but does not by itself compel a test, and there is no separately signed waiver at license renewal (B)."}},"learn-alcohol-and-penalties":{"0":{"q":"Teksas'ta, 21 yaşında veya daha büyük bir yetişkin sürücü için DWI'nin kan alkol (BAC) sınırı nedir?","options":["%0,08","%0,04","%0,10","%0,05"],"explanation":"In Texas, an adult age 21 or older is legally intoxicated (DWI) at a BAC of 0.08% or higher."},"1":{"q":"Teksas'ta kandaki alkol oranı %0,08 veya üzeriyle araç kullanmak hangi suçtur?","options":["Hız sınırını aşma","Sarhoş Araç Kullanma (DWI)","Dikkatsiz araç kullanma","Açık kap ihlali"],"explanation":"Driving at or above 0.08% BAC is the offense called Driving While Intoxicated (DWI)."},"2":{"q":"Bir sürücü kandaki alkol oranı (BAC) %0,08'in altındaysa DWI ile suçlanabilir mi?","options":["Hayır, %0,08'in altında asla","Yalnızca ticari sürücüler","Evet, alkol veya uyuşturucu etkisindeyse","Yalnızca testi reddederse"],"explanation":"A driver can still be charged with DWI below 0.08% BAC if impaired by alcohol or drugs."},"3":{"q":"Teksas'ta ticari sürücü için kandaki alkol seviyesi (BAC) sınırı nedir?","options":["%0,08","%0,10","%0,02","%0,04"],"explanation":"A commercial driver's BAC limit is 0.04%, lower than the standard adult limit of 0.08%."},"4":{"q":"Teksas'ta 21 yaşından küçük bir sürücü için yasal kandaki alkol sınırı nedir?","options":["0,00'ın üzerindeki herhangi bir miktar yasa dışıdır","0,08 BAC","0,04 BAC","0,05 BAC"],"explanation":"Texas uses Zero Tolerance, so any detectable alcohol (a BAC above 0.00) is illegal for a driver under 21."},"5":{"q":"Bir reşit olmayan kişi, tespit edilebilir herhangi bir miktarda alkolle araç kullanarak ne işler?","options":["Yasa dışı bir şey değil","Reşit olmayan kişinin alkollü araç kullanması (DUI)","Park ihlali","Ticari DWI"],"explanation":"Under Texas Zero Tolerance, any detectable alcohol means a minor commits DUI of alcohol by a minor."},"6":{"q":"Teksas'ta bir reşit olmayan için DUI ne anlama gelir?","options":["Kapalı alanda güvensiz sürüş","Sigorta altında sürüş","Etkisi altında araç kullanma (Driving Under the Influence)","Niyetle araç kullanma"],"explanation":"DUI stands for Driving Under the Influence, the offense used for minors, distinct from the adult DWI."},"7":{"q":"Teksas'ta Sıfır Tolerans yasası, kaç yaşından küçük sürücüler için geçerlidir?","options":["16 yaşından","18 yaşından","25 yaşından","21 yaşından"],"explanation":"Texas's Zero Tolerance law makes any detectable alcohol illegal for drivers under 21 years of age."},"8":{"q":"Alkol ne tür bir maddedir?","options":["Bir yatıştırıcı (depresan)","Bir uyarıcı","Bir ağrı kesici","Bir vitamin"],"explanation":"Alcohol is a depressant that slows your reaction time and impairs your judgment."},"9":{"q":"Alkol bir sürücünün tepki süresini nasıl etkiler?","options":["Hızlandırır","Yavaşlatır","Hiçbir etkisi yoktur","İyileştirir"],"explanation":"Alcohol is a depressant that slows your reaction time."},"10":{"q":"Araç kullanırken alkol neyi bozar?","options":["Yakıt seviyenizi","Lastik basıncınızı","Muhakemenizi","Farlarınızı"],"explanation":"Alcohol impairs judgment, which is the first driving ability affected."},"11":{"q":"Alkol bir sürücünün koordinasyonuna ne yapar?","options":["Koordinasyonu keskinleştirir","Koordinasyon üzerinde hiçbir etkisi yoktur","Koordinasyonu yalnızca geceleri etkiler","Koordinasyonu azaltır"],"explanation":"Alcohol is a depressant that reduces a driver's coordination."},"12":{"q":"Alkol bir sürücünün görüşünü nasıl etkiler?","options":["Görüşü azaltır","Görüşü iyileştirir","Görüş üzerinde etkisi yoktur","Gece görüşünü keskinleştirir"],"explanation":"Alcohol reduces vision, making it harder to see clearly while driving."},"13":{"q":"Alkol sürüş yeteneklerinden ilk olarak hangisini etkiler?","options":["Görme","Muhakeme","İşitme","Direksiyon tutuşu"],"explanation":"Alcohol affects judgment before other driving abilities."},"14":{"q":"Kandaki alkol konsantrasyonunu (BAC) düşüren tek şey nedir?","options":["Kahve içmek","Soğuk duş almak","Zamanın geçmesi","Doyurucu bir yemek yemek"],"explanation":"Only the passage of time lowers BAC; coffee, food, and showers do not speed it up."},"15":{"q":"Kandaki alkol seviyesini düşüren tek şey nedir?","options":["Kahve içmek","Doyurucu bir yemek yemek","Soğuk duş almak","Beklemek ve zamanın geçmesini sağlamak"],"explanation":"Only time lowers your BAC; coffee, food, and showers do not speed up sobering."},"16":{"q":"Kandaki alkol düzeyini (BAC) düşüren tek şey nedir?","options":["Zaman","Yemek yemek","Kahve içmek","Soğuk duş almak"],"explanation":"Only time lowers BAC; food, coffee, and showers do not speed up sobering."},"17":{"q":"Bir kişinin kandaki alkol konsantrasyonunu (BAC) düşüren tek şey nedir?","options":["Kahve içmek","Zaman","Soğuk duş","Temiz hava"],"explanation":"Only time lowers BAC; coffee, a cold shower, and fresh air do not speed up sobering."},"18":{"q":"Kandaki alkol seviyesini düşüren tek şey nedir?","options":["Temiz hava","Kahve içmek","Zaman","Soğuk duş"],"explanation":"Only time lowers BAC; fresh air, coffee, and a cold shower do not speed up sobering."},"19":{"q":"Karaciğeriniz bir saatte yaklaşık ne kadar alkol işler?","options":["Yaklaşık dört içki","Yaklaşık üç içki","Yaklaşık iki içki","Yaklaşık bir içki"],"explanation":"The liver processes about one standard drink per hour, and nothing can speed it up."},"20":{"q":"Herhangi bir sey karacigerin alkolu normal hizindan daha hizli islemesini saglayabilir mi?","options":["Hayir, hicbir sey hizlandirmaz","Evet, kahve icmek","Evet, soguk dus","Evet, yemek yemek"],"explanation":"Nothing can make the liver process alcohol faster than its normal rate."},"21":{"q":"İlaçları alkolle birleştirdiğinizde ne olur?","options":["Alkolün etkisini ortadan kaldırır","Bozulmayı kat kat artırır","Ayılmayı hızlandırır","Hiçbir etkisi yoktur"],"explanation":"Mixing drugs (illegal, prescription, or over-the-counter) with alcohol multiplies impairment."},"22":{"q":"Reçeteli veya reçetesiz ilaçlar alkolle birlikte alındığında bozulmayı artırabilir mi?","options":["Hayır, sadece yasa dışı uyuşturucular","Hayır, alkolü etkisiz kılarlar","Evet, bozulmayı kat kat artırabilirler","Hayır, hiçbir etkisi yoktur"],"explanation":"Even prescription and over-the-counter drugs can multiply impairment when combined with alcohol."},"23":{"q":"Texas'ta, DWI nedeniyle yasal olarak tutuklanırsanız araç kullanarak neyi kabul etmiş olursunuz?","options":["Görme testini","Sürüş sınavını","İşitme testini","Nefes veya kan testini"],"explanation":"By driving in Texas you give implied consent to a breath or blood test if lawfully arrested for DWI."},"24":{"q":"Teksas'ta zımni rıza hangi teste uygulanır?","options":["Nefes veya kan testi","Görme testi","İşitme testi","Yazılı test"],"explanation":"By driving in Texas, you give implied consent to a breath or blood test if lawfully arrested for DWI."},"25":{"q":"Teksas'ta teste zımni rıza ne zaman geçerlidir?","options":["Bir sürücü hız sınırını aştığı için durdurulduğunda","Bir sürücü alkollü araç kullanmaktan yasal olarak tutuklandığında","Bir sürücü hatalı park ettiğinde","Bir sürücü ehliyetini yenilediğinde"],"explanation":"By driving in Texas you give implied consent to a breath or blood test if you are lawfully arrested for DWI."},"26":{"q":"Nefes veya kan testini reddetmek, ilk reddetme için kaç günlük otomatik ehliyet askıya alınmasına neden olur?","options":["30 gün","90 gün","180 gün","365 gün"],"explanation":"A first refusal of the breath or blood test results in an automatic 180-day license suspension."},"27":{"q":"Testi reddetmek için otomatik ehliyet askıya alma hangi yasa kapsamında uygulanır?","options":["Zımni Rıza İptal Yasası","Açık Kap Yasası","Sıfır Tolerans Yasası","İdari Ehliyet İptali (ALR)"],"explanation":"Refusing a breath or blood test triggers an automatic license suspension under Administrative License Revocation (ALR)."},"28":{"q":"Testi reddetmek için uygulanan ALR ehliyet askıya alması, DWI mahkumiyet cezalarından ayrı mıdır?","options":["Evet, ayrıdır","Hayır, onların yerine geçer","Hayır, yalnızca mahkum olunursa","Evet, ama yalnızca reşit olmayanlar için"],"explanation":"The ALR suspension for refusing a test is separate from any DWI conviction penalties."},"29":{"q":"Teksas'ta ilk alkollü araç kullanma (DWI) suçunun azami para cezası nedir?","options":["500 dolara kadar","2.000 dolara kadar","5.000 dolara kadar","10.000 dolara kadar"],"explanation":"A first DWI in Texas carries a fine of up to $2,000."},"30":{"q":"Teksas'ta ilk DWI ne kadar hapis cezası getirebilir?","options":["1 ila 30 gün","2 ila 90 gün","3 gün ila 180 gün","5 gün ila 365 gün"],"explanation":"A first DWI in Texas carries jail time of 3 days to 180 days."},"31":{"q":"Teksas'ta ilk alkollü araç kullanma (DWI) suçunun asgari hapis cezası nedir?","options":["30 gün","10 gün","1 gün","3 gün"],"explanation":"A first DWI in Texas carries a minimum jail time of 3 days."},"32":{"q":"Teksas'ta ilk DWI (alkollü araç kullanma) suçunda azami hapis süresi nedir?","options":["180 gün","30 gün","1 yıl","10 gün"],"explanation":"A first DWI in Texas carries a maximum jail term of 180 days."},"33":{"q":"Teksas'ta ilk DWI (alkollü araç kullanma) için ehliyetiniz ne kadar süreyle askıya alınabilir?","options":["30 güne kadar","1 yıla kadar","5 yıla kadar","Hiçbir zaman askıya alınmaz"],"explanation":"A first DWI in Texas carries a license suspension of up to 1 year."},"34":{"q":"Teksas'ta tekrarlanan alkollü araç kullanma (DWI) suçları için cezalara ne olur?","options":["Kaldırılırlar","Aynı kalırlar","Artarlar","İsteğe bağlı olurlar"],"explanation":"In Texas, penalties increase for repeat DWI offenses."},"35":{"q":"Teksas'ta hangi BAC (kandaki alkol oranı) seviyesi DWI cezalarını artıracak kadar yüksektir?","options":["%0,04 veya üzeri","%0,06 veya üzeri","%0,08 veya üzeri","%0,15 veya üzeri"],"explanation":"A high BAC of 0.15% or above increases the penalties for DWI."},"36":{"q":"Teksas'ta hangi yüksek BAC seviyesi DWI cezalarını artırır?","options":["%0,15","%0,08","%0,04","%0,02"],"explanation":"A BAC of 0.15% or higher increases the penalties for a Texas DWI."},"37":{"q":"Teksas'ta ilk suçta alkollü araç kullanma cezalarını ne artırır?","options":["Yavaş sürmek","Çocuk yolcu bulunması","Emniyet kemeri takmak","Gece araç kullanmak"],"explanation":"Penalties increase when there is a child passenger in the vehicle."},"38":{"q":"Teksas'ta, araçta 15 yaşından küçük bir çocukla alkollü araç kullanmak (DWI) nedir?","options":["Sadece bir uyarı","Bir park cezası","Bir ağır suç (felony)","Bir suç değil"],"explanation":"In Texas, driving while intoxicated with a child under 15 in the vehicle is a felony."},"39":{"q":"Teksas'ta, araçta hangi yaşın altında bir çocuk yolcu varsa alkollü araç kullanmak (DWI) ağır suç (felony) hâline gelir?","options":["8 yaşın altında","10 yaşın altında","12 yaşın altında","15 yaşın altında"],"explanation":"In Texas, DWI with a child passenger under 15 years old is a felony."},"40":{"q":"Teksas'ta, yolcu bölümünde açık bir alkol kabı bulundurmak ayrı bir suç mudur?","options":["Evet, bu ayrı bir suçtur","Hayır, her zaman serbesttir","Sadece yolcular için, asla sürücü için değil","Sadece otoyollarda"],"explanation":"In Texas, having an open container of alcohol in the passenger area is a separate offense."},"41":{"q":"Araçta açık alkol kabı suçu nerede geçerlidir?","options":["Sadece bagajda","Yolcu bölümünde","Tavanda","Kaputun altında"],"explanation":"The open container offense applies to alcohol in the passenger area of the vehicle."},"42":{"q":"Teksas'ta bir reşit olmayanın ilk alkollü araç kullanma (DUI) suçunun azami para cezası nedir?","options":["$100'a kadar","$250'ye kadar","$500'e kadar","$2.000'e kadar"],"explanation":"A minor's first DUI for alcohol carries a fine of up to $500."},"43":{"q":"Bir reşit olmayanın alkolle ilgili ilk DUI suçu neyi içerir?","options":["Hiçbir ceza yok","Sadece bir uyarı mektubu","Ücretsiz bir sürüş dersi","Ehliyetin askıya alınması"],"explanation":"A minor's first DUI for alcohol includes a license suspension."},"44":{"q":"Teksas'ta bir reşit olmayanın ilk DUI (alkol) cezalarından biri nedir?","options":["Toplum hizmeti","Ücretsiz sürücü kursu","Yeni ehliyet indirimi","Fazla ehliyet puanlarının silinmesi"],"explanation":"A minor's first alcohol DUI in Texas includes community service."},"45":{"q":"Teksas'ta bir reşit olmayan, alkolden dolayı ilk DUI'den sonra neyi tamamlamak zorundadır?","options":["Güvenli sürüş kursu","Alkol farkındalığı kursu","Görme muayenesi","İlk yardım kursu"],"explanation":"A minor's first alcohol DUI requires completing an alcohol-awareness course."},"46":{"q":"Trafik mahkumiyetleri sürücü kaydınıza ne ekler?","options":["Ücretsiz sürüş dersleri","Ekstra ehliyet yılları","Puan","Nakit ödüller"],"explanation":"Traffic convictions add points to your driving record."},"47":{"q":"Çok fazla trafik mahkumiyeti neye yol açabilir?","options":["Daha düşük sigorta ücretleri","Ücretsiz bir sürüş kursu","Fazladan ehliyet puanlarının silinmesi","Ek ücretler (surcharge)"],"explanation":"Too many convictions can lead to surcharges and even license suspension."},"48":{"q":"Çok fazla trafik cezası neye yol açabilir?","options":["Ehliyetin askıya alınması","Ücretsiz ehliyet yenileme","Daha fazla sürüş ayrıcalığı","Daha düşük sigorta maliyetleri"],"explanation":"Too many convictions can add surcharges and lead to license suspension."},"49":{"q":"Teksas'ta bir DWI mahkumiyetine zamanla ne olur?","options":["Bir ay sonra silinir","Sicilinizde kalır","Para cezasını ödediğinizde kaybolur","Bir güvenli yolculuktan sonra kaldırılır"],"explanation":"A DWI conviction stays on your record and raises your insurance costs."},"50":{"q":"Alkollü araç kullanma (DWI) mahkumiyeti araba sigortası maliyetinizi nasıl etkiler?","options":["Düşürür","Hiçbir etkisi yoktur","Keskin şekilde yükseltir","Tüm ücretleri iptal eder"],"explanation":"A DWI conviction stays on your record and sharply raises insurance costs."},"51":{"q":"Teksas'ta sürüş ayrıcalıklarınızı geri kazanmak için hangi sigorta gerekebilir?","options":["Seyahat sigortası","Evcil hayvan sigortası","Sağlık sigortası","SR-22 mali sorumluluk sigortası"],"explanation":"SR-22 financial responsibility insurance may be required to reinstate your driving privileges."},"52":{"q":"SR-22 nedir?","options":["Bir mali sorumluluk sigortası türü","Bir tür sürücü belgesi","Bir trafik cezası","Bir kan alkol testi"],"explanation":"SR-22 is a form of financial responsibility insurance that may be required to reinstate driving privileges."},"53":{"q":"Araç kullanmadan önce içilebilecek en güvenli alkol miktarı nedir?","options":["Bir içki","Sıfır alkol","İki içki","Bir bira"],"explanation":"The safest choice is zero alcohol before driving."},"54":{"q":"İçtikten sonra araç kullanmaktan nasıl kaçınabilirsiniz?","options":["Önce kahve için","Yavaş sürün","Ayık bir sürücü belirleyin","Pencereleri açın"],"explanation":"Choosing a sober driver lets you avoid driving after drinking."},"55":{"q":"İçki içip araç kullanmaktan kaçınmak için neyi kullanabilirsiniz?","options":["Bir fincan kahve","Soğuk bir duş","Temiz hava","Bir taşıma hizmeti"],"explanation":"Using a ride service lets you avoid drinking and driving."},"56":{"q":"İçki içip araç kullanmaktan kaçınmanın bir yolu nedir?","options":["Araç kullanmak yerine olduğunuz yerde kalın","Çok yavaş araç kullanın","Önce biraz su için","Araba camlarını açın"],"explanation":"Staying put instead of driving keeps you from drinking and driving."},"57":{"q":"Teksas'ta 21 yaşından küçük bir sürücü için hangi kandaki alkol seviyesi yasa dışıdır?","options":["%0,08 veya daha yüksek","0,00'ın üzerindeki herhangi bir miktar","%0,04 veya daha yüksek","%0,15 veya daha yüksek"],"explanation":"Texas has zero tolerance, so any detectable alcohol above 0.00 is illegal for a minor."},"58":{"q":"Alkol bir depresandır, peki vücuda ne yapar?","options":["Tepki süresini hızlandırır","Koordinasyonu iyileştirir","Vücut işlevlerini yavaşlatır","Görüşü keskinleştirir"],"explanation":"As a depressant, alcohol slows down the body's functions instead of stimulating them."},"59":{"q":"Teksas'ta ilk DWI (alkollü araç kullanma) mahkumiyeti için maksimum para cezası nedir?","options":["200 dolar","500 dolar","1.000 dolar","2.000 dolar"],"explanation":"A first DWI conviction in Texas carries a fine of up to $2,000."}}},"es":{"road-signs":{"0":{"q":"Al anochecer, se acerca a una intersección donde la señal que está frente a usted está muy descolorida y ya no puede leer ninguna de sus letras. Aun así, puede ver claramente que la señal tiene ocho lados. ¿Qué debe hacer en esta intersección?","options":["Detenerse por completo, porque una señal de ocho lados (octagonal) siempre significa PARE (ALTO).","Reducir la velocidad y ceder el paso, deteniéndose solo si hay otro tráfico presente.","Reducir la velocidad y avanzar con precaución, ya que la forma solo advierte de un peligro más adelante.","Tratarla como un cruce escolar y estar atento a niños que entren a la vía."],"explanation":"The octagon is the only eight-sided sign and always means STOP, so the shape alone tells you to come to a full stop even when the lettering is unreadable. Yielding is signaled by an inverted triangle, not an octagon, which makes that option the trap."},"1":{"q":"Está incorporándose a una autopista desde una rampa de acceso y ve frente a usted una señal roja y blanca con forma de triángulo invertido (con la punta hacia abajo). ¿Qué le exige hacer esta señal?","options":["Detenerse por completo y permanecer detenido hasta que la autopista esté vacía en ambos sentidos","Ceder el paso al tránsito de la autopista, reduciendo la velocidad o deteniéndose solo si es necesario para hacerlo con seguridad","Continuar a la velocidad máxima indicada porque usted tiene la preferencia al incorporarse","Tratarla como una advertencia de un peligro adelante y continuar con precaución sin ceder el paso"],"explanation":"An inverted triangle is a YIELD sign: you must give the right of way to traffic already on the highway and slow or stop only if needed to merge safely. A full stop every time (A) describes an octagonal STOP sign, and a diamond-shaped warning sign (D) does not require yielding the right of way."},"2":{"q":"Conduce por una carretera rural de dos carriles y quiere adelantar a un tractor lento que va adelante. Justo antes de salir al otro carril, nota una señal con forma de triángulo acostado de lado (con una punta horizontal) colocada en el arcén IZQUIERDO de la carretera. ¿Qué le indica esta señal?","options":["Ceda el paso al tráfico que viene en sentido contrario antes de volver a su carril","Hay una zona escolar o un cruce escolar adelante, reduzca la velocidad","Está entrando en una Zona de No Rebasar y no debe adelantar al tractor aquí","Hay un peligro o una condición adelante, reduzca la velocidad y proceda con precaución"],"explanation":"A pennant (a horizontal triangle) posted on the LEFT side of the road marks a No Passing Zone, so you must not pass the tractor. A yield is an inverted (upside-down) triangle, and a diamond is the warning shape, so those options confuse other sign shapes with the pennant."},"3":{"q":"Conduce por una carretera de dos carriles desconocida al anochecer. Más adelante, en el arcén derecho, ve una señal amarilla en forma de rombo, pero aún está demasiado lejos para leer las palabras o el símbolo impreso en ella. Basándose únicamente en su forma, ¿qué debe entender de inmediato?","options":["Es una señal reglamentaria que indica una ley que debe obedecer, como un límite de velocidad","Marca una zona escolar o un cruce escolar más adelante","Es una señal informativa que da direcciones o distancias hasta el próximo pueblo","Es una señal de advertencia que le avisa de un peligro o un cambio en las condiciones de la carretera más adelante"],"explanation":"A diamond shape always means a warning sign, telling you a hazard or condition lies ahead. Regulatory laws use vertical rectangles (A) and guide/direction information uses horizontal rectangles (C), while school zones use a pentagon (B)."},"4":{"q":"Mientras conduce por una zona residencial desconocida, ve una señal de cinco lados, de color amarillo-verde, con la punta hacia arriba. Según su forma únicamente, ¿de qué le advierte esta señal?","options":["Se está acercando a una zona escolar o un cruce escolar","Hay un cruce de ferrocarril más adelante","Está entrando en una zona de prohibido adelantar","Hay un peligro o condición general más adelante"],"explanation":"A pentagon (5-sided, point up) shape always means a school zone or school crossing. A round sign warns of a railroad crossing ahead, so option B confuses two different sign shapes."},"5":{"q":"Conduce por una carretera rural de dos carriles y observa en el arcén derecho una señal redonda de color amarillo con una 'X' negra y las letras 'RR', colocada mucho antes de que se vean las vías. ¿Qué le está indicando esta señal?","options":["Ha llegado a las vías mismas y debe detener su vehículo sobre ellas","Hay un cruce ferroviario más adelante, así que prepárese para reducir la velocidad y vigilar los trenes","Está entrando en una zona escolar y debe reducir la velocidad por los niños","Esta es una zona de prohibido adelantar y no puede adelantar a otros vehículos aquí"],"explanation":"A round (circular) sign is the advance warning that a railroad crossing lies ahead, so you should slow down and watch for trains. The crossing itself is marked by the X-shaped Crossbuck (not this round sign), and the pentagon shape, not the circle, signals a school zone."},"6":{"q":"Conduce por una carretera rural y se acerca a las vías del tren propiamente dichas, donde ve una señal blanca en forma de X con las palabras 'CRUCE FERROVIARIO'. En este cruce no hay señal de alto, ni barrera, ni luces intermitentes. ¿Cómo debe interpretar esta señal?","options":["Detenerse por completo cada vez, porque la señal en forma de X funciona legalmente como una señal de alto","Ignorarla a menos que se vea un tren, porque la cruz de San Andrés es solo una advertencia previa colocada antes de las vías","Tratarla como una señal de ceda el paso: reducir la velocidad, mirar a ambos lados y detenerse solo si se acerca un tren","Continuar a su velocidad normal, porque la señal redonda de advertencia previa ya le indicó antes todo lo necesario"],"explanation":"Una señal en forma de X (cruz de San Andrés) marca el cruce ferroviario propiamente dicho y debe tratarse como una señal de ceda el paso: reducir la velocidad, comprobar si vienen trenes y detenerse solo si se acerca uno. No es una señal de alto (A) y, a diferencia de la señal redonda de advertencia previa (B, D), esta señal se ubica en las vías mismas, no antes de ellas."},"7":{"q":"Está conduciendo por una carretera desconocida y necesita saber a qué velocidad puede circular legalmente. Más adelante ve una señal con forma de rectángulo vertical (más alta que ancha). Basándose únicamente en su forma, ¿qué tipo de señal es más probable que sea?","options":["Una señal de guía o información que indica direcciones y distancias al siguiente pueblo","Una señal de advertencia que le alerta de un peligro o de un cambio de condición más adelante","Una señal de construcción o de zona de obras que advierte de cuadrillas de trabajo más adelante","Una señal reglamentaria que establece una ley que debe obedecer, como el límite de velocidad"],"explanation":"A vertical rectangle is a regulatory sign that tells you a law you must obey, such as the posted speed limit. A horizontal rectangle (option A) is the guide/information shape, and a diamond (option B) is the warning shape, so neither matches a vertical rectangle."},"8":{"q":"Está conduciendo por una autopista buscando la salida hacia su ciudad de destino. Más adelante ve un letrero ancho con forma de rectángulo horizontal (más largo que alto). Basándose únicamente en su forma, ¿qué tipo de información debería esperar que le dé este letrero?","options":["Direcciones y distancias a lugares, como qué salida tomar y a qué distancia está su ciudad","Una ley de tránsito que debe obedecer, como el límite de velocidad indicado","Una advertencia sobre un peligro o condición más adelante, como una curva pronunciada","Una orden de detenerse por completo antes de continuar"],"explanation":"A horizontal rectangle is a guide/information sign, giving directions and distances. A vertical rectangle (not horizontal) is the regulatory shape for laws like speed limits, warnings use a diamond, and only an octagon means stop."},"9":{"q":"Mientras conduce de noche, gira hacia una calle y sus faros iluminan justo delante de usted un letrero rojo con letras blancas que dice WRONG WAY (CONTRASENTIDO). ¿Qué le indica hacer este letrero?","options":["Reducir la velocidad porque hay un peligro o una condición inusual más adelante","Detenerse; va de frente contra el tráfico que viene en sentido contrario y no debe continuar en esta dirección","Continuar, pero ceder el paso a los servicios para conductores como gasolina y comida en la próxima salida","Avanzar con precaución porque está entrando a una zona de construcción u obras"],"explanation":"WRONG WAY is a red sign, and red means stop, yield, or prohibited, so you must not continue in that direction because you are heading into oncoming traffic. Option A describes a yellow warning sign and option D describes an orange construction sign, neither of which is red."},"10":{"q":"Conduce por una carretera de dos carriles que no conoce al anochecer cuando los faros iluminan una señal amarilla en forma de rombo con una flecha curva que gira hacia la derecha. Según su color, ¿qué le indica esta señal?","options":["Una ley que debe obedecer: se requiere un giro cerrado a la derecha más adelante","Una cuadrilla de construcción está trabajando al doblar la curva hacia la derecha","Una advertencia general: hay una curva en la carretera más adelante, así que reduzca la velocidad","Una señal de guía que lo dirige hacia un destino a la derecha"],"explanation":"Yellow signs are general warning signs alerting you to a hazard or condition ahead, such as a curve, so you should reduce speed. The construction trap is wrong because work-zone warnings are orange, and the regulatory/guide traps are wrong because those use white/green, not yellow."},"11":{"q":"Está conduciendo por una autopista cuando ve adelante una señal en forma de rombo con fondo naranja que dice \"TRABAJOS EN LA VÍA ADELANTE\". ¿Qué le indica el color naranja de esta señal?","options":["Marca un área recreativa o escénica a la que se aproxima","Indica servicios para el conductor como gasolina, comida u hospedaje adelante","Es una advertencia general sobre una curva o una colina en la vía","Está entrando en una zona de construcción o de trabajo"],"explanation":"Orange signs always indicate a construction or work zone, so you should slow down and be alert for workers and equipment. Brown is used for recreation/scenic areas and yellow is used for general warnings like curves or hills, which is why those options are wrong."},"12":{"q":"Conduce por una carretera rural buscando la salida hacia su ciudad de destino. Más adelante ve un letrero verde grande con letras blancas que dice \"Lubbock 45 / Amarillo 120\" y una flecha. ¿Qué le indica este letrero?","options":["Es un letrero de guía que le da las direcciones y las distancias a esas ciudades","Es un letrero de advertencia que le indica que las ciudades de adelante tienen condiciones peligrosas en la carretera","Señala servicios para el automovilista, como gasolina y comida, disponibles en esas ciudades","Es un letrero regulatorio que le obliga a salir hacia una de esas ciudades"],"explanation":"Green signs are guide signs that indicate permitted movements, directions, and distances, so this sign is simply telling you the way and mileage to each city. Warning information would be on a yellow sign, and motorist-services signs are blue, so those choices place the wrong color and meaning together."},"13":{"q":"Conduce por una autopista desconocida, con poco combustible y con hambre, cuando ve más adelante un letrero con fondo azul que muestra los símbolos de un surtidor de gasolina y un tenedor con un cuchillo. ¿Qué le indica este letrero?","options":["Es un letrero de guía que muestra la dirección y la distancia hasta la próxima ciudad","Le indica servicios para conductores cercanos, como gasolina y comida","Le advierte de un peligro o condición más adelante junto a la carretera","Señala una zona recreativa o paisajística disponible en la próxima salida"],"explanation":"Blue signs indicate motorist services such as gas, food, lodging, and hospital, so the blue background with the fuel and dining symbols points you to those services. Green signs (not blue) handle directions and distances, and brown signs mark recreational or scenic areas."},"14":{"q":"Mientras conduce por una carretera rural, ve más adelante una señal cuadrada con fondo marrón y símbolos blancos que apuntan hacia un parque estatal y un campo de batalla histórico. ¿Qué le indica esta señal?","options":["Se acerca a servicios para el conductor, como gasolina, comida y alojamiento","Hay una zona de construcción o de obras más adelante, así que debe reducir la velocidad","Se acerca a áreas recreativas, culturales o escénicas, como parques y sitios históricos","Debe obedecer una ley regulatoria, como un límite de velocidad indicado"],"explanation":"Brown signs indicate recreation, cultural, or scenic areas like parks and historic sites, so option C is correct. Blue signs (not brown) mark motorist services such as gas and food, which makes that the trap answer."},"15":{"q":"Conduce de noche por una autopista desconocida. Una señal más adelante es un rectángulo blanco vertical con letras negras que dice \"45\". ¿Qué le indica esta señal?","options":["Es una señal de guía que indica la distancia hasta la próxima salida.","Es una señal de advertencia sobre un peligro a 45 pies más adelante.","Es una señal de zona de construcción que fija un límite temporal en la zona de trabajo.","Es una señal reguladora que fija la velocidad máxima legal en 45 mph."],"explanation":"White signs with black lettering are regulatory signs, and a white rectangle with a number sets the maximum legal speed (45 mph). Guide/distance signs are green and warning signs are yellow, so those options place real facts on the wrong color of sign."},"16":{"q":"Mientras conduce por un vecindario desconocido, se acerca a una señal en forma de diamante con un fondo amarillo verdoso fluorescente brillante que muestra a dos niños caminando. ¿Sobre qué le advierte esta señal?","options":["Peatones, ciclistas o un cruce escolar más adelante","Una zona de construcción o de obras más adelante","Una zona recreativa o escénica más adelante","Un peligro general de curva o pendiente más adelante"],"explanation":"Fluorescent yellow-green is reserved for pedestrian, bicycle, and school warnings, so this sign means people may be crossing ahead. Orange signals construction zones and brown marks recreation/scenic areas, so those colors would not appear on this warning."},"17":{"q":"Conduce al anochecer hacia un cruce desconocido. El letrero frente a usted se ha desteñido tanto que ya no puede leer la palabra escrita en él, pero todavía distingue su contorno y su color. Para saber que es una señal de ALTO (PARE) y que debe detenerse por completo, ¿qué forma y color debería buscar?","options":["Un triángulo rojo invertido (con la punta hacia abajo)","Un octágono rojo de ocho lados","Un rombo amarillo","Un rectángulo vertical blanco"],"explanation":"A STOP sign is the only red, eight-sided octagon, so its shape and color identify it even when the word is unreadable. A red inverted triangle is a YIELD sign (give the right of way, not necessarily a full stop), which is the trap."},"18":{"q":"Está incorporándose a una autopista con mucho tráfico desde una rampa de acceso. Al final de la rampa ve una señal con forma de triángulo apuntando hacia abajo, de color rojo y blanco. ¿Qué le exige hacer esta señal?","options":["Detenerse por completo, ya que esta es la única forma de señal que legalmente significa alto","Tratar la intersección como un alto en todas las direcciones porque el semáforo está apagado","Reducir la velocidad y ceder el paso al tráfico de la autopista, deteniéndose solo si es necesario","No entrar, porque una señal roja y blanca siempre significa que la vía está cerrada para usted"],"explanation":"A red-and-white inverted (downward-pointing) triangle is a YIELD sign, which means give the right of way and slow or stop only if needed. The full-stop trap describes the red octagon STOP sign, and the 'do not enter' trap confuses YIELD with a prohibitory sign."},"19":{"q":"Está buscando un estacionamiento en el centro y se acerca a una rampa donde ve una señal roja que dice 'NO ENTRE' (DO NOT ENTER). ¿Qué le exige hacer esta señal roja?","options":["Reducir la velocidad y avanzar con precaución, ya que las señales rojas solo indican un peligro adelante","Ceder el paso a cualquier vehículo en la rampa y luego entrar si el camino está libre","Detenerse por completo y luego continuar una vez que haya verificado si vienen autos","No avanzar hacia la rampa; esta entrada está cerrada para su dirección de circulación"],"explanation":"DO NOT ENTER is a red sign meaning do not proceed, because that entrance is closed to your direction of travel. Yielding (B) or stopping then continuing (C) are wrong because the sign prohibits entry entirely rather than allowing you to proceed after caution."},"20":{"q":"Usted gira hacia una calle y ve una señal rectangular con una flecha horizontal que apunta a la derecha y las palabras ONE WAY (un solo sentido). Usted quería ir a la izquierda por esta calle. ¿Qué debe hacer?","options":["No gire a la izquierda; circule solo hacia la derecha, en la dirección que indica la flecha","Gire a la izquierda, pero primero ceda el paso al tráfico que viene de frente, ya que es una calle compartida","Gire a la izquierda solo si tampoco hay una señal de DO NOT ENTER (no entre) en la esquina","Trátela como una advertencia y avance hacia la izquierda despacio y con precaución"],"explanation":"A ONE WAY sign means traffic may travel only in the direction the arrow points, so you must go right and cannot turn left onto that street. Turning left would send you against legal traffic flow, so the options allowing a left turn are wrong."},"21":{"q":"Conduce en un día despejado y seco y pasa junto a una señal rectangular blanca con el número negro 65. Comienza a caer una lluvia ligera y el pavimento se vuelve resbaladizo. ¿Qué le indica esa señal sobre su velocidad con este cambio de clima?","options":["65 es la velocidad mínima que debe mantener sin importar la lluvia","65 es la velocidad máxima legal para condiciones ideales, así que ahora debe reducir por debajo de ella por el pavimento mojado","El rectángulo blanco es solo una señal de guía, por lo que el 65 es solo orientativo y no obligatorio","Como está lloviendo, el límite aumenta automáticamente para darle más espacio para detenerse"],"explanation":"A SPEED LIMIT sign is a white rectangle with black numbers showing the maximum legal speed in ideal conditions, so in rain you must drive slower than the posted number. It is not a minimum, it is a regulatory (not guide) sign, and the limit never rises in bad weather."},"22":{"q":"Se acerca a una intersección y quiere hacer un cambio de sentido (vuelta en U). Sobre el semáforo hay una señal cuadrada blanca que muestra una flecha de vuelta en U dentro de un círculo rojo con una línea diagonal roja que la cruza. ¿Qué le exige hacer esta señal?","options":["Solo advierte que las vueltas en U son complicadas aquí, así que puede hacerla si es seguro","Permite la vuelta en U pero solo con una flecha verde protegida","Prohíbe las vueltas en U en esta intersección, por lo que no debe hacer una","Significa ceder el paso al tráfico que viene en sentido contrario antes de completar la vuelta en U"],"explanation":"A red circle with a slash is a regulatory 'No' sign, and a U-turn arrow inside it means U-turns are prohibited here. The trap answers treat a mandatory prohibition as a mere warning or a conditional/yield situation, but the red circle and slash means the movement is flatly illegal."},"23":{"q":"Conduce de noche por una carretera de dos carriles que no conoce. La línea pintada en el centro de la carretera, entre su carril y el carril a su izquierda, es amarilla. ¿Qué le indica este color sobre el tránsito en el carril del otro lado de esa línea?","options":["Es una calle de un solo sentido, por lo que no viene tránsito en sentido contrario","La línea amarilla solo marca el borde del pavimento, no un carril de circulación","El tránsito en ese carril circula en el mismo sentido que usted","El tránsito en ese carril circula en sentido contrario, hacia usted"],"explanation":"Las líneas amarillas separan el tránsito que circula en sentidos opuestos, por lo que el carril al otro lado de una línea amarilla central lleva tránsito que viene de frente. Las líneas blancas (no las amarillas) separan el tránsito del mismo sentido y marcan el borde de la carretera, lo que hace incorrectas las opciones del mismo sentido y del borde."},"24":{"q":"Conduce por una autopista ancha y se acerca a una larga línea blanca continua que corre paralela a su carril por la izquierda, con más tráfico circulando en la misma dirección al otro lado de ella. ¿Qué le indica esta línea blanca sobre el tráfico que está a su lado?","options":["El tráfico a su lado se mueve en la misma dirección que usted, y la línea desaconseja cambiar de carril cruzándola.","El tráfico a su lado se mueve en dirección opuesta, por lo que cruzar la línea lo pondría frente a vehículos que vienen de frente.","La línea marca el borde de la carretera, por lo que no hay ningún carril de circulación más allá de ella.","La línea significa que rebasar solo está permitido cuando la vía está despejada, igual que una línea amarilla discontinua."],"explanation":"White lines separate lanes of traffic moving in the SAME direction, and a solid white line discourages crossing or changing lanes. Yellow lines (B) separate opposite directions, white edge lines mark the pavement edge but here it sits between two same-direction lanes (C), and broken-line passing rules apply to yellow lines, not this solid white one (D)."},"25":{"q":"Está conduciendo en una carretera de dos carriles y quiere adelantar a un tractor lento que va delante. Al acercarse, nota que la línea de su lado del centro es una sola línea amarilla continua, mientras que el lado opuesto tiene una línea amarilla discontinua. ¿Qué le indica esto sobre el adelantamiento?","options":["Puede adelantar porque la línea amarilla discontinua del otro lado se aplica a ambos sentidos de circulación.","No puede adelantar, porque la línea amarilla continua de su lado prohíbe el adelantamiento.","Solo puede adelantar a velocidades inferiores al límite señalado, ya que las marcas son orientativas.","Debe detenerse por completo antes de cruzar cualquier línea amarilla."],"explanation":"A solid yellow line on your side of the road means passing is prohibited for you, even if the opposite side has a broken (dashed) yellow line that permits passing for oncoming traffic. The broken line only allows passing for drivers on that side, and yellow markings are regulatory, not merely advisory."},"26":{"q":"Conduce por una carretera de dos carriles y quiere adelantar a un tractor lento que va delante. En su lado del centro, el pavimento está marcado con una línea amarilla discontinua (segmentada), el carril contrario está vacío y tiene una vista despejada y larga por delante. ¿Qué le indica esta marca sobre adelantar?","options":["Nunca puede cruzar una línea amarilla por ningún motivo, así que quédese detrás del tractor","La línea discontinua marca el borde de la calzada, así que no se desplace a la izquierda","Se permite adelantar, y puede cruzar al carril contrario para adelantar cuando la vía esté despejada","Puede cambiar de carril libremente porque las líneas discontinuas siempre separan el tráfico en la misma dirección"],"explanation":"Una línea amarilla discontinua (segmentada) en su lado significa que se permite adelantar cuando la vía por delante está despejada, así que puede cruzarla para adelantar al tractor. La opción D es la trampa: las líneas blancas discontinuas separan el tráfico en la misma dirección, pero las líneas amarillas siempre separan el tráfico en sentidos opuestos, por lo que aquí esa regla se aplica mal."},"27":{"q":"Conduce por una carretera de dos carriles donde una doble línea amarilla continua recorre el centro. Delante de usted hay un tractor lento, la vía está despejada y hay buena visibilidad. A su izquierda, un camino de entrada lleva a la casa que desea visitar. ¿Qué le permite hacer aquí la doble línea amarilla continua?","options":["Adelantar al tractor, ya que la vía está despejada y la visibilidad es buena","Adelantar al tractor, porque la doble línea amarilla solo restringe el tránsito en sentido contrario","Nada le obliga a esperar; puede cambiar de carril libremente como con una línea blanca discontinua","Cruzar la línea solo para girar a la izquierda hacia el camino de entrada, pero no para adelantar al tractor"],"explanation":"Una doble línea amarilla continua significa que no se puede adelantar en ningún sentido, por lo que no puede adelantar al tractor aunque la visibilidad sea buena; solo puede cruzarla para girar (por ejemplo, hacia el camino de entrada). Las opciones de vía despejada y 'solo sentido contrario' son trampas porque la prohibición se aplica en ambos sentidos sin importar la visibilidad."},"28":{"q":"Está conduciendo por una autopista de tres carriles donde todo el tránsito circula en la misma dirección. Al acercarse a una salida, nota que la línea del carril a su derecha ha cambiado de una línea blanca discontinua a una sola línea blanca continua. ¿Qué le indica esta línea blanca continua sobre el cambio de carril aquí?","options":["Desaconseja cruzar la línea para cambiar de carril en este punto","Le permite cambiar de carril libremente siempre que la vía esté despejada","Separa el tránsito que circula en direcciones opuestas","Significa que se permite rebasar solo cuando no hay tránsito en sentido contrario"],"explanation":"A solid white line discourages lane changes, so you should stay in your lane rather than cross it near the exit, whereas a broken white line is what allows lane changes when clear (option B). White lines separate same-direction traffic, so the opposite-direction and oncoming-traffic options describe yellow-line rules, not this marking."},"29":{"q":"Llega a un semáforo en rojo en una intersección y quiere girar a la derecha. No hay ninguna señal que prohíba girar en rojo, y el cruce peatonal y el tráfico transversal están despejados. ¿Cuál es la acción correcta?","options":["Reducir la velocidad pero pasar el rojo sin detenerse, ya que el camino está despejado","Detenerse por completo detrás de la línea primero y luego girar a la derecha cuando sea seguro","Esperar una flecha verde antes de poder girar a la derecha","Tratar el rojo como un ceda el paso e incorporarse al giro sin detenerse por completo"],"explanation":"Una luz roja fija exige una parada completa detrás de la línea, y el giro a la derecha en rojo solo se permite tras esa parada total cuando ninguna señal lo prohíbe. Pasar sin detenerse (A) o ceder sin parar (D) omiten la parada completa obligatoria, y no se necesita una flecha verde (C) para un giro a la derecha permitido en rojo."},"30":{"q":"Se acerca a una intersección a la velocidad máxima cuando el semáforo frente a usted cambia de verde a AMARILLO fijo. Todavía está a cierta distancia, con bastante espacio para frenar suavemente. ¿Qué significa esta señal y qué debe hacer?","options":["La luz está a punto de volver a ponerse verde; acelere para cruzar la intersección antes de que cambie","Es una advertencia de un peligro adelante, como una curva o una incorporación; reduzca la velocidad pero puede continuar","La luz está a punto de ponerse en rojo; deténgase antes de la línea si puede hacerlo de forma segura","Trate la intersección como un alto de cuatro vías, deténgase por completo y luego continúe cuando sea su turno"],"explanation":"A steady yellow light warns that the signal is about to turn red, so you must stop before the line if you can do so safely, which you can from this distance. Option D describes a dark/non-working signal, and option B confuses the signal with a yellow warning sign, not a traffic light."},"31":{"q":"Llega a una intersección con una luz VERDE fija y señala un giro a la izquierda. Se acercan autos en sentido contrario y un peatón está entrando al cruce peatonal que usted debe atravesar. ¿Qué debe hacer?","options":["Avanzar de inmediato, ya que la luz verde le da el derecho protegido de girar.","Detenerse completamente detrás de la línea y esperar una flecha verde antes de girar.","Girar rápidamente frente a los autos que vienen porque ellos deben cederle el paso a un vehículo que gira.","Esperar, cediendo el paso al peatón y al tránsito en sentido contrario, y luego completar el giro cuando el camino esté despejado."],"explanation":"A steady green means go only if the way is clear; when turning you must yield to pedestrians and oncoming traffic, so you wait until both are clear before turning. A plain green is not a protected turn (only a green arrow is), and oncoming traffic does not yield to you, so the other answers are wrong."},"32":{"q":"Se acerca a una intersección de noche y el semáforo elevado parpadea en rojo en su dirección. No hay otro tráfico a la vista. ¿Qué debe hacer?","options":["Detenerse por completo y luego avanzar cuando el camino esté despejado, tratándolo como una señal de PARE","Reducir la velocidad y avanzar con precaución sin detenerse","Seguir conduciendo, ya que una luz parpadeante significa que el semáforo no está en funcionamiento","Detenerse y esperar a que la luz cambie a verde fijo antes de avanzar"],"explanation":"A flashing red light must be treated exactly like a STOP sign: come to a full stop, then proceed when it is safe. Slowing without stopping (B) is the rule for a flashing yellow light, not a flashing red one."},"33":{"q":"Se acerca a una intersección de noche y el semáforo que tiene enfrente muestra una luz amarilla intermitente. ¿Qué debe hacer?","options":["Detenerse por completo detrás de la línea, luego avanzar cuando el camino esté despejado, tratándolo como una señal de alto","Reducir la velocidad y cruzar la intersección con precaución","Detenerse por completo y permanecer detenido hasta que la luz se ponga verde","Tratar la intersección como un alto en todas las direcciones y ceder el paso al conductor a su derecha"],"explanation":"A flashing yellow light means slow down and proceed with caution, so option B is correct. Option A describes a flashing RED light (treated as a stop sign), and option D describes a dark or non-working signal, which are the wrong responses for a flashing yellow."},"34":{"q":"Está detenido en el carril de giro a la izquierda en una intersección. La señal principal para su dirección está en rojo fijo, pero una señal de giro a la izquierda separada junto a ella muestra una FLECHA VERDE fija apuntando hacia la izquierda. ¿Qué significa esto para su giro a la izquierda?","options":["Debe esperar, porque la luz roja fija controla todos los movimientos en la intersección","Puede girar a la izquierda solo después de ceder el paso al tráfico que viene de frente, ya que el verde siempre significa ceder el paso a los vehículos que vienen","Tiene un giro protegido y puede girar a la izquierda en la dirección de la flecha","Debe tratar la intersección como un alto en todas las direcciones y avanzar por turno"],"explanation":"A green arrow signals a protected turn in the direction it points, so you may turn left with the right of way even though the main signal is red. Option B describes a steady green ball (yield to oncoming traffic), not a green arrow, and option A wrongly lets the red ball override the dedicated turn arrow."},"35":{"q":"Está detenido en el carril de giro a la izquierda en una intersección. La señal exclusiva para girar a la izquierda muestra una flecha roja fija que apunta a la izquierda, mientras que la señal para el tráfico que sigue de frente está en verde. ¿Qué debe hacer?","options":["Girar a la izquierda, porque la luz verde de los carriles de paso le da el derecho de paso","Girar a la izquierda después de detenerse por completo, igual que un giro a la derecha con luz roja","Tratar la flecha roja como una amarilla intermitente y girar a la izquierda con precaución","Permanecer detenido y esperar, porque una flecha roja significa que no se permite girar a la izquierda en esa dirección"],"explanation":"A red arrow means no turn is permitted in the direction the arrow points, so you must stay stopped until the arrow changes. The green light for the through lanes does not apply to your protected turn, and a red arrow does not allow a turn after stopping the way a steady red ball can."},"36":{"q":"Se aproxima a una concurrida intersección de cuatro vías durante un apagón, y el semáforo que normalmente la controla está completamente apagado y no muestra ninguna luz. No hay policías ni señales temporales presentes. ¿Cómo debe proceder?","options":["Tratar la intersección como un ALTO de todas las vías: detenerse por completo y ceder el paso según las reglas habituales de prioridad.","Reducir la velocidad y avanzar con precaución sin detenerse, ya que un semáforo apagado funciona como una luz amarilla intermitente.","Continuar a velocidad normal porque un semáforo que no funciona significa que la intersección no tiene control activo.","Detenerse solo si hay tráfico cruzado y luego avanzar antes que los conductores que lleguen después de usted."],"explanation":"A dark or non-working signal must be treated as an all-way STOP, so you stop fully and follow normal right-of-way rules. Option B is wrong because a dark signal is not the same as a flashing yellow (slow and proceed with caution); a dead signal requires a complete stop from every direction."},"37":{"q":"Conduce por una autopista cuando ve dos señales de advertencia en forma de diamante más adelante. La primera es amarilla brillante y muestra una carretera con curva, y la segunda es naranja brillante y muestra a un trabajador con una pala. ¿Qué le indica específicamente el color naranja de la segunda señal?","options":["Hay un peligro general de curva o pendiente más adelante, igual que la señal amarilla","Se está acercando a una zona de construcción u obras","Hay un cruce de peatones o escolar más adelante","Debe detenerse porque la carretera está cerrada"],"explanation":"Orange signs indicate a construction or work zone, distinguishing them from standard yellow general-warning signs (curve, hill, merge). Option A confuses orange with the yellow general-warning color, and pedestrian/school warnings use fluorescent yellow-green, not orange."},"38":{"q":"Conduce por una carretera de dos carriles desconocida al anochecer. La línea central entre su carril y el carril a su izquierda es una línea AMARILLA continua. ¿Qué le indica este color sobre el tráfico en el carril a su izquierda?","options":["Es un carril de giro que el tráfico puede usar desde cualquier dirección","Es el arcén pavimentado, por lo que no circula tráfico de paso","Lleva tráfico que circula en dirección opuesta a la suya","Lleva tráfico que circula en la misma dirección que usted"],"explanation":"Yellow lines separate traffic moving in opposite directions, so the yellow center line means the lane to your left carries oncoming traffic. White lines (option D) would indicate traffic moving in the same direction, which is the trap here."},"39":{"q":"Conduciendo al anochecer por un pueblo desconocido, se acerca a una señal al borde de la carretera que puede ver con claridad pero cuyas palabras aún no se pueden leer. Es un rectángulo vertical y alto, con fondo blanco liso y letras negras. Antes incluso de poder leerla, ¿qué le indican la forma y el color de la señal sobre su propósito?","options":["Es una señal de guía que da direcciones, distancias o servicios más adelante","Es una señal de advertencia que le alerta de un peligro o una condición cambiante más adelante","Es una señal de construcción que marca una zona de obras activa","Es una señal reguladora que establece una ley que está obligado a obedecer"],"explanation":"A vertical rectangle that is white with black lettering is a regulatory sign, meaning it states a law (such as a speed limit) that you must obey. Guide signs are green or horizontal rectangles, warning signs are yellow diamonds, and construction signs are orange, so those choices misread the white-and-black vertical rectangle."}},"learn-road-signs":{"0":{"q":"¿Qué forma tiene una señal de ALTO?","options":["Octágono (8 lados)","Rombo","Círculo","Rectángulo vertical"],"explanation":"A STOP sign is the only octagonal (8-sided) sign and requires a full stop."},"1":{"q":"¿Qué significa una señal con forma de triángulo invertido (al revés)?","options":["Alto","Ceda el paso","Prohibido adelantar","Zona escolar"],"explanation":"An inverted triangle means YIELD, so give the right of way and slow or stop if needed."},"2":{"q":"¿Qué significa una señal de banderín (un triángulo horizontal en el lado izquierdo de la carretera)?","options":["Zona escolar adelante","Detenerse por completo","Zona de no rebasar","Cruce de ferrocarril"],"explanation":"A pennant, a horizontal triangle placed on the left side of the road, marks a No Passing Zone."},"3":{"q":"¿Qué indica una señal en forma de rombo?","options":["Debe detenerse por completo","Está entrando a una calle de un solo sentido","Ha alcanzado el límite de velocidad","Hay un peligro o condición más adelante"],"explanation":"A diamond-shaped sign is a warning sign that indicates a hazard or condition ahead."},"4":{"q":"¿Qué indica una señal con forma de pentágono (5 lados, punta hacia arriba)?","options":["Una zona escolar o cruce escolar","Un cruce de ferrocarril","Una zona de no rebasar","Una intersección con alto"],"explanation":"A pentagon (5 sides, point up) marks a school zone or school crossing."},"5":{"q":"¿Sobre qué le advierte una señal de tránsito redonda (circular)?","options":["Una zona escolar adelante","Un cruce de ferrocarril adelante","Una zona de no rebasar","Una zona de construcción"],"explanation":"A round (circular) sign is an advance warning that a railroad crossing is ahead."},"6":{"q":"¿Qué significa una señal de aspa (con forma de X)?","options":["Detenerse por completo","Construcción adelante","Cruce de ferrocarril; trátelo como ceda el paso","Zona escolar adelante"],"explanation":"A crossbuck (X shape) marks the railroad crossing itself and should be treated like a yield."},"7":{"q":"¿Qué significa una señal de rectángulo vertical?","options":["Advertencia de un peligro adelante","Cruce de zona escolar","Cruce de ferrocarril adelante","Una ley regulatoria que debe obedecer"],"explanation":"A vertical rectangle is a regulatory sign indicating a law you must obey, such as a speed limit."},"8":{"q":"¿Qué tipo de señal es un rectángulo horizontal?","options":["Una señal de guía o información con direcciones y distancias","Una señal de alto","Una señal de advertencia de un peligro adelante","Una señal de zona escolar"],"explanation":"A horizontal rectangle is a guide or information sign that gives directions and distances."},"9":{"q":"¿Qué forma de señal se usa solo para PARE?","options":["Rombo","Octágono","Triángulo","Rectángulo"],"explanation":"The octagon (8 sides) is the only sign shape reserved exclusively for STOP."},"10":{"q":"¿Qué significa el color rojo en una señal de tránsito?","options":["Zona de construcción","Servicios para conductores","Alto, ceda el paso o prohibido","Advertencia general"],"explanation":"Red is used on STOP, YIELD, DO NOT ENTER, and WRONG WAY signs to mean stop, yield, or prohibited."},"11":{"q":"¿Qué significa una señal de tránsito amarilla?","options":["Zona de construcción adelante","Pare o no entre","Servicios para conductores cerca","Advertencia general adelante"],"explanation":"Yellow signals a general warning, such as a curve, hill, merge, or signal ahead."},"12":{"q":"¿Qué significa una señal de tránsito naranja?","options":["Zona de construcción u obras","Pare o ceda el paso","Servicios para conductores","Área de recreación"],"explanation":"Orange signs warn of construction or a work zone ahead."},"13":{"q":"¿Qué significa una señal de tránsito verde?","options":["Pare o ceda el paso","Guía y direcciones","Zona de construcción","Advertencia general"],"explanation":"Green signs give guide information like directions and distances."},"14":{"q":"¿Qué significa una señal de tráfico azul?","options":["Zona de construcción adelante","Alto o ceda el paso","Servicios para conductores como gasolina y comida","Áreas recreativas"],"explanation":"Blue signs show motorist services such as gas, food, lodging, and hospital."},"15":{"q":"¿Qué color de señal de tránsito indica áreas recreativas, culturales o escénicas?","options":["Azul","Verde","Amarillo","Marrón"],"explanation":"Brown signs mark recreation, cultural, or scenic areas."},"16":{"q":"¿Qué significa una señal blanca con letras negras?","options":["Reglamentaria, como un límite de velocidad","Construcción o zona de trabajo","Área recreativa o escénica","Advertencia general adelante"],"explanation":"A white sign with black letters is regulatory, such as a speed limit or lane use sign."},"17":{"q":"¿Sobre qué advierte una señal amarillo-verde fluorescente?","options":["Zonas de obras de construcción","Áreas de peatones, bicicletas y escuelas","Servicios para conductores como gasolina y comida","Áreas recreativas y paisajísticas"],"explanation":"Fluorescent yellow-green signs warn of pedestrian, bicycle, and school crossings."},"18":{"q":"¿De qué color es una señal de WRONG WAY (Sentido Contrario)?","options":["Amarillo","Verde","Rojo","Azul"],"explanation":"A WRONG WAY sign is red, signaling you must not proceed."},"19":{"q":"¿De qué color es una señal de advertencia de incorporación?","options":["Naranja","Azul","Verde","Amarillo"],"explanation":"Yellow is used for general warning signs, including merge signs."},"20":{"q":"¿Qué forma tiene una señal de PARE (STOP)?","options":["Octágono (8 lados)","Rombo","Círculo","Cuadrado"],"explanation":"A STOP sign is a red octagon, the only sign with that shape."},"21":{"q":"¿De qué color es una señal de CEDA EL PASO?","options":["Amarillo y negro","Rojo y blanco","Verde y blanco","Azul y blanco"],"explanation":"A YIELD sign is a red-and-white inverted triangle."},"22":{"q":"¿De qué color son las señales de PROHIBIDO EL PASO y CONTRAMANO?","options":["Amarillo","Verde","Rojo","Azul"],"explanation":"DO NOT ENTER and WRONG WAY signs are red and mean do not proceed."},"23":{"q":"¿Qué indica una señal de SENTIDO ÚNICO (ONE WAY)?","options":["Detenerse por completo antes de girar","El camino está cerrado más adelante","Se permite rebasar aquí","Circular solo en la dirección de la flecha"],"explanation":"A ONE WAY sign means you may travel only in the direction the arrow points."},"24":{"q":"¿Qué muestra una señal de LÍMITE DE VELOCIDAD?","options":["La velocidad máxima legal en condiciones ideales","La velocidad mínima por debajo de la cual nunca debes ir","Una velocidad sugerida para curvas cerradas","La velocidad solo para conducir de noche"],"explanation":"A SPEED LIMIT sign is a white rectangle with black numbers showing the maximum legal speed in ideal conditions."},"25":{"q":"¿Qué diseño usan las señales reglamentarias de \"No\"?","options":["Un rombo amarillo","Un círculo rojo con una raya","Un rectángulo verde","Un cuadrado azul"],"explanation":"Regulatory \"No\" signs, such as no U-turn or no left turn, use a red circle with a slash."},"26":{"q":"Que significa el numero en una senal de LIMITE DE VELOCIDAD?","options":["La velocidad minima legal","La velocidad promedio del trafico","La velocidad maxima legal","La velocidad recomendada para camiones"],"explanation":"The number on a SPEED LIMIT sign is the maximum legal speed under ideal conditions."},"27":{"q":"¿Qué indica el límite de velocidad señalado?","options":["La velocidad más baja que puede ir","La velocidad para cualquier clima","Una velocidad solo de noche","El máximo para condiciones ideales"],"explanation":"The posted speed limit is the maximum for ideal conditions, so drive slower in poor conditions."},"28":{"q":"¿Qué separan las líneas amarillas en la carretera?","options":["El tráfico que circula en direcciones opuestas","El tráfico que circula en la misma dirección","Los espacios de estacionamiento","Los carriles para bicicletas"],"explanation":"Yellow lines separate traffic moving in opposite directions."},"29":{"q":"¿Qué indican las líneas blancas en la carretera?","options":["Una zona escolar adelante","Tráfico que circula en la misma dirección","Tráfico que circula en direcciones opuestas","Una zona de no rebasar"],"explanation":"White lines separate lanes of traffic moving in the same direction and mark the road edge."},"30":{"q":"¿Qué significa una línea amarilla continua en su lado de la carretera?","options":["Se permite rebasar","La carretera termina adelante","No se permite rebasar","Calle de un solo sentido"],"explanation":"A solid yellow line on your side means you may not pass."},"31":{"q":"¿Qué significa una línea amarilla discontinua (entrecortada)?","options":["Nunca cruce esta línea","No se permite rebasar en ninguna dirección","Marca el borde de la carretera","Se permite rebasar cuando el camino está despejado"],"explanation":"A broken (dashed) yellow line means passing is allowed when the way is clear."},"32":{"q":"¿Qué significa una doble línea amarilla continua?","options":["Prohibido rebasar en ambos sentidos","Se permite rebasar en ambos sentidos","Los carriles van en la misma dirección","Borde del camino adelante"],"explanation":"A double solid yellow line means no passing in either direction; do not cross except to turn."},"33":{"q":"¿Qué significa una línea blanca continua en la carretera?","options":["Se permite adelantar","No se recomienda cambiar de carril","El tráfico circula en direcciones opuestas","Debe detenerse"],"explanation":"A solid white line discourages lane changes."},"34":{"q":"¿Qué le permite hacer una línea blanca discontinua?","options":["Detenerse por completo","Adelantar al tráfico que viene de frente","Cambiar de carril","Nunca cruzarla"],"explanation":"A broken white line separates lanes going the same way and allows lane changes."},"35":{"q":"¿Qué marcan las líneas blancas en el pavimento?","options":["Un cruce de ferrocarril","Una zona escolar adelante","Tráfico que circula en direcciones opuestas","El borde de la carretera"],"explanation":"White lines mark the edge of the road and separate traffic moving in the same direction."},"36":{"q":"¿De qué color son las líneas que separan los carriles del tráfico que va en la misma dirección?","options":["Blancas","Amarillas","Rojas","Azules"],"explanation":"White lines separate traffic moving in the same direction, while yellow lines separate opposite directions."},"37":{"q":"¿Qué debe hacer en una luz roja fija del semáforo?","options":["Reducir la velocidad y seguir","Detenerse por completo detrás de la línea","Acelerar para cruzar la intersección","Tocar la bocina y avanzar"],"explanation":"A steady red light means you must stop completely behind the line and remain stopped."},"38":{"q":"¿Cuándo puede girar a la derecha en una luz roja fija?","options":["Nunca, en ningún momento","Sin detenerse primero","Después de una parada total, a menos que una señal lo prohíba","Solo cuando se muestra una flecha"],"explanation":"At a steady red light you may turn right after coming to a full stop, unless a sign prohibits it."},"39":{"q":"¿Qué significa una luz de semáforo amarilla fija?","options":["Acelere para pasar antes del rojo","El semáforo está dañado; pase en cualquier momento","Deténgase solo si hay un auto detrás de usted","La luz está por cambiar a rojo; deténgase si es seguro"],"explanation":"A steady yellow light warns that the signal is about to turn red, so stop if you can do so safely."},"40":{"q":"¿Qué significa una luz VERDE fija del semáforo?","options":["Avance si el camino está despejado","Deténgase por completo","Reduzca la velocidad y prepárese para detenerse","Haga solo un giro protegido"],"explanation":"A steady green light means you may go if the way is clear."},"41":{"q":"En una luz verde fija, ¿a quién debe ceder el paso al girar?","options":["A nadie","A los peatones y al tráfico que viene de frente","Solo a los autos estacionados","Al tráfico detrás de usted"],"explanation":"At a steady green light, you must yield to pedestrians and oncoming traffic when turning."},"42":{"q":"¿Cómo debe tratar un semáforo en rojo intermitente?","options":["Como una luz verde","Como una señal de ceda el paso","Como una señal de alto","Como una luz amarilla"],"explanation":"A flashing red light means you must stop completely, just like at a stop sign."},"43":{"q":"¿Qué significa una luz de tráfico amarilla intermitente?","options":["Detenerse por completo","Acelerar para cruzar la intersección","La luz está dañada, no avance","Reduzca la velocidad y avance con precaución"],"explanation":"A flashing yellow light means slow down and proceed with caution."},"44":{"q":"¿Qué significa una flecha verde en el semáforo?","options":["Un giro protegido en la dirección de la flecha","No girar en esa dirección","Detenerse antes de girar","Reducir la velocidad y tener precaución"],"explanation":"A green arrow means a protected turn in the direction the arrow points."},"45":{"q":"¿Qué significa una flecha roja?","options":["Gire rápido en esa dirección","No se permite girar en esa dirección","Ceda el paso antes de girar","Gire solo después de detenerse"],"explanation":"A red arrow means you may not turn in that direction."},"46":{"q":"¿Cómo debe tratar un semáforo apagado o que no funciona?","options":["Pasar sin detenerse","Tratarlo como una señal de ceda el paso","Tratarlo como un alto de todas las direcciones","Acelerar para cruzar la intersección"],"explanation":"A dark or non-working signal should be treated as an all-way stop."},"47":{"q":"¿Qué forma tiene una señal de PARE (STOP)?","options":["Rombo","Redonda","Triángulo","Octágono"],"explanation":"A STOP sign is the only octagonal (8-sided) sign, so its shape alone tells you to stop."},"48":{"q":"¿De qué color es una señal de límite de velocidad?","options":["Blanca con letras negras","Amarilla con letras negras","Roja con letras blancas","Verde con letras blancas"],"explanation":"A speed limit sign is white with black lettering because it is regulatory, not a warning."},"49":{"q":"¿De qué color es una señal de área escénica?","options":["Azul","Marrón","Verde","Amarillo"],"explanation":"Brown signs mark recreation, cultural, and scenic areas."},"50":{"q":"¿De qué color son las señales de servicios para conductores, como hospitales y comida?","options":["Rojo","Verde","Azul","Marrón"],"explanation":"Blue signs show motorist services such as gas, food, lodging, and hospitals."},"51":{"q":"¿De qué color es una señal de zona de trabajo o construcción?","options":["Amarillo","Verde","Azul","Naranja"],"explanation":"Work zone and construction signs are orange, which sets them apart from yellow general-warning signs."},"52":{"q":"¿De qué color es una señal de advertencia de cruce escolar?","options":["Amarillo-verde fluorescente","Azul","Marrón","Naranja"],"explanation":"Fluorescent yellow-green is the color for pedestrian, bicycle, and school warnings."},"53":{"q":"Que color comparten las senales STOP (ALTO), YIELD (CEDA EL PASO), DO NOT ENTER (NO ENTRE) y WRONG WAY (VIA EQUIVOCADA)?","options":["Amarillo","Rojo","Verde","Azul"],"explanation":"Red is the color shared by STOP, YIELD, DO NOT ENTER, and WRONG WAY signs."},"54":{"q":"¿Cuándo puede cruzar una doble línea amarilla continua?","options":["Para rebasar a otro auto","En cualquier momento si está despejado","Solo para girar","Nunca por ninguna razón"],"explanation":"A double solid yellow line may be crossed only to turn, not to pass."},"55":{"q":"¿Qué significa una flecha verde en el semáforo?","options":["Deténgase y espere al tráfico","Reduzca la velocidad y ceda el paso","No se permite girar","Un giro protegido con el tráfico opuesto detenido"],"explanation":"A green arrow gives a protected turn because oncoming traffic is stopped during that movement."},"56":{"q":"¿Qué significa una línea amarilla discontinua en su lado de la carretera?","options":["Se permite rebasar cuando el camino adelante está despejado","Nunca se permite rebasar","Debe detenerse","La carretera es de un solo sentido"],"explanation":"A broken yellow line on your side means you may pass when the road ahead is clear."},"57":{"q":"¿Qué forma tiene la señal de advertencia anticipada de cruce de ferrocarril?","options":["Rombo","Redonda","Octágono","Cruz de San Andrés (forma de X)"],"explanation":"The railroad advance-warning sign is round, while the sign at the crossing itself is a crossbuck."},"58":{"q":"¿Qué debe hacer ante una luz roja intermitente?","options":["Reducir la velocidad y seguir","Acelerar para pasar","Detenerse por completo","Ignorarla si está despejado"],"explanation":"A flashing red light means come to a complete stop, just like at a STOP sign."},"59":{"q":"¿Qué significa un círculo rojo con una línea diagonal sobre una flecha de giro a la izquierda?","options":["Solo giro a la izquierda","El carril izquierdo termina","Giro a la izquierda adelante","Prohibido girar a la izquierda"],"explanation":"A red circle and slash over a left-turn arrow means no left turn is allowed."}},"rules-of-the-road":{"0":{"q":"Conduce por una carretera rural de Texas con un límite señalizado de 70 mph. De repente entra una niebla densa y apenas puede ver dos largos de auto por delante. Según la ley de Texas, ¿a qué velocidad se le permite conducir?","options":["Más despacio que 70 mph — a una velocidad razonable y segura para la niebla, porque el límite señalizado es el máximo solo para condiciones ideales","Hasta 70 mph, porque ese es el límite señalizado legalmente y siempre puede conducir a la velocidad indicada","Exactamente 50 mph, porque la ley de Texas exige reducir la velocidad en 20 mph siempre que la visibilidad sea mala","Hasta 75 mph, ya que las autopistas interestatales rurales de Texas permiten 75 mph sin importar las condiciones"],"explanation":"Según la ley básica de velocidad de Texas (prima facie), nunca debe conducir más rápido de lo que es razonable y seguro para las condiciones existentes, así que con niebla densa debe reducir bastante por debajo de las 70 mph señalizadas. Conducir al límite señalizado completo (B) es la trampa: el número indicado es un máximo para buenas condiciones, no una garantía, y las cifras de 20 mph y 75 mph (C, D) son reglas reales aplicadas en el contexto equivocado."},"1":{"q":"Usted sale de una carretera señalizada y entra en una calle residencial dentro del distrito urbano de una ciudad. No ve ninguna señal de límite de velocidad en toda la cuadra. ¿Qué velocidad debe suponer que es el máximo legal aquí?","options":["20 mph, porque ese es el valor predeterminado en cualquier zona donde haya viviendas","30 mph, el límite predeterminado común para un distrito urbano cuando no hay señal colocada","70 mph, ya que ese es el valor predeterminado para las carreteras y ninguna otra señal lo anula","No hay límite mientras conduzca con seguridad, porque falta la señal"],"explanation":"Where no sign is posted, the common default speed limit in an urban district is 30 mph, so you should treat 30 mph as the legal maximum. The 20 mph figure is the typical reduced limit for active school zones, not residential streets generally, and 70 mph is the daytime default for numbered highways, not a city street."},"2":{"q":"Usted conduce por una carretera numerada de Texas a media tarde. Las condiciones son despejadas y secas, pero no ha visto ni un solo letrero de límite de velocidad durante varias millas. ¿Cuál es la velocidad máxima a la que puede conducir legalmente según la ley básica de velocidad?","options":["75 mph, porque ese es el límite en todas las carreteras rurales de Texas","30 mph, porque ese es el límite predeterminado donde no hay letreros","70 mph, el límite predeterminado diurno en carreteras numeradas","85 mph, la velocidad más alta permitida en cualquier lugar de Texas"],"explanation":"Where no sign is posted, the default daytime limit on numbered highways in Texas is 70 mph. The 30 mph trap is the default for urban districts, not numbered highways, and 75 and 85 mph apply only to specific posted Interstates and tollways, not as a general default."},"3":{"q":"Está conduciendo por una autopista interestatal rural de Texas con un límite señalizado de 75 mph. Después de varias millas pasa a una autopista de peaje específica de Texas, y ahora las señales indican 85 mph. El tráfico es ligero, el pavimento está seco y la visibilidad es clara. ¿Cuál es la velocidad máxima a la que puede conducir legalmente en este tramo de la autopista de peaje?","options":["70 mph, porque ese es el máximo diurno estatal para carreteras numeradas","75 mph, porque ese era el límite en la interestatal que acaba de dejar","80 mph, porque la ley de Texas limita todas las vías a 80 mph","85 mph, porque esa es la velocidad señalizada en esta autopista de peaje específica"],"explanation":"En las carreteras de Texas puede conducir legalmente hasta el límite de velocidad señalizado cuando las condiciones son seguras, y algunas autopistas de peaje específicas de Texas tienen señales de hasta 80 a 85 mph. Las opciones de 70 y 75 mph son límites reales para otras vías, pero no anulan la señal de mayor velocidad de esta autopista de peaje."},"4":{"q":"Conduce frente a una escuela primaria a las 7:45 a.m. La señal de zona escolar indica '20 MPH CUANDO PARPADEE', y las luces amarillas de la señal están parpadeando. ¿Cuál es la velocidad correcta para conducir aquí?","options":["20 mph, porque debe obedecer el límite reducido de zona escolar señalizado mientras las luces estén parpadeando","30 mph, el límite urbano predeterminado, ya que el límite de zona escolar solo se aplica al carril junto a la acera","Cualquier velocidad segura por debajo del límite normal, porque las luces parpadeantes son solo una advertencia, no una ley","70 mph, el límite de carretera diurno, ya que el límite reducido solo se aplica después de que los niños salgan del edificio"],"explanation":"When school-zone lights are flashing (or children are present), you must obey the posted reduced limit, typically 20 mph. The 30 mph default applies only on ordinary urban streets without a posted school-zone sign, so it is the wrong limit here."},"5":{"q":"Está conduciendo junto a una escuela primaria por la mañana. Las luces de la zona escolar están parpadeando y hay niños en la acera. Su teléfono suena con una llamada del trabajo. ¿Qué le exige la ley de Texas?","options":["Contestar la llamada, ya que el límite de velocidad de la zona escolar solo restringe a qué velocidad puede conducir","No tocar el teléfono de mano, porque usar un teléfono de mano es ilegal en una zona escolar activa","Contestar la llamada pero reducir a 20 mph por debajo del límite indicado mientras habla","Detenerse a menos de 15 pies del cruce peatonal escolar para contestar la llamada de forma segura"],"explanation":"In an active school zone (lights flashing or children present), Texas law prohibits using a handheld phone, so you must not answer the call. Option A is wrong because the rule covers phone use, not just speed; the 20-mph-below figure in C is the Move Over/Slow Down rule for stopped emergency vehicles, not school zones."},"6":{"q":"Conduce por una carretera de dos carriles al límite señalizado de 55 mph cuando aparece una niebla espesa y la visibilidad cae bruscamente. ¿Qué debe hacer?","options":["Mantener las 55 mph, ya que es el límite legal señalizado y tiene derecho a conducir a esa velocidad","Encender las luces altas y mantener su velocidad actual para ver más lejos","Reducir la velocidad por debajo del límite señalizado para adecuarla a la visibilidad reducida y a las condiciones de la vía","Salirse al acotamiento derecho y estacionarse allí hasta que la niebla se disipe por completo"],"explanation":"Texas's basic speed law requires you to never drive faster than is safe for conditions, so you must slow below the posted limit in fog. Keeping 55 mph (A) ignores that the posted number is only a maximum for ideal conditions, and high beams (B) actually reflect off fog and worsen visibility."},"7":{"q":"Llega a un tranquilo cruce residencial sin señales de alto, señales de ceda el paso ni semáforos en ninguna dirección. Una camioneta en la calle transversal claramente llegó al cruce un par de segundos antes que usted y está esperando para seguir de frente. ¿Qué debe hacer?","options":["Avanzar primero, porque la camioneta debe ceder el paso al vehículo que está a su derecha","Avanzar primero, porque el tránsito en la vía principal tiene el derecho de paso","Ambos deben tratarlo como un alto de cuatro vías y usted avanza si está a la derecha","Ceder el paso a la camioneta y dejar que pase primero, porque llegó al cruce antes que usted"],"explanation":"At an uncontrolled intersection, you must yield to the vehicle that arrived first, so the pickup truck goes through before you. The 'yield to the driver on your right' rule only applies when two vehicles reach the intersection at the same time, which is not the case here."},"8":{"q":"Usted llega a una intersección de un vecindario que no tiene señales de alto, señales de ceda el paso ni semáforos en ninguna dirección. Otro auto llega a la intersección por su derecha exactamente en el mismo momento que usted, y ambos tienen la intención de seguir de frente. ¿Qué debe hacer?","options":["Dejar que el auto a su derecha pase primero y luego avanzar una vez que haya despejado la intersección.","Avanzar primero, porque el vehículo de la derecha debe ceder el paso al vehículo de la izquierda.","Avanzar de inmediato, ya que el conductor que va de frente siempre tiene la preferencia sobre el que gira.","Ambos deben detenerse por completo y esperar, porque una intersección sin control se trata igual que un alto en todas las direcciones."],"explanation":"At an uncontrolled intersection where two vehicles arrive at the same time, you must yield to the driver on your right. The car is on your right, so it goes first; the idea that the left vehicle has priority or that you must treat it as an all-way stop is incorrect."},"9":{"q":"Está detenido en un semáforo en verde esperando para girar a la izquierda en una intersección. Un automóvil se aproxima en sentido contrario yendo recto, y un peatón comienza a cruzar la calle a la que desea girar. ¿Qué debe hacer antes de completar su giro a la izquierda?","options":["Girar rápidamente antes de que llegue el automóvil que se aproxima, ya que la luz verde le da el derecho de paso","Ceder el paso tanto al automóvil que se aproxima como al peatón, y luego completar su giro cuando sea seguro","Ceder el paso solo al automóvil que se aproxima, porque los peatones deben esperar a que los vehículos despejen la intersección","Avanzar primero porque el conductor a su derecha debe cederle el paso"],"explanation":"When making a left turn you must yield to oncoming traffic and to pedestrians, so you wait for both the approaching car and the crossing pedestrian before turning. A green light does not give a left-turning driver priority over oncoming traffic, and pedestrians in a crosswalk always have the right of way."},"10":{"q":"Usted conduce por una calle residencial que termina en una calle principal con mucho tráfico, formando una intersección en T. No hay señales de alto, semáforos ni otros controles en el cruce. Al llegar al final de su calle, un automóvil se aproxima por su izquierda en la calle principal. ¿Qué debe hacer?","options":["Avanzar primero, porque en una intersección sin control el vehículo a la derecha siempre tiene el derecho de paso","Avanzar primero, porque el automóvil en la calle principal debe ceder el paso al tráfico que entra desde una calle lateral","Ceder el paso al automóvil en la calle principal, porque el tráfico en la vía principal (la parte superior de la T) tiene el derecho de paso","Ceder el paso solo si el otro automóvil señala un giro; de lo contrario, usted puede entrar primero a la intersección"],"explanation":"At a T-intersection, the road that ends (the stem of the T) must yield to traffic on the through road that forms the top of the T, so you wait for the approaching car. The right-on-arrival rule applies only to vehicles arriving together at an equal, uncontrolled crossing, not to a side road meeting a through road."},"11":{"q":"Usted se acerca a una rotonda de un solo carril en Texas y hay dos autos circulando ya por el círculo a su izquierda. ¿Qué debe hacer para entrar de forma correcta y segura?","options":["Entrar de inmediato y girar a la izquierda (en sentido horario), ya que el tránsito en el círculo debe ceder el paso a los vehículos que entran","Detenerse por completo y esperar a que todo el tránsito del círculo salga antes de entrar","Ceder el paso a los autos en el círculo y luego entrar a la izquierda (en sentido horario) cuando haya un espacio","Ceder el paso a los autos que ya están en el círculo y luego entrar a la derecha (en sentido antihorario) cuando haya un espacio"],"explanation":"At a roundabout you must yield to traffic already in the circle and enter to the right, traveling counter-clockwise. Option C uses the correct yield rule but the wrong direction, and you do not need a full stop or to wait for the circle to empty if a safe gap is available."},"12":{"q":"Está conduciendo en el carril derecho de una calle urbana de un solo sentido y dos carriles cuando oye una sirena y ve una ambulancia que se acerca por detrás con sus luces de emergencia encendidas. Hay espacio libre junto a la acera a su derecha. ¿Qué debe hacer?","options":["Orillarse hacia la derecha y detenerse hasta que la ambulancia haya pasado.","Mantener su velocidad y permanecer en su carril para que la ambulancia pueda rebasarlo por la izquierda.","Cambiarse un carril o reducir a 20 mph por debajo del límite de velocidad y seguir conduciendo.","Acelerar para cruzar la intersección que tiene adelante antes de que la ambulancia lo alcance."],"explanation":"When an emergency vehicle approaches with lights and siren, you must pull over to the right and stop until it passes. Option C describes the separate Move Over/Slow Down law for stopped emergency vehicles on the roadside, not for an emergency vehicle responding behind you, and the other choices fail to yield."},"13":{"q":"Está detenido en una luz verde, esperando para girar a la derecha en una intersección concurrida en Houston. Un peatón acaba de bajar de la acera y está cruzando por el paso de peatones hacia el carril al que usted quiere girar. ¿Qué debe hacer?","options":["Hacer su giro rápidamente antes de que el peatón llegue a su trayectoria, ya que tiene la luz verde","Ceder el paso al peatón en el paso de peatones y esperar hasta que haya despejado su trayectoria de forma segura","Avanzar si primero toca la bocina para advertir al peatón que se apure","Avanzar hacia el paso de peatones para que el peatón sepa que debe caminar por detrás de su vehículo"],"explanation":"Pedestrians in a crosswalk always have the right of way, so you must yield and wait until they have safely cleared your path before turning, even on a green light. Having a green signal does not allow you to turn through a pedestrian who is already lawfully crossing, and honking or edging forward does not transfer that right of way to you."},"14":{"q":"Está detenido en un semáforo en verde, esperando para girar a la derecha. Un peatón con gafas oscuras baja de la acera al cruce peatonal, moviendo un bastón blanco frente a él y claramente dirigiéndose a cruzar su trayectoria. ¿Qué debe hacer?","options":["Avanzar lentamente en el giro, ya que el semáforo en verde le da a su vehículo el derecho de paso sobre los peatones que cruzan","Tocar la bocina para advertir al peatón y luego completar el giro a la derecha antes de que llegue a su carril","Detenerse por completo y ceder el paso, permitiendo que el peatón con el bastón blanco cruce con seguridad antes de girar","Esperar solo si el peatón ya está en su carril; de lo contrario, girar por delante de él"],"explanation":"Texas law requires drivers to yield to a blind pedestrian using a white cane or guide dog, and pedestrians in a crosswalk always have the right of way. A green light does not override your duty to yield to a pedestrian lawfully in the crosswalk, so you must stop and let them cross."},"15":{"q":"Se acerca a una luz verde en una intersección y está a punto de seguir recto. Desde la calle transversal, una fila de autos con los faros encendidos y pequeñas banderas sigue a una carroza fúnebre, entrando lentamente a la intersección contra su luz roja como parte de un cortejo fúnebre. ¿Qué debe hacer?","options":["Avanzar con su luz verde, ya que el cortejo tiene la luz roja y debe detenerse por usted","Tocar la bocina y avanzar para tomar su turno, luego incorporarse en un hueco entre los vehículos del cortejo","Orillarse a la derecha y detenerse por completo hasta que pase todo el cortejo, como lo haría con un vehículo de emergencia","Ceder el paso y esperar a que todo el cortejo fúnebre cruce la intersección antes de continuar"],"explanation":"A funeral procession has the right of way at intersections, so you must yield and let the whole procession pass even though you have a green light. Proceeding on green ignores the procession's right of way, and pulling fully to the right is the rule for emergency vehicles with lights and siren, not a funeral procession."},"16":{"q":"Está conduciendo por una calle de la ciudad y planea girar a la derecha en la siguiente intersección. Quiere señalizar correctamente para que los demás conductores conozcan sus intenciones a tiempo. ¿En qué punto debe comenzar a señalizar antes del giro?","options":["Al menos 100 pies antes de la intersección donde va a girar","Al menos 20 pies antes de la intersección donde va a girar","Solo después de haberse pasado al carril derecho cerca del bordillo","Al menos 30 pies antes de la intersección donde va a girar"],"explanation":"Texas law requires you to signal at least 100 feet before making a turn or changing lanes so other drivers have enough warning. The 20-foot and 30-foot distances are real Texas rules (no parking within 20 feet of a crosswalk, 30 feet of a stop sign), but they do not apply to signaling for a turn."},"17":{"q":"Está conduciendo por una calle de un solo sentido con dos carriles y necesita girar a la derecha en la próxima intersección. No hay ninguna señal que restrinja el uso de carriles para los giros. ¿En qué carril debe estar y dónde debe posicionar su vehículo para hacer el giro correctamente?","options":["En el carril izquierdo, manteniéndose cerca de la línea central al girar","En el carril derecho, cerca del bordillo al girar","En cualquier carril, siempre que señale al menos 100 pies antes de girar","En el carril derecho, pero manteniéndose bien alejado del bordillo para dejar espacio a los ciclistas"],"explanation":"A right turn must be made from the right lane, keeping close to the curb. Option A describes the correct setup for a left turn, and signaling distance (Option C) does not change the lane and curb requirement for a right turn."},"18":{"q":"Usted se aproxima a una intersección en una calle de doble sentido y planea girar a la izquierda hacia la calle transversal. Hay dos carriles en su dirección. Para colocar correctamente su vehículo para el giro, ¿a qué carril debe cambiarse antes de la intersección?","options":["Al carril derecho, manteniéndose cerca del bordillo","A cualquier carril, siempre que señalice al menos 100 pies antes","Al carril izquierdo, el más cercano a la línea central","Al carril central de giro a la izquierda de doble sentido, usándolo para avanzar hasta la intersección"],"explanation":"A left turn must be made from the left lane, the one nearest the center line, so you cross the least amount of opposing traffic. The right lane is for right turns, and a two-way left-turn lane is only for turning, not for traveling up to an intersection on a two-way street with regular through lanes."},"19":{"q":"Se detiene por completo en un semáforo en rojo en el carril derecho, con la intención de girar a la derecha. No hay ninguna señal en la intersección que prohíba el giro en rojo, y el tráfico transversal está despejado. ¿Qué debe hacer?","options":["Esperar a que el semáforo se ponga en verde antes de girar, porque los giros a la derecha nunca están permitidos con el semáforo en rojo.","Girar solo después de ceder el paso al tráfico que viene en sentido contrario, igual que en un giro a la izquierda.","Girar sin detenerse, ya que el carril ya está libre de tráfico transversal.","Realizar el giro a la derecha tras su parada completa, ya que ninguna señal lo prohíbe y el tráfico está despejado."],"explanation":"In Texas, a right turn on red is allowed after coming to a full stop, unless a sign prohibits it; with no such sign and clear traffic, you may turn. Option C is wrong because a complete stop is always required first, and the oncoming-traffic yield in B applies to left turns, not a right turn on red."},"20":{"q":"Está detenido en un semáforo en rojo en una calle de un solo sentido y tiene la intención de girar a la izquierda hacia otra calle de un solo sentido cuyo tráfico circula hacia la izquierda. Ninguna señal en la intersección prohíbe el giro. ¿Qué puede hacer legalmente?","options":["Girar a la izquierda después de detenerse por completo, cuando el camino esté despejado","Girar a la izquierda sin detenerse, ya que ambas calles son de un solo sentido","Esperar la luz verde, porque en Texas nunca se permite girar a la izquierda con el semáforo en rojo","Girar a la izquierda en rojo solo si además proviene de una calle de doble sentido"],"explanation":"A left turn on red is allowed only from a one-way street onto a one-way street, and only after a full stop when no sign prohibits it. You may not roll through without stopping (B), and the turn is permitted in Texas in this exact situation, so waiting for green is not required (C)."},"21":{"q":"Conduce por el carril central de una calle de un solo sentido con tres carriles y necesita girar a la derecha en la próxima intersección. ¿Desde qué carril debe completar el giro?","options":["Desde el carril central, ya que está posicionado en el centro de la vía","Desde el carril más a la derecha, el carril más cercano a la dirección hacia la que gira","Desde el carril más a la izquierda, porque en una calle de un solo sentido todos los giros deben comenzar por la izquierda","Desde cualquier carril, ya que la posición del carril no importa en una calle de un solo sentido"],"explanation":"On a one-way street you turn from the lane nearest the direction you are turning, so a right turn must be made from the rightmost lane. Option C confuses this with the left-turn rule, and the left lane is correct only when turning left."},"22":{"q":"En una carretera de dos carriles, se cambia al carril izquierdo para adelantar a un camión lento. Después de acelerar y rebasarlo, quiere regresar al carril derecho. ¿Cuándo es seguro volver a su carril?","options":["Tan pronto como su parachoques delantero pase el frente del camión","Solo después de que el camión le haga señales con las luces para indicarle que regrese","Cuando pueda ver el camión rebasado en su espejo retrovisor","Después de haber recorrido al menos 100 pies más allá del camión"],"explanation":"You may return to your lane only when you can see the passed vehicle in your rearview mirror, which confirms you have enough space ahead of it to merge safely. Clearing only your front bumper (A) leaves too little room and could cut the truck off, and there is no rule about a 100-foot distance for merging back."},"23":{"q":"Conduce por una carretera rural de dos carriles detrás de un tractor lento. Al acercarse a la cima de una colina, la carretera de adelante queda oculta y no puede ver si algún vehículo viene en sentido contrario. ¿Qué debe hacer respecto a rebasar al tractor?","options":["Rebasar rápidamente mientras está en la colina, ya que el tractor va muy por debajo del límite de velocidad","Rebasar por el acotamiento derecho para no invadir el carril contrario","Rebasar ahora, pero solo después de tocar la bocina para advertir al tránsito que viene","No rebasar; esperar hasta haber pasado la colina y poder ver claramente la carretera de adelante"],"explanation":"You must not pass on a hill where your view of oncoming traffic is blocked, so you should wait until you can see the road ahead clearly. Passing on the hill (A), sounding the horn (C), or using the right shoulder (B) are all unsafe and illegal because you still cannot verify the lane is clear and passing must be done on the left."},"24":{"q":"Conduce por una carretera rural de dos carriles detrás de un camión lento y quiere rebasarlo. Más adelante, en el acotamiento derecho, ve una señal amarilla en forma de banderín (triángulo apuntado). ¿Qué le indica esta señal sobre rebasar?","options":["Está entrando en una Zona de No Rebasar, así que no debe rebasar el camión aquí","Es una señal de Ceda el Paso, así que puede rebasar una vez que se despeje el tránsito en sentido contrario","Marca un carril central de giro a la izquierda más adelante que puede usar para rebasar","Es solo una advertencia de un cruce ferroviario, y aún se permite rebasar"],"explanation":"A pennant-shaped sign on the right side of the road marks the start of a No Passing Zone, so you must not pass here. A Yield sign is a downward-pointing triangle facing oncoming drivers, not a side-mounted pennant, which makes option B the trap."},"25":{"q":"Está conduciendo por el carril izquierdo de una autopista de tres carriles en Texas a la velocidad máxima señalizada. Un vehículo más rápido se acerca por detrás y quiere adelantarlo. ¿Qué debe hacer?","options":["Mantener su velocidad y permanecer en el carril izquierdo, ya que va al límite legal","Cambiarse a un carril a su derecha para dejar pasar al vehículo más rápido, y luego mantenerse a la derecha","Acelerar por encima del límite para que el vehículo de atrás ya no necesite adelantarlo","Detenerse en el carril izquierdo y hacerle señas al vehículo más rápido para que lo rodee"],"explanation":"In Texas you must keep right except to pass, and slower traffic keeps right, so you should move into a lane to your right and let the faster vehicle pass. Staying in the left lane just because you are at the limit is wrong, and speeding up or stopping would create a hazard."},"26":{"q":"Conduce de noche por una carretera de dos carriles que no conoce. A su izquierda, una línea amarilla continua corre junto al carril por donde circula el tráfico, y nota los faros de autos que vienen hacia usted al otro lado de esa línea. ¿Qué le indica esta línea amarilla central sobre la carretera?","options":["El carril del otro lado va en la misma dirección que usted, así que puede cruzar a él cuando esté despejado","La carretera es de un solo sentido, y la línea amarilla solo marca el borde exterior de la calzada","El tráfico al otro lado de la línea se mueve en sentido contrario, hacia usted","La línea amarilla es solo una marca del arcén, y no hay ningún carril de tráfico más allá de ella"],"explanation":"Yellow center lines divide traffic moving in opposite directions, which is why you see oncoming headlights across that line. White lines (not yellow) separate lanes traveling the same direction, so options suggesting same-direction or one-way travel are wrong."},"27":{"q":"Conduce por una carretera de cuatro carriles y observa que la línea que separa su carril del carril inmediatamente a su izquierda es blanca continua, mientras que la línea que recorre el centro de la carretera es amarilla. ¿Qué le indica la línea blanca entre usted y el carril de su izquierda sobre ese carril contiguo?","options":["El tránsito en ese carril circula en sentido contrario, por lo que nunca debe invadirlo","El carril a su izquierda es un carril central de giro a la izquierda en ambos sentidos, destinado solo a girar","Puede cambiarse libremente a ese carril en cualquier momento porque las líneas blancas siempre son solo orientativas","El tránsito en ese carril circula en el mismo sentido que usted"],"explanation":"White lines separate lanes of traffic traveling in the same direction, so the lane to your left carries traffic going your way. Yellow lines (option A) divide opposite-direction traffic and mark the center of the road, which is the trap here."},"28":{"q":"El tráfico se acumula en su carril, así que se mete en el carril central marcado con flechas de giro a la izquierda en ambos extremos y avanza por él durante media cuadra para pasar a los autos lentos. ¿Por qué es ilegal?","options":["Un carril central de giro a la izquierda de doble sentido está reservado solo para hacer giros a la izquierda y no puede usarse para circular, ni siquiera brevemente.","Puede circular por el carril central de giro a la izquierda solo si permanece en él menos de 200 pies.","El carril central es un carril de adelantamiento, pero solo puede usarlo para adelantar por la derecha.","Conducir por el carril central está permitido siempre que señalice con al menos 100 pies de anticipación."],"explanation":"A two-way left-turn lane (the center lane marked with arrows) is only for preparing to turn left, never for driving through traffic. Option B invents a distance allowance, and the 100-foot signal rule in D applies to turns and lane changes, not to using this lane for travel."},"29":{"q":"Usted se acerca a una señal de alto en una intersección. Hay una línea de alto blanca claramente pintada en el pavimento a unos pocos pies antes del cruce peatonal, pero desde allí su visión del tráfico transversal está parcialmente bloqueada por un camión estacionado. ¿Cuál es el procedimiento correcto?","options":["Cruzar lentamente la línea de alto y detenerse solo cuando pueda ver el tráfico transversal en el cruce peatonal","Detenerse por completo detrás de la línea de alto primero, luego avanzar un poco y detenerse de nuevo si es necesario para ver","Reducir a unas 5 mph en la línea; solo se requiere un alto total si hay otro vehículo presente","Detenerse sobre el cruce peatonal para tener la mejor visión posible del tráfico transversal"],"explanation":"Texas law requires a full stop at a stop sign behind the stop line or crosswalk, so you must stop there first even if your view is blocked, then creep forward and stop again to see. Rolling through the line, stopping on the crosswalk, or only slowing down all violate the stop-line requirement."},"30":{"q":"Conduce por una carretera de dos carriles con un carril en cada sentido y sin mediana. Delante de usted, en su mismo sentido, un autobús escolar se detiene, enciende sus luces rojas intermitentes y extiende el brazo de pare. ¿Qué debe hacer?","options":["Reducir a 20 mph por debajo del límite de velocidad y pasar el autobús con cuidado por la izquierda","Continuar a velocidad reducida solo si no se ven niños cerca del autobús","Detenerse por completo y permanecer detenido hasta que las luces rojas dejen de parpadear y el brazo de pare se retraiga","Detenerse solo si está detrás del autobús; el tráfico en sentido contrario en esta carretera puede continuar"],"explanation":"On a road with no physical median or barrier, all traffic from both directions must stop for a school bus showing flashing red lights and an extended stop arm, and stay stopped until the lights stop and the arm folds in. Option D states the median exception, but here there is no median, so traffic from both directions must stop; the 20-mph-below rule in A applies to stopped emergency/utility vehicles, not school buses."},"31":{"q":"Va con retraso y ve un espacio libre junto al bordillo en una calle concurrida del centro. Justo delante del espacio hay un hidrante contra incendios. Para estacionar legalmente, ¿a qué distancia del hidrante debe mantener su vehículo?","options":["Al menos 30 pies, la misma distancia requerida respecto a una señal de alto o un semáforo","Al menos 20 pies, la misma distancia requerida respecto a un paso de peatones en una intersección","Está bien estacionar pegado al hidrante siempre que no bloquee la acera","Al menos 15 pies"],"explanation":"La ley de Texas prohíbe estacionar a menos de 15 pies de un hidrante contra incendios para que los bomberos puedan acceder a él en una emergencia. Las distancias de 30 pies y 20 pies son reales en Texas, pero corresponden a las señales/semáforos de alto y a los pasos de peatones respectivamente, no a los hidrantes."},"32":{"q":"Está buscando un lugar para estacionar en una concurrida calle del centro, cerca de una intersección. Hay un cruce peatonal marcado donde la calle lateral se une a la vía principal. Para estacionar legalmente, ¿a qué distancia de ese cruce peatonal debe permanecer su vehículo?","options":["Al menos 20 pies del cruce peatonal","Al menos 15 pies del cruce peatonal","Al menos 30 pies del cruce peatonal","Al menos 10 pies del cruce peatonal"],"explanation":"Texas law prohibits parking within 20 feet of a crosswalk at an intersection so drivers turning into the street can see crossing pedestrians. The 15-foot figure is the no-parking distance for a fire hydrant, and 30 feet applies to a stop sign or signal, so both are real rules placed in the wrong situation."},"33":{"q":"Está buscando un lugar para estacionar en una concurrida calle del centro. Ve un tramo libre de acera justo al lado de la esquina donde hay una señal de alto. Para estacionar legalmente, ¿a qué distancia de esa señal de alto debe estar su vehículo?","options":["Al menos 15 pies","Al menos 30 pies","Al menos 20 pies","Al menos 50 pies"],"explanation":"In Texas you may not park within 30 feet of a stop sign or traffic signal so your vehicle does not block other drivers' view of it. The 15-foot rule applies to fire hydrants and the 20-foot rule to crosswalks at an intersection, so those distances are traps from other parking rules."},"34":{"q":"Va con retraso y quiere dejar el auto solo un minuto para comprar un café. Al mirar alrededor, ve varios espacios libres a lo largo de la cuadra. ¿Cuál de estos es un lugar LEGAL para estacionar?","options":["A la mitad de un cruce peatonal marcado, ya que solo sobresale parte de su auto","Justo frente a la entrada de cochera de una vivienda, porque solo estará ausente un minuto","Junto al bordillo derecho, de su lado de una calle de doble sentido, lejos de cualquier entrada, cruce o hidrante","De frente al tráfico que viene, contra el bordillo izquierdo, donde está el único espacio libre"],"explanation":"Parking is legal only when you are on the correct (right) side of the street and not blocking a driveway, crosswalk, sidewalk, hydrant, or traffic. Options A and B are prohibited because you may never park on a crosswalk or in front of a driveway, and D is illegal because parking against the left curb means facing the wrong way on a two-way street."},"35":{"q":"Estaciona en una calle empinada que sube cuesta arriba y hay un bordillo en el borde derecho de la vía. Antes de salir del auto, ¿hacia dónde debe girar las ruedas delanteras?","options":["Hacia el bordillo, para que las llantas se traben contra él si el auto rueda","Rectas, ya que el bordillo por sí solo sujetará el auto en su lugar","Bruscamente a la izquierda, hacia el centro de la vía, para mantener las llantas fuera del bordillo","Lejos del bordillo, para que un auto que ruede se desplace de vuelta contra el bordillo"],"explanation":"When parking uphill with a curb, turn the wheels away from the curb so that if the car rolls back, the front tire catches against the curb and stops it. Turning toward the curb is correct only when parking downhill, and the curb by itself is never a substitute for properly aimed wheels and a set parking brake."},"36":{"q":"Estaciona su auto mirando cuesta abajo en una calle con bordillo. Antes de salir del vehículo, ¿hacia dónde debe girar las ruedas delanteras?","options":["Hacia el bordillo, para que el auto choque contra el bordillo si se mueve","Lejos del bordillo, para que el auto ruede hacia el bordillo si se mueve","Rectas, ya que el freno de mano sujetará el auto","Hacia el bordillo solo si además está en el lado equivocado de la calle"],"explanation":"When parking downhill next to a curb, turn the front wheels toward the curb so that if the car rolls, the curb blocks it. Turning the wheels away from the curb is the correct method for parking uphill, not downhill, which makes that option a common reversal trap."},"37":{"q":"Se detiene en el arcén de grava de un camino rural plano para atender una llamada telefónica. Aquí no hay bordillo, solo un arcén de tierra inclinado que desciende hacia su derecha. Antes de bajar del vehículo, ¿hacia qué lado debe girar las ruedas delanteras?","options":["Rectas, ya que el camino es plano y no hay bordillo contra el cual apoyarlas","Hacia el arcén (a la derecha), para que el vehículo ruede fuera del camino si se mueve","Hacia el centro del camino (a la izquierda), para que el tráfico vea sus ruedas delanteras","No importa en un camino plano; solo ponga el freno de mano y déjelas como están"],"explanation":"When parking where there is no curb, you should always turn the front wheels toward the shoulder (to the right) so the vehicle would roll away from traffic and off the road if it starts to move. Turning them straight or toward the road is wrong because, even on ground that looks flat, a rolling vehicle could drift into the travel lane and into oncoming traffic."},"38":{"q":"Conduce a 65 mph por una carretera de dos carriles en Texas cuando ve más adelante un camión de mantenimiento de TxDOT detenido en el arcén derecho con sus luces ámbar destellando. Hay tráfico constante en el carril izquierdo, por lo que no puede cambiar de carril con seguridad. ¿Qué le exige hacer la ley de Move Over/Slow Down (Cámbiese de carril/Reduzca la velocidad)?","options":["Mantener la velocidad pero tocar la bocina para advertir a los trabajadores al pasar","Detenerse por completo detrás del camión y esperar a que un trabajador le indique con la mano que pase","Reducir la velocidad a 45 mph (20 mph por debajo del límite de velocidad) hasta haber pasado el camión detenido","Reducir a 20 mph y avanzar solo cuando el arcén esté despejado"],"explanation":"When you cannot safely move over a lane, Texas's Move Over/Slow Down law requires you to slow to 20 mph below the posted speed limit, which is 45 mph in a 65 mph zone. Option D wrongly uses 20 mph itself (a school-zone figure) instead of 20 mph below the limit, and stopping or just honking is not required."}},"learn-rules-of-the-road":{"0":{"q":"Según la ley básica de velocidad de Texas, ¿a qué velocidad puede conducir?","options":["Nunca más rápido de lo que es seguro para las condiciones actuales","Siempre exactamente el límite de velocidad indicado","Tan rápido como permita su vehículo","10 mph por encima del límite si hay poco tráfico"],"explanation":"Texas's basic speed law means you must never drive faster than is safe for the current conditions."},"1":{"q":"En Texas, ¿cuál es el límite de velocidad predeterminado en un distrito urbano donde no hay señal?","options":["20 mph","30 mph","45 mph","55 mph"],"explanation":"Where unposted, the default speed limit in a Texas urban district is 30 mph."},"2":{"q":"En una carretera numerada durante el día sin señal indicada, ¿cuál es el límite de velocidad predeterminado?","options":["30 mph","55 mph","70 mph","85 mph"],"explanation":"Where unposted, the default daytime speed limit on numbered highways is 70 mph."},"3":{"q":"¿Cuál es el límite de velocidad más alto permitido en algunas autopistas de peaje de Texas?","options":["65 mph","70 mph","75 mph","85 mph"],"explanation":"Some specific Texas tollways are posted with speed limits as high as 85 mph."},"4":{"q":"¿Qué debe hacer en una zona escolar cuando las luces parpadean o hay niños presentes?","options":["Obedecer el límite de velocidad reducido indicado","Conducir al límite de velocidad normal","Acelerar para salir de la zona","Detenerse por completo y esperar"],"explanation":"In a school zone you must obey the posted reduced limit (often 20 mph) when lights flash or children are present."},"5":{"q":"En una zona escolar activa en Texas, ¿es legal usar un teléfono de mano?","options":["Sí, siempre","No, es ilegal","Solo después de las 9 p.m.","Solo estando estacionado cerca"],"explanation":"Using a handheld phone in an active school zone is illegal in Texas."},"6":{"q":"¿Cuándo debe reducir su velocidad de conducción?","options":["Solo en autopistas secas y vacías","Solo cuando no hay peatones","Con lluvia, niebla, tráfico pesado, en curvas y cerca de peatones","Solo de noche en carreteras rectas"],"explanation":"You should always reduce speed in rain, fog, heavy traffic, on curves, and near pedestrians."},"7":{"q":"En una intersección sin control, ¿qué vehículo tiene el derecho de paso?","options":["El vehículo más rápido","El vehículo más grande","El vehículo de la izquierda","El vehículo que llegó primero"],"explanation":"At an uncontrolled intersection, you yield to the vehicle that arrived first."},"8":{"q":"En una intersección sin control, si dos vehículos llegan al mismo tiempo, ¿quién tiene el derecho de paso?","options":["El conductor de la derecha","El conductor de la izquierda","El vehículo más rápido","El vehículo más grande"],"explanation":"When two vehicles arrive at the same time, yield to the driver on your right."},"9":{"q":"Al girar a la izquierda, ¿a quién debe ceder el paso?","options":["Solo a los peatones","Al tráfico que viene en sentido contrario y a los peatones","Solo al tráfico que viene detrás de usted","A nadie, usted tiene el derecho de paso"],"explanation":"When turning left, you must yield to oncoming traffic and to pedestrians."},"10":{"q":"En una intersección en T, ¿qué tránsito tiene el derecho de paso?","options":["El tránsito que gira a la izquierda","El vehículo de la izquierda","El tránsito de la vía principal","El que llega más tarde"],"explanation":"Traffic on the through road (the top of the T) has the right of way."},"11":{"q":"En una rotonda, ¿quién tiene el derecho de paso?","options":["Los conductores que esperan para entrar","El vehículo más rápido","Quien toque la bocina primero","El tránsito que ya está en el círculo"],"explanation":"At a roundabout, you must yield to traffic already in the circle before entering."},"12":{"q":"¿Qué debe hacer cuando se acerca un vehículo de emergencia con luces y sirena?","options":["Hacerse a la derecha y detenerse hasta que pase","Acelerar para apartarse del camino","Detenerse en medio de su carril","Girar a la izquierda delante de él"],"explanation":"Pull over to the right and stop until the emergency vehicle has passed."},"13":{"q":"¿Quién tiene el derecho de paso en un cruce peatonal?","options":["El vehículo más cercano","Los peatones","El vehículo más rápido","Los vehículos que giran"],"explanation":"Pedestrians in a crosswalk always have the right of way."},"14":{"q":"¿A quién debe ceder el paso si lleva un bastón blanco o usa un perro guía?","options":["A un auto estacionado","A un trabajador vial","A un peatón ciego","A un ciclista"],"explanation":"You must yield to a blind pedestrian carrying a white cane or using a guide dog."},"15":{"q":"¿Quién tiene el derecho de paso en las intersecciones durante una procesión fúnebre?","options":["El tráfico transversal","Quien llegue primero","El conductor de la derecha","La procesión fúnebre"],"explanation":"A funeral procession has the right of way at intersections."},"16":{"q":"¿Con qué anticipación debe señalizar antes de un giro o cambio de carril?","options":["Al menos 100 pies","Al menos 25 pies","Al menos 250 pies","Al menos 500 pies"],"explanation":"In Texas, you must signal at least 100 feet before a turn or lane change."},"17":{"q":"¿Qué carril debe usar para girar a la derecha?","options":["El carril izquierdo","El carril derecho, cerca del bordillo","El carril central","Cualquier carril libre"],"explanation":"A right turn should be made from the right lane, close to the curb."},"18":{"q":"¿Desde qué carril debe hacer un giro a la izquierda?","options":["El carril derecho","El carril central","El carril izquierdo","Cualquier carril libre"],"explanation":"A left turn should be made from the left lane."},"19":{"q":"¿Cuándo se permite girar a la derecha con luz roja en Texas?","options":["Nunca, bajo ninguna condición","Solo de noche","Sin detenerse primero","Después de una parada completa, a menos que una señal lo prohíba"],"explanation":"A right turn on red is allowed after coming to a full stop, unless a sign prohibits it."},"20":{"q":"¿Cuándo se permite girar a la izquierda con luz roja en Texas?","options":["De una calle de un solo sentido a otra de un solo sentido, después de detenerse por completo","Desde cualquier calle, después de detenerse por completo","Hacia una calle de doble sentido, después de detenerse por completo","Nunca, bajo ninguna condición"],"explanation":"In Texas, a left turn on red is only allowed from a one-way street onto a one-way street after stopping fully."},"21":{"q":"En una calle de un solo sentido, ¿desde qué carril debe girar?","options":["Desde el carril central","Desde el carril más cercano a la dirección hacia la que gira","Desde cualquier carril libre","Desde el carril más alejado de su giro"],"explanation":"On a one-way street, turn from the lane nearest the direction you are turning."},"22":{"q":"¿Por qué lado debe rebasar a otro vehículo?","options":["Por la derecha","Por cualquier lado","Por la izquierda","Por el acotamiento"],"explanation":"You should pass on the left and return to your lane only when you can see the passed vehicle in your mirror."},"23":{"q":"¿Dónde NO debe rebasar a otro vehículo?","options":["En un camino recto y plano","Cuando el carril está despejado","En una calle ancha","En una colina o curva"],"explanation":"You must not pass on a hill or curve because you cannot see oncoming traffic."},"24":{"q":"¿Dónde NO debe rebasar a otro vehículo?","options":["En una intersección o cruce de ferrocarril","En una carretera larga, recta y plana","En un carril de rebase claramente marcado","Donde haya una línea amarilla discontinua en su lado"],"explanation":"It is unsafe and illegal to pass at an intersection or railroad crossing."},"25":{"q":"¿Cuándo puede rebasar a otro vehículo?","options":["Cuando hay una línea amarilla continua de su lado","Cuando la línea de su lado es discontinua","En una colina o curva","En un cruce ferroviario"],"explanation":"You may pass when the yellow line on your side is broken, but not where a solid yellow line is on your side."},"26":{"q":"¿Qué forma tiene la señal que marca una zona de no rebasar?","options":["Redonda","Cuadrada","Banderín (triángulo)","Rombo"],"explanation":"A No Passing Zone is marked by a pennant-shaped (triangular) sign, where passing is not allowed."},"27":{"q":"En una carretera de varios carriles, ¿qué carril debe usar el tráfico más lento?","options":["El carril izquierdo","El carril central","Cualquier carril que elijan","El carril derecho"],"explanation":"Keep right except to pass; slower traffic stays in the right lane."},"28":{"q":"¿Qué separan las líneas centrales amarillas en una carretera?","options":["El tráfico que circula en sentidos opuestos","El tráfico que circula en el mismo sentido","Los espacios de estacionamiento de los carriles","Los carriles para bicicletas de las aceras"],"explanation":"Yellow center lines divide traffic moving in opposite directions."},"29":{"q":"¿Qué separan las líneas blancas en una carretera?","options":["El tráfico que va en direcciones opuestas","Carriles de tráfico que van en la misma dirección","Los espacios de estacionamiento de la carretera","La carretera de la acera"],"explanation":"White lines separate lanes of traffic moving in the same direction."},"30":{"q":"¿Para qué se usa el carril central marcado con flechas de giro a la izquierda?","options":["Para rebasar otros autos","Para circular en el tráfico","Solo para girar a la izquierda","Para estacionar el vehículo"],"explanation":"A two-way left-turn lane is only for turning left, not for travel."},"31":{"q":"En una señal de alto, ¿dónde debe detenerse por completo?","options":["En medio de la intersección","En cualquier lugar donde se sienta seguro","Después de cruzar el paso de peatones","Detrás de la línea de alto o el paso de peatones"],"explanation":"At a stop sign you must come to a full stop behind the stop line or crosswalk."},"32":{"q":"¿Cuándo debe detenerse por un autobús escolar detenido?","options":["Cuando sus luces rojas parpadean y el brazo de parada está afuera","Solo cuando los niños cruzan la calle","Solo si está directamente detrás de él","Nunca, puede pasar despacio"],"explanation":"You must stop for a stopped school bus when its red lights are flashing and its stop arm is out."},"33":{"q":"¿Cuándo debe detenerse ante un autobús escolar detenido con sus luces rojas intermitentes?","options":["Solo si está detrás del autobús","Desde ambas direcciones, salvo que un camellón separe las vías","Nunca, solo reduzca la velocidad","Solo si hay niños cruzando"],"explanation":"You must stop from both directions unless a physical median or barrier separates the roadways."},"34":{"q":"¿Qué tan cerca de una boca de incendios puede estacionar?","options":["A menos de 5 pies","A menos de 10 pies","No más cerca de 15 pies","Justo al lado"],"explanation":"You may not park within 15 feet of a fire hydrant."},"35":{"q":"¿A qué distancia de un cruce peatonal en una intersección no debe estacionar?","options":["5 pies","10 pies","15 pies","20 pies"],"explanation":"You may not park within 20 feet of a crosswalk at an intersection."},"36":{"q":"¿Qué tan cerca de una señal de alto puede estacionar?","options":["No más cerca de 30 pies","No más cerca de 5 pies","No más cerca de 10 pies","No más cerca de 15 pies"],"explanation":"In Texas, you may not park within 30 feet of a stop sign or signal."},"37":{"q":"¿Dónde no puede estacionar su vehículo?","options":["En un espacio de estacionamiento marcado","En un cruce peatonal o una acera","A lo largo del bordillo derecho","En un garaje de estacionamiento"],"explanation":"It is illegal to park on a crosswalk or sidewalk."},"38":{"q":"¿Dónde NO se permite estacionar?","options":["En una calle lateral tranquila","En un estacionamiento marcado","Frente a una entrada para vehículos","Junto a un parquímetro"],"explanation":"You may not park in front of a driveway."},"39":{"q":"¿Dónde no se permite estacionar?","options":["En el lado derecho de la calle","En un espacio de estacionamiento marcado","Junto a un parquímetro","En el lado equivocado de la calle"],"explanation":"You may not park on the wrong side of the street."},"40":{"q":"¿Dónde no se permite estacionar?","options":["Donde bloquearía el tráfico","En un espacio de estacionamiento marcado","En un estacionamiento cubierto","En su propia entrada para autos"],"explanation":"You may not park where you would be blocking traffic."},"41":{"q":"Al estacionar cuesta arriba junto a un bordillo, ¿hacia dónde debe girar las ruedas?","options":["Rectas hacia adelante","Hacia afuera del bordillo","Hacia el bordillo","No importa"],"explanation":"When parking uphill with a curb, turn your wheels away from the curb so the car rolls into the curb if it moves."},"42":{"q":"Al estacionar cuesta abajo junto a un bordillo, ¿hacia dónde debe girar las ruedas delanteras?","options":["Hacia adelante recto","En sentido contrario al bordillo","Hacia el bordillo","No importa"],"explanation":"When parking downhill with a curb, turn your wheels toward the curb so the car rolls into it if it moves."},"43":{"q":"Al estacionar en una pendiente sin bordillo, ¿hacia dónde gira las ruedas?","options":["Rectas hacia adelante","Hacia el centro de la carretera","No importa","Hacia el arcén (a la derecha)"],"explanation":"Without a curb, always turn your wheels toward the shoulder/right so the car rolls off the road if it moves."},"44":{"q":"Según la ley de Cambio de Carril, ¿cuánto debe reducir la velocidad ante un vehículo de emergencia detenido con luces intermitentes?","options":["20 mph por debajo del límite de velocidad","5 mph por debajo del límite de velocidad","10 mph por debajo del límite de velocidad","Hasta detenerse por completo"],"explanation":"You must move over a lane or slow to 20 mph below the speed limit for stopped emergency vehicles."},"45":{"q":"En una intersección sin control, ¿quién tiene el derecho de paso?","options":["El vehículo más rápido","El vehículo que llegó primero","El vehículo más grande","El vehículo de la izquierda"],"explanation":"At an uncontrolled intersection, yield to the vehicle that arrived first."},"46":{"q":"¿Con cuánta anticipación debe señalizar antes de girar o cambiar de carril?","options":["Al menos 25 pies","Al menos 50 pies","Al menos 100 pies","Al menos 200 pies"],"explanation":"In Texas, you must signal at least 100 feet before turning or changing lanes."},"47":{"q":"¿Cuál es el límite de velocidad comúnmente señalizado en una zona escolar?","options":["40 mph","55 mph","70 mph","20 mph"],"explanation":"The reduced school zone speed limit is commonly posted at 20 mph."},"48":{"q":"Después de rebasar, ¿cuándo puede volver con seguridad a su carril?","options":["Cuando pueda ver el vehículo rebasado en su espejo retrovisor","En cuanto termine de rebasar","Cuando el vehículo rebasado toca la bocina","Después de esperar 30 segundos"],"explanation":"You may return to your lane once you can see the passed vehicle in your rearview mirror."},"49":{"q":"En una rotonda, ¿en qué dirección se conduce alrededor del círculo?","options":["En el sentido de las agujas del reloj","En sentido contrario a las agujas del reloj","En cualquier dirección","Recto a través del centro"],"explanation":"In a roundabout, traffic moves around the circle counter-clockwise."},"50":{"q":"¿Qué tan cerca de un hidrante puede estacionarse?","options":["Sin límite","5 pies","15 pies","50 pies"],"explanation":"You may not park within 15 feet of a fire hydrant."},"51":{"q":"La ley de Cambiar de Carril / Reducir Velocidad también protege qué tipo de vehículo con luces intermitentes?","options":["Camionetas de reparto","Autobuses escolares","Autobuses urbanos","Vehículos de servicios públicos"],"explanation":"The Move Over / Slow Down law also covers utility vehicles, along with emergency, tow, and TxDOT vehicles."},"52":{"q":"¿Cuál es el límite de velocidad publicado más alto en Texas?","options":["80 a 85 mph","55 mph","65 mph","70 mph"],"explanation":"Some specific Texas tollways are posted at 80 to 85 mph, the highest posted limits in the state."},"53":{"q":"¿Qué debe hacer antes de girar a la derecha con luz roja?","options":["Acelerar para incorporarse rápido","Detenerse por completo primero","Tocar la bocina para avisar a otros conductores","Apagar los faros"],"explanation":"A right turn on red is allowed only after coming to a full stop, unless a sign prohibits it."},"54":{"q":"¿Qué forma tiene la señal de Zona de No Rebasar?","options":["Redonda","Cuadrada","Banderín (triangular)","Rombo"],"explanation":"A No Passing Zone is marked by a pennant-shaped (triangular) sign."},"55":{"q":"En una intersección en T, ¿quién tiene el derecho de paso?","options":["El tráfico del pie de la T","El vehículo más rápido","El vehículo a la izquierda","El tráfico de la vía principal"],"explanation":"Traffic on the through road (top of the T) has the right of way."},"56":{"q":"Al estacionar cuesta abajo, ¿hacia dónde debe girar las ruedas delanteras?","options":["Hacia el bordillo","Lejos del bordillo","Rectas","No importa"],"explanation":"Turning the wheels toward the curb lets the curb block the vehicle if it rolls."},"57":{"q":"Según la ley básica de velocidad, ¿puede el máximo legal ser menor que el número indicado en la señal?","options":["No, el número de la señal siempre es el máximo legal","Sí, cuando las condiciones hacen que la velocidad indicada sea insegura","No, solo la policía puede reducirlo","Sí, pero solo de noche"],"explanation":"The basic speed law requires a speed safe for conditions, so the legal limit can fall below the posted number when conditions make it unsafe."},"58":{"q":"Al girar a la izquierda, ¿a quién debe ceder el paso?","options":["Solo a los vehículos que vienen de frente","Solo a los peatones","A los vehículos que vienen de frente y a los peatones","A nadie"],"explanation":"A driver turning left must yield to both oncoming vehicles and pedestrians before completing the turn."},"59":{"q":"Según la ley de Cambiar de Carril / Reducir la Velocidad, ¿cuáles son las dos opciones del conductor al pasar junto a un vehículo de emergencia detenido con luces intermitentes?","options":["Detenerse por completo o tocar la bocina dos veces","Encender las luces de emergencia o destellar las luces altas","Acelerar o cambiar de carril","Cambiar un carril o reducir a 20 mph por debajo del límite"],"explanation":"The Move Over / Slow Down law lets you move over one lane away or slow to 20 mph below the speed limit."}},"signals-and-markings":{"0":{"q":"Usted llega a una intersección y el semáforo que tiene enfrente está en verde fijo. Quiere girar a la izquierda cruzando el tránsito que viene de frente, pero varios autos vienen hacia usted a través de la intersección. ¿Qué le permite hacer la ley?","options":["Avanzar derecho o hacer su giro, pero primero ceder el paso a los autos que vienen de frente y a cualquier vehículo que ya esté en la intersección.","Girar a la izquierda de inmediato, porque un verde fijo le da un giro protegido y el tránsito que viene de frente debe detenerse para usted.","Detenerse por completo detrás de la línea y esperar, tratando el verde como un rojo intermitente hasta que pasen los autos que vienen de frente.","Reducir la velocidad y avanzar con precaución sin ceder el paso, ya que un verde fijo funciona igual que un amarillo intermitente."],"explanation":"A steady green means go only when the intersection is clear; you may proceed straight or turn, but you must yield to oncoming traffic and vehicles already in the intersection. Option B is the trap: only a green arrow gives a protected turn where oncoming traffic is stopped, not a steady green light."},"1":{"q":"Conduce hacia una intersección al límite de velocidad cuando la luz verde cambia a amarillo fijo. Todavía está a aproximadamente media cuadra de distancia y la vía detrás de usted está despejada. ¿Qué debe hacer?","options":["Acelerar para cruzar la intersección antes de que la luz se ponga en rojo","Detenerse antes de la intersección si puede hacerlo de forma segura, porque la luz está a punto de ponerse en rojo","Tratarla como un amarillo intermitente y continuar con cuidado sin detenerse","Detenerse por completo y luego avanzar cuando la vía esté despejada, como haría con un rojo intermitente"],"explanation":"A steady yellow light warns that the signal is about to turn red, so you should stop if you can do so safely and never speed up to beat the light. Option C describes a flashing yellow (caution) and Option D describes a flashing red (stop sign), which are different signals."},"2":{"q":"Se aproxima a una intersección y el semáforo que tiene de frente cambia a rojo fijo cuando usted todavía está a poca distancia de la línea de alto marcada. No hay ninguna señal que prohíba girar y usted tiene la intención de seguir de frente. ¿Qué debe hacer?","options":["Reducir la velocidad y cruzar la intersección con cuidado sin detenerse, ya que el semáforo podría cambiar pronto","Detenerse solo si hay tráfico cruzando, y luego continuar de frente pasando el semáforo en rojo","Detenerse por completo detrás de la línea de alto y permanecer detenido hasta que el semáforo cambie a verde","Tratar el semáforo como una señal de alto, detenerse por completo y luego seguir de frente cuando la vía esté despejada"],"explanation":"Un semáforo en rojo fijo exige que se detenga por completo detrás de la línea de alto y permanezca detenido hasta que cambie a verde. La opción D describe un semáforo en rojo intermitente (tratado como señal de alto), no un rojo fijo, por lo que seguir de frente con un rojo fijo es incorrecto."},"3":{"q":"Está en el carril derecho acercándose a una intersección con una luz roja fija. Quiere girar a la derecha. No hay ninguna señal que prohíba el giro y el tráfico transversal tiene un espacio libre. ¿Qué debe hacer?","options":["Reducir la velocidad y girar a la derecha sin detenerse, ya que el tráfico transversal tiene un espacio libre","Tratarla como una señal de alto y luego girar a la derecha solo cuando aparezca una flecha verde","Esperar a que la luz cambie a verde antes de girar a la derecha, porque nunca se puede girar en rojo","Detenerse por completo detrás de la línea y luego girar a la derecha, ya que está despejado y ninguna señal lo prohíbe"],"explanation":"At a steady red light you must stop completely behind the line, and a right turn is permitted only after that full stop when the way is clear and no sign prohibits it. Option A skips the required full stop, and option C wrongly claims right-on-red is never allowed."},"4":{"q":"Se acerca a una intersección de noche y el semáforo elevado está parpadeando en rojo en todas las direcciones. No hay ningún otro vehículo a la vista. ¿Qué debe hacer?","options":["Detenerse por completo y luego cruzar la intersección cuando sea seguro.","Reducir la velocidad, mirar a ambos lados y pasar sin detenerse, ya que la vía está despejada.","Detenerse y permanecer detenido hasta que el rojo intermitente cambie a una luz verde fija.","Tratarlo como una señal de ceda el paso y cruzar solo si se acerca otro vehículo."],"explanation":"A flashing red light means the same thing as a stop sign: you must come to a full stop and then proceed when it is safe. Option B is wrong because a flashing red always requires a complete stop (rolling through is the rule for a flashing yellow), and option C is wrong because a flashing red signal will not turn green."},"5":{"q":"A altas horas de la noche, usted se acerca a una intersección donde el semáforo ya no funciona en su ciclo normal y, en cambio, muestra una luz AMARILLA intermitente constante sobre su carril. ¿Qué debe hacer?","options":["Detenerse por completo detrás de la línea y luego continuar cuando el paso esté despejado, como lo haría en una señal de alto.","Reducir la velocidad y cruzar la intersección con cuidado sin detenerse, atento al tráfico transversal.","Tratar la intersección como un alto en todas las direcciones porque el semáforo no funciona con normalidad.","Detenerse y permanecer detenido hasta que el semáforo vuelva a una luz verde fija."],"explanation":"A flashing YELLOW light means caution, so you slow down and proceed carefully through the intersection without coming to a stop. A flashing RED light is the one that means a full stop like a stop sign, and a completely dark or non-working signal is the one treated as an all-way stop, so those are the wrong responses here."},"6":{"q":"Está detenido en una intersección esperando para girar a la izquierda. Su semáforo había estado en rojo fijo, pero acaba de cambiar a una FLECHA verde de giro a la izquierda que apunta en la dirección a la que desea ir. ¿Qué le indica esto sobre cómo proceder?","options":["Puede girar a la izquierda, pero primero debe ceder el paso al tránsito que viene en sentido contrario y que tiene el derecho de paso","Debe detenerse por completo y esperar, porque una señal de flecha significa que no se permite ningún giro en esa dirección","Puede girar a la izquierda ahora y el tránsito que viene en sentido contrario está detenido, lo que le da un giro protegido","Puede girar a la izquierda solo después de reducir la velocidad para verificar, ya que la flecha funciona como una señal de precaución amarilla intermitente"],"explanation":"A green ARROW means a protected turn in the arrow's direction, so oncoming traffic is being held by a red light and you may turn without yielding. Option A describes a steady green light (a permitted turn requiring you to yield), and option B incorrectly describes a red arrow, so both are wrong."},"7":{"q":"Está en el carril de giro a la izquierda en una intersección concurrida, esperando para girar a la izquierda. El semáforo de su carril muestra una FLECHA roja fija que apunta a la izquierda, mientras que el semáforo redondo normal para el tráfico que va recto está en verde. ¿Qué debe hacer?","options":["Girar a la izquierda con cuidado, ya que la luz verde para los carriles rectos significa que el tráfico que viene en sentido contrario tiene una parada protegida","Tratar la flecha roja como un rojo intermitente y hacer el giro a la izquierda después de detenerse por completo","Hacer el giro a la izquierda después de ceder el paso al tráfico que viene en sentido contrario, ya que los giros a la izquierda siempre están permitidos con una flecha roja cuando está despejado","Permanecer detenido y esperar, porque una flecha roja significa que no se permite girar en esa dirección hasta que cambie"],"explanation":"A red arrow means no turn is allowed in the direction it points, so you must wait until the signal changes, regardless of what the round signal for other lanes shows. A red arrow is not the same as a flashing red, and there is no 'turn after yielding' permitted on a steady red arrow."},"8":{"q":"Se acerca a una concurrida intersección de cuatro vías durante un corte de electricidad. Los semáforos están completamente apagados y no funcionan en absoluto. ¿Qué debe hacer?","options":["Tratar la intersección como un PARE en todas las direcciones, deteniéndose y cediendo el paso por turno antes de avanzar","Reducir la velocidad y avanzar con cuidado por la intersección sin detenerse","Suponer que su dirección tiene el derecho de paso y continuar a velocidad normal","Detenerse solo si ya hay un vehículo en la intersección, de lo contrario seguir avanzando"],"explanation":"A dark or non-working signal must be treated as an all-way STOP, so every driver stops and yields in turn. Slowing without stopping (B) is the rule for a flashing yellow light, not a dead signal, and the other options wrongly assume right of way."},"9":{"q":"Está detenido en un semáforo en verde y quiere girar a la derecha hacia una calle lateral. En la señal peatonal frente al cruce que pretende atravesar, se muestra un símbolo blanco fijo de una persona caminando. ¿Qué le indica este símbolo sobre las personas en la esquina?","options":["Los peatones deben esperar, así que puede girar sin revisar el cruce peatonal","Los peatones pueden comenzar a cruzar legalmente, así que debe cederles el paso antes de girar","Los peatones solo pueden terminar de cruzar pero no comenzar, así que habrá pocos en el cruce","El cruce peatonal está cerrado a los peatones y reservado para los vehículos que giran"],"explanation":"A WALK signal or walking-person symbol means pedestrians may cross, so they have the right of way and you must yield before turning. Option C describes a flashing DON'T WALK/raised hand (finish but don't start), not the steady walking-person symbol."},"10":{"q":"Se acerca a una intersección en el centro y se detiene ante un semáforo en rojo. Mientras espera, observa que la señal peatonal al otro lado cambia de un símbolo de mano levantada parpadeante a un símbolo de mano levantada fija mientras una persona sigue parada en su esquina. ¿Qué le indica hacer esa mano levantada fija a ese peatón?","options":["Significa que debe apresurarse para terminar de cruzar antes de que cambie el semáforo","Significa que el cruce peatonal está cerrado y debe usar otra intersección","Significa que no debe comenzar a cruzar la calle","Significa que puede comenzar a cruzar porque empieza la fase de CAMINAR"],"explanation":"A steady DON'T WALK signal or steady raised-hand symbol means do not start to cross. The flashing raised hand (option A) is what tells someone already in the crosswalk to finish crossing, but a steady hand means do not begin."},"11":{"q":"Está detenido en un semáforo en verde esperando para girar a la derecha en una calle de la ciudad. Un peatón baja de la acera al cruce peatonal que usted debe atravesar justo cuando la señal peatonal que mira hacia él comienza a mostrar el símbolo de la mano alzada intermitente (NO CRUCE). ¿Qué le indica esa señal intermitente sobre el derecho legal del peatón a estar en el cruce?","options":["El peatón debe detenerse de inmediato y regresar a la acera, por lo que usted puede girar en cuanto él retroceda","La mano intermitente significa lo mismo que la mano fija, por lo que el peatón no tenía derecho a entrar y usted puede continuar","La mano intermitente es solo una precaución como una luz amarilla intermitente, por lo que tanto el peatón como usted pueden avanzar juntos","Un peatón que ya está en el cruce puede terminar de cruzar; la mano intermitente solo significa que nadie nuevo debe empezar a cruzar"],"explanation":"A flashing DON'T WALK or flashing raised-hand symbol means anyone already in the crosswalk should finish crossing, while no new pedestrian should start; you must yield until they finish. The steady-hand meaning (B) and the flashing-yellow caution rule (C) are real facts placed in the wrong context."},"12":{"q":"Está conduciendo en una autopista de varios carriles donde hay señales de uso de carril colgadas sobre cada carril. Sobre el carril al que quiere entrar, ve una flecha verde hacia abajo fija. ¿Qué le indica esto sobre ese carril?","options":["El carril está abierto y puede conducir en él","El carril está cerrado y debe salir de él","El carril está cambiando de uso, así que salga de él antes de que se cierre","El carril está reservado solo para vehículos HOV o de uso compartido"],"explanation":"A lane-use green down-arrow means the lane is open for travel, so you may drive in it. A red X means the lane is closed and a yellow X means the lane is changing use and you should move out of it, but neither of those signals is shown here."},"13":{"q":"Está conduciendo por una autopista de varios carriles y mira hacia arriba a las señales de control de carril suspendidas. Sobre su carril hay una X roja fija encendida, mientras que el carril a su derecha muestra una flecha verde fija apuntando hacia abajo. ¿Qué debe hacer?","options":["Permanecer en su carril y proceder con precaución, ya que la X roja simplemente advierte de un peligro próximo","Cambiarse al carril de su derecha, porque la X roja significa que su carril está cerrado y la flecha verde hacia abajo significa que ese carril está abierto","Detenerse por completo en su carril y esperar, tratando la X roja como una señal roja intermitente","Permanecer en su carril pero salir de él de inmediato, porque la X roja significa que el carril está cambiando de uso"],"explanation":"A lane-use red X means the lane is closed, so you must leave it, and a green down-arrow means the lane beneath it is open for travel. The trap options confuse the red X with a flashing red (stop) signal or with a yellow X, which is the signal that means the lane is changing use and you should move out of it."},"14":{"q":"Conduce por un carril central en una carretera de varios carriles cuando la señal de uso de carril sobre su carril cambia a una X amarilla fija. ¿Qué significa esta señal que debe hacer?","options":["Detenerse de inmediato dentro del carril, porque una X amarilla funciona como una luz roja fija en lo alto","Permanecer en el carril pero reducir casi hasta detenerse, ya que una X amarilla solo advierte que el carril está congestionado más adelante","Prepararse para salir del carril con seguridad, porque el carril está cambiando de uso y está a punto de cerrarse en su sentido","Continuar normalmente, porque una X amarilla simplemente confirma que el carril está abierto para el tráfico de paso"],"explanation":"An overhead lane-use yellow X means the lane is changing use, so you should prepare to safely move out of it before it closes. Stopping in the lane (A) is wrong because a yellow X is not a red light, and continuing as if the lane is open (D) confuses it with a green down-arrow, which is the signal for an open lane."},"15":{"q":"Conduce por una carretera rural de dos carriles detrás de un tractor lento. Quiere adelantarlo, pero nota una línea amarilla continua pintada en el centro, en su lado de la carretera. ¿Qué le indica esta marca sobre adelantar aquí?","options":["Puede adelantar porque las líneas amarillas siempre permiten adelantar cuando la vía está despejada","Puede adelantar solo si también hay una línea blanca discontinua junto a ella","Se permite adelantar en ambos sentidos porque la línea es amarilla","No debe adelantar; la línea amarilla continua en su lado significa que adelantar está prohibido"],"explanation":"A solid yellow line on your side of the centerline means no passing, so you must stay behind the tractor until the marking changes. Option A confuses this with a broken yellow line (passing allowed when safe), and the white-line and both-directions ideas do not apply to a solid yellow line on your side."},"16":{"q":"Conduce por una carretera rural de dos carriles detrás de un tractor lento. El centro de la vía tiene una línea amarilla discontinua (entrecortada) de su lado, el camino adelante es recto con buena visibilidad y no hay tráfico en sentido contrario a la vista. ¿Qué le indica esta marca del pavimento sobre rebasar al tractor?","options":["Rebasar está permitido cuando es seguro, así que puede cruzar la línea para adelantar al tractor","Rebasar está prohibido de su lado porque cualquier línea amarilla significa prohibido rebasar","Solo puede cruzar la línea para girar a la izquierda, no para rebasar","Rebasar solo se permite por el acotamiento derecho, nunca cruzando la línea central"],"explanation":"A broken (dashed) yellow line on your side of the center means passing is permitted when it is safe to do so, which it is here with clear visibility and no oncoming traffic. The trap in B confuses this with a solid yellow line (no passing), and the turn-only restriction in C applies to a double solid yellow line."},"17":{"q":"Conduce por una carretera de dos carriles y llega a un tramo marcado en el centro con dos líneas amarillas continuas una al lado de la otra. Delante de usted hay un tractor lento y la vía está despejada en ambos sentidos. A su izquierda hay una entrada a la que podría girar. ¿Qué le permite hacer esta marca?","options":["Adelantar al tractor, porque la vía está despejada en ambos sentidos y puede ver lejos hacia adelante","Permanecer en su carril y no adelantar, aunque puede cruzar las líneas para girar a la izquierda hacia la entrada","Adelantar al tractor, ya que una doble línea amarilla continua restringe el adelantamiento solo para el sentido contrario","Cruzar libremente las líneas para adelantar, porque la amarilla continua solo desaconseja cruzar pero no lo prohíbe"],"explanation":"A double solid yellow line means no passing in either direction, so you must stay in your lane, but you may still cross it to turn (such as into a driveway). Passing is never allowed here regardless of visibility, and the rule applies to both directions, not just oncoming traffic."},"18":{"q":"Está conduciendo por una autopista de varios carriles donde todo el tráfico se mueve en la misma dirección. Nota una línea pintada entre su carril y el carril inmediatamente a su derecha. ¿De qué color es probable que sea esa línea?","options":["Amarilla, porque las líneas amarillas siempre marcan los bordes de cada carril","Amarilla, porque la línea advierte que no se permite rebasar allí","Blanca, porque las líneas blancas separan carriles de tráfico que circula en la misma dirección","Doble amarilla continua, porque impide cruzar al carril contiguo"],"explanation":"White lines separate lanes of traffic that travel in the same direction, so the line between two same-direction lanes is white. Yellow lines are used to separate traffic moving in opposite directions or to mark no-passing zones, which does not apply here."},"19":{"q":"Conduce por una carretera de varios carriles donde todo el tránsito se mueve en la misma dirección. El carril a su izquierda está separado del suyo por una línea blanca discontinua (de trazos). El tránsito por delante en su carril se está frenando y el carril izquierdo está despejado. ¿Qué le indica esa marca sobre cambiarse al carril izquierdo?","options":["No puede cruzarla; una línea blanca siempre significa que debe permanecer en su carril","Cruzar solo se permite para hacer un giro, igual que trataría una doble línea amarilla continua","Aquí se permite rebasar solo porque la línea separa el tránsito en sentido contrario","Puede cambiar de carril cruzándola cuando la vía esté despejada y sea seguro hacerlo"],"explanation":"A broken white line separates lanes going the same direction and permits a lane change when it is safe, so moving into the clear left lane is allowed. Option A describes a solid white line, and option B describes a double solid yellow line, so both apply the wrong marking's rule here."},"20":{"q":"Conduce por una autopista de cuatro carriles donde todos los carriles avanzan en la misma dirección. Al acercarse a una rampa de entrada a la autopista, una sola línea blanca continua separa su carril del carril a su derecha. Le gustaría pasarse a ese carril para tomar una mejor posición. ¿Qué le indica esta marca?","options":["Permanezca en su carril; cruzar la línea blanca continua no se recomienda","Puede cambiarse libremente al carril derecho cuando esté despejado","Está prohibido rebasar en ambas direcciones, como con una línea doble continua","Esto marca el borde derecho de la calzada, así que no conduzca más allá"],"explanation":"A solid white line separates lanes going the same direction and means stay in your lane, as crossing it is discouraged. A broken white line is what allows a free lane change (option B), and a solid white edge line marks the road's right edge (option D), so those facts are placed here in the wrong context."},"21":{"q":"Conduce de noche por una carretera rural desconocida con poca visibilidad. A su derecha nota una línea blanca continua que corre a lo largo del pavimento, paralela a su dirección de marcha. ¿Qué le indica esta línea?","options":["Marca el centro de la vía y no debe cruzarla para adelantar","Marca el borde derecho de la vía, ayudándole a mantenerse en el pavimento","Marca el borde izquierdo de la vía en una calle de un solo sentido","Indica un carril para bicicletas por el que no debe circular"],"explanation":"A solid white edge line marks the right edge of the road, which is especially useful for staying on the pavement at night or in poor visibility. The trap in C confuses edge colors: a yellow line marks the left edge, while white marks the right edge."},"22":{"q":"Conduce de noche por una carretera de doble sentido que no conoce. Sus faros iluminan una línea amarilla continua a lo largo del lado más a la izquierda de su carril, justo en el borde del pavimento. ¿Qué le indica esta línea?","options":["Marca el borde derecho de la carretera, por lo que el pavimento termina justo a su izquierda","Es una línea de prohibido adelantar, por lo que no debe cruzar el centro de la carretera para adelantar","Marca el borde izquierdo de la carretera, por lo que indica dónde termina el pavimento a su izquierda","Separa carriles de tráfico que circulan en la misma dirección que usted"],"explanation":"A yellow edge line marks the left edge of the roadway, showing the driver where the pavement ends on the left side. The line being yellow does not make it a center no-passing line, and the right edge of the road is marked with a solid white line, not yellow."},"23":{"q":"Usted se acerca a una intersección con un semáforo en rojo. Antes del cruce peatonal, nota una línea blanca ancha pintada a lo ancho de su carril. ¿Dónde debe detener completamente su vehículo?","options":["Sobre la línea blanca ancha, de modo que su parachoques quede alineado con ella","Justo después de la línea blanca ancha pero antes de entrar al cruce peatonal","En cualquier parte de la intersección, mientras esté totalmente detenido antes del verde","Detrás de la línea blanca ancha, que es la línea de parada que indica dónde detenerse"],"explanation":"The wide white line is a stop line, and you must stop behind it, not on or beyond it. Stopping on the line or past it into the crosswalk blocks pedestrians and is incorrect even though you are technically stopped."},"24":{"q":"Al acercarse a un semáforo en verde en una intersección, ve unas marcas blancas pintadas cruzando la calzada y un peatón que entra en ellas. ¿Dónde debe detenerse?","options":["Antes de las marcas blancas del paso de peatones, para dejar cruzar al peatón","Sobre las marcas del paso de peatones, mientras deje espacio para el peatón","Donde quiera, ya que la luz verde significa que siempre tiene preferencia de paso","Detrás del símbolo de rombo pintado en el carril"],"explanation":"A crosswalk is marked by white lines for pedestrians, and you must stop before it to let them cross safely. Stopping on top of it blocks the pedestrian, and a green light still requires yielding to people already in the crosswalk; the diamond symbol marks an HOV/carpool lane, not a stopping point."},"25":{"q":"Conduce solo por una autopista de Texas en hora pico. El carril más a la izquierda tiene grandes símbolos de diamante pintados en el pavimento a intervalos regulares. ¿Qué le indica esta marca sobre ese carril?","options":["Es un carril para bicicletas, así que no debe conducir ni estacionar en él","Es un carril reservado HOV/para vehículos compartidos o de uso especial que quizás no pueda usar yendo solo","Está cerrado a todo el tráfico, igual que una señal de X roja sobre el carril","Es un carril de borde y los diamantes marcan dónde termina la superficie de la carretera"],"explanation":"A diamond symbol painted in a lane marks a reserved HOV/carpool or special-use lane, which often requires a minimum number of occupants, so driving alone may not be permitted. A bike lane is marked differently, and a closed lane is shown by an overhead red X, not pavement diamonds."},"26":{"q":"Va con retraso y ve un tramo de pavimento despejado a la derecha del carril de circulación normal. Está delimitado con una línea blanca continua y tiene un símbolo de bicicleta pintado, pero en este momento no hay ciclistas en él. ¿Qué debe hacer?","options":["Circular por él para adelantar al tráfico lento, ya que ahora está vacío","Meterse en él y estacionar mientras espera a que se despeje el tráfico","Mantenerse completamente fuera de él; es un carril para bicicletas reservado a las bicicletas, no para conducir ni estacionar","Usarlo como carril para vehículos compartidos, ya que lleva pasajeros en el vehículo"],"explanation":"A lane marked with a bicycle symbol is a bike lane reserved for bicycles, and you must not drive or park in it even when no cyclists are present. Options A and B are the trap (driving and parking are both prohibited), and D confuses the bike lane with an HOV/carpool lane, which is marked with a diamond symbol instead."},"27":{"q":"Vas con retraso y necesitas dejar tu auto unos minutos. El único espacio libre está junto a un bordillo pintado de amarillo sólido, sin ningún letrero cerca. ¿Qué te indica ese bordillo amarillo sobre estacionar ahí?","options":["Está bien estacionar porque no hay ningún letrero que lo restrinja","Marca el borde izquierdo de la calzada, por lo que se permite estacionar a su derecha","Está reservado solo para vehículos HOV o de uso compartido (carpool)","Indica una restricción de no estacionar o de carga, por lo que no debes estacionar ahí"],"explanation":"A yellow curb signals a no-parking or loading restriction even when no sign is present, though exact meanings can vary by city, so you should not leave your car there. The left-edge yellow line refers to roadway center markings, not curbs, and HOV reservations are shown by a diamond symbol in a lane, not by a painted curb."},"28":{"q":"Conduce por una carretera desconocida y el pavimento más adelante muestra un gran símbolo pintado \"RXR\" seguido de una línea blanca ancha que cruza su carril. Las barreras todavía están levantadas, pero escucha la bocina de un tren y ve uno acercándose. ¿Qué debe hacer?","options":["Detenerse detrás de la línea blanca y esperar, porque el RXR marca un cruce de ferrocarril y debe detenerse cuando un tren se aproxima","Considerar la línea blanca como opcional y cruzar despacio, ya que las barreras siguen levantadas y se le puede ganar al tren","Detenerse solo si la línea fuera amarilla, ya que una línea amarilla de su lado significa prohibido adelantar","Continuar sin detenerse porque el símbolo de diamante indica un carril de uso especial para el tráfico que cruza"],"explanation":"The large RXR painted on the pavement marks a railroad crossing, and the wide white line is a stop line; you must stop behind it when a train is approaching. The traps misuse other real facts: a solid yellow line means no passing, and a diamond marks an HOV/special-use lane, neither of which applies at a railroad crossing."},"29":{"q":"Está detenido en una intersección esperando para girar a la izquierda cuando su semáforo se pone en verde fijo. Un vehículo se aproxima desde el sentido contrario y está cerca de la intersección. ¿Qué debe hacer?","options":["Girar a la izquierda de inmediato, ya que un semáforo en verde fijo le da derecho a avanzar antes que el tráfico que viene de frente.","Ceder el paso al vehículo que viene de frente y luego completar el giro a la izquierda cuando sea seguro hacerlo.","Esperar una flecha verde, porque un semáforo en verde fijo no permite girar a la izquierda.","Detenerse por completo detrás de la línea y avanzar solo después de que haya pasado el vehículo que viene de frente, ya que el verde fijo exige detenerse primero."],"explanation":"At a steady green light you may proceed or turn, but you must first yield to oncoming traffic and pedestrians rather than turn without regard to other vehicles. A green arrow gives a protected turn and a stop is required only at red or yellow, so options C and D misapply other signal rules."},"30":{"q":"Usted se acerca a una intersección al límite de velocidad establecido cuando la luz cambia de verde a amarillo fijo. Hay suficiente distancia por delante para detenerse de forma segura antes de la línea. ¿Qué debe hacer?","options":["Acelerar para cruzar la intersección antes de que la luz se ponga en rojo","Detenerse solo si un letrero se lo indica, de lo contrario mantener la velocidad pasando el amarillo","Reducir la velocidad y detenerse de forma segura detrás de la línea, porque el amarillo advierte que viene el rojo","Tratar el amarillo como un amarillo intermitente y pasar con precaución sin detenerse"],"explanation":"A steady yellow means the light is about to turn red, so you should stop if you can do so safely rather than speed up to beat the light. Accelerating through (A) is the exact mistake the yellow warns against, and a flashing yellow (D) is a different signal that means caution and does not require stopping."},"31":{"q":"Se acerca a una intersección tarde en la noche cuando el semáforo cambia a una luz amarilla intermitente en su dirección. No hay tráfico cruzado visible. ¿Qué debe hacer?","options":["Detenerse por completo detrás de la línea de alto y luego continuar cuando la intersección esté despejada","Detenerse por completo, tratarlo como un alto de cuatro vías y ceder el paso a cualquier vehículo a su derecha","Acelerar para cruzar la intersección antes de que la luz cambie a rojo","Reducir la velocidad y cruzar la intersección con cuidado sin detenerse"],"explanation":"A flashing yellow light means caution: you slow down and proceed carefully without needing to stop. A full stop is required at a flashing red (which is treated like a stop sign), so options requiring a complete stop confuse the flashing red rule with the flashing yellow."},"32":{"q":"Conduce por una carretera de dos carriles desconocida al atardecer. La línea en el centro de la carretera, que separa su carril del carril contiguo, es amarilla. ¿Qué le indica este color sobre el tránsito en el carril al otro lado de esa línea?","options":["Circula en sentido contrario, hacia usted","Circula en el mismo sentido que usted","Es un carril reservado para uso de HOV o vehículos compartidos (carpool)","Es el borde derecho de la calzada"],"explanation":"Yellow center lines separate traffic moving in opposite directions, so the lane across a yellow line carries oncoming traffic. White lines, not yellow, separate traffic moving in the same direction, which makes B the trap."},"33":{"q":"Llega a pie a un cruce peatonal y quiere cruzar la calle. Al llegar a la acera, la señal peatonal cambia a un DON'T WALK / mano levantada intermitente. ¿Qué significa esto para usted?","options":["No empiece a cruzar ahora, pero si ya está en el cruce debe regresar a la acera de la que salió","No empiece a cruzar ahora; solo quienes ya están en el cruce deben continuar y terminar de cruzar","Puede empezar a cruzar porque intermitente significa precaución, similar a una señal amarilla intermitente","Puede empezar a cruzar con cuidado, pero solo después de detenerse primero en el borde del cruce"],"explanation":"A flashing DON'T WALK warns pedestrians not to begin crossing; those already in the crosswalk should finish crossing. Option C wrongly borrows the flashing-yellow 'caution, proceed' meaning, and A invents a rule about turning back that the handbook does not state."},"34":{"q":"Está detenido en un semáforo en rojo con la intención de girar a la derecha. Ve un letrero en la intersección que dice 'PROHIBIDO GIRAR EN ROJO' (NO TURN ON RED). Después de detenerse por completo y comprobar que el tráfico transversal está despejado, ¿qué debe hacer?","options":["Girar a la derecha, porque una parada total cumple el requisito legal para girar a la derecha en rojo","Girar a la derecha lentamente, ya que el carril está despejado y cedió el paso correctamente","Permanecer detenido y esperar la luz verde antes de girar a la derecha","Tratar la luz roja como un rojo intermitente y avanzar cuando el tráfico esté despejado"],"explanation":"When a posted sign prohibits turning right on red, you may not turn regardless of stopping or a clear path, so you must wait for the green light. Stopping fully only permits a right on red when no sign forbids it, and a steady red is never treated like a flashing red."},"35":{"q":"Está estudiando para el examen de conocimientos de la licencia de conducir de Texas y quiere asegurarse de que una regla específica sobre marcas del pavimento que leyó en línea sea realmente correcta y se aplique actualmente en Texas. Para confirmar cuáles son las reglas oficiales en realidad, ¿en qué fuente debe basarse?","options":["En lo que coincide la mayoría de los sitios web de exámenes de manejo en línea, ya que resumen las reglas de muchos estados","Solo en el MUTCD federal, porque las normas nacionales reemplazan por completo cualquier guía específica de Texas","En el manual del conductor de un estado vecino, ya que las marcas del pavimento son idénticas en todos los estados de EE. UU.","En el Manual del Conductor de Texas (DPS, DL-7) junto con las normas nacionales del MUTCD que se aplican en Texas"],"explanation":"The authoritative source of truth is the Texas Driver Handbook (DPS, DL-7) combined with the MUTCD national standards that apply in Texas. The MUTCD alone is not enough because it works together with the state handbook, and quiz sites or another state's handbook are not official Texas sources."},"36":{"q":"Está conduciendo por una carretera de dos carriles y hay una doble línea amarilla continua en el centro. Delante de usted hay un tractor lento, y justo después de él ve la entrada donde necesita girar a la izquierda hacia un estacionamiento. ¿Qué le permite legalmente hacer esa doble línea amarilla continua?","options":["Cruzarla para girar a la izquierda hacia el estacionamiento, pero no para adelantar al tractor","Cruzarla para adelantar al tractor, ya que el carril de adelante está despejado","Cruzarla libremente porque las dobles líneas amarillas solo aplican al tránsito que viene en sentido contrario","Tratarla como una línea amarilla discontinua y adelantar cuando sea seguro hacerlo"],"explanation":"A double solid yellow line means no passing in either direction; you may cross it only to make a turn, such as turning left into a driveway or parking lot. Passing the tractor (B and D) is prohibited, and the line applies to drivers on both sides, not just oncoming traffic (C)."},"37":{"q":"Conduce hacia un cruce de ferrocarril marcado con un gran símbolo RXR y una ancha línea blanca de detención pintada en el pavimento. No hay luces intermitentes ni barreras, no se ve ningún tren, y puede ver y oír claramente que ninguno se aproxima. ¿Qué debe hacer?","options":["Detenerse por completo en la línea de detención y esperar, ya que todo cruce de ferrocarril exige una parada total","Cruzar las vías sin detenerse, pero estar listo para parar en la línea de detención marcada si se aproxima un tren","Reducir la velocidad y tratar el cruce como un alto de todas las direcciones, cediendo primero el paso al tráfico de su derecha","Detenerse momentáneamente sobre las vías para mirar en ambas direcciones antes de continuar"],"explanation":"At this type of railroad crossing you stop only if a train is approaching, and the stop must be made at the marked stop line; with no train coming you may proceed across without stopping. Option A is wrong because a stop is not required at every crossing when no train is near, and stopping on the tracks (D) is always dangerous."},"38":{"q":"Conduce por una autopista de varios carriles cuando nota que la señal aérea justo encima de su carril cambia de una flecha verde hacia abajo a una X amarilla fija. ¿Qué significa esto y qué debe hacer?","options":["Su carril ahora está cerrado solo para el tráfico detenido; deténgase por completo dentro del carril y espere.","Es una señal de precaución como una luz amarilla intermitente; reduzca la velocidad pero permanezca en su carril actual.","El uso de su carril está cambiando; salga con seguridad de este carril hacia un carril abierto marcado con una flecha verde hacia abajo.","Hay peatones cruzando más adelante; permanezca en su carril y ceda el paso hasta que la señal cambie."],"explanation":"A yellow X overhead lane-control signal means the lane is changing use and you should move out of it safely, while a green down-arrow marks a lane that is open. The caution answer confuses this with a flashing yellow traffic light, which applies to intersections, not overhead lane control."},"39":{"q":"Está esperando en una intersección en el carril de giro a la izquierda. La señal frente a usted muestra una flecha verde fija hacia la IZQUIERDA junto con una luz roja fija para los carriles de paso. ¿Por qué puede iniciar su giro a la izquierda sin ceder el paso al tránsito que viene de frente?","options":["Porque una flecha verde significa que primero debe detenerse por completo y luego girar solo si el paso está despejado","Porque la flecha verde solo da precaución, así que debe reducir la velocidad y ceder el paso a los autos que vienen de frente antes de girar","Porque el tránsito que viene de frente tiene una luz amarilla intermitente que le indica avanzar con cuidado por la intersección","Porque la flecha verde otorga un giro protegido: el tránsito que viene de frente enfrenta una luz roja y está detenido mientras dura la flecha"],"explanation":"A green arrow grants a protected turn in the arrow's direction because oncoming traffic faces a red signal and is stopped, so you may turn without yielding. A green arrow is not a stop-and-go or caution signal, and oncoming drivers are stopped by red, not waved through by a flashing yellow."}},"learn-signals-and-markings":{"0":{"q":"¿Qué significa una luz verde fija del semáforo?","options":["Avance si la intersección está despejada","Deténgase por completo detrás de la línea","Reduzca la velocidad y deténgase si es seguro","Trátela como una señal de alto"],"explanation":"A steady green light means you may go if the intersection is clear, proceeding straight or turning after yielding."},"1":{"q":"¿Qué debe hacer antes de girar con una luz verde fija?","options":["Acelerar para completar el giro","Ceder el paso a otros vehículos y peatones","Siempre detenerse por completo primero","Esperar a que aparezca una flecha verde"],"explanation":"At a steady green light you may turn only after yielding to other traffic and pedestrians."},"2":{"q":"¿Qué significa una luz amarilla fija del semáforo?","options":["Acelerar para cruzar la intersección","La luz acaba de ponerse verde","La luz está a punto de ponerse roja","Usted tiene el derecho de paso"],"explanation":"A steady yellow light warns that the signal is about to turn red, so stop if you can do so safely."},"3":{"q":"¿Qué debe hacer ante una luz amarilla fija?","options":["Acelerar para pasar antes del rojo","Detenerse por completo siempre","Ignorarla y seguir conduciendo","Detenerse si puede hacerlo con seguridad"],"explanation":"A steady yellow light means the light is about to turn red, so stop if you can do so safely and do not speed up."},"4":{"q":"¿Qué significa una luz roja fija?","options":["Detenerse por completo hasta que cambie a verde","Reducir la velocidad y avanzar con precaución","Acelerar para despejar la intersección","Avanzar si la intersección está despejada"],"explanation":"A steady red light means stop completely behind the line and stay stopped until the light turns green."},"5":{"q":"En un semáforo en rojo donde se permite girar a la derecha, ¿qué debe hacer primero?","options":["Acelerar y girar a la derecha","Detenerse por completo, luego girar si está despejado","Girar sin detenerse","Esperar una flecha verde"],"explanation":"At a red light where right turns are permitted, you must stop completely, then turn right if it is clear and not prohibited by a sign."},"6":{"q":"¿Qué debe hacer ante una luz roja intermitente?","options":["Acelerar para pasar","Reducir la velocidad pero seguir","Detenerse por completo y avanzar cuando sea seguro","Ignorarla si no hay autos cerca"],"explanation":"A flashing red light means the same as a stop sign: stop fully, then go when it is safe."},"7":{"q":"¿Qué significa una luz amarilla intermitente del semáforo?","options":["Detenerse por completo y luego avanzar","La luz está por cambiar a rojo","El carril está cerrado más adelante","Precaución: reduzca la velocidad y avance con cuidado"],"explanation":"A flashing yellow light means caution, so slow down and proceed carefully without stopping."},"8":{"q":"¿Qué significa una señal de flecha verde?","options":["Un giro protegido en la dirección de la flecha","Detenerse y esperar la siguiente luz","Reducir la velocidad y ceder el paso al tráfico que viene","No se permite girar en esa dirección"],"explanation":"A green arrow means a protected turn in the arrow's direction, and oncoming traffic is stopped."},"9":{"q":"¿Qué significa una flecha roja?","options":["Gire ahora si el camino está libre","No hay giro en esa dirección; espere","Acelere para girar rápido","Gire solo para camiones"],"explanation":"A red arrow means no turn is allowed in that direction, so you must wait."},"10":{"q":"¿Cómo debe tratar un semáforo apagado o que no funciona?","options":["Pasar a toda velocidad","Tratarlo como luz verde","Tratarlo como un alto de todas las direcciones","Ignorar la intersección"],"explanation":"A dark or non-working signal should be treated as an all-way stop."},"11":{"q":"¿Qué significa la señal WALK (Camine)?","options":["Los autos deben acelerar","Las bicicletas deben detenerse","Los conductores pueden girar a la izquierda","Los peatones pueden cruzar"],"explanation":"A WALK signal or walking-person symbol means pedestrians may cross."},"12":{"q":"¿Qué significa una señal fija de DON'T WALK (No cruce) o un símbolo fijo de mano levantada?","options":["No comience a cruzar","Comience a cruzar ahora","Cruce solo corriendo","Detenga su automóvil"],"explanation":"A steady DON'T WALK signal or steady raised-hand symbol means pedestrians should not start to cross."},"13":{"q":"¿Qué significa la señal intermitente de NO CRUCE o mano levantada?","options":["Empiece a cruzar la calle de inmediato","Termine de cruzar si ya empezó, pero no comience","Cruce la calle corriendo rápido","Cruce solo si un auto le hace señas"],"explanation":"A flashing DON'T WALK means finish crossing if you have already started, but do not begin to cross."},"14":{"q":"En una señal de uso de carril, ¿qué significa una flecha verde hacia abajo?","options":["El carril está cerrado","Salga del carril","El carril está abierto","Reduzca la velocidad y deténgase"],"explanation":"A green down-arrow on a lane-use signal means the lane is open."},"15":{"q":"En una señal de uso de carril, ¿qué significa una X roja?","options":["El carril está abierto","Reduzca la velocidad en el carril","Salga pronto del carril","El carril está cerrado"],"explanation":"A red X on a lane-use signal means the lane is closed."},"16":{"q":"En una señal de uso de carril, ¿qué significa una X amarilla sobre su carril?","options":["El carril cambia de uso, salga de él","El carril está abierto, puede usarlo","El carril está cerrado, nunca lo use","Deténgase y espere en el carril"],"explanation":"A yellow X means the lane is changing use, so you should move out of it."},"17":{"q":"¿Qué significa una línea amarilla continua en su lado de la carretera?","options":["Se permite rebasar","No rebasar","El carril está cerrado","Alto adelante"],"explanation":"A solid yellow line on your side of the road means you may not pass."},"18":{"q":"¿Qué significa una línea amarilla discontinua (entrecortada)?","options":["No se permite rebasar","Deténgase y espere","Se permite rebasar cuando es seguro","El carril está cerrado"],"explanation":"A broken (dashed) yellow line means passing is allowed when it is safe to do so."},"19":{"q":"¿Qué significa una doble línea amarilla continua?","options":["Se permite rebasar en ambos sentidos","Los carriles van en la misma dirección","Puede rebasar cuando esté libre","No se permite rebasar en ningún sentido"],"explanation":"A double solid yellow line means no passing in either direction; do not cross it except to turn."},"20":{"q":"¿Qué separan las líneas blancas en la carretera?","options":["Carriles en la misma dirección","Carriles en direcciones opuestas","Espacios de estacionamiento","Solo carriles para bicicletas"],"explanation":"White lines separate lanes of traffic traveling in the same direction."},"21":{"q":"¿Qué significa una línea blanca discontinua?","options":["No se permite rebasar","Se permiten cambios de carril","Borde de la carretera adelante","Deténgase y espere aquí"],"explanation":"A broken white line means you may change lanes when it is safe."},"22":{"q":"¿Qué significa una línea blanca continua?","options":["Puede rebasar a otros autos","Se permiten cambios de carril","Permanezca en su carril","El tránsito va en sentido contrario"],"explanation":"A solid white line means stay in your lane; crossing it is discouraged."},"23":{"q":"¿Qué separan las líneas amarillas en la carretera?","options":["El tráfico que va en la misma dirección","Los carriles para bicicletas de los de autos","Los espacios de estacionamiento","El tráfico que va en direcciones opuestas"],"explanation":"Yellow lines separate traffic moving in opposite directions, while white lines separate traffic moving in the same direction."},"24":{"q":"¿Qué marca una línea de borde blanca continua?","options":["El borde derecho de la carretera","El borde izquierdo de la carretera","El centro de la carretera","Una zona de adelantamiento"],"explanation":"A solid white edge line marks the right edge of the road."},"25":{"q":"Que marca una linea amarilla de borde en una carretera?","options":["El borde derecho de la carretera","El borde izquierdo de la carretera","El centro de un carril para bicicletas","Un cruce peatonal"],"explanation":"A yellow edge line marks the left edge of the road."},"26":{"q":"¿Qué es una línea de alto?","options":["Una línea para que crucen los peatones","Una línea que marca un carril para bicicletas","Una línea blanca ancha que indica dónde detenerse","Una línea que separa el tráfico de doble sentido"],"explanation":"A stop line is a wide white line that shows where to stop, and you must stop behind it."},"27":{"q":"¿Qué significa un cruce peatonal marcado con líneas blancas?","options":["Marca el borde de la carretera","Es un carril compartido","Está cerrado al tráfico","Es para peatones; deténgase antes de él"],"explanation":"A crosswalk has white markings for pedestrians, and you must stop before it."},"28":{"q":"¿Qué significa un símbolo de diamante pintado en un carril?","options":["Carril reservado para HOV o vehículos compartidos","Carril solo para camiones","Carril para bicicletas adelante","El carril está cerrado"],"explanation":"A diamond symbol marks a reserved HOV, carpool, or special-use lane."},"29":{"q":"¿Para qué está marcado un carril para bicicletas?","options":["Para estacionar autos","Para bicicletas","Para girar a la izquierda","Para vehículos de emergencia"],"explanation":"A bike lane is marked for bicycles, and you should not drive or park in it."},"30":{"q":"¿Qué suele indicar un bordillo amarillo?","options":["Estacionamiento gratis a cualquier hora","Estacionamiento reservado para discapacitados","Restricción de no estacionar o de carga","Solo parada de autobús"],"explanation":"A yellow curb indicates a no-parking or loading restriction, though curb colors vary by city."},"31":{"q":"¿Qué marca en el pavimento advierte de un cruce de ferrocarril?","options":["Un símbolo de diamante","Una doble línea amarilla","Un cruce peatonal blanco","Una gran RXR"],"explanation":"A railroad crossing is marked on the pavement with a large RXR and a stop line."},"32":{"q":"¿Qué debe hacer ante un semáforo en amarillo fijo?","options":["Detenerse si puede hacerlo con seguridad","Acelerar para pasar antes del rojo","Detenerse por completo siempre","Hacer una parada total y luego avanzar"],"explanation":"A steady yellow light means the light is about to turn red, so stop if you can do so safely and do not speed up."},"33":{"q":"En una luz roja fija, ¿dónde debe detenerse?","options":["Sobre la línea","Detrás de la línea","Pasada la línea","En el cruce peatonal"],"explanation":"At a steady red light you must stop behind the line, not on or beyond it."},"34":{"q":"¿Qué significa una señal de flecha verde?","options":["Reduzca la velocidad y ceda el paso a todo el tráfico","Deténgase y espere antes de girar","Giro protegido en la dirección de la flecha","No se permite girar"],"explanation":"A green arrow means a protected turn in the arrow's direction because oncoming traffic is stopped."},"35":{"q":"¿Qué debe hacer ante una luz roja intermitente?","options":["Acelerar para pasar","Reducir la velocidad y avanzar con precaución","Ignorarla y seguir","Detenerse por completo, como en una señal de alto"],"explanation":"A flashing red light means make a full stop and go when safe, just like a stop sign."},"36":{"q":"En un semáforo en rojo, ¿cuándo se permite el giro a la derecha permitido?","options":["Cuando el camino está despejado y ninguna señal lo prohíbe","En cualquier momento sin detenerse","Solo cuando otro auto gira primero","Nunca en un semáforo en rojo"],"explanation":"At a red light you may turn right only when the way is clear and no sign prohibits it."},"37":{"q":"¿Qué debe hacer si NO CAMINE empieza a parpadear mientras usted cruza?","options":["Deténgase donde está","Termine de cruzar la calle","Regrese a la acera","Cruce corriendo rápido"],"explanation":"If the signal flashes while you are crossing, finish crossing rather than turn back."},"38":{"q":"¿Qué significa una X roja sobre un carril?","options":["El carril está abierto","Debe salir del carril","El carril está cerrado","Los peatones pueden cruzar"],"explanation":"A red X means the lane is closed, while a yellow X means the lane is changing use and you must move out of it."},"39":{"q":"¿Qué significa una línea central amarilla discontinua (a trazos)?","options":["No rebasar en su lado","No rebasar en ninguna dirección","Los carriles van en la misma dirección","Se permite rebasar cuando es seguro"],"explanation":"A broken (dashed) yellow centerline means passing is allowed when it is safe."},"40":{"q":"¿Cuándo puede cruzar una línea amarilla doble continua?","options":["Solo para hacer un giro","Solo para rebasar autos lentos","En cualquier momento que esté despejado","Solo de noche"],"explanation":"A double solid yellow line may be crossed only to make a turn."},"41":{"q":"¿Qué debe hacer ante una línea blanca continua?","options":["Adelantar a otros autos","Permanecer en su carril","Hacer un cambio de sentido","Estacionar su auto"],"explanation":"A solid white line means you should stay in your lane, as crossing it is discouraged."},"42":{"q":"¿Dónde debe detenerse en una línea de alto?","options":["Sobre la línea","Pasando la línea","Detrás de la línea","En el cruce peatonal"],"explanation":"A stop line shows where to stop, and you must stop behind it."},"43":{"q":"¿De qué color son las marcas del cruce peatonal?","options":["Rojas","Azules","Verdes","Blancas"],"explanation":"Crosswalk markings are white and are for pedestrians."},"44":{"q":"¿Qué significa un símbolo de diamante pintado en un carril?","options":["El carril está reservado para vehículos compartidos y de alta ocupación (HOV)","El carril es una ciclovía","El carril está cerrado a todo el tráfico","El carril es solo para girar"],"explanation":"A diamond symbol marks a lane reserved for carpools and high-occupancy (HOV) vehicles."},"45":{"q":"¿Qué puede hacer en un carril para bicicletas?","options":["Conducir en él","Ni conducir ni estacionar en él","Estacionar en él","Detenerse y esperar en él"],"explanation":"You may not drive in a bike lane, and you may not park in a bike lane."},"46":{"q":"¿Qué significa una línea amarilla continua en su lado de la carretera?","options":["Se permite rebasar","El carril está cerrado","No se permite rebasar","Detenerse y esperar"],"explanation":"A solid yellow line on your side means no passing."},"47":{"q":"¿Qué normas de señales y semáforos se aplican en Texas?","options":["Solo reglas de la ciudad","Solo reglas del condado","No hay normas fijas","Normas nacionales compartidas"],"explanation":"Texas follows the shared national MUTCD standards for signs and signals."},"48":{"q":"¿Qué significa una luz verde fija del semáforo?","options":["Avance solo si la intersección está despejada","Deténgase por completo detrás de la línea","Reduzca la velocidad y prepárese para detenerse","No se permite girar en esa dirección"],"explanation":"A steady green light means go, but only proceed if the intersection is clear."},"49":{"q":"¿Qué significa una señal de uso de carril con una X roja sobre un carril?","options":["El carril está abierto","El carril está cerrado","El carril es para girar","El carril es para estacionar"],"explanation":"A red X means the lane is closed, while a green down-arrow means the lane is open."},"50":{"q":"¿Qué significa una línea amarilla continua en su lado de la carretera?","options":["Se permite rebasar","El carril está cerrado","No se permite rebasar","Deténgase y espere"],"explanation":"A solid yellow line on your side means no passing, while a broken yellow line allows passing when safe."},"51":{"q":"¿De qué color son las líneas que separan el tráfico en sentidos opuestos?","options":["Azul","Verde","Blanco","Amarillo"],"explanation":"Yellow lines separate traffic moving in opposite directions and show passing rules."},"52":{"q":"¿De qué color son las líneas que separan carriles que van en la misma dirección?","options":["Blanco","Amarillo","Rojo","Azul"],"explanation":"White lines separate lanes of traffic traveling in the same direction."},"53":{"q":"¿Qué debe hacer en una marca de cruce de ferrocarril (RXR) si se acerca un tren?","options":["Acelerar para cruzar primero","Detenerse en la línea de alto","Tocar la bocina y seguir","Cambiar de carril"],"explanation":"At a railroad crossing marked RXR with a stop line, you must stop if a train approaches."},"54":{"q":"¿Qué debe hacer en una intersección cuando el semáforo está completamente apagado o no funciona?","options":["Acelerar para pasar rápido","Continuar sin reducir la velocidad","Tratarla como un alto en todas las direcciones","Esperar hasta que el semáforo encienda"],"explanation":"A dark or non-working signal should be treated as an all-way stop."},"55":{"q":"¿Qué significa para los peatones una señal fija de mano levantada (NO CAMINE)?","options":["Cruce más rápido","Cruce corriendo ahora","Comience a cruzar","No comience a cruzar"],"explanation":"A steady raised-hand (DON'T WALK) signal means pedestrians should not start to cross."},"56":{"q":"¿Qué significa generalmente un bordillo amarillo?","options":["Prohibido estacionar o restricción de carga","Estacionamiento gratis en cualquier momento","Reservado solo para autobuses","Lugar seguro para esperar"],"explanation":"A yellow curb generally indicates a no-parking or loading restriction, though curb colors can vary by city."},"57":{"q":"¿Qué debe hacer ante una flecha roja fija?","options":["Girar en la dirección de la flecha","Esperar; no girar en esa dirección","Acelerar al girar","Ceder el paso y luego girar libremente"],"explanation":"A red arrow means you cannot turn in that direction and must wait until the signal changes."},"58":{"q":"¿Qué le permite hacer una línea blanca discontinua en la carretera?","options":["Adelantar a un vehículo que viene en sentido contrario","Detenerse en medio de la carretera","Cambiar de carril cuando sea seguro","Estacionar junto al borde de la carretera"],"explanation":"A broken white line allows you to change lanes when it is safe, while a solid white line means stay in your lane."},"59":{"q":"¿Cómo se ve una línea de alto?","options":["Una línea verde discontinua","Una fila de puntos pequeños","Una línea amarilla doble","Una línea blanca ancha a lo ancho del carril"],"explanation":"A stop line is a wide white line painted across the lane to show where to stop."}},"safe-driving":{"0":{"q":"Va siguiendo a un sedán en una autopista seca. Cuando el parachoques trasero del sedán pasa por un letrero al borde de la carretera, usted empieza a contar; llega al mismo letrero un poco menos de 2 segundos después. ¿Qué le indica esto y qué debe hacer?","options":["Lo sigue demasiado de cerca; suelte el acelerador para ampliar el espacio a por lo menos 3 segundos.","Su distancia es segura porque 2 segundos es el mínimo recomendado en carretera seca.","Su distancia está bien; la regla de los 3 segundos solo se aplica con lluvia, niebla o hielo.","Debe frenar fuerte de inmediato para retroceder, ya que está dentro del punto ciego del camión."],"explanation":"The three-second rule says that if you reach the fixed point in less than 3 seconds after the car ahead, you are too close, so easing off the gas to restore a 3-second gap is correct. Two seconds is not the safe minimum, the 3-second rule applies in all conditions (you add more seconds for bad weather), and braking hard or worrying about a truck's No-Zone does not fit this car-following scenario."},"1":{"q":"Normalmente deja un espacio de 3 segundos detrás del auto que va adelante. Esta noche empieza a llover fuerte en la autopista y aparece una niebla densa. ¿Qué debe hacer con su distancia de seguimiento?","options":["Mantener el mismo espacio de 3 segundos, ya que la regla de los tres segundos cubre todas las condiciones de manejo","Aumentar el espacio a más de 3 segundos, porque la lluvia y la niebla reducen la tracción y la visibilidad","Reducir el espacio para mantener a la vista las luces traseras del auto de adelante a través de la niebla","Encender las luces altas y mantener un espacio de 2 segundos para reaccionar más rápido a sus luces de freno"],"explanation":"The three-second rule is a minimum for good conditions; in rain, fog, ice, or at high speed you must add more seconds because traction and visibility are reduced. Shortening the gap or relying on high beams (which reflect back off fog) only increases your danger."},"2":{"q":"Conduce por una autopista de Texas cuando una camioneta se acerca mucho por detrás y se queda a solo unos pocos pies de su parachoques, claramente pegada a usted. ¿Cuál es la forma más segura de manejar el espacio alrededor de su vehículo?","options":["Tocar el freno varias veces para advertir al de atrás que se aleje","Acelerar para que el vehículo de atrás quede más lejos","Aumentar la distancia de seguimiento entre usted y el vehículo de adelante para tener más espacio para frenar de forma gradual","Mantenerse exactamente a tres segundos del auto de adelante, ya que esa regla cubre cada situación"],"explanation":"When you are being tailgated, you should increase your following distance to the vehicle ahead so you can slow down or stop gradually instead of braking hard, giving the tailgater more time to react. Three seconds is only a minimum baseline and should be increased behind motorcycles, large trucks, and when tailgated, so option D is wrong, and brake-tapping or speeding up only raises the risk of a crash."},"3":{"q":"Está conduciendo por una autopista de varios carriles junto a un camión de 18 ruedas, manteniéndose justo detrás de su cabina donde no puede ver los espejos laterales del conductor del camión. ¿Qué le indica esta posición y qué debería hacer?","options":["El conductor del camión lo ve bien, así que puede quedarse ahí mientras mantenga una velocidad constante","Debería acercarse más al remolque, ya que el lugar más seguro es justo al lado de las ruedas traseras","Debería destellar las luces altas para que el conductor del camión sepa que está ahí antes de rebasar","Está en el punto ciego del camión (una No-Zone) porque no puede ver los espejos del conductor, así que acelere o reduzca la velocidad para salir de él"],"explanation":"If you can't see a large truck's side mirrors, the driver can't see you, meaning you are sitting in a No-Zone blind spot; the safe response is to clear it quickly by speeding up to pass or easing back. Staying put, moving beside the rear wheels, or relying on high-beam flashes all leave you in the blind spot where the driver cannot see you."},"4":{"q":"Conduciendo por una autopista de Texas, ve un auto averiado más adelante y detiene su vehículo por completo. Al recordarlo, se da cuenta de que la parada tomó más tiempo del que esperaba. ¿Qué tres distancias sumadas conforman la distancia total que recorrió su auto desde que apareció el peligro hasta detenerse por completo?","options":["Distancia de percepción + distancia de reacción + distancia de frenado","Distancia de percepción + distancia de reacción + distancia de seguimiento","Distancia de reacción + distancia de frenado + distancia de hidroplaneo","Distancia de seguimiento + distancia de frenado + distancia de visibilidad de los faros"],"explanation":"Total stopping distance is the sum of perception distance (seeing the hazard), reaction distance (moving your foot to the brake), and braking distance (the car slowing to a stop). Following distance, hydroplaning, and headlight sight distance are real safe-driving concepts but are not components of the stopping-distance formula."},"5":{"q":"Un venado se cruza de repente en la carretera frente a usted en una autopista seca. Desde el momento en que sus ojos registran al venado hasta el instante en que su pie realmente comienza a presionar el freno, su auto sigue avanzando. ¿Cuánto tiempo suele tardar ese tiempo de reacción para el conductor promedio?","options":["Aproximadamente 1,5 segundos","Aproximadamente tres cuartos (¾) de segundo","Aproximadamente 3 segundos","Aproximadamente 35 segundos"],"explanation":"The average driver's reaction time is about ¾ of a second, so the car keeps moving during that interval before braking begins. Option A (about 1.5 s) is the combined perception-plus-reaction time, and 3 seconds is the safe-following-distance rule, not reaction time."},"6":{"q":"Conduce por una carretera de Texas cuando un venado se mete de repente en la vía, lejos por delante. Antes de que su auto siquiera empiece a frenar, deben ocurrir dos cosas: sus ojos y su cerebro deben percibir al venado, y luego usted debe mover el pie hacia el freno. En conjunto, ¿aproximadamente cuánto tarda este proceso de percepción más reacción antes de que los frenos realmente empiecen a actuar?","options":["Unos 1,000 pies, la misma distancia a la que debería poder ver hacia adelante de noche","Unos 3 segundos, porque esa es la distancia de seguimiento segura que siempre debe mantener","Aproximadamente 1.5 segundos combinados, antes de que se añada cualquier distancia de frenado","Unas 35 mph, la velocidad a la que puede comenzar el hidroplaneo en carreteras mojadas"],"explanation":"The combined perception-plus-reaction time is roughly 1.5 seconds, and this happens before braking distance is even added to the total stopping distance. The 3-second answer confuses the separate three-second following-distance rule with reaction time, and the other options misplace unrelated facts (night visibility distance and hydroplaning speed)."},"7":{"q":"En una autopista seca de Texas normalmente necesita unos 45 pies de distancia de frenado para detenerse desde 30 mph una vez que aplica los frenos. El tráfico se despeja y aumenta su velocidad de 30 mph a 60 mph. ¿Aproximadamente cuánta distancia de frenado debería esperar necesitar ahora para detenerse?","options":["Casi los mismos 45 pies, porque la distancia de frenado no cambia mucho con la velocidad","Unos 90 pies, porque duplicar la velocidad duplica la distancia de frenado","Unos 68 pies, porque la distancia de frenado aumenta solo alrededor de la mitad","Unos 180 pies, porque duplicar la velocidad aproximadamente cuadruplica la distancia de frenado"],"explanation":"Braking distance increases with the square of speed, so doubling speed from 30 to 60 mph roughly quadruples it (45 feet x 4 = about 180 feet). Option B is the common trap of assuming the relationship is simply linear (double speed = double distance)."},"8":{"q":"Sale de una calle residencial de 30 mph y se incorpora a una autopista donde duplica su velocidad a 60 mph. De repente, una pelota de niño rueda hacia la carretera delante de usted. En comparación con frenar a 30 mph, ¿cómo cambia su mayor velocidad la capacidad de detenerse?","options":["Su distancia de frenado se cuadruplica aproximadamente, así que se necesita mucho más espacio para detenerse y cualquier choque golpearía con más fuerza","Su distancia de frenado se duplica aproximadamente, igualando el aumento de su velocidad","Su distancia de detención permanece casi igual porque su tiempo de reacción sigue siendo de unos tres cuartos de segundo","Su distancia de detención se acorta porque la mayor velocidad da a los frenos más energía para trabajar"],"explanation":"Braking distance increases with the square of speed, so doubling your speed from 30 to 60 mph roughly quadruples the braking distance and a crash carries far more energy. Doubling speed does not merely double braking distance, and a faster speed never shortens stopping distance even though reaction time stays about three-quarters of a second."},"9":{"q":"Ha estado lloviendo de forma constante en la autopista y hay agua acumulada en el carril. Conduce a unas 40 mph cuando siente que el volante se vuelve liviano y las llantas delanteras parecen deslizarse sobre el agua. ¿Cuál es la forma más segura de recuperar la tracción?","options":["Frenar con fuerza para frenar las llantas y dejar que vuelvan a agarrar el camino","Soltar el acelerador, mantener el volante recto y no frenar bruscamente","Girar el volante hacia donde quiere que vaya el frente del auto y bombear los frenos","Encender las luces altas y agregar un segundo a su distancia de seguimiento"],"explanation":"You are hydroplaning, which can begin near 35 mph as water builds under the tires; easing off the gas, steering straight, and avoiding hard braking lets the tires settle back onto the road. Braking firmly (A) can lock the tires and worsen the slide, and steering/pumping advice (C) is the procedure for a skid, not hydroplaning."},"10":{"q":"Conduce a 45 mph en una carretera de Texas durante un aguacero intenso cuando de repente siente que la dirección se vuelve liviana y el auto comienza a deslizarse como si flotara sobre el agua. ¿Qué debe hacer?","options":["Bombear el pedal del freno con firmeza para que las llantas vuelvan a agarrarse al pavimento","Girar el volante hacia donde quiere que vaya la parte delantera del auto y frenar suavemente","Soltar el acelerador, mantener el volante firme y apuntando recto, y evitar frenar bruscamente","Frenar bruscamente de inmediato y reducir a una marcha más baja para disminuir la velocidad"],"explanation":"When hydroplaning, the tires lose contact with the road, so you should ease off the gas, hold the wheel straight, and avoid braking hard until traction returns. Braking hard (A, D) can cause a skid, and the steer-where-you-want technique (B) applies to correcting a skid, not recovering from hydroplaning."},"11":{"q":"Después de tres semanas sin lluvia, comienza a caer una ligera llovizna mientras conduce por la ciudad. La superficie de la carretera apenas se ve mojada y el tráfico a su alrededor sigue circulando al límite de velocidad normal. ¿Por qué debe tener especial cuidado con la tracción en este momento?","options":["La lluvia ligera no puede reducir la tracción, así que el único peligro real son los aguaceros fuertes que acumulan agua en la carretera","Los puentes y los pasos elevados son las únicas superficies que se vuelven resbaladizas tan temprano en una tormenta","La carretera está más resbaladiza cuando se ha acumulado suficiente agua para comenzar el hidroplaneo cerca de las 35 mph","El aceite y la grasa acumulados durante el período seco se mezclan con la primera lluvia ligera, haciendo que la carretera esté más resbaladiza ahora"],"explanation":"The first rain after a dry spell is the most slippery because accumulated oil and grease mix with the water before being washed away, so a light early drizzle is more dangerous than it looks. Option C is a real fact about hydroplaning but describes a different hazard that needs water to build up, not the slick oily film of the first rain."},"12":{"q":"Es una mañana despejada con una temperatura justo bajo cero y usted conduce por una carretera rural. La superficie de la carretera por delante parece seca y siente buena tracción. Al acercarse a un puente sobre un arroyo, ¿qué debe hacer?","options":["Soltar el acelerador y reducir la velocidad antes del puente, porque los puentes y los pasos elevados se congelan antes que el resto de la carretera","Mantener la velocidad, ya que la carretera seca que dejó atrás prueba que la superficie del puente también es segura","Frenar con fuerza justo al llegar al puente para comprobar si la superficie está resbaladiza","Cambiar a las luces altas para detectar antes el hielo en el puente"],"explanation":"Bridges and overpasses are exposed to cold air on all sides, so they freeze before regular pavement; easing off the gas and slowing down before the bridge is the safe response. Maintaining speed because the road behind feels dry ignores that the bridge can be icy even when the surrounding road is not, and braking hard on a possibly icy surface can cause a skid."},"13":{"q":"Es una mañana de invierno despejada y muy fría, alrededor de -1°C. Conduce por una autopista y se acerca a un paso elevado. El pavimento más adelante se ve un poco más oscuro y mojado, pero no nota hielo evidente. ¿Cuál es la forma más segura de manejar esta situación?","options":["La carretera solo parece mojada, así que mantenga la velocidad y frene con firmeza si empieza a resbalar","Trate la zona oscura y de aspecto mojado como posible hielo negro; reduzca la velocidad gradualmente antes del paso elevado y evite frenar o girar bruscamente","Cambie a las luces altas para que el pavimento mojado refleje más luz y pueda ver mejor la superficie","Acelere para cruzar el paso elevado rápidamente y pasar menos tiempo sobre la superficie resbaladiza"],"explanation":"Bridges and overpasses freeze first, and black ice is hard to see, so a dark, wet-looking patch in freezing temperatures should be treated as ice by slowing gradually and avoiding sudden braking or steering. Maintaining speed (A) assumes the surface is only wet, and speeding up (D) increases the risk of a skid you cannot control."},"14":{"q":"Conduce por una autopista húmeda de Texas cuando la parte trasera de su auto se desliza de repente hacia la derecha y empieza a coletear. ¿Qué debe hacer para recuperar el control?","options":["Pisar el freno con firmeza para frenar el auto de inmediato y luego enderezar el volante","Mantener presión constante en el acelerador para impulsar el auto hacia adelante y sacarlo del derrape","Quitar el pie del acelerador y girar el volante en la dirección hacia donde quiere que vaya la parte delantera del auto, sin pisar bruscamente el freno","Cambiar a una marcha más baja y bombear el pedal del freno repetidamente hasta que regrese la tracción"],"explanation":"In a skid you should ease off the gas and steer in the direction you want the front of the car to go, never slamming the brakes, which would only worsen the loss of traction. Hard braking (A) and pumping the brake while downshifting (D) are recovery steps for other emergencies, not skids, and holding the gas (B) keeps the wheels spinning."},"15":{"q":"Conduce de noche por una carretera rural cuando de repente entra en un banco de niebla espesa y apenas puede ver el camino por delante. ¿Qué debe hacer?","options":["Encender las luces altas para que la luz más brillante atraviese más lejos la niebla","Mantener la velocidad actual pero encender las luces de emergencia para seguir siendo visible","Dirigirse hacia el borde derecho de la carretera y apartar la vista del resplandor","Cambiar a luces bajas, reducir la velocidad y orillarse de forma segura si la visibilidad empeora demasiado"],"explanation":"In fog or smoke you should use low beams because high beams reflect off the moisture and glare back at you, and you should slow down or pull off safely. High beams (A) make visibility worse, and looking to the right edge (C) is the response for oncoming headlight glare, not fog."},"16":{"q":"Conduce a casa una tarde despejada cuando se desata una fuerte tormenta. La visibilidad disminuye tanto que apenas distingue una señal de tráfico a unos 800 pies de distancia, aunque falta bastante para el atardecer. ¿Qué debe hacer con las luces?","options":["Encender los faros, porque debe usarlos siempre que no pueda ver a unos 1,000 pies de distancia, sin importar la hora del día.","Dejar los faros apagados, ya que la regla de usarlos solo aplica entre el atardecer y el amanecer.","Encender las luces altas para atravesar la lluvia y mejorar la distancia de visibilidad.","Mantener los faros apagados pero reducir la velocidad, porque los faros solo son obligatorios cuando no puede ver a unos 500 pies de distancia."],"explanation":"Texas requires headlights from sunset to sunrise AND any time you cannot see about 1,000 feet ahead, so the reduced visibility means you must turn them on even in daylight. High beams reflect off rain and fog and make it harder to see, and 500 feet is the dimming distance for oncoming traffic, not the visibility threshold for using lights."},"17":{"q":"Conduce de noche por una carretera rural oscura de dos carriles con las luces altas encendidas. Distingue un vehículo que se aproxima en el carril contrario y calcula que ahora está a un poco menos de 500 pies. ¿Qué debe hacer?","options":["Mantener las luces altas encendidas hasta que el otro vehículo baje las suyas primero","Cambiar ahora las luces altas a luces bajas","Cambiar a luces bajas solo si también está a menos de 300 pies detrás de otro vehículo","Hacer destellos con las luces altas para advertir al conductor que se aproxima y seguir con las altas"],"explanation":"Texas exige bajar las luces altas a bajas cuando se está a menos de 500 pies de un vehículo que se aproxima, así que debe cambiar ahora. Esperar al otro conductor (A) o hacer destellos (D) mantiene un resplandor cegador en la carretera, y la regla de los 300 pies (C) se aplica al circular detrás de un vehículo, no al tráfico que se aproxima."},"18":{"q":"Conduce de noche por una carretera rural oscura con las luces altas encendidas. Alcanza a un auto más lento que va adelante y reduce gradualmente la distancia hasta quedar a unos 250 pies detrás de él, sin tráfico en sentido contrario a la vista. ¿Qué debe hacer con las luces altas?","options":["Mantener las luces altas, ya que la regla de bajarlas solo se aplica a los vehículos que vienen de frente","Dejar las luces altas hasta estar a 100 pies del auto de adelante, y luego cambiar a luces bajas","Cambiar a luces bajas ahora, porque debe bajarlas cuando está a 300 pies o menos detrás de otro vehículo","Mantener las luces altas pero mirar hacia el borde derecho de la carretera para evitar el deslumbramiento"],"explanation":"Texas law requires you to dim your high beams to low when within 300 feet behind another vehicle, so at 250 feet you must already be on low beams. The high beams glare in the lead driver's mirrors; the 500-foot rule (A) applies to oncoming traffic, and looking to the right edge (D) is the technique for when you are blinded, not for following."},"19":{"q":"Conduce de noche por una carretera oscura de dos carriles cuando un vehículo que se aproxima no baja sus luces altas, y el resplandor le dificulta ver el camino que tiene delante. ¿Qué debe hacer para mantener el control hasta que el vehículo pase?","options":["Encender sus propias luces altas para que el otro conductor vea lo brillantes que son y las baje","Frenar bruscamente de inmediato y detenerse en su carril hasta que sus ojos se recuperen","Mirar directamente a los faros que se aproximan para poder seguir exactamente dónde está el otro vehículo","Reducir la velocidad y mirar hacia el borde derecho de su carril hasta que el vehículo haya pasado"],"explanation":"When blinded by oncoming high beams, you should look toward the right edge of the road to avoid the glare while still guiding your car. Flashing your own high beams or staring into the lights only worsens the blindness, and stopping hard in a travel lane risks a rear-end collision."},"20":{"q":"Conduce de noche por una carretera rural oscura con las luces bajas encendidas. El camino que tiene delante solo está iluminado hasta donde alcanzan sus faros, y va tan rápido que un venado que de repente entre en esa zona iluminada quedaría dentro de su distancia de frenado antes de que pudiera reaccionar y frenar. ¿Qué error está cometiendo?","options":["Está sobrepasando el alcance de sus faros: va tan rápido que no puede detenerse dentro de la distancia iluminada que tiene delante","Está aplicando mal la regla de los tres segundos para estas condiciones","No bajó las luces altas a bajas dentro de los 500 pies de un vehículo que viene en sentido contrario","Está haciendo hidroplaneo porque su velocidad superó el límite seguro para la superficie"],"explanation":"Overdriving your headlights means traveling so fast that you cannot stop within the distance your headlights illuminate ahead, which is exactly the scenario described. The three-second rule applies to spacing behind another vehicle, dimming high beams concerns glare to others, and hydroplaning involves water on the road—none fit a dry night road with a fixed lighted distance."},"21":{"q":"Va bajando una pendiente larga cuando pisa el pedal del freno y este se hunde hasta el fondo casi sin resistencia. El auto sigue ganando velocidad. ¿Cuál es la mejor manera de reducir la velocidad y detenerse?","options":["Sujete el volante con firmeza, suelte el acelerador y no frene con fuerza, luego salga de la vía lentamente","Bombee el pedal del freno, cambie a una marcha más baja y aplique el freno de mano gradualmente","Quite el pie del acelerador y dirija el volante hacia donde quiere que vaya el frente del auto","Tire del freno de mano hasta el tope de una sola vez y apague el motor para frenar la velocidad"],"explanation":"When the brakes fail, pumping the pedal may restore some pressure, shifting to a lower gear uses engine braking to slow you, and applying the parking brake gradually brings you to a stop. Option A is the correct response to a tire blowout, and pulling the parking brake all the way up at once (D) can cause a skid."},"22":{"q":"Conduce a 60 mph por una autopista de Texas cuando escucha un fuerte estallido y la dirección de repente tira con fuerza hacia un lado. Se da cuenta de que se le ha reventado un neumático delantero. ¿Cuál es la forma más segura de recuperar el control?","options":["Frenar de golpe de inmediato para detenerse lo más rápido posible antes de que el auto se desvíe más","Girar bruscamente el volante hacia el lado opuesto para contrarrestar el tirón y luego frenar fuerte hacia el arcén","Sujetar el volante con firmeza, soltar suavemente el acelerador y dejar que el auto reduzca la velocidad gradualmente antes de salir de la vía","Bombear el pedal del freno y cambiar a una marcha más baja para reducir la velocidad del vehículo"],"explanation":"In a blowout you hold the wheel firmly, ease off the gas, and avoid braking hard, then pull off slowly once the car has slowed. Braking hard (A) or jerking the wheel (B) can cause a complete loss of control, and pumping the pedal with a lower gear (D) is the technique for brake failure, not a tire blowout."},"23":{"q":"El motor de su auto se apaga mientras cruza una vía de tren en un cruce rural. El auto no vuelve a arrancar y puede ver un tren acercándose a lo lejos. ¿Qué debe hacer?","options":["Permanecer con el cinturón puesto en el auto y bombear rápidamente el pedal del freno para sacar el auto de las vías","Encender las luces intermitentes de emergencia y esperar dentro del vehículo a que pase el tren","Cambiar a una marcha más baja e intentar cruzar antes de que el tren llegue al cruce","Sacar a todos del auto y alejarse mucho de las vías, luego llamar para pedir ayuda"],"explanation":"If your vehicle stalls on railroad tracks, the only priority is getting everyone out and well away from the tracks before calling for help, because you can never safely beat an approaching train. Pumping the brake, waiting in the car, or trying to drive across all keep people in the path of the train."},"24":{"q":"En una carretera rural de dos carriles, su motor pierde potencia de repente y usted logra llegar rodando hasta el borde de la vía. Hay un arcén pavimentado amplio disponible. ¿Cuál es la forma correcta de detenerse y protegerse mientras espera ayuda?","options":["Salirse por completo al arcén, encender las luces intermitentes de emergencia y colocar dispositivos de advertencia detrás del vehículo.","Detenerse en su carril con el freno de mano puesto para que los demás conductores lo vean bien, y encender los faros.","Dejar la parte trasera del auto en el carril, bombear el pedal del freno y poner una marcha más baja para seguir siendo visible.","Estacionar la mitad del auto en el arcén, salir y pararse en el carril para indicar al tráfico que lo rodee."],"explanation":"If you must stop on the road, pull fully onto the shoulder, turn on your hazard flashers, and use warning devices so approaching traffic is alerted. Stopping in the lane or leaving part of the car in traffic exposes you to a rear-end crash, and pumping the brake/shifting down is the procedure for brake failure, not a stopped breakdown."},"25":{"q":"Ha estado conduciendo durante seis horas en un viaje largo y nota que bosteza constantemente, que el vehículo se desvía hacia la línea del carril y que le cuesta recordar las últimas millas. Aún le faltan dos horas para llegar a su destino. ¿Qué debe hacer?","options":["Bajar la ventanilla y subir el volumen de la radio para mantenerse alerta, y seguir conduciendo hasta su destino","Salir en un área de descanso segura y tomar una siesta o pasar la noche, porque la somnolencia retarda el tiempo de reacción y el juicio igual que el alcohol","Aumentar la distancia de seguimiento a la regla de los tres segundos y continuar conduciendo las dos horas restantes","Encender las luces altas para ver más lejos y aguantar las últimas dos horas"],"explanation":"Fatigue slows reaction time and impairs judgment much like drugs or alcohol, so the only safe choice is to stop and rest rather than drive drowsy. Tricks like fresh air, loud music, or a longer following distance do not cure drowsiness, and high beams have nothing to do with the danger of falling asleep at the wheel."},"26":{"q":"Está detenido en un semáforo en rojo en Texas cuando le llega un mensaje de texto al teléfono. El semáforo sigue en rojo y el tráfico es intenso. ¿Qué debe hacer?","options":["Responder rápidamente ahora que está detenido, ya que resolverlo antes de que el semáforo se ponga en verde es el momento más seguro","Mirar la pantalla solo para leerlo, porque leer un mensaje está permitido mientras no escriba","Dejar el teléfono y esperar hasta estar estacionado de forma segura, porque enviar mensajes de texto mientras conduce es ilegal en Texas y una distracción importante","Responder, pero primero encender las luces intermitentes de emergencia para avisar a los conductores de que está temporalmente ocupado"],"explanation":"Texting while driving is illegal in Texas and is a major distraction, so you should not text from behind the wheel even when stopped at a light; wait until you are safely parked. Reading or replying at a red light is still using the phone to text, and hazard flashers are for a disabled or stopped-on-the-road vehicle, not for excusing phone use."},"27":{"q":"Llevas a dos amigos a un partido en Texas. Uno se sienta adelante y el otro se sube al asiento trasero y dice: \"No me pongo el cinturón, solo voy atrás por diez minutos\". ¿Qué debes hacer antes de arrancar?","options":["Dejar que el pasajero del asiento trasero viaje sin cinturón, ya que las reglas del cinturón solo aplican al conductor y a los pasajeros del asiento delantero","Permitirlo porque el viaje es corto y te quedarás en calles lentas del vecindario","Pasarle tu teléfono para que le escriba a alguien y pida otro aventón, así no tiene que viajar sin cinturón","Insistir en que se abroche el cinturón antes de conducir, porque la ley de Texas exige que el conductor y todos los pasajeros usen el cinturón de seguridad"],"explanation":"Texas law requires a seat belt for the driver and every passenger, including those in the back seat, regardless of how short the trip is. Options A and B rely on common myths (rear seats are exempt, or short/slow trips don't count), and texting while driving is itself illegal and unsafe."},"28":{"q":"Conduce por una autopista seca detrás de una camioneta. Para comprobar su distancia de seguimiento, observa cuándo la camioneta pasa la sombra de un paso elevado sobre la carretera y luego cuenta hasta que el frente de su auto llega a ese mismo punto. ¿Cuánto debe durar esa cuenta para que su distancia de seguimiento se considere adecuada?","options":["Tres segundos o más después de que la camioneta pase el punto","Menos de tres segundos después de que la camioneta pase el punto","Alrededor de tres cuartos de segundo, igual que el tiempo de reacción promedio","Exactamente 500 pies de espacio detrás de la camioneta"],"explanation":"With the three-second rule, you pick a fixed point and count; reaching it in three seconds or more after the vehicle ahead means your following distance is adequate. Reaching it in less than three seconds means you are too close, while three-quarters of a second describes average reaction time and 500 feet is the high-beam dimming distance, not a following gap."},"29":{"q":"Va siguiendo a una camioneta en una autopista seca y quiere comprobar si mantiene una distancia de seguimiento segura usando la regla de los tres segundos. El parachoques trasero de la camioneta acaba de pasar una señal de tráfico más adelante. ¿Qué debe hacer para aplicar la regla correctamente?","options":["Empezar a contar cuando la camioneta pasa la señal y detenerse después de tres segundos, luego asegurarse de que la camioneta siga dentro de esa distancia.","Empezar a contar cuando la parte trasera de la camioneta pasa la señal y detenerse cuando su parachoques delantero llegue a la misma señal; si es menos de tres segundos, va demasiado cerca.","Medir un espacio de tres largos de vehículo entre su parachoques delantero y el trasero de la camioneta.","Contar los segundos que tarda la camioneta en detenerse por completo desde el momento en que pasa la señal."],"explanation":"The three-second rule works by picking a fixed point and counting the seconds between when the vehicle ahead passes it and when you pass the same point; under three seconds means you're following too closely. Fixed car-length spacing (C) and timing the lead vehicle's stop (D) are not how the rule works."},"30":{"q":"Conduce por una autopista despejada y de repente un venado salta a la carretera delante de usted. Lo ve, decide detenerse y pisa el freno. Una vez que su pie ya está pisando el pedal del freno, la distancia que su vehículo sigue recorriendo antes de detenerse por completo se conoce como qué?","options":["Distancia total de frenado, que es la distancia completa desde que ve el venado hasta que el vehículo se detiene","Distancia de reacción, la distancia recorrida mientras decide pisar el freno","Distancia de frenado, uno de los tres componentes de la distancia total de detención","Distancia de percepción, la distancia recorrida antes de que sus ojos noten al venado"],"explanation":"Braking distance is the distance the vehicle travels from the moment the brakes are applied until it stops, and it is one of the three components of total stopping distance (perception + reaction + braking). Total stopping distance is the sum of all three, not just the part after braking begins, so that option is the trap."},"31":{"q":"Conduce a velocidad de autopista cuando un venado entra de repente en su carril muy adelante. Antes de que su pie siquiera toque el pedal del freno, su vehículo ya ha recorrido cierta distancia. ¿Cuáles componentes de la distancia total de frenado corresponden a ese recorrido que ocurre ANTES de que los frenos se apliquen realmente?","options":["Distancia de frenado y distancia de reacción","Distancia de percepción y distancia de frenado","Solo la distancia de frenado, ya que el auto sigue moviéndose hasta que las ruedas se bloquean","Distancia de percepción y distancia de reacción"],"explanation":"Total stopping distance is perception distance plus reaction distance plus braking distance, and only perception and reaction distance occur before the brakes are applied; braking distance is the travel after the brakes engage, so any option containing braking distance is wrong."},"32":{"q":"Conduce a unas 40 mph por una carretera de Texas durante una fuerte tormenta de lluvia cuando de repente siente que la dirección se vuelve ligera y el auto empieza a deslizarse sobre el agua sin responder al volante. ¿Cuál es la forma más segura de reaccionar?","options":["Levante suavemente el pie del acelerador, mantenga el volante recto y deje que el auto frene hasta que las llantas vuelvan a agarrar","Pise el freno con firmeza y de forma constante para reducir velocidad y recuperar tracción rápidamente","Gire bruscamente el volante hacia el acotamiento para salir de la película de agua","Bombee rápidamente el pedal del freno y cambie a una marcha más baja para controlar el deslizamiento"],"explanation":"During hydroplaning the tires ride on a layer of water and lose contact with the road, so you should ease off the gas, steer straight, and avoid braking hard until traction returns. Braking firmly (B) or pumping the brakes (D) is a real technique for other emergencies like brake failure, but hard braking during hydroplaning can cause you to skid out of control."},"33":{"q":"Es una mañana clara de invierno, justo por debajo de cero. La carretera de asfalto parece seca, pero te acercas a un paso elevado largo. Para conducir con seguridad, ¿qué debes esperar y hacer?","options":["El paso elevado es la parte más cálida de la carretera, así que puedes mantener tu velocidad actual al cruzarlo","El paso elevado puede estar helado aunque la carretera parezca seca, así que reduce la velocidad antes de llegar a él","El hidroplaneo es el principal peligro en el paso elevado, así que suelta el acelerador y dirige recto","Usa las luces altas al cruzar el paso elevado para detectar hielo más adelante"],"explanation":"Bridges and overpasses freeze before the rest of the roadway because cold air reaches them from all sides, so they can be icy even when the surrounding pavement looks dry; slowing before the overpass is the safe move. Hydroplaning involves water on the road near 35 mph, not freezing, and high beams do not help here, so those are the traps."},"34":{"q":"Son las 2:00 de la tarde en una autopista de Texas cuando comienza un aguacero repentino e intenso. La lluvia es tan densa que apenas distingue las luces traseras del vehículo que va un par de cientos de pies por delante, y calcula que ya no puede ver con claridad ni siquiera 1,000 pies más adelante en el camino. ¿Qué debe hacer con sus luces?","options":["Dejar las luces delanteras apagadas porque es de día, y encender solo las luces intermitentes de emergencia mientras sigue avanzando","Encender las luces altas para que la lluvia intensa de adelante quede iluminada lo más lejos posible","Encender las luces delanteras, ya que debe usarlas siempre que no pueda ver unos 1,000 pies por delante, incluso de día","Mantener las luces delanteras apagadas pero encender la luz interior del techo para seguir siendo visible para otros conductores"],"explanation":"En Texas debe usar las luces delanteras siempre que no pueda ver aproximadamente 1,000 pies por delante, lo que incluye condiciones diurnas como la lluvia intensa, por lo que encenderlas es lo correcto. Las luces altas son incorrectas porque con lluvia o niebla se reflejan de vuelta y reducen la visibilidad, y las luces de emergencia o la luz del techo no sustituyen a las luces delanteras mientras conduce."},"35":{"q":"Conduce de noche por una carretera oscura de dos carriles con las luces altas encendidas. Adelante, un automóvil viene hacia usted en el carril contrario y, al mismo tiempo, va alcanzando poco a poco a un camión más lento en su propio carril justo delante. ¿Qué exige la ley de Texas que haga con las luces altas?","options":["Mantener las luces altas para el auto que viene de frente, pero bajarlas para el camión de adelante, ya que el tránsito al que se acerca importa más","Bajarlas solo para el auto que viene de frente dentro de 500 pies; detrás de otro vehículo se permiten las luces altas a cualquier distancia","Bajarlas solo para el camión de adelante dentro de 300 pies; hacia el tránsito que viene de frente se permiten las luces altas a cualquier distancia","Bajarlas a luces bajas para el auto que viene de frente dentro de 500 pies y para el camión de adelante dentro de 300 pies"],"explanation":"Texas law requires dimming high beams to low within 500 feet of an oncoming vehicle and within 300 feet when approaching another vehicle from behind, so in this scenario both situations require low beams. Options that excuse you from dimming for one of the two vehicles ignore half the rule and would blind another driver."},"36":{"q":"Conduce a 65 mph por una autopista interestatal de Texas cuando escucha un fuerte estallido y el volante tira bruscamente hacia un lado: se ha reventado una llanta delantera. ¿Qué debe hacer?","options":["Sujetar el volante con firmeza para mantener el auto recto, soltar el acelerador gradualmente y salir de la carretera despacio una vez que haya reducido la velocidad","Frenar firme e inmediatamente para detener el vehículo lo más rápido posible","Quitar el pie del acelerador y girar el volante hacia donde quiere que vaya la parte delantera del auto","Bombear el pedal del freno y cambiar a una marcha más baja para reducir la velocidad del vehículo"],"explanation":"During a blowout you must hold the wheel firmly and gradually ease off the gas before pulling off slowly—braking hard (B) can cause you to lose control. Steering toward where you want the front to go (C) is the fix for a skid, and pumping the brakes with a lower gear (D) is the procedure for brake failure, not a blowout."}},"learn-safe-driving":{"0":{"q":"¿Para qué se usa la regla de los tres segundos?","options":["Para mantener una distancia de seguimiento segura","Para saber cuándo cambiar el aceite","Para poner el freno de estacionamiento","Para cronometrar cuánto señalizar"],"explanation":"The three-second rule helps you keep a safe following distance behind the car ahead."},"1":{"q":"¿Cómo se usa la regla de los tres segundos?","options":["Contar tres largos de auto adelante","Contar los segundos hasta un punto fijo","Conducir tres millas por hora más lento","Esperar tres segundos en cada parada"],"explanation":"Pick a fixed point ahead and count the seconds it takes to reach it after the car ahead passes it."},"2":{"q":"¿Cuándo debe agregar más segundos a su distancia de seguimiento?","options":["En caminos secos y despejados","Cuando hay poco tráfico","En lluvia, niebla, hielo o a alta velocidad","Cuando conduce despacio"],"explanation":"Add more seconds to your following distance in rain, fog, ice, or at high speed."},"3":{"q":"¿Cuándo debe agregar segundos adicionales a la distancia de seguimiento de tres segundos?","options":["Solo en días soleados","Cuando la carretera está seca y vacía","Cuando hay poco tráfico","Con lluvia, niebla, hielo o a alta velocidad"],"explanation":"Rain, fog, ice, and high speed all require adding extra seconds to your following distance."},"4":{"q":"¿Cuándo debe aumentar la distancia de seguimiento?","options":["Cuando conduce detrás de una motocicleta o un camión grande","Cuando la carretera está seca y despejada","Cuando hay poco tráfico","Cuando tiene prisa"],"explanation":"Increase your following distance behind motorcycles, large trucks, or when being tailgated."},"5":{"q":"Cuando otro conductor lo sigue muy de cerca, ¿qué debe hacer?","options":["Frenar de repente para advertirle","Aumentar su distancia con el vehículo de adelante","Acelerar para escapar de él","Detenerse en medio de la carretera"],"explanation":"Increasing your following distance gives you more room to stop safely when being tailgated."},"6":{"q":"¿Cómo se llaman los grandes puntos ciegos alrededor de los camiones y autobuses grandes?","options":["Zonas lentas","Zonas seguras","No-Zones (puntos ciegos)","Zonas de choque"],"explanation":"Large trucks and buses have big blind spots called No-Zones, and if you can't see the driver's mirrors, they can't see you."},"7":{"q":"Si no puede ver los espejos del conductor de un camión o autobús, ¿qué significa?","options":["Puede pasar por la derecha","El conductor lo ve con claridad","Sus propios espejos están rotos","El conductor no puede verlo"],"explanation":"Large trucks and buses have big blind spots, so if you can't see the driver's mirrors, the driver can't see you."},"8":{"q":"¿Qué tres distancias forman la distancia total de frenado?","options":["Distancia de percepción, distancia de reacción y distancia de frenado","Distancia de velocidad, distancia del clima y distancia de frenado","Distancia de seguimiento, distancia del punto ciego y distancia de reacción","Distancia diurna, distancia nocturna y distancia de percepción"],"explanation":"Total stopping distance equals perception distance plus reaction distance plus braking distance."},"9":{"q":"¿Cuáles son las tres partes de la distancia total de frenado?","options":["Velocidad, peso y distancia de neumáticos","Distancia de percepción, reacción y frenado","Distancia de dirección, señal y frenado","Distancia de visión, clima y reacción"],"explanation":"Total stopping distance is made up of perception distance, reaction distance, and braking distance."},"10":{"q":"¿Cuánto dura aproximadamente el tiempo de reacción del conductor promedio?","options":["Unos 3 segundos","Unos 2 segundos","Unos tres cuartos de segundo","Unos 5 segundos"],"explanation":"The average driver's reaction time is about three-fourths (3/4) of a second."},"11":{"q":"¿Aproximadamente cuánto dura el tiempo combinado de percepción más reacción?","options":["Unos 0,5 segundos","Unos 3 segundos","Unos 5 segundos","Unos 1,5 segundos"],"explanation":"The combined perception-plus-reaction time is roughly 1.5 seconds."},"12":{"q":"Si duplica su velocidad, la distancia de frenado aproximadamente:","options":["Se cuadruplica (se vuelve unas 4 veces mayor)","Se duplica (se vuelve unas 2 veces mayor)","Permanece igual","Se reduce a la mitad"],"explanation":"Braking distance increases with the square of speed, so doubling speed roughly quadruples it."},"13":{"q":"Si duplica su velocidad, ¿cuánto aumenta aproximadamente su distancia de frenado?","options":["Permanece igual","Aproximadamente cuatro veces","Aproximadamente dos veces","Aproximadamente tres veces"],"explanation":"Doubling your speed roughly quadruples your braking distance."},"14":{"q":"¿Cómo afecta a la detención conducir más rápido?","options":["Facilita la detención","No afecta a la detención","Se tarda más en detenerse","Reduce el impacto del choque"],"explanation":"The faster you go, the longer it takes to stop and the harder a crash, because of the speed-energy relationship."},"15":{"q":"¿Por qué debe reducir la velocidad en carreteras mojadas?","options":["Para ahorrar combustible","Para seguir más de cerca","Para iluminar más los faros","Porque se reduce la tracción"],"explanation":"Wet roads reduce traction, so slowing down helps you stay in control."},"16":{"q":"¿A qué velocidad aproximada puede comenzar el hidroplaneo en una carretera mojada?","options":["Cerca de 35 mph","Cerca de 5 mph","Cerca de 15 mph","Cerca de 70 mph"],"explanation":"Hydroplaning can begin near 35 mph as water builds up under the tires."},"17":{"q":"Que es el hidroplaneo?","options":["Cuando las llantas agarran mejor el camino bajo la lluvia","Cuando las llantas pierden contacto con el camino sobre el agua","Cuando los frenos se sobrecalientan en una bajada larga","Cuando los faros se reflejan en el pavimento mojado"],"explanation":"Hydroplaning happens when water builds up under the tires and they lose contact with the road surface."},"18":{"q":"¿Qué debe hacer si su auto comienza a hidroplanear?","options":["Frenar fuerte de inmediato","Acelerar para recuperar el agarre","Soltar el acelerador y mantener el volante recto","Girar el volante bruscamente"],"explanation":"If you hydroplane, ease off the gas, do not brake hard, and steer straight."},"19":{"q":"¿Por qué la primera lluvia después de un período seco es la más resbaladiza?","options":["La carretera está más fría de lo normal","La lluvia arrastra toda la suciedad","Los neumáticos pierden aire con la lluvia","El aceite se mezcla con el agua en la carretera"],"explanation":"The first rain mixes with built-up oil on the road, making it the most slippery."},"20":{"q":"En clima helado, ¿qué parte de la carretera se congela primero?","options":["Los puentes y pasos elevados","Las cimas de las colinas","Los túneles","Los estacionamientos"],"explanation":"Bridges and overpasses freeze before the rest of the road in icy conditions."},"21":{"q":"¿Por qué es peligroso el hielo negro?","options":["Se derrite rápido","Es difícil de ver en la carretera","Huele fuerte","Hace mucho ruido"],"explanation":"Black ice is dangerous because it is hard to see on the road."},"22":{"q":"Si su carro empieza a patinar, ¿qué debe hacer?","options":["Frenar de golpe con fuerza","Pisar más el acelerador","Soltar el acelerador y dirigir hacia donde quiere ir","Cerrar los ojos y sujetarse"],"explanation":"In a skid, take your foot off the gas, don't slam the brakes, and steer in the direction you want the front of the car to go."},"23":{"q":"¿Cómo debe girar el volante para recuperarse de un derrape?","options":["Hacia el borde de la carretera","En la dirección opuesta al derrape","Lejos de donde quiere ir","En la dirección hacia donde quiere que vaya el frente"],"explanation":"To recover from a skid, steer in the direction you want the front of the car to go."},"24":{"q":"Durante un derrape, ¿qué debe hacer con el pie?","options":["Quitar el pie del pedal del acelerador","Presionar más fuerte el acelerador","Frenar bruscamente con el pedal del freno","Mantener presión constante en el acelerador"],"explanation":"Easing off the gas helps you regain traction during a skid."},"25":{"q":"Con niebla o humo, ¿qué luces debe usar?","options":["Luces altas","Luces bajas","Sin luces","Solo luces intermitentes de emergencia"],"explanation":"Use low beams in fog or smoke because high beams reflect back and reduce your visibility."},"26":{"q":"En niebla o humo, ¿qué debe hacer?","options":["Acelerar para atravesarlo","Encender las luces altas","Reducir la velocidad o salirse de la carretera de forma segura","Apagar los faros"],"explanation":"In fog or smoke you should slow down or pull off the road safely."},"27":{"q":"Con niebla, ¿qué luces debe usar?","options":["Solo las luces de emergencia","Ninguna luz","Las luces altas","Las luces bajas"],"explanation":"In fog you should use low beams because high beams reflect off the fog and reduce your visibility."},"28":{"q":"¿Cuándo debe usar los faros?","options":["Desde el atardecer hasta el amanecer","Solo durante lluvia fuerte","Solo en la autopista","Solo al estacionar"],"explanation":"Texas law requires headlights from sunset to sunrise."},"29":{"q":"¿Cuándo debe encender los faros según la visibilidad?","options":["Cuando no puede ver al menos 100 pies adelante","Cuando no puede ver al menos 1,000 pies adelante","Cuando no puede ver al menos 50 pies adelante","Cuando no puede ver al menos 5,000 pies adelante"],"explanation":"Use your headlights any time you cannot see at least about 1,000 feet ahead."},"30":{"q":"¿Cuándo debe bajar las luces altas a las luces bajas ante un vehículo que viene en sentido contrario?","options":["A menos de 100 pies","A menos de 250 pies","A menos de 500 pies","A menos de 1,000 pies"],"explanation":"You must dim your high beams to low beams when within 500 feet of an oncoming vehicle."},"31":{"q":"Al seguir a otro vehículo, ¿a qué distancia debe bajar las luces altas a luces bajas?","options":["A menos de 100 pies por detrás","A menos de 150 pies por detrás","A menos de 200 pies por detrás","A menos de 300 pies por detrás"],"explanation":"You must dim your high beams to low beams when within 300 feet behind another vehicle."},"32":{"q":"¿A cuántos pies de un vehículo que viene de frente debe bajar las luces altas?","options":["500 pies","100 pies","250 pies","1,000 pies"],"explanation":"You must dim your high beams to low within 500 feet of an oncoming vehicle."},"33":{"q":"¿A cuántos pies de un vehículo que sigue debe bajar las luces altas?","options":["100 pies","300 pies","500 pies","1,000 pies"],"explanation":"You must dim your high beams to low when within 300 feet behind another vehicle."},"34":{"q":"Si las luces altas de un vehículo que viene de frente lo ciegan, ¿hacia dónde debe mirar?","options":["Directamente a los faros","Hacia arriba al cielo","Hacia el borde derecho de la carretera","Hacia abajo al tablero"],"explanation":"Looking toward the right edge of the road helps you avoid the glare and stay in your lane."},"35":{"q":"¿Qué significa \"sobrepasar el alcance de los faros\"?","options":["Usar las luces altas con demasiada frecuencia","Olvidar encender las luces","Conducir con un faro apagado","Ir tan rápido que no puede detenerse en la zona iluminada"],"explanation":"Overdriving your headlights means going so fast you cannot stop within the distance lighted by your headlights."},"36":{"q":"¿Qué debe hacer si fallan los frenos?","options":["Bombee el pedal, cambie a una marcha baja, use el freno de mano gradualmente","Apague el motor y gire bruscamente","Acelere para llegar a la próxima salida","Cierre los ojos y toque la bocina"],"explanation":"If your brakes fail, pump the brake pedal, shift to a lower gear, and use the parking brake gradually."},"37":{"q":"¿Cómo debe aplicar el freno de mano durante una falla de frenos?","options":["Todo de golpe","Gradualmente","Nunca usarlo","Solo después de detenerse"],"explanation":"During brake failure, apply the parking brake gradually rather than all at once."},"38":{"q":"Si fallan los frenos, ¿cuál es una respuesta recomendada?","options":["Acelerar para seguir en movimiento","Apagar los faros","Cambiar a una marcha más baja","Tocar la bocina con fuerza"],"explanation":"Shifting to a lower gear helps slow the vehicle when your brakes fail."},"39":{"q":"¿Qué debe hacer si se le revienta una llanta?","options":["Frenar fuerte de inmediato","Acelerar para mantener el control","Soltar el volante","Sujetar el volante con firmeza y soltar el acelerador"],"explanation":"In a blowout, hold the wheel firmly, ease off the gas, and do not brake hard."},"40":{"q":"Después de un reventón de llanta, una vez que tenga el control, ¿cómo debe salir de la carretera?","options":["Salga de la carretera lentamente","Frene fuerte y deténgase rápido","Acelere para incorporarse","Quédese en su carril"],"explanation":"After a tire blowout, once you have control you should pull off the road slowly."},"41":{"q":"¿Qué debe hacer durante un reventón de neumático?","options":["Frenar fuerte de inmediato","No frenar fuerte","Acelerar rápidamente","Soltar el volante"],"explanation":"During a tire blowout, do not brake hard; ease off the gas and pull off slowly."},"42":{"q":"Si su vehículo se apaga sobre las vías del tren, ¿qué debe hacer?","options":["Quedarse en el vehículo y esperar","Intentar arrancar y ganarle al tren","Saque a todos y aléjense, luego pida ayuda","Empujar el vehículo a lo largo de las vías"],"explanation":"Get everyone out and away from the tracks, then call for help; never try to beat a train."},"43":{"q":"¿Qué nunca debe intentar hacer en las vías del tren?","options":["Detenerse antes de las vías","Mirar a ambos lados","Reducir la velocidad cerca de las vías","Ganarle el paso a un tren"],"explanation":"You should never try to beat a train across railroad tracks."},"44":{"q":"Si debe detenerse en la carretera, ¿qué debe hacer?","options":["Orillarse al acotamiento y encender las luces intermitentes","Detenerse en su carril y esperar","Estacionarse a la mitad en el carril de circulación","Dejar los faros apagados"],"explanation":"Pull fully onto the shoulder, turn on hazard flashers, and use warning devices."},"45":{"q":"¿Qué debe encender cuando se detiene al costado del camino en una emergencia?","options":["Las luces altas","Las luces intermitentes de emergencia","La luz interior del techo","Nada"],"explanation":"When stopped on the roadside in an emergency, turn on your hazard (emergency) flashers."},"46":{"q":"Al detenerse en la carretera en una emergencia, ¿qué tan lejos debe mover su vehículo?","options":["Quedarse en su carril de circulación","Hasta la mitad en el arcén","Completamente en el arcén","Sobre la línea central"],"explanation":"Pull fully onto the shoulder so your vehicle is clear of traffic."},"47":{"q":"¿Qué le hacen al conductor la fatiga, las drogas y el alcohol?","options":["Mejoran el tiempo de reacción","Agudizan el juicio","No tienen efecto","Retrasan la reacción y deterioran el juicio"],"explanation":"Fatigue, drugs, and alcohol all slow reaction time and impair judgment."},"48":{"q":"¿Cuándo debe evitar conducir?","options":["Cuando está afectado o somnoliento","Cuando está bien descansado","Cuando la carretera está despejada","Cuando hay poco tráfico"],"explanation":"You should never drive while impaired or drowsy because it slows your reaction time and judgment."},"49":{"q":"¿Cómo afecta la fatiga (somnolencia) a su conducción?","options":["Mejora su concentración","Retrasa el tiempo de reacción y el juicio, como las drogas y el alcohol","No tiene ningún efecto en la conducción","Hace que frene más rápido"],"explanation":"Fatigue slows your reaction time and judgment just like drugs and alcohol."},"50":{"q":"¿Qué actividad es una distracción importante al conducir?","options":["Usar el cinturón de seguridad","Revisar los espejos","Enviar mensajes o usar el teléfono en la mano","Reducir la velocidad bajo la lluvia"],"explanation":"Texting and handheld phone use is a major distraction and texting while driving is illegal in Texas."},"51":{"q":"En Texas, ¿es legal enviar mensajes de texto mientras se conduce?","options":["Sí, siempre es legal","Sí, solo en autopistas","Sí, si el tráfico es lento","No, es ilegal"],"explanation":"Texting while driving is illegal in Texas."},"52":{"q":"¿Cuándo debe usar el cinturón de seguridad mientras conduce?","options":["Siempre","Solo en autopistas","Solo de noche","Solo cuando llueve"],"explanation":"Texas law requires you to always wear your seat belt while driving."},"53":{"q":"¿Quién debe usar el cinturón de seguridad en Texas?","options":["Solo el conductor","El conductor y todos los pasajeros","Solo los del asiento delantero","Solo los niños menores de 12 años"],"explanation":"Texas law requires the driver and all passengers to wear seat belts."},"54":{"q":"¿Qué es la distancia de reacción?","options":["La distancia donde sus llantas dejan marcas de derrape","La distancia que mantiene detrás de otros autos","La distancia que recorre su vehículo mientras reacciona después de percibir un peligro","La distancia en que sus frenos detienen el vehículo"],"explanation":"Reaction distance is how far your vehicle travels while you react after perceiving a hazard."},"55":{"q":"¿Qué es la distancia de frenado?","options":["El tiempo que pasa mirando la carretera","La distancia que conduce antes de un giro","El espacio entre dos autos estacionados","La distancia que recorre su vehículo desde que frena hasta que se detiene"],"explanation":"Braking distance is how far your vehicle travels from when you apply the brakes until it fully stops."},"56":{"q":"Si su auto comienza a hidroplanear, ¿qué debe hacer?","options":["Suelte el acelerador y mantenga el volante recto","Frene fuerte de inmediato","Acelere rápidamente","Gire el volante bruscamente"],"explanation":"During hydroplaning, ease off the gas and steer straight instead of braking hard."},"57":{"q":"¿Qué le ayuda a mantener la regla de los tres segundos?","options":["Un parabrisas limpio","Una distancia de seguimiento segura","Un tanque de combustible lleno","La presión correcta de los neumáticos"],"explanation":"The three-second rule helps you keep a safe following distance behind the vehicle ahead."},"58":{"q":"¿Cuándo debe encender los faros durante el día?","options":["Solo en la autopista","Solo cuando está oscuro afuera","Cuando no puede ver unos 1,000 pies por delante","Nunca durante el día"],"explanation":"Turn on headlights whenever visibility drops and you cannot see about 1,000 feet ahead, even in daytime rain or fog."},"59":{"q":"Si se detiene en el costado de la carretera en una emergencia, ¿qué debe hacer?","options":["Quedarse en su carril y esperar","Apagar todas las luces","Alejarse rápidamente","Colocar dispositivos de advertencia para otros conductores"],"explanation":"Warning devices alert other drivers that your vehicle is stopped on the roadside."}},"alcohol-and-penalties":{"0":{"q":"Marcus, de 34 años, es detenido al salir de una barbacoa de un amigo en Houston. El oficial sospecha que ha estado bebiendo y le pide una prueba de aliento. ¿A partir de qué nivel de alcohol en sangre (BAC) se considera legalmente que Marcus, como conductor adulto, conduce en estado de embriaguez (DWI) en Texas?","options":["0.08% de BAC o más","0.04% de BAC o más","0.15% de BAC o más","Cualquier cantidad detectable por encima del 0.00% de BAC"],"explanation":"For an adult driver age 21 or older, the Texas DWI limit is 0.08% BAC. 0.04% is the limit for commercial drivers, and any detectable amount (above 0.00%) applies only to drivers under 21 under Zero Tolerance."},"1":{"q":"Marcus, de 26 años, es detenido en Austin después de zigzaguear entre carriles. Pasa una prueba de aliento que marca 0,08% de concentración de alcohol en la sangre (BAC) y le dice al oficial que se siente perfectamente bien y que conducía con cuidado. Según la ley de Texas, ¿qué delito ha cometido Marcus con base en esa lectura?","options":["Nada, porque 0,08% es el límite legal y solo lo supera cuando la lectura excede 0,08%","Conducir en Estado de Intoxicación (DWI), porque conducir con 0,08% de BAC o más es DWI para un adulto","Conducir Bajo la Influencia (DUI), porque cualquier cantidad detectable de alcohol hace culpable de DUI a un adulto","Nada, porque le dijo al oficial que se sentía bien y no mostró un deterioro real"],"explanation":"For an adult 21 or older, driving at or above 0.08% BAC is the offense of Driving While Intoxicated (DWI), so reaching exactly 0.08% counts. The Zero Tolerance DUI for any detectable alcohol applies only to drivers under 21, and feeling 'fine' does not change the legal BAC limit."},"2":{"q":"Un conductor de 30 años es detenido después de zigzaguear entre carriles. Una prueba de aliento marca 0,06% de BAC, pero el oficial observa habla arrastrada y mala coordinación consistentes con deterioro por alcohol. Según la ley de Texas, ¿qué puede ocurrir?","options":["Nada, porque 0,06% está por debajo del límite adulto de 0,08%, así que el DWI no puede aplicarse","El conductor queda automáticamente exonerado en cuanto la prueba de aliento marca menos de 0,08%","El conductor aún puede ser acusado de DWI porque está deteriorado por el alcohol, aunque su BAC esté por debajo de 0,08%","Al conductor solo se le puede multar por una infracción de envase abierto, no por DWI"],"explanation":"In Texas, a driver can be charged with DWI below 0.08% BAC if alcohol or drugs impair them, so the observed impairment supports a DWI charge. The 0.08% figure is a per se limit, not a safe harbor, so being under it does not automatically clear the driver."},"3":{"q":"Marcus conduce un tractocamión comercial para una empresa de carga. Después de un turno largo, se toma dos cervezas con la cena y una prueba de aliento posterior marca 0,05% de BAC. Argumenta que está muy por debajo del límite legal y que puede seguir conduciendo su camión. ¿Tiene razón y cuál es el límite que aplica?","options":["Tiene razón; el límite para todos los conductores en Texas es 0,08% de BAC, así que 0,05% es legal.","Tiene razón porque cualquier BAC por debajo de 0,08% nunca puede resultar en un cargo.","Está por encima del límite porque Texas tiene tolerancia cero y cualquier alcohol detectable es ilegal para él.","Está por encima del límite; los conductores comerciales tienen un límite más bajo de 0,04% de BAC, y 0,05% lo supera."],"explanation":"Commercial drivers in Texas are held to a lower limit of 0.04% BAC, so Marcus's 0.05% reading puts him over the limit. The 0.08% figure (A) is the standard adult limit, not the commercial one, and zero tolerance (C) applies only to drivers under 21, not commercial drivers."},"4":{"q":"Marcus tiene 19 años y conduce a casa desde una fiesta de un amigo donde tomó una cerveza. Un oficial de policía lo detiene legalmente y una prueba de aliento muestra una concentración de alcohol en sangre (BAC) del 0,03%. Según la ley de Texas, ¿cuál es su situación legal?","options":["Es ilegal que conduzca — bajo la Tolerancia Cero de Texas, cualquier alcohol detectable (un BAC superior a 0,00) para un conductor menor de 21 años es un DUI por parte de un menor.","Es legal que conduzca porque su BAC del 0,03% está por debajo del límite de DWI del 0,08%.","Es legal que conduzca porque su BAC del 0,03% está por debajo del límite del 0,04% para conductores comerciales.","Es legal que conduzca porque solo tomó una bebida y el hígado procesa una bebida estándar por hora."],"explanation":"For drivers under 21, Texas has Zero Tolerance, so ANY detectable alcohol (a BAC above 0.00) is illegal and is a DUI by a minor. The 0.08% adult DWI limit and the 0.04% commercial limit do not apply to a 19-year-old minor, making those traps wrong."},"5":{"q":"Un conductor de 19 años sale de una fiesta y es detenido en Texas. Una prueba de aliento muestra una concentración de alcohol en sangre (BAC) de 0.03%, muy por debajo del límite para adultos de 0.08%. ¿Qué infracción, si la hay, ha cometido el conductor?","options":["Ninguna, porque la BAC está por debajo del límite para adultos de 0.08%","DUI (conducir bajo la influencia) de alcohol por un menor, porque cualquier alcohol detectable es ilegal para menores de 21 años","DWI, porque el conductor está automáticamente intoxicado con cualquier BAC","Ninguna, pero la licencia del conductor se suspende 180 días por consentimiento implícito"],"explanation":"Texas has a Zero Tolerance law for drivers under 21: any detectable alcohol (a BAC above 0.00) is a DUI of alcohol by a minor, regardless of the 0.08% adult DWI limit. Option A wrongly applies the adult threshold to a minor, and the 180-day suspension in D is the penalty for refusing a test, not for a 0.03% reading."},"6":{"q":"En una fiesta, Marcus ha tomado un par de cervezas y se siente tranquilo y relajado, así que le dice a un amigo que en realidad es un conductor más seguro y cuidadoso después de beber. Su amigo le advierte que esto es peligroso. ¿Por qué el alcohol convierte a Marcus en un conductor más peligroso, aunque se sienta relajado?","options":["El alcohol es un estimulante que acelera su corazón y lo vuelve demasiado agresivo al volante","El alcohol solo afecta a los conductores cuando su nivel de alcohol en sangre alcanza el límite legal de 0.08%, así que dos cervezas no pueden afectarlo","El alcohol es un depresor que ralentiza su tiempo de reacción y afecta su juicio, aunque se sienta relajado","El alcohol agudiza su visión y coordinación, pero embota su capacidad de obedecer las señales de tránsito"],"explanation":"Alcohol is a depressant, so it slows reaction time and impairs judgment even when the drinker feels calm and relaxed. It is not a stimulant (A is the wrong category), and a driver can be impaired well below 0.08% (B is false), making C correct."},"7":{"q":"Mientras conduce a casa desde una fiesta donde tomó varias bebidas, Marcus nota que se desvía constantemente en su carril, titubea al alcanzar la palanca de la señal de giro y reacciona un instante tarde cuando el auto de adelante frena. ¿Qué combinación de efectos del alcohol explica mejor lo que está experimentando?","options":["Su nivel de alcohol en sangre está subiendo porque el aire fresco de la noche acelera el regreso del alcohol a su torrente sanguíneo.","El alcohol actúa como estimulante, por lo que agudiza su concentración pero hace que sus movimientos musculares sean nerviosos y rápidos.","Los efectos provienen solo del cansancio; el alcohol en sí ya se ha disipado porque ha pasado más de una hora desde su última bebida.","El alcohol ha ralentizado su tiempo de reacción, afectado su juicio y reducido su coordinación y visión."],"explanation":"Alcohol is a depressant that slows reaction time, impairs judgment, and reduces coordination and vision, which matches Marcus's lane drifting, fumbling, and delayed braking. Alcohol is not a stimulant and does not sharpen focus, and only time lowers BAC, so fresh air and the passage of one hour do not undo the impairment."},"8":{"q":"Después de dos cervezas en casa de un amigo, Marcus se siente físicamente bien, no le tiemblan las manos y habla con normalidad, así que decide que es seguro conducir a casa e incluso acelera para alcanzar un semáforo en amarillo ante el que normalmente se habría detenido. ¿Cuál de sus capacidades fue la que el alcohol probablemente afectó PRIMERO, llevándolo a esta decisión arriesgada?","options":["Su juicio, que es la primera capacidad de conducción afectada por el alcohol","Su visión, que siempre es la primera capacidad que afecta el alcohol","Su coordinación, ya que las manos firmes prueban que su juicio sigue intacto","Su tiempo de reacción, que el alcohol afecta antes que cualquier otra cosa"],"explanation":"El juicio es la primera capacidad de conducción afectada por el alcohol, por eso Marcus tomó la decisión arriesgada de acelerar en el semáforo aunque se sintiera físicamente bien. La visión, la coordinación y el tiempo de reacción también se ven afectados por el alcohol, pero se afectan después del juicio, no antes."},"9":{"q":"En una fiesta, un amigo ha bebido varias copas en las últimas dos horas y ahora quiere conducir a casa. Insiste en que está bien porque acaba de tomar dos tazas grandes de café negro, comió una comida completa y salió al aire frío para 'despejarse la cabeza'. ¿Qué deberías decirle sobre su capacidad para conducir de forma segura?","options":["El café y el aire frío han acelerado el procesamiento del alcohol en su cuerpo, así que ahora puede conducir con seguridad.","Nada de eso reduce su nivel de alcohol en sangre; solo el paso del tiempo lo puede hacer recuperar la sobriedad, así que no debe conducir.","Comer una comida completa absorbe el alcohol que ya está en su sangre, así que su nivel de alcohol ya volvió a un nivel legal.","Como se siente alerta, su juicio y su tiempo de reacción han vuelto por completo y puede conducir legalmente."],"explanation":"Only the passage of time lowers BAC, because the liver processes alcohol at a fixed rate of about one drink per hour. Coffee, food, cold air, and feeling alert do not speed up sobering or reduce impairment, so he should not drive."},"10":{"q":"En una fiesta, su amigo se ha tomado varias cervezas en las últimas dos horas y ahora quiere conducir a casa. Dice que estará bien para conducir si primero toma una taza de café fuerte, come una comida abundante y se da una ducha fría. Según lo que sabe sobre cómo el alcohol sale del cuerpo, ¿cuál es la respuesta más acertada?","options":["El café y una ducha fría lo despejarán rápidamente, así que puede conducir en cuanto se sienta alerta de nuevo.","Una comida abundante absorberá el alcohol que ya está en su sangre y bajará su BAC lo suficiente para conducir con seguridad.","Nada de eso acelerará el proceso de eliminar la embriaguez; solo el tiempo baja el BAC, así que no debe conducir.","El aire fresco durante el camino a casa eliminará el alcohol de su organismo, así que un viaje corto está bien."],"explanation":"Only the passage of time lowers BAC because the liver processes about one standard drink per hour, and nothing makes it faster. Coffee, food, a cold shower, and fresh air may make a person feel more alert but do not reduce intoxication, so they are dangerous myths."},"11":{"q":"Marcus tomó cuatro tragos estándar en una fiesta que terminó a la medianoche. Bebe dos cafés grandes, come una comida completa y se da una ducha fría antes de conducir a casa a la 1:30 a.m. Se siente alerta. ¿Qué es cierto sobre su capacidad para conducir con seguridad?","options":["El café y la comida han bajado su nivel de alcohol en sangre lo suficiente como para que ahora sea seguro conducir","La ducha fría aceleró su hígado, así que la mayor parte del alcohol ya se ha eliminado","Como se siente alerta y su juicio está claro, está bien para conducir","Solo el tiempo puede bajar su nivel de alcohol en sangre; su hígado elimina alrededor de un trago por hora, por lo que probablemente sigue intoxicado"],"explanation":"The liver processes only about one standard drink per hour and nothing speeds it up, so after roughly 90 minutes Marcus has cleared at most one or two of his four drinks. Coffee, food, and a cold shower do not lower BAC, and feeling alert is misleading because judgment is the first ability alcohol impairs."},"12":{"q":"Marcus tomó una cerveza en la cena y apenas se siente algo mareado. Más temprano ese día tomó una pastilla para la alergia de venta libre que advierte que puede causar somnolencia. Piensa que una cerveza está muy por debajo del límite legal, así que cree que puede conducir a casa. ¿Cuál es el verdadero peligro en su situación?","options":["El medicamento de venta libre combinado con el alcohol puede multiplicar su deterioro, haciéndolo mucho menos seguro para conducir de lo que sugeriría una sola cerveza","No pasa nada, porque los medicamentos de venta libre son legales y no pueden afectar su capacidad para conducir","Está seguro siempre que coma más y beba café para contrarrestar los efectos combinados antes de salir","Solo corre riesgo si su BAC alcanza el límite de 0,04% para conductores comerciales, algo que una cerveza no puede lograr"],"explanation":"Drugs of any kind—including legal over-the-counter medicines—combined with alcohol multiply impairment, so Marcus can be far more impaired than one beer alone would suggest. Coffee and food do not speed sobering, and the 0.04% limit applies only to commercial drivers, not Marcus."},"13":{"q":"A Marcus lo detienen a altas horas de la noche y lo arrestan legalmente por DWI (conducir en estado de ebriedad) en Austin. En la comisaría, el oficial le pide una muestra de aliento. Marcus dice que nunca aceptó ninguna prueba y se niega. Según la ley de Texas, ¿sobre qué base ya se consideraba que él había aceptado?","options":["Aceptó cuando firmó los documentos del arresto en la comisaría, por lo que la prueba ahora es obligatoria.","Al conducir en Texas, dio consentimiento implícito a una prueba de aliento o de sangre al ser arrestado legalmente por DWI.","Aceptó solo porque su nivel de alcohol en sangre ya se midió en 0,08% o más durante la detención.","Dio su consentimiento cuando solicitó su licencia de conducir de Texas, lo que renuncia permanentemente a todas las negativas."],"explanation":"Texas law states that by driving in the state you give implied consent to a breath or blood test if lawfully arrested for DWI, so consent already exists at the time of arrest. Option A is wrong because consent comes from the act of driving, not signing paperwork, and a 0.08% reading or the license application does not establish it."},"14":{"q":"Marcus es arrestado legalmente por conducir intoxicado (DWI) después de ser detenido a altas horas de la noche. En la estación, el oficial le pide una muestra de aliento, pero Marcus se niega, creyendo que sin una prueba no hay evidencia en su contra. Dejando de lado el cargo de DWI en sí, ¿qué le ocurre a su licencia de conducir únicamente por haberse negado a la prueba?","options":["No le pasa nada a su licencia, porque bajo el consentimiento implícito un conductor siempre tiene derecho a negarse a una prueba de aliento o sangre sin consecuencias","Su licencia se suspende por hasta 1 año por esta primera negativa","Su licencia se suspende automáticamente por 180 días por esta primera negativa","Enfrenta una multa de $2,000 y hasta 180 días de cárcel por negarse a la prueba"],"explanation":"Under Texas implied consent, refusing a lawful breath or blood test triggers an automatic 180-day license suspension for a first refusal under Administrative License Revocation, separate from any DWI charge. The 'up to 1 year' suspension and the $2,000 fine/jail time are penalties for a DWI conviction, not for refusing the test, and refusal does carry consequences."},"15":{"q":"Marcus es arrestado legalmente por conducir intoxicado (DWI) en Texas tras no pasar un control de sobriedad en la carretera. En la comisaría, se niega a dar una muestra de aliento o de sangre, creyendo que sin un resultado de la prueba el Estado no tiene caso y su licencia está a salvo. Varios meses después, su cargo de DWI es desestimado en el tribunal. ¿Cuál es el estado de sus privilegios de conducir?","options":["Como el cargo de DWI fue desestimado, no se aplica ninguna suspensión y su licencia permanece totalmente válida.","Su licencia queda suspendida por hasta 1 año, la sanción estándar vinculada a una primera condena por DWI.","Solo enfrenta una multa de $2,000 por la negativa, pero su licencia no queda suspendida.","Su licencia queda suspendida automáticamente por 180 días bajo la Revocación Administrativa de Licencia (ALR) por la negativa, de forma separada del cargo de DWI desestimado."],"explanation":"Refusing a breath or blood test triggers an automatic 180-day ALR suspension that is entirely separate from the DWI case, so it stands even though the DWI charge was dismissed. Option B wrongly applies the up-to-1-year suspension tied to a DWI conviction, which never occurred here, and the dismissal does not erase the refusal-based ALR suspension."},"16":{"q":"En un bar de Houston, Marcus, de 24 años, toma varias bebidas, luego conduce a casa y lo detienen con un nivel de alcohol en sangre (BAC) del 0.11%. Lo arrestan y lo condenan por su primer DWI (conducir intoxicado), sin delitos previos y sin pasajeros en el auto. ¿Cuál es la multa máxima que un tribunal puede imponer por esta primera condena por DWI?","options":["Hasta $2,000","Hasta $500","Hasta $4,000","Hasta $10,000"],"explanation":"A first DWI in Texas carries a fine of up to $2,000, along with possible jail time and license suspension. The $500 figure is the maximum fine for a minor's first DUI, and the higher amounts apply to repeat or aggravated offenses, not a standard first DWI."},"17":{"q":"Marcus es condenado por su primer DWI en Texas tras ser detenido al salir de la fiesta de un amigo con un nivel de alcohol en sangre del 0,10%. El juez ahora decide su pena de cárcel dentro del rango establecido por la ley de Texas para un primer DWI. ¿Cuál es el posible periodo de cárcel que el juez puede imponer?","options":["Hasta 1 año de cárcel","De 3 a 180 días de cárcel","Una suspensión fija de 180 días en lugar de cárcel","Sin cárcel, solo una multa de 500 dólares"],"explanation":"Under Texas law, a first DWI carries 3 days to 180 days in jail, so the judge's range is set by that statute. The 1-year figure is the license suspension (not jail), the 180-day suspension applies to refusing a chemical test under ALR, and the $500 fine is a minor's first DUI penalty."},"18":{"q":"Marcus, de 28 años, es detenido cuando sale de una fiesta un viernes por la noche. Se somete a la prueba de aliento, da 0.10% de BAC y es condenado por su primer DWI (conducir en estado de ebriedad) en Texas. No lleva ningún niño como pasajero ni tiene antecedentes. En la sentencia, ¿cuál es el periodo máximo por el que se le puede suspender la licencia de conducir por esta primera condena por DWI?","options":["180 días, el mismo periodo impuesto por negarse a la prueba de aliento","Ninguna suspensión, ya que su BAC estaba por debajo de 0.15%","Hasta 1 año","Hasta 2 años, el plazo estándar para cualquier DWI"],"explanation":"A first DWI conviction in Texas carries a license suspension of up to 1 year. The 180-day figure is the separate automatic suspension for refusing a chemical test under implied consent, not the penalty for a DWI conviction, so option A is a trap."},"19":{"q":"A Marcus lo condenaron por conducir en estado de ebriedad (DWI) en Texas el año pasado; pagó su multa y cumplió su condena. Esta noche lo detienen y lo arrestan por DWI por segunda vez. En comparación con su primera condena, ¿qué debe esperar por esta reincidencia?","options":["Las penas son exactamente las mismas que en un primer DWI: una multa máxima de $2,000 y hasta 1 año de suspensión de la licencia.","No hay penas adicionales porque Texas solo cuenta la condena por DWI más reciente.","Su licencia se suspende automáticamente por 180 días, y eso reemplaza cualquier otra pena por DWI.","Las penas aumentan por reincidencia, así que enfrenta multas más severas, más tiempo de cárcel y una suspensión más larga que en el primer DWI."],"explanation":"Texas law increases DWI penalties for repeat offenses, so a second conviction brings tougher consequences than the first. Option A wrongly states the first-offense maximums ($2,000 / 1 year) apply unchanged, and option C confuses the 180-day ALR suspension for refusing a test with the criminal DWI penalty."},"20":{"q":"Detienen a Marcus cuando regresa a casa de una fiesta. Tiene 27 años, este es su primer arresto por DWI (conducir en estado de ebriedad) en la vida, y la prueba de aliento muestra un nivel de alcohol en sangre (BAC) de 0.16%. Su amigo dice que las sanciones serán exactamente iguales que las de cualquier otro primer delito de DWI. ¿Por qué se equivoca el amigo?","options":["Porque un BAC de 0.15% o más activa sanciones más severas, incluso en un primer delito.","Porque negarse a la prueba de aliento siempre duplica la multa estándar del primer delito.","Porque cualquier primer delito de DWI se considera automáticamente un delito grave (felony).","Porque las sanciones solo aumentan si hay un niño menor de 15 años en el vehículo."],"explanation":"In Texas, penalties for a first DWI increase when the driver's BAC is 0.15% or higher, so Marcus's 0.16% reading means enhanced penalties. A child passenger under 15 (D) is a separate felony enhancement, but it does not apply here since Marcus was alone."},"21":{"q":"De camino a casa desde una fiesta, detienen a Marcus y su prueba de alcohol en sangre marca 0,10%. Es su primer delito de DWI (conducir en estado de ebriedad), pero su sobrina de 8 años está sentada con el cinturón puesto en el asiento trasero. ¿Cómo cambia la clasificación de este delito el hecho de llevar a una pasajera menor de edad?","options":["No tiene ningún efecto en el cargo porque sigue siendo su primer delito","Conducir en estado de ebriedad con un pasajero menor de 15 años convierte el delito en un delito grave (felony)","Añade una suspensión automática de la licencia por 180 días bajo la regla del envase abierto","Eleva la multa máxima a 500 dólares porque hay un menor involucrado"],"explanation":"In Texas, DWI with a child passenger under age 15 is a felony, regardless of whether it is a first offense. The 180-day suspension belongs to refusing a chemical test, and the $500 figure is the fine for a minor's own first DUI, not a penalty tied to carrying a child passenger."},"22":{"q":"A un conductor en Texas lo detienen, pasa la prueba de sobriedad y registra una concentración de alcohol en sangre (BAC) del 0.05%, por lo que el oficial no lo acusa de conducir intoxicado (DWI). Sin embargo, el oficial nota una botella de cerveza medio vacía en el portavasos junto al conductor. ¿Cómo trata la ley de Texas este recipiente abierto de alcohol en el área de pasajeros?","options":["Se ignora porque su BAC estaba por debajo del límite legal del 0.08%.","Suspende automáticamente su licencia por 180 días bajo el consentimiento implícito.","Es un delito separado de cualquier cargo por DWI.","Solo es un delito si hay un menor de 15 años en el vehículo."],"explanation":"Having an open container of alcohol in the passenger area is a separate offense in Texas, independent of whether a DWI charge applies or what the driver's BAC was. The 180-day suspension relates to refusing a chemical test under implied consent, and the child-passenger rule concerns the felony DWI enhancement, not open containers."},"23":{"q":"Marcus tiene 18 años y lo detienen mientras conduce a casa desde una fiesta. Una prueba de aliento muestra una concentración de alcohol en sangre (BAC) de 0,02% y es condenado por su primer DUI (alcohol) como menor de edad. Además de la suspensión de la licencia, el servicio comunitario y un curso de concientización sobre el alcohol, ¿cuál es la multa máxima que puede enfrentar por esta primera infracción?","options":["Hasta $2,000, la misma multa que se aplica a un primer DWI de un adulto","Ninguna multa, ya que el BAC estaba por debajo del límite de 0,08% para adultos","Hasta $1,000, duplicada porque se detectó alcohol","Hasta $500"],"explanation":"Under Texas zero-tolerance law, a minor's first DUI (alcohol) carries a fine of up to $500, along with license suspension, community service, and an alcohol-awareness course. The $2,000 figure is the maximum for an adult first DWI, and no fine being charged is wrong because any detectable alcohol is illegal for a driver under 21."},"24":{"q":"Marcus tiene 19 años y lo detienen de camino a casa desde una fiesta. El oficial huele alcohol y una prueba de aliento muestra un nivel de alcohol en sangre (BAC) de 0,03%. Esta es la primera infracción de Marcus relacionada con el alcohol. Según la ley de Texas, ¿qué le pasa a su licencia de conducir?","options":["Su licencia es suspendida, porque cualquier alcohol detectable en un conductor menor de 21 años es un DUI que conlleva una suspensión.","No le pasa nada a su licencia, porque su BAC está por debajo del límite legal de 0,08%.","Su licencia es suspendida por 180 días específicamente por negarse a la prueba de aliento.","Enfrenta un cargo de delito grave y una suspensión de un año porque se midió su BAC."],"explanation":"Texas has zero tolerance for drivers under 21, so any detectable alcohol (above 0.00%) is a DUI for a minor and carries a license suspension. The 0.08% limit (B) applies only to adults 21+, the 180-day suspension (C) is for refusing a test, and a felony (D) does not result from a minor's first DUI."},"25":{"q":"A Marcus, de 19 anos, lo detienen en Austin una noche tarde. El oficial detecta una pequena cantidad de alcohol en su aliento, y una prueba confirma un nivel de alcohol en sangre (BAC) de 0,03%. Es su primer delito. Bajo la ley de tolerancia cero de Texas, cual de las siguientes opciones incluira su sentencia?","options":["Solo una advertencia por escrito, ya que su BAC esta muy por debajo del limite adulto de 0,08%","Una multa de hasta $500, suspension de la licencia, servicio comunitario y un curso de concientizacion sobre el alcohol","Hasta 180 dias de carcel y una multa de $2,000, igual que un DWI de adulto","Una suspension automatica de 180 dias por rechazar la prueba de aliento"],"explanation":"Because Marcus is under 21, any detectable alcohol is a DUI by a minor under zero-tolerance, and a first offense carries a fine up to $500, license suspension, community service, and an alcohol-awareness course. The 0.08% adult limit and adult DWI jail/fine penalties do not apply to a minor's first DUI, and the 180-day suspension is for refusing the test, which he did not refuse."},"26":{"q":"Marcus, de 19 años, es detenido al salir de una fiesta en Austin. Una prueba de aliento muestra un nivel de alcohol en sangre (BAC) de 0,03 % y es condenado por su primer DUI siendo menor de edad. Como parte de la resolución del caso, ¿cuál de los siguientes es un componente obligatorio de su sanción según la ley de tolerancia cero de Texas?","options":["Nada más, porque su BAC estaba por debajo del límite adulto de 0,08 %","Una suspensión automática de 180 días únicamente por hacerse la prueba de aliento","Completar un curso de concientización sobre el alcohol","Un mínimo obligatorio de 3 días de cárcel"],"explanation":"A minor's first DUI for alcohol requires completion of an alcohol-awareness course (plus a fine up to $500, license suspension, and community service). Option A is wrong because under-21 zero tolerance makes ANY detectable alcohol illegal, and the 3-day jail minimum (D) and the 180-day suspension for refusing a test (B) belong to adult DWI and refusal rules, not a minor's first DUI."},"27":{"q":"Marcus ha acumulado tres multas por exceso de velocidad y una condena por pasarse un semáforo en rojo en los últimos dos años. Le preocupa lo que estas infracciones de tránsito significan para su historial de conducir en Texas más allá de las multas que ya pagó. ¿Cuál es la consecuencia más precisa de acumular estas condenas de tránsito?","options":["No pasa nada más una vez pagadas las multas; las condenas no tienen efecto en su historial.","Cada condena le exige automáticamente tener el seguro de responsabilidad financiera SR-22.","Las condenas activan una suspensión automática de la licencia por 180 días tras la segunda multa.","Las condenas suman puntos a su historial, y demasiados pueden llevar a recargos (surcharges) y a la suspensión de la licencia."],"explanation":"Traffic convictions add points to your Texas driving record, and accumulating too many can result in surcharges and license suspension. SR-22 is tied to serious offenses like a DWI rather than ordinary tickets, and the automatic 180-day suspension applies to refusing a breath/blood test under implied consent, not to routine moving violations."},"28":{"q":"Marcus ha acumulado varias condenas de tránsito en los últimos dos años en su licencia de conducir de Texas. En su última comparecencia ante el tribunal, el juez le advierte que seguir acumulando condenas activará consecuencias adicionales más allá de las multas individuales. Según el sistema de puntos/recargos (surcharge) de Texas, ¿a qué pueden conducir finalmente demasiadas condenas?","options":["A recargos (surcharges) y a la suspensión de la licencia","A una suspensión automática de 180 días por negarse a una prueba de aliento","A un seguro SR-22 obligatorio solo si una condena es por envase abierto de alcohol","A cargos por delito grave porque las condenas repetidas se tratan como DWI con un menor"],"explanation":"Under the Texas point/surcharge system, traffic convictions add points to your record, and too many convictions can lead to surcharges and license suspension. The 180-day suspension applies specifically to refusing a breath or blood test (implied consent), not to accumulating ordinary convictions, so that option is a misplaced fact."},"29":{"q":"Marcus fue condenado por su primer DWI (conducir intoxicado) en Texas hace un año. Ya cumplió su suspensión y pagó su multa, pero su compañía de seguros de auto lo canceló, y las únicas pólizas que encuentra cotizan tarifas casi el triple de lo que pagaba antes. Llama al DPS para preguntar por qué su situación de conducción sigue afectada tanto tiempo después de que terminó el caso. ¿Cuál es la explicación más precisa que recibirá?","options":["Una vez pagada la multa y cumplida la suspensión, el DWI se elimina automáticamente de su registro, así que cualquier tarifa alta es un error de facturación no relacionado.","Una condena por DWI permanece en su registro y eleva drásticamente los costos del seguro, y es posible que deba contratar un seguro de responsabilidad financiera SR-22 para reinstaurar sus privilegios de conducir.","El costo alto es solo un recargo temporal de 180 días vinculado a su negativa a la prueba de aliento, y desaparecerá cuando termine ese período.","Su registro ahora muestra el DWI, pero a las aseguradoras en Texas se les prohíbe legalmente subir las tarifas por una sola primera infracción."],"explanation":"A DWI conviction stays on the driver's record and sharply raises insurance costs, and an SR-22 financial responsibility filing may be required to reinstate driving privileges. Option A is wrong because completing penalties does not erase the conviction, and option C confuses this with the separate 180-day ALR suspension for refusing a test."},"30":{"q":"Marcus cumplió su condena judicial por una primera condena por conducir en estado de ebriedad (DWI), y su período de suspensión de licencia de un año ya terminó. Cuando visita la oficina del DPS para restablecer sus privilegios de conducir, el empleado le dice que primero debe presentar un formulario específico que demuestre que tiene cobertura de responsabilidad adecuada en adelante. ¿Cómo se llama este requisito?","options":["Una declaración de envase abierto que demuestre que no guarda alcohol en el área de pasajeros","Una renuncia al consentimiento implícito que reconozca futuras pruebas de aliento o sangre","Seguro de responsabilidad financiera SR-22","Un certificado de finalización de un curso de concientización sobre el alcohol"],"explanation":"After a DWI, Texas may require SR-22 financial responsibility insurance to prove coverage before driving privileges are reinstated. The alcohol-awareness course is tied to a minor's DUI penalty, not the insurance reinstatement requirement, and implied consent and open container are unrelated to proving financial responsibility."},"31":{"q":"Tiene 28 años y se ha tomado dos cervezas durante la cena en casa de un amigo. Se siente perfectamente bien y tiene un trayecto de 25 minutos a casa por carreteras tranquilas. ¿Cuál es la opción más segura?","options":["Conducir a casa, ya que dos bebidas siempre mantienen a un adulto por debajo del límite legal de 0,08%","Esperar unos 20 minutos, tomar algo de café y conducir una vez que se sienta despejado","Conducir ahora porque no está legalmente intoxicado a menos que su juicio esté visiblemente afectado","No conducir en absoluto; gestionar un servicio de transporte, un conductor sobrio o quedarse donde está"],"explanation":"The safest choice is always zero alcohol before driving, so arranging a sober ride or staying put is correct. Two beers will not reliably keep you under 0.08%, and only time (not coffee) lowers BAC, so the other options are dangerous mistakes."},"32":{"q":"Se reúne con amigos en un bar después del trabajo y toma varias copas durante dos horas. Siente los efectos del alcohol y sabe que no está en condiciones de conducir a casa de forma segura. ¿Cuál es la manera más segura de llegar a casa?","options":["Llamar a un servicio de transporte, entregar las llaves a un amigo que no haya bebido o simplemente quedarse donde está hasta estar sobrio","Tomar varias tazas de café fuerte y esperar unos 30 minutos antes de conducir a casa","Comer una comida abundante y darse una ducha fría para acelerar la sobriedad antes de conducir","Esperar una hora por cada copa sentado en su auto y luego conducir usted mismo a casa"],"explanation":"The safe, always-true choices are to use a ride service, designate a sober driver, or stay put until sober. Coffee, food, and a cold shower do NOT speed up sobering; only time lowers BAC, and the answer to alcohol is not to drive at all rather than wait it out in your car and then drive."},"33":{"q":"Marcus tiene 24 años y conduce su propio auto a casa después de una cena. Un oficial de policía lo detiene y una prueba de aliento muestra que su concentración de alcohol en sangre (BAC) es exactamente 0.08%. Con esta lectura, ¿qué se considera legalmente a Marcus según la ley de Texas?","options":["Está por debajo del límite legal porque el umbral de 0.08% solo se aplica a conductores comerciales","Está Conduciendo en Estado de Ebriedad (DWI), porque para adultos de 21 años o más un BAC igual o superior a 0.08% es el umbral legal","Solo es culpable si además muestra signos visibles de deterioro, ya que 0.08% por sí solo no es suficiente","Ha cometido un DUI bajo Tolerancia Cero, ya que cualquier cantidad detectable de alcohol es ilegal"],"explanation":"For adults 21 and older, driving at or above 0.08% BAC is Driving While Intoxicated (DWI), so Marcus's exact 0.08% reading meets the threshold. The 0.04% commercial limit and the Zero Tolerance rule for drivers under 21 do not apply to a 24-year-old in his personal vehicle, and no additional visible impairment is required at or above 0.08%."},"34":{"q":"Marcus tiene 19 años. Después de una fiesta de graduación lo detienen, y una prueba de aliento muestra un nivel de alcohol en sangre (BAC) de 0.03%. Él argumenta que no puede ser acusado porque su lectura está muy por debajo del límite adulto de 0.08%. Según la ley de Texas, ¿qué es cierto sobre su situación?","options":["Tiene razón; no aplica ningún cargo porque 0.03% está por debajo del límite de DWI de 0.08%.","Solo puede ser acusado si su BAC alcanza 0.04%, el límite para conductores comerciales.","Como es menor de 21 años, aplica la Tolerancia Cero, por lo que cualquier alcohol detectable lo convierte en un DUI por un menor.","Enfrenta un cargo de DWI como delito grave porque 0.03% cuenta como un BAC alto para un menor."],"explanation":"La Tolerancia Cero de Texas hace que cualquier alcohol detectable (BAC superior a 0.00) sea ilegal para conductores menores de 21 años, por lo que Marcus es acusado de DUI por un menor sin importar que esté por debajo de 0.08%. Los límites de 0.08% para adultos y 0.04% comercial no aplican a menores, y 0.03% no es una situación de delito grave por BAC alto."},"35":{"q":"Detienen a María en Austin por zigzaguear entre carriles. Es su primer arresto por conducir en estado de ebriedad (DWI), su nivel de alcohol en sangre (BAC) da 0,10% y su sobrino de 9 años va con el cinturón puesto en el asiento trasero. ¿Cómo cambia la presencia del niño la gravedad legal de su DWI?","options":["Nada cambia; el pasajero menor solo afecta el monto de la multa, que sube a un máximo de 2.000 dólares","Su licencia se suspende automáticamente por 180 días porque había un niño presente en el vehículo","Sigue siendo un delito menor estándar de primera infracción, pero además debe completar un curso de concienciación sobre el alcohol","Como había un pasajero menor de 15 años, la infracción pasa de ser un delito menor a un delito grave (felony)"],"explanation":"Under Texas law, a DWI committed with a child passenger younger than 15 in the vehicle is elevated to a felony, regardless of it being a first offense. Option B confuses this with the 180-day ALR suspension for refusing a chemical test, and the $2,000 fine in A is the standard first-offense misdemeanor penalty, not the felony enhancement triggered by the child."},"36":{"q":"Lo arrestan legalmente por conducir bajo los efectos del alcohol (DWI) en Austin. El oficial le pide que se someta a una prueba de aliento, pero usted se niega y dice que solo aceptará dar una muestra de sangre. Según la ley de consentimiento implícito de Texas, ¿qué es cierto sobre su situación?","options":["Al conducir en Texas, usted ha dado su consentimiento implícito a una prueba de aliento O de sangre, por lo que el tipo de prueba no se limita a una sola; negarse a la prueba solicitada puede provocar una suspensión automática de la licencia.","El consentimiento implícito solo cubre la prueba de aliento, así que tiene derecho a exigir una prueba de sangre en su lugar sin penalización.","El consentimiento implícito solo se aplica a la prueba de sangre, así que negarse a la prueba de aliento no tiene ninguna consecuencia.","Como usted ofreció una alternativa, el hígado procesará el alcohol en una hora y no se necesita ninguna prueba."],"explanation":"Texas implied consent covers a breath OR blood test, not just one type, so you can't limit it to your preferred test; refusing the lawfully requested test triggers an automatic 180-day suspension under ALR. Options B and C wrongly restrict implied consent to a single test type, and D confuses the unrelated fact that the liver processes about one drink per hour."},"37":{"q":"Después de un par de cervezas en la cena, un conductor nota que las luces de los autos que vienen de frente ahora se ven borrosas y le cuesta ver los bordes de su carril y a un peatón que baja de la acera. ¿Qué efecto del alcohol explica mejor lo que está experimentando al volante?","options":["El alcohol actúa como un estimulante que agudiza la concentración, así que la borrosidad debe deberse a sus faros, no al alcohol","El alcohol es un depresor que reduce la visión, dificultando ver los objetos con claridad y estrechando lo que puede detectar","El alcohol solo afecta la visión cuando el conductor supera el límite legal del 0,08%, así que por debajo de eso su vista no se ve afectada","El alcohol acelera el tiempo de reacción, lo que solo hace que los objetos cercanos se vean borrosos a altas velocidades"],"explanation":"Alcohol is a depressant that reduces vision among the abilities it impairs, so blurry headlights and trouble seeing the lane and pedestrian are direct effects of the alcohol. Option C is wrong because alcohol can impair vision and driving even below 0.08%, and A and D misstate alcohol as a stimulant or claim it speeds reaction time, when it actually slows reactions."},"38":{"q":"Después de tres cervezas en casa de un amigo, Marcus se pone al volante. Durante el camino a casa nota que se desvía constantemente de su carril y que sus manos se sienten torpes y lentas cuando intenta hacer pequeñas correcciones de dirección. ¿Qué efecto del alcohol en su cuerpo explica mejor por qué su manejo del volante se ha vuelto descuidado e impreciso?","options":["El alcohol acelera su tiempo de reacción, por lo que está corrigiendo el volante en exceso","El alcohol actúa como un estimulante que hace que sus músculos se tensen y se vuelvan bruscos","El alcohol reduce su coordinación, dificultando un manejo del volante suave y preciso","El alcohol ya se ha eliminado porque tres cervezas están por debajo del límite legal"],"explanation":"Alcohol is a depressant that reduces coordination, which is exactly why smooth, precise steering becomes difficult. Option A is wrong because alcohol slows reaction time rather than speeding it up, and option B is wrong because alcohol is a depressant, not a stimulant."},"39":{"q":"Un oficial detiene a Marcus por zigzaguear entre carriles tarde en la noche. Tras las pruebas de sobriedad en campo, el oficial arresta legalmente a Marcus por conducir en estado de ebriedad (DWI) y luego le pide una muestra de aliento. Según la ley de consentimiento implícito de Texas, ¿qué hizo legal que el oficial exigiera esta prueba de aliento?","options":["El nivel de alcohol en la sangre de Marcus ya se había medido en 0,08% o más antes de cualquier arresto","Marcus firmó una renuncia de consentimiento implícito cuando renovó su licencia de conducir","El oficial vio a Marcus zigzaguear entre carriles, lo cual por sí solo basta para obligar a una prueba","Marcus fue arrestado legalmente por conducir en estado de ebriedad (DWI), lo que activa el consentimiento implícito a una prueba de aliento o de sangre"],"explanation":"In Texas, the lawful trigger for implied consent testing is being lawfully arrested for DWI, so option D is correct. Observing bad driving (C) may justify the stop or arrest but does not by itself compel a test, and there is no separately signed waiver at license renewal (B)."}},"learn-alcohol-and-penalties":{"0":{"q":"En Texas, ¿cuál es el límite de alcohol en sangre (BAC) para DWI de un conductor adulto de 21 años o más?","options":["0.08%","0.04%","0.10%","0.05%"],"explanation":"In Texas, an adult age 21 or older is legally intoxicated (DWI) at a BAC of 0.08% or higher."},"1":{"q":"En Texas, ¿qué delito es conducir con una concentración de alcohol en sangre de 0.08% o más?","options":["Exceso de velocidad","Conducir en Estado de Ebriedad (DWI)","Conducción imprudente","Infracción por envase abierto"],"explanation":"Driving at or above 0.08% BAC is the offense called Driving While Intoxicated (DWI)."},"2":{"q":"¿Puede acusarse a un conductor de DWI si su BAC es inferior al 0,08%?","options":["No, nunca por debajo del 0,08%","Solo a conductores comerciales","Sí, si está afectado por alcohol o drogas","Solo si rechaza una prueba"],"explanation":"A driver can still be charged with DWI below 0.08% BAC if impaired by alcohol or drugs."},"3":{"q":"¿Cuál es el límite de alcohol en sangre (BAC) para un conductor comercial en Texas?","options":["0.08%","0.10%","0.02%","0.04%"],"explanation":"A commercial driver's BAC limit is 0.04%, lower than the standard adult limit of 0.08%."},"4":{"q":"En Texas, ¿cuál es el límite legal de alcohol en sangre para un conductor menor de 21 años?","options":["Cualquier cantidad superior a 0.00 es ilegal","0.08 BAC","0.04 BAC","0.05 BAC"],"explanation":"Texas uses Zero Tolerance, so any detectable alcohol (a BAC above 0.00) is illegal for a driver under 21."},"5":{"q":"Que comete un menor al conducir con cualquier cantidad detectable de alcohol?","options":["Nada ilegal","DUI (conducir bajo los efectos del alcohol) por un menor","Una infraccion de estacionamiento","Un DWI comercial"],"explanation":"Under Texas Zero Tolerance, any detectable alcohol means a minor commits DUI of alcohol by a minor."},"6":{"q":"En Texas, ¿qué significa DUI cometido por un menor?","options":["Conducir de forma insegura en interiores","Conducir bajo seguro","Conducir bajo la influencia (Driving Under the Influence)","Conducir con intención"],"explanation":"DUI stands for Driving Under the Influence, the offense used for minors, distinct from the adult DWI."},"7":{"q":"En Texas, ¿la ley de Tolerancia Cero se aplica a conductores menores de qué edad?","options":["16 años de edad","18 años de edad","25 años de edad","21 años de edad"],"explanation":"Texas's Zero Tolerance law makes any detectable alcohol illegal for drivers under 21 years of age."},"8":{"q":"¿Qué tipo de sustancia es el alcohol?","options":["Un depresor","Un estimulante","Un analgésico","Una vitamina"],"explanation":"Alcohol is a depressant that slows your reaction time and impairs your judgment."},"9":{"q":"¿Cómo afecta el alcohol al tiempo de reacción de un conductor?","options":["Lo acelera","Lo ralentiza","No tiene efecto","Lo mejora"],"explanation":"Alcohol is a depressant that slows your reaction time."},"10":{"q":"¿Qué afecta el alcohol cuando conduce?","options":["Su nivel de combustible","La presión de sus llantas","Su juicio","Sus faros"],"explanation":"Alcohol impairs judgment, which is the first driving ability affected."},"11":{"q":"¿Qué le hace el alcohol a la coordinación de un conductor?","options":["Mejora la coordinación","No tiene efecto en la coordinación","Solo afecta la coordinación de noche","Reduce la coordinación"],"explanation":"Alcohol is a depressant that reduces a driver's coordination."},"12":{"q":"¿Cómo afecta el alcohol a la visión de un conductor?","options":["Reduce la visión","Mejora la visión","No tiene efecto sobre la visión","Agudiza la visión nocturna"],"explanation":"Alcohol reduces vision, making it harder to see clearly while driving."},"13":{"q":"¿Cuál habilidad de conducción afecta primero el alcohol?","options":["La visión","El juicio","La audición","El agarre del volante"],"explanation":"Alcohol affects judgment before other driving abilities."},"14":{"q":"¿Qué es lo único que reduce la concentración de alcohol en la sangre (BAC)?","options":["Tomar café","Darse una ducha fría","El paso del tiempo","Comer una comida abundante"],"explanation":"Only the passage of time lowers BAC; coffee, food, and showers do not speed it up."},"15":{"q":"¿Qué es lo único que reduce el nivel de alcohol en la sangre?","options":["Tomar café","Comer una comida abundante","Tomar una ducha fría","Esperar y dejar que pase el tiempo"],"explanation":"Only time lowers your BAC; coffee, food, and showers do not speed up sobering."},"16":{"q":"¿Qué es lo único que reduce el nivel de alcohol en la sangre (BAC)?","options":["El tiempo","Comer alimentos","Tomar café","Darse una ducha fría"],"explanation":"Only time lowers BAC; food, coffee, and showers do not speed up sobering."},"17":{"q":"¿Qué es lo único que reduce la concentración de alcohol en la sangre (BAC) de una persona?","options":["Tomar café","El tiempo","Una ducha fría","El aire fresco"],"explanation":"Only time lowers BAC; coffee, a cold shower, and fresh air do not speed up sobering."},"18":{"q":"¿Qué es lo único que reduce su nivel de alcohol en la sangre?","options":["Aire fresco","Beber café","El tiempo","Una ducha fría"],"explanation":"Only time lowers BAC; fresh air, coffee, and a cold shower do not speed up sobering."},"19":{"q":"¿Aproximadamente cuánto alcohol puede procesar su hígado en una hora?","options":["Unas cuatro bebidas","Unas tres bebidas","Unas dos bebidas","Una bebida aproximadamente"],"explanation":"The liver processes about one standard drink per hour, and nothing can speed it up."},"20":{"q":"Puede algo hacer que el higado procese el alcohol mas rapido de lo normal?","options":["No, nada lo acelera","Si, tomar cafe","Si, una ducha fria","Si, comer alimentos"],"explanation":"Nothing can make the liver process alcohol faster than its normal rate."},"21":{"q":"¿Qué sucede cuando combina drogas con alcohol?","options":["Anula el alcohol","Multiplica el deterioro","Acelera la sobriedad","No tiene efecto"],"explanation":"Mixing drugs (illegal, prescription, or over-the-counter) with alcohol multiplies impairment."},"22":{"q":"¿Pueden los medicamentos con receta o de venta libre aumentar la afectación si se toman con alcohol?","options":["No, solo las drogas ilegales","No, anulan el alcohol","Sí, pueden multiplicar la afectación","No, no tienen efecto"],"explanation":"Even prescription and over-the-counter drugs can multiply impairment when combined with alcohol."},"23":{"q":"En Texas, ¿a qué das tu consentimiento al conducir si eres arrestado legalmente por DWI?","options":["A un examen de la vista","A un examen de manejo","A un examen de audición","A una prueba de aliento o de sangre"],"explanation":"By driving in Texas you give implied consent to a breath or blood test if lawfully arrested for DWI."},"24":{"q":"En Texas, el consentimiento implícito se aplica a qué prueba?","options":["Una prueba de aliento o de sangre","Una prueba de visión","Una prueba de audición","Una prueba escrita"],"explanation":"By driving in Texas, you give implied consent to a breath or blood test if lawfully arrested for DWI."},"25":{"q":"¿Cuándo se aplica el consentimiento implícito a la prueba en Texas?","options":["Cuando se detiene a un conductor por exceso de velocidad","Cuando un conductor es arrestado legalmente por conducir ebrio (DWI)","Cuando un conductor se estaciona ilegalmente","Cuando un conductor renueva su licencia"],"explanation":"By driving in Texas you give implied consent to a breath or blood test if you are lawfully arrested for DWI."},"26":{"q":"¿Negarse a una prueba de aliento o sangre causa una suspensión automática de la licencia de cuántos días en una primera negativa?","options":["30 días","90 días","180 días","365 días"],"explanation":"A first refusal of the breath or blood test results in an automatic 180-day license suspension."},"27":{"q":"¿Bajo qué ley se impone la suspensión automática de licencia por negarse a una prueba?","options":["Ley de Derogación del Consentimiento Implícito","Ley de Envase Abierto","Ley de Tolerancia Cero","Revocación Administrativa de Licencia (ALR)"],"explanation":"Refusing a breath or blood test triggers an automatic license suspension under Administrative License Revocation (ALR)."},"28":{"q":"¿La suspensión de licencia ALR por negarse a una prueba es independiente de las penas por condena por DWI?","options":["Sí, es independiente","No, las reemplaza","No, solo si hay condena","Sí, pero solo para menores"],"explanation":"The ALR suspension for refusing a test is separate from any DWI conviction penalties."},"29":{"q":"¿Cuál es la multa máxima por un primer DWI en Texas?","options":["Hasta $500","Hasta $2,000","Hasta $5,000","Hasta $10,000"],"explanation":"A first DWI in Texas carries a fine of up to $2,000."},"30":{"q":"¿Cuánto tiempo de cárcel puede conllevar un primer DWI en Texas?","options":["De 1 a 30 días","De 2 a 90 días","De 3 días a 180 días","De 5 días a 365 días"],"explanation":"A first DWI in Texas carries jail time of 3 days to 180 days."},"31":{"q":"¿Cuál es el tiempo mínimo de cárcel por un primer DWI en Texas?","options":["30 días","10 días","1 día","3 días"],"explanation":"A first DWI in Texas carries a minimum jail time of 3 days."},"32":{"q":"¿Cuál es la pena máxima de cárcel por un primer DWI en Texas?","options":["180 días","30 días","1 año","10 días"],"explanation":"A first DWI in Texas carries a maximum jail term of 180 days."},"33":{"q":"En Texas, ¿por cuánto tiempo pueden suspender su licencia por un primer DWI (conducir ebrio)?","options":["Hasta 30 días","Hasta 1 año","Hasta 5 años","Nunca se suspende"],"explanation":"A first DWI in Texas carries a license suspension of up to 1 year."},"34":{"q":"En Texas, ¿qué pasa con las sanciones por DWI en caso de reincidencia?","options":["Se eliminan","Se mantienen iguales","Aumentan","Se vuelven opcionales"],"explanation":"In Texas, penalties increase for repeat DWI offenses."},"35":{"q":"En Texas, ¿qué nivel de BAC (alcohol en sangre) es lo suficientemente alto para aumentar las sanciones por DWI?","options":["0.04% o más","0.06% o más","0.08% o más","0.15% o más"],"explanation":"A high BAC of 0.15% or above increases the penalties for DWI."},"36":{"q":"En Texas, ¿qué nivel alto de BAC aumenta las sanciones por DWI?","options":["0.15%","0.08%","0.04%","0.02%"],"explanation":"A BAC of 0.15% or higher increases the penalties for a Texas DWI."},"37":{"q":"En Texas, ¿qué hace que aumenten las sanciones por conducir ebrio en una primera infracción?","options":["Conducir despacio","Llevar a un niño como pasajero","Usar el cinturón de seguridad","Conducir de noche"],"explanation":"Penalties increase when there is a child passenger in the vehicle."},"38":{"q":"En Texas, ¿qué es conducir intoxicado (DWI) con un menor de 15 años en el vehículo?","options":["Solo una advertencia","Una multa de estacionamiento","Un delito grave (felonía)","No es una infracción"],"explanation":"In Texas, driving while intoxicated with a child under 15 in the vehicle is a felony."},"39":{"q":"En Texas, conducir en estado de ebriedad (DWI) se convierte en delito grave si hay un pasajero menor de qué edad?","options":["Menor de 8 años","Menor de 10 años","Menor de 12 años","Menor de 15 años"],"explanation":"In Texas, DWI with a child passenger under 15 years old is a felony."},"40":{"q":"En Texas, ¿tener un recipiente abierto de alcohol en el área de pasajeros es un delito separado?","options":["Sí, es un delito separado","No, siempre está permitido","Solo para los pasajeros, nunca el conductor","Solo en las autopistas"],"explanation":"In Texas, having an open container of alcohol in the passenger area is a separate offense."},"41":{"q":"¿Dónde se aplica la infracción de recipiente abierto de alcohol en un vehículo?","options":["Solo en el maletero","En el área de pasajeros","En el techo","Debajo del capó"],"explanation":"The open container offense applies to alcohol in the passenger area of the vehicle."},"42":{"q":"¿Cuál es la multa máxima por el primer DUI (alcohol) de un menor en Texas?","options":["Hasta $100","Hasta $250","Hasta $500","Hasta $2,000"],"explanation":"A minor's first DUI for alcohol carries a fine of up to $500."},"43":{"q":"¿Qué incluye el primer DUI por alcohol de un menor?","options":["Ninguna sanción en absoluto","Solo una carta de advertencia","Una clase de conducción gratis","La suspensión de la licencia"],"explanation":"A minor's first DUI for alcohol includes a license suspension."},"44":{"q":"¿Cuál es una sanción por el primer DUI (alcohol) de un menor en Texas?","options":["Servicio comunitario","Un curso de manejo gratis","Un descuento en la nueva licencia","Eliminar puntos extra de la licencia"],"explanation":"A minor's first alcohol DUI in Texas includes community service."},"45":{"q":"En Texas, ¿qué debe completar un menor después de un primer DUI por alcohol?","options":["Un curso de manejo defensivo","Un curso de concientización sobre el alcohol","Un examen de la vista","Un curso de primeros auxilios"],"explanation":"A minor's first alcohol DUI requires completing an alcohol-awareness course."},"46":{"q":"¿Qué agregan las condenas de tránsito a su registro de conducir?","options":["Clases de manejo gratis","Años extra de licencia","Puntos","Recompensas en efectivo"],"explanation":"Traffic convictions add points to your driving record."},"47":{"q":"¿A qué pueden llevar demasiadas condenas de tránsito?","options":["Tarifas de seguro más bajas","Un curso de manejo gratuito","Quitar puntos adicionales de la licencia","Recargos (surcharges)"],"explanation":"Too many convictions can lead to surcharges and even license suspension."},"48":{"q":"¿A qué pueden llevar demasiadas condenas de tránsito?","options":["Suspensión de la licencia","Una renovación gratuita de la licencia","Más privilegios de conducir","Costos de seguro más bajos"],"explanation":"Too many convictions can add surcharges and lead to license suspension."},"49":{"q":"En Texas, ¿qué pasa con una condena por DWI con el tiempo?","options":["Se borra después de un mes","Permanece en su historial","Desaparece cuando paga la multa","Se elimina después de un viaje seguro"],"explanation":"A DWI conviction stays on your record and raises your insurance costs."},"50":{"q":"¿Cómo afecta una condena por conducir intoxicado (DWI) el costo de su seguro de auto?","options":["Lo reduce","No tiene efecto","Lo aumenta considerablemente","Cancela todas las tarifas"],"explanation":"A DWI conviction stays on your record and sharply raises insurance costs."},"51":{"q":"¿Qué seguro puede requerirse para restablecer sus privilegios de conducir en Texas?","options":["Seguro de viaje","Seguro para mascotas","Seguro de salud","Seguro de responsabilidad financiera SR-22"],"explanation":"SR-22 financial responsibility insurance may be required to reinstate your driving privileges."},"52":{"q":"¿Qué es el SR-22?","options":["Una forma de seguro de responsabilidad financiera","Un tipo de licencia de conducir","Una multa de tránsito","Una prueba de alcohol en sangre"],"explanation":"SR-22 is a form of financial responsibility insurance that may be required to reinstate driving privileges."},"53":{"q":"¿Cuál es la cantidad más segura de alcohol para beber antes de conducir?","options":["Una bebida","Cero alcohol","Dos bebidas","Una cerveza"],"explanation":"The safest choice is zero alcohol before driving."},"54":{"q":"¿Cómo puede evitar beber y conducir?","options":["Beber café primero","Conducir despacio","Designar un conductor sobrio","Abrir las ventanas"],"explanation":"Choosing a sober driver lets you avoid driving after drinking."},"55":{"q":"¿Qué puede usar para evitar conducir después de beber?","options":["Una taza de café","Una ducha fría","Aire fresco","Un servicio de transporte"],"explanation":"Using a ride service lets you avoid drinking and driving."},"56":{"q":"¿Cuál es una manera de evitar conducir después de beber?","options":["Quédese donde está en lugar de conducir","Conduzca muy despacio","Beba un poco de agua primero","Abra las ventanas del auto"],"explanation":"Staying put instead of driving keeps you from drinking and driving."},"57":{"q":"¿Qué nivel de alcohol en la sangre es ilegal para un conductor menor de 21 años en Texas?","options":["0,08% o más","Cualquier cantidad superior a 0,00","0,04% o más","0,15% o más"],"explanation":"Texas has zero tolerance, so any detectable alcohol above 0.00 is illegal for a minor."},"58":{"q":"El alcohol es un depresor, entonces, ¿qué le hace al cuerpo?","options":["Acelera el tiempo de reacción","Mejora la coordinación","Ralentiza las funciones del cuerpo","Agudiza la visión"],"explanation":"As a depressant, alcohol slows down the body's functions instead of stimulating them."},"59":{"q":"En Texas, ¿cuál es la multa máxima por una primera condena por DWI (conducir en estado de ebriedad)?","options":["$200","$500","$1,000","$2,000"],"explanation":"A first DWI conviction in Texas carries a fine of up to $2,000."}}},"hi":{"road-signs":{"0":{"q":"शाम के धुंधलके में, आप एक चौराहे के पास पहुँचते हैं जहाँ आपके सामने वाला चिह्न बुरी तरह फीका पड़ चुका है और आप उस पर लिखा कोई भी अक्षर नहीं पढ़ पा रहे हैं। फिर भी आप साफ़ देख सकते हैं कि उस चिह्न की आठ भुजाएँ हैं। इस चौराहे पर आपको क्या करना चाहिए?","options":["पूरी तरह रुक जाएँ, क्योंकि आठ भुजाओं वाला (अष्टभुज) चिह्न हमेशा STOP (रुकें) का अर्थ रखता है।","गति धीमी करें और रास्ता दें, केवल तभी रुकें जब अन्य यातायात मौजूद हो।","गति धीमी करें और सावधानी से आगे बढ़ें, क्योंकि यह आकृति केवल आगे किसी ख़तरे की चेतावनी देती है।","इसे स्कूल क्रॉसिंग मानें और सड़क पर आते बच्चों के लिए तैयार रहें।"],"explanation":"The octagon is the only eight-sided sign and always means STOP, so the shape alone tells you to come to a full stop even when the lettering is unreadable. Yielding is signaled by an inverted triangle, not an octagon, which makes that option the trap."},"1":{"q":"आप एक ऑन-रैंप से हाईवे पर मिल रहे हैं और अपने सामने एक उल्टे (शीर्ष नीचे की ओर) त्रिकोण के आकार का लाल-और-सफेद चिह्न देखते हैं। यह चिह्न आपसे क्या करने की मांग करता है?","options":["पूरी तरह रुक जाएं और तब तक रुके रहें जब तक हाईवे दोनों दिशाओं में खाली न हो जाए","हाईवे पर चल रहे यातायात को रास्ता दें, और सुरक्षित रूप से मिलने के लिए आवश्यक होने पर ही धीमे हों या रुकें","निर्धारित अधिकतम गति से चलते रहें क्योंकि मिलते समय रास्ते का अधिकार आपके पास है","इसे आगे किसी खतरे की चेतावनी मानें और रास्ता दिए बिना सावधानी से चलते रहें"],"explanation":"An inverted triangle is a YIELD sign: you must give the right of way to traffic already on the highway and slow or stop only if needed to merge safely. A full stop every time (A) describes an octagonal STOP sign, and a diamond-shaped warning sign (D) does not require yielding the right of way."},"2":{"q":"आप दो-लेन वाले ग्रामीण राजमार्ग पर गाड़ी चला रहे हैं और आगे चल रहे धीमे ट्रैक्टर को ओवरटेक करना चाहते हैं। दूसरी लेन में निकलने से ठीक पहले, आपको सड़क के बाईं ओर वाले किनारे पर एक तरफ लेटे हुए त्रिकोण (क्षैतिज नुकीले सिरे वाला) के आकार का एक संकेत दिखाई देता है। यह संकेत आपको क्या बता रहा है?","options":["अपनी लेन में वापस आने से पहले सामने से आ रहे यातायात को रास्ता दें","आगे स्कूल क्षेत्र या स्कूल क्रॉसिंग है, गति कम करें","आप एक नो पासिंग ज़ोन में प्रवेश कर रहे हैं और यहाँ ट्रैक्टर को ओवरटेक नहीं करना चाहिए","आगे कोई खतरा या स्थिति है, गति धीमी करें और सावधानी से आगे बढ़ें"],"explanation":"A pennant (a horizontal triangle) posted on the LEFT side of the road marks a No Passing Zone, so you must not pass the tractor. A yield is an inverted (upside-down) triangle, and a diamond is the warning shape, so those options confuse other sign shapes with the pennant."},"3":{"q":"आप शाम के धुंधलके में एक अनजान दो-लेन वाले राजमार्ग पर गाड़ी चला रहे हैं। आगे दाईं ओर के किनारे पर आपको एक पीला, हीरे के आकार का चिह्न दिखता है, लेकिन आप अभी इतनी दूर हैं कि उस पर लिखे शब्द या चिह्न नहीं पढ़ सकते। केवल उसके आकार के आधार पर, आपको तुरंत क्या समझ लेना चाहिए?","options":["यह एक नियामक चिह्न है जो आपको किसी ऐसे कानून के बारे में बताता है जिसका पालन आपको करना है, जैसे गति सीमा","यह आगे एक स्कूल क्षेत्र या स्कूल क्रॉसिंग को दर्शाता है","यह एक मार्गदर्शक चिह्न है जो अगले कस्बे की दिशा या दूरी बताता है","यह एक चेतावनी चिह्न है जो आपको आगे किसी खतरे या सड़क की स्थिति में बदलाव के बारे में सचेत करता है"],"explanation":"A diamond shape always means a warning sign, telling you a hazard or condition lies ahead. Regulatory laws use vertical rectangles (A) and guide/direction information uses horizontal rectangles (C), while school zones use a pentagon (B)."},"4":{"q":"एक अनजान आवासीय क्षेत्र में गाड़ी चलाते समय, आपको एक पीला-हरा, पाँच भुजाओं वाला चिह्न दिखता है जिसका शीर्ष ऊपर की ओर है। केवल इसके आकार के आधार पर, यह चिह्न आपको किस बारे में चेतावनी दे रहा है?","options":["आप एक स्कूल क्षेत्र या स्कूल क्रॉसिंग के पास पहुँच रहे हैं","आगे एक रेलवे क्रॉसिंग है","आप एक ओवरटेकिंग-निषिद्ध क्षेत्र में प्रवेश कर रहे हैं","आगे कोई सामान्य खतरा या स्थिति है"],"explanation":"A pentagon (5-sided, point up) shape always means a school zone or school crossing. A round sign warns of a railroad crossing ahead, so option B confuses two different sign shapes."},"5":{"q":"आप एक ग्रामीण दो-लेन राजमार्ग पर गाड़ी चला रहे हैं और दाहिने किनारे पर एक गोल, पीले रंग का चिह्न देखते हैं जिस पर काला 'X' और 'RR' अक्षर हैं, जो किसी भी पटरी के दिखाई देने से काफी पहले लगाया गया है। यह चिह्न आपको क्या बता रहा है?","options":["आप पटरियों तक पहुँच गए हैं और आपको अपना वाहन उन्हीं पर रोकना होगा","आगे एक रेलवे क्रॉसिंग है, इसलिए गति धीमी करने और ट्रेनों के लिए सतर्क रहने के लिए तैयार रहें","आप एक स्कूल क्षेत्र में प्रवेश कर रहे हैं और बच्चों के लिए अपनी गति कम करनी होगी","यह एक नो-पासिंग क्षेत्र है और आप यहाँ अन्य वाहनों को ओवरटेक नहीं कर सकते"],"explanation":"A round (circular) sign is the advance warning that a railroad crossing lies ahead, so you should slow down and watch for trains. The crossing itself is marked by the X-shaped Crossbuck (not this round sign), and the pentagon shape, not the circle, signals a school zone."},"6":{"q":"आप एक ग्रामीण सड़क पर गाड़ी चला रहे हैं और रेलवे पटरियों के ठीक पास पहुँचते हैं, जहाँ आपको 'RAILROAD CROSSING' शब्दों के साथ एक सफेद X-आकार का चिह्न दिखता है। इस क्रॉसिंग पर कोई स्टॉप चिह्न, कोई फाटक और कोई चमकती बत्तियाँ नहीं हैं। आपको इस चिह्न को कैसे मानना चाहिए?","options":["हर बार पूरी तरह रुकें, क्योंकि X-आकार का क्रॉसबक कानूनी रूप से स्टॉप चिह्न की तरह काम करता है","जब तक ट्रेन दिखाई न दे, इसे अनदेखा करें, क्योंकि यह क्रॉसबक केवल पटरियों से पहले लगाई गई एक पूर्व चेतावनी है","इसे यील्ड (रास्ता दें) चिह्न की तरह मानें: गति धीमी करें, दोनों ओर देखें और केवल तभी रुकें जब कोई ट्रेन आ रही हो","अपनी सामान्य गति से आगे बढ़ें, क्योंकि पहले आया गोल पूर्व-चेतावनी चिह्न आपको ज़रूरी सब कुछ पहले ही बता चुका है"],"explanation":"X-आकार का क्रॉसबक चिह्न रेलवे क्रॉसिंग को ही चिह्नित करता है और इसे यील्ड चिह्न की तरह माना जाना चाहिए, यानी गति धीमी करें, ट्रेनों की जाँच करें और केवल तभी रुकें जब कोई ट्रेन आ रही हो। यह स्टॉप चिह्न नहीं है (A), और गोल पूर्व-चेतावनी चिह्न (B, D) के विपरीत, क्रॉसबक पटरियों से पहले नहीं बल्कि पटरियों के ठीक पास स्थित होता है।"},"7":{"q":"आप एक अनजान सड़क पर गाड़ी चला रहे हैं और आपको यह जानना है कि कानूनी रूप से आप कितनी तेज़ गति से चल सकते हैं। आगे आपको एक ऊर्ध्वाधर आयत (चौड़ाई से अधिक ऊँचा) के आकार का संकेत दिखाई देता है। केवल इसके आकार के आधार पर, यह सबसे अधिक संभावना से किस प्रकार का संकेत है?","options":["एक मार्गदर्शक या सूचना संकेत जो अगले शहर की दिशाएँ और दूरियाँ बताता है","एक चेतावनी संकेत जो आपको आगे किसी खतरे या बदलती स्थिति के बारे में सचेत करता है","एक निर्माण या कार्य क्षेत्र संकेत जो आगे सड़क कर्मियों की चेतावनी देता है","एक नियामक संकेत जो किसी ऐसे कानून को बताता है जिसका आपको पालन करना होगा, जैसे गति सीमा"],"explanation":"A vertical rectangle is a regulatory sign that tells you a law you must obey, such as the posted speed limit. A horizontal rectangle (option A) is the guide/information shape, and a diamond (option B) is the warning shape, so neither matches a vertical rectangle."},"8":{"q":"आप अपने गंतव्य शहर की ओर जाने वाले निकास (exit) की तलाश में राजमार्ग पर गाड़ी चला रहे हैं। आगे आपको एक चौड़ा संकेत दिखाई देता है जो क्षैतिज आयत (horizontal rectangle) के आकार का है (ऊंचाई से अधिक लंबा)। केवल इसके आकार के आधार पर, आपको इस संकेत से किस प्रकार की जानकारी मिलने की उम्मीद करनी चाहिए?","options":["स्थानों की दिशाएँ और दूरियाँ, जैसे कौन सा निकास लेना है और आपका शहर कितनी दूर है","एक यातायात कानून जिसका आपको पालन करना चाहिए, जैसे निर्धारित गति सीमा","आगे किसी खतरे या स्थिति के बारे में चेतावनी, जैसे तीखा मोड़","आगे बढ़ने से पहले पूरी तरह रुकने का आदेश"],"explanation":"A horizontal rectangle is a guide/information sign, giving directions and distances. A vertical rectangle (not horizontal) is the regulatory shape for laws like speed limits, warnings use a diamond, and only an octagon means stop."},"9":{"q":"रात में गाड़ी चलाते समय आप एक सड़क पर मुड़ते हैं और आपकी हेडलाइट सीधे आपके सामने एक लाल चिह्न को रोशन करती है जिस पर सफेद अक्षरों में WRONG WAY (गलत दिशा) लिखा है। यह चिह्न आपको क्या करने को कहता है?","options":["गति धीमी करें क्योंकि आगे कोई खतरा या असामान्य स्थिति है","रुकें; आप आने वाले यातायात के सामने जा रहे हैं और आपको इस दिशा में आगे नहीं बढ़ना चाहिए","आगे बढ़ें, लेकिन अगले निकास पर ईंधन और भोजन जैसी चालक सेवाओं को रास्ता दें","सावधानी से आगे बढ़ें क्योंकि आप निर्माण या कार्य क्षेत्र में प्रवेश कर रहे हैं"],"explanation":"WRONG WAY is a red sign, and red means stop, yield, or prohibited, so you must not continue in that direction because you are heading into oncoming traffic. Option A describes a yellow warning sign and option D describes an orange construction sign, neither of which is red."},"10":{"q":"आप शाम के धुंधलके में एक अनजान दो-लेन वाले राजमार्ग पर गाड़ी चला रहे हैं, तभी आपकी हेडलाइट्स की रोशनी एक पीले हीरे के आकार के संकेत पर पड़ती है जिसमें दाईं ओर मुड़ता हुआ एक घुमावदार तीर है। इसके रंग के आधार पर, यह संकेत आपको क्या बता रहा है?","options":["एक कानून जिसका आपको पालन करना चाहिए: आगे तीव्र दाहिना मोड़ अनिवार्य है","दाईं ओर मोड़ के पीछे एक निर्माण दल काम कर रहा है","एक सामान्य चेतावनी: आगे सड़क में एक मोड़ है, इसलिए गति धीमी करें","एक मार्गदर्शक संकेत जो आपको दाईं ओर एक गंतव्य की ओर निर्देशित करता है"],"explanation":"Yellow signs are general warning signs alerting you to a hazard or condition ahead, such as a curve, so you should reduce speed. The construction trap is wrong because work-zone warnings are orange, and the regulatory/guide traps are wrong because those use white/green, not yellow."},"11":{"q":"आप एक राजमार्ग पर गाड़ी चला रहे हैं, तभी आपको आगे नारंगी पृष्ठभूमि वाला एक हीरे के आकार का साइन दिखता है जिस पर लिखा है \"आगे सड़क कार्य\"। इस साइन का नारंगी रंग आपको क्या बताता है?","options":["यह उस मनोरंजन या प्राकृतिक दृश्य वाले क्षेत्र को चिह्नित करता है जिसके पास आप आ रहे हैं","यह आगे चालक सेवाओं जैसे ईंधन, भोजन या ठहरने की सुविधा दर्शाता है","यह सड़क पर मोड़ या ढलान के बारे में एक सामान्य चेतावनी है","आप एक निर्माण या कार्य क्षेत्र में प्रवेश कर रहे हैं"],"explanation":"Orange signs always indicate a construction or work zone, so you should slow down and be alert for workers and equipment. Brown is used for recreation/scenic areas and yellow is used for general warnings like curves or hills, which is why those options are wrong."},"12":{"q":"आप अपने गंतव्य शहर की ओर निकास खोजते हुए एक ग्रामीण राजमार्ग पर गाड़ी चला रहे हैं। आगे आपको एक बड़ा हरा साइन दिखता है जिस पर सफेद अक्षरों में \"Lubbock 45 / Amarillo 120\" और एक तीर लिखा है। यह साइन आपको क्या बताता है?","options":["यह एक मार्गदर्शक साइन है जो आपको उन शहरों की दिशाएँ और दूरियाँ बताता है","यह एक चेतावनी साइन है जो बताता है कि आगे उन शहरों में खतरनाक सड़क स्थितियाँ हैं","यह उन शहरों में उपलब्ध मोटर चालक सेवाओं, जैसे ईंधन और भोजन, को दर्शाता है","यह एक नियामक साइन है जो आपको उन शहरों में से किसी एक की ओर निकलने के लिए बाध्य करता है"],"explanation":"Green signs are guide signs that indicate permitted movements, directions, and distances, so this sign is simply telling you the way and mileage to each city. Warning information would be on a yellow sign, and motorist-services signs are blue, so those choices place the wrong color and meaning together."},"13":{"q":"आप एक अनजान राजमार्ग पर गाड़ी चला रहे हैं, ईंधन कम है और आपको भूख लगी है, तभी आप आगे एक नीले रंग की पृष्ठभूमि वाला साइन देखते हैं जिस पर पेट्रोल पंप और कांटा-छुरी के चिह्न हैं। यह साइन आपको क्या बता रहा है?","options":["यह एक गाइड साइन है जो अगले शहर की दिशा और दूरी दिखाता है","यह आपको पास की मोटर चालक सेवाओं जैसे पेट्रोल और भोजन की ओर निर्देशित कर रहा है","यह आपको सड़क के किनारे आगे किसी खतरे या स्थिति की चेतावनी दे रहा है","यह अगले निकास पर उपलब्ध मनोरंजन या दर्शनीय क्षेत्र को दर्शाता है"],"explanation":"Blue signs indicate motorist services such as gas, food, lodging, and hospital, so the blue background with the fuel and dining symbols points you to those services. Green signs (not blue) handle directions and distances, and brown signs mark recreational or scenic areas."},"14":{"q":"ग्रामीण राजमार्ग पर गाड़ी चलाते समय, आपको आगे भूरे रंग की पृष्ठभूमि और सफेद प्रतीकों वाला एक चौकोर चिह्न दिखता है, जो एक राज्य उद्यान और एक ऐतिहासिक युद्धक्षेत्र की ओर इशारा कर रहा है। यह चिह्न आपको क्या बता रहा है?","options":["आप पेट्रोल, भोजन और ठहरने जैसी चालक सेवाओं के पास पहुँच रहे हैं","आगे निर्माण या कार्य क्षेत्र है, इसलिए आपको गति धीमी करनी चाहिए","आप मनोरंजन, सांस्कृतिक या सुंदर दृश्य वाले क्षेत्रों जैसे उद्यानों और ऐतिहासिक स्थलों के पास पहुँच रहे हैं","आपको किसी नियामक कानून का पालन करना चाहिए, जैसे कि निर्धारित गति सीमा"],"explanation":"Brown signs indicate recreation, cultural, or scenic areas like parks and historic sites, so option C is correct. Blue signs (not brown) mark motorist services such as gas and food, which makes that the trap answer."},"15":{"q":"आप रात में एक अनजान राजमार्ग पर गाड़ी चला रहे हैं। आगे एक चिह्न है जो काले अक्षरों में \"45\" लिखा एक खड़ा सफेद आयत है। यह चिह्न आपको क्या बताता है?","options":["यह एक मार्गदर्शक चिह्न है जो अगले निकास तक की दूरी बताता है।","यह आगे 45 फीट पर किसी खतरे के बारे में एक चेतावनी चिह्न है।","यह एक निर्माण-क्षेत्र चिह्न है जो अस्थायी कार्य-क्षेत्र सीमा निर्धारित करता है।","यह एक नियामक चिह्न है जो अधिकतम कानूनी गति 45 मील प्रति घंटा निर्धारित करता है।"],"explanation":"White signs with black lettering are regulatory signs, and a white rectangle with a number sets the maximum legal speed (45 mph). Guide/distance signs are green and warning signs are yellow, so those options place real facts on the wrong color of sign."},"16":{"q":"एक अपरिचित पड़ोस से गाड़ी चलाते समय, आप एक हीरे के आकार के चिह्न के पास पहुंचते हैं जिसकी पृष्ठभूमि चमकीली फ्लोरोसेंट पीली-हरी है और उस पर दो चलते हुए बच्चे दिखाए गए हैं। यह चिह्न आपको किस बारे में चेतावनी दे रहा है?","options":["आगे पैदल यात्री, साइकिल चालक या स्कूल क्रॉसिंग","आगे निर्माण या कार्य क्षेत्र","आगे मनोरंजन या दर्शनीय क्षेत्र","आगे सामान्य मोड़ या ढलान का खतरा"],"explanation":"Fluorescent yellow-green is reserved for pedestrian, bicycle, and school warnings, so this sign means people may be crossing ahead. Orange signals construction zones and brown marks recreation/scenic areas, so those colors would not appear on this warning."},"17":{"q":"आप शाम के धुंधलके में एक अनजान चौराहे की ओर गाड़ी चला रहे हैं। आपके सामने लगा साइन इतना फीका पड़ गया है कि उस पर लिखा शब्द अब आप पढ़ नहीं सकते, लेकिन उसकी बनावट (आकृति) और रंग अब भी पहचान सकते हैं। यह जानने के लिए कि यह एक STOP साइन है और आपको पूरी तरह रुकना है, आपको किस आकार और रंग को देखना चाहिए?","options":["लाल, उल्टा (शीर्ष नीचे की ओर) त्रिकोण","लाल, आठ भुजाओं वाला अष्टभुज (ऑक्टागन)","पीला विषमकोण (डायमंड)","सफेद खड़ा आयत"],"explanation":"A STOP sign is the only red, eight-sided octagon, so its shape and color identify it even when the word is unreadable. A red inverted triangle is a YIELD sign (give the right of way, not necessarily a full stop), which is the trap."},"18":{"q":"आप एक व्यस्त राजमार्ग पर एक ऑन-रैंप से मर्ज कर रहे हैं। रैंप के अंत में आपको एक चिन्ह दिखाई देता है जो नीचे की ओर इशारा करते त्रिकोण के आकार का है, और लाल और सफेद रंग का है। यह चिन्ह आपसे क्या करने की अपेक्षा करता है?","options":["पूरी तरह रुक जाएं, क्योंकि कानूनी रूप से 'रुकें' का अर्थ रखने वाला यही एकमात्र चिन्ह आकार है","चौराहे को सभी दिशाओं से रुकने वाला मानें क्योंकि सिग्नल बंद है","गति धीमी करें और राजमार्ग के यातायात को रास्ता दें, केवल आवश्यकता होने पर ही रुकें","प्रवेश न करें, क्योंकि लाल और सफेद चिन्ह हमेशा यह दर्शाता है कि सड़क आपके लिए बंद है"],"explanation":"A red-and-white inverted (downward-pointing) triangle is a YIELD sign, which means give the right of way and slow or stop only if needed. The full-stop trap describes the red octagon STOP sign, and the 'do not enter' trap confuses YIELD with a prohibitory sign."},"19":{"q":"आप शहर के केंद्र में पार्किंग गैरेज ढूंढ रहे हैं और एक रैंप के पास पहुंचते हैं जहां आपको 'DO NOT ENTER' (प्रवेश निषेध) लिखा एक लाल चिह्न दिखाई देता है। यह लाल चिह्न आपसे क्या करने की मांग करता है?","options":["गति धीमी करें और सावधानी से आगे बढ़ें, क्योंकि लाल चिह्न केवल आगे किसी खतरे का संकेत देते हैं","रैंप पर किसी भी यातायात को रास्ता दें, फिर रास्ता साफ होने पर प्रवेश करें","पूरी तरह रुकें, फिर आने वाली गाड़ियों की जांच करने के बाद आगे बढ़ें","रैंप में प्रवेश न करें; यह प्रवेश आपकी यात्रा की दिशा के लिए बंद है"],"explanation":"DO NOT ENTER is a red sign meaning do not proceed, because that entrance is closed to your direction of travel. Yielding (B) or stopping then continuing (C) are wrong because the sign prohibits entry entirely rather than allowing you to proceed after caution."},"20":{"q":"आप एक सड़क पर मुड़ते हैं और एक आयताकार चिह्न देखते हैं जिसमें दाईं ओर इशारा करता एक क्षैतिज तीर और ONE WAY (एकतरफ़ा) शब्द लिखे हैं। आप इस सड़क पर बाईं ओर जाना चाहते थे। आपको क्या करना चाहिए?","options":["बाएं न मुड़ें; केवल दाईं ओर, तीर जिस दिशा में इशारा कर रहा है उसी दिशा में चलें","बाएं मुड़ें, लेकिन पहले सामने से आने वाले यातायात को रास्ता दें क्योंकि यह साझा सड़क है","बाएं तभी मुड़ें जब कोने पर DO NOT ENTER (प्रवेश निषेध) का चिह्न भी न लगा हो","इसे एक चेतावनी मानें और सावधानी से धीरे-धीरे बाईं ओर बढ़ें"],"explanation":"A ONE WAY sign means traffic may travel only in the direction the arrow points, so you must go right and cannot turn left onto that street. Turning left would send you against legal traffic flow, so the options allowing a left turn are wrong."},"21":{"q":"आप एक साफ, सूखे दिन में गाड़ी चला रहे हैं और एक सफेद आयताकार चिह्न के पास से गुजरते हैं जिस पर काले रंग में संख्या 65 लिखी है। हल्की बारिश शुरू हो जाती है और सड़क फिसलन भरी हो जाती है। बदलते इस मौसम में वह चिह्न आपकी गति के बारे में क्या बताता है?","options":["65 वह न्यूनतम गति है जिसे बारिश के बावजूद आपको बनाए रखना चाहिए","65 आदर्श परिस्थितियों के लिए अधिकतम कानूनी गति है, इसलिए गीली सड़क पर अब आपको इससे कम गति पर चलना चाहिए","सफेद आयत केवल एक मार्गदर्शक चिह्न है, इसलिए 65 केवल सलाह है और बाध्यकारी नहीं है","चूँकि बारिश हो रही है, रुकने के लिए अधिक जगह देने हेतु सीमा अपने आप बढ़ जाती है"],"explanation":"A SPEED LIMIT sign is a white rectangle with black numbers showing the maximum legal speed in ideal conditions, so in rain you must drive slower than the posted number. It is not a minimum, it is a regulatory (not guide) sign, and the limit never rises in bad weather."},"22":{"q":"आप एक चौराहे के पास पहुँच रहे हैं और यू-टर्न लेना चाहते हैं। सिग्नल के ऊपर एक सफेद चौकोर चिह्न लगा है जिसमें एक लाल घेरे के अंदर यू-टर्न का तीर दिखाया गया है और उसके आर-पार एक लाल तिरछी रेखा खिंची है। यह चिह्न आपसे क्या करने की माँग करता है?","options":["यह केवल चेतावनी देता है कि यहाँ यू-टर्न मुश्किल है, इसलिए सुरक्षित होने पर आप यू-टर्न ले सकते हैं","यह यू-टर्न की अनुमति देता है लेकिन केवल संरक्षित हरे तीर पर","यह इस चौराहे पर यू-टर्न पर रोक लगाता है, इसलिए आपको यू-टर्न नहीं लेना चाहिए","इसका मतलब है कि यू-टर्न पूरा करने से पहले सामने से आ रहे यातायात को रास्ता दें"],"explanation":"A red circle with a slash is a regulatory 'No' sign, and a U-turn arrow inside it means U-turns are prohibited here. The trap answers treat a mandatory prohibition as a mere warning or a conditional/yield situation, but the red circle and slash means the movement is flatly illegal."},"23":{"q":"आप रात में एक अनजान दो-लेन वाली सड़क पर गाड़ी चला रहे हैं। सड़क के बीच में, आपकी लेन और आपकी बाईं ओर की लेन के बीच खिंची हुई रेखा पीली है। यह रंग उस रेखा के दूसरी ओर वाली लेन के यातायात के बारे में आपको क्या बताता है?","options":["यह एकतरफा सड़क है, इसलिए विपरीत दिशा से कोई यातायात नहीं आता","पीली रेखा केवल सड़क के किनारे को दर्शाती है, किसी यातायात लेन को नहीं","उस लेन का यातायात आपकी ही दिशा में चल रहा है","उस लेन का यातायात विपरीत दिशा में, आपकी ओर चल रहा है"],"explanation":"पीली रेखाएँ विपरीत दिशाओं में चलने वाले यातायात को अलग करती हैं, इसलिए पीली केंद्र रेखा के पार वाली लेन में सामने से आने वाला यातायात होता है। सफेद रेखाएँ (पीली नहीं) एक ही दिशा के यातायात को अलग करती हैं और सड़क के किनारे को दर्शाती हैं, जिससे एक ही दिशा और किनारे वाले विकल्प गलत हो जाते हैं।"},"24":{"q":"आप एक चौड़े राजमार्ग पर गाड़ी चला रहे हैं और अपनी बाईं ओर अपनी लेन के समानांतर चलती एक लंबी ठोस सफेद रेखा के पास पहुँचते हैं, जिसके दूसरी ओर उसी दिशा में और यातायात चल रहा है। यह सफेद रेखा आपके बगल के यातायात के बारे में आपको क्या बताती है?","options":["आपके बगल का यातायात आपकी ही दिशा में चल रहा है, और यह रेखा इसे पार करके लेन बदलने को हतोत्साहित करती है।","आपके बगल का यातायात विपरीत दिशा में चल रहा है, इसलिए रेखा पार करने पर आप सामने से आती गाड़ियों के बीच आ जाएंगे।","रेखा सड़क के किनारे को चिह्नित करती है, इसलिए उसके आगे कोई यातायात लेन है ही नहीं।","रेखा का मतलब है कि आगे का रास्ता साफ होने पर ही ओवरटेक करने की अनुमति है, ठीक टूटी पीली रेखा की तरह।"],"explanation":"White lines separate lanes of traffic moving in the SAME direction, and a solid white line discourages crossing or changing lanes. Yellow lines (B) separate opposite directions, white edge lines mark the pavement edge but here it sits between two same-direction lanes (C), and broken-line passing rules apply to yellow lines, not this solid white one (D)."},"25":{"q":"आप दो-लेन वाले राजमार्ग पर गाड़ी चला रहे हैं और आगे चल रहे धीमे ट्रैक्टर को ओवरटेक करना चाहते हैं। पास पहुँचने पर आप देखते हैं कि केंद्र की आपकी ओर वाली रेखा एक सतत पीली रेखा है, जबकि विपरीत ओर टूटी हुई पीली रेखा है। यह आपको ओवरटेक करने के बारे में क्या बताता है?","options":["आप ओवरटेक कर सकते हैं क्योंकि दूसरी ओर की टूटी हुई पीली रेखा दोनों दिशाओं के यातायात पर लागू होती है।","आप ओवरटेक नहीं कर सकते, क्योंकि आपकी ओर की सतत पीली रेखा ओवरटेक करने पर रोक लगाती है।","आप केवल निर्धारित सीमा से कम गति पर ही ओवरटेक कर सकते हैं क्योंकि ये निशान सलाहकारी हैं।","किसी भी पीली रेखा को पार करने से पहले आपको पूरी तरह रुकना होगा।"],"explanation":"A solid yellow line on your side of the road means passing is prohibited for you, even if the opposite side has a broken (dashed) yellow line that permits passing for oncoming traffic. The broken line only allows passing for drivers on that side, and yellow markings are regulatory, not merely advisory."},"26":{"q":"आप दो-लेन वाले राजमार्ग पर गाड़ी चला रहे हैं और आगे चल रहे धीमे ट्रैक्टर को ओवरटेक करना चाहते हैं। बीच की रेखा के आपकी ओर सड़क पर टूटी हुई (खंडित) पीली रेखा बनी है, सामने वाली लेन खाली है, और आपके आगे दूर तक साफ दृश्य है। यह निशान आपको ओवरटेक करने के बारे में क्या बताता है?","options":["आप किसी भी कारण से पीली रेखा को कभी पार नहीं कर सकते, इसलिए ट्रैक्टर के पीछे ही रहें","खंडित रेखा सड़क के किनारे को दर्शाती है, इसलिए बाईं ओर न जाएं","ओवरटेक करने की अनुमति है, और जब रास्ता साफ हो तो आप ओवरटेक करने के लिए सामने वाली लेन में जा सकते हैं","आप स्वतंत्र रूप से लेन बदल सकते हैं क्योंकि खंडित रेखाएं हमेशा एक ही दिशा के यातायात को अलग करती हैं"],"explanation":"आपकी ओर की टूटी हुई (खंडित) पीली रेखा का अर्थ है कि जब आगे का रास्ता साफ हो तो ओवरटेक करने की अनुमति है, इसलिए आप ट्रैक्टर को ओवरटेक करने के लिए इसे पार कर सकते हैं। विकल्प D जाल है: खंडित सफेद रेखाएं एक ही दिशा के यातायात को अलग करती हैं, लेकिन पीली रेखाएं हमेशा विपरीत दिशा के यातायात को अलग करती हैं, इसलिए यहां यह नियम गलत तरीके से लागू किया गया है।"},"27":{"q":"आप एक दो-लेन वाली सड़क पर चला रहे हैं जिसके बीच में दोहरी ठोस पीली रेखा चलती है। आपके आगे एक धीमा ट्रैक्टर है, सड़क खाली है और दृश्यता अच्छी है। आपकी बाईं ओर, एक प्रवेश मार्ग उस घर की ओर जाता है जहाँ आप जाना चाहते हैं। दोहरी ठोस पीली रेखा यहाँ आपको क्या करने की अनुमति देती है?","options":["ट्रैक्टर को ओवरटेक करें, क्योंकि सड़क खाली है और दृश्यता अच्छी है","ट्रैक्टर को ओवरटेक करें, क्योंकि दोहरी पीली रेखा केवल सामने से आने वाले यातायात को रोकती है","कुछ भी आपको रुकने के लिए बाध्य नहीं करता; आप टूटी सफेद रेखा की तरह स्वतंत्र रूप से लेन बदल सकते हैं","रेखा को केवल बाईं ओर प्रवेश मार्ग में मुड़ने के लिए पार करें, लेकिन ट्रैक्टर को ओवरटेक करने के लिए नहीं"],"explanation":"दोहरी ठोस पीली रेखा का अर्थ है दोनों दिशाओं में ओवरटेक करना मना है, इसलिए अच्छी दृश्यता होने पर भी आप ट्रैक्टर को ओवरटेक नहीं कर सकते; आप इसे केवल मुड़ने के लिए (जैसे प्रवेश मार्ग में) पार कर सकते हैं। खाली सड़क और 'केवल सामने से आने वाला यातायात' वाले विकल्प जाल हैं क्योंकि यह प्रतिबंध दृश्यता की परवाह किए बिना दोनों दिशाओं में लागू होता है।"},"28":{"q":"आप एक तीन-लेन वाले राजमार्ग पर गाड़ी चला रहे हैं जहाँ सारा यातायात एक ही दिशा में चल रहा है। एक निकास के पास पहुँचते समय, आप देखते हैं कि आपके दाहिनी ओर की लेन रेखा टूटी हुई सफेद रेखा से बदलकर एक ठोस सफेद रेखा हो गई है। यह ठोस सफेद रेखा आपको यहाँ लेन बदलने के बारे में क्या बताती है?","options":["यह इस स्थान पर लेन बदलने के लिए रेखा को पार करने को हतोत्साहित करती है","यह आपको रास्ता साफ होने पर जब चाहें स्वतंत्र रूप से लेन बदलने की अनुमति देती है","यह विपरीत दिशाओं में चल रहे यातायात को अलग करती है","इसका मतलब है कि ओवरटेक केवल तभी अनुमत है जब सामने से आता हुआ कोई यातायात न हो"],"explanation":"A solid white line discourages lane changes, so you should stay in your lane rather than cross it near the exit, whereas a broken white line is what allows lane changes when clear (option B). White lines separate same-direction traffic, so the opposite-direction and oncoming-traffic options describe yellow-line rules, not this marking."},"29":{"q":"आप एक चौराहे पर लाल ट्रैफ़िक लाइट के पास पहुँचते हैं और दाएँ मुड़ना चाहते हैं। लाल पर मुड़ने से रोकने वाला कोई संकेत नहीं लगा है, और पैदल-पार पथ तथा आर-पार का यातायात साफ़ है। सही कार्रवाई क्या है?","options":["गति धीमी करें पर रुके बिना ही लाल लाइट पार कर जाएँ, क्योंकि रास्ता साफ़ है","पहले रेखा के पीछे पूरी तरह रुकें, फिर सुरक्षित होने पर दाएँ मुड़ें","दाएँ मुड़ने की अनुमति मिलने से पहले हरे तीर का इंतज़ार करें","लाल लाइट को 'रास्ता दें' मानकर बिना पूरी तरह रुके मोड़ में शामिल हो जाएँ"],"explanation":"स्थिर लाल लाइट पर रेखा के पीछे पूरी तरह रुकना अनिवार्य है, और लाल पर दाएँ मुड़ना केवल उस पूर्ण विराम के बाद ही अनुमत है जब कोई संकेत इसे न रोके। बिना रुके पार करना (A) या बिना रुके रास्ता देना (D) अनिवार्य पूर्ण विराम को छोड़ देता है, और अनुमत दाएँ मोड़ के लिए हरे तीर (C) की आवश्यकता नहीं होती।"},"30":{"q":"आप गति सीमा पर एक चौराहे के पास पहुंच रहे हैं जब आपके सामने का सिग्नल हरे से स्थिर पीले में बदल जाता है। आप अभी भी कुछ दूरी पर हैं, सहजता से ब्रेक लगाने के लिए पर्याप्त जगह है। इस सिग्नल का क्या अर्थ है और आपको क्या करना चाहिए?","options":["बत्ती फिर से हरी होने वाली है; बदलने से पहले चौराहा पार करने के लिए गति बढ़ाएं","यह आगे किसी खतरे, जैसे मोड़ या विलय की चेतावनी है; गति धीमी करें लेकिन आप आगे बढ़ सकते हैं","बत्ती लाल होने वाली है; यदि आप सुरक्षित रूप से ऐसा कर सकते हैं तो लाइन से पहले रुकें","चौराहे को चार-तरफा स्टॉप मानें, पूरी तरह रुकें, फिर अपनी बारी आने पर आगे बढ़ें"],"explanation":"A steady yellow light warns that the signal is about to turn red, so you must stop before the line if you can do so safely, which you can from this distance. Option D describes a dark/non-working signal, and option B confuses the signal with a yellow warning sign, not a traffic light."},"31":{"q":"आप एक स्थिर हरी बत्ती पर एक चौराहे पर पहुंचते हैं और बाएं मुड़ने का संकेत देते हैं। सामने से वाहन आ रहे हैं, और एक पैदल यात्री उस क्रॉसवॉक में कदम रख रहा है जिसे आपको पार करना है। आपको क्या करना चाहिए?","options":["तुरंत आगे बढ़ें, क्योंकि हरी बत्ती आपको मुड़ने का संरक्षित अधिकार देती है।","लाइन के पीछे पूरी तरह रुकें और मुड़ने से पहले हरे तीर का इंतजार करें।","सामने से आ रहे वाहनों के आगे जल्दी से मुड़ जाएं क्योंकि उन्हें मुड़ने वाले वाहन को रास्ता देना होता है।","रुकें, पैदल यात्री और सामने से आ रहे यातायात को रास्ता दें, और फिर रास्ता साफ होने पर मोड़ पूरा करें।"],"explanation":"A steady green means go only if the way is clear; when turning you must yield to pedestrians and oncoming traffic, so you wait until both are clear before turning. A plain green is not a protected turn (only a green arrow is), and oncoming traffic does not yield to you, so the other answers are wrong."},"32":{"q":"रात में आप एक चौराहे के पास पहुँचते हैं और आपकी दिशा में ऊपर लगा ट्रैफ़िक सिग्नल लाल रंग में टिमटिमा रहा है। आसपास कोई अन्य यातायात दिखाई नहीं दे रहा। आपको क्या करना चाहिए?","options":["पूरी तरह रुकें, फिर रास्ता साफ़ होने पर आगे बढ़ें, इसे STOP (रुको) चिह्न की तरह मानें","गति धीमी करें और बिना रुके सावधानी से आगे बढ़ें","गाड़ी चलाते रहें, क्योंकि टिमटिमाती बत्ती का मतलब है कि सिग्नल चालू नहीं है","रुकें और आगे बढ़ने से पहले बत्ती के स्थिर हरे होने का इंतज़ार करें"],"explanation":"A flashing red light must be treated exactly like a STOP sign: come to a full stop, then proceed when it is safe. Slowing without stopping (B) is the rule for a flashing yellow light, not a flashing red one."},"33":{"q":"आप रात में एक चौराहे के पास पहुंच रहे हैं और आपके सामने वाला ट्रैफिक सिग्नल चमकती पीली बत्ती दिखा रहा है। आपको क्या करना चाहिए?","options":["रेखा के पीछे पूरी तरह रुकें, फिर रास्ता साफ होने पर आगे बढ़ें, इसे स्टॉप साइन की तरह मानें","गति धीमी करें और सावधानी से चौराहे को पार करें","पूरी तरह रुकें और हरी बत्ती होने तक रुके रहें","चौराहे को चारों ओर के स्टॉप की तरह मानें और अपनी दाईं ओर के चालक को रास्ता दें"],"explanation":"A flashing yellow light means slow down and proceed with caution, so option B is correct. Option A describes a flashing RED light (treated as a stop sign), and option D describes a dark or non-working signal, which are the wrong responses for a flashing yellow."},"34":{"q":"आप एक चौराहे पर बाएं मुड़ने वाली लेन में रुके हुए हैं। आपकी दिशा के लिए मुख्य सिग्नल स्थिर लाल है, लेकिन उसके बगल में एक अलग बाएं-मोड़ सिग्नल बाईं ओर इशारा करता हुआ स्थिर हरा तीर दिखा रहा है। आपके बाएं मोड़ के लिए इसका क्या मतलब है?","options":["आपको प्रतीक्षा करनी चाहिए, क्योंकि स्थिर लाल बत्ती चौराहे पर सभी गतिविधियों को नियंत्रित करती है","आप बाएं तभी मुड़ सकते हैं जब आप सामने से आने वाले यातायात को रास्ता दें, क्योंकि हरा हमेशा सामने आने वाले वाहनों को रास्ता देने का मतलब है","आपके पास एक सुरक्षित मोड़ है और आप तीर की दिशा में बाएं मुड़ सकते हैं","आपको चौराहे को सभी दिशाओं के स्टॉप की तरह मानना चाहिए और अपनी बारी पर आगे बढ़ना चाहिए"],"explanation":"A green arrow signals a protected turn in the direction it points, so you may turn left with the right of way even though the main signal is red. Option B describes a steady green ball (yield to oncoming traffic), not a green arrow, and option A wrongly lets the red ball override the dedicated turn arrow."},"35":{"q":"आप एक चौराहे पर बाएं मुड़ने वाली लेन में रुके हुए हैं। बाएं मुड़ने का अलग सिग्नल बाईं ओर इशारा करता हुआ स्थिर लाल तीर दिखा रहा है, जबकि सीधे जाने वाले यातायात का सिग्नल हरा है। आपको क्या करना चाहिए?","options":["बाएं मुड़ जाएं, क्योंकि सीधी लेन की हरी बत्ती आपको रास्ते का अधिकार देती है","पूरी तरह रुकने के बाद बाएं मुड़ें, जैसे लाल बत्ती पर दाएं मुड़ते हैं","लाल तीर को टिमटिमाते पीले की तरह मानें और सावधानी से बाएं मुड़ें","रुके रहें और प्रतीक्षा करें, क्योंकि लाल तीर का अर्थ है कि उस दिशा में बाएं मुड़ना अनुमत नहीं है"],"explanation":"A red arrow means no turn is permitted in the direction the arrow points, so you must stay stopped until the arrow changes. The green light for the through lanes does not apply to your protected turn, and a red arrow does not allow a turn after stopping the way a steady red ball can."},"36":{"q":"बिजली कटौती के दौरान आप एक व्यस्त चार-तरफा चौराहे के पास पहुँचते हैं, और जो ट्रैफ़िक सिग्नल सामान्यतः इसे नियंत्रित करता है वह पूरी तरह बंद है और कोई भी रोशनी नहीं दिखा रहा। आसपास कोई पुलिसकर्मी या अस्थायी संकेत नहीं है। आपको कैसे आगे बढ़ना चाहिए?","options":["चौराहे को सभी दिशाओं वाले STOP के रूप में मानें: पूरी तरह रुकें और सामान्य प्राथमिकता नियमों के अनुसार रास्ता दें।","रुके बिना गति धीमी करके सावधानी से आगे बढ़ें, क्योंकि बंद सिग्नल चमकती पीली बत्ती की तरह काम करता है।","सामान्य गति से आगे बढ़ें क्योंकि बंद सिग्नल का मतलब है कि चौराहे पर कोई सक्रिय नियंत्रण नहीं है।","केवल तभी रुकें जब आड़ी-तिरछी ट्रैफ़िक मौजूद हो, फिर आपके बाद आने वाले चालकों से पहले निकल जाएँ।"],"explanation":"A dark or non-working signal must be treated as an all-way STOP, so you stop fully and follow normal right-of-way rules. Option B is wrong because a dark signal is not the same as a flashing yellow (slow and proceed with caution); a dead signal requires a complete stop from every direction."},"37":{"q":"आप एक राजमार्ग पर गाड़ी चला रहे हैं तभी आपको आगे हीरे के आकार के दो चेतावनी संकेत दिखाई देते हैं। पहला चमकीला पीला है जिस पर मुड़ती हुई सड़क दिखाई गई है, और दूसरा चमकीला नारंगी है जिस पर फावड़े के साथ एक मजदूर दिखाया गया है। दूसरे संकेत का नारंगी रंग आपको विशेष रूप से क्या बताता है?","options":["आगे एक सामान्य मोड़ या ढलान का खतरा है, बिल्कुल पीले संकेत की तरह","आप एक निर्माण या कार्य क्षेत्र के पास पहुँच रहे हैं","आगे एक पैदल यात्री या स्कूल क्रॉसिंग है","आपको रुकना होगा क्योंकि सड़क बंद है"],"explanation":"Orange signs indicate a construction or work zone, distinguishing them from standard yellow general-warning signs (curve, hill, merge). Option A confuses orange with the yellow general-warning color, and pedestrian/school warnings use fluorescent yellow-green, not orange."},"38":{"q":"आप शाम के धुंधलके में एक अनजान दो-लेन वाली सड़क पर गाड़ी चला रहे हैं। आपकी लेन और आपकी बाईं ओर की लेन के बीच की केंद्र रेखा एक ठोस पीली रेखा है। यह रंग आपकी बाईं ओर की लेन में यातायात के बारे में आपको क्या बताता है?","options":["यह एक मोड़ वाली लेन है जिसका उपयोग दोनों दिशाओं से यातायात कर सकता है","यह पक्की किनारा (शोल्डर) है, इसलिए इस पर कोई आर-पार यातायात नहीं चलता","इस पर आपकी विपरीत दिशा में चलने वाला यातायात चलता है","इस पर आपकी ही दिशा में चलने वाला यातायात चलता है"],"explanation":"Yellow lines separate traffic moving in opposite directions, so the yellow center line means the lane to your left carries oncoming traffic. White lines (option D) would indicate traffic moving in the same direction, which is the trap here."},"39":{"q":"गोधूलि के समय किसी अनजान कस्बे से गुजरते हुए, आप सड़क किनारे लगे एक संकेत के पास पहुँचते हैं जिसे आप साफ देख सकते हैं लेकिन जिसके शब्द अभी पढ़े नहीं जा सकते। यह एक ऊँचा खड़ा (वर्टिकल) आयत है जिसकी पृष्ठभूमि सादी सफेद और अक्षर काले हैं। उसे पढ़ पाने से पहले ही, संकेत का आकार और रंग उसके उद्देश्य के बारे में आपको क्या बताते हैं?","options":["यह एक मार्गदर्शक संकेत है जो आगे की दिशाएँ, दूरियाँ या सेवाएँ बताता है","यह एक चेतावनी संकेत है जो आगे किसी खतरे या बदलती स्थिति के बारे में सावधान करता है","यह एक निर्माण संकेत है जो सक्रिय कार्य क्षेत्र को दर्शाता है","यह एक नियामक (रेगुलेटरी) संकेत है जो ऐसा कानून बताता है जिसका पालन करना आपके लिए अनिवार्य है"],"explanation":"A vertical rectangle that is white with black lettering is a regulatory sign, meaning it states a law (such as a speed limit) that you must obey. Guide signs are green or horizontal rectangles, warning signs are yellow diamonds, and construction signs are orange, so those choices misread the white-and-black vertical rectangle."}},"learn-road-signs":{"0":{"q":"रुकने (STOP) के चिह्न का आकार क्या होता है?","options":["अष्टभुज (8 भुजाएँ)","समचतुर्भुज","वृत्त","ऊर्ध्वाधर आयत"],"explanation":"A STOP sign is the only octagonal (8-sided) sign and requires a full stop."},"1":{"q":"उल्टे (नीचे की ओर नुकीले) त्रिकोण वाले चिह्न का क्या अर्थ है?","options":["रुकें","रास्ता दें","आगे निकलना मना","स्कूल क्षेत्र"],"explanation":"An inverted triangle means YIELD, so give the right of way and slow or stop if needed."},"2":{"q":"पेनेंट चिह्न (सड़क के बाईं ओर एक क्षैतिज त्रिकोण) का क्या अर्थ है?","options":["आगे स्कूल क्षेत्र","पूरी तरह रुकें","ओवरटेक निषेध क्षेत्र","रेलवे क्रॉसिंग"],"explanation":"A pennant, a horizontal triangle placed on the left side of the road, marks a No Passing Zone."},"3":{"q":"हीरे के आकार का चिह्न आपको क्या बताता है?","options":["आपको पूरी तरह रुकना चाहिए","आप एकतरफा सड़क में प्रवेश कर रहे हैं","आप गति सीमा तक पहुँच गए हैं","आगे कोई खतरा या स्थिति है"],"explanation":"A diamond-shaped sign is a warning sign that indicates a hazard or condition ahead."},"4":{"q":"पंचभुज आकार का चिह्न (5 भुजाएं, नोक ऊपर) क्या दर्शाता है?","options":["स्कूल क्षेत्र या स्कूल क्रॉसिंग","रेलवे क्रॉसिंग","ओवरटेक न करने का क्षेत्र","रुकने वाला चौराहा"],"explanation":"A pentagon (5 sides, point up) marks a school zone or school crossing."},"5":{"q":"एक गोल (वृत्ताकार) सड़क संकेत आपको किस बारे में चेतावनी देता है?","options":["आगे एक स्कूल क्षेत्र","आगे एक रेलमार्ग क्रॉसिंग","एक नो-पासिंग क्षेत्र","एक निर्माण क्षेत्र"],"explanation":"A round (circular) sign is an advance warning that a railroad crossing is ahead."},"6":{"q":"क्रॉसबक (X आकार वाला) चिह्न का क्या अर्थ है?","options":["पूरी तरह रुकें","आगे निर्माण कार्य","रेलमार्ग क्रॉसिंग; इसे यील्ड की तरह मानें","आगे स्कूल क्षेत्र"],"explanation":"A crossbuck (X shape) marks the railroad crossing itself and should be treated like a yield."},"7":{"q":"ऊर्ध्वाधर आयत वाला चिह्न क्या दर्शाता है?","options":["आगे खतरे की चेतावनी","स्कूल क्षेत्र क्रॉसिंग","आगे रेलवे क्रॉसिंग","एक नियामक कानून जिसका आपको पालन करना चाहिए"],"explanation":"A vertical rectangle is a regulatory sign indicating a law you must obey, such as a speed limit."},"8":{"q":"क्षैतिज आयत किस प्रकार का चिह्न है?","options":["दिशाओं और दूरियों वाला एक मार्गदर्शक या सूचना चिह्न","एक रुकने (स्टॉप) का चिह्न","आगे खतरे के लिए चेतावनी चिह्न","एक स्कूल क्षेत्र चिह्न"],"explanation":"A horizontal rectangle is a guide or information sign that gives directions and distances."},"9":{"q":"केवल STOP के लिए कौन सा चिह्न आकार उपयोग किया जाता है?","options":["हीरा","अष्टभुज","त्रिभुज","आयत"],"explanation":"The octagon (8 sides) is the only sign shape reserved exclusively for STOP."},"10":{"q":"यातायात संकेत पर लाल रंग का क्या अर्थ है?","options":["निर्माण क्षेत्र","चालक सेवाएं","रुकें, रास्ता दें, या निषिद्ध","सामान्य चेतावनी"],"explanation":"Red is used on STOP, YIELD, DO NOT ENTER, and WRONG WAY signs to mean stop, yield, or prohibited."},"11":{"q":"पीला सड़क चिह्न क्या दर्शाता है?","options":["आगे निर्माण क्षेत्र","रुकें या प्रवेश न करें","पास में चालक सेवाएं","आगे सामान्य चेतावनी"],"explanation":"Yellow signals a general warning, such as a curve, hill, merge, or signal ahead."},"12":{"q":"नारंगी सड़क संकेत का क्या अर्थ है?","options":["निर्माण या कार्य क्षेत्र","रुकें या रास्ता दें","चालक सेवाएं","मनोरंजन क्षेत्र"],"explanation":"Orange signs warn of construction or a work zone ahead."},"13":{"q":"हरे रंग का सड़क चिह्न क्या दर्शाता है?","options":["रुकें या रास्ता दें","मार्गदर्शन और दिशाएँ","निर्माण क्षेत्र","सामान्य चेतावनी"],"explanation":"Green signs give guide information like directions and distances."},"14":{"q":"नीले सड़क चिह्न का क्या मतलब है?","options":["आगे निर्माण क्षेत्र","रुकें या रास्ता दें","चालक सेवाएं जैसे पेट्रोल और भोजन","मनोरंजन क्षेत्र"],"explanation":"Blue signs show motorist services such as gas, food, lodging, and hospital."},"15":{"q":"कौन से रंग का सड़क चिह्न मनोरंजन, सांस्कृतिक या दर्शनीय क्षेत्रों को दर्शाता है?","options":["नीला","हरा","पीला","भूरा"],"explanation":"Brown signs mark recreation, cultural, or scenic areas."},"16":{"q":"काले अक्षरों वाले सफेद चिह्न का क्या अर्थ है?","options":["नियामक, जैसे गति सीमा","निर्माण या कार्य क्षेत्र","मनोरंजन या दर्शनीय क्षेत्र","आगे सामान्य चेतावनी"],"explanation":"A white sign with black letters is regulatory, such as a speed limit or lane use sign."},"17":{"q":"फ्लोरोसेंट पीला-हरा संकेत किसके बारे में चेतावनी देता है?","options":["निर्माण कार्य क्षेत्र","पैदल यात्री, साइकिल और स्कूल क्षेत्र","ईंधन और भोजन जैसी चालक सेवाएं","मनोरंजन और प्राकृतिक दृश्य क्षेत्र"],"explanation":"Fluorescent yellow-green signs warn of pedestrian, bicycle, and school crossings."},"18":{"q":"WRONG WAY (गलत रास्ता) का चिह्न किस रंग का होता है?","options":["पीला","हरा","लाल","नीला"],"explanation":"A WRONG WAY sign is red, signaling you must not proceed."},"19":{"q":"विलय चेतावनी संकेत किस रंग का होता है?","options":["नारंगी","नीला","हरा","पीला"],"explanation":"Yellow is used for general warning signs, including merge signs."},"20":{"q":"STOP (रुकें) के चिह्न का आकार क्या होता है?","options":["अष्टभुज (8 भुजाएँ)","समचतुर्भुज","वृत्त","वर्ग"],"explanation":"A STOP sign is a red octagon, the only sign with that shape."},"21":{"q":"YIELD (रास्ता दें) चिह्न किस रंग का होता है?","options":["पीला और काला","लाल और सफेद","हरा और सफेद","नीला और सफेद"],"explanation":"A YIELD sign is a red-and-white inverted triangle."},"22":{"q":"DO NOT ENTER (प्रवेश निषेध) और WRONG WAY (गलत दिशा) के संकेत किस रंग के होते हैं?","options":["पीला","हरा","लाल","नीला"],"explanation":"DO NOT ENTER and WRONG WAY signs are red and mean do not proceed."},"23":{"q":"एक तरफ़ा (ONE WAY) चिह्न आपको क्या बताता है?","options":["मुड़ने से पहले पूरी तरह रुकें","आगे सड़क बंद है","यहाँ ओवरटेक करने की अनुमति है","केवल तीर की दिशा में ही चलें"],"explanation":"A ONE WAY sign means you may travel only in the direction the arrow points."},"24":{"q":"गति सीमा (SPEED LIMIT) का चिह्न क्या दर्शाता है?","options":["आदर्श परिस्थितियों में अधिकतम कानूनी गति","न्यूनतम गति जिससे कम कभी नहीं चलना चाहिए","तीखे मोड़ों के लिए सुझाई गई गति","केवल रात में गाड़ी चलाने की गति"],"explanation":"A SPEED LIMIT sign is a white rectangle with black numbers showing the maximum legal speed in ideal conditions."},"25":{"q":"निषेधात्मक \"नहीं\" संकेत किस डिज़ाइन का उपयोग करते हैं?","options":["एक पीला हीरा","तिरछी रेखा वाला एक लाल वृत्त","एक हरा आयत","एक नीला वर्ग"],"explanation":"Regulatory \"No\" signs, such as no U-turn or no left turn, use a red circle with a slash."},"26":{"q":"गति सीमा (SPEED LIMIT) चिह्न पर लिखी संख्या का क्या अर्थ है?","options":["न्यूनतम कानूनी गति","औसत यातायात गति","अधिकतम कानूनी गति","ट्रकों के लिए अनुशंसित गति"],"explanation":"The number on a SPEED LIMIT sign is the maximum legal speed under ideal conditions."},"27":{"q":"लगा हुआ गति सीमा क्या दिखाता है?","options":["सबसे धीमी गति जो आप चला सकते हैं","किसी भी मौसम के लिए गति","केवल रात के लिए गति","आदर्श परिस्थितियों के लिए अधिकतम"],"explanation":"The posted speed limit is the maximum for ideal conditions, so drive slower in poor conditions."},"28":{"q":"सड़क पर पीली रेखाएं किसे अलग करती हैं?","options":["विपरीत दिशाओं में चलने वाला यातायात","एक ही दिशा में चलने वाला यातायात","पार्किंग स्थान","साइकिल लेन"],"explanation":"Yellow lines separate traffic moving in opposite directions."},"29":{"q":"सड़क पर सफेद रेखाएं क्या दर्शाती हैं?","options":["आगे स्कूल क्षेत्र","एक ही दिशा में चलता यातायात","विपरीत दिशाओं में चलता यातायात","ओवरटेक न करने वाला क्षेत्र"],"explanation":"White lines separate lanes of traffic moving in the same direction and mark the road edge."},"30":{"q":"सड़क पर आपकी ओर एक ठोस पीली रेखा का क्या मतलब है?","options":["ओवरटेक करने की अनुमति है","आगे सड़क समाप्त होती है","ओवरटेक करना मना है","एकतरफ़ा सड़क"],"explanation":"A solid yellow line on your side means you may not pass."},"31":{"q":"टूटी हुई (खंडित) पीली रेखा का क्या अर्थ है?","options":["इस रेखा को कभी पार न करें","किसी भी दिशा में ओवरटेक करना मना है","यह सड़क के किनारे को दर्शाती है","रास्ता साफ होने पर ओवरटेक करने की अनुमति है"],"explanation":"A broken (dashed) yellow line means passing is allowed when the way is clear."},"32":{"q":"दोहरी ठोस पीली रेखा का क्या अर्थ है?","options":["किसी भी दिशा में ओवरटेक करना मना है","दोनों दिशाओं में ओवरटेक की अनुमति है","लेन एक ही दिशा में जाती हैं","आगे सड़क का किनारा है"],"explanation":"A double solid yellow line means no passing in either direction; do not cross except to turn."},"33":{"q":"सड़क पर एक ठोस सफेद रेखा का क्या अर्थ है?","options":["ओवरटेक करने की अनुमति है","लेन बदलने को हतोत्साहित किया जाता है","यातायात विपरीत दिशाओं में चलता है","आपको रुकना चाहिए"],"explanation":"A solid white line discourages lane changes."},"34":{"q":"टूटी हुई सफेद रेखा आपको क्या करने की अनुमति देती है?","options":["पूरी तरह रुकना","सामने से आ रहे यातायात को ओवरटेक करना","लेन बदलना","इसे कभी पार न करना"],"explanation":"A broken white line separates lanes going the same way and allows lane changes."},"35":{"q":"सड़क पर सफेद रेखाएं क्या चिह्नित करती हैं?","options":["एक रेलवे क्रॉसिंग","आगे एक स्कूल क्षेत्र","विपरीत दिशाओं में चलने वाला यातायात","सड़क का किनारा"],"explanation":"White lines mark the edge of the road and separate traffic moving in the same direction."},"36":{"q":"एक ही दिशा में जाने वाले यातायात की लेन को अलग करने वाली रेखाएं किस रंग की होती हैं?","options":["सफेद","पीली","लाल","नीली"],"explanation":"White lines separate traffic moving in the same direction, while yellow lines separate opposite directions."},"37":{"q":"स्थिर लाल ट्रैफिक लाइट पर आपको क्या करना चाहिए?","options":["गति धीमी करें और चलते रहें","रेखा के पीछे पूरी तरह रुकें","चौराहा पार करने के लिए गति बढ़ाएं","हॉर्न बजाकर आगे बढ़ें"],"explanation":"A steady red light means you must stop completely behind the line and remain stopped."},"38":{"q":"स्थिर लाल बत्ती पर आप दाईं ओर कब मुड़ सकते हैं?","options":["कभी नहीं, किसी भी समय नहीं","पहले रुके बिना","पूरी तरह रुकने के बाद, जब तक कोई संकेत इसे मना न करे","केवल जब तीर दिखाई दे"],"explanation":"At a steady red light you may turn right after coming to a full stop, unless a sign prohibits it."},"39":{"q":"स्थिर पीली ट्रैफिक लाइट का क्या मतलब है?","options":["लाल से पहले निकलने के लिए गति बढ़ाएं","लाइट खराब है; कभी भी चले जाएं","केवल तभी रुकें जब आपके पीछे कोई कार हो","लाइट लाल होने वाली है; सुरक्षित हो तो रुकें"],"explanation":"A steady yellow light warns that the signal is about to turn red, so stop if you can do so safely."},"40":{"q":"स्थिर हरी ट्रैफिक लाइट का क्या अर्थ है?","options":["यदि रास्ता साफ हो तो आगे बढ़ें","पूरी तरह रुकें","धीमे हों और रुकने के लिए तैयार रहें","केवल सुरक्षित मोड़ लें"],"explanation":"A steady green light means you may go if the way is clear."},"41":{"q":"स्थिर हरी बत्ती पर मुड़ते समय आपको किसे रास्ता देना चाहिए?","options":["किसी को नहीं","पैदल यात्रियों और सामने से आने वाले यातायात को","केवल खड़ी कारों को","अपने पीछे के यातायात को"],"explanation":"At a steady green light, you must yield to pedestrians and oncoming traffic when turning."},"42":{"q":"चमकती लाल ट्रैफिक लाइट को कैसे समझना चाहिए?","options":["हरी बत्ती की तरह","रास्ता दें संकेत की तरह","रुकें (स्टॉप) संकेत की तरह","पीली बत्ती की तरह"],"explanation":"A flashing red light means you must stop completely, just like at a stop sign."},"43":{"q":"चमकती पीली ट्रैफिक लाइट का क्या मतलब है?","options":["पूरी तरह रुक जाएं","चौराहा पार करने के लिए गति बढ़ाएं","लाइट खराब है, आगे न बढ़ें","गति धीमी करें और सावधानी से आगे बढ़ें"],"explanation":"A flashing yellow light means slow down and proceed with caution."},"44":{"q":"हरा तीर ट्रैफिक सिग्नल का क्या मतलब है?","options":["तीर की दिशा में एक सुरक्षित मोड़","उस दिशा में कोई मोड़ नहीं","मुड़ने से पहले रुकें","धीमे हों और सावधानी बरतें"],"explanation":"A green arrow means a protected turn in the direction the arrow points."},"45":{"q":"लाल तीर के संकेत का क्या मतलब है?","options":["उस दिशा में तेज़ी से मुड़ें","उस दिशा में मुड़ने की अनुमति नहीं है","मुड़ने से पहले रास्ता दें","रुकने के बाद ही मुड़ें"],"explanation":"A red arrow means you may not turn in that direction."},"46":{"q":"बंद या काम न करने वाले ट्रैफिक सिग्नल को कैसे समझना चाहिए?","options":["बिना रुके आगे बढ़ें","इसे यील्ड (रास्ता दें) संकेत मानें","इसे सभी दिशाओं के लिए स्टॉप मानें","चौराहा पार करने के लिए गति बढ़ाएं"],"explanation":"A dark or non-working signal should be treated as an all-way stop."},"47":{"q":"STOP (रुकें) का चिह्न किस आकार का होता है?","options":["हीरा (डायमंड)","गोल","त्रिभुज","अष्टभुज"],"explanation":"A STOP sign is the only octagonal (8-sided) sign, so its shape alone tells you to stop."},"48":{"q":"गति सीमा का चिह्न किस रंग का होता है?","options":["काले अक्षरों के साथ सफेद","काले अक्षरों के साथ पीला","सफेद अक्षरों के साथ लाल","सफेद अक्षरों के साथ हरा"],"explanation":"A speed limit sign is white with black lettering because it is regulatory, not a warning."},"49":{"q":"सुंदर दृश्य क्षेत्र का चिह्न किस रंग का होता है?","options":["नीला","भूरा","हरा","पीला"],"explanation":"Brown signs mark recreation, cultural, and scenic areas."},"50":{"q":"अस्पताल और भोजन जैसी चालक सेवाओं के संकेत किस रंग के होते हैं?","options":["लाल","हरा","नीला","भूरा"],"explanation":"Blue signs show motorist services such as gas, food, lodging, and hospitals."},"51":{"q":"कार्य क्षेत्र या निर्माण का चिह्न किस रंग का होता है?","options":["पीला","हरा","नीला","नारंगी"],"explanation":"Work zone and construction signs are orange, which sets them apart from yellow general-warning signs."},"52":{"q":"स्कूल क्रॉसिंग चेतावनी संकेत किस रंग का होता है?","options":["फ्लोरोसेंट पीला-हरा","नीला","भूरा","नारंगी"],"explanation":"Fluorescent yellow-green is the color for pedestrian, bicycle, and school warnings."},"53":{"q":"STOP (रुकें), YIELD (रास्ता दें), DO NOT ENTER (प्रवेश निषेध) और WRONG WAY (गलत दिशा) संकेतों में कौन सा रंग समान है?","options":["पीला","लाल","हरा","नीला"],"explanation":"Red is the color shared by STOP, YIELD, DO NOT ENTER, and WRONG WAY signs."},"54":{"q":"आप दोहरी ठोस पीली रेखा को कब पार कर सकते हैं?","options":["दूसरी कार को ओवरटेक करने के लिए","जब भी रास्ता साफ हो","केवल मुड़ने के लिए","किसी भी कारण से कभी नहीं"],"explanation":"A double solid yellow line may be crossed only to turn, not to pass."},"55":{"q":"हरे तीर वाला ट्रैफिक सिग्नल क्या दर्शाता है?","options":["रुकें और यातायात की प्रतीक्षा करें","गति धीमी करें और रास्ता दें","मुड़ने की अनुमति नहीं है","सुरक्षित मोड़, सामने का यातायात रुका हुआ"],"explanation":"A green arrow gives a protected turn because oncoming traffic is stopped during that movement."},"56":{"q":"सड़क पर आपकी तरफ टूटी हुई पीली रेखा का क्या मतलब है?","options":["जब आगे की सड़क साफ हो तो ओवरटेक करने की अनुमति है","ओवरटेक करने की कभी अनुमति नहीं है","आपको रुकना चाहिए","सड़क एकतरफा है"],"explanation":"A broken yellow line on your side means you may pass when the road ahead is clear."},"57":{"q":"रेलरोड क्रॉसिंग की अग्रिम-चेतावनी संकेत का आकार कैसा होता है?","options":["हीरा (डायमंड)","गोल","अष्टभुज","क्रॉसबक (X आकार)"],"explanation":"The railroad advance-warning sign is round, while the sign at the crossing itself is a crossbuck."},"58":{"q":"चमकती लाल बत्ती पर आपको क्या करना चाहिए?","options":["गति धीमी करें और चलते रहें","पार करने के लिए गति बढ़ाएँ","पूरी तरह रुक जाएँ","रास्ता साफ हो तो अनदेखा करें"],"explanation":"A flashing red light means come to a complete stop, just like at a STOP sign."},"59":{"q":"बाएं मुड़ने वाले तीर के ऊपर लाल घेरा और तिरछी रेखा का क्या अर्थ है?","options":["केवल बाएं मुड़ें","बाईं लेन समाप्त होती है","आगे बाएं मुड़ना है","बाएं मुड़ना मना है"],"explanation":"A red circle and slash over a left-turn arrow means no left turn is allowed."}},"rules-of-the-road":{"0":{"q":"आप टेक्सास के एक ग्रामीण हाईवे पर गाड़ी चला रहे हैं जहाँ 70 मील प्रति घंटा की सीमा लगी है। अचानक घना कोहरा छा जाता है और आप आगे मुश्किल से दो कार की लंबाई तक देख पा रहे हैं। टेक्सास कानून के अनुसार, आपको किस गति से गाड़ी चलाने की अनुमति है?","options":["70 मील प्रति घंटा से धीमी — कोहरे के लिए उचित और सुरक्षित गति पर, क्योंकि लगी हुई सीमा केवल आदर्श परिस्थितियों के लिए अधिकतम है","70 मील प्रति घंटा तक, क्योंकि यह कानूनी रूप से लगी हुई सीमा है और आप हमेशा लगी हुई गति पर गाड़ी चला सकते हैं","ठीक 50 मील प्रति घंटा, क्योंकि टेक्सास कानून दृश्यता खराब होने पर गति को 20 मील प्रति घंटा कम करने की मांग करता है","75 मील प्रति घंटा तक, क्योंकि टेक्सास के ग्रामीण अंतरराज्यीय राजमार्ग परिस्थितियों की परवाह किए बिना 75 मील प्रति घंटा की अनुमति देते हैं"],"explanation":"टेक्सास के मूल गति कानून (prima facie) के अनुसार, आपको कभी भी मौजूदा परिस्थितियों के लिए उचित और सुरक्षित गति से तेज़ नहीं चलाना चाहिए, इसलिए घने कोहरे में आपको 70 मील प्रति घंटा से काफी कम गति करनी चाहिए। पूरी लगी हुई गति पर गाड़ी चलाना (B) जाल है: लगा हुआ अंक अच्छी परिस्थितियों के लिए अधिकतम है, गारंटी नहीं, और 20 मील तथा 75 मील के आंकड़े (C, D) वास्तविक नियम हैं जो गलत संदर्भ में रखे गए हैं।"},"1":{"q":"आप एक चिह्नित राजमार्ग से मुड़कर किसी शहर के शहरी क्षेत्र के भीतर एक आवासीय सड़क पर आते हैं। पूरे ब्लॉक में आपको कहीं भी गति सीमा का कोई चिह्न नहीं दिखता। यहाँ आपको कानूनी अधिकतम गति क्या माननी चाहिए?","options":["20 मील प्रति घंटा, क्योंकि जहाँ भी घर मौजूद हों वहाँ यही डिफ़ॉल्ट होता है","30 मील प्रति घंटा, चिह्न न लगे होने पर शहरी क्षेत्र के लिए सामान्य डिफ़ॉल्ट सीमा","70 मील प्रति घंटा, क्योंकि यह राजमार्गों के लिए डिफ़ॉल्ट है और कोई अन्य चिह्न इसे रद्द नहीं करता","जब तक आप सुरक्षित रूप से चलाते हैं तब तक कोई सीमा नहीं है, क्योंकि चिह्न गायब है"],"explanation":"Where no sign is posted, the common default speed limit in an urban district is 30 mph, so you should treat 30 mph as the legal maximum. The 20 mph figure is the typical reduced limit for active school zones, not residential streets generally, and 70 mph is the daytime default for numbered highways, not a city street."},"2":{"q":"आप दोपहर के समय टेक्सास के एक क्रमांकित राजमार्ग पर गाड़ी चला रहे हैं। मौसम साफ और सूखा है, लेकिन कई मील तक आपको गति सीमा का एक भी संकेत नहीं दिखा है। मूल गति कानून के अनुसार आप कानूनी रूप से अधिकतम कितनी गति से गाड़ी चला सकते हैं?","options":["75 mph, क्योंकि टेक्सास के सभी ग्रामीण राजमार्गों पर यही सीमा है","30 mph, क्योंकि जहाँ संकेत नहीं होते वहाँ यही डिफ़ॉल्ट सीमा है","70 mph, क्रमांकित राजमार्गों पर दिन के समय की डिफ़ॉल्ट सीमा","85 mph, टेक्सास में कहीं भी अनुमत सबसे अधिक गति"],"explanation":"Where no sign is posted, the default daytime limit on numbered highways in Texas is 70 mph. The 30 mph trap is the default for urban districts, not numbered highways, and 75 and 85 mph apply only to specific posted Interstates and tollways, not as a general default."},"3":{"q":"आप टेक्सास के एक ग्रामीण इंटरस्टेट पर गाड़ी चला रहे हैं जहाँ 75 मील प्रति घंटा की गति सीमा लगी है। कुछ मील बाद आप टेक्सास के एक विशिष्ट टोलवे पर पहुँचते हैं, और अब लगे संकेतों पर 85 मील प्रति घंटा लिखा है। यातायात हल्का है, सड़क सूखी है और दृश्यता साफ है। इस टोलवे खंड पर आप कानूनी रूप से अधिकतम कितनी गति से गाड़ी चला सकते हैं?","options":["70 मील प्रति घंटा, क्योंकि क्रमांकित राजमार्गों के लिए यही राज्यव्यापी दिन की अधिकतम सीमा है","75 मील प्रति घंटा, क्योंकि जिस इंटरस्टेट को आपने अभी छोड़ा वहाँ यही सीमा थी","80 मील प्रति घंटा, क्योंकि टेक्सास का कानून सभी सड़कों को 80 मील प्रति घंटा तक सीमित करता है","85 मील प्रति घंटा, क्योंकि इस विशिष्ट टोलवे पर लगे संकेत पर यही गति दर्ज है"],"explanation":"टेक्सास की सड़कों पर, जब परिस्थितियाँ सुरक्षित हों, आप संकेत पर दर्ज गति सीमा तक कानूनी रूप से गाड़ी चला सकते हैं, और टेक्सास के कुछ विशिष्ट टोलवे पर सीमा 80 से 85 मील प्रति घंटा तक हो सकती है। 70 और 75 मील प्रति घंटा वाले विकल्प अन्य सड़कों के लिए वास्तविक सीमाएँ हैं, लेकिन वे इस टोलवे पर लगे ऊँचे संकेत को रद्द नहीं करते।"},"4":{"q":"आप सुबह 7:45 बजे एक प्राथमिक विद्यालय के पास से गुजर रहे हैं। लगे हुए स्कूल-ज़ोन संकेत पर लिखा है '20 MPH जब चमक रहा हो', और उस पर लगी पीली बत्तियाँ चमक रही हैं। यहाँ चलाने की सही गति क्या है?","options":["20 mph, क्योंकि जब बत्तियाँ चमक रही हों तब आपको लगे हुए घटी हुई स्कूल-ज़ोन सीमा का पालन करना अनिवार्य है","30 mph, डिफ़ॉल्ट शहरी गति सीमा, क्योंकि स्कूल-ज़ोन सीमा केवल किनारे वाली लेन पर लागू होती है","सामान्य सीमा से कम कोई भी सुरक्षित गति, क्योंकि चमकती बत्तियाँ केवल एक चेतावनी हैं, कानून नहीं","70 mph, दिन की हाईवे सीमा, क्योंकि घटी हुई सीमा केवल तभी लागू होती है जब बच्चे इमारत से बाहर निकल जाते हैं"],"explanation":"When school-zone lights are flashing (or children are present), you must obey the posted reduced limit, typically 20 mph. The 30 mph default applies only on ordinary urban streets without a posted school-zone sign, so it is the wrong limit here."},"5":{"q":"आप सुबह एक प्राथमिक विद्यालय के पास से गुजर रहे हैं। स्कूल-ज़ोन की लाइटें चमक रही हैं और फुटपाथ पर बच्चे हैं। आपके फोन पर काम से एक कॉल आती है। टेक्सास का कानून आपसे क्या करने की मांग करता है?","options":["कॉल का उत्तर दें, क्योंकि स्कूल-ज़ोन की गति सीमा केवल यह प्रतिबंधित करती है कि आप कितनी तेज़ चला सकते हैं","हाथ में पकड़े फोन को छुएं नहीं, क्योंकि सक्रिय स्कूल ज़ोन में हाथ में पकड़े फोन का उपयोग करना अवैध है","कॉल का उत्तर दें लेकिन बात करते समय निर्धारित सीमा से 20 मील प्रति घंटा कम कर दें","कॉल को सुरक्षित रूप से लेने के लिए स्कूल क्रॉसवॉक के 15 फीट के भीतर रुक जाएं"],"explanation":"In an active school zone (lights flashing or children present), Texas law prohibits using a handheld phone, so you must not answer the call. Option A is wrong because the rule covers phone use, not just speed; the 20-mph-below figure in C is the Move Over/Slow Down rule for stopped emergency vehicles, not school zones."},"6":{"q":"आप दो-लेन वाली सड़क पर अंकित 55 मील प्रति घंटा की सीमा पर गाड़ी चला रहे हैं, तभी घना कोहरा छा जाता है और दृश्यता तेज़ी से घट जाती है। आपको क्या करना चाहिए?","options":["55 मील प्रति घंटा बनाए रखें क्योंकि यही कानूनी अंकित सीमा है और आपको इस गति पर चलने का अधिकार है","अपनी हाई-बीम हेडलाइट चालू करें और आगे दूर तक देखने के लिए अपनी मौजूदा गति बनाए रखें","घटी हुई दृश्यता और सड़क की स्थिति के अनुरूप अपनी गति को अंकित सीमा से नीचे कम करें","दाहिनी ओर के किनारे पर गाड़ी रोककर तब तक वहीं खड़े रहें जब तक कोहरा पूरी तरह साफ़ न हो जाए"],"explanation":"Texas's basic speed law requires you to never drive faster than is safe for conditions, so you must slow below the posted limit in fog. Keeping 55 mph (A) ignores that the posted number is only a maximum for ideal conditions, and high beams (B) actually reflect off fog and worsen visibility."},"7":{"q":"आप एक शांत आवासीय चौराहे पर पहुंचते हैं जहां किसी भी दिशा में स्टॉप साइन, यील्ड साइन या ट्रैफिक लाइट नहीं है। क्रॉस स्ट्रीट पर एक पिकअप ट्रक स्पष्ट रूप से आपसे कुछ सेकंड पहले चौराहे पर पहुंच गया और सीधे आगे जाने के लिए इंतजार कर रहा है। आपको क्या करना चाहिए?","options":["पहले आगे बढ़ें, क्योंकि ट्रक को अपने दाईं ओर के वाहन को रास्ता देना होगा","पहले आगे बढ़ें, क्योंकि मुख्य सड़क पर चल रहे यातायात को रास्ते का अधिकार है","आप दोनों को इसे ऑल-वे स्टॉप की तरह मानना चाहिए और यदि आप दाईं ओर हैं तो आप जाएं","पिकअप ट्रक को रास्ता दें और उसे पहले जाने दें, क्योंकि वह आपसे पहले चौराहे पर पहुंचा था"],"explanation":"At an uncontrolled intersection, you must yield to the vehicle that arrived first, so the pickup truck goes through before you. The 'yield to the driver on your right' rule only applies when two vehicles reach the intersection at the same time, which is not the case here."},"8":{"q":"आप एक मोहल्ले के चौराहे पर पहुंचते हैं जहां किसी भी दिशा में कोई स्टॉप साइन, यील्ड साइन या ट्रैफिक लाइट नहीं है। एक दूसरी कार ठीक उसी क्षण आपके दाईं ओर से चौराहे पर पहुंचती है जब आप पहुंचते हैं, और आप दोनों सीधे जाना चाहते हैं। आपको क्या करना चाहिए?","options":["अपनी दाईं ओर की कार को पहले जाने दें, फिर उसके चौराहा पार कर लेने के बाद आगे बढ़ें।","पहले आप जाएं, क्योंकि दाईं ओर के वाहन को बाईं ओर के वाहन को रास्ता देना आवश्यक है।","तुरंत आगे बढ़ें, क्योंकि सीधे जाने वाले चालक को मुड़ने वाले की तुलना में हमेशा रास्ते का अधिकार होता है।","आप दोनों को पूरी तरह रुककर इंतजार करना चाहिए, क्योंकि बिना नियंत्रण वाले चौराहे को सभी दिशाओं वाले स्टॉप के समान माना जाता है।"],"explanation":"At an uncontrolled intersection where two vehicles arrive at the same time, you must yield to the driver on your right. The car is on your right, so it goes first; the idea that the left vehicle has priority or that you must treat it as an all-way stop is incorrect."},"9":{"q":"आप एक चौराहे पर बाएं मुड़ने के लिए हरी बत्ती पर रुके हुए हैं। विपरीत दिशा से एक कार सीधी आ रही है, और एक पैदल यात्री उस सड़क को पार करना शुरू कर रहा है जिस पर आप मुड़ना चाहते हैं। अपना बायां मोड़ पूरा करने से पहले आपको क्या करना चाहिए?","options":["आने वाली कार के पहुंचने से पहले तेजी से मुड़ जाएं, क्योंकि हरी बत्ती आपको रास्ते का अधिकार देती है","आने वाली कार और पैदल यात्री दोनों को रास्ता दें, फिर सुरक्षित होने पर अपना मोड़ पूरा करें","केवल आने वाली कार को रास्ता दें, क्योंकि पैदल यात्रियों को वाहनों के चौराहा खाली करने का इंतजार करना चाहिए","पहले आगे बढ़ें क्योंकि आपके दाईं ओर के चालक को आपको रास्ता देना होगा"],"explanation":"When making a left turn you must yield to oncoming traffic and to pedestrians, so you wait for both the approaching car and the crossing pedestrian before turning. A green light does not give a left-turning driver priority over oncoming traffic, and pedestrians in a crosswalk always have the right of way."},"10":{"q":"आप एक रिहायशी सड़क पर गाड़ी चला रहे हैं जो एक व्यस्त मुख्य सड़क पर समाप्त होती है, जिससे एक T-चौराहा बनता है। इस चौराहे पर कोई स्टॉप साइन, ट्रैफिक सिग्नल या अन्य नियंत्रण नहीं है। जैसे ही आप अपनी सड़क के अंत में पहुँचते हैं, मुख्य सड़क पर आपकी बाईं ओर से एक कार आ रही है। आपको क्या करना चाहिए?","options":["पहले आगे बढ़ें, क्योंकि अनियंत्रित चौराहे पर दाईं ओर के वाहन को हमेशा रास्ते का अधिकार होता है","पहले आगे बढ़ें, क्योंकि मुख्य सड़क पर चल रही कार को बगल की सड़क से आने वाले यातायात को रास्ता देना चाहिए","मुख्य सड़क पर चल रही कार को रास्ता दें, क्योंकि मुख्य सड़क (T के ऊपरी हिस्से) पर चल रहे यातायात को रास्ते का अधिकार होता है","केवल तभी रास्ता दें जब दूसरी कार मुड़ने का संकेत दे, अन्यथा आप पहले चौराहे में प्रवेश कर सकते हैं"],"explanation":"At a T-intersection, the road that ends (the stem of the T) must yield to traffic on the through road that forms the top of the T, so you wait for the approaching car. The right-on-arrival rule applies only to vehicles arriving together at an equal, uncontrolled crossing, not to a side road meeting a through road."},"11":{"q":"आप टेक्सास में एक सिंगल-लेन गोलचक्कर (राउंडअबाउट) के पास पहुँचते हैं और आपकी बाईं ओर चक्र में पहले से दो कारें घूम रही हैं। सही और सुरक्षित तरीके से प्रवेश करने के लिए आपको क्या करना चाहिए?","options":["तुरंत प्रवेश करें और बाएँ (घड़ी की दिशा में) मुड़ें, क्योंकि चक्र में चल रहे वाहनों को प्रवेश करने वाले वाहनों को रास्ता देना होता है","पूरी तरह रुक जाएँ और प्रवेश करने से पहले चक्र के सारे यातायात के बाहर निकलने का इंतज़ार करें","चक्र में चल रही कारों को रास्ता दें, फिर जगह मिलने पर बाएँ (घड़ी की दिशा में) प्रवेश करें","चक्र में पहले से चल रही कारों को रास्ता दें, फिर जगह मिलने पर दाएँ (घड़ी की विपरीत दिशा में) प्रवेश करें"],"explanation":"At a roundabout you must yield to traffic already in the circle and enter to the right, traveling counter-clockwise. Option C uses the correct yield rule but the wrong direction, and you do not need a full stop or to wait for the circle to empty if a safe gap is available."},"12":{"q":"आप एक दो-लेन वाली, एकतरफ़ा शहरी सड़क की दाहिनी लेन में गाड़ी चला रहे हैं, तभी आपको सायरन सुनाई देता है और पीछे से एक एम्बुलेंस अपनी आपातकालीन बत्तियाँ जलाते हुए आती दिखती है। आपके दाहिनी ओर फुटपाथ के किनारे खाली जगह है। आपको क्या करना चाहिए?","options":["दाहिनी ओर गाड़ी रोककर तब तक रुके रहें जब तक एम्बुलेंस गुज़र न जाए।","अपनी गति बनाए रखें और अपनी लेन में बने रहें ताकि एम्बुलेंस आपको बाईं ओर से पार कर सके।","एक लेन दाहिनी ओर हो जाएं या गति को सीमा से 20 मील प्रति घंटा कम करके चलते रहें।","एम्बुलेंस के आपके पास पहुँचने से पहले आगे का चौराहा पार करने के लिए गति बढ़ा दें।"],"explanation":"When an emergency vehicle approaches with lights and siren, you must pull over to the right and stop until it passes. Option C describes the separate Move Over/Slow Down law for stopped emergency vehicles on the roadside, not for an emergency vehicle responding behind you, and the other choices fail to yield."},"13":{"q":"आप हरी बत्ती पर रुके हैं, ह्यूस्टन के एक व्यस्त चौराहे पर दाहिनी ओर मुड़ने का इंतज़ार कर रहे हैं। एक पैदल यात्री अभी-अभी फुटपाथ से उतरा है और क्रॉसवॉक से होकर उस लेन की ओर चल रहा है जिस पर आप मुड़ना चाहते हैं। आपको क्या करना चाहिए?","options":["हरी बत्ती होने के कारण पैदल यात्री के आपके रास्ते में आने से पहले जल्दी से मुड़ जाएं","क्रॉसवॉक में पैदल यात्री को रास्ता दें और तब तक प्रतीक्षा करें जब तक वह सुरक्षित रूप से आपका रास्ता साफ़ न कर दे","पहले हॉर्न बजाकर पैदल यात्री को जल्दी करने की चेतावनी दें और फिर आगे बढ़ें","क्रॉसवॉक की ओर आगे बढ़ें ताकि पैदल यात्री समझ जाए कि उसे आपके वाहन के पीछे से चलना है"],"explanation":"Pedestrians in a crosswalk always have the right of way, so you must yield and wait until they have safely cleared your path before turning, even on a green light. Having a green signal does not allow you to turn through a pedestrian who is already lawfully crossing, and honking or edging forward does not transfer that right of way to you."},"14":{"q":"आप हरी बत्ती पर रुके हुए हैं और दाएं मुड़ने की प्रतीक्षा कर रहे हैं। काला चश्मा पहने एक पैदल यात्री अपने सामने सफेद छड़ी घुमाते हुए फुटपाथ से क्रॉसवॉक में कदम रखता है और स्पष्ट रूप से आपके रास्ते को पार करने जा रहा है। आपको क्या करना चाहिए?","options":["मोड़ को धीरे-धीरे पूरा करें, क्योंकि हरी बत्ती आपके वाहन को पार करने वाले पैदल यात्रियों पर रास्ते का अधिकार देती है","पैदल यात्री को सचेत करने के लिए हॉर्न बजाएं, फिर उसके आपकी लेन तक पहुंचने से पहले अपना दायां मोड़ पूरा करें","पूरी तरह रुकें और रास्ता दें, सफेद छड़ी वाले पैदल यात्री को मुड़ने से पहले सुरक्षित रूप से पार करने दें","केवल तभी प्रतीक्षा करें जब पैदल यात्री पहले से आपकी लेन में हो, अन्यथा उसके सामने से मुड़ जाएं"],"explanation":"Texas law requires drivers to yield to a blind pedestrian using a white cane or guide dog, and pedestrians in a crosswalk always have the right of way. A green light does not override your duty to yield to a pedestrian lawfully in the crosswalk, so you must stop and let them cross."},"15":{"q":"आप एक चौराहे पर हरी बत्ती के पास पहुँच रहे हैं और सीधे आगे जाने वाले हैं। पार वाली सड़क से, हेडलाइट जलाए और छोटे झंडे लगाए कारों की एक कतार एक शव-वाहन के पीछे चल रही है, जो अंतिम-संस्कार जुलूस के रूप में अपनी लाल बत्ती के बावजूद धीरे-धीरे चौराहे में प्रवेश कर रही है। आपको क्या करना चाहिए?","options":["अपनी हरी बत्ती पर आगे बढ़ें, क्योंकि जुलूस के सामने लाल बत्ती है और उसे आपके लिए रुकना होगा","हॉर्न बजाएँ और अपनी बारी लेने के लिए आगे बढ़ें, फिर जुलूस की गाड़ियों के बीच की जगह में घुस जाएँ","दाईं ओर गाड़ी रोककर पूरी तरह रुक जाएँ जब तक पूरा जुलूस न गुज़र जाए, जैसा आप किसी आपातकालीन वाहन के लिए करते हैं","रास्ता दें और आगे बढ़ने से पहले पूरे अंतिम-संस्कार जुलूस के चौराहे से गुज़र जाने का इंतज़ार करें"],"explanation":"A funeral procession has the right of way at intersections, so you must yield and let the whole procession pass even though you have a green light. Proceeding on green ignores the procession's right of way, and pulling fully to the right is the rule for emergency vehicles with lights and siren, not a funeral procession."},"16":{"q":"आप एक शहर की सड़क पर गाड़ी चला रहे हैं और अगले चौराहे पर दाएं मुड़ने की योजना बना रहे हैं। आप सही तरीके से संकेत देना चाहते हैं ताकि अन्य चालक समय रहते आपके इरादे को समझ सकें। मुड़ने से पहले आपको किस बिंदु पर संकेत देना शुरू करना चाहिए?","options":["जहां आप मुड़ेंगे उस चौराहे से कम से कम 100 फीट पहले","जहां आप मुड़ेंगे उस चौराहे से कम से कम 20 फीट पहले","केवल तभी जब आप कर्ब के पास दाएं लेन में आ चुके हों","जहां आप मुड़ेंगे उस चौराहे से कम से कम 30 फीट पहले"],"explanation":"Texas law requires you to signal at least 100 feet before making a turn or changing lanes so other drivers have enough warning. The 20-foot and 30-foot distances are real Texas rules (no parking within 20 feet of a crosswalk, 30 feet of a stop sign), but they do not apply to signaling for a turn."},"17":{"q":"आप दो लेन वाली, एकतरफ़ा सड़क पर गाड़ी चला रहे हैं और आपको आने वाले चौराहे पर दाएँ मुड़ना है। मोड़ के लिए लेन के उपयोग को प्रतिबंधित करने वाला कोई संकेत नहीं है। मोड़ को सही ढंग से लेने के लिए आपको किस लेन में होना चाहिए और आपके वाहन की स्थिति कहाँ होनी चाहिए?","options":["बाईं लेन में, मुड़ते समय केंद्र रेखा के पास रहते हुए","दाईं लेन में, मुड़ते समय कर्ब के पास","किसी भी लेन में, बशर्ते आप मुड़ने से कम से कम 100 फीट पहले संकेत दें","दाईं लेन में, लेकिन साइकिल चालकों के लिए जगह छोड़ने हेतु कर्ब से अच्छी दूरी बनाए रखते हुए"],"explanation":"A right turn must be made from the right lane, keeping close to the curb. Option A describes the correct setup for a left turn, and signaling distance (Option C) does not change the lane and curb requirement for a right turn."},"18":{"q":"आप दोतरफा सड़क पर एक चौराहे के पास पहुंच रहे हैं और क्रॉस स्ट्रीट पर बाएं मुड़ने की योजना बना रहे हैं। आपकी दिशा में दो लेन हैं। मोड़ के लिए अपने वाहन को सही ढंग से स्थापित करने के लिए, चौराहे से पहले आपको किस लेन में जाना चाहिए?","options":["दाईं लेन में, कर्ब के पास रहते हुए","किसी भी लेन में, बशर्ते आप कम से कम 100 फीट पहले संकेत दें","बाईं लेन में, केंद्र रेखा के सबसे नजदीक","केंद्रीय दोतरफा बाएं-मोड़ लेन में, इसे चौराहे तक यात्रा के लिए उपयोग करते हुए"],"explanation":"A left turn must be made from the left lane, the one nearest the center line, so you cross the least amount of opposing traffic. The right lane is for right turns, and a two-way left-turn lane is only for turning, not for traveling up to an intersection on a two-way street with regular through lanes."},"19":{"q":"आप दाएं मुड़ने के इरादे से दाईं लेन में लाल बत्ती पर पूरी तरह रुक जाते हैं। चौराहे पर ऐसा कोई संकेत नहीं है जो लाल बत्ती पर मुड़ने से रोकता हो, और आड़ी (क्रॉस) यातायात साफ है। आपको क्या करना चाहिए?","options":["मुड़ने से पहले बत्ती के हरा होने का इंतजार करें, क्योंकि लाल बत्ती पर दाएं मुड़ना कभी भी अनुमत नहीं है।","केवल सामने से आने वाले यातायात को रास्ता देने के बाद ही मुड़ें, ठीक बाएं मोड़ की तरह।","बिना रुके मुड़ें, क्योंकि लेन पहले से ही आड़ी यातायात से साफ है।","अपनी पूरी रुकावट के बाद दायां मोड़ लें, क्योंकि कोई संकेत इसे प्रतिबंधित नहीं करता और यातायात साफ है।"],"explanation":"In Texas, a right turn on red is allowed after coming to a full stop, unless a sign prohibits it; with no such sign and clear traffic, you may turn. Option C is wrong because a complete stop is always required first, and the oncoming-traffic yield in B applies to left turns, not a right turn on red."},"20":{"q":"आप एकतरफ़ा (वन-वे) सड़क पर लाल बत्ती पर रुके हैं और किसी दूसरी एकतरफ़ा सड़क पर बाएँ मुड़ना चाहते हैं, जिसका यातायात बाईं ओर बहता है। चौराहे पर कोई संकेत इस मोड़ को प्रतिबंधित नहीं करता। आप कानूनी रूप से क्या कर सकते हैं?","options":["पूरी तरह रुकने के बाद, जब रास्ता साफ़ हो, बाएँ मुड़ें","बिना रुके बाएँ मुड़ें, क्योंकि दोनों सड़कें एकतरफ़ा हैं","हरी बत्ती का इंतज़ार करें, क्योंकि टेक्सास में लाल बत्ती पर बाएँ मुड़ना कभी अनुमत नहीं है","लाल बत्ती पर बाएँ तभी मुड़ें जब आप किसी दोतरफ़ा सड़क से भी आ रहे हों"],"explanation":"A left turn on red is allowed only from a one-way street onto a one-way street, and only after a full stop when no sign prohibits it. You may not roll through without stopping (B), and the turn is permitted in Texas in this exact situation, so waiting for green is not required (C)."},"21":{"q":"आप तीन लेन वाली एकतरफा सड़क की बीच वाली लेन में गाड़ी चला रहे हैं और आने वाले चौराहे पर दाएं मुड़ना है। आपको किस लेन से मोड़ पूरा करना चाहिए?","options":["बीच वाली लेन से, क्योंकि आप पहले से ही सड़क के केंद्र में स्थित हैं","सबसे दाईं लेन से, यानी जिस दिशा में आप मुड़ रहे हैं उसके सबसे नजदीक वाली लेन से","सबसे बाईं लेन से, क्योंकि एकतरफा सड़क पर सभी मोड़ बाईं ओर से शुरू होने चाहिए","किसी भी लेन से, क्योंकि एकतरफा सड़क पर लेन की स्थिति मायने नहीं रखती"],"explanation":"On a one-way street you turn from the lane nearest the direction you are turning, so a right turn must be made from the rightmost lane. Option C confuses this with the left-turn rule, and the left lane is correct only when turning left."},"22":{"q":"दो-लेन वाले राजमार्ग पर, आप एक धीमे ट्रक को ओवरटेक करने के लिए बाईं लेन में आते हैं। उसे पार करने के बाद, आप फिर से दाईं लेन में लौटना चाहते हैं। अपनी लेन में लौटना कब सुरक्षित है?","options":["जैसे ही आपका अगला बम्पर ट्रक के अगले हिस्से को पार कर ले","केवल तब जब ट्रक आपको वापस आने का संकेत देने के लिए अपनी हेडलाइट जलाए-बुझाए","जब आप ओवरटेक किए गए ट्रक को अपने रियरव्यू मिरर में देख सकें","जब आप ट्रक से कम से कम 100 फीट आगे निकल जाएं"],"explanation":"You may return to your lane only when you can see the passed vehicle in your rearview mirror, which confirms you have enough space ahead of it to merge safely. Clearing only your front bumper (A) leaves too little room and could cut the truck off, and there is no rule about a 100-foot distance for merging back."},"23":{"q":"आप एक धीमे ट्रैक्टर के पीछे दो-लेन वाली ग्रामीण सड़क पर गाड़ी चला रहे हैं। जैसे ही आप किसी पहाड़ी की चोटी के पास पहुँचते हैं, आगे की सड़क दिखाई नहीं देती और आप यह नहीं देख पाते कि कोई वाहन सामने से आ रहा है या नहीं। ट्रैक्टर को ओवरटेक करने के बारे में आपको क्या करना चाहिए?","options":["जल्दी से पहाड़ी पर ही ओवरटेक कर लें, क्योंकि ट्रैक्टर गति सीमा से काफी कम चल रहा है","सामने वाली लेन में जाने से बचने के लिए दाईं ओर की पटरी (शोल्डर) से ओवरटेक करें","अभी ओवरटेक करें, लेकिन सामने से आने वाले यातायात को सचेत करने के लिए हॉर्न बजाने के बाद ही","ओवरटेक न करें; तब तक प्रतीक्षा करें जब तक आप पहाड़ी पार न कर लें और आगे की सड़क साफ-साफ न देख सकें"],"explanation":"You must not pass on a hill where your view of oncoming traffic is blocked, so you should wait until you can see the road ahead clearly. Passing on the hill (A), sounding the horn (C), or using the right shoulder (B) are all unsafe and illegal because you still cannot verify the lane is clear and passing must be done on the left."},"24":{"q":"आप एक दो-लेन वाले ग्रामीण राजमार्ग पर एक धीमे ट्रक के पीछे चल रहे हैं और उसे ओवरटेक करना चाहते हैं। आगे दाईं ओर सड़क के किनारे आपको एक पीला, पताका के आकार का (नुकीला त्रिकोण) चिह्न दिखाई देता है। यह चिह्न आपको ओवरटेक करने के बारे में क्या बताता है?","options":["आप एक नो पासिंग ज़ोन में प्रवेश कर रहे हैं, इसलिए आपको यहाँ ट्रक को ओवरटेक नहीं करना चाहिए","यह एक यील्ड चिह्न है, इसलिए सामने से आने वाला यातायात साफ़ होने पर आप ओवरटेक कर सकते हैं","यह आगे एक दो-तरफ़ा बाएँ-मोड़ लेन को दर्शाता है जिसका उपयोग आप ओवरटेक करने के लिए कर सकते हैं","यह केवल एक रेलवे क्रॉसिंग की चेतावनी है, और ओवरटेक करना अभी भी अनुमत है"],"explanation":"A pennant-shaped sign on the right side of the road marks the start of a No Passing Zone, so you must not pass here. A Yield sign is a downward-pointing triangle facing oncoming drivers, not a side-mounted pennant, which makes option B the trap."},"25":{"q":"आप तीन लेन वाले टेक्सास फ्रीवे की बाईं लेन में निर्धारित गति सीमा पर गाड़ी चला रहे हैं। एक तेज़ वाहन आपके पीछे आता है और आगे निकलना चाहता है। आपको क्या करना चाहिए?","options":["अपनी गति बनाए रखें और बाईं लेन में ही रहें, क्योंकि आप पहले से ही कानूनी सीमा पर हैं","तेज़ वाहन को आगे निकलने देने के लिए अपनी दाईं ओर की लेन में चले जाएं, फिर दाईं ओर ही रहें","गति सीमा से ऊपर तेज़ हो जाएं ताकि पीछे वाले वाहन को आगे निकलने की ज़रूरत न रहे","बाईं लेन में रुक जाएं और तेज़ वाहन को हाथ से इशारा करके आगे निकलने के लिए कहें"],"explanation":"In Texas you must keep right except to pass, and slower traffic keeps right, so you should move into a lane to your right and let the faster vehicle pass. Staying in the left lane just because you are at the limit is wrong, and speeding up or stopping would create a hazard."},"26":{"q":"आप रात में एक अनजान दो-लेन वाली सड़क पर गाड़ी चला रहे हैं। आपकी बाईं ओर, यातायात वाली लेन के साथ-साथ एक ठोस पीली रेखा चलती है, और आप उस रेखा के दूसरी ओर अपनी ओर आ रही गाड़ियों की हेडलाइट देखते हैं। यह पीली केंद्रीय रेखा आपको सड़क के बारे में क्या बताती है?","options":["दूसरी ओर की लेन आपकी ही दिशा में जा रही है, इसलिए जब साफ हो तब आप उसमें मुड़कर मिल सकते हैं","सड़क एकतरफा है, और पीली रेखा बस सड़क के दूर वाले किनारे को दर्शाती है","रेखा के दूसरी ओर का यातायात विपरीत दिशा में, आपकी ओर चल रहा है","पीली रेखा केवल किनारे (शोल्डर) का निशान है, और उसके आगे कोई यातायात लेन नहीं है"],"explanation":"Yellow center lines divide traffic moving in opposite directions, which is why you see oncoming headlights across that line. White lines (not yellow) separate lanes traveling the same direction, so options suggesting same-direction or one-way travel are wrong."},"27":{"q":"आप एक चार-लेन वाली सड़क पर गाड़ी चला रहे हैं और देखते हैं कि आपकी लेन को आपके ठीक बाईं ओर की लेन से अलग करने वाली रेखा ठोस सफेद है, जबकि सड़क के बिल्कुल बीच से गुजरने वाली रेखा पीली है। आपके और आपकी बाईं ओर की लेन के बीच की सफेद रेखा उस बगल वाली लेन के बारे में आपको क्या बताती है?","options":["उस लेन में यातायात विपरीत दिशा में चल रहा है, इसलिए आपको कभी भी उसमें नहीं जाना चाहिए","आपकी बाईं ओर की लेन एक केंद्रीय दो-तरफा बाएं मुड़ने वाली लेन है, जो केवल मुड़ने के लिए है","आप किसी भी समय स्वतंत्र रूप से उस लेन में बदल सकते हैं क्योंकि सफेद रेखाएं हमेशा केवल सलाहकारी होती हैं","उस लेन में यातायात आपकी ही दिशा में चल रहा है"],"explanation":"White lines separate lanes of traffic traveling in the same direction, so the lane to your left carries traffic going your way. Yellow lines (option A) divide opposite-direction traffic and mark the center of the road, which is the trap here."},"28":{"q":"आपकी लेन में भारी ट्रैफ़िक जमा हो रहा है, इसलिए आप दोनों सिरों पर बाएँ-मुड़ने वाले तीरों से चिह्नित बीच वाली लेन में चले जाते हैं और धीमी कारों से आगे निकलने के लिए उसमें आधा ब्लॉक तक आगे बढ़ते हैं। यह अवैध क्यों है?","options":["दो-तरफ़ा बाएँ-मुड़ने वाली लेन केवल बाएँ मुड़ने के लिए आरक्षित है और इसका उपयोग आगे चलने के लिए नहीं किया जा सकता, चाहे थोड़ी देर के लिए ही क्यों न हो।","आप बीच वाली बाएँ-मुड़ने वाली लेन में केवल तभी चल सकते हैं जब आप उसमें 200 फ़ीट से कम रहें।","बीच वाली लेन एक ओवरटेकिंग लेन है, लेकिन आप इसका उपयोग केवल दाईं ओर से ओवरटेक करने के लिए कर सकते हैं।","बीच वाली लेन में गाड़ी चलाना तब तक अनुमत है जब तक आप कम से कम 100 फ़ीट पहले संकेत देते हैं।"],"explanation":"A two-way left-turn lane (the center lane marked with arrows) is only for preparing to turn left, never for driving through traffic. Option B invents a distance allowance, and the 100-foot signal rule in D applies to turns and lane changes, not to using this lane for travel."},"29":{"q":"आप एक चौराहे पर रुकने (स्टॉप) के संकेत के पास पहुँचते हैं। पैदल-पार पथ से कुछ फुट पहले सड़क पर एक स्पष्ट रूप से पुती हुई सफेद स्टॉप लाइन है, लेकिन वहाँ से एक खड़े ट्रक के कारण आड़ी यातायात का आपका दृश्य आंशिक रूप से बाधित है। सही प्रक्रिया क्या है?","options":["स्टॉप लाइन को धीरे-धीरे पार करें और तभी रुकें जब पैदल-पार पथ पर आड़ी यातायात दिखाई दे","पहले स्टॉप लाइन के पीछे पूरी तरह रुकें, फिर देखने के लिए आवश्यकता हो तो थोड़ा आगे बढ़कर दोबारा रुकें","लाइन पर गति लगभग 5 मील प्रति घंटा तक घटाएँ; पूरी तरह रुकना केवल तभी आवश्यक है जब कोई अन्य वाहन मौजूद हो","आड़ी यातायात का सर्वोत्तम दृश्य पाने के लिए पैदल-पार पथ पर ही रुकें"],"explanation":"Texas law requires a full stop at a stop sign behind the stop line or crosswalk, so you must stop there first even if your view is blocked, then creep forward and stop again to see. Rolling through the line, stopping on the crosswalk, or only slowing down all violate the stop-line requirement."},"30":{"q":"आप एक दो-लेन वाली सड़क पर चल रहे हैं जिसमें हर दिशा में एक लेन है और कोई मध्य विभाजक (मीडियन) नहीं है। आपके आगे, आपकी ही दिशा में, एक स्कूल बस रुकती है, अपनी चमकती लाल बत्तियाँ जलाती है और स्टॉप आर्म बाहर निकालती है। आपको क्या करना चाहिए?","options":["गति को गति सीमा से 20 मील प्रति घंटा कम करें और बस को बाईं ओर से सावधानी से पार करें","केवल तभी कम गति से चलते रहें जब बस के पास कोई बच्चा न दिखे","पूरी तरह रुक जाएँ और तब तक रुके रहें जब तक लाल बत्तियाँ चमकना बंद न कर दें और स्टॉप आर्म वापस अंदर न हो जाए","केवल तभी रुकें जब आप बस के पीछे हों; इस सड़क पर सामने से आने वाला यातायात आगे बढ़ सकता है"],"explanation":"On a road with no physical median or barrier, all traffic from both directions must stop for a school bus showing flashing red lights and an extended stop arm, and stay stopped until the lights stop and the arm folds in. Option D states the median exception, but here there is no median, so traffic from both directions must stop; the 20-mph-below rule in A applies to stopped emergency/utility vehicles, not school buses."},"31":{"q":"आपको देर हो रही है और शहर के एक व्यस्त डाउनटाउन रास्ते पर आपको कर्ब के पास एक खाली जगह दिखती है। उस जगह के ठीक आगे एक फायर हाइड्रेंट है। कानूनी रूप से पार्क करने के लिए, आपको अपने वाहन को हाइड्रेंट से कितनी दूरी पर रखना चाहिए?","options":["कम से कम 30 फीट, उतनी ही दूरी जितनी स्टॉप साइन या सिग्नल से आवश्यक होती है","कम से कम 20 फीट, उतनी ही दूरी जितनी चौराहे पर क्रॉसवॉक से आवश्यक होती है","जब तक आप फुटपाथ नहीं रोकते, हाइड्रेंट के बिल्कुल पास पार्क करना ठीक है","कम से कम 15 फीट"],"explanation":"टेक्सास का कानून फायर हाइड्रेंट के 15 फीट के भीतर पार्किंग पर रोक लगाता है ताकि आपातकाल में दमकलकर्मी उस तक पहुंच सकें। 30 फीट और 20 फीट की दूरियां टेक्सास में वास्तविक हैं, लेकिन वे क्रमशः स्टॉप साइन/सिग्नल और क्रॉसवॉक पर लागू होती हैं, हाइड्रेंट पर नहीं।"},"32":{"q":"आप एक चौराहे के पास, शहर के व्यस्त मुख्य बाज़ार की सड़क पर पार्क करने के लिए जगह ढूंढ रहे हैं। जहाँ साइड वाली सड़क मुख्य सड़क से मिलती है, वहाँ एक चिह्नित क्रॉसवॉक (पैदल पार पथ) है। कानूनी रूप से पार्क करने के लिए, आपके वाहन को उस क्रॉसवॉक से कितनी दूर रहना चाहिए?","options":["क्रॉसवॉक से कम से कम 20 फीट दूर","क्रॉसवॉक से कम से कम 15 फीट दूर","क्रॉसवॉक से कम से कम 30 फीट दूर","क्रॉसवॉक से कम से कम 10 फीट दूर"],"explanation":"Texas law prohibits parking within 20 feet of a crosswalk at an intersection so drivers turning into the street can see crossing pedestrians. The 15-foot figure is the no-parking distance for a fire hydrant, and 30 feet applies to a stop sign or signal, so both are real rules placed in the wrong situation."},"33":{"q":"आप एक व्यस्त डाउनटाउन सड़क पर पार्क करने के लिए जगह ढूंढ रहे हैं। आपको कोने के ठीक बगल में फुटपाथ का एक खाली हिस्सा दिखता है, जहां एक स्टॉप साइन (रुकें का चिह्न) लगा है। कानूनी रूप से पार्क करने के लिए, आपके वाहन को उस स्टॉप साइन से कम से कम कितनी दूरी पर होना चाहिए?","options":["कम से कम 15 फीट","कम से कम 30 फीट","कम से कम 20 फीट","कम से कम 50 फीट"],"explanation":"In Texas you may not park within 30 feet of a stop sign or traffic signal so your vehicle does not block other drivers' view of it. The 15-foot rule applies to fire hydrants and the 20-foot rule to crosswalks at an intersection, so those distances are traps from other parking rules."},"34":{"q":"आप देर से चल रहे हैं और सिर्फ एक मिनट के लिए कॉफी लेने के लिए अपनी कार छोड़ना चाहते हैं। चारों ओर देखने पर आपको ब्लॉक के साथ कई खाली जगहें दिखती हैं। इनमें से कौन-सी पार्किंग की वैध जगह है?","options":["एक चिह्नित क्रॉसवॉक के बीच में, क्योंकि आपकी कार का केवल कुछ हिस्सा बाहर निकलता है","किसी आवासीय ड्राइववे के ठीक सामने, क्योंकि आप केवल एक मिनट के लिए जाएंगे","दो-तरफा सड़क पर अपनी ओर के दाहिने कर्ब के साथ, किसी भी ड्राइववे, क्रॉसवॉक या हाइड्रेंट से दूर","बाएँ कर्ब के पास आती हुई ट्रैफिक की ओर मुँह करके, जहाँ एकमात्र खाली जगह है"],"explanation":"Parking is legal only when you are on the correct (right) side of the street and not blocking a driveway, crosswalk, sidewalk, hydrant, or traffic. Options A and B are prohibited because you may never park on a crosswalk or in front of a driveway, and D is illegal because parking against the left curb means facing the wrong way on a two-way street."},"35":{"q":"आप एक खड़ी सड़क पर पार्क करते हैं जो ऊपर की ओर चढ़ती है, और सड़क के दाहिने किनारे पर एक कर्ब (किनारा पट्टी) है। कार से उतरने से पहले, आपको अगले पहियों को किस दिशा में मोड़ना चाहिए?","options":["कर्ब की ओर, ताकि कार लुढ़कने पर टायर उससे टिक जाएं","सीधा, क्योंकि कर्ब अकेले ही कार को अपनी जगह पर रोक लेगा","तेजी से बाईं ओर, सड़क के बीच की ओर, ताकि टायर कर्ब से दूर रहें","कर्ब से दूर, ताकि लुढ़कती हुई कार वापस कर्ब की ओर आ जाए"],"explanation":"When parking uphill with a curb, turn the wheels away from the curb so that if the car rolls back, the front tire catches against the curb and stops it. Turning toward the curb is correct only when parking downhill, and the curb by itself is never a substitute for properly aimed wheels and a set parking brake."},"36":{"q":"आप अपनी कार को कर्ब वाली सड़क पर ढलान की ओर मुंह करके पार्क करते हैं। वाहन से बाहर निकलने से पहले, आपको अगले पहियों को किस दिशा में मोड़ना चाहिए?","options":["कर्ब की ओर, ताकि कार हिले तो कर्ब से टकराकर रुक जाए","कर्ब से दूर, ताकि कार हिले तो कर्ब की ओर लुढ़के","सीधा, क्योंकि पार्किंग ब्रेक कार को रोक लेगा","कर्ब की ओर केवल तभी जब आप सड़क के गलत किनारे पर भी हों"],"explanation":"When parking downhill next to a curb, turn the front wheels toward the curb so that if the car rolls, the curb blocks it. Turning the wheels away from the curb is the correct method for parking uphill, not downhill, which makes that option a common reversal trap."},"37":{"q":"एक समतल ग्रामीण सड़क के बजरी वाले किनारे पर आप फोन कॉल लेने के लिए रुकते हैं। यहाँ कोई कर्ब नहीं है, बस आपकी दाईं ओर नीचे की ओर ढलान वाला मिट्टी का किनारा है। वाहन से उतरने से पहले, आपको अपने अगले पहियों को किस ओर मोड़ना चाहिए?","options":["सीधा, क्योंकि सड़क समतल है और टिकाने के लिए कोई कर्ब नहीं है","किनारे की ओर (दाईं ओर), ताकि वाहन हिले तो सड़क से बाहर लुढ़क जाए","सड़क के केंद्र की ओर (बाईं ओर), ताकि यातायात आपके अगले पहिये देख सके","समतल सड़क पर इससे कोई फर्क नहीं पड़ता; बस पार्किंग ब्रेक लगाएँ और पहियों को वैसे ही छोड़ दें"],"explanation":"When parking where there is no curb, you should always turn the front wheels toward the shoulder (to the right) so the vehicle would roll away from traffic and off the road if it starts to move. Turning them straight or toward the road is wrong because, even on ground that looks flat, a rolling vehicle could drift into the travel lane and into oncoming traffic."},"38":{"q":"आप टेक्सास के दो-लेन वाले राजमार्ग पर 65 मील प्रति घंटे की गति से चल रहे हैं, तभी आपको आगे दाहिनी ओर के किनारे (शोल्डर) पर एक TxDOT रखरखाव ट्रक खड़ा दिखता है, जिसकी पीली बत्तियां चमक रही हैं। बाईं लेन में लगातार यातायात है, इसलिए आप सुरक्षित रूप से लेन नहीं बदल सकते। Move Over/Slow Down (लेन बदलें/गति धीमी करें) कानून आपसे क्या करने की अपेक्षा करता है?","options":["अपनी गति बनाए रखें लेकिन गुजरते समय श्रमिकों को चेतावनी देने के लिए हॉर्न बजाएं","ट्रक के पीछे पूरी तरह रुक जाएं और किसी श्रमिक द्वारा हाथ से इशारा करके जाने देने तक प्रतीक्षा करें","खड़े ट्रक को पार करने तक गति घटाकर 45 मील प्रति घंटे (गति सीमा से 20 मील प्रति घंटे कम) कर लें","गति घटाकर 20 मील प्रति घंटे करें और केवल तब आगे बढ़ें जब किनारा (शोल्डर) खाली हो"],"explanation":"When you cannot safely move over a lane, Texas's Move Over/Slow Down law requires you to slow to 20 mph below the posted speed limit, which is 45 mph in a 65 mph zone. Option D wrongly uses 20 mph itself (a school-zone figure) instead of 20 mph below the limit, and stopping or just honking is not required."}},"learn-rules-of-the-road":{"0":{"q":"टेक्सास के मूल गति कानून के तहत, आप कितनी तेज़ गाड़ी चला सकते हैं?","options":["कभी भी मौजूदा परिस्थितियों के लिए सुरक्षित गति से अधिक तेज़ नहीं","हमेशा बिल्कुल निर्धारित गति सीमा पर","जितनी तेज़ आपका वाहन अनुमति दे","यदि यातायात कम हो तो सीमा से 10 मील प्रति घंटा अधिक"],"explanation":"Texas's basic speed law means you must never drive faster than is safe for the current conditions."},"1":{"q":"टेक्सास में, जहां कोई संकेत नहीं लगा है, ऐसे शहरी क्षेत्र में डिफ़ॉल्ट गति सीमा क्या है?","options":["20 मील प्रति घंटा","30 मील प्रति घंटा","45 मील प्रति घंटा","55 मील प्रति घंटा"],"explanation":"Where unposted, the default speed limit in a Texas urban district is 30 mph."},"2":{"q":"दिन के समय बिना संकेत वाली नंबर वाली राजमार्ग पर डिफ़ॉल्ट गति सीमा क्या है?","options":["30 मील प्रति घंटा","55 मील प्रति घंटा","70 मील प्रति घंटा","85 मील प्रति घंटा"],"explanation":"Where unposted, the default daytime speed limit on numbered highways is 70 mph."},"3":{"q":"टेक्सास के कुछ टोलवे पर अनुमत सबसे अधिक गति सीमा क्या है?","options":["65 mph","70 mph","75 mph","85 mph"],"explanation":"Some specific Texas tollways are posted with speed limits as high as 85 mph."},"4":{"q":"स्कूल ज़ोन में जब लाइटें चमक रही हों या बच्चे मौजूद हों तो आपको क्या करना चाहिए?","options":["लगाई गई कम गति सीमा का पालन करें","सामान्य गति सीमा पर गाड़ी चलाएं","क्षेत्र से निकलने के लिए गति बढ़ाएं","पूरी तरह रुकें और प्रतीक्षा करें"],"explanation":"In a school zone you must obey the posted reduced limit (often 20 mph) when lights flash or children are present."},"5":{"q":"टेक्सास में सक्रिय स्कूल ज़ोन में हाथ में पकड़ा फोन इस्तेमाल करना क्या कानूनी है?","options":["हाँ, हमेशा","नहीं, यह गैरकानूनी है","केवल रात 9 बजे के बाद","केवल पास में पार्क करते समय"],"explanation":"Using a handheld phone in an active school zone is illegal in Texas."},"6":{"q":"आपको अपनी गाड़ी की गति कब कम करनी चाहिए?","options":["केवल सूखे, खाली राजमार्गों पर","केवल जब कोई पैदल यात्री न हो","बारिश, कोहरे, भारी यातायात, मोड़ों पर और पैदल यात्रियों के पास","केवल रात में सीधी सड़कों पर"],"explanation":"You should always reduce speed in rain, fog, heavy traffic, on curves, and near pedestrians."},"7":{"q":"बिना नियंत्रण वाले चौराहे पर किस वाहन को रास्ते का अधिकार होता है?","options":["तेज़ चलने वाला वाहन","बड़ा वाहन","बाईं ओर का वाहन","जो वाहन पहले पहुंचा"],"explanation":"At an uncontrolled intersection, you yield to the vehicle that arrived first."},"8":{"q":"बिना नियंत्रण वाले चौराहे पर, यदि दो वाहन एक ही समय पर पहुँचते हैं, तो रास्ता देने का अधिकार किसका होता है?","options":["दाईं ओर का चालक","बाईं ओर का चालक","तेज़ वाहन","बड़ा वाहन"],"explanation":"When two vehicles arrive at the same time, yield to the driver on your right."},"9":{"q":"बाएं मुड़ते समय, आपको किसे रास्ता देना चाहिए?","options":["केवल पैदल चलने वालों को","सामने से आने वाले यातायात और पैदल चलने वालों को","केवल आपके पीछे आने वाले यातायात को","किसी को नहीं, रास्ता आपका है"],"explanation":"When turning left, you must yield to oncoming traffic and to pedestrians."},"10":{"q":"T-चौराहे पर किस यातायात को रास्ते का अधिकार होता है?","options":["बाएं मुड़ने वाला यातायात","बाईं ओर का वाहन","सीधी सड़क का यातायात","सबसे बाद में आने वाला"],"explanation":"Traffic on the through road (the top of the T) has the right of way."},"11":{"q":"गोलचक्कर पर किसे रास्ते का अधिकार है?","options":["प्रवेश के लिए प्रतीक्षा कर रहे चालक","तेज़ चलने वाला वाहन","जो पहले हॉर्न बजाए","जो यातायात पहले से गोलचक्कर में है"],"explanation":"At a roundabout, you must yield to traffic already in the circle before entering."},"12":{"q":"जब कोई आपातकालीन वाहन लाइट और सायरन के साथ नज़दीक आए तो आपको क्या करना चाहिए?","options":["दाईं ओर हटकर रुक जाएं जब तक वह गुज़र न जाए","रास्ता छोड़ने के लिए गति बढ़ा दें","अपनी लेन के बीच में रुक जाएं","उसके सामने बाईं ओर मुड़ जाएं"],"explanation":"Pull over to the right and stop until the emergency vehicle has passed."},"13":{"q":"क्रॉसवॉक में किसे रास्ते का अधिकार होता है?","options":["सबसे नज़दीकी वाहन","पैदल यात्री","तेज़ चलने वाला वाहन","मुड़ने वाले वाहन"],"explanation":"Pedestrians in a crosswalk always have the right of way."},"14":{"q":"सफेद छड़ी लिए हुए या गाइड कुत्ते का उपयोग करने वाले किसे आपको रास्ता देना चाहिए?","options":["एक खड़ी कार को","एक सड़क कर्मचारी को","एक नेत्रहीन पैदल यात्री को","एक साइकिल चालक को"],"explanation":"You must yield to a blind pedestrian carrying a white cane or using a guide dog."},"15":{"q":"अंतिम संस्कार के जुलूस के दौरान चौराहों पर किसका रास्ते का अधिकार होता है?","options":["आड़ा यातायात","जो पहले पहुंचे","दाईं ओर का चालक","अंतिम संस्कार का जुलूस"],"explanation":"A funeral procession has the right of way at intersections."},"16":{"q":"मोड़ या लेन बदलने से कितनी दूरी पहले संकेत देना चाहिए?","options":["कम से कम 100 फीट","कम से कम 25 फीट","कम से कम 250 फीट","कम से कम 500 फीट"],"explanation":"In Texas, you must signal at least 100 feet before a turn or lane change."},"17":{"q":"दाएं मुड़ने के लिए आपको कौन सी लेन का उपयोग करना चाहिए?","options":["बाईं लेन","दाईं लेन, कर्ब के पास","बीच की लेन","कोई भी खाली लेन"],"explanation":"A right turn should be made from the right lane, close to the curb."},"18":{"q":"बायाँ मोड़ किस लेन से लेना चाहिए?","options":["दायीं लेन से","बीच की लेन से","बायीं लेन से","किसी भी खाली लेन से"],"explanation":"A left turn should be made from the left lane."},"19":{"q":"टेक्सास में लाल बत्ती पर दाहिनी ओर मुड़ना कब अनुमत है?","options":["कभी नहीं, किसी भी स्थिति में नहीं","केवल रात में","पहले रुके बिना","पूरी तरह रुकने के बाद, जब तक कोई संकेत इसे मना न करे"],"explanation":"A right turn on red is allowed after coming to a full stop, unless a sign prohibits it."},"20":{"q":"टेक्सास में लाल बत्ती पर बाएं मुड़ने की अनुमति कब है?","options":["पूरी तरह रुकने के बाद, एकतरफा सड़क से एकतरफा सड़क पर","पूरी तरह रुकने के बाद, किसी भी सड़क से","पूरी तरह रुकने के बाद, दोतरफा सड़क पर","कभी नहीं, किसी भी स्थिति में नहीं"],"explanation":"In Texas, a left turn on red is only allowed from a one-way street onto a one-way street after stopping fully."},"21":{"q":"एकतरफ़ा सड़क पर आपको किस लेन से मुड़ना चाहिए?","options":["बीच वाली लेन से","जिस दिशा में आप मुड़ रहे हैं उसके सबसे नज़दीक की लेन से","किसी भी खाली लेन से","अपने मोड़ से सबसे दूर वाली लेन से"],"explanation":"On a one-way street, turn from the lane nearest the direction you are turning."},"22":{"q":"आपको दूसरे वाहन को किस ओर से पास करना चाहिए?","options":["दाईं ओर से","किसी भी ओर से","बाईं ओर से","किनारे से"],"explanation":"You should pass on the left and return to your lane only when you can see the passed vehicle in your mirror."},"23":{"q":"आपको दूसरे वाहन को कहाँ नहीं ओवरटेक करना चाहिए?","options":["सीधी, समतल सड़क पर","जब लेन साफ हो","चौड़ी सड़क पर","पहाड़ी या मोड़ पर"],"explanation":"You must not pass on a hill or curve because you cannot see oncoming traffic."},"24":{"q":"आपको दूसरे वाहन को कहाँ नहीं ओवरटेक करना चाहिए?","options":["चौराहे या रेलवे क्रॉसिंग पर","लंबी, सीधी और समतल सड़क पर","स्पष्ट रूप से चिह्नित ओवरटेकिंग लेन पर","जहाँ आपकी ओर टूटी हुई पीली रेखा हो"],"explanation":"It is unsafe and illegal to pass at an intersection or railroad crossing."},"25":{"q":"आप दूसरे वाहन को कब ओवरटेक कर सकते हैं?","options":["जब आपकी ओर एक ठोस पीली रेखा हो","जब आपकी ओर की रेखा टूटी हुई हो","पहाड़ी या मोड़ पर","रेलवे क्रॉसिंग पर"],"explanation":"You may pass when the yellow line on your side is broken, but not where a solid yellow line is on your side."},"26":{"q":"नो पासिंग ज़ोन को चिह्नित करने वाले संकेत का आकार कैसा होता है?","options":["गोल","चौकोर","पताका (त्रिकोण)","हीरा"],"explanation":"A No Passing Zone is marked by a pennant-shaped (triangular) sign, where passing is not allowed."},"27":{"q":"बहु-लेन वाली सड़क पर धीमे यातायात को कौन सी लेन का उपयोग करना चाहिए?","options":["बायीं लेन","बीच की लेन","कोई भी लेन जो वे चुनें","दायीं लेन"],"explanation":"Keep right except to pass; slower traffic stays in the right lane."},"28":{"q":"सड़क पर पीली केंद्र रेखाएँ किसे अलग करती हैं?","options":["विपरीत दिशाओं में चलने वाला यातायात","एक ही दिशा में चलने वाला यातायात","पार्किंग स्थानों को यातायात लेन से","साइकिल लेन को फुटपाथ से"],"explanation":"Yellow center lines divide traffic moving in opposite directions."},"29":{"q":"सड़क पर सफेद रेखाएं किसे अलग करती हैं?","options":["विपरीत दिशाओं में जाने वाला यातायात","एक ही दिशा में जाने वाली यातायात लेन","पार्किंग स्थानों को सड़क से","सड़क को फुटपाथ से"],"explanation":"White lines separate lanes of traffic moving in the same direction."},"30":{"q":"बाएं मुड़ने के तीरों से चिह्नित बीच वाली लेन का उपयोग किसके लिए होता है?","options":["दूसरी कारों से आगे निकलने के लिए","यातायात में सीधे चलने के लिए","केवल बाएं मुड़ने के लिए","अपना वाहन पार्क करने के लिए"],"explanation":"A two-way left-turn lane is only for turning left, not for travel."},"31":{"q":"रुकने (स्टॉप) के संकेत पर, आपको पूरी तरह कहाँ रुकना चाहिए?","options":["चौराहे के बीच में","जहाँ भी आपको सुरक्षित लगे","क्रॉसवॉक पार करने के बाद","स्टॉप लाइन या क्रॉसवॉक के पीछे"],"explanation":"At a stop sign you must come to a full stop behind the stop line or crosswalk."},"32":{"q":"रुकी हुई स्कूल बस के लिए आपको कब रुकना चाहिए?","options":["जब उसकी लाल बत्तियाँ चमक रही हों और स्टॉप आर्म बाहर हो","केवल जब बच्चे सड़क पार कर रहे हों","केवल यदि आप सीधे उसके पीछे हों","कभी नहीं, आप धीरे से निकल सकते हैं"],"explanation":"You must stop for a stopped school bus when its red lights are flashing and its stop arm is out."},"33":{"q":"लाल बत्तियां चमकाते हुए रुके स्कूल बस के लिए आपको कब रुकना चाहिए?","options":["केवल तभी जब आप बस के पीछे हों","दोनों दिशाओं से, जब तक कोई मीडियन सड़कों को अलग न करे","कभी नहीं, बस गति धीमी करें","केवल तभी जब बच्चे सड़क पार कर रहे हों"],"explanation":"You must stop from both directions unless a physical median or barrier separates the roadways."},"34":{"q":"आप अग्निशमन हाइड्रेंट के कितने पास पार्क कर सकते हैं?","options":["5 फीट के भीतर","10 फीट के भीतर","15 फीट से अधिक पास नहीं","ठीक उसके बगल में"],"explanation":"You may not park within 15 feet of a fire hydrant."},"35":{"q":"चौराहे पर पैदल पार पथ से कितनी दूरी के भीतर आप पार्क नहीं कर सकते?","options":["5 फीट","10 फीट","15 फीट","20 फीट"],"explanation":"You may not park within 20 feet of a crosswalk at an intersection."},"36":{"q":"आप स्टॉप साइन के कितने पास पार्क कर सकते हैं?","options":["30 फीट से अधिक पास नहीं","5 फीट से अधिक पास नहीं","10 फीट से अधिक पास नहीं","15 फीट से अधिक पास नहीं"],"explanation":"In Texas, you may not park within 30 feet of a stop sign or signal."},"37":{"q":"आप अपना वाहन कहाँ पार्क नहीं कर सकते?","options":["चिह्नित पार्किंग स्थान में","क्रॉसवॉक या फुटपाथ पर","दाएँ किनारे के साथ","पार्किंग गैरेज में"],"explanation":"It is illegal to park on a crosswalk or sidewalk."},"38":{"q":"पार्किंग कहाँ करने की अनुमति नहीं है?","options":["एक शांत बगल वाली गली में","एक चिह्नित पार्किंग स्थल में","एक ड्राइववे के सामने","एक पार्किंग मीटर के बगल में"],"explanation":"You may not park in front of a driveway."},"39":{"q":"पार्किंग कहाँ नहीं की जा सकती?","options":["सड़क के दाहिनी ओर","चिह्नित पार्किंग स्थान में","पार्किंग मीटर के पास","सड़क के गलत ओर"],"explanation":"You may not park on the wrong side of the street."},"40":{"q":"आपको कहाँ पार्क करने की अनुमति नहीं है?","options":["जहाँ आप यातायात को अवरुद्ध करेंगे","चिह्नित पार्किंग स्थान में","पार्किंग गैरेज में","अपने स्वयं के ड्राइववे में"],"explanation":"You may not park where you would be blocking traffic."},"41":{"q":"किसी कर्ब के पास चढ़ाई पर पार्क करते समय आपको अपने पहिए किस ओर मोड़ने चाहिए?","options":["सीधे आगे","कर्ब से दूर की ओर","कर्ब की ओर","इससे कोई फर्क नहीं पड़ता"],"explanation":"When parking uphill with a curb, turn your wheels away from the curb so the car rolls into the curb if it moves."},"42":{"q":"किनारे (कर्ब) के पास ढलान में नीचे की ओर पार्क करते समय आपको अगले पहिये किस दिशा में मोड़ने चाहिए?","options":["सीधे आगे की ओर","कर्ब से दूर","कर्ब की ओर","इससे कोई फर्क नहीं पड़ता"],"explanation":"When parking downhill with a curb, turn your wheels toward the curb so the car rolls into it if it moves."},"43":{"q":"बिना किनारे (कर्ब) वाली ढलान पर पार्क करते समय आप अपने पहिये किस ओर मोड़ते हैं?","options":["सीधा आगे की ओर","सड़क के बीच की ओर","इससे कोई फर्क नहीं पड़ता","किनारे की ओर (दाईं ओर)"],"explanation":"Without a curb, always turn your wheels toward the shoulder/right so the car rolls off the road if it moves."},"44":{"q":"मूव ओवर कानून के तहत, चमकती लाइटों वाले रुके हुए आपातकालीन वाहन के लिए आपको कितना धीमा होना चाहिए?","options":["गति सीमा से 20 मील प्रति घंटा कम","गति सीमा से 5 मील प्रति घंटा कम","गति सीमा से 10 मील प्रति घंटा कम","पूरी तरह रुकने तक"],"explanation":"You must move over a lane or slow to 20 mph below the speed limit for stopped emergency vehicles."},"45":{"q":"बिना नियंत्रण वाले चौराहे पर किसे रास्ता देने का अधिकार है?","options":["तेज़ चलने वाला वाहन","वह वाहन जो पहले पहुँचा","बड़ा वाहन","बाईं ओर का वाहन"],"explanation":"At an uncontrolled intersection, yield to the vehicle that arrived first."},"46":{"q":"मुड़ने या लेन बदलने से कितनी दूरी पहले आपको संकेत देना चाहिए?","options":["कम से कम 25 फीट","कम से कम 50 फीट","कम से कम 100 फीट","कम से कम 200 फीट"],"explanation":"In Texas, you must signal at least 100 feet before turning or changing lanes."},"47":{"q":"स्कूल ज़ोन में आमतौर पर कौन सी गति सीमा दर्शाई जाती है?","options":["40 मील प्रति घंटा","55 मील प्रति घंटा","70 मील प्रति घंटा","20 मील प्रति घंटा"],"explanation":"The reduced school zone speed limit is commonly posted at 20 mph."},"48":{"q":"ओवरटेक करने के बाद, आप सुरक्षित रूप से अपनी लेन में कब लौट सकते हैं?","options":["जब आप ओवरटेक किए गए वाहन को अपने रियरव्यू मिरर में देख सकें","जैसे ही आप ओवरटेक करना समाप्त करें","जब ओवरटेक किया गया वाहन हॉर्न बजाए","30 सेकंड प्रतीक्षा करने के बाद"],"explanation":"You may return to your lane once you can see the passed vehicle in your rearview mirror."},"49":{"q":"गोल चक्कर में, आप वृत्त के चारों ओर किस दिशा में चलते हैं?","options":["घड़ी की दिशा में","घड़ी की विपरीत दिशा में","किसी भी दिशा में","सीधे आर-पार"],"explanation":"In a roundabout, traffic moves around the circle counter-clockwise."},"50":{"q":"आप अग्निशमन हाइड्रेंट के कितने पास पार्क कर सकते हैं?","options":["कोई सीमा नहीं","5 फीट","15 फीट","50 फीट"],"explanation":"You may not park within 15 feet of a fire hydrant."},"51":{"q":"मूव ओवर / स्लो डाउन कानून चमकती लाइटों वाले किस प्रकार के वाहन की भी रक्षा करता है?","options":["डिलीवरी वैन","स्कूल बसें","शहर की बसें","उपयोगिता वाहन"],"explanation":"The Move Over / Slow Down law also covers utility vehicles, along with emergency, tow, and TxDOT vehicles."},"52":{"q":"टेक्सास में सबसे अधिक पोस्ट की गई गति सीमा क्या है?","options":["80 से 85 मील प्रति घंटा","55 मील प्रति घंटा","65 मील प्रति घंटा","70 मील प्रति घंटा"],"explanation":"Some specific Texas tollways are posted at 80 to 85 mph, the highest posted limits in the state."},"53":{"q":"लाल बत्ती पर दाएं मुड़ने से पहले आपको क्या करना चाहिए?","options":["जल्दी शामिल होने के लिए गति बढ़ाएं","पहले पूरी तरह रुकें","अन्य चालकों को चेतावनी देने के लिए हॉर्न बजाएं","अपनी हेडलाइट बंद कर दें"],"explanation":"A right turn on red is allowed only after coming to a full stop, unless a sign prohibits it."},"54":{"q":"नो पासिंग ज़ोन का चिह्न किस आकार का होता है?","options":["गोल","चौकोर","पताका (त्रिकोणीय)","हीरे जैसा"],"explanation":"A No Passing Zone is marked by a pennant-shaped (triangular) sign."},"55":{"q":"T-चौराहे पर रास्ते का अधिकार किसका होता है?","options":["T के तने से आने वाला यातायात","तेज़ चलने वाला वाहन","बाईं ओर का वाहन","मुख्य सड़क पर चलने वाला यातायात"],"explanation":"Traffic on the through road (top of the T) has the right of way."},"56":{"q":"ढलान पर नीचे की ओर पार्क करते समय अगले पहियों को किस ओर मोड़ना चाहिए?","options":["किनारे (कर्ब) की ओर","किनारे (कर्ब) से दूर","सीधा","इससे कोई फर्क नहीं पड़ता"],"explanation":"Turning the wheels toward the curb lets the curb block the vehicle if it rolls."},"57":{"q":"मूल गति कानून के अनुसार, क्या कानूनी अधिकतम गति बोर्ड पर लिखी संख्या से कम हो सकती है?","options":["नहीं, बोर्ड पर लिखी संख्या हमेशा कानूनी अधिकतम होती है","हाँ, जब परिस्थितियाँ बोर्ड की गति को असुरक्षित बना दें","नहीं, केवल पुलिस ही इसे कम कर सकती है","हाँ, लेकिन केवल रात में"],"explanation":"The basic speed law requires a speed safe for conditions, so the legal limit can fall below the posted number when conditions make it unsafe."},"58":{"q":"बाएं मुड़ते समय आपको किसे रास्ता देना चाहिए?","options":["केवल सामने से आने वाले वाहनों को","केवल पैदल चलने वालों को","सामने से आने वाले वाहनों और पैदल चलने वालों को","किसी को नहीं"],"explanation":"A driver turning left must yield to both oncoming vehicles and pedestrians before completing the turn."},"59":{"q":"मूव ओवर / स्लो डाउन कानून के तहत, चमकती बत्तियों वाले रुके हुए आपातकालीन वाहन के पास से गुजरते समय चालक के पास कौन से दो विकल्प होते हैं?","options":["पूरी तरह रुकें या दो बार हॉर्न बजाएं","हैज़र्ड लाइट जलाएं या हाई बीम चमकाएं","गति बढ़ाएं या लेन बदलें","एक लेन हटें या सीमा से 20 मील प्रति घंटा कम करें"],"explanation":"The Move Over / Slow Down law lets you move over one lane away or slow to 20 mph below the speed limit."}},"signals-and-markings":{"0":{"q":"आप एक चौराहे पर पहुंचते हैं और आपके सामने वाला ट्रैफिक सिग्नल स्थिर हरी बत्ती दिखा रहा है। आप सामने से आ रहे यातायात को पार करते हुए बाएं मुड़ना चाहते हैं, लेकिन कई गाड़ियां चौराहे से होकर आपकी ओर आ रही हैं। कानूनी रूप से आपको क्या करने की अनुमति है?","options":["सीधे आगे बढ़ें या अपना मोड़ लें, लेकिन पहले सामने से आ रही गाड़ियों और चौराहे में पहले से मौजूद किसी भी यातायात को रास्ता दें।","तुरंत बाएं मुड़ें, क्योंकि स्थिर हरी बत्ती आपको एक संरक्षित मोड़ देती है और सामने से आ रहे यातायात को आपके लिए रुकना होगा।","लाइन के पीछे पूरी तरह रुकें और प्रतीक्षा करें, हरी बत्ती को चमकती लाल बत्ती की तरह मानते हुए जब तक सामने से आ रही गाड़ियां न निकल जाएं।","धीमे हो जाएं और रास्ता दिए बिना सावधानी से आगे बढ़ें, क्योंकि स्थिर हरी बत्ती चमकती पीली बत्ती की तरह ही काम करती है।"],"explanation":"A steady green means go only when the intersection is clear; you may proceed straight or turn, but you must yield to oncoming traffic and vehicles already in the intersection. Option B is the trap: only a green arrow gives a protected turn where oncoming traffic is stopped, not a steady green light."},"1":{"q":"आप गति सीमा पर एक चौराहे की ओर गाड़ी चला रहे हैं, तभी हरी बत्ती स्थिर पीली बत्ती में बदल जाती है। आप अभी भी लगभग आधे ब्लॉक की दूरी पर हैं और आपके पीछे की सड़क खाली है। आपको क्या करना चाहिए?","options":["बत्ती लाल होने से पहले चौराहा पार करने के लिए गति बढ़ा दें","यदि आप सुरक्षित रूप से ऐसा कर सकते हैं तो चौराहे से पहले रुक जाएं, क्योंकि बत्ती लाल होने वाली है","इसे चमकती पीली बत्ती की तरह मानें और बिना रुके सावधानी से आगे बढ़ें","पूरी तरह रुकें और फिर रास्ता साफ होने पर आगे बढ़ें, जैसा आप चमकती लाल बत्ती के लिए करते हैं"],"explanation":"A steady yellow light warns that the signal is about to turn red, so you should stop if you can do so safely and never speed up to beat the light. Option C describes a flashing yellow (caution) and Option D describes a flashing red (stop sign), which are different signals."},"2":{"q":"आप एक चौराहे के पास पहुँच रहे हैं और जब आप अंकित स्टॉप लाइन से थोड़ी दूरी पर ही हैं, तभी आपके सामने का ट्रैफ़िक सिग्नल स्थिर लाल हो जाता है। मुड़ने पर रोक लगाने वाला कोई संकेत नहीं है और आप सीधे आगे जाना चाहते हैं। आपको क्या करना चाहिए?","options":["गति धीमी करके बिना रुके सावधानी से चौराहा पार करें, क्योंकि सिग्नल जल्द ही बदल सकता है","केवल तभी रुकें जब आड़ा यातायात हो, फिर लाल बत्ती पर सीधे आगे निकल जाएँ","स्टॉप लाइन के पीछे पूरी तरह रुक जाएँ और सिग्नल के हरा होने तक रुके रहें","सिग्नल को स्टॉप संकेत की तरह मानें, पूरी तरह रुकें, फिर रास्ता साफ़ होने पर सीधे आगे बढ़ें"],"explanation":"स्थिर लाल बत्ती पर आपको स्टॉप लाइन के पीछे पूरी तरह रुकना होगा और सिग्नल के हरा होने तक रुके रहना होगा। विकल्प D चमकती लाल बत्ती (जिसे स्टॉप संकेत की तरह माना जाता है) का वर्णन करता है, न कि स्थिर लाल का, इसलिए स्थिर लाल पर सीधे आगे बढ़ना ग़लत है।"},"3":{"q":"आप दाईं लेन में हैं और एक चौराहे के पास पहुँच रहे हैं जहाँ स्थिर लाल बत्ती जल रही है। आप दाएँ मुड़ना चाहते हैं। मुड़ने से रोकने वाला कोई संकेत नहीं है, और आड़ी दिशा के यातायात में जगह है। आपको क्या करना चाहिए?","options":["गति धीमी करें और बिना रुके दाएँ मुड़ें, क्योंकि आड़ी दिशा के यातायात में जगह है","इसे स्टॉप संकेत की तरह मानें, फिर केवल तभी दाएँ मुड़ें जब हरा तीर दिखाई दे","दाएँ मुड़ने से पहले बत्ती के हरा होने का इंतज़ार करें, क्योंकि लाल बत्ती पर कभी भी मुड़ा नहीं जा सकता","लाइन के पीछे पूरी तरह रुकें, फिर दाएँ मुड़ें क्योंकि रास्ता साफ़ है और कोई संकेत इसे प्रतिबंधित नहीं करता"],"explanation":"At a steady red light you must stop completely behind the line, and a right turn is permitted only after that full stop when the way is clear and no sign prohibits it. Option A skips the required full stop, and option C wrongly claims right-on-red is never allowed."},"4":{"q":"देर रात आप एक चौराहे के पास पहुँचते हैं और ऊपर लगा ट्रैफ़िक सिग्नल हर दिशा में लाल रंग में चमक (फ्लैश) रहा है। आसपास कोई अन्य वाहन नहीं है। आपको क्या करना चाहिए?","options":["पूरी तरह रुकें, फिर जब सुरक्षित हो तब चौराहे को पार करें।","गति धीमी करें, दोनों ओर देखें और रास्ता साफ़ होने के कारण बिना रुके निकल जाएँ।","रुकें और तब तक रुके रहें जब तक चमकती लाल बत्ती स्थिर हरी बत्ती में न बदल जाए।","इसे 'रास्ता दें' (यील्ड) के संकेत की तरह मानें और केवल तभी पार करें जब कोई अन्य वाहन आ रहा हो।"],"explanation":"A flashing red light means the same thing as a stop sign: you must come to a full stop and then proceed when it is safe. Option B is wrong because a flashing red always requires a complete stop (rolling through is the rule for a flashing yellow), and option C is wrong because a flashing red signal will not turn green."},"5":{"q":"देर रात आप एक चौराहे के पास पहुँचते हैं जहाँ ट्रैफ़िक सिग्नल अपने सामान्य चक्र में नहीं चल रहा है और इसके बजाय आपकी लेन के ऊपर लगातार चमकती हुई पीली बत्ती दिखा रहा है। आपको क्या करना चाहिए?","options":["लाइन के पीछे पूरी तरह रुकें, और फिर रास्ता साफ़ होने पर आगे बढ़ें, जैसे आप स्टॉप साइन पर करते हैं।","गति धीमी करें और बिना रुके सावधानी से चौराहे को पार करें, क्रॉस ट्रैफ़िक पर नज़र रखते हुए।","चौराहे को सभी दिशाओं के स्टॉप की तरह मानें क्योंकि सिग्नल सामान्य रूप से नहीं चल रहा है।","रुकें और तब तक रुके रहें जब तक सिग्नल वापस स्थिर हरी बत्ती पर न आ जाए।"],"explanation":"A flashing YELLOW light means caution, so you slow down and proceed carefully through the intersection without coming to a stop. A flashing RED light is the one that means a full stop like a stop sign, and a completely dark or non-working signal is the one treated as an all-way stop, so those are the wrong responses here."},"6":{"q":"आप एक चौराहे पर बाएँ मुड़ने की प्रतीक्षा में रुके हुए हैं। आपका सिग्नल स्थिर लाल बत्ती था, लेकिन वह अभी-अभी बदलकर उस दिशा में इशारा करता हुआ हरा बायाँ-मोड़ तीर बन गया जिस ओर आप जाना चाहते हैं। यह आपको आगे कैसे बढ़ना है, इसके बारे में क्या बताता है?","options":["आप बाएँ मुड़ सकते हैं, लेकिन पहले आपको उस सामने से आने वाले यातायात को रास्ता देना होगा जिसके पास अधिकार है","आपको पूरी तरह रुककर प्रतीक्षा करनी चाहिए, क्योंकि तीर सिग्नल का अर्थ है कि उस दिशा में मुड़ना मना है","आप अब बाएँ मुड़ सकते हैं और सामने से आने वाला यातायात रुका हुआ है, जिससे आपको एक सुरक्षित (प्रोटेक्टेड) मोड़ मिलता है","आप बाएँ केवल धीमे होकर जाँचने के बाद ही मुड़ सकते हैं, क्योंकि तीर एक चमकती पीली सावधानी संकेत की तरह काम करता है"],"explanation":"A green ARROW means a protected turn in the arrow's direction, so oncoming traffic is being held by a red light and you may turn without yielding. Option A describes a steady green light (a permitted turn requiring you to yield), and option B incorrectly describes a red arrow, so both are wrong."},"7":{"q":"आप एक व्यस्त चौराहे पर बाएं मुड़ने वाली लेन में बाएं मुड़ने के लिए प्रतीक्षा कर रहे हैं। आपकी लेन का सिग्नल बाईं ओर इशारा करता हुआ एक स्थिर लाल तीर दिखा रहा है, जबकि सीधे जाने वाले यातायात के लिए सामान्य गोल सिग्नल हरा है। आपको क्या करना चाहिए?","options":["सावधानी से बाएं मुड़ें, क्योंकि सीधी लेन के लिए हरी बत्ती का मतलब है कि सामने से आने वाले यातायात के पास संरक्षित रुकाव है","लाल तीर को टिमटिमाती लाल बत्ती की तरह मानें और पूरी तरह रुकने के बाद बाएं मुड़ें","सामने से आने वाले यातायात को रास्ता देने के बाद बाएं मुड़ें, क्योंकि रास्ता साफ होने पर लाल तीर पर बाएं मुड़ना हमेशा अनुमत है","रुके रहें और प्रतीक्षा करें, क्योंकि लाल तीर का मतलब है कि सिग्नल बदलने तक उस दिशा में मुड़ने की अनुमति नहीं है"],"explanation":"A red arrow means no turn is allowed in the direction it points, so you must wait until the signal changes, regardless of what the round signal for other lanes shows. A red arrow is not the same as a flashing red, and there is no 'turn after yielding' permitted on a steady red arrow."},"8":{"q":"बिजली कटौती के दौरान आप एक व्यस्त चार-तरफा चौराहे के पास पहुंचते हैं। ट्रैफिक सिग्नल पूरी तरह बंद हैं और बिल्कुल काम नहीं कर रहे। आपको क्या करना चाहिए?","options":["चौराहे को सभी दिशाओं में STOP (ऑल-वे स्टॉप) की तरह मानें, आगे बढ़ने से पहले रुकें और बारी-बारी से रास्ता दें","गति धीमी करें और बिना रुके सावधानी से चौराहे को पार करें","यह मान लें कि आपकी दिशा को रास्ते का अधिकार है और सामान्य गति से चलते रहें","केवल तभी रुकें जब चौराहे में पहले से कोई वाहन हो, अन्यथा चलते रहें"],"explanation":"A dark or non-working signal must be treated as an all-way STOP, so every driver stops and yields in turn. Slowing without stopping (B) is the rule for a flashing yellow light, not a dead signal, and the other options wrongly assume right of way."},"9":{"q":"आप हरी बत्ती पर रुके हैं और एक साइड स्ट्रीट पर दाहिने मुड़ना चाहते हैं। जिस क्रॉसवॉक को आप पार करने वाले हैं, उसकी ओर वाले पैदल यात्री सिग्नल पर एक स्थिर सफेद चलते हुए व्यक्ति का प्रतीक दिख रहा है। यह प्रतीक कोने पर खड़े लोगों के बारे में आपको क्या बताता है?","options":["पैदल यात्रियों को रुकना होगा, इसलिए आप क्रॉसवॉक की जाँच किए बिना मुड़ सकते हैं","पैदल यात्री कानूनी रूप से पार करना शुरू कर सकते हैं, इसलिए मुड़ने से पहले आपको उन्हें रास्ता देना होगा","पैदल यात्री केवल पार करना पूरा कर सकते हैं लेकिन शुरू नहीं कर सकते, इसलिए क्रॉसवॉक में बहुत कम लोग होंगे","क्रॉसवॉक पैदल यात्रियों के लिए बंद है और मुड़ने वाले वाहनों के लिए आरक्षित है"],"explanation":"A WALK signal or walking-person symbol means pedestrians may cross, so they have the right of way and you must yield before turning. Option C describes a flashing DON'T WALK/raised hand (finish but don't start), not the steady walking-person symbol."},"10":{"q":"आप शहर के केंद्र में एक चौराहे पर पहुँचते हैं और लाल बत्ती पर रुकते हैं। प्रतीक्षा करते समय, आप देखते हैं कि सड़क के उस पार पैदल यात्री संकेत झपकते हुए उठे हुए हाथ के चिह्न से स्थिर उठे हुए हाथ के चिह्न में बदल जाता है, जबकि एक व्यक्ति अभी भी आपके कोने पर खड़ा है। वह स्थिर उठा हुआ हाथ उस पैदल यात्री को क्या करने के लिए कहता है?","options":["इसका अर्थ है कि उसे बत्ती बदलने से पहले पार करना पूरा करने के लिए जल्दी करनी चाहिए","इसका अर्थ है कि पैदल पार पथ बंद है और उसे दूसरे चौराहे का उपयोग करना चाहिए","इसका अर्थ है कि उसे सड़क पार करना शुरू नहीं करना चाहिए","इसका अर्थ है कि वह पार करना शुरू कर सकता है क्योंकि चलने (WALK) का चरण शुरू हो रहा है"],"explanation":"A steady DON'T WALK signal or steady raised-hand symbol means do not start to cross. The flashing raised hand (option A) is what tells someone already in the crosswalk to finish crossing, but a steady hand means do not begin."},"11":{"q":"आप एक शहर की सड़क पर दाएं मुड़ने के लिए हरी बत्ती पर रुके हुए हैं। ठीक उसी समय जब पैदल यात्री की ओर मुख किए सिग्नल पर चमकता हुआ उठा हुआ हाथ (पार न करें) का चिह्न दिखना शुरू होता है, एक पैदल यात्री फुटपाथ से उस क्रॉसवॉक में उतरता है जिसे आपको पार करना है। वह चमकता हुआ सिग्नल आपको पैदल यात्री के क्रॉसवॉक में रहने के कानूनी अधिकार के बारे में क्या बताता है?","options":["पैदल यात्री को तुरंत रुककर फुटपाथ पर वापस लौटना होगा, इसलिए जैसे ही वह पीछे हटे आप मुड़ सकते हैं","चमकता हुआ हाथ स्थिर हाथ के समान ही है, इसलिए पैदल यात्री को प्रवेश करने का अधिकार नहीं था और आप आगे बढ़ सकते हैं","चमकता हुआ हाथ केवल चमकती पीली बत्ती जैसी सावधानी है, इसलिए पैदल यात्री और आप दोनों एक साथ आगे बढ़ सकते हैं","जो पैदल यात्री पहले से ही क्रॉसवॉक में है वह पार करना पूरा कर सकता है; चमकता हुआ हाथ केवल यह बताता है कि कोई नया व्यक्ति पार करना शुरू न करे"],"explanation":"A flashing DON'T WALK or flashing raised-hand symbol means anyone already in the crosswalk should finish crossing, while no new pedestrian should start; you must yield until they finish. The steady-hand meaning (B) and the flashing-yellow caution rule (C) are real facts placed in the wrong context."},"12":{"q":"आप एक बहु-लेन राजमार्ग पर गाड़ी चला रहे हैं जहाँ प्रत्येक लेन के ऊपर लेन-उपयोग संकेत लटके हुए हैं। जिस लेन में आप जाना चाहते हैं उसके ऊपर, आपको एक स्थिर हरा नीचे की ओर तीर दिखता है। यह उस लेन के बारे में आपको क्या बताता है?","options":["लेन खुली है और आप उसमें गाड़ी चला सकते हैं","लेन बंद है और आपको उससे बाहर निकलना होगा","लेन का उपयोग बदल रहा है, इसलिए बंद होने से पहले उससे बाहर निकल जाएँ","लेन केवल HOV या कारपूल वाहनों के लिए आरक्षित है"],"explanation":"A lane-use green down-arrow means the lane is open for travel, so you may drive in it. A red X means the lane is closed and a yellow X means the lane is changing use and you should move out of it, but neither of those signals is shown here."},"13":{"q":"आप एक बहु-लेन राजमार्ग पर गाड़ी चला रहे हैं और ऊपर लगे लेन-नियंत्रण संकेतों को देखते हैं। आपकी लेन के ऊपर एक स्थिर लाल X जल रहा है, जबकि आपके दाईं ओर की लेन में एक स्थिर हरा नीचे की ओर तीर दिख रहा है। आपको क्या करना चाहिए?","options":["अपनी लेन में रहें और सावधानी से आगे बढ़ें, क्योंकि लाल X केवल आगे आने वाले खतरे की चेतावनी देता है","अपनी दाईं ओर की लेन में चले जाएं, क्योंकि लाल X का मतलब है कि आपकी लेन बंद है और हरा नीचे की ओर तीर का मतलब है कि वह लेन खुली है","अपनी लेन में पूरी तरह रुक जाएं और प्रतीक्षा करें, लाल X को चमकते लाल संकेत की तरह मानते हुए","अपनी लेन में रहें लेकिन तुरंत उससे बाहर निकल जाएं, क्योंकि लाल X का मतलब है कि लेन का उपयोग बदल रहा है"],"explanation":"A lane-use red X means the lane is closed, so you must leave it, and a green down-arrow means the lane beneath it is open for travel. The trap options confuse the red X with a flashing red (stop) signal or with a yellow X, which is the signal that means the lane is changing use and you should move out of it."},"14":{"q":"आप एक बहु-लेन सड़क पर बीच की लेन में गाड़ी चला रहे हैं, तभी आपकी लेन के ऊपर लगा लेन-उपयोग संकेत स्थिर पीले X में बदल जाता है। इस संकेत का मतलब है कि आपको क्या करना चाहिए?","options":["तुरंत लेन में ही रुक जाएं, क्योंकि पीला X ऊपर लगी स्थिर लाल बत्ती की तरह काम करता है","लेन में बने रहें लेकिन लगभग रुकने तक धीमे हो जाएं, क्योंकि पीला X केवल यह चेतावनी देता है कि आगे लेन में भीड़ है","लेन से सुरक्षित रूप से बाहर निकलने की तैयारी करें, क्योंकि लेन का उपयोग बदल रहा है और यह आपकी दिशा के लिए बंद होने वाली है","सामान्य रूप से चलते रहें, क्योंकि पीला X केवल यह पुष्टि करता है कि लेन आर-पार के यातायात के लिए खुली है"],"explanation":"An overhead lane-use yellow X means the lane is changing use, so you should prepare to safely move out of it before it closes. Stopping in the lane (A) is wrong because a yellow X is not a red light, and continuing as if the lane is open (D) confuses it with a green down-arrow, which is the signal for an open lane."},"15":{"q":"आप एक धीमे ट्रैक्टर के पीछे दो-लेन वाले ग्रामीण राजमार्ग पर गाड़ी चला रहे हैं। आप उसे ओवरटेक करना चाहते हैं, लेकिन आप देखते हैं कि सड़क के बीच में आपकी ओर एक ठोस पीली रेखा बनी हुई है। यह चिह्न आपको यहाँ ओवरटेक करने के बारे में क्या बताता है?","options":["आप ओवरटेक कर सकते हैं क्योंकि पीली रेखाएँ सड़क साफ होने पर हमेशा ओवरटेक करने की अनुमति देती हैं","आप तभी ओवरटेक कर सकते हैं जब उसके साथ एक टूटी हुई सफेद रेखा भी हो","ओवरटेक दोनों दिशाओं में अनुमत है क्योंकि रेखा पीली है","आपको ओवरटेक नहीं करना चाहिए; आपकी ओर की ठोस पीली रेखा का अर्थ है कि ओवरटेक करना निषिद्ध है"],"explanation":"A solid yellow line on your side of the centerline means no passing, so you must stay behind the tractor until the marking changes. Option A confuses this with a broken yellow line (passing allowed when safe), and the white-line and both-directions ideas do not apply to a solid yellow line on your side."},"16":{"q":"आप एक दो-लेन वाले ग्रामीण राजमार्ग पर एक धीमे ट्रैक्टर के पीछे चल रहे हैं। सड़क के केंद्र में आपकी ओर एक टूटी हुई (बिंदुदार) पीली रेखा है, आगे सड़क सीधी है और दृश्यता साफ है, और कोई सामने से आता ट्रैफ़िक नहीं दिख रहा। यह सड़क चिह्न आपको ट्रैक्टर को ओवरटेक करने के बारे में क्या बताता है?","options":["सुरक्षित होने पर ओवरटेक करने की अनुमति है, इसलिए आप ट्रैक्टर को पार करने के लिए रेखा पार कर सकते हैं","आपकी ओर ओवरटेक करना मना है क्योंकि कोई भी पीली रेखा का मतलब ओवरटेक नहीं है","आप रेखा को केवल बाएं मुड़ने के लिए पार कर सकते हैं, ओवरटेक करने के लिए नहीं","ओवरटेक केवल दाहिने किनारे (शोल्डर) से अनुमत है, कभी भी केंद्र रेखा पार करके नहीं"],"explanation":"A broken (dashed) yellow line on your side of the center means passing is permitted when it is safe to do so, which it is here with clear visibility and no oncoming traffic. The trap in B confuses this with a solid yellow line (no passing), and the turn-only restriction in C applies to a double solid yellow line."},"17":{"q":"आप दो-लेन वाली सड़क पर चल रहे हैं और एक ऐसे हिस्से पर पहुँचते हैं जहाँ बीच में दो ठोस पीली रेखाएँ एक-दूसरे के बगल में बनी हैं। आपके आगे एक धीमा ट्रैक्टर है और सड़क दोनों दिशाओं में साफ है। आपकी बाईं ओर एक ड्राइववे है जिसमें आप मुड़ सकते हैं। यह निशान आपको क्या करने की अनुमति देता है?","options":["ट्रैक्टर को ओवरटेक करें, क्योंकि सड़क दोनों दिशाओं में साफ है और आप दूर तक आगे देख सकते हैं","अपनी लेन में रहें और ओवरटेक न करें, हालाँकि बाईं ओर ड्राइववे में मुड़ने के लिए आप रेखाओं को पार कर सकते हैं","ट्रैक्टर को ओवरटेक करें, क्योंकि दोहरी ठोस पीली रेखा केवल आने वाली दिशा के लिए ओवरटेकिंग पर रोक लगाती है","ओवरटेक करने के लिए रेखाओं को स्वतंत्र रूप से पार करें, क्योंकि ठोस पीली रेखा केवल पार करने को हतोत्साहित करती है पर मना नहीं करती"],"explanation":"A double solid yellow line means no passing in either direction, so you must stay in your lane, but you may still cross it to turn (such as into a driveway). Passing is never allowed here regardless of visibility, and the rule applies to both directions, not just oncoming traffic."},"18":{"q":"आप एक बहु-लेन राजमार्ग पर गाड़ी चला रहे हैं जहाँ सारा यातायात एक ही दिशा में चल रहा है। आपको अपनी लेन और तुरंत दाहिनी ओर की लेन के बीच एक रेखा बनी हुई दिखती है। वह रेखा सबसे अधिक संभावना किस रंग की होगी?","options":["पीली, क्योंकि पीली रेखाएँ हमेशा हर लेन के किनारों को चिह्नित करती हैं","पीली, क्योंकि रेखा चेतावनी देती है कि वहाँ ओवरटेक करना मना है","सफेद, क्योंकि सफेद रेखाएँ एक ही दिशा में चलने वाले यातायात की लेनों को अलग करती हैं","दोहरी ठोस पीली, क्योंकि यह बगल की लेन में जाने से रोकती है"],"explanation":"White lines separate lanes of traffic that travel in the same direction, so the line between two same-direction lanes is white. Yellow lines are used to separate traffic moving in opposite directions or to mark no-passing zones, which does not apply here."},"19":{"q":"आप एक बहु-लेन सड़क पर गाड़ी चला रहे हैं जहाँ सारा यातायात एक ही दिशा में चल रहा है। आपकी बाईं ओर की लेन आपकी लेन से टूटी हुई (खंडित) सफेद रेखा द्वारा अलग की गई है। आपकी लेन में आगे का यातायात धीमा हो रहा है और बाईं लेन खाली है। यह चिह्न आपको बाईं लेन में जाने के बारे में क्या बताता है?","options":["आप इसे पार नहीं कर सकते; सफेद रेखा का हमेशा यही अर्थ है कि आपको अपनी लेन में रहना चाहिए","पार करना केवल मुड़ने के लिए अनुमत है, जैसे आप दोहरी ठोस पीली रेखा को मानते हैं","यहाँ ओवरटेक करने की अनुमति केवल इसलिए है क्योंकि यह रेखा विपरीत दिशा के यातायात को अलग करती है","जब रास्ता खाली हो और ऐसा करना सुरक्षित हो, तब आप इसे पार करके लेन बदल सकते हैं"],"explanation":"A broken white line separates lanes going the same direction and permits a lane change when it is safe, so moving into the clear left lane is allowed. Option A describes a solid white line, and option B describes a double solid yellow line, so both apply the wrong marking's rule here."},"20":{"q":"आप एक चार-लेन वाले राजमार्ग पर गाड़ी चला रहे हैं जहाँ सभी लेन एक ही दिशा में चलती हैं। जैसे ही आप एक फ्रीवे प्रवेश रैंप के पास पहुँचते हैं, एक एकल ठोस सफेद रेखा आपकी लेन को दाईं ओर की लेन से अलग करती है। बेहतर स्थिति पाने के लिए आप उस लेन में जाना चाहते हैं। यह चिह्न आपको क्या बताता है?","options":["अपनी लेन में रहें; ठोस सफेद रेखा को पार करना हतोत्साहित किया जाता है","जब भी दाईं लेन खाली हो, आप स्वतंत्र रूप से उसमें बदल सकते हैं","दोहरी ठोस रेखा की तरह, दोनों दिशाओं में ओवरटेक करना निषिद्ध है","यह सड़क के दाएं किनारे को चिह्नित करता है, इसलिए इसके आगे गाड़ी न चलाएं"],"explanation":"A solid white line separates lanes going the same direction and means stay in your lane, as crossing it is discouraged. A broken white line is what allows a free lane change (option B), and a solid white edge line marks the road's right edge (option D), so those facts are placed here in the wrong context."},"21":{"q":"आप रात में कम दृश्यता वाले एक अपरिचित ग्रामीण राजमार्ग पर गाड़ी चला रहे हैं। अपने दाईं ओर आप सड़क की सतह के साथ-साथ, अपनी यात्रा की दिशा के समानांतर एक ठोस सफेद रेखा देखते हैं। यह रेखा आपको क्या बताती है?","options":["यह सड़क के केंद्र को चिह्नित करती है और ओवरटेक करने के लिए आपको इसे पार नहीं करना चाहिए","यह सड़क के दाएं किनारे को चिह्नित करती है, जो आपको सतह पर बने रहने में मदद करती है","यह एकतरफा सड़क पर सड़क के बाएं किनारे को चिह्नित करती है","यह एक बाइक लेन दर्शाती है जिसमें आपको गाड़ी नहीं चलानी चाहिए"],"explanation":"A solid white edge line marks the right edge of the road, which is especially useful for staying on the pavement at night or in poor visibility. The trap in C confuses edge colors: a yellow line marks the left edge, while white marks the right edge."},"22":{"q":"आप रात में एक अनजान दो-तरफा सड़क पर गाड़ी चला रहे हैं। आपकी हेडलाइट्स आपकी लेन के सबसे बाईं ओर, पक्की सड़क की सीमा पर चलती हुई एक ठोस पीली रेखा को रोशन करती हैं। यह रेखा आपको क्या बता रही है?","options":["यह सड़क के दाहिने किनारे को चिह्नित करती है, इसलिए पक्की सड़क आपके ठीक बाईं ओर समाप्त होती है","यह ओवरटेक न करने की रेखा है, इसलिए आपको ओवरटेक करने के लिए सड़क के बीच को पार नहीं करना चाहिए","यह सड़क के बाएं किनारे को चिह्नित करती है, इसलिए यह दिखाती है कि आपकी बाईं ओर पक्की सड़क कहां समाप्त होती है","यह आपके समान दिशा में चलने वाले यातायात की लेन को अलग करती है"],"explanation":"A yellow edge line marks the left edge of the roadway, showing the driver where the pavement ends on the left side. The line being yellow does not make it a center no-passing line, and the right edge of the road is marked with a solid white line, not yellow."},"23":{"q":"आप एक चौराहे के पास लाल बत्ती पर पहुँचते हैं। पैदल पार पथ (क्रॉसवॉक) से पहले, आपको अपनी लेन के आर-पार खिंची एक चौड़ी सफेद रेखा दिखाई देती है। आपको अपना वाहन पूरी तरह कहाँ रोकना चाहिए?","options":["चौड़ी सफेद रेखा के ऊपर, ताकि आपका बम्पर उसके साथ बराबर में आ जाए","चौड़ी सफेद रेखा से थोड़ा आगे, लेकिन पैदल पार पथ में प्रवेश करने से पहले","चौराहे में कहीं भी, बशर्ते आप हरी बत्ती से पहले पूरी तरह रुक जाएँ","चौड़ी सफेद रेखा के पीछे, जो स्टॉप लाइन है और रुकने का स्थान दर्शाती है"],"explanation":"The wide white line is a stop line, and you must stop behind it, not on or beyond it. Stopping on the line or past it into the crosswalk blocks pedestrians and is incorrect even though you are technically stopped."},"24":{"q":"किसी चौराहे पर हरी बत्ती की ओर बढ़ते हुए, आपको सड़क पर बने सफेद निशान और उन पर कदम रखता एक पैदल यात्री दिखाई देता है। आपको कहाँ रुकना चाहिए?","options":["सफेद क्रॉसवॉक निशानों से पहले, ताकि पैदल यात्री पार कर सके","क्रॉसवॉक निशानों के ऊपर, जब तक आप पैदल यात्री के लिए जगह छोड़ते हैं","जहाँ चाहें, क्योंकि हरी बत्ती का मतलब है कि आपको हमेशा रास्ते का अधिकार है","लेन में बने हीरे (डायमंड) के निशान के पीछे"],"explanation":"A crosswalk is marked by white lines for pedestrians, and you must stop before it to let them cross safely. Stopping on top of it blocks the pedestrian, and a green light still requires yielding to people already in the crosswalk; the diamond symbol marks an HOV/carpool lane, not a stopping point."},"25":{"q":"आप व्यस्त समय के दौरान टेक्सास के एक फ्रीवे पर अकेले गाड़ी चला रहे हैं। सबसे बाईं ओर की लेन में नियमित अंतराल पर बड़े डायमंड (हीरे के आकार के) चिह्न पेंट किए गए हैं। यह चिह्न उस लेन के बारे में आपको क्या बताता है?","options":["यह एक साइकिल लेन है, इसलिए आपको इसमें गाड़ी नहीं चलानी या पार्क नहीं करनी चाहिए","यह एक आरक्षित HOV/कारपूल या विशेष-उपयोग लेन है जिसे अकेले उपयोग करने की आपको अनुमति नहीं हो सकती","यह सभी यातायात के लिए बंद है, बिल्कुल ऊपर लगे लाल X संकेत की तरह","यह एक किनारे की लेन है और डायमंड चिह्न बताते हैं कि सड़क की सतह कहाँ समाप्त होती है"],"explanation":"A diamond symbol painted in a lane marks a reserved HOV/carpool or special-use lane, which often requires a minimum number of occupants, so driving alone may not be permitted. A bike lane is marked differently, and a closed lane is shown by an overhead red X, not pavement diamonds."},"26":{"q":"आप देर से चल रहे हैं और सामान्य यातायात लेन के दाईं ओर एक खाली सड़क का हिस्सा देखते हैं। इसे एक ठोस सफेद रेखा से अलग किया गया है और इस पर एक साइकिल का चिह्न बना है, लेकिन इस समय इसमें कोई साइकिल चालक नहीं है। आपको क्या करना चाहिए?","options":["धीमे यातायात को पार करने के लिए इसमें गाड़ी चलाएं, क्योंकि यह अभी खाली है","इसमें घुसकर पार्क कर दें जब तक यातायात साफ न हो जाए","इससे पूरी तरह दूर रहें; यह साइकिलों के लिए आरक्षित एक बाइक लेन है, गाड़ी चलाने या पार्क करने के लिए नहीं","इसे कारपूल लेन के रूप में उपयोग करें क्योंकि आपके वाहन में यात्री हैं"],"explanation":"A lane marked with a bicycle symbol is a bike lane reserved for bicycles, and you must not drive or park in it even when no cyclists are present. Options A and B are the trap (driving and parking are both prohibited), and D confuses the bike lane with an HOV/carpool lane, which is marked with a diamond symbol instead."},"27":{"q":"आपको देर हो रही है और आपको अपनी कार कुछ मिनटों के लिए छोड़नी है। एकमात्र खाली जगह एक ठोस पीले रंग से रंगे फुटपाथ-किनारे (कर्ब) के साथ है, और आसपास कोई संकेत-पट्ट नहीं लगा है। वह पीला कर्ब आपको वहाँ पार्किंग के बारे में क्या बताता है?","options":["पार्किंग ठीक है क्योंकि इसे रोकने वाला कोई संकेत नहीं लगा है","यह सड़क के बाएँ किनारे को चिह्नित करता है, इसलिए इसके दाईं ओर पार्किंग की अनुमति है","यह केवल HOV या कारपूल वाहनों के लिए आरक्षित है","यह नो-पार्किंग या लोडिंग प्रतिबंध दर्शाता है, इसलिए आपको वहाँ पार्क नहीं करना चाहिए"],"explanation":"A yellow curb signals a no-parking or loading restriction even when no sign is present, though exact meanings can vary by city, so you should not leave your car there. The left-edge yellow line refers to roadway center markings, not curbs, and HOV reservations are shown by a diamond symbol in a lane, not by a painted curb."},"28":{"q":"आप एक अनजान सड़क पर गाड़ी चला रहे हैं और आगे सड़क की सतह पर एक बड़ा \"RXR\" चिह्न बना है, जिसके बाद आपकी लेन के आर-पार एक चौड़ी सफेद रेखा है। फाटक अभी भी ऊपर हैं, लेकिन आपको ट्रेन का हॉर्न सुनाई देता है और एक ट्रेन आती हुई दिखती है। आपको क्या करना चाहिए?","options":["सफेद रेखा के पीछे रुककर प्रतीक्षा करें, क्योंकि RXR रेलवे क्रॉसिंग को दर्शाता है और ट्रेन के आने पर आपको रुकना अनिवार्य है","सफेद रेखा को वैकल्पिक मानकर धीरे-धीरे पार कर लें, क्योंकि फाटक अभी ऊपर हैं और ट्रेन से पहले निकला जा सकता है","केवल तभी रुकें जब रेखा पीली हो, क्योंकि आपकी ओर पीली रेखा का मतलब है ओवरटेक करना मना है","बिना रुके आगे बढ़ें क्योंकि हीरे का चिह्न पार करने वाले यातायात के लिए विशेष-उपयोग लेन दर्शाता है"],"explanation":"The large RXR painted on the pavement marks a railroad crossing, and the wide white line is a stop line; you must stop behind it when a train is approaching. The traps misuse other real facts: a solid yellow line means no passing, and a diamond marks an HOV/special-use lane, neither of which applies at a railroad crossing."},"29":{"q":"आप एक चौराहे पर बाएं मुड़ने के लिए रुके हुए हैं, तभी आपकी बत्ती स्थिर हरी हो जाती है। विपरीत दिशा से एक वाहन आ रहा है और चौराहे के करीब है। आपको क्या करना चाहिए?","options":["तुरंत बाएं मुड़ जाएं, क्योंकि स्थिर हरी बत्ती आपको सामने से आने वाले यातायात से पहले आगे बढ़ने का अधिकार देती है।","सामने से आ रहे वाहन को रास्ता दें, फिर सुरक्षित होने पर अपना बायां मोड़ पूरा करें।","हरे तीर का इंतजार करें, क्योंकि स्थिर हरी बत्ती बाएं मुड़ने की अनुमति नहीं देती।","लाइन के पीछे पूरी तरह रुकें और सामने वाला वाहन गुजर जाने के बाद ही आगे बढ़ें, क्योंकि स्थिर हरी बत्ती में पहले रुकना आवश्यक है।"],"explanation":"At a steady green light you may proceed or turn, but you must first yield to oncoming traffic and pedestrians rather than turn without regard to other vehicles. A green arrow gives a protected turn and a stop is required only at red or yellow, so options C and D misapply other signal rules."},"30":{"q":"आप निर्धारित गति सीमा पर एक चौराहे के पास पहुंच रहे हैं, तभी बत्ती हरी से स्थिर पीली हो जाती है। आपके आगे रेखा से पहले सुरक्षित रूप से रुकने के लिए पर्याप्त दूरी है। आपको क्या करना चाहिए?","options":["बत्ती लाल होने से पहले चौराहा पार करने के लिए गति बढ़ा दें","केवल तभी रुकें जब कोई संकेत आपको बताए, अन्यथा पीली बत्ती पर अपनी गति बनाए रखें","गति धीमी करें और रेखा के पीछे सुरक्षित रूप से रुकें, क्योंकि पीली बत्ती चेतावनी देती है कि लाल आने वाली है","पीली बत्ती को चमकती पीली बत्ती की तरह मानें और बिना रुके सावधानी से पार करें"],"explanation":"A steady yellow means the light is about to turn red, so you should stop if you can do so safely rather than speed up to beat the light. Accelerating through (A) is the exact mistake the yellow warns against, and a flashing yellow (D) is a different signal that means caution and does not require stopping."},"31":{"q":"देर रात आप एक चौराहे के पास पहुँच रहे हैं जब आपकी दिशा में ट्रैफिक सिग्नल चमकती पीली बत्ती में बदल जाता है। कोई क्रॉस ट्रैफिक दिखाई नहीं दे रहा है। आपको क्या करना चाहिए?","options":["स्टॉप लाइन के पीछे पूरी तरह रुकें, फिर चौराहा साफ होने पर आगे बढ़ें","पूरी तरह रुकें, इसे सभी दिशाओं वाले स्टॉप की तरह मानें, और अपने दाहिनी ओर के किसी भी वाहन को रास्ता दें","बत्ती लाल होने से पहले चौराहा पार करने के लिए गति बढ़ाएं","गति धीमी करें और बिना रुके सावधानी से चौराहे से गुजरें"],"explanation":"A flashing yellow light means caution: you slow down and proceed carefully without needing to stop. A full stop is required at a flashing red (which is treated like a stop sign), so options requiring a complete stop confuse the flashing red rule with the flashing yellow."},"32":{"q":"आप शाम के समय एक अनजान दो-लेन वाली सड़क पर गाड़ी चला रहे हैं। सड़क के बीच की रेखा, जो आपकी लेन को बगल वाली लेन से अलग करती है, पीली है। यह रंग उस रेखा के दूसरी ओर वाली लेन के यातायात के बारे में आपको क्या बताता है?","options":["यह विपरीत दिशा में, आपकी ओर आ रहा है","यह आपकी ही दिशा में चल रहा है","यह HOV या कारपूल उपयोग के लिए आरक्षित लेन है","यह सड़क का दायाँ किनारा है"],"explanation":"Yellow center lines separate traffic moving in opposite directions, so the lane across a yellow line carries oncoming traffic. White lines, not yellow, separate traffic moving in the same direction, which makes B the trap."},"33":{"q":"आप पैदल एक क्रॉसवॉक पर पहुंचते हैं और सड़क पार करना चाहते हैं। जैसे ही आप किनारे पर पहुंचते हैं, पैदल यात्री संकेत झपकता हुआ DON'T WALK / उठा हुआ हाथ में बदल जाता है। इसका आपके लिए क्या अर्थ है?","options":["अभी पार करना शुरू न करें, लेकिन यदि आप पहले से क्रॉसवॉक में हैं तो आपको उस किनारे पर लौटना होगा जहां से आप आए थे","अभी पार करना शुरू न करें; केवल वे लोग जो पहले से क्रॉसवॉक में हैं उन्हें जारी रखकर पार करना पूरा करना चाहिए","आप पार करना शुरू कर सकते हैं क्योंकि झपकना सावधानी का अर्थ है, झपकते पीले संकेत के समान","आप सावधानी से पार करना शुरू कर सकते हैं, लेकिन केवल पहले क्रॉसवॉक के किनारे पर रुकने के बाद"],"explanation":"A flashing DON'T WALK warns pedestrians not to begin crossing; those already in the crosswalk should finish crossing. Option C wrongly borrows the flashing-yellow 'caution, proceed' meaning, and A invents a rule about turning back that the handbook does not state."},"34":{"q":"आप लाल बत्ती पर रुके हैं और दाएँ मुड़ना चाहते हैं। चौराहे पर आपको एक चिह्न दिखता है जिस पर लिखा है 'लाल पर मुड़ना मना है' (NO TURN ON RED)। पूरी तरह रुकने और यह देखने के बाद कि आड़ा यातायात साफ है, आपको क्या करना चाहिए?","options":["दाएँ मुड़ जाएँ, क्योंकि पूरी तरह रुकना लाल पर दाएँ मुड़ने की कानूनी शर्त पूरी कर देता है","धीरे-धीरे दाएँ मुड़ें, क्योंकि लेन साफ है और आपने सही तरह से रास्ता दिया","रुके रहें और दाएँ मुड़ने से पहले हरी बत्ती का इंतज़ार करें","लाल बत्ती को टिमटिमाती लाल बत्ती मानें और यातायात साफ होते ही आगे बढ़ें"],"explanation":"When a posted sign prohibits turning right on red, you may not turn regardless of stopping or a clear path, so you must wait for the green light. Stopping fully only permits a right on red when no sign forbids it, and a steady red is never treated like a flashing red."},"35":{"q":"आप टेक्सास ड्राइवर लाइसेंस ज्ञान परीक्षा की तैयारी कर रहे हैं और यह सुनिश्चित करना चाहते हैं कि आपने ऑनलाइन पढ़ा हुआ एक विशिष्ट सड़क-चिह्न नियम वास्तव में सही है और वर्तमान में टेक्सास में लागू है। आधिकारिक नियम वास्तव में क्या हैं, यह पुष्टि करने के लिए आपको किस स्रोत पर भरोसा करना चाहिए?","options":["जिस पर अधिकांश ऑनलाइन ड्राइविंग-क्विज़ वेबसाइटें सहमत हों, क्योंकि वे कई राज्यों के नियमों का सारांश देती हैं","केवल संघीय MUTCD पर, क्योंकि राष्ट्रीय मानक टेक्सास-विशिष्ट किसी भी मार्गदर्शन को पूरी तरह से बदल देते हैं","किसी पड़ोसी राज्य की ड्राइवर पुस्तिका पर, क्योंकि सभी अमेरिकी राज्यों में सड़क-चिह्न एक समान होते हैं","टेक्सास ड्राइवर हैंडबुक (DPS, DL-7) के साथ टेक्सास में लागू होने वाले MUTCD राष्ट्रीय मानकों पर"],"explanation":"The authoritative source of truth is the Texas Driver Handbook (DPS, DL-7) combined with the MUTCD national standards that apply in Texas. The MUTCD alone is not enough because it works together with the state handbook, and quiz sites or another state's handbook are not official Texas sources."},"36":{"q":"आप दो-लेन वाली सड़क पर गाड़ी चला रहे हैं और बीच में एक दोहरी ठोस पीली रेखा है। आपके आगे एक धीमा ट्रैक्टर है, और उसके ठीक बाद आपको वह प्रवेश-द्वार दिखता है जहाँ आपको बाएँ मुड़कर पार्किंग में जाना है। इस दोहरी ठोस पीली रेखा के साथ आपको कानूनी रूप से क्या करने की अनुमति है?","options":["पार्किंग में बाएँ मुड़ने के लिए इसे पार करें, लेकिन ट्रैक्टर को ओवरटेक करने के लिए नहीं","इसे पार करके ट्रैक्टर को ओवरटेक करें, क्योंकि आगे की लेन खाली है","इसे स्वतंत्र रूप से पार करें क्योंकि दोहरी पीली रेखाएँ केवल सामने से आने वाले यातायात पर लागू होती हैं","इसे टूटी हुई पीली रेखा की तरह मानें और जब सुरक्षित हो तब ओवरटेक करें"],"explanation":"A double solid yellow line means no passing in either direction; you may cross it only to make a turn, such as turning left into a driveway or parking lot. Passing the tractor (B and D) is prohibited, and the line applies to drivers on both sides, not just oncoming traffic (C)."},"37":{"q":"आप एक रेलरोड क्रॉसिंग की ओर बढ़ते हैं जो सड़क पर बने बड़े RXR चिह्न और एक चौड़ी सफेद स्टॉप लाइन से चिह्नित है। कोई चमकती बत्तियाँ या फाटक नहीं हैं, कोई ट्रेन नज़र नहीं आ रही, और आप साफ़ देख और सुन सकते हैं कि कोई ट्रेन नहीं आ रही। आपको क्या करना चाहिए?","options":["स्टॉप लाइन पर पूरी तरह रुककर इंतज़ार करें, क्योंकि हर रेलरोड क्रॉसिंग पर पूरी तरह रुकना आवश्यक है","बिना रुके पटरियों को पार करें, लेकिन यदि कोई ट्रेन आ रही हो तो चिह्नित स्टॉप लाइन पर रुकने के लिए तैयार रहें","गति धीमी करें और क्रॉसिंग को सभी दिशाओं के स्टॉप वाले चौराहे की तरह समझें, पहले अपनी दाईं ओर के यातायात को रास्ता दें","आगे बढ़ने से पहले दोनों दिशाओं में देखने के लिए पटरियों पर कुछ क्षण के लिए रुकें"],"explanation":"At this type of railroad crossing you stop only if a train is approaching, and the stop must be made at the marked stop line; with no train coming you may proceed across without stopping. Option A is wrong because a stop is not required at every crossing when no train is near, and stopping on the tracks (D) is always dangerous."},"38":{"q":"आप एक बहु-लेन फ्रीवे पर गाड़ी चला रहे हैं, तभी आप देखते हैं कि आपकी लेन के ठीक ऊपर का ओवरहेड सिग्नल हरे नीचे-तीर से बदलकर स्थिर पीला X हो जाता है। इसका क्या मतलब है, और आपको क्या करना चाहिए?","options":["आपकी लेन अब केवल रुके हुए यातायात के लिए बंद है; लेन के भीतर पूरी तरह रुकें और प्रतीक्षा करें।","यह झपकती पीली बत्ती की तरह एक सावधानी संकेत है; गति धीमी करें लेकिन अपनी मौजूदा लेन में बने रहें।","आपकी लेन का उपयोग बदल रहा है; सुरक्षित रूप से इस लेन से निकलकर हरे नीचे-तीर से चिह्नित किसी खुली लेन में चले जाएं।","आगे पैदल यात्री पार कर रहे हैं; सिग्नल बदलने तक अपनी लेन में रहें और रास्ता दें।"],"explanation":"A yellow X overhead lane-control signal means the lane is changing use and you should move out of it safely, while a green down-arrow marks a lane that is open. The caution answer confuses this with a flashing yellow traffic light, which applies to intersections, not overhead lane control."},"39":{"q":"आप एक चौराहे पर बाएं मुड़ने वाली लेन में प्रतीक्षा कर रहे हैं। आपके सामने का सिग्नल सीधी जाने वाली लेन के लिए स्थिर लाल बत्ती के साथ बाईं ओर एक स्थिर हरा तीर दिखा रहा है। आप सामने से आने वाले यातायात को रास्ता दिए बिना बाएं मुड़ना क्यों शुरू कर सकते हैं?","options":["क्योंकि हरे तीर का मतलब है कि पहले पूरी तरह रुकें और फिर तभी मुड़ें जब रास्ता साफ हो","क्योंकि हरा तीर केवल सावधानी देता है, इसलिए मुड़ने से पहले आपको गति धीमी करनी चाहिए और सामने से आने वाली कारों को रास्ता देना चाहिए","क्योंकि सामने से आने वाले यातायात के पास झपकती पीली बत्ती है जो उन्हें चौराहे से सावधानी से गुजरने को कहती है","क्योंकि हरा तीर एक संरक्षित मोड़ देता है: सामने से आने वाला यातायात लाल सिग्नल का सामना कर रहा है और तीर के दौरान रुका हुआ है"],"explanation":"A green arrow grants a protected turn in the arrow's direction because oncoming traffic faces a red signal and is stopped, so you may turn without yielding. A green arrow is not a stop-and-go or caution signal, and oncoming drivers are stopped by red, not waved through by a flashing yellow."}},"learn-signals-and-markings":{"0":{"q":"स्थिर हरी ट्रैफ़िक लाइट का क्या अर्थ है?","options":["यदि चौराहा खाली है तो आगे बढ़ें","लाइन के पीछे पूरी तरह रुकें","गति धीमी करें और सुरक्षित होने पर रुकें","इसे स्टॉप साइन की तरह मानें"],"explanation":"A steady green light means you may go if the intersection is clear, proceeding straight or turning after yielding."},"1":{"q":"स्थिर हरी बत्ती पर मुड़ने से पहले आपको क्या करना चाहिए?","options":["मोड़ पूरा करने के लिए गति बढ़ाएं","अन्य यातायात और पैदल चलने वालों को रास्ता दें","हमेशा पहले पूरी तरह रुकें","हरे तीर के दिखने का इंतज़ार करें"],"explanation":"At a steady green light you may turn only after yielding to other traffic and pedestrians."},"2":{"q":"स्थिर पीली ट्रैफिक लाइट का क्या मतलब है?","options":["चौराहा पार करने के लिए गति बढ़ाएं","लाइट अभी हरी हुई है","लाइट लाल होने वाली है","आपको रास्ते का अधिकार है"],"explanation":"A steady yellow light warns that the signal is about to turn red, so stop if you can do so safely."},"3":{"q":"स्थिर पीली ट्रैफिक लाइट पर आपको क्या करना चाहिए?","options":["लाल होने से पहले निकलने के लिए तेज़ हो जाएं","हमेशा पूरी तरह रुक जाएं","इसे अनदेखा करें और चलते रहें","यदि आप सुरक्षित रूप से रुक सकते हैं तो रुकें"],"explanation":"A steady yellow light means the light is about to turn red, so stop if you can do so safely and do not speed up."},"4":{"q":"स्थिर लाल बत्ती का क्या अर्थ है?","options":["हरी बत्ती होने तक पूरी तरह रुकें","गति धीमी करें और सावधानी से आगे बढ़ें","चौराहा खाली करने के लिए गति बढ़ाएं","यदि चौराहा खाली है तो आगे बढ़ें"],"explanation":"A steady red light means stop completely behind the line and stay stopped until the light turns green."},"5":{"q":"लाल बत्ती पर जहाँ दाएँ मुड़ने की अनुमति है, आपको पहले क्या करना चाहिए?","options":["गति बढ़ाएँ और दाएँ मुड़ें","पूरी तरह रुकें, फिर रास्ता साफ हो तो मुड़ें","बिना रुके मुड़ें","हरे तीर का इंतज़ार करें"],"explanation":"At a red light where right turns are permitted, you must stop completely, then turn right if it is clear and not prohibited by a sign."},"6":{"q":"चमकती लाल बत्ती पर आपको क्या करना चाहिए?","options":["तेज़ चलकर पार कर जाएं","धीमे हों पर चलते रहें","पूरी तरह रुकें, फिर सुरक्षित होने पर जाएं","पास कोई गाड़ी न हो तो अनदेखा करें"],"explanation":"A flashing red light means the same as a stop sign: stop fully, then go when it is safe."},"7":{"q":"चमकती पीली ट्रैफिक लाइट का क्या मतलब है?","options":["पूरी तरह रुकें, फिर चलें","लाइट जल्द ही लाल होने वाली है","आगे लेन बंद है","सावधानी: गति धीमी करें और सावधानी से आगे बढ़ें"],"explanation":"A flashing yellow light means caution, so slow down and proceed carefully without stopping."},"8":{"q":"हरे तीर का संकेत क्या दर्शाता है?","options":["तीर की दिशा में एक संरक्षित मोड़","रुकें और अगली बत्ती का इंतज़ार करें","गति धीमी करें और सामने से आने वाले यातायात को रास्ता दें","उस दिशा में मुड़ने की अनुमति नहीं है"],"explanation":"A green arrow means a protected turn in the arrow's direction, and oncoming traffic is stopped."},"9":{"q":"लाल तीर के संकेत का क्या अर्थ है?","options":["रास्ता साफ हो तो अभी मुड़ें","उस दिशा में मुड़ना मना है; प्रतीक्षा करें","जल्दी मुड़ने के लिए गति बढ़ाएँ","केवल ट्रकों के लिए मुड़ें"],"explanation":"A red arrow means no turn is allowed in that direction, so you must wait."},"10":{"q":"बंद या खराब ट्रैफ़िक सिग्नल को कैसे माना जाना चाहिए?","options":["तेज़ी से निकल जाएं","इसे हरी बत्ती मानें","इसे सभी दिशाओं वाला स्टॉप मानें","चौराहे को अनदेखा करें"],"explanation":"A dark or non-working signal should be treated as an all-way stop."},"11":{"q":"WALK (चलें) संकेत का क्या मतलब है?","options":["कारों को तेज़ होना चाहिए","साइकिलों को रुकना चाहिए","चालक बाएं मुड़ सकते हैं","पैदल यात्री पार कर सकते हैं"],"explanation":"A WALK signal or walking-person symbol means pedestrians may cross."},"12":{"q":"स्थिर DON'T WALK (न चलें) संकेत या स्थिर उठे हुए हाथ का चिह्न क्या दर्शाता है?","options":["पार करना शुरू न करें","अभी पार करना शुरू करें","केवल दौड़कर पार करें","अपनी कार चलाना बंद करें"],"explanation":"A steady DON'T WALK signal or steady raised-hand symbol means pedestrians should not start to cross."},"13":{"q":"टिमटिमाते \"न चलें\" या उठे हुए हाथ के संकेत का क्या अर्थ है?","options":["तुरंत सड़क पार करना शुरू करें","यदि शुरू कर दिया है तो पार करना पूरा करें, पर शुरू न करें","सड़क को तेज़ी से दौड़कर पार करें","केवल तभी पार करें जब कार इशारा करे"],"explanation":"A flashing DON'T WALK means finish crossing if you have already started, but do not begin to cross."},"14":{"q":"लेन-उपयोग सिग्नल पर हरे रंग का नीचे की ओर तीर का क्या अर्थ है?","options":["लेन बंद है","लेन से बाहर निकलें","लेन खुली है","धीमे चलें और रुकें"],"explanation":"A green down-arrow on a lane-use signal means the lane is open."},"15":{"q":"लेन-उपयोग सिग्नल पर लाल X का क्या अर्थ है?","options":["लेन खुली है","लेन में गति धीमी करें","जल्द ही लेन से बाहर निकलें","लेन बंद है"],"explanation":"A red X on a lane-use signal means the lane is closed."},"16":{"q":"लेन-उपयोग संकेत पर, आपकी लेन के ऊपर पीला X क्या दर्शाता है?","options":["लेन का उपयोग बदल रहा है, उससे बाहर निकलें","लेन खुली है, आप इसका उपयोग कर सकते हैं","लेन बंद है, इसका कभी उपयोग न करें","रुकें और लेन में प्रतीक्षा करें"],"explanation":"A yellow X means the lane is changing use, so you should move out of it."},"17":{"q":"सड़क पर आपकी ओर एक ठोस पीली रेखा का क्या अर्थ है?","options":["ओवरटेक करने की अनुमति है","ओवरटेक करना मना है","लेन बंद है","आगे रुकें"],"explanation":"A solid yellow line on your side of the road means you may not pass."},"18":{"q":"टूटी हुई (बिंदीदार) पीली रेखा का क्या अर्थ है?","options":["ओवरटेक करना मना है","रुकें और प्रतीक्षा करें","सुरक्षित होने पर ओवरटेक करना अनुमत है","लेन बंद है"],"explanation":"A broken (dashed) yellow line means passing is allowed when it is safe to do so."},"19":{"q":"दोहरी ठोस पीली रेखा का क्या मतलब है?","options":["दोनों दिशाओं में ओवरटेक करने की अनुमति है","लेन एक ही दिशा में जाती हैं","रास्ता साफ होने पर ओवरटेक कर सकते हैं","किसी भी दिशा में ओवरटेक करना मना है"],"explanation":"A double solid yellow line means no passing in either direction; do not cross it except to turn."},"20":{"q":"सड़क पर सफेद रेखाएं किसे अलग करती हैं?","options":["एक ही दिशा में जाने वाली लेन","विपरीत दिशा में जाने वाली लेन","पार्किंग स्थान","केवल साइकिल लेन"],"explanation":"White lines separate lanes of traffic traveling in the same direction."},"21":{"q":"टूटी हुई सफेद रेखा का क्या अर्थ है?","options":["ओवरटेक करने की अनुमति नहीं है","लेन बदलने की अनुमति है","आगे सड़क का किनारा है","यहाँ रुकें और प्रतीक्षा करें"],"explanation":"A broken white line means you may change lanes when it is safe."},"22":{"q":"ठोस सफेद रेखा का क्या अर्थ है?","options":["आप अन्य कारों को पास कर सकते हैं","लेन बदलने की अनुमति है","अपनी लेन में रहें","यातायात विपरीत दिशा में चलता है"],"explanation":"A solid white line means stay in your lane; crossing it is discouraged."},"23":{"q":"सड़क पर पीली रेखाएं किसे अलग करती हैं?","options":["एक ही दिशा में चलने वाला यातायात","साइकिल लेन को कार लेन से","पार्किंग स्थान","विपरीत दिशाओं में चलने वाला यातायात"],"explanation":"Yellow lines separate traffic moving in opposite directions, while white lines separate traffic moving in the same direction."},"24":{"q":"एक ठोस सफेद किनारा रेखा क्या दर्शाती है?","options":["सड़क का दायाँ किनारा","सड़क का बायाँ किनारा","सड़क का मध्य भाग","एक ओवरटेकिंग क्षेत्र"],"explanation":"A solid white edge line marks the right edge of the road."},"25":{"q":"सड़क पर पीली किनारा रेखा क्या दर्शाती है?","options":["सड़क का दायां किनारा","सड़क का बायां किनारा","साइकिल लेन का केंद्र","एक पैदल यात्री क्रॉसवॉक"],"explanation":"A yellow edge line marks the left edge of the road."},"26":{"q":"स्टॉप लाइन क्या है?","options":["पैदल चलने वालों के चलने के लिए एक रेखा","साइकिल लेन को चिह्नित करने वाली रेखा","एक चौड़ी सफेद रेखा जो दिखाती है कि कहाँ रुकना है","दोतरफा यातायात को अलग करने वाली रेखा"],"explanation":"A stop line is a wide white line that shows where to stop, and you must stop behind it."},"27":{"q":"सफेद रेखाओं से चिह्नित क्रॉसवॉक का क्या अर्थ है?","options":["यह सड़क के किनारे को चिह्नित करता है","यह एक कारपूल लेन है","यह यातायात के लिए बंद है","यह पैदल चलने वालों के लिए है; इसके पहले रुकें"],"explanation":"A crosswalk has white markings for pedestrians, and you must stop before it."},"28":{"q":"किसी लेन में बने हीरे के चिह्न का क्या अर्थ है?","options":["आरक्षित HOV या कारपूल लेन","केवल ट्रकों के लिए लेन","आगे साइकिल लेन","लेन बंद है"],"explanation":"A diamond symbol marks a reserved HOV, carpool, or special-use lane."},"29":{"q":"साइकिल लेन किसके लिए चिह्नित होती है?","options":["कार पार्क करने के लिए","साइकिलों के लिए","बाएं मुड़ने के लिए","आपातकालीन वाहनों के लिए"],"explanation":"A bike lane is marked for bicycles, and you should not drive or park in it."},"30":{"q":"पीला कर्ब आमतौर पर क्या दर्शाता है?","options":["किसी भी समय मुफ्त पार्किंग","विकलांगों के लिए आरक्षित पार्किंग","पार्किंग निषेध या लोडिंग प्रतिबंध","केवल बस स्टॉप"],"explanation":"A yellow curb indicates a no-parking or loading restriction, though curb colors vary by city."},"31":{"q":"कौन सा सड़क चिह्न रेलवे क्रॉसिंग की चेतावनी देता है?","options":["एक हीरे का प्रतीक","एक दोहरी पीली रेखा","एक सफेद पैदल-पार पथ","एक बड़ा RXR"],"explanation":"A railroad crossing is marked on the pavement with a large RXR and a stop line."},"32":{"q":"स्थिर पीली ट्रैफिक लाइट पर आपको क्या करना चाहिए?","options":["यदि आप सुरक्षित रूप से कर सकते हैं तो रुकें","लाइट पार करने के लिए गति बढ़ाएं","हमेशा पूरी तरह रुकें","पूरी तरह रुकें, फिर आगे बढ़ें"],"explanation":"A steady yellow light means the light is about to turn red, so stop if you can do so safely and do not speed up."},"33":{"q":"स्थिर लाल बत्ती पर, आपको कहाँ रुकना चाहिए?","options":["रेखा के ऊपर","रेखा के पीछे","रेखा के आगे","पैदल पार पथ में"],"explanation":"At a steady red light you must stop behind the line, not on or beyond it."},"34":{"q":"हरे तीर का संकेत क्या दर्शाता है?","options":["गति धीमी करें और सभी यातायात को रास्ता दें","रुकें और मुड़ने से पहले प्रतीक्षा करें","तीर की दिशा में संरक्षित मोड़","मुड़ने की अनुमति नहीं है"],"explanation":"A green arrow means a protected turn in the arrow's direction because oncoming traffic is stopped."},"35":{"q":"चमकती लाल बत्ती पर आपको क्या करना चाहिए?","options":["पार करने के लिए गति बढ़ाएँ","गति धीमी करें और सावधानी से आगे बढ़ें","इसे अनदेखा करें और चलते रहें","पूरी तरह रुकें, स्टॉप साइन की तरह"],"explanation":"A flashing red light means make a full stop and go when safe, just like a stop sign."},"36":{"q":"लाल बत्ती पर, अनुमत दायाँ मोड़ कब लिया जा सकता है?","options":["जब रास्ता साफ हो और कोई संकेत इसे प्रतिबंधित न करता हो","बिना रुके किसी भी समय","केवल जब कोई दूसरी कार पहले मुड़े","लाल बत्ती पर कभी नहीं"],"explanation":"At a red light you may turn right only when the way is clear and no sign prohibits it."},"37":{"q":"अगर सड़क पार करते समय DON'T WALK संकेत झपकाने लगे तो आपको क्या करना चाहिए?","options":["जहाँ हैं वहीं रुक जाएँ","सड़क पार करना पूरा करें","फुटपाथ पर वापस लौट आएँ","जल्दी से दौड़कर पार करें"],"explanation":"If the signal flashes while you are crossing, finish crossing rather than turn back."},"38":{"q":"किसी लेन के ऊपर लाल X का क्या अर्थ है?","options":["लेन खुली है","आपको लेन से बाहर निकलना होगा","लेन बंद है","पैदल यात्री पार कर सकते हैं"],"explanation":"A red X means the lane is closed, while a yellow X means the lane is changing use and you must move out of it."},"39":{"q":"टूटी हुई (बिंदुदार) पीली केंद्र रेखा का क्या अर्थ है?","options":["आपकी ओर ओवरटेक करना मना है","किसी भी दिशा में ओवरटेक करना मना है","लेन एक ही दिशा में जाती हैं","सुरक्षित होने पर ओवरटेक करने की अनुमति है"],"explanation":"A broken (dashed) yellow centerline means passing is allowed when it is safe."},"40":{"q":"आप दोहरी ठोस पीली रेखा को कब पार कर सकते हैं?","options":["केवल मुड़ने के लिए","केवल धीमी गाड़ियों को पार करने के लिए","जब भी रास्ता साफ हो, किसी भी समय","केवल रात में"],"explanation":"A double solid yellow line may be crossed only to make a turn."},"41":{"q":"ठोस सफेद रेखा पर आपको क्या करना चाहिए?","options":["अन्य कारों से आगे निकलें","अपनी लेन में रहें","यू-टर्न लें","अपनी कार पार्क करें"],"explanation":"A solid white line means you should stay in your lane, as crossing it is discouraged."},"42":{"q":"रुकने की रेखा पर आपको कहाँ रुकना चाहिए?","options":["रेखा के ऊपर","रेखा के आगे","रेखा के पीछे","पैदल पार पथ में"],"explanation":"A stop line shows where to stop, and you must stop behind it."},"43":{"q":"क्रॉसवॉक के निशान किस रंग के होते हैं?","options":["लाल","नीला","हरा","सफेद"],"explanation":"Crosswalk markings are white and are for pedestrians."},"44":{"q":"किसी लेन में बने हीरे (डायमंड) के चिह्न का क्या अर्थ है?","options":["लेन कारपूल और अधिक सवारियों वाले वाहनों (HOV) के लिए आरक्षित है","लेन एक साइकिल लेन है","लेन सभी यातायात के लिए बंद है","लेन केवल मुड़ने के लिए है"],"explanation":"A diamond symbol marks a lane reserved for carpools and high-occupancy (HOV) vehicles."},"45":{"q":"बाइक लेन में आप क्या कर सकते हैं?","options":["उसमें गाड़ी चलाना","न गाड़ी चलाना और न पार्क करना","उसमें पार्क करना","उसमें रुककर इंतजार करना"],"explanation":"You may not drive in a bike lane, and you may not park in a bike lane."},"46":{"q":"सड़क पर आपकी ओर एक ठोस पीली रेखा का क्या मतलब है?","options":["ओवरटेक करने की अनुमति है","लेन बंद है","ओवरटेक करना मना है","रुकें और प्रतीक्षा करें"],"explanation":"A solid yellow line on your side means no passing."},"47":{"q":"टेक्सास में कौन से यातायात संकेत और सिग्नल मानक लागू होते हैं?","options":["केवल शहर के नियम","केवल काउंटी के नियम","कोई निर्धारित मानक नहीं","साझा राष्ट्रीय मानक"],"explanation":"Texas follows the shared national MUTCD standards for signs and signals."},"48":{"q":"लगातार हरी ट्रैफिक लाइट का क्या मतलब है?","options":["केवल तभी आगे बढ़ें जब चौराहा खाली हो","रेखा के पीछे पूरी तरह रुकें","गति धीमी करें और रुकने के लिए तैयार रहें","उस दिशा में मुड़ने की अनुमति नहीं है"],"explanation":"A steady green light means go, but only proceed if the intersection is clear."},"49":{"q":"किसी लेन के ऊपर लाल X लेन-उपयोग सिग्नल का क्या अर्थ है?","options":["लेन खुली है","लेन बंद है","लेन मुड़ने के लिए है","लेन पार्किंग के लिए है"],"explanation":"A red X means the lane is closed, while a green down-arrow means the lane is open."},"50":{"q":"सड़क पर आपकी ओर एक ठोस पीली रेखा का क्या अर्थ है?","options":["ओवरटेक करने की अनुमति है","लेन बंद है","ओवरटेक करना मना है","रुकें और प्रतीक्षा करें"],"explanation":"A solid yellow line on your side means no passing, while a broken yellow line allows passing when safe."},"51":{"q":"विपरीत दिशाओं में चलने वाले यातायात को अलग करने वाली रेखाएं किस रंग की होती हैं?","options":["नीला","हरा","सफेद","पीला"],"explanation":"Yellow lines separate traffic moving in opposite directions and show passing rules."},"52":{"q":"एक ही दिशा में जाने वाली लेन को अलग करने वाली रेखाओं का रंग क्या होता है?","options":["सफेद","पीला","लाल","नीला"],"explanation":"White lines separate lanes of traffic traveling in the same direction."},"53":{"q":"यदि कोई ट्रेन आ रही हो तो रेलमार्ग क्रॉसिंग (RXR) चिह्न पर आपको क्या करना चाहिए?","options":["पहले पार करने के लिए तेज़ चलें","स्टॉप लाइन पर रुकें","हॉर्न बजाएँ और चलते रहें","लेन बदलें"],"explanation":"At a railroad crossing marked RXR with a stop line, you must stop if a train approaches."},"54":{"q":"जब ट्रैफिक सिग्नल पूरी तरह बंद हो या काम न कर रहा हो, तो चौराहे पर आपको क्या करना चाहिए?","options":["जल्दी निकलने के लिए गति बढ़ाएं","बिना गति कम किए आगे बढ़ें","इसे सभी दिशाओं वाले स्टॉप की तरह मानें","सिग्नल चालू होने तक प्रतीक्षा करें"],"explanation":"A dark or non-working signal should be treated as an all-way stop."},"55":{"q":"पैदल चलने वालों के लिए स्थिर उठे हुए हाथ (मत चलें) का संकेत क्या मतलब है?","options":["तेज़ी से पार करें","अभी दौड़कर पार करें","पार करना शुरू करें","पार करना शुरू न करें"],"explanation":"A steady raised-hand (DON'T WALK) signal means pedestrians should not start to cross."},"56":{"q":"पीले रंग का कर्ब आमतौर पर क्या दर्शाता है?","options":["पार्किंग नहीं या लोडिंग प्रतिबंध","किसी भी समय मुफ्त पार्किंग","केवल बसों के लिए आरक्षित","प्रतीक्षा करने के लिए सुरक्षित स्थान"],"explanation":"A yellow curb generally indicates a no-parking or loading restriction, though curb colors can vary by city."},"57":{"q":"स्थिर लाल तीर पर आपको क्या करना चाहिए?","options":["तीर की दिशा में मुड़ें","रुकें; उस दिशा में न मुड़ें","मोड़ पर गति बढ़ाएं","रास्ता दें, फिर स्वतंत्र रूप से मुड़ें"],"explanation":"A red arrow means you cannot turn in that direction and must wait until the signal changes."},"58":{"q":"सड़क पर टूटी हुई सफेद रेखा आपको क्या करने की अनुमति देती है?","options":["विपरीत दिशा से आ रहे वाहन को ओवरटेक करना","सड़क के बीच में रुकना","सुरक्षित होने पर लेन बदलना","सड़क के किनारे पार्क करना"],"explanation":"A broken white line allows you to change lanes when it is safe, while a solid white line means stay in your lane."},"59":{"q":"स्टॉप लाइन कैसी दिखती है?","options":["एक हरी टूटी हुई रेखा","छोटे बिंदुओं की एक पंक्ति","एक दोहरी पीली रेखा","लेन के आर-पार एक चौड़ी सफेद रेखा"],"explanation":"A stop line is a wide white line painted across the lane to show where to stop."}},"safe-driving":{"0":{"q":"आप सूखे राजमार्ग पर एक सेडान के पीछे चल रहे हैं। जैसे ही उसका पिछला बंपर सड़क किनारे लगे एक संकेत से गुज़रता है, आप गिनना शुरू करते हैं; उसी संकेत तक आप 2 सेकंड से थोड़ा कम समय में पहुँच जाते हैं। यह आपको क्या बताता है और आपको क्या करना चाहिए?","options":["आप बहुत पास से चल रहे हैं; गैस छोड़कर दूरी को कम से कम 3 सेकंड तक बढ़ाएँ।","आपकी दूरी सुरक्षित है क्योंकि सूखी सड़क पर 2 सेकंड अनुशंसित न्यूनतम है।","आपकी दूरी ठीक है; 3-सेकंड का नियम केवल बारिश, कोहरे या बर्फ में लागू होता है।","आपको तुरंत ज़ोर से ब्रेक लगाकर पीछे हटना चाहिए, क्योंकि आप ट्रक के ब्लाइंड स्पॉट में हैं।"],"explanation":"The three-second rule says that if you reach the fixed point in less than 3 seconds after the car ahead, you are too close, so easing off the gas to restore a 3-second gap is correct. Two seconds is not the safe minimum, the 3-second rule applies in all conditions (you add more seconds for bad weather), and braking hard or worrying about a truck's No-Zone does not fit this car-following scenario."},"1":{"q":"आप सामान्यतः आगे वाली कार से 3 सेकंड का अंतराल रखते हैं। आज रात हाईवे पर तेज़ बारिश शुरू हो जाती है और घना कोहरा छा जाता है। अपनी अनुसरण दूरी के बारे में आपको क्या करना चाहिए?","options":["वही 3 सेकंड का अंतराल बनाए रखें, क्योंकि तीन-सेकंड का नियम पहले से ही सभी ड्राइविंग परिस्थितियों को कवर करता है","अंतराल को 3 सेकंड से अधिक बढ़ाएँ, क्योंकि बारिश और कोहरा पकड़ और दृश्यता को कम कर देते हैं","अंतराल को कम करें ताकि आप कोहरे के बीच आगे वाली कार की पिछली बत्तियाँ साफ़ देख सकें","अपनी हाई बीम चालू करें और 2 सेकंड का अंतराल रखें ताकि उसकी ब्रेक लाइट पर तेज़ी से प्रतिक्रिया दे सकें"],"explanation":"The three-second rule is a minimum for good conditions; in rain, fog, ice, or at high speed you must add more seconds because traction and visibility are reduced. Shortening the gap or relying on high beams (which reflect back off fog) only increases your danger."},"2":{"q":"आप टेक्सास के एक हाईवे पर गाड़ी चला रहे हैं, तभी एक पिकअप ट्रक आपके पीछे बहुत करीब आ जाता है और आपके बंपर से कुछ ही फीट की दूरी पर रहता है, साफ़ तौर पर बहुत पास से पीछा कर रहा है। अपने वाहन के आसपास की जगह को संभालने का सबसे सुरक्षित तरीका क्या है?","options":["पीछे वाले को दूर हटने की चेतावनी देने के लिए कुछ बार ब्रेक हल्के से दबाएँ","गति बढ़ाएँ ताकि पीछा करने वाला वाहन और पीछे रह जाए","अपने और आगे वाले वाहन के बीच की दूरी बढ़ाएँ ताकि धीरे-धीरे ब्रेक लगाने के लिए आपके पास अधिक जगह हो","आगे वाली कार से ठीक तीन सेकंड पीछे रहें, क्योंकि यह नियम पहले से ही हर स्थिति को कवर करता है"],"explanation":"When you are being tailgated, you should increase your following distance to the vehicle ahead so you can slow down or stop gradually instead of braking hard, giving the tailgater more time to react. Three seconds is only a minimum baseline and should be increased behind motorcycles, large trucks, and when tailgated, so option D is wrong, and brake-tapping or speeding up only raises the risk of a crash."},"3":{"q":"आप एक बहु-लेन राजमार्ग पर एक 18-पहियों वाले ट्रक के बगल में चल रहे हैं, उसके केबिन के ठीक पीछे रहते हुए जहाँ से आप ट्रक चालक के साइड मिरर नहीं देख सकते। यह स्थिति आपको क्या बताती है और आपको क्या करना चाहिए?","options":["ट्रक चालक आपको ठीक से देख सकता है, इसलिए जब तक आप एक समान गति बनाए रखते हैं, आप वहाँ रह सकते हैं","आपको ट्रेलर के और करीब जाना चाहिए, क्योंकि सबसे सुरक्षित जगह पिछले पहियों के ठीक बगल में है","आगे निकलने से पहले ट्रक चालक को यह बताने के लिए कि आप वहाँ हैं, आपको अपनी हाई बीम लाइट चमकानी चाहिए","आप ट्रक के ब्लाइंड स्पॉट (No-Zone) में हैं क्योंकि आप चालक के मिरर नहीं देख सकते, इसलिए उससे बाहर निकलने के लिए गति बढ़ाएँ या पीछे हट जाएँ"],"explanation":"If you can't see a large truck's side mirrors, the driver can't see you, meaning you are sitting in a No-Zone blind spot; the safe response is to clear it quickly by speeding up to pass or easing back. Staying put, moving beside the rear wheels, or relying on high-beam flashes all leave you in the blind spot where the driver cannot see you."},"4":{"q":"टेक्सास के एक राजमार्ग पर गाड़ी चलाते समय, आप आगे एक खराब खड़ी कार देखते हैं और अपने वाहन को पूरी तरह रोक देते हैं। पीछे मुड़कर सोचने पर आपको एहसास होता है कि रुकने में आपकी अपेक्षा से अधिक समय लगा। खतरे के प्रकट होने के क्षण से लेकर पूरी तरह रुकने तक आपकी कार द्वारा तय की गई कुल दूरी किन तीन दूरियों के योग से बनती है?","options":["अनुभूति दूरी + प्रतिक्रिया दूरी + ब्रेकिंग दूरी","अनुभूति दूरी + प्रतिक्रिया दूरी + अनुसरण दूरी","प्रतिक्रिया दूरी + ब्रेकिंग दूरी + हाइड्रोप्लेनिंग दूरी","अनुसरण दूरी + ब्रेकिंग दूरी + हेडलाइट दृश्यता दूरी"],"explanation":"Total stopping distance is the sum of perception distance (seeing the hazard), reaction distance (moving your foot to the brake), and braking distance (the car slowing to a stop). Following distance, hydroplaning, and headlight sight distance are real safe-driving concepts but are not components of the stopping-distance formula."},"5":{"q":"सूखे राजमार्ग पर आपके आगे अचानक एक हिरण सड़क पर आ जाता है। जिस क्षण आपकी आँखें हिरण को देखती हैं, उस क्षण से लेकर जब तक आपका पैर वास्तव में ब्रेक दबाना शुरू करता है, तब तक आपकी कार आगे की ओर लुढ़कती रहती है। औसत चालक के लिए यह प्रतिक्रिया समय आमतौर पर लगभग कितना लगता है?","options":["लगभग 1.5 सेकंड","लगभग तीन-चौथाई (¾) सेकंड","लगभग 3 सेकंड","लगभग 35 सेकंड"],"explanation":"The average driver's reaction time is about ¾ of a second, so the car keeps moving during that interval before braking begins. Option A (about 1.5 s) is the combined perception-plus-reaction time, and 3 seconds is the safe-following-distance rule, not reaction time."},"6":{"q":"आप टेक्सास के एक हाईवे पर गाड़ी चला रहे हैं, तभी काफ़ी आगे अचानक एक हिरण सड़क पर आ जाता है। आपकी गाड़ी की गति कम होने से पहले दो चीज़ें होनी चाहिए: आपकी आँखें और दिमाग हिरण को पहचानें, और फिर आपको अपना पैर ब्रेक पर ले जाना होगा। ब्रेक के वास्तव में काम करना शुरू करने से पहले, यह बोध-और-प्रतिक्रिया प्रक्रिया मिलाकर लगभग कितना समय लेती है?","options":["लगभग 1,000 फ़ीट, वही दूरी जितना रात में आपको आगे देख पाना चाहिए","लगभग 3 सेकंड, क्योंकि यही सुरक्षित फॉलोइंग दूरी है जो आपको हमेशा बनाए रखनी चाहिए","मिलाकर लगभग 1.5 सेकंड, इससे पहले कि कोई ब्रेकिंग दूरी जोड़ी जाए","लगभग 35 mph, वह गति जिस पर गीली सड़कों पर हाइड्रोप्लेनिंग शुरू हो सकती है"],"explanation":"The combined perception-plus-reaction time is roughly 1.5 seconds, and this happens before braking distance is even added to the total stopping distance. The 3-second answer confuses the separate three-second following-distance rule with reaction time, and the other options misplace unrelated facts (night visibility distance and hydroplaning speed)."},"7":{"q":"टेक्सास के एक सूखे राजमार्ग पर ब्रेक लगाने के बाद 30 मील प्रति घंटे की गति से रुकने के लिए आपको आमतौर पर लगभग 45 फुट की ब्रेकिंग दूरी की आवश्यकता होती है। यातायात खुल जाता है और आप अपनी गति 30 मील प्रति घंटे से बढ़ाकर 60 मील प्रति घंटे कर देते हैं। अब रुकने के लिए आपको लगभग कितनी ब्रेकिंग दूरी की आवश्यकता होने की उम्मीद करनी चाहिए?","options":["लगभग वही 45 फुट, क्योंकि ब्रेकिंग दूरी गति के साथ ज्यादा नहीं बदलती","लगभग 90 फुट, क्योंकि गति दोगुनी करने से ब्रेकिंग दूरी दोगुनी हो जाती है","लगभग 68 फुट, क्योंकि ब्रेकिंग दूरी केवल लगभग आधी ही बढ़ती है","लगभग 180 फुट, क्योंकि गति दोगुनी करने से ब्रेकिंग दूरी लगभग चार गुना हो जाती है"],"explanation":"Braking distance increases with the square of speed, so doubling speed from 30 to 60 mph roughly quadruples it (45 feet x 4 = about 180 feet). Option B is the common trap of assuming the relationship is simply linear (double speed = double distance)."},"8":{"q":"आप 30 मील प्रति घंटे की एक आवासीय सड़क से निकलकर एक राजमार्ग पर जाते हैं जहाँ आप अपनी गति दोगुनी करके 60 मील प्रति घंटे कर देते हैं। तभी अचानक आपके आगे सड़क पर एक बच्चे की गेंद लुढ़क आती है। 30 मील प्रति घंटे पर रुकने की तुलना में, आपकी अधिक गति रुकने की क्षमता को कैसे बदल देती है?","options":["आपकी ब्रेकिंग दूरी लगभग चार गुना बढ़ जाती है, इसलिए रुकने में बहुत अधिक दूरी लगती है और कोई भी टक्कर अधिक जोर से लगेगी","आपकी ब्रेकिंग दूरी लगभग दोगुनी हो जाती है, जो आपकी गति में वृद्धि के बराबर है","आपकी रुकने की दूरी लगभग समान रहती है क्योंकि आपका प्रतिक्रिया समय अभी भी लगभग तीन-चौथाई सेकंड है","आपकी रुकने की दूरी कम हो जाती है क्योंकि अधिक गति ब्रेक को काम करने के लिए अधिक ऊर्जा देती है"],"explanation":"Braking distance increases with the square of speed, so doubling your speed from 30 to 60 mph roughly quadruples the braking distance and a crash carries far more energy. Doubling speed does not merely double braking distance, and a faster speed never shortens stopping distance even though reaction time stays about three-quarters of a second."},"9":{"q":"हाईवे पर लगातार बारिश हो रही है और लेन में पानी जमा है। आप लगभग 40 मील प्रति घंटे की रफ्तार से चल रहे हैं, तभी आपको लगता है कि स्टीयरिंग हल्का हो गया है और आगे के टायर पानी की सतह पर फिसलते हुए महसूस होते हैं। पकड़ (ट्रैक्शन) दोबारा पाने का सबसे सुरक्षित तरीका क्या है?","options":["टायरों को धीमा करने और दोबारा सड़क पर पकड़ बनाने के लिए जोर से ब्रेक लगाएं","एक्सेलरेटर से पैर हटा लें, स्टीयरिंग सीधा रखें और जोर से ब्रेक न लगाएं","कार के अगले हिस्से को जिस दिशा में ले जाना है उस ओर स्टीयरिंग घुमाएं और ब्रेक को रुक-रुक कर दबाएं","हाई बीम चालू करें और अपनी फॉलोइंग दूरी में एक सेकंड जोड़ें"],"explanation":"You are hydroplaning, which can begin near 35 mph as water builds under the tires; easing off the gas, steering straight, and avoiding hard braking lets the tires settle back onto the road. Braking firmly (A) can lock the tires and worsen the slide, and steering/pumping advice (C) is the procedure for a skid, not hydroplaning."},"10":{"q":"आप तेज़ बारिश के दौरान टेक्सास के एक हाईवे पर 45 मील प्रति घंटे की रफ़्तार से गाड़ी चला रहे हैं, तभी अचानक आपको स्टीयरिंग हल्की महसूस होती है और गाड़ी पानी पर तैरती हुई सी फिसलने लगती है। आपको क्या करना चाहिए?","options":["टायरों को फिर से सड़क पर पकड़ बनाने के लिए ब्रेक पेडल को ज़ोर से दबाएँ-छोड़ें","जिस दिशा में आप गाड़ी का अगला हिस्सा ले जाना चाहते हैं उस ओर स्टीयरिंग घुमाएँ और हल्के से ब्रेक लगाएँ","गैस से पैर हटा लें, स्टीयरिंग को स्थिर और सीधा रखें, और ज़ोर से ब्रेक लगाने से बचें","तुरंत ज़ोर से ब्रेक लगाएँ और गति कम करने के लिए नीचे के गियर में डालें"],"explanation":"When hydroplaning, the tires lose contact with the road, so you should ease off the gas, hold the wheel straight, and avoid braking hard until traction returns. Braking hard (A, D) can cause a skid, and the steer-where-you-want technique (B) applies to correcting a skid, not recovering from hydroplaning."},"11":{"q":"तीन सप्ताह तक बारिश न होने के बाद, जब आप शहर में गाड़ी चला रहे होते हैं तो हल्की बूंदाबांदी शुरू हो जाती है। सड़क की सतह बमुश्किल गीली दिखती है, और आपके आसपास का यातायात सामान्य गति सीमा पर चलता रहता है। आपको अभी ट्रैक्शन के बारे में विशेष रूप से सावधान क्यों रहना चाहिए?","options":["हल्की बारिश ट्रैक्शन को कम नहीं कर सकती, इसलिए एकमात्र वास्तविक खतरा भारी मूसलाधार बारिश है जो सड़क पर पानी जमा करती है","बारिश की शुरुआत में केवल पुल और ओवरपास ही फिसलन भरे होते हैं","सड़क तब सबसे अधिक फिसलन भरी होती है जब लगभग 35 मील प्रति घंटे पर हाइड्रोप्लेनिंग शुरू करने के लिए पर्याप्त पानी जमा हो जाता है","सूखे समय में जमा हुआ तेल और ग्रीस पहली हल्की बारिश के साथ मिल जाता है, जिससे सड़क अभी सबसे अधिक फिसलन भरी हो जाती है"],"explanation":"The first rain after a dry spell is the most slippery because accumulated oil and grease mix with the water before being washed away, so a light early drizzle is more dangerous than it looks. Option C is a real fact about hydroplaning but describes a different hazard that needs water to build up, not the slick oily film of the first rain."},"12":{"q":"एक साफ़ सुबह तापमान हिमांक से थोड़ा नीचे है और आप एक ग्रामीण राजमार्ग पर गाड़ी चला रहे हैं। आगे की सड़क की सतह सूखी दिखती है और आपको अच्छी पकड़ महसूस होती है। एक नाले पर बने पुल के पास पहुँचते समय आपको क्या करना चाहिए?","options":["गैस से पैर हटाकर पुल से पहले गति कम कर दें, क्योंकि पुल और ओवरपास बाकी सड़क से पहले जम जाते हैं","अपनी गति बनाए रखें, क्योंकि पीछे की सूखी सड़क यह साबित करती है कि पुल की सतह भी सुरक्षित है","यह जाँचने के लिए कि सतह फिसलन भरी है या नहीं, पुल पर पहुँचते ही ज़ोर से ब्रेक लगाएँ","पुल पर बर्फ़ को जल्दी देख पाने के लिए हाई बीम चालू कर दें"],"explanation":"Bridges and overpasses are exposed to cold air on all sides, so they freeze before regular pavement; easing off the gas and slowing down before the bridge is the safe response. Maintaining speed because the road behind feels dry ignores that the bridge can be icy even when the surrounding road is not, and braking hard on a possibly icy surface can cause a skid."},"13":{"q":"एक साफ, बहुत ठंडी सर्दियों की सुबह है, तापमान लगभग -1°C। आप एक हाईवे पर गाड़ी चला रहे हैं और एक ओवरपास के पास पहुँच रहे हैं। आगे की सड़क थोड़ी गहरे रंग की और गीली दिख रही है, लेकिन आपको कोई स्पष्ट बर्फ नहीं दिखती। इस स्थिति को संभालने का सबसे सुरक्षित तरीका क्या है?","options":["सड़क केवल गीली दिख रही है, इसलिए अपनी गति बनाए रखें और यदि फिसलने लगें तो जोर से ब्रेक लगाएँ","गहरे रंग के, गीले दिखने वाले हिस्से को संभावित ब्लैक आइस मानें; ओवरपास से पहले धीरे-धीरे गति कम करें और अचानक ब्रेक लगाने या स्टीयरिंग घुमाने से बचें","हाई बीम पर स्विच करें ताकि गीली सड़क अधिक रोशनी परावर्तित करे और आप सतह को बेहतर देख सकें","गति बढ़ाकर ओवरपास को जल्दी पार करें ताकि आप फिसलन भरी सतह पर कम समय बिताएँ"],"explanation":"Bridges and overpasses freeze first, and black ice is hard to see, so a dark, wet-looking patch in freezing temperatures should be treated as ice by slowing gradually and avoiding sudden braking or steering. Maintaining speed (A) assumes the surface is only wet, and speeding up (D) increases the risk of a skid you cannot control."},"14":{"q":"आप टेक्सास के एक नम राजमार्ग पर गाड़ी चला रहे हैं, तभी आपकी कार का पिछला हिस्सा अचानक दाईं ओर फिसल जाता है और पीछे का भाग बाहर की ओर घूमने लगता है। नियंत्रण वापस पाने के लिए आपको क्या करना चाहिए?","options":["कार को तुरंत धीमा करने के लिए ब्रेक पर मजबूती से दबाएं, फिर पहिए को सीधा करें","कार को आगे खींचकर फिसलन से बाहर निकालने के लिए गैस पर लगातार दबाव बनाए रखें","अपना पैर गैस से हटा लें और स्टीयरिंग को उस दिशा में घुमाएं जिधर आप कार के अगले हिस्से को ले जाना चाहते हैं, बिना ब्रेक पर जोर से दबाए","निचले गियर में शिफ्ट करें और पकड़ वापस आने तक ब्रेक पेडल को बार-बार पंप करें"],"explanation":"In a skid you should ease off the gas and steer in the direction you want the front of the car to go, never slamming the brakes, which would only worsen the loss of traction. Hard braking (A) and pumping the brake while downshifting (D) are recovery steps for other emergencies, not skids, and holding the gas (B) keeps the wheels spinning."},"15":{"q":"आप रात में एक ग्रामीण राजमार्ग पर गाड़ी चला रहे हैं, तभी अचानक आप घने कोहरे के झुंड में प्रवेश कर जाते हैं और आगे की सड़क मुश्किल से देख पाते हैं। आपको क्या करना चाहिए?","options":["अपनी हाई बीम चालू करें ताकि तेज़ रोशनी कोहरे को चीरते हुए और दूर तक पहुंचे","अपनी मौजूदा गति बनाए रखें लेकिन दिखाई देते रहने के लिए हैज़र्ड फ्लैशर चालू करें","सड़क के दाहिने किनारे की ओर मुड़ें और चकाचौंध से नज़रें हटा लें","लो बीम पर स्विच करें, गति कम करें, और अगर दृश्यता बहुत खराब हो जाए तो सुरक्षित रूप से सड़क के किनारे रुक जाएं"],"explanation":"In fog or smoke you should use low beams because high beams reflect off the moisture and glare back at you, and you should slow down or pull off safely. High beams (A) make visibility worse, and looking to the right edge (C) is the response for oncoming headlight glare, not fog."},"16":{"q":"आप एक साफ दोपहर को घर जा रहे हैं, तभी एक तेज़ तूफ़ान आ जाता है। दृश्यता इतनी कम हो जाती है कि आप सूर्यास्त में काफ़ी समय बाकी होने के बावजूद लगभग 800 फीट आगे के एक सड़क संकेत को मुश्किल से देख पाते हैं। आपको अपनी हेडलाइट्स के बारे में क्या करना चाहिए?","options":["अपनी हेडलाइट्स चालू करें, क्योंकि जब भी आप लगभग 1,000 फीट आगे तक नहीं देख सकते, तब आपको दिन के समय की परवाह किए बिना उन्हें उपयोग करना ज़रूरी है।","हेडलाइट्स बंद रखें, क्योंकि उन्हें उपयोग करने का नियम केवल सूर्यास्त और सूर्योदय के बीच ही लागू होता है।","बारिश को चीरकर देखने की दूरी बढ़ाने के लिए अपनी हाई बीम चालू करें।","हेडलाइट्स बंद रखें पर गति धीमी करें, क्योंकि हेडलाइट्स केवल तभी ज़रूरी हैं जब आप लगभग 500 फीट आगे तक नहीं देख सकते।"],"explanation":"Texas requires headlights from sunset to sunrise AND any time you cannot see about 1,000 feet ahead, so the reduced visibility means you must turn them on even in daylight. High beams reflect off rain and fog and make it harder to see, and 500 feet is the dimming distance for oncoming traffic, not the visibility threshold for using lights."},"17":{"q":"आप रात में एक अंधेरी, दो-लेन वाली ग्रामीण सड़क पर अपनी हाई बीम जलाकर चला रहे हैं। आप विपरीत लेन में अपनी ओर आते हुए एक वाहन को देखते हैं, और आपका अनुमान है कि वह अब 500 फीट से थोड़ा कम दूरी पर है। आपको क्या करना चाहिए?","options":["जब तक सामने वाला वाहन पहले अपनी रोशनी कम न कर ले, तब तक अपनी हाई बीम जलाए रखें","अभी अपनी हाई बीम को लो बीम पर कर दें","लो बीम पर तभी जाएं जब आप किसी अन्य वाहन के 300 फीट पीछे भी हों","सामने आ रहे चालक को सचेत करने के लिए अपनी हाई बीम चमकाएं, फिर हाई बीम पर ही चलते रहें"],"explanation":"टेक्सास में सामने से आते वाहन के 500 फीट के भीतर होने पर हाई बीम को लो बीम पर करना आवश्यक है, इसलिए आपको अभी बदलना चाहिए। दूसरे चालक का इंतज़ार करना (A) या बीम चमकाना (D) सड़क पर चकाचौंध बनाए रखता है, और 300 फीट का नियम (C) किसी वाहन के पीछे चलने पर लागू होता है, सामने से आते यातायात पर नहीं।"},"18":{"q":"आप रात में एक अंधेरे ग्रामीण राजमार्ग पर अपनी हाई बीम चालू रखकर गाड़ी चला रहे हैं। आप आगे चल रही एक धीमी कार के पास पहुँच जाते हैं और धीरे-धीरे दूरी कम करते हुए उसके लगभग 250 फीट पीछे आ जाते हैं, और सामने से कोई वाहन नहीं दिख रहा। आपको अपनी हाई बीम के साथ क्या करना चाहिए?","options":["हाई बीम चालू रखें, क्योंकि कम करने का नियम केवल सामने से आने वाले वाहनों पर लागू होता है","आगे वाली कार से 100 फीट की दूरी तक हाई बीम चालू रखें, फिर लो बीम पर स्विच करें","अभी लो बीम पर स्विच करें, क्योंकि किसी अन्य वाहन के पीछे 300 फीट के भीतर होने पर आपको हाई बीम कम करनी चाहिए","हाई बीम चालू रखें लेकिन चकाचौंध से बचने के लिए सड़क के दाहिने किनारे की ओर देखें"],"explanation":"Texas law requires you to dim your high beams to low when within 300 feet behind another vehicle, so at 250 feet you must already be on low beams. The high beams glare in the lead driver's mirrors; the 500-foot rule (A) applies to oncoming traffic, and looking to the right edge (D) is the technique for when you are blinded, not for following."},"19":{"q":"आप रात में एक अंधेरे दो-लेन वाले राजमार्ग पर गाड़ी चला रहे हैं, तभी सामने से आ रही एक कार अपनी हाई बीम लाइटें कम नहीं करती, और चकाचौंध से आपको आगे की सड़क देखना मुश्किल हो जाता है। जब तक वाहन गुजर न जाए, तब तक नियंत्रण बनाए रखने के लिए आपको क्या करना चाहिए?","options":["अपनी हाई बीम लाइटें चालू कर दें ताकि दूसरा चालक देख सके कि यह कितनी तेज़ है और अपनी लाइटें कम कर ले","तुरंत ज़ोर से ब्रेक लगाएं और अपनी आँखें ठीक होने तक अपनी लेन में रुक जाएं","सामने से आ रही हेडलाइट्स को सीधे देखते रहें ताकि आप ठीक-ठीक पता लगा सकें कि दूसरी कार कहाँ है","गति धीमी करें और जब तक वाहन गुजर न जाए, तब तक अपनी लेन के दाहिने किनारे की ओर देखें"],"explanation":"When blinded by oncoming high beams, you should look toward the right edge of the road to avoid the glare while still guiding your car. Flashing your own high beams or staring into the lights only worsens the blindness, and stopping hard in a travel lane risks a rear-end collision."},"20":{"q":"आप रात को एक अंधेरे ग्रामीण राजमार्ग पर अपनी लो बीम के साथ गाड़ी चला रहे हैं। आगे की सड़क केवल उतनी दूर तक रोशन है जितनी दूर आपकी हेडलाइटों की रोशनी पहुँचती है, और आप इतनी तेज़ी से चल रहे हैं कि अगर कोई हिरन अचानक उस रोशन क्षेत्र में आ जाए, तो वह आपके प्रतिक्रिया करके ब्रेक लगाने से पहले ही आपकी रुकने की दूरी के भीतर आ जाएगा। आप कौन सी गलती कर रहे हैं?","options":["आप अपनी हेडलाइटों से आगे गाड़ी चला रहे हैं—इतनी तेज़ी चल रहे हैं कि आगे की रोशन दूरी के भीतर रुक नहीं सकते","आप इन परिस्थितियों के लिए तीन-सेकंड नियम का गलत पालन कर रहे हैं","आपने सामने से आ रहे वाहन के 500 फीट के भीतर अपनी हाई बीम को लो बीम में नहीं किया","आप हाइड्रोप्लेनिंग कर रहे हैं क्योंकि आपकी गति इस सतह के लिए सुरक्षित सीमा से अधिक हो गई"],"explanation":"Overdriving your headlights means traveling so fast that you cannot stop within the distance your headlights illuminate ahead, which is exactly the scenario described. The three-second rule applies to spacing behind another vehicle, dimming high beams concerns glare to others, and hydroplaning involves water on the road—none fit a dry night road with a fixed lighted distance."},"21":{"q":"आप एक लंबी ढलान से नीचे जा रहे हैं, तभी आप ब्रेक पेडल दबाते हैं और वह बिना किसी प्रतिरोध के फर्श तक धंस जाता है। कार की गति बढ़ती जा रही है। धीमा होकर रुकने का सबसे अच्छा तरीका क्या है?","options":["स्टीयरिंग को मजबूती से पकड़ें, गैस से पैर हटाएं और जोर से ब्रेक न लगाएं, फिर धीरे-धीरे सड़क से किनारे हटें","ब्रेक पेडल को बार-बार दबाएं (पंप करें), नीचे के गियर में बदलें और पार्किंग ब्रेक को धीरे-धीरे लगाएं","गैस से पैर हटाएं और स्टीयरिंग को उस दिशा में मोड़ें जिधर आप कार का अगला हिस्सा ले जाना चाहते हैं","पार्किंग ब्रेक को एक ही बार में पूरा ऊपर खींच लें और गति रोकने के लिए इंजन बंद कर दें"],"explanation":"When the brakes fail, pumping the pedal may restore some pressure, shifting to a lower gear uses engine braking to slow you, and applying the parking brake gradually brings you to a stop. Option A is the correct response to a tire blowout, and pulling the parking brake all the way up at once (D) can cause a skid."},"22":{"q":"आप टेक्सास के एक हाईवे पर 60 मील प्रति घंटे की रफ्तार से गाड़ी चला रहे हैं, तभी आपको एक तेज़ धमाका सुनाई देता है और स्टीयरिंग अचानक एक तरफ ज़ोर से खिंचने लगता है। आपको एहसास होता है कि अगला टायर फट गया है। नियंत्रण वापस पाने का सबसे सुरक्षित तरीका क्या है?","options":["गाड़ी और ज़्यादा बहकने से पहले जितनी जल्दी हो सके रुकने के लिए तुरंत ज़ोर से ब्रेक लगाएं","खिंचाव की भरपाई के लिए स्टीयरिंग को विपरीत दिशा में झटके से घुमाएं, फिर ज़ोर से ब्रेक लगाकर किनारे लगाएं","स्टीयरिंग को मज़बूती से पकड़ें, धीरे से एक्सेलेरेटर से पैर हटाएं, और गाड़ी को धीरे-धीरे धीमा होने दें फिर सड़क से किनारे उतरें","ब्रेक पेडल को पंप करें और गाड़ी की रफ्तार कम करने के लिए नीचे के गियर में डालें"],"explanation":"In a blowout you hold the wheel firmly, ease off the gas, and avoid braking hard, then pull off slowly once the car has slowed. Braking hard (A) or jerking the wheel (B) can cause a complete loss of control, and pumping the pedal with a lower gear (D) is the technique for brake failure, not a tire blowout."},"23":{"q":"किसी ग्रामीण क्रॉसिंग पर रेलवे पटरी पार करते समय आपकी कार का इंजन बंद हो जाता है। कार दोबारा स्टार्ट नहीं होती, और आप दूर से एक ट्रेन को आते हुए देख सकते हैं। आपको क्या करना चाहिए?","options":["सीट बेल्ट बांधे कार में ही बैठे रहें और कार को पटरी से हटाने के लिए तेज़ी से ब्रेक पेडल दबाएं","अपनी खतरे वाली फ्लैशर लाइटें चालू करें और ट्रेन के गुज़रने तक वाहन में प्रतीक्षा करें","नीचे के गियर में डालें और ट्रेन के क्रॉसिंग तक पहुंचने से पहले पार करने की कोशिश करें","सभी को कार से बाहर निकालें और पटरी से दूर चले जाएं, फिर मदद के लिए कॉल करें"],"explanation":"If your vehicle stalls on railroad tracks, the only priority is getting everyone out and well away from the tracks before calling for help, because you can never safely beat an approaching train. Pumping the brake, waiting in the car, or trying to drive across all keep people in the path of the train."},"24":{"q":"ग्रामीण दो-लेन वाले राजमार्ग पर आपके इंजन की शक्ति अचानक खत्म हो जाती है और आप गाड़ी को लुढ़काकर सड़क के किनारे तक ले आते हैं। वहाँ एक चौड़ी पक्की कंधा-पट्टी (शोल्डर) उपलब्ध है। मदद की प्रतीक्षा करते समय रुकने और स्वयं की सुरक्षा करने का सही तरीका क्या है?","options":["पूरी तरह से शोल्डर पर ले जाएँ, अपनी हैज़र्ड फ्लैशर लाइटें चालू करें, और वाहन के पीछे चेतावनी उपकरण लगाएँ।","अपनी लेन में पार्किंग ब्रेक लगाकर रुकें ताकि दूसरे चालक आपको साफ देख सकें, और अपनी हेडलाइटें चालू करें।","कार का पिछला हिस्सा लेन में छोड़ दें, ब्रेक पेडल को बार-बार दबाएँ, और दिखाई देते रहने के लिए नीचे के गियर में बदलें।","कार को आधा शोल्डर पर पार्क करें, बाहर निकलें, और लेन में खड़े होकर यातायात को अपने चारों ओर से जाने का इशारा करें।"],"explanation":"If you must stop on the road, pull fully onto the shoulder, turn on your hazard flashers, and use warning devices so approaching traffic is alerted. Stopping in the lane or leaving part of the car in traffic exposes you to a rear-end crash, and pumping the brake/shifting down is the procedure for brake failure, not a stopped breakdown."},"25":{"q":"आप एक लंबी यात्रा पर छह घंटे से गाड़ी चला रहे हैं और महसूस करते हैं कि आप लगातार जम्हाई ले रहे हैं, गाड़ी लेन की रेखा की ओर बहक रही है, और आपको पिछले कुछ मील याद करने में मुश्किल हो रही है। आपके गंतव्य तक पहुंचने में अभी भी दो घंटे बाकी हैं। आपको क्या करना चाहिए?","options":["सतर्क रहने के लिए खिड़की नीचे करें और रेडियो की आवाज़ तेज़ करें, फिर अपने गंतव्य तक गाड़ी चलाते रहें","किसी सुरक्षित विश्राम स्थल पर रुकें और झपकी लें या रात भर रुक जाएं, क्योंकि उनींदापन शराब की तरह ही आपकी प्रतिक्रिया समय और निर्णय क्षमता को धीमा कर देता है","अपनी अनुसरण दूरी को तीन-सेकंड नियम तक बढ़ाएं और शेष दो घंटे गाड़ी चलाते रहें","आगे तक देखने के लिए हाई बीम चालू करें और आखिरी दो घंटे जैसे-तैसे पूरे करें"],"explanation":"Fatigue slows reaction time and impairs judgment much like drugs or alcohol, so the only safe choice is to stop and rest rather than drive drowsy. Tricks like fresh air, loud music, or a longer following distance do not cure drowsiness, and high beams have nothing to do with the danger of falling asleep at the wheel."},"26":{"q":"टेक्सास में आप लाल बत्ती पर रुके हुए हैं, तभी आपके फ़ोन पर एक टेक्स्ट संदेश आता है। बत्ती अभी भी लाल है और यातायात भारी है। आपको क्या करना चाहिए?","options":["रुके हुए अभी जल्दी से जवाब दे दें, क्योंकि बत्ती हरी होने से पहले इसे निपटा लेना सबसे सुरक्षित समय है","केवल पढ़ने के लिए स्क्रीन पर नज़र डालें, क्योंकि जब तक आप टाइप नहीं करते, तब तक संदेश पढ़ना अनुमत है","फ़ोन को छुएं नहीं और तब तक प्रतीक्षा करें जब तक आप सुरक्षित रूप से पार्क न कर लें, क्योंकि टेक्सास में गाड़ी चलाते समय टेक्स्ट करना अवैध है और एक बड़ा ध्यान भटकाने वाला कारक है","जवाब दें, लेकिन पहले अपनी ख़तरे की चेतावनी वाली लाइटें (हैज़र्ड फ़्लैशर) चालू करें ताकि चालकों को पता चले कि आप अस्थायी रूप से व्यस्त हैं"],"explanation":"Texting while driving is illegal in Texas and is a major distraction, so you should not text from behind the wheel even when stopped at a light; wait until you are safely parked. Reading or replying at a red light is still using the phone to text, and hazard flashers are for a disabled or stopped-on-the-road vehicle, not for excusing phone use."},"27":{"q":"आप टेक्सास में अपने दो दोस्तों को एक खेल के लिए ले जा रहे हैं। एक आगे बैठता है, दूसरा पीछे की सीट पर चढ़ता है और कहता है, \"मैं बेल्ट नहीं लगाऊंगा, मुझे तो बस दस मिनट पीछे बैठना है।\" गाड़ी निकालने से पहले आपको क्या करना चाहिए?","options":["पीछे बैठे यात्री को बिना बेल्ट के बैठने दें, क्योंकि सीट बेल्ट के नियम केवल चालक और आगे की सीट के यात्रियों पर लागू होते हैं","इसकी अनुमति दें क्योंकि यात्रा छोटी है और आप धीमी गति वाली मोहल्ले की सड़कों पर ही रहेंगे","उसे अपना फोन दें ताकि वह किसी को मैसेज करके दूसरी सवारी बुला ले, जिससे उसे बिना बेल्ट के न बैठना पड़े","गाड़ी चलाने से पहले उससे बेल्ट लगाने पर जोर दें, क्योंकि टेक्सास का कानून चालक और सभी यात्रियों के लिए सीट बेल्ट पहनना अनिवार्य करता है"],"explanation":"Texas law requires a seat belt for the driver and every passenger, including those in the back seat, regardless of how short the trip is. Options A and B rely on common myths (rear seats are exempt, or short/slow trips don't count), and texting while driving is itself illegal and unsafe."},"28":{"q":"आप एक सूखे राजमार्ग पर एक पिकअप ट्रक के पीछे गाड़ी चला रहे हैं। अपनी अनुसरण दूरी जांचने के लिए, आप देखते हैं कि ट्रक सड़क पर एक ओवरपास की छाया को पार करता है, फिर तब तक गिनते हैं जब तक आपकी कार का अगला हिस्सा उसी स्थान पर न पहुंच जाए। आपकी अनुसरण दूरी को पर्याप्त माने जाने के लिए यह गिनती कितनी होनी चाहिए?","options":["ट्रक के उस बिंदु को पार करने के तीन सेकंड या उससे अधिक बाद","ट्रक के उस बिंदु को पार करने के तीन सेकंड से कम बाद","लगभग तीन-चौथाई सेकंड, जो औसत प्रतिक्रिया समय के बराबर है","ट्रक के पीछे ठीक 500 फीट की जगह"],"explanation":"With the three-second rule, you pick a fixed point and count; reaching it in three seconds or more after the vehicle ahead means your following distance is adequate. Reaching it in less than three seconds means you are too close, while three-quarters of a second describes average reaction time and 500 feet is the high-beam dimming distance, not a following gap."},"29":{"q":"आप सूखे राजमार्ग पर एक पिकअप ट्रक के पीछे चल रहे हैं और तीन-सेकंड नियम का उपयोग करके यह जाँचना चाहते हैं कि क्या आप सुरक्षित अनुसरण दूरी बनाए रख रहे हैं। ट्रक का पिछला बंपर अभी-अभी आगे एक सड़क संकेत को पार कर गया। नियम को सही ढंग से लागू करने के लिए आपको क्या करना चाहिए?","options":["जब ट्रक संकेत को पार करे तब गिनना शुरू करें और तीन सेकंड बाद रुक जाएँ, फिर सुनिश्चित करें कि ट्रक अब भी उस दूरी के भीतर है।","जब ट्रक का पिछला हिस्सा संकेत को पार करे तब गिनना शुरू करें और जब आपका अगला बंपर उसी संकेत तक पहुँचे तब रुकें; यदि तीन सेकंड से कम है, तो आप बहुत पास चल रहे हैं।","अपने अगले बंपर और ट्रक के पिछले बंपर के बीच तीन वाहन लंबाई की दूरी मापें।","ट्रक के संकेत पार करने के क्षण से पूरी तरह रुकने तक के सेकंड गिनें।"],"explanation":"The three-second rule works by picking a fixed point and counting the seconds between when the vehicle ahead passes it and when you pass the same point; under three seconds means you're following too closely. Fixed car-length spacing (C) and timing the lead vehicle's stop (D) are not how the rule works."},"30":{"q":"आप एक साफ हाईवे पर गाड़ी चला रहे हैं और अचानक आपके आगे सड़क पर एक हिरण कूद आता है। आप उसे देखते हैं, रुकने का फैसला करते हैं और ब्रेक दबाते हैं। एक बार जब आपका पैर ब्रेक पेडल दबा देता है, उसके बाद आपकी गाड़ी पूरी तरह रुकने से पहले जितनी दूरी तय करती रहती है, उसे क्या कहते हैं?","options":["कुल रुकने की दूरी, जो हिरण को देखने से लेकर गाड़ी के रुकने तक की पूरी दूरी है","प्रतिक्रिया दूरी, वह दूरी जो आप ब्रेक दबाने का फैसला करते समय तय करते हैं","ब्रेकिंग दूरी, कुल रुकने की दूरी के तीन घटकों में से एक","अनुभूति दूरी, वह दूरी जो आपकी आंखों के हिरण को नोटिस करने से पहले तय होती है"],"explanation":"Braking distance is the distance the vehicle travels from the moment the brakes are applied until it stops, and it is one of the three components of total stopping distance (perception + reaction + braking). Total stopping distance is the sum of all three, not just the part after braking begins, so that option is the trap."},"31":{"q":"आप हाईवे की गति से गाड़ी चला रहे हैं, तभी बहुत आगे एक हिरण अचानक आपकी लेन में आ जाता है। आपके पैर के ब्रेक पेडल को छूने से पहले ही आपका वाहन कुछ दूरी तय कर चुका होता है। कुल रुकने की दूरी के कौन से घटक उस दूरी के लिए जिम्मेदार हैं जो ब्रेक वास्तव में लगाए जाने से पहले तय हो जाती है?","options":["ब्रेकिंग दूरी और प्रतिक्रिया दूरी","अनुभव (परसेप्शन) दूरी और ब्रेकिंग दूरी","केवल ब्रेकिंग दूरी, क्योंकि पहिए लॉक होने तक कार चलती रहती है","अनुभव (परसेप्शन) दूरी और प्रतिक्रिया दूरी"],"explanation":"Total stopping distance is perception distance plus reaction distance plus braking distance, and only perception and reaction distance occur before the brakes are applied; braking distance is the travel after the brakes engage, so any option containing braking distance is wrong."},"32":{"q":"भारी बारिश के तूफान के दौरान आप टेक्सास के एक राजमार्ग पर लगभग 40 मील प्रति घंटे की रफ्तार से गाड़ी चला रहे हैं, तभी अचानक आपको स्टीयरिंग हल्की महसूस होती है और कार पानी के ऊपर फिसलने लगती है तथा स्टीयरिंग पर प्रतिक्रिया नहीं देती। प्रतिक्रिया करने का सबसे सुरक्षित तरीका क्या है?","options":["अपना पैर धीरे-धीरे एक्सेलरेटर से हटाएं, स्टीयरिंग व्हील को सीधा रखें और कार को तब तक धीमा होने दें जब तक टायर फिर से पकड़ न लें","गति कम करने और जल्दी से ट्रैक्शन वापस पाने के लिए ब्रेक पर मजबूती और स्थिरता से दबाव डालें","पानी की परत से बाहर निकलने के लिए स्टीयरिंग को तेजी से किनारे (शोल्डर) की ओर मोड़ें","फिसलन को नियंत्रित करने के लिए ब्रेक पेडल को तेजी से पंप करें और निचले गियर में बदलें"],"explanation":"During hydroplaning the tires ride on a layer of water and lose contact with the road, so you should ease off the gas, steer straight, and avoid braking hard until traction returns. Braking firmly (B) or pumping the brakes (D) is a real technique for other emergencies like brake failure, but hard braking during hydroplaning can cause you to skid out of control."},"33":{"q":"एक साफ सर्दी की सुबह है, तापमान जमाव बिंदु से थोड़ा नीचे है। डामर का राजमार्ग सूखा दिखता है, लेकिन आप एक लंबे ओवरपास के पास पहुँच रहे हैं। सुरक्षित रूप से गाड़ी चलाने के लिए आपको क्या उम्मीद करनी चाहिए और क्या करना चाहिए?","options":["ओवरपास सड़क का सबसे गर्म हिस्सा है, इसलिए आप उस पर अपनी मौजूदा गति बनाए रख सकते हैं","सड़क सूखी दिखने के बावजूद ओवरपास बर्फीला हो सकता है, इसलिए उस तक पहुँचने से पहले गति कम करें","ओवरपास पर मुख्य खतरा हाइड्रोप्लेनिंग है, इसलिए एक्सेलरेटर से पैर हटाएँ और सीधा चलाएँ","आगे बर्फ देखने के लिए ओवरपास पर अपनी हाई बीम का उपयोग करें"],"explanation":"Bridges and overpasses freeze before the rest of the roadway because cold air reaches them from all sides, so they can be icy even when the surrounding pavement looks dry; slowing before the overpass is the safe move. Hydroplaning involves water on the road near 35 mph, not freezing, and high beams do not help here, so those are the traps."},"34":{"q":"टेक्सास के एक राजमार्ग पर दोपहर के 2:00 बजे हैं जब अचानक भारी बारिश शुरू हो जाती है। बारिश इतनी घनी है कि आप कुछ सौ फीट आगे चल रहे वाहन की पिछली बत्तियाँ मुश्किल से देख पा रहे हैं, और आपका अनुमान है कि आप अब सड़क पर 1,000 फीट आगे तक भी साफ नहीं देख सकते। आपको अपनी बत्तियों के बारे में क्या करना चाहिए?","options":["अपनी हेडलाइट बंद रखें क्योंकि दिन का समय है, और चलते रहते हुए केवल अपनी खतरे की फ्लैशर लाइट चालू करें","अपनी हाई बीम चालू करें ताकि आगे की भारी बारिश यथासंभव दूर तक रोशन हो जाए","अपनी हेडलाइट चालू करें, क्योंकि जब भी आप लगभग 1,000 फीट आगे तक नहीं देख सकते, तो आपको उन्हें इस्तेमाल करना ही चाहिए, दिन के समय भी","अपनी हेडलाइट बंद रखें लेकिन अन्य चालकों को दिखते रहने के लिए अपनी अंदरूनी छत की बत्ती चालू करें"],"explanation":"टेक्सास में जब भी आप लगभग 1,000 फीट आगे तक नहीं देख सकते, तो आपको हेडलाइट का उपयोग करना ही चाहिए, जिसमें भारी बारिश जैसी दिन की स्थितियाँ शामिल हैं, इसलिए उन्हें चालू करना सही है। हाई बीम गलत है क्योंकि बारिश या कोहरे में वे वापस परावर्तित होकर दृश्यता कम कर देती हैं, और खतरे की फ्लैशर या छत की बत्ती गाड़ी चलाते समय हेडलाइट का विकल्प नहीं हैं।"},"35":{"q":"आप रात में एक अंधेरे दो-लेन वाले राजमार्ग पर अपनी हाई बीम जलाकर गाड़ी चला रहे हैं। आगे, विपरीत लेन में एक कार आपकी ओर आ रही है, और उसी समय आप अपनी ही लेन में ठीक आगे चल रहे एक धीमे ट्रक को धीरे-धीरे पकड़ रहे हैं। टेक्सास कानून के अनुसार आपको अपनी हाई बीम के साथ क्या करना आवश्यक है?","options":["सामने से आ रही कार के लिए हाई बीम जलाए रखें लेकिन आगे के ट्रक के लिए उन्हें मंद कर दें, क्योंकि आगे चल रहे यातायात का महत्व अधिक है","केवल 500 फीट के भीतर सामने से आ रही कार के लिए मंद करें; किसी अन्य वाहन के पीछे किसी भी दूरी पर हाई बीम की अनुमति है","केवल 300 फीट के भीतर आगे के ट्रक के लिए मंद करें; सामने से आ रहे यातायात की ओर किसी भी दूरी पर हाई बीम की अनुमति है","सामने से आ रही कार 500 फीट के भीतर होने पर और आगे का ट्रक 300 फीट के भीतर होने पर हाई बीम को लो बीम में मंद करें"],"explanation":"Texas law requires dimming high beams to low within 500 feet of an oncoming vehicle and within 300 feet when approaching another vehicle from behind, so in this scenario both situations require low beams. Options that excuse you from dimming for one of the two vehicles ignore half the rule and would blind another driver."},"36":{"q":"आप टेक्सास के एक इंटरस्टेट हाईवे पर 65 मील प्रति घंटे की रफ्तार से गाड़ी चला रहे हैं, तभी आपको एक जोरदार धमाके की आवाज सुनाई देती है और स्टीयरिंग अचानक एक तरफ जोर से खिंचने लगता है—आगे का एक टायर फट गया है। आपको क्या करना चाहिए?","options":["गाड़ी को सीधा रखने के लिए स्टीयरिंग को मजबूती से पकड़ें, धीरे-धीरे गैस से पैर हटाएं, और गति कम होने पर धीरे से सड़क के किनारे ले जाएं","गाड़ी को जितनी जल्दी हो सके रोकने के लिए तुरंत और जोर से ब्रेक लगाएं","गैस से पैर हटाएं और स्टीयरिंग को उस दिशा में घुमाएं जिधर आप गाड़ी के अगले हिस्से को ले जाना चाहते हैं","ब्रेक पेडल को पंप करें और गाड़ी की गति कम करने के लिए नीचे के गियर में डालें"],"explanation":"During a blowout you must hold the wheel firmly and gradually ease off the gas before pulling off slowly—braking hard (B) can cause you to lose control. Steering toward where you want the front to go (C) is the fix for a skid, and pumping the brakes with a lower gear (D) is the procedure for brake failure, not a blowout."}},"learn-safe-driving":{"0":{"q":"तीन-सेकंड नियम किसके लिए उपयोग किया जाता है?","options":["आगे चल रही गाड़ी से सुरक्षित दूरी बनाए रखने के लिए","तेल कब बदलना है यह जानने के लिए","पार्किंग ब्रेक लगाने के लिए","कितनी देर सिग्नल देना है यह मापने के लिए"],"explanation":"The three-second rule helps you keep a safe following distance behind the car ahead."},"1":{"q":"तीन-सेकंड नियम का उपयोग कैसे करें?","options":["आगे तीन कार की लंबाई गिनें","एक स्थिर बिंदु तक पहुंचने के सेकंड गिनें","तीन मील प्रति घंटा धीमे चलें","हर पड़ाव पर तीन सेकंड रुकें"],"explanation":"Pick a fixed point ahead and count the seconds it takes to reach it after the car ahead passes it."},"2":{"q":"आपको अपनी अनुसरण दूरी में अधिक सेकंड कब जोड़ने चाहिए?","options":["सूखी, साफ सड़कों पर","जब यातायात कम हो","बारिश, कोहरे, बर्फ में या तेज़ गति पर","जब धीरे गाड़ी चला रहे हों"],"explanation":"Add more seconds to your following distance in rain, fog, ice, or at high speed."},"3":{"q":"तीन सेकंड की पीछा करने की दूरी में अतिरिक्त सेकंड कब जोड़ने चाहिए?","options":["केवल धूप वाले दिनों में","जब सड़क सूखी और खाली हो","जब यातायात कम हो","बारिश, कोहरे, बर्फ या तेज गति में"],"explanation":"Rain, fog, ice, and high speed all require adding extra seconds to your following distance."},"4":{"q":"आपको अपनी अनुसरण दूरी कब बढ़ानी चाहिए?","options":["जब आप मोटरसाइकिल या बड़े ट्रक के पीछे चला रहे हों","जब सड़क सूखी और साफ हो","जब यातायात कम हो","जब आपको जल्दी हो"],"explanation":"Increase your following distance behind motorcycles, large trucks, or when being tailgated."},"5":{"q":"जब कोई अन्य चालक आपके बहुत करीब चल रहा हो, तो आपको क्या करना चाहिए?","options":["उसे चेतावनी देने के लिए अचानक ब्रेक लगाएं","आगे वाले वाहन से अपनी दूरी बढ़ाएं","उससे बचने के लिए तेज़ चलें","सड़क के बीच में रुक जाएं"],"explanation":"Increasing your following distance gives you more room to stop safely when being tailgated."},"6":{"q":"बड़े ट्रकों और बसों के आसपास के बड़े अंधे स्थानों को क्या कहा जाता है?","options":["धीमे क्षेत्र","सुरक्षित क्षेत्र","नो-ज़ोन (अंधे स्थान)","दुर्घटना क्षेत्र"],"explanation":"Large trucks and buses have big blind spots called No-Zones, and if you can't see the driver's mirrors, they can't see you."},"7":{"q":"यदि आप किसी ट्रक या बस के चालक के शीशे नहीं देख सकते, तो इसका क्या अर्थ है?","options":["आप दाईं ओर से आगे निकल सकते हैं","चालक आपको साफ देख सकता है","आपके अपने शीशे टूटे हुए हैं","चालक आपको नहीं देख सकता"],"explanation":"Large trucks and buses have big blind spots, so if you can't see the driver's mirrors, the driver can't see you."},"8":{"q":"कुल रुकने की दूरी किन तीन दूरियों से मिलकर बनती है?","options":["अनुभूति दूरी, प्रतिक्रिया दूरी और ब्रेकिंग दूरी","गति दूरी, मौसम दूरी और ब्रेकिंग दूरी","अनुसरण दूरी, ब्लाइंड-स्पॉट दूरी और प्रतिक्रिया दूरी","दिन की दूरी, रात की दूरी और अनुभूति दूरी"],"explanation":"Total stopping distance equals perception distance plus reaction distance plus braking distance."},"9":{"q":"कुल रुकने की दूरी के तीन भाग कौन से हैं?","options":["गति, वजन और टायर दूरी","अनुभव, प्रतिक्रिया और ब्रेकिंग दूरी","स्टीयरिंग, सिग्नल और ब्रेकिंग दूरी","दृष्टि, मौसम और प्रतिक्रिया दूरी"],"explanation":"Total stopping distance is made up of perception distance, reaction distance, and braking distance."},"10":{"q":"औसत चालक का प्रतिक्रिया समय लगभग कितना होता है?","options":["लगभग 3 सेकंड","लगभग 2 सेकंड","लगभग तीन-चौथाई सेकंड","लगभग 5 सेकंड"],"explanation":"The average driver's reaction time is about three-fourths (3/4) of a second."},"11":{"q":"संयुक्त धारणा और प्रतिक्रिया का समय लगभग कितना होता है?","options":["लगभग 0.5 सेकंड","लगभग 3 सेकंड","लगभग 5 सेकंड","लगभग 1.5 सेकंड"],"explanation":"The combined perception-plus-reaction time is roughly 1.5 seconds."},"12":{"q":"यदि आप अपनी गति दोगुनी कर देते हैं, तो ब्रेकिंग दूरी लगभग:","options":["चार गुना हो जाती है (लगभग 4 गुना)","दोगुनी हो जाती है (लगभग 2 गुना)","समान रहती है","आधी हो जाती है"],"explanation":"Braking distance increases with the square of speed, so doubling speed roughly quadruples it."},"13":{"q":"यदि आप अपनी गति दोगुनी कर देते हैं, तो आपकी ब्रेकिंग दूरी लगभग कितनी बढ़ जाती है?","options":["वही रहती है","लगभग चार गुना","लगभग दो गुना","लगभग तीन गुना"],"explanation":"Doubling your speed roughly quadruples your braking distance."},"14":{"q":"तेज़ गाड़ी चलाने से रुकने पर क्या असर पड़ता है?","options":["रुकना आसान हो जाता है","रुकने पर कोई असर नहीं पड़ता","रुकने में अधिक समय लगता है","टक्कर का असर कम हो जाता है"],"explanation":"The faster you go, the longer it takes to stop and the harder a crash, because of the speed-energy relationship."},"15":{"q":"गीली सड़कों पर आपको गति क्यों कम करनी चाहिए?","options":["ईंधन बचाने के लिए","अधिक करीब चलने के लिए","हेडलाइट को तेज़ करने के लिए","क्योंकि पकड़ (ट्रैक्शन) कम हो जाती है"],"explanation":"Wet roads reduce traction, so slowing down helps you stay in control."},"16":{"q":"गीली सड़क पर हाइड्रोप्लेनिंग लगभग किस गति पर शुरू हो सकती है?","options":["लगभग 35 मील प्रति घंटा","लगभग 5 मील प्रति घंटा","लगभग 15 मील प्रति घंटा","लगभग 70 मील प्रति घंटा"],"explanation":"Hydroplaning can begin near 35 mph as water builds up under the tires."},"17":{"q":"हाइड्रोप्लेनिंग क्या है?","options":["जब टायर बारिश में सड़क को बेहतर पकड़ते हैं","जब टायर पानी पर सड़क से संपर्क खो देते हैं","जब लंबी ढलान पर ब्रेक ज़्यादा गरम हो जाते हैं","जब हेडलाइट गीली सड़क से परावर्तित होती है"],"explanation":"Hydroplaning happens when water builds up under the tires and they lose contact with the road surface."},"18":{"q":"अगर आपकी कार हाइड्रोप्लेन करने लगे तो आपको क्या करना चाहिए?","options":["तुरंत जोर से ब्रेक लगाएं","पकड़ वापस पाने के लिए तेज करें","गैस छोड़ें और स्टीयरिंग सीधा रखें","स्टीयरिंग को तेजी से घुमाएं"],"explanation":"If you hydroplane, ease off the gas, do not brake hard, and steer straight."},"19":{"q":"सूखे मौसम के बाद पहली बारिश सबसे अधिक फिसलन भरी क्यों होती है?","options":["सड़क सामान्य से अधिक ठंडी होती है","बारिश सारी गंदगी बहा ले जाती है","गीले मौसम में टायरों की हवा निकल जाती है","सड़क पर तेल पानी के साथ मिल जाता है"],"explanation":"The first rain mixes with built-up oil on the road, making it the most slippery."},"20":{"q":"बर्फीले मौसम में सड़क का कौन सा हिस्सा पहले जमता है?","options":["पुल और ओवरपास","पहाड़ी की चोटियाँ","सुरंगें","पार्किंग स्थल"],"explanation":"Bridges and overpasses freeze before the rest of the road in icy conditions."},"21":{"q":"ब्लैक आइस खतरनाक क्यों है?","options":["यह जल्दी पिघल जाती है","इसे सड़क पर देखना मुश्किल होता है","इसमें तेज गंध आती है","यह तेज आवाज करती है"],"explanation":"Black ice is dangerous because it is hard to see on the road."},"22":{"q":"अगर आपकी गाड़ी फिसलने लगे, तो आपको क्या करना चाहिए?","options":["जोर से ब्रेक दबाएं","एक्सेलरेटर को और दबाएं","एक्सेलरेटर से पैर हटाएं और जहां जाना है उस दिशा में स्टीयर करें","आंखें बंद करके पकड़े रहें"],"explanation":"In a skid, take your foot off the gas, don't slam the brakes, and steer in the direction you want the front of the car to go."},"23":{"q":"फिसलन (स्किड) से उबरने के लिए आपको स्टीयरिंग किस दिशा में घुमाना चाहिए?","options":["सड़क के किनारे की ओर","स्किड की विपरीत दिशा में","जहाँ आप जाना चाहते हैं उससे दूर","जिस दिशा में आप कार के अगले हिस्से को ले जाना चाहते हैं"],"explanation":"To recover from a skid, steer in the direction you want the front of the car to go."},"24":{"q":"फिसलन के दौरान आपको अपने पैर से क्या करना चाहिए?","options":["गैस पेडल से अपना पैर हटा लें","गैस पेडल को और ज़ोर से दबाएं","ब्रेक पेडल को ज़ोर से दबाएं","गैस पर लगातार दबाव बनाए रखें"],"explanation":"Easing off the gas helps you regain traction during a skid."},"25":{"q":"कोहरे या धुएं में आपको कौन सी हेडलाइट का उपयोग करना चाहिए?","options":["हाई बीम","लो बीम","कोई हेडलाइट नहीं","केवल खतरे की चेतावनी लाइट"],"explanation":"Use low beams in fog or smoke because high beams reflect back and reduce your visibility."},"26":{"q":"कोहरे या धुएं में आपको क्या करना चाहिए?","options":["उसमें से गुजरने के लिए गति बढ़ाएं","अपनी हाई बीम चालू करें","गति धीमी करें या सुरक्षित रूप से सड़क के किनारे रुकें","अपनी हेडलाइट्स बंद कर दें"],"explanation":"In fog or smoke you should slow down or pull off the road safely."},"27":{"q":"कोहरे में आपको कौन सी हेडलाइट का उपयोग करना चाहिए?","options":["केवल हैज़र्ड फ़्लैशर","कोई हेडलाइट नहीं","हाई बीम","लो बीम"],"explanation":"In fog you should use low beams because high beams reflect off the fog and reduce your visibility."},"28":{"q":"आपको अपनी हेडलाइट्स कब इस्तेमाल करनी चाहिए?","options":["सूर्यास्त से सूर्योदय तक","केवल भारी बारिश के दौरान","केवल राजमार्ग पर","केवल पार्किंग करते समय"],"explanation":"Texas law requires headlights from sunset to sunrise."},"29":{"q":"दृश्यता के आधार पर आपको अपनी हेडलाइट कब चालू करनी चाहिए?","options":["जब आप कम से कम 100 फ़ीट आगे नहीं देख सकते","जब आप कम से कम 1,000 फ़ीट आगे नहीं देख सकते","जब आप कम से कम 50 फ़ीट आगे नहीं देख सकते","जब आप कम से कम 5,000 फ़ीट आगे नहीं देख सकते"],"explanation":"Use your headlights any time you cannot see at least about 1,000 feet ahead."},"30":{"q":"सामने से आ रहे वाहन के लिए आपको अपनी हाई बीम को लो बीम पर कब करना चाहिए?","options":["100 फीट के भीतर","250 फीट के भीतर","500 फीट के भीतर","1,000 फीट के भीतर"],"explanation":"You must dim your high beams to low beams when within 500 feet of an oncoming vehicle."},"31":{"q":"किसी अन्य वाहन के पीछे चलते समय, कितनी दूरी के भीतर आपको अपनी हाई बीम को लो बीम में करना चाहिए?","options":["पीछे 100 फीट के भीतर","पीछे 150 फीट के भीतर","पीछे 200 फीट के भीतर","पीछे 300 फीट के भीतर"],"explanation":"You must dim your high beams to low beams when within 300 feet behind another vehicle."},"32":{"q":"सामने से आ रहे वाहन से कितने फीट के भीतर आपको अपनी हाई बीम कम करनी चाहिए?","options":["500 फीट","100 फीट","250 फीट","1,000 फीट"],"explanation":"You must dim your high beams to low within 500 feet of an oncoming vehicle."},"33":{"q":"जिस वाहन के पीछे आप चल रहे हैं, उससे कितने फ़ीट के भीतर आपको हाई बीम को मंद करना चाहिए?","options":["100 फ़ीट","300 फ़ीट","500 फ़ीट","1,000 फ़ीट"],"explanation":"You must dim your high beams to low when within 300 feet behind another vehicle."},"34":{"q":"यदि सामने से आ रहे वाहन की हाई बीम आपको चौंधिया दे, तो आपको कहाँ देखना चाहिए?","options":["सीधे हेडलाइट्स की ओर","ऊपर आकाश की ओर","सड़क के दाहिने किनारे की ओर","नीचे डैशबोर्ड की ओर"],"explanation":"Looking toward the right edge of the road helps you avoid the glare and stay in your lane."},"35":{"q":"\"अपनी हेडलाइट्स से तेज़ चलना\" का क्या मतलब है?","options":["हाई बीम का बहुत बार उपयोग करना","लाइटें चालू करना भूल जाना","एक हेडलाइट बंद होने पर चलाना","इतनी तेज़ चलना कि रोशन क्षेत्र में रुक न सकें"],"explanation":"Overdriving your headlights means going so fast you cannot stop within the distance lighted by your headlights."},"36":{"q":"अगर आपके ब्रेक फेल हो जाएं तो आपको क्या करना चाहिए?","options":["पेडल को बार-बार दबाएं, निचले गियर में डालें, पार्किंग ब्रेक धीरे-धीरे लगाएं","इंजन बंद करें और स्टीयरिंग जोर से घुमाएं","अगले निकास तक पहुंचने के लिए गति बढ़ाएं","आंखें बंद करें और हॉर्न बजाएं"],"explanation":"If your brakes fail, pump the brake pedal, shift to a lower gear, and use the parking brake gradually."},"37":{"q":"ब्रेक खराब होने पर आपको पार्किंग ब्रेक कैसे लगाना चाहिए?","options":["एक ही बार में","धीरे-धीरे","कभी इस्तेमाल न करें","रुकने के बाद ही"],"explanation":"During brake failure, apply the parking brake gradually rather than all at once."},"38":{"q":"यदि आपके ब्रेक फेल हो जाएं, तो अनुशंसित प्रतिक्रिया क्या है?","options":["चलते रहने के लिए गति बढ़ाएं","अपनी हेडलाइट बंद कर दें","कम गियर में शिफ्ट करें","जोर से हॉर्न बजाएं"],"explanation":"Shifting to a lower gear helps slow the vehicle when your brakes fail."},"39":{"q":"अगर आपका टायर फट जाए तो आपको क्या करना चाहिए?","options":["तुरंत जोर से ब्रेक लगाएं","नियंत्रण बनाए रखने के लिए गति बढ़ाएं","स्टीयरिंग व्हील छोड़ दें","स्टीयरिंग व्हील को मजबूती से पकड़ें और गैस से पैर हटाएं"],"explanation":"In a blowout, hold the wheel firmly, ease off the gas, and do not brake hard."},"40":{"q":"टायर फटने के बाद, जब आप नियंत्रण पा लें, तो आपको सड़क से कैसे हटना चाहिए?","options":["धीरे-धीरे सड़क से हट जाएं","जोर से ब्रेक लगाकर तेजी से रुकें","मिलने के लिए गति बढ़ाएं","अपनी लेन में बने रहें"],"explanation":"After a tire blowout, once you have control you should pull off the road slowly."},"41":{"q":"टायर फटने पर आपको क्या करना चाहिए?","options":["तुरंत जोर से ब्रेक लगाएं","जोर से ब्रेक न लगाएं","तेजी से गति बढ़ाएं","स्टीयरिंग व्हील छोड़ दें"],"explanation":"During a tire blowout, do not brake hard; ease off the gas and pull off slowly."},"42":{"q":"अगर आपका वाहन रेल की पटरियों पर बंद हो जाए, तो आपको क्या करना चाहिए?","options":["वाहन में रहकर इंतजार करें","चालू करके ट्रेन से पहले निकलने की कोशिश करें","सबको बाहर निकालकर दूर ले जाएं, फिर मदद के लिए बुलाएं","वाहन को पटरियों के साथ धकेलें"],"explanation":"Get everyone out and away from the tracks, then call for help; never try to beat a train."},"43":{"q":"रेलवे पटरियों पर आपको कभी क्या करने की कोशिश नहीं करनी चाहिए?","options":["पटरियों से पहले रुकना","दोनों ओर देखना","पटरियों के पास गति धीमी करना","ट्रेन से पहले पार करने की कोशिश करना"],"explanation":"You should never try to beat a train across railroad tracks."},"44":{"q":"यदि आपको सड़क पर रुकना पड़े, तो आपको क्या करना चाहिए?","options":["किनारे (शोल्डर) पर ले जाएं और खतरे की चेतावनी वाली लाइटें (हैज़र्ड फ्लैशर) चालू करें","अपनी लेन में रुककर इंतजार करें","आधा वाहन यातायात लेन में रखकर पार्क करें","अपनी हेडलाइटें बंद रखें"],"explanation":"Pull fully onto the shoulder, turn on hazard flashers, and use warning devices."},"45":{"q":"आपातकाल में सड़क के किनारे रुकने पर आपको क्या चालू करना चाहिए?","options":["अपनी हाई बीम लाइट","अपने हैज़र्ड (आपातकालीन) फ्लैशर","अपनी अंदर की छत की लाइट","कुछ भी नहीं"],"explanation":"When stopped on the roadside in an emergency, turn on your hazard (emergency) flashers."},"46":{"q":"आपात स्थिति में सड़क पर रुकते समय, आपको अपने वाहन को कितनी दूर ले जाना चाहिए?","options":["अपनी ड्राइविंग लेन में रहें","आधा शोल्डर पर","पूरी तरह शोल्डर पर","केंद्र रेखा पर"],"explanation":"Pull fully onto the shoulder so your vehicle is clear of traffic."},"47":{"q":"थकान, नशीली दवाएं और शराब चालक के साथ क्या करती हैं?","options":["प्रतिक्रिया समय सुधारती हैं","निर्णय क्षमता तेज करती हैं","कोई प्रभाव नहीं डालतीं","प्रतिक्रिया धीमी करती हैं और निर्णय बिगाड़ती हैं"],"explanation":"Fatigue, drugs, and alcohol all slow reaction time and impair judgment."},"48":{"q":"आपको कब गाड़ी चलाने से बचना चाहिए?","options":["जब आप नशे में हों या उनींदे हों","जब आप अच्छी तरह आराम कर चुके हों","जब सड़क खाली हो","जब यातायात कम हो"],"explanation":"You should never drive while impaired or drowsy because it slows your reaction time and judgment."},"49":{"q":"थकान (नींद आना) आपकी ड्राइविंग को कैसे प्रभावित करती है?","options":["यह आपका ध्यान बेहतर करती है","यह नशीली दवाओं और शराब की तरह प्रतिक्रिया समय और निर्णय को धीमा करती है","इसका ड्राइविंग पर कोई प्रभाव नहीं पड़ता","यह आपको तेज़ी से ब्रेक लगवाती है"],"explanation":"Fatigue slows your reaction time and judgment just like drugs and alcohol."},"50":{"q":"कौन सी गतिविधि गाड़ी चलाते समय एक बड़ा ध्यान भटकाव है?","options":["अपनी सीट बेल्ट पहनना","अपने शीशे जाँचना","संदेश भेजना या हाथ में फोन का उपयोग करना","बारिश में गति धीमी करना"],"explanation":"Texting and handheld phone use is a major distraction and texting while driving is illegal in Texas."},"51":{"q":"टेक्सास में, गाड़ी चलाते समय टेक्स्ट करना क्या कानूनी है?","options":["हाँ, यह हमेशा कानूनी है","हाँ, केवल राजमार्गों पर","हाँ, अगर यातायात धीमा हो","नहीं, यह गैरकानूनी है"],"explanation":"Texting while driving is illegal in Texas."},"52":{"q":"गाड़ी चलाते समय आपको सीट बेल्ट कब पहननी चाहिए?","options":["हमेशा","केवल राजमार्गों पर","केवल रात में","केवल बारिश में"],"explanation":"Texas law requires you to always wear your seat belt while driving."},"53":{"q":"टेक्सास में सीट बेल्ट किसे पहननी चाहिए?","options":["केवल चालक","चालक और सभी यात्री","केवल आगे बैठने वाले","केवल 12 साल से कम उम्र के बच्चे"],"explanation":"Texas law requires the driver and all passengers to wear seat belts."},"54":{"q":"प्रतिक्रिया दूरी क्या है?","options":["वह दूरी जहाँ आपके टायर फिसलने के निशान छोड़ते हैं","वह दूरी जो आप अन्य कारों के पीछे रखते हैं","वह दूरी जो आपका वाहन किसी खतरे को देखने के बाद प्रतिक्रिया करते समय तय करता है","वह दूरी जिसमें आपके ब्रेक वाहन को रोकते हैं"],"explanation":"Reaction distance is how far your vehicle travels while you react after perceiving a hazard."},"55":{"q":"ब्रेकिंग दूरी क्या है?","options":["सड़क देखने में लगने वाला समय","मोड़ से पहले आपके द्वारा चलाई गई दूरी","दो खड़ी कारों के बीच की जगह","ब्रेक लगाने से रुकने तक आपके वाहन द्वारा तय की गई दूरी"],"explanation":"Braking distance is how far your vehicle travels from when you apply the brakes until it fully stops."},"56":{"q":"अगर आपकी कार हाइड्रोप्लेन करने लगे, तो आपको क्या करना चाहिए?","options":["गैस से पैर हटाएं और सीधा चलाएं","तुरंत जोर से ब्रेक लगाएं","तेजी से गति बढ़ाएं","स्टीयरिंग को तेजी से मोड़ें"],"explanation":"During hydroplaning, ease off the gas and steer straight instead of braking hard."},"57":{"q":"तीन-सेकंड का नियम आपको क्या बनाए रखने में मदद करता है?","options":["साफ विंडशील्ड","सुरक्षित अनुसरण दूरी","भरा हुआ ईंधन टैंक","सही टायर दबाव"],"explanation":"The three-second rule helps you keep a safe following distance behind the vehicle ahead."},"58":{"q":"दिन के दौरान आपको हेडलाइट कब चालू करनी चाहिए?","options":["केवल राजमार्ग पर","केवल जब बाहर अंधेरा हो","जब आप लगभग 1,000 फीट आगे नहीं देख सकते","दिन के दौरान कभी नहीं"],"explanation":"Turn on headlights whenever visibility drops and you cannot see about 1,000 feet ahead, even in daytime rain or fog."},"59":{"q":"अगर आप आपात स्थिति में सड़क किनारे रुकते हैं, तो आपको क्या करना चाहिए?","options":["अपनी लेन में रहकर इंतजार करें","अपनी सभी लाइटें बंद कर दें","तेजी से वहां से निकल जाएं","अन्य चालकों के लिए चेतावनी उपकरण लगाएं"],"explanation":"Warning devices alert other drivers that your vehicle is stopped on the roadside."}},"alcohol-and-penalties":{"0":{"q":"34 वर्षीय मार्कस को ह्यूस्टन में एक दोस्त के बारबेक्यू से निकलते समय रोका जाता है। अधिकारी को संदेह है कि उसने शराब पी है और वह सांस की जांच (ब्रेथ टेस्ट) करवाने को कहता है। टेक्सास में एक वयस्क चालक के रूप में मार्कस को किस रक्त अल्कोहल स्तर (BAC) पर कानूनी रूप से नशे में गाड़ी चलाना (DWI) माना जाता है?","options":["0.08% BAC या इससे अधिक","0.04% BAC या इससे अधिक","0.15% BAC या इससे अधिक","0.00% से ऊपर कोई भी पता लगाने योग्य मात्रा"],"explanation":"For an adult driver age 21 or older, the Texas DWI limit is 0.08% BAC. 0.04% is the limit for commercial drivers, and any detectable amount (above 0.00%) applies only to drivers under 21 under Zero Tolerance."},"1":{"q":"26 वर्षीय मार्कस को ऑस्टिन में लेन के बीच लहराते हुए गाड़ी चलाने के बाद रोका जाता है। वह 0.08% BAC (रक्त में अल्कोहल की मात्रा) दिखाने वाला सांस परीक्षण पास करता है और अधिकारी से कहता है कि वह पूरी तरह ठीक महसूस कर रहा है और सावधानी से गाड़ी चला रहा था। टेक्सास कानून के अनुसार, इस रीडिंग के आधार पर मार्कस ने कौन सा अपराध किया है?","options":["कुछ नहीं, क्योंकि 0.08% कानूनी सीमा है और वह केवल तभी इससे ऊपर होता है जब रीडिंग 0.08% से अधिक हो","नशे में गाड़ी चलाना (DWI), क्योंकि किसी वयस्क के लिए 0.08% BAC या उससे अधिक पर गाड़ी चलाना DWI है","प्रभाव में गाड़ी चलाना (DUI), क्योंकि कोई भी पता लगाने योग्य अल्कोहल किसी वयस्क को DUI का दोषी बना देता है","कुछ नहीं, क्योंकि उसने अधिकारी से कहा कि वह ठीक महसूस कर रहा है और उसने कोई वास्तविक नशे का प्रभाव नहीं दिखाया"],"explanation":"For an adult 21 or older, driving at or above 0.08% BAC is the offense of Driving While Intoxicated (DWI), so reaching exactly 0.08% counts. The Zero Tolerance DUI for any detectable alcohol applies only to drivers under 21, and feeling 'fine' does not change the legal BAC limit."},"2":{"q":"एक 30 वर्षीय चालक को लेन के बीच लहराते हुए चलाने के बाद रोका जाता है। साँस की जाँच में 0.06% BAC आता है, लेकिन अधिकारी शराब के नशे के अनुरूप लड़खड़ाती आवाज़ और खराब समन्वय देखता है। टेक्सास कानून के तहत क्या हो सकता है?","options":["कुछ नहीं, क्योंकि 0.06% वयस्क सीमा 0.08% से नीचे है, इसलिए DWI लागू नहीं हो सकता","जैसे ही साँस की जाँच 0.08% से कम आती है, चालक स्वतः बरी हो जाता है","चालक पर अब भी DWI का आरोप लगाया जा सकता है क्योंकि वह शराब से प्रभावित है, भले ही BAC 0.08% से नीचे हो","चालक पर केवल खुले कंटेनर के उल्लंघन का जुर्माना लगाया जा सकता है, DWI का नहीं"],"explanation":"In Texas, a driver can be charged with DWI below 0.08% BAC if alcohol or drugs impair them, so the observed impairment supports a DWI charge. The 0.08% figure is a per se limit, not a safe harbor, so being under it does not automatically clear the driver."},"3":{"q":"मार्कस एक माल ढुलाई कंपनी के लिए वाणिज्यिक ट्रैक्टर-ट्रेलर चलाता है। एक लंबी शिफ्ट के बाद, वह रात के खाने के साथ दो बीयर पीता है और बाद में सांस की जांच में 0.05% BAC आता है। उसका तर्क है कि वह कानूनी सीमा से काफी नीचे है और अपना ट्रक चलाते रहने के लिए ठीक है। क्या वह सही है, और संबंधित सीमा क्या है?","options":["वह सही है; टेक्सास में सभी चालकों के लिए सीमा 0.08% BAC है, इसलिए 0.05% कानूनी है।","वह सही है क्योंकि 0.08% से नीचे कोई भी BAC कभी भी आरोप का कारण नहीं बन सकता।","वह सीमा से ऊपर है क्योंकि टेक्सास में शून्य सहनशीलता है और उसके लिए कोई भी पता लगाने योग्य शराब अवैध है।","वह सीमा से ऊपर है; वाणिज्यिक चालकों की कम सीमा 0.04% BAC है, और 0.05% इससे अधिक है।"],"explanation":"Commercial drivers in Texas are held to a lower limit of 0.04% BAC, so Marcus's 0.05% reading puts him over the limit. The 0.08% figure (A) is the standard adult limit, not the commercial one, and zero tolerance (C) applies only to drivers under 21, not commercial drivers."},"4":{"q":"मार्कस 19 वर्ष का है और अपने दोस्त की पार्टी से घर जा रहा है जहाँ उसने एक बीयर पी थी। एक पुलिस अधिकारी उसे कानूनी रूप से रोकता है और सांस की जाँच में रक्त-अल्कोहल स्तर (BAC) 0.03% दिखता है। टेक्सास कानून के तहत उसकी कानूनी स्थिति क्या है?","options":["उसका गाड़ी चलाना अवैध है — टेक्सास की ज़ीरो टॉलरेंस के तहत, 21 वर्ष से कम उम्र के चालक के लिए कोई भी पता लगाने योग्य अल्कोहल (0.00 से ऊपर का BAC) नाबालिग द्वारा DUI है।","उसका गाड़ी चलाना कानूनी है क्योंकि उसका 0.03% BAC, 0.08% DWI सीमा से कम है।","उसका गाड़ी चलाना कानूनी है क्योंकि उसका 0.03% BAC, 0.04% वाणिज्यिक चालक सीमा से कम है।","उसका गाड़ी चलाना कानूनी है क्योंकि उसने केवल एक ड्रिंक पी थी और लिवर प्रति घंटे एक मानक ड्रिंक संसाधित करता है।"],"explanation":"For drivers under 21, Texas has Zero Tolerance, so ANY detectable alcohol (a BAC above 0.00) is illegal and is a DUI by a minor. The 0.08% adult DWI limit and the 0.04% commercial limit do not apply to a 19-year-old minor, making those traps wrong."},"5":{"q":"एक 19 वर्षीय चालक एक पार्टी से निकलता है और टेक्सास में रोका जाता है। एक सांस परीक्षण में रक्त-अल्कोहल सांद्रता (BAC) 0.03% दिखती है, जो वयस्क सीमा 0.08% से काफी कम है। चालक ने कौन सा अपराध किया है, यदि कोई हो?","options":["कुछ नहीं, क्योंकि BAC वयस्क सीमा 0.08% से कम है","नाबालिग द्वारा अल्कोहल के प्रभाव में वाहन चलाना (DUI), क्योंकि 21 वर्ष से कम आयु में कोई भी पता लगाने योग्य अल्कोहल अवैध है","DWI, क्योंकि चालक किसी भी BAC पर स्वतः नशे में माना जाता है","कुछ नहीं, लेकिन निहित सहमति के कारण चालक का लाइसेंस 180 दिनों के लिए निलंबित है"],"explanation":"Texas has a Zero Tolerance law for drivers under 21: any detectable alcohol (a BAC above 0.00) is a DUI of alcohol by a minor, regardless of the 0.08% adult DWI limit. Option A wrongly applies the adult threshold to a minor, and the 180-day suspension in D is the penalty for refusing a test, not for a 0.03% reading."},"6":{"q":"एक पार्टी में, मार्कस ने कुछ बीयर पी ली हैं और वह शांत और आराम महसूस कर रहा है, इसलिए वह एक दोस्त से कहता है कि पीने के बाद वह वास्तव में अधिक सुरक्षित और सावधान चालक है। उसका दोस्त चेतावनी देता है कि यह खतरनाक है। आराम महसूस करने के बावजूद शराब मार्कस को अधिक खतरनाक चालक क्यों बनाती है?","options":["शराब एक उत्तेजक है जो उसके दिल की धड़कन तेज करती है और उसे गाड़ी चलाते समय अत्यधिक आक्रामक बनाती है","शराब चालकों को केवल तभी प्रभावित करती है जब उनका रक्त-अल्कोहल स्तर 0.08% की कानूनी सीमा तक पहुँच जाता है, इसलिए दो बीयर उसे प्रभावित नहीं कर सकतीं","शराब एक अवसादक है जो उसकी प्रतिक्रिया समय को धीमा करती है और उसके निर्णय को कमजोर करती है, भले ही वह आराम महसूस करे","शराब उसकी दृष्टि और समन्वय को तेज करती है लेकिन यातायात संकेतों का पालन करने की उसकी क्षमता को कुंद कर देती है"],"explanation":"Alcohol is a depressant, so it slows reaction time and impairs judgment even when the drinker feels calm and relaxed. It is not a stimulant (A is the wrong category), and a driver can be impaired well below 0.08% (B is false), making C correct."},"7":{"q":"एक पार्टी से घर लौटते समय, जहाँ उसने कई ड्रिंक्स लिए थे, मार्कस को पता चलता है कि वह बार-बार अपनी लेन में इधर-उधर हो रहा है, टर्न सिग्नल तक पहुँचने में लड़खड़ा रहा है, और जब आगे की कार ब्रेक लगाती है तो वह एक पल देर से प्रतिक्रिया करता है। शराब के किस प्रभावों का संयोजन उसकी इस स्थिति को सबसे अच्छी तरह समझाता है?","options":["उसके रक्त में अल्कोहल का स्तर बढ़ रहा है क्योंकि ठंडी रात की हवा अल्कोहल को वापस उसके रक्तप्रवाह में तेज़ी से भेज रही है।","शराब एक उत्तेजक की तरह काम करती है, इसलिए यह उसका ध्यान तेज़ करती है लेकिन उसकी मांसपेशियों की हरकतों को घबराहट भरा और तेज़ बना देती है।","ये प्रभाव केवल थकान से आते हैं; शराब का असर तो खत्म हो चुका है क्योंकि उसके आखिरी ड्रिंक को एक घंटे से ज़्यादा हो गया है।","शराब ने उसकी प्रतिक्रिया समय को धीमा कर दिया है, उसके निर्णय को कमज़ोर कर दिया है, और उसके समन्वय व दृष्टि को कम कर दिया है।"],"explanation":"Alcohol is a depressant that slows reaction time, impairs judgment, and reduces coordination and vision, which matches Marcus's lane drifting, fumbling, and delayed braking. Alcohol is not a stimulant and does not sharpen focus, and only time lowers BAC, so fresh air and the passage of one hour do not undo the impairment."},"8":{"q":"एक दोस्त के घर पर दो बीयर पीने के बाद मार्कस शारीरिक रूप से ठीक महसूस करता है, उसके हाथ स्थिर हैं और उसकी बोली सामान्य है, इसलिए वह तय करता है कि घर ड्राइव करके जाना सुरक्षित है और यहाँ तक कि पीली बत्ती पकड़ने के लिए गति भी बढ़ा देता है, जिस पर वह सामान्यतः रुक जाता। शराब ने उसकी किस क्षमता को सबसे पहले प्रभावित किया होगा, जिससे यह जोखिम भरा निर्णय हुआ?","options":["उसका निर्णय (विवेक), जो शराब से प्रभावित होने वाली पहली ड्राइविंग क्षमता है","उसकी दृष्टि, जो हमेशा शराब से प्रभावित होने वाली पहली क्षमता होती है","उसका समन्वय, क्योंकि स्थिर हाथ यह साबित करते हैं कि उसका विवेक अभी भी बरकरार है","उसकी प्रतिक्रिया का समय, जिसे शराब बाकी सब से पहले प्रभावित करती है"],"explanation":"निर्णय (विवेक) शराब से प्रभावित होने वाली पहली ड्राइविंग क्षमता है, इसीलिए मार्कस ने शारीरिक रूप से ठीक महसूस करने के बावजूद पीली बत्ती पर गति बढ़ाने का जोखिम भरा निर्णय लिया। दृष्टि, समन्वय और प्रतिक्रिया का समय भी शराब से प्रभावित होते हैं, पर वे निर्णय के बाद प्रभावित होते हैं, उससे पहले नहीं।"},"9":{"q":"एक पार्टी में, आपके एक दोस्त ने पिछले दो घंटों में कई ड्रिंक्स पी हैं और अब वह गाड़ी चलाकर घर जाना चाहता है। वह जोर देकर कहता है कि वह ठीक है क्योंकि उसने अभी-अभी दो बड़े कप काली कॉफी पी है, भरपेट खाना खाया है, और 'अपना दिमाग साफ करने' के लिए ठंडी हवा में बाहर गया है। सुरक्षित रूप से गाड़ी चलाने की उसकी क्षमता के बारे में आपको उसे क्या बताना चाहिए?","options":["कॉफी और ठंडी हवा ने उसके शरीर द्वारा शराब को संसाधित करने की गति बढ़ा दी है, इसलिए अब वह सुरक्षित रूप से गाड़ी चला सकता है।","इनमें से कोई भी चीज़ उसका BAC कम नहीं करती; केवल समय बीतने से ही वह होश में आ सकता है, इसलिए उसे गाड़ी नहीं चलानी चाहिए।","भरपेट खाना खाने से उसके खून में पहले से मौजूद शराब सोख ली जाती है, इसलिए उसका BAC अब फिर से कानूनी स्तर पर आ गया है।","चूंकि वह सतर्क महसूस करता है, उसका निर्णय और प्रतिक्रिया समय पूरी तरह से लौट आया है और वह कानूनी रूप से गाड़ी चला सकता है।"],"explanation":"Only the passage of time lowers BAC, because the liver processes alcohol at a fixed rate of about one drink per hour. Coffee, food, cold air, and feeling alert do not speed up sobering or reduce impairment, so he should not drive."},"10":{"q":"एक पार्टी में आपके दोस्त ने पिछले दो घंटों में कई बीयर पी ली हैं और अब वह गाड़ी चलाकर घर जाना चाहता है। वह कहता है कि अगर वह पहले एक कप कड़क कॉफी पी ले, भरपेट खाना खा ले और ठंडे पानी से नहा ले तो वह गाड़ी चलाने के लिए ठीक रहेगा। शराब शरीर से कैसे बाहर निकलती है, इस बारे में आप जो जानते हैं, उसके आधार पर सबसे सटीक उत्तर क्या है?","options":["कॉफी और ठंडा स्नान उसे जल्दी होश में ले आएंगे, इसलिए जैसे ही वह फिर से चुस्त महसूस करे, वह गाड़ी चला सकता है।","भरपेट खाना उसके खून में पहले से मौजूद शराब को सोख लेगा और उसका BAC सुरक्षित रूप से गाड़ी चलाने लायक कम कर देगा।","इनमें से कोई भी होश में आने की प्रक्रिया को तेज़ नहीं करेगा; केवल समय ही BAC को कम करता है, इसलिए उसे गाड़ी नहीं चलानी चाहिए।","घर जाते समय ताज़ी हवा उसके शरीर से शराब को साफ़ कर देगी, इसलिए एक छोटी यात्रा ठीक है।"],"explanation":"Only the passage of time lowers BAC because the liver processes about one standard drink per hour, and nothing makes it faster. Coffee, food, a cold shower, and fresh air may make a person feel more alert but do not reduce intoxication, so they are dangerous myths."},"11":{"q":"मार्कस ने आधी रात को समाप्त हुई एक पार्टी में चार मानक पेय पिए। रात 1:30 बजे घर ड्राइव करने से पहले वह दो बड़े कॉफी पीता है, भरपेट खाना खाता है और ठंडे पानी से नहाता है। वह सतर्क महसूस करता है। सुरक्षित रूप से गाड़ी चलाने की उसकी क्षमता के बारे में क्या सही है?","options":["कॉफी और खाने ने उसके रक्त में अल्कोहल का स्तर इतना कम कर दिया है कि अब वह सुरक्षित रूप से गाड़ी चला सकता है","ठंडे पानी के स्नान ने उसके यकृत को तेज कर दिया, इसलिए अधिकांश अल्कोहल पहले ही निकल चुका है","चूँकि वह सतर्क महसूस करता है और उसका निर्णय स्पष्ट है, वह गाड़ी चलाने के लिए ठीक है","केवल समय ही उसके रक्त में अल्कोहल का स्तर कम कर सकता है; उसका यकृत प्रति घंटे लगभग एक पेय साफ करता है, इसलिए वह संभवतः अभी भी नशे में है"],"explanation":"The liver processes only about one standard drink per hour and nothing speeds it up, so after roughly 90 minutes Marcus has cleared at most one or two of his four drinks. Coffee, food, and a cold shower do not lower BAC, and feeling alert is misleading because judgment is the first ability alcohol impairs."},"12":{"q":"मार्कस ने रात के खाने के साथ एक बीयर पी है और उसे बस हल्का सा नशा महसूस हो रहा है। उसी दिन पहले उसने एलर्जी की एक बिना पर्चे की दवा ली थी जिस पर चेतावनी थी कि इससे नींद आ सकती है। उसे लगता है कि एक बीयर कानूनी सीमा से काफी कम है, इसलिए वह घर गाड़ी चलाकर जा सकता है। उसकी स्थिति में वास्तविक खतरा क्या है?","options":["बिना पर्चे की दवा शराब के साथ मिलकर उसकी क्षमता को कई गुना कम कर सकती है, जिससे वह गाड़ी चलाने के लिए अकेली एक बीयर की तुलना में कहीं अधिक असुरक्षित हो जाता है","कुछ गलत नहीं है, क्योंकि बिना पर्चे की दवाएं कानूनी हैं और गाड़ी चलाने की क्षमता को प्रभावित नहीं कर सकतीं","वह सुरक्षित है बशर्ते वह निकलने से पहले संयुक्त प्रभाव को कम करने के लिए अधिक खाना खाए और कॉफी पिए","वह केवल तभी जोखिम में है जब उसका BAC वाणिज्यिक चालक की 0.04% सीमा तक पहुंचे, जो एक बीयर से संभव नहीं है"],"explanation":"Drugs of any kind—including legal over-the-counter medicines—combined with alcohol multiply impairment, so Marcus can be far more impaired than one beer alone would suggest. Coffee and food do not speed sobering, and the 0.04% limit applies only to commercial drivers, not Marcus."},"13":{"q":"मार्कस को देर रात ऑस्टिन में रोका जाता है और DWI (नशे में गाड़ी चलाने) के लिए कानूनी रूप से गिरफ्तार किया जाता है। थाने में अधिकारी उससे सांस का नमूना देने को कहता है। मार्कस कहता है कि उसने कभी किसी परीक्षण के लिए सहमति नहीं दी और मना कर देता है। टेक्सास कानून के अनुसार, किस आधार पर उसे पहले से ही सहमत माना जाता था?","options":["उसने थाने में गिरफ्तारी के दस्तावेजों पर हस्ताक्षर करते समय सहमति दी, इसलिए अब परीक्षण अनिवार्य है।","टेक्सास में गाड़ी चलाकर, उसने DWI के लिए कानूनी रूप से गिरफ्तार होने पर सांस या रक्त परीक्षण के लिए अंतर्निहित सहमति दे दी।","उसने सहमति केवल इसलिए दी क्योंकि रोके जाने के दौरान उसका रक्त-अल्कोहल स्तर पहले से ही 0.08% या उससे अधिक मापा गया था।","उसने अपने टेक्सास ड्राइवर लाइसेंस के लिए आवेदन करते समय सहमति दी, जो सभी इनकारों को स्थायी रूप से माफ कर देता है।"],"explanation":"Texas law states that by driving in the state you give implied consent to a breath or blood test if lawfully arrested for DWI, so consent already exists at the time of arrest. Option A is wrong because consent comes from the act of driving, not signing paperwork, and a 0.08% reading or the license application does not establish it."},"14":{"q":"देर रात रोके जाने के बाद मार्कस को नशे में गाड़ी चलाने (DWI) के लिए कानूनी रूप से गिरफ्तार किया जाता है। थाने में अधिकारी उससे सांस का नमूना देने को कहता है, लेकिन मार्कस यह मानते हुए मना कर देता है कि बिना जांच के उसके खिलाफ कोई सबूत नहीं होगा। DWI के आरोप को एक तरफ रखते हुए, केवल जांच से इनकार करने के कारण उसके ड्राइवर लाइसेंस का क्या होता है?","options":["उसके लाइसेंस को कुछ नहीं होता, क्योंकि निहित सहमति के तहत चालक को बिना किसी परिणाम के सांस या रक्त जांच से इनकार करने का अधिकार हमेशा होता है","इस पहली बार इनकार के लिए उसका लाइसेंस 1 साल तक के लिए निलंबित कर दिया जाता है","इस पहली बार इनकार के लिए उसका लाइसेंस स्वतः 180 दिनों के लिए निलंबित कर दिया जाता है","जांच से इनकार करने के लिए उस पर $2,000 का जुर्माना और 180 दिनों तक की जेल हो सकती है"],"explanation":"Under Texas implied consent, refusing a lawful breath or blood test triggers an automatic 180-day license suspension for a first refusal under Administrative License Revocation, separate from any DWI charge. The 'up to 1 year' suspension and the $2,000 fine/jail time are penalties for a DWI conviction, not for refusing the test, and refusal does carry consequences."},"15":{"q":"मार्कस को सड़क किनारे संयम जांच में विफल होने के बाद टेक्सास में नशे में गाड़ी चलाने (DWI) के लिए कानूनी रूप से गिरफ्तार किया जाता है। थाने में, वह सांस या रक्त का नमूना देने से इनकार कर देता है, यह मानते हुए कि परीक्षण परिणाम के बिना राज्य के पास कोई मामला नहीं है और उसका लाइसेंस सुरक्षित है। कई महीने बाद उसका DWI आरोप अदालत में खारिज कर दिया जाता है। उसके ड्राइविंग विशेषाधिकारों की स्थिति क्या है?","options":["चूंकि DWI आरोप खारिज कर दिया गया, कोई निलंबन लागू नहीं होता और उसका लाइसेंस पूरी तरह वैध रहता है।","उसका लाइसेंस 1 साल तक के लिए निलंबित रहता है, जो पहली DWI सजा से जुड़ा मानक दंड है।","उसे इनकार के लिए केवल $2,000 का जुर्माना भरना पड़ता है, लेकिन उसका लाइसेंस निलंबित नहीं होता।","इनकार के लिए उसका लाइसेंस प्रशासनिक लाइसेंस रद्दीकरण (ALR) के तहत स्वचालित रूप से 180 दिनों के लिए निलंबित हो जाता है, जो खारिज किए गए DWI आरोप से अलग है।"],"explanation":"Refusing a breath or blood test triggers an automatic 180-day ALR suspension that is entirely separate from the DWI case, so it stands even though the DWI charge was dismissed. Option B wrongly applies the up-to-1-year suspension tied to a DWI conviction, which never occurred here, and the dismissal does not erase the refusal-based ALR suspension."},"16":{"q":"ह्यूस्टन के एक बार में, 24 वर्षीय मार्कस कई ड्रिंक्स पीता है, फिर घर की ओर गाड़ी चलाता है और 0.11% रक्त अल्कोहल स्तर (BAC) के साथ रोका जाता है। उसे गिरफ्तार किया जाता है और बिना किसी पूर्व अपराध और कार में बिना किसी सवारी के, उसके पहले DWI (नशे में गाड़ी चलाने) के लिए दोषी ठहराया जाता है। इस पहले DWI दोषसिद्धि के लिए अदालत अधिकतम कितना जुर्माना लगा सकती है?","options":["$2,000 तक","$500 तक","$4,000 तक","$10,000 तक"],"explanation":"A first DWI in Texas carries a fine of up to $2,000, along with possible jail time and license suspension. The $500 figure is the maximum fine for a minor's first DUI, and the higher amounts apply to repeat or aggravated offenses, not a standard first DWI."},"17":{"q":"मार्कस को टेक्सास में उसके पहले DWI के लिए दोषी ठहराया गया, जब उसे एक दोस्त की पार्टी से निकलते समय 0.10% रक्त अल्कोहल स्तर के साथ रोका गया। न्यायाधीश अब पहले DWI के लिए टेक्सास कानून द्वारा निर्धारित सीमा के भीतर उसकी जेल की सजा तय कर रहे हैं। न्यायाधीश कौन सी संभावित जेल अवधि लगा सकते हैं?","options":["1 वर्ष तक की जेल","3 दिन से 180 दिन तक की जेल","जेल के बजाय निश्चित 180 दिन का लाइसेंस निलंबन","कोई जेल नहीं, केवल 500 डॉलर का जुर्माना"],"explanation":"Under Texas law, a first DWI carries 3 days to 180 days in jail, so the judge's range is set by that statute. The 1-year figure is the license suspension (not jail), the 180-day suspension applies to refusing a chemical test under ALR, and the $500 fine is a minor's first DUI penalty."},"18":{"q":"28 वर्षीय मार्कस को शुक्रवार रात एक पार्टी से निकलते समय रोका जाता है। वह सांस परीक्षण देता है, 0.10% BAC दर्ज करता है, और टेक्सास में अपने पहले DWI (नशे में गाड़ी चलाने) के लिए दोषी ठहराया जाता है। उसके साथ कोई बच्चा यात्री नहीं है और कोई पूर्व अपराध भी नहीं है। सजा सुनाते समय, इस पहले DWI दोषसिद्धि के लिए उसका ड्राइवर लाइसेंस अधिकतम कितनी अवधि के लिए निलंबित किया जा सकता है?","options":["180 दिन, सांस परीक्षण से इनकार करने पर लगाई जाने वाली वही अवधि","कोई निलंबन नहीं, क्योंकि उसका BAC 0.15% से कम था","1 साल तक","2 साल तक, किसी भी DWI के लिए मानक अवधि"],"explanation":"A first DWI conviction in Texas carries a license suspension of up to 1 year. The 180-day figure is the separate automatic suspension for refusing a chemical test under implied consent, not the penalty for a DWI conviction, so option A is a trap."},"19":{"q":"मार्कस को पिछले साल टेक्सास में नशे में गाड़ी चलाने (DWI) के लिए दोषी ठहराया गया था; उसने अपना जुर्माना भरा और सजा काटी। आज रात उसे रोका गया और दूसरी बार DWI के लिए गिरफ्तार किया गया। उसकी पहली सजा की तुलना में, इस दोबारा अपराध के लिए उसे क्या उम्मीद करनी चाहिए?","options":["सजा बिल्कुल पहली DWI जैसी ही है: अधिकतम $2,000 का जुर्माना और 1 साल तक लाइसेंस निलंबन।","कोई अतिरिक्त सजा नहीं है क्योंकि टेक्सास केवल सबसे हाल की DWI सजा को गिनता है।","उसका लाइसेंस स्वतः 180 दिनों के लिए निलंबित हो जाता है, और यह किसी भी अन्य DWI सजा की जगह ले लेता है।","दोबारा अपराध के लिए सजा बढ़ जाती है, इसलिए उसे पहली DWI की तुलना में अधिक कठोर जुर्माना, लंबी जेल अवधि और लंबा निलंबन झेलना पड़ता है।"],"explanation":"Texas law increases DWI penalties for repeat offenses, so a second conviction brings tougher consequences than the first. Option A wrongly states the first-offense maximums ($2,000 / 1 year) apply unchanged, and option C confuses the 180-day ALR suspension for refusing a test with the criminal DWI penalty."},"20":{"q":"मार्कस को एक पार्टी से घर लौटते समय रोका जाता है। वह 27 वर्ष का है, यह उसका जीवन का पहला DWI (नशे में गाड़ी चलाने) गिरफ्तारी है, और सांस परीक्षण में BAC 0.16% दिखता है। उसका दोस्त कहता है कि दंड किसी भी अन्य पहले अपराध वाले DWI के बिल्कुल समान ही होंगे। दोस्त क्यों गलत है?","options":["क्योंकि 0.15% या उससे अधिक का BAC पहले अपराध पर भी बढ़े हुए दंड को सक्रिय कर देता है।","क्योंकि सांस परीक्षण से इनकार करने पर मानक पहले अपराध का जुर्माना हमेशा दोगुना हो जाता है।","क्योंकि कोई भी पहला DWI अपराध स्वतः ही गंभीर अपराध (felony) के रूप में दर्ज होता है।","क्योंकि दंड केवल तभी बढ़ते हैं जब वाहन में 15 वर्ष से कम आयु का बच्चा हो।"],"explanation":"In Texas, penalties for a first DWI increase when the driver's BAC is 0.15% or higher, so Marcus's 0.16% reading means enhanced penalties. A child passenger under 15 (D) is a separate felony enhancement, but it does not apply here since Marcus was alone."},"21":{"q":"एक पार्टी से घर लौटते समय मार्कस को रोका जाता है और उसके रक्त में अल्कोहल की मात्रा (BAC) 0.10% मापी जाती है। यह उसका पहला DWI (नशे में गाड़ी चलाने) का अपराध है, लेकिन उसकी 8 साल की भतीजी पीछे की सीट पर सीट बेल्ट लगाकर बैठी है। एक बच्चे के सवार होने से इस अपराध का वर्गीकरण कैसे बदल जाता है?","options":["इसका आरोप पर कोई असर नहीं पड़ता क्योंकि यह फिर भी उसका पहला अपराध है","15 साल से कम उम्र के बच्चे को सवारी के रूप में बिठाकर नशे में गाड़ी चलाना इस अपराध को एक गंभीर अपराध (फेलनी) बना देता है","यह खुले कंटेनर नियम के तहत स्वचालित 180 दिन का लाइसेंस निलंबन जोड़ देता है","यह अधिकतम जुर्माना बढ़ाकर 500 डॉलर कर देता है क्योंकि इसमें एक नाबालिग शामिल है"],"explanation":"In Texas, DWI with a child passenger under age 15 is a felony, regardless of whether it is a first offense. The 180-day suspension belongs to refusing a chemical test, and the $500 figure is the fine for a minor's own first DUI, not a penalty tied to carrying a child passenger."},"22":{"q":"टेक्सास में एक चालक को रोका जाता है, वह संयम परीक्षण पास कर लेता है और उसका रक्त-अल्कोहल स्तर (BAC) 0.05% दर्ज होता है, इसलिए अधिकारी उस पर नशे में गाड़ी चलाने (DWI) का आरोप नहीं लगाता। हालांकि, अधिकारी चालक के बगल वाले कप-होल्डर में आधी खाली बीयर की बोतल देखता है। टेक्सास का कानून यात्री क्षेत्र में अल्कोहल के इस खुले कंटेनर को कैसे मानता है?","options":["इसे नजरअंदाज किया जाता है क्योंकि उसका BAC 0.08% की कानूनी सीमा से कम था।","यह निहित सहमति के तहत उसके लाइसेंस को स्वतः 180 दिनों के लिए निलंबित कर देता है।","यह किसी भी DWI आरोप से अलग एक स्वतंत्र अपराध है।","यह केवल तभी अपराध है जब वाहन में 15 वर्ष से कम उम्र का बच्चा हो।"],"explanation":"Having an open container of alcohol in the passenger area is a separate offense in Texas, independent of whether a DWI charge applies or what the driver's BAC was. The 180-day suspension relates to refusing a chemical test under implied consent, and the child-passenger rule concerns the felony DWI enhancement, not open containers."},"23":{"q":"मार्कस 18 साल का है और एक पार्टी से घर जाते समय उसे रोका जाता है। सांस परीक्षण में रक्त में अल्कोहल की मात्रा (BAC) 0.02% दिखती है, और एक नाबालिग के रूप में उसे अपने पहले DUI (अल्कोहल) के लिए दोषी ठहराया जाता है। लाइसेंस निलंबन, सामुदायिक सेवा और अल्कोहल-जागरूकता पाठ्यक्रम के अलावा, इस पहले अपराध के लिए उसे अधिकतम कितना जुर्माना भुगतना पड़ सकता है?","options":["$2,000 तक, वही जुर्माना जो एक वयस्क के पहले DWI के लिए लगता है","कोई जुर्माना नहीं, क्योंकि BAC वयस्क सीमा 0.08% से कम था","$1,000 तक, अल्कोहल पाए जाने के कारण दोगुना","$500 तक"],"explanation":"Under Texas zero-tolerance law, a minor's first DUI (alcohol) carries a fine of up to $500, along with license suspension, community service, and an alcohol-awareness course. The $2,000 figure is the maximum for an adult first DWI, and no fine being charged is wrong because any detectable alcohol is illegal for a driver under 21."},"24":{"q":"मार्कस 19 साल का है और एक पार्टी से घर लौटते समय उसे रोका जाता है। अधिकारी को शराब की गंध आती है, और एक सांस परीक्षण 0.03% का BAC दिखाता है। यह मार्कस का पहला शराब से संबंधित अपराध है। टेक्सास कानून के तहत उसके ड्राइविंग विशेषाधिकारों का क्या होता है?","options":["उसका लाइसेंस निलंबित कर दिया जाता है, क्योंकि 21 वर्ष से कम उम्र के चालक में किसी भी मात्रा में पाई गई शराब एक DUI है जिसके लिए निलंबन होता है।","उसके लाइसेंस के साथ कुछ नहीं होता, क्योंकि उसका BAC 0.08% की कानूनी सीमा से कम है।","सांस परीक्षण से इनकार करने के लिए विशेष रूप से उसका लाइसेंस 180 दिनों के लिए निलंबित कर दिया जाता है।","उसे गंभीर अपराध (फेलोनी) का आरोप और एक साल का निलंबन झेलना पड़ता है क्योंकि उसका BAC मापा गया था।"],"explanation":"Texas has zero tolerance for drivers under 21, so any detectable alcohol (above 0.00%) is a DUI for a minor and carries a license suspension. The 0.08% limit (B) applies only to adults 21+, the 180-day suspension (C) is for refusing a test, and a felony (D) does not result from a minor's first DUI."},"25":{"q":"19 saal ke Marcus ko ek raat der se Austin mein roka jata hai. Adhikari uski saans mein thodi matra mein sharab ka pata lagata hai, aur ek janch 0.03% BAC (rakt mein sharab ki matra) ki pushti karti hai. Yah uska pahla apraadh hai. Texas ke shunya-sahanshilta kanoon ke tahat, uski saza mein nimnalikhit mein se kya shamil hoga?","options":["Keval ek likhit chetavani, kyonki uska BAC vayask 0.08% seema se kaafi neeche hai","$500 tak ka jurmana, license nilamban, samudayik seva, aur ek sharab-jagrukta paathyakram","180 din tak ki jail aur $2,000 jurmana, ek vayask DWI ke samaan","Saans janch se inkaar karne ke liye स्वचालित 180-din ka nilamban"],"explanation":"Because Marcus is under 21, any detectable alcohol is a DUI by a minor under zero-tolerance, and a first offense carries a fine up to $500, license suspension, community service, and an alcohol-awareness course. The 0.08% adult limit and adult DWI jail/fine penalties do not apply to a minor's first DUI, and the 180-day suspension is for refusing the test, which he did not refuse."},"26":{"q":"19 वर्षीय मार्कस को ऑस्टिन में एक पार्टी से निकलते समय रोका जाता है। सांस परीक्षण में उसका रक्त-अल्कोहल स्तर (BAC) 0.03% दिखता है, और उसे नाबालिग के रूप में अपने पहले DUI का दोषी ठहराया जाता है। टेक्सास के शून्य-सहनशीलता कानून के तहत, निम्नलिखित में से कौन सा उसकी सजा का एक अनिवार्य हिस्सा है?","options":["कुछ और नहीं, क्योंकि उसका BAC वयस्क सीमा 0.08% से कम था","केवल सांस परीक्षण कराने के लिए स्वतः 180 दिन का निलंबन","एक अल्कोहल-जागरूकता पाठ्यक्रम पूरा करना","अनिवार्य न्यूनतम 3 दिन की जेल"],"explanation":"A minor's first DUI for alcohol requires completion of an alcohol-awareness course (plus a fine up to $500, license suspension, and community service). Option A is wrong because under-21 zero tolerance makes ANY detectable alcohol illegal, and the 3-day jail minimum (D) and the 180-day suspension for refusing a test (B) belong to adult DWI and refusal rules, not a minor's first DUI."},"27":{"q":"मार्कस ने पिछले दो वर्षों में तीन तेज़ रफ़्तार के टिकट और एक लाल बत्ती तोड़ने की सज़ा पाई है। उसे चिंता है कि पहले से चुकाए गए जुर्मानों के अलावा इन ट्रैफ़िक उल्लंघनों का उसके टेक्सास ड्राइविंग रिकॉर्ड पर क्या असर होगा। इन ट्रैफ़िक दोषसिद्धियों के जमा होने का सबसे सही परिणाम क्या है?","options":["जुर्माना चुकाने के बाद कुछ नहीं होता; इन दोषसिद्धियों का उसके रिकॉर्ड पर कोई असर नहीं पड़ता।","हर दोषसिद्धि के लिए उसे स्वतः ही SR-22 वित्तीय उत्तरदायित्व बीमा रखना अनिवार्य हो जाता है।","दूसरे टिकट के बाद ये दोषसिद्धियाँ स्वतः 180 दिन के लाइसेंस निलंबन को सक्रिय कर देती हैं।","ये दोषसिद्धियाँ उसके रिकॉर्ड में अंक जोड़ती हैं, और बहुत अधिक अंक होने पर सरचार्ज और लाइसेंस निलंबन हो सकता है।"],"explanation":"Traffic convictions add points to your Texas driving record, and accumulating too many can result in surcharges and license suspension. SR-22 is tied to serious offenses like a DWI rather than ordinary tickets, and the automatic 180-day suspension applies to refusing a breath/blood test under implied consent, not to routine moving violations."},"28":{"q":"मार्कस ने अपने टेक्सास ड्राइवर लाइसेंस पर पिछले दो वर्षों में कई ट्रैफ़िक दोषसिद्धियाँ जमा कर ली हैं। अपनी हाल की अदालती पेशी में, जज उसे चेतावनी देते हैं कि दोषसिद्धियाँ जमा करते रहने से अलग-अलग जुर्मानों के अलावा अतिरिक्त परिणाम भी होंगे। टेक्सास के पॉइंट/सरचार्ज प्रणाली के अनुसार, बहुत अधिक दोषसिद्धियाँ अंततः किस ओर ले जा सकती हैं?","options":["सरचार्ज (surcharges) और लाइसेंस निलंबन की ओर","सांस परीक्षण से इनकार करने पर स्वचालित 180-दिन के निलंबन की ओर","अनिवार्य SR-22 की ओर, केवल तभी जब एक दोषसिद्धि खुले शराब कंटेनर के लिए हो","गंभीर अपराध (फेलनी) आरोपों की ओर, क्योंकि बार-बार की दोषसिद्धियाँ बच्चे के साथ DWI मानी जाती हैं"],"explanation":"Under the Texas point/surcharge system, traffic convictions add points to your record, and too many convictions can lead to surcharges and license suspension. The 180-day suspension applies specifically to refusing a breath or blood test (implied consent), not to accumulating ordinary convictions, so that option is a misplaced fact."},"29":{"q":"मार्कस को एक साल पहले टेक्सास में अपने पहले DWI (नशे में गाड़ी चलाने) के लिए दोषी ठहराया गया था। अब उसने अपना निलंबन पूरा कर लिया है और जुर्माना भर दिया है, लेकिन उसकी ऑटो बीमा कंपनी ने उसे हटा दिया है, और जो एकमात्र पॉलिसियाँ उसे मिल रही हैं वे पहले की तुलना में लगभग तीन गुना दरें बता रही हैं। वह DPS को फोन करके पूछता है कि मामला समाप्त होने के इतने समय बाद भी उसकी ड्राइविंग स्थिति क्यों प्रभावित हो रही है। उसे सबसे सटीक स्पष्टीकरण क्या मिलेगा?","options":["एक बार जुर्माना भरने और निलंबन पूरा होने पर, DWI स्वतः ही उसके रिकॉर्ड से हट जाता है, इसलिए कोई भी ऊंची दर एक असंबंधित बिलिंग त्रुटि है।","DWI का दोषसिद्धि उसके रिकॉर्ड में बनी रहती है और बीमा लागत को तेजी से बढ़ा देती है, और ड्राइविंग विशेषाधिकार बहाल करने के लिए उसे SR-22 वित्तीय जिम्मेदारी बीमा रखना आवश्यक हो सकता है।","ऊंची लागत केवल 180-दिन का अस्थायी अधिभार है जो उसके सांस परीक्षण से इनकार से जुड़ा है, और यह अवधि समाप्त होने के बाद समाप्त हो जाएगा।","उसके रिकॉर्ड में अब DWI दिखता है, लेकिन टेक्सास में बीमाकर्ताओं को केवल एक पहले अपराध के आधार पर दरें बढ़ाने से कानूनी रूप से रोका गया है।"],"explanation":"A DWI conviction stays on the driver's record and sharply raises insurance costs, and an SR-22 financial responsibility filing may be required to reinstate driving privileges. Option A is wrong because completing penalties does not erase the conviction, and option C confuses this with the separate 180-day ALR suspension for refusing a test."},"30":{"q":"मार्कस ने पहली DWI (नशे में गाड़ी चलाने) की सजा के लिए अपनी अदालती सजा पूरी कर ली, और उसके एक साल के लाइसेंस निलंबन की अवधि अब समाप्त हो गई है। जब वह अपने ड्राइविंग विशेषाधिकार बहाल कराने के लिए DPS कार्यालय जाता है, तो क्लर्क उसे बताता है कि उसे पहले एक विशिष्ट फॉर्म दाखिल करना होगा जो यह साबित करता हो कि वह आगे के लिए पर्याप्त देयता कवरेज रखता है। इस आवश्यकता को क्या कहा जाता है?","options":["एक खुले कंटेनर की घोषणा जो दर्शाती हो कि वह यात्री क्षेत्र में शराब नहीं रखता","एक निहित सहमति त्याग पत्र जो भविष्य के सांस या रक्त परीक्षणों को स्वीकार करता हो","SR-22 वित्तीय उत्तरदायित्व बीमा","एक शराब जागरूकता पाठ्यक्रम पूर्णता प्रमाणपत्र"],"explanation":"After a DWI, Texas may require SR-22 financial responsibility insurance to prove coverage before driving privileges are reinstated. The alcohol-awareness course is tied to a minor's DUI penalty, not the insurance reinstatement requirement, and implied consent and open container are unrelated to proving financial responsibility."},"31":{"q":"आपकी उम्र 28 साल है और आपने एक दोस्त के घर रात के खाने के साथ दो बीयर पी हैं। आप पूरी तरह ठीक महसूस कर रहे हैं, और आपको शांत सड़कों पर घर तक 25 मिनट की ड्राइव करनी है। सबसे सुरक्षित विकल्प क्या है?","options":["घर ड्राइव करें, क्योंकि दो ड्रिंक हमेशा एक वयस्क को 0.08% की कानूनी सीमा से नीचे रखते हैं","लगभग 20 मिनट रुकें, थोड़ी कॉफी पिएं, और सतर्क महसूस होने पर ड्राइव करें","अभी ड्राइव करें क्योंकि जब तक आपका निर्णय स्पष्ट रूप से प्रभावित न हो, आप कानूनी रूप से नशे में नहीं माने जाते","बिल्कुल भी ड्राइव न करें; राइड सेवा बुलाएं, एक शांत (बिना नशे वाला) चालक का प्रबंध करें, या वहीं रुक जाएं"],"explanation":"The safest choice is always zero alcohol before driving, so arranging a sober ride or staying put is correct. Two beers will not reliably keep you under 0.08%, and only time (not coffee) lowers BAC, so the other options are dangerous mistakes."},"32":{"q":"काम के बाद आप दोस्तों से एक बार में मिलते हैं और दो घंटे में कई ड्रिंक पीते हैं। आपको शराब का असर महसूस होता है और आप जानते हैं कि आप सुरक्षित रूप से घर चलाने की स्थिति में नहीं हैं। घर पहुंचने का सबसे सुरक्षित तरीका क्या है?","options":["किसी राइड सेवा को बुलाएं, अपनी चाबियां ऐसे दोस्त को दें जिसने शराब नहीं पी है, या जब तक आप होश में न आ जाएं तब तक वहीं रुके रहें","कुछ कप कड़क कॉफी पिएं और घर चलाने से पहले लगभग 30 मिनट प्रतीक्षा करें","चलाने से पहले जल्दी होश में आने के लिए भरपेट भोजन करें और ठंडे पानी से नहाएं","अपनी कार में बैठकर हर ड्रिंक के लिए एक घंटा प्रतीक्षा करें, फिर खुद घर चलाकर जाएं"],"explanation":"The safe, always-true choices are to use a ride service, designate a sober driver, or stay put until sober. Coffee, food, and a cold shower do NOT speed up sobering; only time lowers BAC, and the answer to alcohol is not to drive at all rather than wait it out in your car and then drive."},"33":{"q":"मार्कस 24 वर्ष का है और एक रात्रिभोज पार्टी के बाद अपनी कार से घर जा रहा है। एक पुलिस अधिकारी उसे रोकता है, और एक श्वास परीक्षण से पता चलता है कि उसका BAC ठीक 0.08% है। इस रीडिंग पर, टेक्सास कानून के अनुसार मार्कस को कानूनी रूप से क्या माना जाता है?","options":["वह कानूनी सीमा के नीचे है क्योंकि 0.08% की सीमा केवल वाणिज्यिक चालकों पर लागू होती है","वह नशे में वाहन चला रहा है (DWI), क्योंकि 21 वर्ष और उससे अधिक उम्र के वयस्कों के लिए 0.08% या उससे अधिक का BAC कानूनी सीमा है","वह तभी दोषी है जब वह नशे के दृश्य लक्षण भी दिखाए, क्योंकि अकेले 0.08% पर्याप्त नहीं है","उसने शून्य सहनशीलता के तहत DUI किया है, क्योंकि किसी भी पता लगाने योग्य मात्रा में अल्कोहल अवैध है"],"explanation":"For adults 21 and older, driving at or above 0.08% BAC is Driving While Intoxicated (DWI), so Marcus's exact 0.08% reading meets the threshold. The 0.04% commercial limit and the Zero Tolerance rule for drivers under 21 do not apply to a 24-year-old in his personal vehicle, and no additional visible impairment is required at or above 0.08%."},"34":{"q":"मार्कस 19 साल का है। एक ग्रेजुएशन पार्टी के बाद उसे रोका जाता है, और एक सांस परीक्षण में रक्त-अल्कोहल स्तर (BAC) 0.03% दिखता है। वह तर्क देता है कि उस पर आरोप नहीं लगाया जा सकता क्योंकि उसका स्तर वयस्क की 0.08% सीमा से काफी नीचे है। टेक्सास कानून के तहत, उसकी स्थिति के बारे में क्या सच है?","options":["वह सही है; कोई आरोप लागू नहीं होता क्योंकि 0.03%, 0.08% DWI सीमा से नीचे है।","उस पर केवल तभी आरोप लग सकता है जब उसका BAC 0.04%, यानी वाणिज्यिक चालक सीमा तक पहुंचे।","चूंकि वह 21 वर्ष से कम का है, शून्य सहनशीलता लागू होती है, इसलिए कोई भी पता लगाने योग्य अल्कोहल इसे एक नाबालिग द्वारा DUI बना देता है।","उस पर गंभीर अपराध DWI का आरोप लगेगा क्योंकि 0.03% एक नाबालिग के लिए उच्च BAC माना जाता है।"],"explanation":"टेक्सास की शून्य सहनशीलता नीति 21 वर्ष से कम उम्र के चालकों के लिए किसी भी पता लगाने योग्य अल्कोहल (0.00 से अधिक BAC) को अवैध बनाती है, इसलिए मार्कस पर एक नाबालिग के रूप में DUI का आरोप लगाया जाता है, भले ही वह 0.08% से नीचे हो। वयस्क की 0.08% और वाणिज्यिक 0.04% सीमाएं नाबालिगों पर लागू नहीं होतीं, और 0.03% उच्च BAC गंभीर अपराध की स्थिति नहीं है।"},"35":{"q":"मारिया को ऑस्टिन में लेन बदल-बदल कर गाड़ी चलाने के लिए रोका जाता है। यह उसकी जीवन की पहली DWI (नशे में गाड़ी चलाने) की गिरफ्तारी है, उसका BAC 0.10% मापा गया है, और उसका 9 वर्षीय भतीजा पीछे की सीट पर सीट-बेल्ट लगाए बैठा है। बच्चे की मौजूदगी उसके DWI की कानूनी गंभीरता को कैसे बदल देती है?","options":["कुछ नहीं बदलता; बच्चा यात्री केवल जुर्माने की राशि को प्रभावित करता है, जो बढ़कर अधिकतम 2,000 डॉलर हो जाती है","उसका लाइसेंस अपने आप 180 दिनों के लिए निलंबित हो जाता है क्योंकि वाहन में एक बच्चा मौजूद था","यह एक मानक पहली बार का छोटा अपराध (मिसडिमीनर) ही रहता है, लेकिन उसे एक अल्कोहल-जागरूकता पाठ्यक्रम भी पूरा करना होगा","चूंकि 15 वर्ष से कम उम्र का एक बच्चा यात्री मौजूद था, अपराध छोटे अपराध (मिसडिमीनर) से बढ़कर गंभीर अपराध (फेलनी) बन जाता है"],"explanation":"Under Texas law, a DWI committed with a child passenger younger than 15 in the vehicle is elevated to a felony, regardless of it being a first offense. Option B confuses this with the 180-day ALR suspension for refusing a chemical test, and the $2,000 fine in A is the standard first-offense misdemeanor penalty, not the felony enhancement triggered by the child."},"36":{"q":"ऑस्टिन में नशे में गाड़ी चलाने (DWI) के लिए आपको कानूनी रूप से गिरफ्तार किया जाता है। अधिकारी आपसे सांस की जांच कराने को कहता है, लेकिन आप यह कहकर मना कर देते हैं कि आप इसके बजाय केवल रक्त का नमूना देने के लिए सहमत होंगे। टेक्सास के निहित सहमति कानून के तहत आपकी स्थिति के बारे में क्या सही है?","options":["टेक्सास में गाड़ी चलाकर आपने सांस या रक्त जांच के लिए निहित सहमति दे दी है, इसलिए जांच का प्रकार किसी एक तक सीमित नहीं है; मांगी गई जांच से इनकार करने पर लाइसेंस स्वतः निलंबित हो सकता है।","निहित सहमति केवल सांस की जांच को कवर करती है, इसलिए आपको बिना किसी दंड के इसके बजाय रक्त जांच की मांग करने का अधिकार है।","निहित सहमति केवल रक्त जांच पर लागू होती है, इसलिए सांस की जांच से इनकार करने का कोई परिणाम नहीं होता।","चूंकि आपने एक विकल्प पेश किया, इसलिए लीवर एक घंटे के भीतर शराब को संसाधित कर देगा और किसी जांच की आवश्यकता नहीं है।"],"explanation":"Texas implied consent covers a breath OR blood test, not just one type, so you can't limit it to your preferred test; refusing the lawfully requested test triggers an automatic 180-day suspension under ALR. Options B and C wrongly restrict implied consent to a single test type, and D confuses the unrelated fact that the liver processes about one drink per hour."},"37":{"q":"रात के खाने के साथ कुछ बीयर पीने के बाद, एक चालक देखता है कि सामने से आती गाड़ियों की हेडलाइट अब धुंधली दिख रही हैं और उसे अपनी लेन के किनारे तथा फुटपाथ से उतरते एक पैदल यात्री को देखने में कठिनाई हो रही है। वह गाड़ी चलाते समय जो अनुभव कर रहा है, उसे शराब का कौन सा प्रभाव सबसे अच्छी तरह समझाता है?","options":["शराब एक उत्तेजक की तरह काम करती है जो ध्यान को तेज करती है, इसलिए धुंधलापन उसकी हेडलाइट के कारण होगा, शराब के कारण नहीं","शराब एक अवसादक है जो दृष्टि को कम करती है, जिससे वस्तुओं को स्पष्ट रूप से देखना कठिन हो जाता है और वह जो पहचान सकता है उसका दायरा सिकुड़ जाता है","शराब दृष्टि को केवल तभी प्रभावित करती है जब चालक 0.08% की कानूनी सीमा से ऊपर हो, इसलिए इससे नीचे उसकी दृष्टि अप्रभावित रहती है","शराब प्रतिक्रिया समय को तेज कर देती है, जिससे केवल तेज गति पर पास की वस्तुएं धुंधली दिखती हैं"],"explanation":"Alcohol is a depressant that reduces vision among the abilities it impairs, so blurry headlights and trouble seeing the lane and pedestrian are direct effects of the alcohol. Option C is wrong because alcohol can impair vision and driving even below 0.08%, and A and D misstate alcohol as a stimulant or claim it speeds reaction time, when it actually slows reactions."},"38":{"q":"एक दोस्त के घर तीन बीयर पीने के बाद मार्कस गाड़ी चलाने बैठता है। घर जाते समय उसे पता चलता है कि वह बार-बार अपनी लेन से भटक रहा है और जब वह स्टीयरिंग में छोटे सुधार करने की कोशिश करता है तो उसके हाथ बेढंगे और धीमे महसूस होते हैं। शराब का उसके शरीर पर कौन सा प्रभाव सबसे अच्छी तरह समझाता है कि उसका स्टीयरिंग लापरवाह और गलत क्यों हो गया है?","options":["शराब उसके प्रतिक्रिया समय को तेज़ कर देती है, इसलिए वह स्टीयरिंग को ज़्यादा सुधार रहा है","शराब एक उत्तेजक के रूप में काम करती है जो उसकी मांसपेशियों को तनावग्रस्त और झटकेदार बना देती है","शराब उसका समन्वय कम कर देती है, जिससे सहज और सटीक स्टीयरिंग करना कठिन हो जाता है","शराब का असर खत्म हो चुका है क्योंकि तीन बीयर कानूनी सीमा से कम है"],"explanation":"Alcohol is a depressant that reduces coordination, which is exactly why smooth, precise steering becomes difficult. Option A is wrong because alcohol slows reaction time rather than speeding it up, and option B is wrong because alcohol is a depressant, not a stimulant."},"39":{"q":"एक अधिकारी देर रात मार्कस को लेन के बीच लहराते हुए गाड़ी चलाने के लिए रोकता है। फील्ड संयम परीक्षणों के बाद, अधिकारी मार्कस को नशे में गाड़ी चलाने (DWI) के लिए वैध रूप से गिरफ्तार करता है और फिर उससे सांस का नमूना देने को कहता है। टेक्सास के निहित सहमति कानून के तहत, अधिकारी के लिए इस सांस परीक्षण की मांग करना किस वजह से वैध हुआ?","options":["किसी भी गिरफ्तारी से पहले ही मार्कस का BAC 0.08% या उससे अधिक मापा जा चुका था","मार्कस ने अपना ड्राइवर लाइसेंस नवीनीकृत करते समय एक निहित सहमति छूट पर हस्ताक्षर किए थे","अधिकारी ने मार्कस को लेन के बीच लहराते हुए देखा, जो अकेले ही परीक्षण के लिए बाध्य करने हेतु पर्याप्त है","मार्कस को नशे में गाड़ी चलाने (DWI) के लिए वैध रूप से गिरफ्तार किया गया, जो सांस या रक्त परीक्षण के लिए निहित सहमति को सक्रिय करता है"],"explanation":"In Texas, the lawful trigger for implied consent testing is being lawfully arrested for DWI, so option D is correct. Observing bad driving (C) may justify the stop or arrest but does not by itself compel a test, and there is no separately signed waiver at license renewal (B)."}},"learn-alcohol-and-penalties":{"0":{"q":"टेक्सास में, 21 वर्ष या उससे अधिक उम्र के वयस्क ड्राइवर के लिए DWI की रक्त-अल्कोहल (BAC) सीमा क्या है?","options":["0.08%","0.04%","0.10%","0.05%"],"explanation":"In Texas, an adult age 21 or older is legally intoxicated (DWI) at a BAC of 0.08% or higher."},"1":{"q":"टेक्सास में, 0.08% BAC या उससे अधिक पर गाड़ी चलाना कौन सा अपराध है?","options":["तेज़ गति से चलाना","नशे में गाड़ी चलाना (DWI)","लापरवाही से गाड़ी चलाना","खुले कंटेनर का उल्लंघन"],"explanation":"Driving at or above 0.08% BAC is the offense called Driving While Intoxicated (DWI)."},"2":{"q":"क्या किसी चालक पर DWI का आरोप लग सकता है यदि उसका BAC 0.08% से कम है?","options":["नहीं, 0.08% से कम कभी नहीं","केवल व्यावसायिक चालकों पर","हाँ, यदि शराब या नशीली दवाओं से प्रभावित हो","केवल यदि वह जाँच से इनकार करे"],"explanation":"A driver can still be charged with DWI below 0.08% BAC if impaired by alcohol or drugs."},"3":{"q":"टेक्सास में व्यावसायिक चालक के लिए रक्त-अल्कोहल सीमा (BAC) क्या है?","options":["0.08%","0.10%","0.02%","0.04%"],"explanation":"A commercial driver's BAC limit is 0.04%, lower than the standard adult limit of 0.08%."},"4":{"q":"टेक्सास में, 21 वर्ष से कम उम्र के चालक के लिए रक्त में अल्कोहल की कानूनी सीमा क्या है?","options":["0.00 से अधिक कोई भी मात्रा अवैध है","0.08 BAC","0.04 BAC","0.05 BAC"],"explanation":"Texas uses Zero Tolerance, so any detectable alcohol (a BAC above 0.00) is illegal for a driver under 21."},"5":{"q":"किसी भी पता लगाने योग्य मात्रा में अल्कोहल के साथ गाड़ी चलाने पर एक नाबालिग क्या अपराध करता है?","options":["कुछ भी अवैध नहीं","नाबालिग द्वारा अल्कोहल का DUI (शराब के प्रभाव में गाड़ी चलाना)","पार्किंग उल्लंघन","एक वाणिज्यिक DWI"],"explanation":"Under Texas Zero Tolerance, any detectable alcohol means a minor commits DUI of alcohol by a minor."},"6":{"q":"टेक्सास में, किसी नाबालिग द्वारा DUI का क्या अर्थ है?","options":["घर के अंदर असुरक्षित ड्राइविंग","बीमा के तहत ड्राइविंग","नशे की हालत में ड्राइविंग (Driving Under the Influence)","इरादे के साथ ड्राइविंग"],"explanation":"DUI stands for Driving Under the Influence, the offense used for minors, distinct from the adult DWI."},"7":{"q":"टेक्सास में, शून्य सहनशीलता कानून किस आयु से कम के चालकों पर लागू होता है?","options":["16 वर्ष की आयु","18 वर्ष की आयु","25 वर्ष की आयु","21 वर्ष की आयु"],"explanation":"Texas's Zero Tolerance law makes any detectable alcohol illegal for drivers under 21 years of age."},"8":{"q":"शराब किस प्रकार का पदार्थ है?","options":["एक अवसादक (डिप्रेसेंट)","एक उत्तेजक","एक दर्द निवारक","एक विटामिन"],"explanation":"Alcohol is a depressant that slows your reaction time and impairs your judgment."},"9":{"q":"शराब चालक के प्रतिक्रिया समय को कैसे प्रभावित करती है?","options":["इसे तेज़ करती है","इसे धीमा करती है","इसका कोई प्रभाव नहीं होता","इसे बेहतर बनाती है"],"explanation":"Alcohol is a depressant that slows your reaction time."},"10":{"q":"गाड़ी चलाते समय शराब किसे कमज़ोर करती है?","options":["आपका ईंधन स्तर","आपके टायर का दबाव","आपका निर्णय","आपकी हेडलाइट्स"],"explanation":"Alcohol impairs judgment, which is the first driving ability affected."},"11":{"q":"शराब चालक के समन्वय के साथ क्या करती है?","options":["यह समन्वय को बेहतर बनाती है","इसका समन्वय पर कोई प्रभाव नहीं पड़ता","यह केवल रात में समन्वय को प्रभावित करती है","यह समन्वय को कम करती है"],"explanation":"Alcohol is a depressant that reduces a driver's coordination."},"12":{"q":"शराब चालक की दृष्टि को कैसे प्रभावित करती है?","options":["यह दृष्टि को कम करती है","यह दृष्टि को बेहतर बनाती है","इसका दृष्टि पर कोई प्रभाव नहीं पड़ता","यह रात की दृष्टि को तेज करती है"],"explanation":"Alcohol reduces vision, making it harder to see clearly while driving."},"13":{"q":"शराब सबसे पहले ड्राइविंग की किस क्षमता को प्रभावित करती है?","options":["दृष्टि","निर्णय क्षमता","श्रवण","स्टीयरिंग पकड़"],"explanation":"Alcohol affects judgment before other driving abilities."},"14":{"q":"रक्त में अल्कोहल की मात्रा (BAC) को केवल कौन सी चीज़ कम करती है?","options":["कॉफ़ी पीना","ठंडा स्नान करना","समय का बीतना","भारी भोजन करना"],"explanation":"Only the passage of time lowers BAC; coffee, food, and showers do not speed it up."},"15":{"q":"रक्त में अल्कोहल का स्तर केवल किससे कम होता है?","options":["कॉफी पीना","भारी भोजन करना","ठंडा स्नान करना","इंतज़ार करना और समय बीतने देना"],"explanation":"Only time lowers your BAC; coffee, food, and showers do not speed up sobering."},"16":{"q":"रक्त में अल्कोहल की मात्रा (BAC) को केवल कौन सी चीज़ कम करती है?","options":["समय","खाना खाना","कॉफ़ी पीना","ठंडा स्नान करना"],"explanation":"Only time lowers BAC; food, coffee, and showers do not speed up sobering."},"17":{"q":"किसी व्यक्ति के रक्त में अल्कोहल की मात्रा (BAC) को केवल कौन-सी चीज़ कम करती है?","options":["कॉफ़ी पीना","समय","ठंडा स्नान","ताज़ी हवा"],"explanation":"Only time lowers BAC; coffee, a cold shower, and fresh air do not speed up sobering."},"18":{"q":"आपके रक्त में अल्कोहल का स्तर कम करने वाली एकमात्र चीज़ क्या है?","options":["ताज़ी हवा","कॉफ़ी पीना","समय","ठंडा स्नान"],"explanation":"Only time lowers BAC; fresh air, coffee, and a cold shower do not speed up sobering."},"19":{"q":"आपका लीवर एक घंटे में लगभग कितनी शराब संसाधित कर सकता है?","options":["लगभग चार ड्रिंक","लगभग तीन ड्रिंक","लगभग दो ड्रिंक","लगभग एक ड्रिंक"],"explanation":"The liver processes about one standard drink per hour, and nothing can speed it up."},"20":{"q":"Kya koi cheez liver ko sharab ko uski samanya gati se tez process karne par majboor kar sakti hai?","options":["Nahi, koi bhi cheez ise tez nahi karti","Haan, coffee peena","Haan, thanda snan","Haan, khana khana"],"explanation":"Nothing can make the liver process alcohol faster than its normal rate."},"21":{"q":"जब आप दवाओं को शराब के साथ मिलाते हैं तो क्या होता है?","options":["यह शराब के असर को खत्म कर देता है","यह क्षीणता को कई गुना बढ़ा देता है","यह नशा उतरने की गति बढ़ाता है","इसका कोई असर नहीं होता"],"explanation":"Mixing drugs (illegal, prescription, or over-the-counter) with alcohol multiplies impairment."},"22":{"q":"क्या डॉक्टरी पर्चे या बिना पर्चे की दवाएँ शराब के साथ लेने पर क्षीणता बढ़ा सकती हैं?","options":["नहीं, केवल अवैध नशे ही ऐसा करते हैं","नहीं, वे शराब को बेअसर कर देती हैं","हाँ, वे क्षीणता को कई गुना बढ़ा सकती हैं","नहीं, उनका कोई असर नहीं होता"],"explanation":"Even prescription and over-the-counter drugs can multiply impairment when combined with alcohol."},"23":{"q":"टेक्सास में, यदि आपको DWI के लिए वैध रूप से गिरफ्तार किया जाता है, तो गाड़ी चलाकर आप किसके लिए सहमति देते हैं?","options":["दृष्टि परीक्षण के लिए","ड्राइविंग परीक्षण के लिए","श्रवण परीक्षण के लिए","सांस या रक्त परीक्षण के लिए"],"explanation":"By driving in Texas you give implied consent to a breath or blood test if lawfully arrested for DWI."},"24":{"q":"टेक्सास में, निहित सहमति किस परीक्षण पर लागू होती है?","options":["सांस या रक्त परीक्षण","दृष्टि परीक्षण","श्रवण परीक्षण","लिखित परीक्षण"],"explanation":"By driving in Texas, you give implied consent to a breath or blood test if lawfully arrested for DWI."},"25":{"q":"टेक्सास में परीक्षण के लिए निहित सहमति कब लागू होती है?","options":["जब किसी चालक को तेज़ गति के लिए रोका जाता है","जब किसी चालक को नशे में गाड़ी चलाने (DWI) के लिए कानूनी रूप से गिरफ्तार किया जाता है","जब कोई चालक अवैध रूप से पार्किंग करता है","जब कोई चालक लाइसेंस का नवीनीकरण करता है"],"explanation":"By driving in Texas you give implied consent to a breath or blood test if you are lawfully arrested for DWI."},"26":{"q":"सांस या रक्त परीक्षण से इनकार करने पर पहली बार इनकार के लिए कितने दिनों का स्वचालित लाइसेंस निलंबन होता है?","options":["30 दिन","90 दिन","180 दिन","365 दिन"],"explanation":"A first refusal of the breath or blood test results in an automatic 180-day license suspension."},"27":{"q":"परीक्षण से इनकार करने पर स्वचालित लाइसेंस निलंबन किस कानून के तहत लगाया जाता है?","options":["निहित सहमति निरसन अधिनियम","खुला कंटेनर कानून","शून्य सहनशीलता कानून","प्रशासनिक लाइसेंस निरसन (ALR)"],"explanation":"Refusing a breath or blood test triggers an automatic license suspension under Administrative License Revocation (ALR)."},"28":{"q":"क्या परीक्षण से इनकार करने पर ALR लाइसेंस निलंबन, DWI दोषसिद्धि दंड से अलग है?","options":["हाँ, यह अलग है","नहीं, यह उनकी जगह लेता है","नहीं, केवल दोषी पाए जाने पर","हाँ, लेकिन केवल नाबालिगों के लिए"],"explanation":"The ALR suspension for refusing a test is separate from any DWI conviction penalties."},"29":{"q":"टेक्सास में पहली बार DWI के लिए अधिकतम जुर्माना कितना है?","options":["$500 तक","$2,000 तक","$5,000 तक","$10,000 तक"],"explanation":"A first DWI in Texas carries a fine of up to $2,000."},"30":{"q":"टेक्सास में पहली DWI में कितनी जेल की सजा हो सकती है?","options":["1 से 30 दिन","2 से 90 दिन","3 दिन से 180 दिन","5 दिन से 365 दिन"],"explanation":"A first DWI in Texas carries jail time of 3 days to 180 days."},"31":{"q":"टेक्सास में पहली बार DWI के लिए न्यूनतम जेल समय कितना है?","options":["30 दिन","10 दिन","1 दिन","3 दिन"],"explanation":"A first DWI in Texas carries a minimum jail time of 3 days."},"32":{"q":"टेक्सास में पहली बार DWI (नशे में गाड़ी चलाने) के लिए अधिकतम जेल की सजा कितनी है?","options":["180 दिन","30 दिन","1 साल","10 दिन"],"explanation":"A first DWI in Texas carries a maximum jail term of 180 days."},"33":{"q":"टेक्सास में, पहले DWI (नशे में गाड़ी चलाना) के लिए आपका लाइसेंस कितने समय तक निलंबित किया जा सकता है?","options":["30 दिन तक","1 साल तक","5 साल तक","कभी निलंबित नहीं होता"],"explanation":"A first DWI in Texas carries a license suspension of up to 1 year."},"34":{"q":"टेक्सास में, बार-बार DWI अपराध करने पर दंड का क्या होता है?","options":["वे हटा दिए जाते हैं","वे वही रहते हैं","वे बढ़ जाते हैं","वे वैकल्पिक हो जाते हैं"],"explanation":"In Texas, penalties increase for repeat DWI offenses."},"35":{"q":"टेक्सास में, कौन सा BAC (रक्त में अल्कोहल) स्तर इतना अधिक है कि DWI के दंड बढ़ जाते हैं?","options":["0.04% या अधिक","0.06% या अधिक","0.08% या अधिक","0.15% या अधिक"],"explanation":"A high BAC of 0.15% or above increases the penalties for DWI."},"36":{"q":"टेक्सास में, कौन सा उच्च BAC स्तर DWI के दंड को बढ़ाता है?","options":["0.15%","0.08%","0.04%","0.02%"],"explanation":"A BAC of 0.15% or higher increases the penalties for a Texas DWI."},"37":{"q":"टेक्सास में, पहली बार के अपराध पर नशे में गाड़ी चलाने के दंड को क्या बढ़ाता है?","options":["धीरे गाड़ी चलाना","वाहन में बच्चा सवार होना","सीट बेल्ट पहनना","रात में गाड़ी चलाना"],"explanation":"Penalties increase when there is a child passenger in the vehicle."},"38":{"q":"टेक्सास में, वाहन में 15 वर्ष से कम उम्र के बच्चे के साथ नशे में गाड़ी चलाना (DWI) क्या है?","options":["केवल एक चेतावनी","एक पार्किंग टिकट","एक गंभीर अपराध (फेलनी)","कोई अपराध नहीं"],"explanation":"In Texas, driving while intoxicated with a child under 15 in the vehicle is a felony."},"39":{"q":"टेक्सास में, यदि गाड़ी में किस उम्र से कम का बच्चा यात्री हो तो नशे में गाड़ी चलाना (DWI) गंभीर अपराध (फेलनी) बन जाता है?","options":["8 साल से कम","10 साल से कम","12 साल से कम","15 साल से कम"],"explanation":"In Texas, DWI with a child passenger under 15 years old is a felony."},"40":{"q":"टेक्सास में, यात्री क्षेत्र में शराब का खुला कंटेनर रखना क्या एक अलग अपराध है?","options":["हां, यह एक अलग अपराध है","नहीं, यह हमेशा अनुमत है","केवल यात्रियों के लिए, चालक के लिए कभी नहीं","केवल राजमार्गों पर"],"explanation":"In Texas, having an open container of alcohol in the passenger area is a separate offense."},"41":{"q":"वाहन में खुले शराब कंटेनर का अपराध कहाँ लागू होता है?","options":["केवल डिक्की में","यात्री क्षेत्र में","छत पर","बोनट के नीचे"],"explanation":"The open container offense applies to alcohol in the passenger area of the vehicle."},"42":{"q":"टेक्सास में किसी नाबालिग के पहले DUI (शराब) के लिए अधिकतम जुर्माना क्या है?","options":["$100 तक","$250 तक","$500 तक","$2,000 तक"],"explanation":"A minor's first DUI for alcohol carries a fine of up to $500."},"43":{"q":"एक नाबालिग के शराब के लिए पहले DUI में क्या शामिल होता है?","options":["कोई दंड नहीं","केवल एक चेतावनी पत्र","एक मुफ्त ड्राइविंग पाठ","लाइसेंस का निलंबन"],"explanation":"A minor's first DUI for alcohol includes a license suspension."},"44":{"q":"टेक्सास में किसी नाबालिग के पहले DUI (शराब) के लिए एक दंड क्या है?","options":["सामुदायिक सेवा","एक मुफ्त ड्राइविंग कोर्स","नए लाइसेंस पर छूट","लाइसेंस के अतिरिक्त अंक हटाना"],"explanation":"A minor's first alcohol DUI in Texas includes community service."},"45":{"q":"टेक्सास में, शराब के लिए पहले DUI के बाद एक नाबालिग को क्या पूरा करना आवश्यक है?","options":["एक रक्षात्मक ड्राइविंग पाठ्यक्रम","एक शराब-जागरूकता पाठ्यक्रम","एक दृष्टि परीक्षण","एक प्राथमिक चिकित्सा पाठ्यक्रम"],"explanation":"A minor's first alcohol DUI requires completing an alcohol-awareness course."},"46":{"q":"यातायात दोषसिद्धि आपके ड्राइविंग रिकॉर्ड में क्या जोड़ती हैं?","options":["मुफ्त ड्राइविंग पाठ","अतिरिक्त लाइसेंस वर्ष","अंक","नकद पुरस्कार"],"explanation":"Traffic convictions add points to your driving record."},"47":{"q":"बहुत अधिक यातायात दोषसिद्धियाँ किस ओर ले जा सकती हैं?","options":["कम बीमा दरें","एक मुफ्त ड्राइविंग पाठ्यक्रम","अतिरिक्त लाइसेंस अंक हटाना","अधिभार (surcharges)"],"explanation":"Too many convictions can lead to surcharges and even license suspension."},"48":{"q":"बहुत अधिक यातायात दोषसिद्धियाँ किस ओर ले जा सकती हैं?","options":["लाइसेंस का निलंबन","मुफ्त लाइसेंस नवीनीकरण","अधिक ड्राइविंग विशेषाधिकार","कम बीमा लागत"],"explanation":"Too many convictions can add surcharges and lead to license suspension."},"49":{"q":"टेक्सास में, समय के साथ DWI दोषसिद्धि का क्या होता है?","options":["एक महीने बाद यह मिट जाती है","यह आपके रिकॉर्ड में रहती है","जुर्माना भरने पर यह गायब हो जाती है","एक सुरक्षित यात्रा के बाद यह हटा दी जाती है"],"explanation":"A DWI conviction stays on your record and raises your insurance costs."},"50":{"q":"नशे में गाड़ी चलाने (DWI) की सजा आपके कार बीमा की लागत को कैसे प्रभावित करती है?","options":["इसे कम करती है","इसका कोई असर नहीं होता","इसे तेजी से बढ़ा देती है","सभी शुल्क रद्द कर देती है"],"explanation":"A DWI conviction stays on your record and sharply raises insurance costs."},"51":{"q":"टेक्सास में अपने ड्राइविंग विशेषाधिकार बहाल करने के लिए कौन सा बीमा आवश्यक हो सकता है?","options":["यात्रा बीमा","पालतू पशु बीमा","स्वास्थ्य बीमा","SR-22 वित्तीय जिम्मेदारी बीमा"],"explanation":"SR-22 financial responsibility insurance may be required to reinstate your driving privileges."},"52":{"q":"SR-22 क्या है?","options":["वित्तीय उत्तरदायित्व बीमा का एक रूप","एक प्रकार का ड्राइवर लाइसेंस","एक यातायात चालान","एक रक्त अल्कोहल परीक्षण"],"explanation":"SR-22 is a form of financial responsibility insurance that may be required to reinstate driving privileges."},"53":{"q":"गाड़ी चलाने से पहले शराब पीने की सबसे सुरक्षित मात्रा क्या है?","options":["एक ड्रिंक","शून्य शराब","दो ड्रिंक","एक बीयर"],"explanation":"The safest choice is zero alcohol before driving."},"54":{"q":"आप शराब पीकर गाड़ी चलाने से कैसे बच सकते हैं?","options":["पहले कॉफ़ी पिएँ","धीरे गाड़ी चलाएँ","एक शांत (बिना नशे वाला) चालक नियुक्त करें","खिड़कियाँ खोल दें"],"explanation":"Choosing a sober driver lets you avoid driving after drinking."},"55":{"q":"शराब पीकर गाड़ी चलाने से बचने के लिए आप क्या उपयोग कर सकते हैं?","options":["एक कप कॉफ़ी","एक ठंडा शॉवर","ताज़ी हवा","एक राइड सेवा"],"explanation":"Using a ride service lets you avoid drinking and driving."},"56":{"q":"शराब पीकर गाड़ी चलाने से बचने का एक तरीका क्या है?","options":["गाड़ी चलाने के बजाय वहीं रुके रहें","बहुत धीरे गाड़ी चलाएं","पहले थोड़ा पानी पिएं","कार की खिड़कियां खोल दें"],"explanation":"Staying put instead of driving keeps you from drinking and driving."},"57":{"q":"टेक्सास में 21 वर्ष से कम उम्र के ड्राइवर के लिए रक्त में अल्कोहल का कौन सा स्तर अवैध है?","options":["0.08% या अधिक","0.00 से अधिक कोई भी मात्रा","0.04% या अधिक","0.15% या अधिक"],"explanation":"Texas has zero tolerance, so any detectable alcohol above 0.00 is illegal for a minor."},"58":{"q":"शराब एक अवसादक है, तो यह शरीर के साथ क्या करती है?","options":["प्रतिक्रिया समय को तेज करती है","समन्वय में सुधार करती है","शरीर के कार्यों को धीमा करती है","दृष्टि को तेज करती है"],"explanation":"As a depressant, alcohol slows down the body's functions instead of stimulating them."},"59":{"q":"टेक्सास में, पहली DWI (नशे में गाड़ी चलाना) दोषसिद्धि के लिए अधिकतम जुर्माना कितना है?","options":["$200","$500","$1,000","$2,000"],"explanation":"A first DWI conviction in Texas carries a fine of up to $2,000."}}}}};
